app.get('/export-json', requireDashboardAuth, (req, res) => {
  try {
    const dir = getCsvTargetDir();
    if (!fs.existsSync(dir)) return res.status(404).json({ error: 'Nenhum arquivo de export encontrado.' });

    const files = fs.readdirSync(dir).filter(f => f.endsWith('.json') && f.startsWith('resultado_scan_'));
    if (!files || files.length === 0) return res.status(404).json({ error: 'Nenhum arquivo JSON de scan encontrado.' });

    // escolher o mais recente por nome (timestamp presente)
    files.sort();
    const latest = files[files.length - 1];
    const filePath = path.join(dir, latest);
    res.sendFile(filePath);
  } catch (err) {
    console.error('Erro servindo export-json:', err);
    res.status(500).json({ error: 'Erro ao servir export-json.' });
  }
});

