/** Shared printer fingerprints (SNMP / HTTP / TLS / hostname). */
const PRINTER_PATTERN = /printer|impressora|impress\w*|laserjet|deskjet|officejet|pagewide|designjet|imageclass|pixma|ecosys|workcentre|versamark|multifunc|mfp\b|jetdirect|cups|ipp\/|printer[-_ ]?server|print[-_ ]?server|bizhub|imagerunner|ir[- ]?adv|canon\s*(i[rfp]|lbp|mf|gx)|hp\s*eprint|kyocera|ricoh|lexmark|xerox|brother|epson|sharp\s*(mx|bp|ar)|konica|minolta|pantum|\boki\b|dell\s*laser|samsung\s*laser|phoenix\s*contact.*print|hw-?printer|prt[-_]|\bprn\b/i;

const PRINTER_VENDOR_PATTERN = /\b(canon|epson|brother|lexmark|xerox|kyocera|ricoh|konica|minolta|sharp|pantum|oki|zebra|honeywell\s*printer|hp\s*(inc|printing|laser)|hewlett[- ]?packard)\b/i;

function looksLikePrinter(...parts) {
  const text = parts.filter(Boolean).join(' ');
  if (!text) return false;
  return PRINTER_PATTERN.test(text) || PRINTER_VENDOR_PATTERN.test(text);
}

const EMPTY = new Set(['', 'N/A', 'n/a', 'Desconhecido', 'null', 'undefined']);

function isEmpty(value) {
  if (value == null) return true;
  const s = String(value).trim();
  return !s || EMPTY.has(s);
}

function pick(...values) {
  for (const v of values) {
    if (!isEmpty(v)) return typeof v === 'string' ? v.trim() : v;
  }
  return 'N/A';
}

function shortName(hostname) {
  if (isEmpty(hostname)) return null;
  return String(hostname).split('.')[0].toUpperCase();
}

function runPowerShell(script, timeoutMs = 20000) {
  const encoded = Buffer.from(script, 'utf16le').toString('base64');
  return execFileAsync(
    'powershell.exe',
    ['-NoProfile', '-NonInteractive', '-ExecutionPolicy', 'Bypass', '-EncodedCommand', encoded],
    {
      timeout: timeoutMs,
      windowsHide: true,
      maxBuffer: 20 * 1024 * 1024,
      encoding: 'utf8'
    }
  ).then(({ stdout, stderr }) => ({ stdout: stdout || '', stderr: stderr || '' }));
}

function filetimeToIso(filetime) {
  const n = Number(filetime);
  if (!Number.isFinite(n) || n <= 0) return null;
  // Windows FILETIME (100ns since 1601) → JS Date
  const ms = (n / 10000) - 11644473600000;
  const d = new Date(ms);
  return Number.isNaN(d.getTime()) ? null : d.toISOString();
}

function mapWindowsBuild(major, minor, build) {
  if (major == null) return null;
  const m = Number(major);
  const n = Number(minor);
  const b = Number(build) || 0;
  if (m === 10 && n === 0) {
    if (b >= 22000) return 'Windows 11 / Server 2022+';
    if (b >= 20348) return 'Windows Server 2022';
    if (b >= 19041) return 'Windows 10 / Server 2019+';
    if (b >= 17763) return 'Windows 10 / Server 2019';
    if (b >= 14393) return 'Windows 10 / Server 2016';
    return 'Windows 10 / Server 2016+';
  }
  if (m === 6 && n === 3) return 'Windows 8.1 / Server 2012 R2';
  if (m === 6 && n === 2) return 'Windows 8 / Server 2012';
  if (m === 6 && n === 1) return 'Windows 7 / Server 2008 R2';
  if (m === 6 && n === 0) return 'Windows Vista / Server 2008';
  if (m === 5) return 'Windows XP / Server 2003';
  return `Windows ${m}.${n}${b ? ` (build ${b})` : ''}`;
}

// ---------- AD / LDAP (catalog once per scan) ----------

async function loadAdCatalog(timeoutMs = 45000) {
  const script = `
$ErrorActionPreference = 'Stop'
try {
  $rootDse = [ADSI]'LDAP://RootDSE'
  $defaultNc = $rootDse.defaultNamingContext.ToString()
  $dnsHost = $null
  try { $dnsHost = $rootDse.dnsHostName.ToString() } catch {}
  $domainDns = $null
  try {
    $domainDns = ([ADSI]("LDAP://$defaultNc")).dnsRoot
    if ($domainDns -is [System.DirectoryServices.PropertyValueCollection]) {
      $domainDns = $domainDns[0]
    }
  } catch {}
  if (-not $domainDns) {
    try { $domainDns = [System.DirectoryServices.ActiveDirectory.Domain]::GetCurrentDomain().Name } catch {}
  }

  $searcher = New-Object System.DirectoryServices.DirectorySearcher
  $searcher.SearchRoot = [ADSI]("LDAP://$defaultNc")
  $searcher.Filter = '(objectCategory=computer)'
  $searcher.PageSize = 1000
  $props = @(
    'cn','name','sAMAccountName','dNSHostName','operatingSystem','operatingSystemVersion',
    'operatingSystemServicePack','distinguishedName','description',
    'whenCreated','lastLogonTimestamp','location','managedBy','userAccountControl'
  )
  foreach ($p in $props) { [void]$searcher.PropertiesToLoad.Add($p) }

  $computers = @()
  foreach ($r in $searcher.FindAll()) {
    $get = {
      param($key)
      if ($r.Properties[$key] -and $r.Properties[$key].Count -gt 0) { return [string]$r.Properties[$key][0] }
      return $null
    }
    $computers += [PSCustomObject]@{
      cn = & $get 'cn'
      name = & $get 'name'
      sAMAccountName = & $get 'sAMAccountName'
      dNSHostName = & $get 'dNSHostName'
      operatingSystem = & $get 'operatingSystem'
      operatingSystemVersion = & $get 'operatingSystemVersion'
      operatingSystemServicePack = & $get 'operatingSystemServicePack'
      distinguishedName = & $get 'distinguishedName'
      description = & $get 'description'
      whenCreated = & $get 'whenCreated'
      lastLogonTimestamp = & $get 'lastLogonTimestamp'
      location = & $get 'location'
      managedBy = & $get 'managedBy'
      userAccountControl = & $get 'userAccountControl'
    }
  }

  $payload = [PSCustomObject]@{
    ok = $true
    defaultNamingContext = $defaultNc
    domainDns = $domainDns
    dnsHostName = $dnsHost
    computerCount = $computers.Count
    computers = $computers
  }
  $payload | ConvertTo-Json -Depth 6 -Compress
} catch {
  (@{ ok = $false; error = $_.Exception.Message }) | ConvertTo-Json -Compress
}
`;

  try {
    const { stdout } = await runPowerShell(script, timeoutMs);
    const jsonStart = stdout.indexOf('{');
    if (jsonStart < 0) {
      return { ok: false, error: 'Resposta LDAP vazia', byDns: new Map(), byCn: new Map(), byIp: new Map() };
    }
    const parsed = JSON.parse(stdout.slice(jsonStart));
    if (!parsed.ok) {
      return { ok: false, error: parsed.error || 'Falha LDAP', byDns: new Map(), byCn: new Map(), byIp: new Map() };
    }

    const byDns = new Map();
    const byCn = new Map();
    const list = Array.isArray(parsed.computers) ? parsed.computers : [];

    for (const c of list) {
      const entry = {
        cn: c.cn || c.name || null,
        name: c.name || c.cn || null,
        sAMAccountName: c.sAMAccountName || null,
        dNSHostName: c.dNSHostName || null,
        operatingSystem: c.operatingSystem || null,
        operatingSystemVersion: c.operatingSystemVersion || null,
        operatingSystemServicePack: c.operatingSystemServicePack || null,
        distinguishedName: c.distinguishedName || null,
        description: c.description || null,
        whenCreated: c.whenCreated || null,
        lastLogonTimestamp: filetimeToIso(c.lastLogonTimestamp) || c.lastLogonTimestamp || null,
        location: c.location || null,
        managedBy: c.managedBy || null,
        userAccountControl: c.userAccountControl || null,
        adDomain: parsed.domainDns || null
      };

      if (entry.dNSHostName) byDns.set(String(entry.dNSHostName).toLowerCase(), entry);
      const cn = shortName(entry.cn || entry.name);
      if (cn) byCn.set(cn, entry);
      const dnsShort = shortName(entry.dNSHostName);
      if (dnsShort) byCn.set(dnsShort, entry);
    }

    return {
      ok: true,
      domainDns: parsed.domainDns || 'N/A',
      defaultNamingContext: parsed.defaultNamingContext || null,
      computerCount: list.length,
      byDns,
      byCn,
      byIp: new Map()
    };
  } catch (err) {
    return { ok: false, error: err.message, byDns: new Map(), byCn: new Map(), byIp: new Map() };
  }
}

function lookupAd(catalog, hostnameHints = []) {
  if (!catalog || !catalog.ok) return null;

  for (const hint of hostnameHints) {
    if (isEmpty(hint)) continue;
    const fqdn = String(hint).toLowerCase();
    if (catalog.byDns.has(fqdn)) return { ...catalog.byDns.get(fqdn), matchedBy: 'dnsHostName' };

    const cn = shortName(hint);
    if (cn && catalog.byCn.has(cn)) return { ...catalog.byCn.get(cn), matchedBy: 'cn' };

    // Try hint + domain
    if (catalog.domainDns && !fqdn.includes('.')) {
      const full = `${fqdn}.${String(catalog.domainDns).toLowerCase()}`;
      if (catalog.byDns.has(full)) return { ...catalog.byDns.get(full), matchedBy: 'dnsHostName+domain' };
    }
  }
  return null;
}

function lookupAdByIp(catalog, ip) {
  if (!catalog || !catalog.ok || !catalog.byIp || !ip) return null;
  const entry = catalog.byIp.get(String(ip).trim());
  if (!entry) return null;
  return { ...entry, matchedBy: 'ip' };
}

function saveAdComputersCache(catalog) {
  if (!catalog?.ok) return;
  try {
    if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
    const seen = new Set();
    const computers = [];
    for (const entry of catalog.byDns.values()) {
      const key = entry.distinguishedName || entry.dNSHostName || entry.cn;
      if (!key || seen.has(key)) continue;
      seen.add(key);
      computers.push({
        cn: entry.cn || null,
        name: entry.name || null,
        sAMAccountName: entry.sAMAccountName || null,
        dNSHostName: entry.dNSHostName || null,
        distinguishedName: entry.distinguishedName || null,
        description: entry.description || null,
        location: entry.location || null,
        managedBy: entry.managedBy || null,
        operatingSystem: entry.operatingSystem || null,
        adDomain: entry.adDomain || catalog.domainDns || null
      });
    }
    const ipMap = {};
    if (catalog.byIp instanceof Map) {
      for (const [ip, entry] of catalog.byIp.entries()) {
        ipMap[ip] = entry.dNSHostName || entry.cn || entry.name || null;
      }
    }
    fs.writeFileSync(
      AD_COMPUTERS_CACHE_FILE,
      JSON.stringify({
        cachedAt: Date.now(),
        domainDns: catalog.domainDns || null,
        computerCount: catalog.computerCount || computers.length,
        computers,
        ipMap
      }),
      'utf8'
    );
  } catch {
    // ignore cache write errors
  }
}

function loadAdIpIndexCache(domainDns, computerCount) {
  try {
    if (!fs.existsSync(AD_IP_INDEX_FILE)) return null;
    const raw = JSON.parse(fs.readFileSync(AD_IP_INDEX_FILE, 'utf8'));
    if (!raw || raw.domainDns !== domainDns || raw.computerCount !== computerCount) return null;
    if (!raw.builtAt || Date.now() - raw.builtAt > AD_IP_INDEX_MAX_AGE_MS) return null;
    if (!raw.map || typeof raw.map !== 'object') return null;
    return raw.map;
  } catch {
    return null;
  }
}

function saveAdIpIndexCache(domainDns, computerCount, mapObj) {
  try {
    if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
    fs.writeFileSync(
      AD_IP_INDEX_FILE,
      JSON.stringify({
        builtAt: Date.now(),
        domainDns,
        computerCount,
        map: mapObj
      }),
      'utf8'
    );
  } catch {
    // ignore cache write errors
  }
}

/**
 * Resolve AD computer DNS names → IPs so we can match hosts that have no PTR/NetBIOS/SMB.
 */
async function buildAdIpIndex(catalog, log = () => {}) {
  if (!catalog || !catalog.ok) return catalog;
  catalog.byIp = catalog.byIp instanceof Map ? catalog.byIp : new Map();

  const cached = loadAdIpIndexCache(catalog.domainDns, catalog.computerCount);
  if (cached) {
    for (const [ip, key] of Object.entries(cached)) {
      const entry =
        (key && catalog.byDns.get(String(key).toLowerCase())) ||
        (key && catalog.byCn.get(shortName(key))) ||
        null;
      if (entry) catalog.byIp.set(ip, entry);
    }
    log(`[+] Índice AD→IP (cache): ${catalog.byIp.size} endereços`);
    saveAdComputersCache(catalog);
    return catalog;
  }

  const names = [];
  const seen = new Set();
  for (const entry of catalog.byDns.values()) {
    const fqdn = entry.dNSHostName;
    if (isEmpty(fqdn)) continue;
    const key = String(fqdn).toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    names.push({ fqdn: key, entry });
  }

  log(`[~] Indexando AD por IP (DNS forward de ${names.length} computadores)...`);
  const mapObj = {};
  const concurrency = 80;
  let resolved = 0;
  let idx = 0;

  async function worker() {
    while (idx < names.length) {
      const current = names[idx++];
      try {
        const addrs = await Promise.race([
          dns.resolve4(current.fqdn),
          new Promise((resolve) => setTimeout(() => resolve([]), 2500))
        ]);
        for (const ip of addrs || []) {
          if (!catalog.byIp.has(ip)) {
            catalog.byIp.set(ip, current.entry);
            mapObj[ip] = current.fqdn;
          }
        }
      } catch {
        // skip
      }
      resolved++;
      if (resolved % 500 === 0 || resolved === names.length) {
        log(`[~] Índice AD→IP: ${resolved}/${names.length} (mapeados=${catalog.byIp.size})`);
      }
    }
  }

  await Promise.all(Array.from({ length: Math.min(concurrency, names.length) }, () => worker()));
  saveAdIpIndexCache(catalog.domainDns, catalog.computerCount, mapObj);
  saveAdComputersCache(catalog);
  log(`[+] Índice AD→IP pronto: ${catalog.byIp.size} endereços`);
  return catalog;
}

// ---------- DNS / Network discovery ----------

function cleanHostnameCandidate(name) {
  if (isEmpty(name)) return null;
  let s = String(name).trim().replace(/\.$/, '');
  // Strip trailing DNS suffixes noise from nslookup
  if (/^(localhost|in-addr\.arpa)$/i.test(s)) return null;
  if (/^\d+\.\d+\.\d+\.\d+$/.test(s)) return null;
  // Reject IPv6 / link-local junk sometimes found in TLS certs
  if (/^[0-9a-f:]+$/i.test(s) || /^fe80:/i.test(s) || s.includes(':')) return null;
  if (/\s/.test(s)) return null;
  return s;
}

function hostnameFromLooseCandidate(raw) {
  const strict = cleanHostnameCandidate(raw);
  if (strict) return strict;
  const s = String(raw || '').trim();
  if (s.length < 3 || s.length > 48) return null;
  if (/^(unknown|default|admin|printer|n\/a|null)$/i.test(s)) return null;
  if (/[<>{}|\\/]/.test(s)) return null;
  const slug = s
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, '-')
    .replace(/[^A-Za-z0-9._-]/g, '')
    .replace(/^-+|-+$/g, '');
  return slug.length >= 3 ? slug : null;
}

function deriveFallbackHostname(ip, meta = {}) {
  const octet = String(ip || '').split('.').pop() || '0';
  let type = meta.deviceType || meta.label || 'equipamento';
  type = String(type)
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, '-')
    .replace(/[^A-Za-z0-9._-]/g, '');
  if (!type || /^host(-ativo)?$/i.test(type)) type = 'equipamento';
  const domain = meta.adDomain && meta.adDomain !== 'N/A' && String(meta.adDomain).includes('.')
    ? String(meta.adDomain).toLowerCase()
    : null;
  const base = `${type}-${octet}`;
  return domain && !base.includes('.') ? `${base}.${domain}` : base;
}

function resolveHostnameFinal(ip, hostname, meta = {}) {
  const hasDiscovered = !isEmpty(hostname) && meta.source !== 'fallback';
  if (hasDiscovered) {
    return { hostname: pick(hostname), source: meta.source || 'discovered' };
  }

  const candidates = [
    { v: meta.snmpPrinterName, source: 'snmp-prtName' },
    { v: meta.snmpSysName, source: 'snmp-sysName' },
    { v: meta.httpTitle, source: 'http-title' },
    { v: meta.httpServer, source: 'http-server' },
    { v: meta.tlsHost, source: 'tls-cert' },
    { v: meta.description, source: 'description' }
  ];
  for (const c of candidates) {
    const h = hostnameFromLooseCandidate(c.v);
    if (h) return { hostname: h, source: c.source };
  }

  return {
    hostname: deriveFallbackHostname(ip, meta),
    source: 'fallback'
  };
}

async function queryLoggedOnUserViaQUser(ip, timeoutMs = 3500) {
  const safeIp = String(ip || '').trim();
  if (!safeIp || !/^\d+\.\d+\.\d+\.\d+$/.test(safeIp)) return null;
  const parseOutput = (text) => {
    const lines = String(text || '').split(/\r?\n/).map((l) => l.trim()).filter(Boolean);
    for (const line of lines) {
      if (/^USERNAME/i.test(line) || /^>{0,1}$/.test(line)) continue;
      const m = line.match(/^([^\s>]+)/);
      if (!m) continue;
      const user = m[1].replace(/^>/, '').trim();
      if (!user || /^USERNAME$/i.test(user) || /^(SERVIÇO|SERVICE)$/i.test(user)) continue;
      return user;
    }
    return null;
  };
  try {
    const { stdout } = await execFileAsync('query', ['user', `/server:${safeIp}`], {
      timeout: timeoutMs,
      windowsHide: true,
      encoding: 'utf8'
    });
    return parseOutput(stdout);
  } catch (err) {
    return parseOutput(err?.stdout || '');
  }
}

async function queryLoggedOnUser(ip, timeoutMs = 3500) {
  const safeIp = String(ip || '').trim();
  if (!safeIp || !/^\d+\.\d+\.\d+\.\d+$/.test(safeIp)) return null;

  const quser = await queryLoggedOnUserViaQUser(safeIp, timeoutMs);
  if (quser) return quser;

  try {
    const { stdout } = await execFileAsync(
      'powershell',
      [
        '-NoProfile',
        '-Command',
        `$u = (Get-CimInstance -ClassName Win32_ComputerSystem -ComputerName '${safeIp}' -ErrorAction SilentlyContinue).UserName; if ($u) { Write-Output $u }`
      ],
      { timeout: timeoutMs, windowsHide: true }
    );
    const line = String(stdout || '').trim().split(/\r?\n/).pop()?.trim();
    if (!line || /error|access denied|rpc|failed/i.test(line)) return null;
    return line;
  } catch {
    return null;
  }
}

async function resolveDnsReverseNode(ip) {
  try {
    const names = await dns.reverse(ip);
    return cleanHostnameCandidate(names && names[0]);
  } catch {
    return null;
  }
}

/** Windows DNS stack often knows names Node's dns.reverse misses (NetBIOS/LLMNR/suffix search). */
async function resolveDnsReverseWindows(ip) {
  // ping -a: "Pinging HOST [ip]" or "Disparando HOST [ip]"
  try {
    const { stdout } = await execFileAsync('ping', ['-a', '-n', '1', '-w', '400', ip], {
      timeout: 2500,
      windowsHide: true,
      encoding: 'utf8'
    });
    const m =
      (stdout || '').match(/Pinging\s+([^\s\[\]]+)\s*\[/i) ||
      (stdout || '').match(/Disparando\s+([^\s\[\]]+)\s*\[/i) ||
      (stdout || '').match(/Pingando\s+([^\s\[\]]+)\s*\[/i);
    if (m) {
      const host = cleanHostnameCandidate(m[1]);
      if (host && host !== ip) return host;
    }
  } catch {
    // continue
  }

  try {
    const { stdout } = await execFileAsync('nslookup', [ip], {
      timeout: 3000,
      windowsHide: true,
      encoding: 'utf8'
    });
    const text = stdout || '';
    const m =
      text.match(/Name:\s*(\S+)/i) ||
      text.match(/Nome:\s*(\S+)/i) ||
      text.match(/name\s*=\s*(\S+)/i);
    if (m) return cleanHostnameCandidate(m[1]);
  } catch (err) {
    // nslookup often exits non-zero but still prints Name:
    const text = (err && err.stdout) || '';
    const m =
      text.match(/Name:\s*(\S+)/i) ||
      text.match(/Nome:\s*(\S+)/i);
    if (m) return cleanHostnameCandidate(m[1]);
  }

  return null;
}

async function resolveDnsReverse(ip) {
  const viaNode = await resolveDnsReverseNode(ip);
  if (viaNode) return viaNode;
  return resolveDnsReverseWindows(ip);
}

async function resolveDnsForward(hostname) {
  if (isEmpty(hostname)) return [];
  try {
    return await dns.resolve4(hostname);
  } catch {
    return [];
  }
}

/** TLS certificate details — CN/O/OU useful for printers with only HTTPS. */
function queryTlsCertInfo(ip, port = 443, timeoutMs = 2500) {
  return new Promise((resolve) => {
    let settled = false;
    const done = (v) => {
      if (settled) return;
      settled = true;
      resolve(v);
    };

    const socket = tls.connect(
      {
        host: ip,
        port,
        rejectUnauthorized: false,
        timeout: timeoutMs
      },
      () => {
        try {
          const cert = socket.getPeerCertificate();
          socket.end();
          if (!cert || Object.keys(cert).length === 0) return done(null);

          const sans = [];
          if (typeof cert.subjectaltname === 'string') {
            for (const part of cert.subjectaltname.split(',')) {
              const m = part.trim().match(/^DNS:(.+)$/i);
              if (m) sans.push(m[1].trim());
            }
          }
          const subject = cert.subject || {};
          const cn = subject.CN || subject.cn || null;
          const org = subject.O || subject.o || null;
          const ou = subject.OU || subject.ou || null;
          const issuer = cert.issuer
            ? [cert.issuer.O || cert.issuer.o, cert.issuer.CN || cert.issuer.cn].filter(Boolean).join(' ')
            : null;
          const hostCandidate = cleanHostnameCandidate(sans[0] || cn);
          done({
            cn: cleanHostnameCandidate(cn) || cn || null,
            org: org || null,
            ou: ou || null,
            issuer,
            sans,
            hostCandidate: hostCandidate && hostCandidate !== ip ? hostCandidate : null,
            blob: [cn, org, ou, issuer, ...(sans || [])].filter(Boolean).join(' ')
          });
        } catch {
          done(null);
        }
      }
    );
    socket.on('error', () => done(null));
    socket.on('timeout', () => {
      socket.destroy();
      done(null);
    });
    setTimeout(() => {
      socket.destroy();
      done(null);
    }, timeoutMs + 200);
  });
}

async function queryTlsCertName(ip, port = 443, timeoutMs = 2500) {
  const info = await queryTlsCertInfo(ip, port, timeoutMs);
  return info?.hostCandidate || null;
}

function extractSnmpOctetStrings(msg) {
  const strings = [];
  if (!Buffer.isBuffer(msg)) return strings;
  let i = 0;
  while (i < msg.length - 2) {
    if (msg[i] !== 0x04) {
      i++;
      continue;
    }
    let len = msg[i + 1];
    let hdr = 2;
    if (len & 0x80) {
      const n = len & 0x7f;
      if (n <= 0 || n > 3 || i + 2 + n >= msg.length) {
        i++;
        continue;
      }
      len = 0;
      for (let j = 0; j < n; j++) len = (len << 8) | msg[i + 2 + j];
      hdr = 2 + n;
    }
    if (len < 0 || i + hdr + len > msg.length) {
      i++;
      continue;
    }
    strings.push(msg.slice(i + hdr, i + hdr + len).toString('utf8').replace(/\0/g, '').trim());
    i += hdr + len;
  }
  return strings.filter(Boolean);
}

function encodeBerLength(len) {
  if (len < 0x80) return Buffer.from([len]);
  if (len <= 0xff) return Buffer.from([0x81, len]);
  return Buffer.from([0x82, (len >> 8) & 0xff, len & 0xff]);
}

function berSequence(tag, content) {
  const body = Buffer.isBuffer(content) ? content : Buffer.concat(content);
  return Buffer.concat([Buffer.from([tag]), encodeBerLength(body.length), body]);
}

function buildSnmpV1Get(oidBytes, community = 'public') {
  const communityBuf = Buffer.from(community, 'ascii');
  const oid = Buffer.concat([Buffer.from([0x06]), encodeBerLength(oidBytes.length), Buffer.from(oidBytes)]);
  const nullVal = Buffer.from([0x05, 0x00]);
  const varbind = berSequence(0x30, Buffer.concat([oid, nullVal]));
  const varbindList = berSequence(0x30, varbind);
  const requestId = Buffer.from([0x02, 0x01, 0x01]);
  const errorStatus = Buffer.from([0x02, 0x01, 0x00]);
  const errorIndex = Buffer.from([0x02, 0x01, 0x00]);
  const pdu = berSequence(0xa0, Buffer.concat([requestId, errorStatus, errorIndex, varbindList]));
  const version = Buffer.from([0x02, 0x01, 0x00]);
  const communityField = Buffer.concat([Buffer.from([0x04]), encodeBerLength(communityBuf.length), communityBuf]);
  return berSequence(0x30, Buffer.concat([version, communityField, pdu]));
}

function snmpGet(ip, oidBytes, timeoutMs = 2000, community = 'public') {
  return new Promise((resolve) => {
    const pdu = buildSnmpV1Get(oidBytes, community);
    const client = dgram.createSocket('udp4');
    let done = false;
    const finish = (v) => {
      if (done) return;
      done = true;
      try { client.close(); } catch {}
      resolve(v);
    };
    const timer = setTimeout(() => finish(null), timeoutMs);
    client.on('message', (msg) => {
      clearTimeout(timer);
      const strings = extractSnmpOctetStrings(msg).filter(s => s.toLowerCase() !== String(community).toLowerCase());
      finish(strings.length ? strings[strings.length - 1] : null);
    });
    client.on('error', () => {
      clearTimeout(timer);
      finish(null);
    });
    try {
      client.send(pdu, 161, ip);
    } catch {
      clearTimeout(timer);
      finish(null);
    }
  });
}

async function snmpGetWithCommunities(ip, oidBytes, timeoutMs = 1600) {
  for (const community of ['public', 'private']) {
    const v = await snmpGet(ip, oidBytes, timeoutMs, community);
    if (v) return v;
  }
  return null;
}

async function querySnmpSysName(ip, timeoutMs = 2000) {
  return snmpGetWithCommunities(ip, [0x2b, 6, 1, 2, 1, 1, 5, 0], timeoutMs);
}

async function querySnmpSysDescr(ip, timeoutMs = 2000) {
  return snmpGetWithCommunities(ip, [0x2b, 6, 1, 2, 1, 1, 1, 0], timeoutMs);
}

async function querySnmpPrinterName(ip, timeoutMs = 2000) {
  return snmpGetWithCommunities(ip, [0x2b, 6, 1, 2, 1, 43, 5, 1, 1, 16, 1], timeoutMs);
}

/** Quick TCP connect — JetDirect/LPD/IPP even if the user didn't scan those ports. */
function probeTcpOpen(ip, port, timeoutMs = 900) {
  return new Promise((resolve) => {
    const socket = new net.Socket();
    let settled = false;
    const done = (v) => {
      if (settled) return;
      settled = true;
      try { socket.destroy(); } catch {}
      resolve(v);
    };
    socket.setTimeout(timeoutMs);
    socket.once('connect', () => done(true));
    socket.once('timeout', () => done(false));
    socket.once('error', () => done(false));
    try {
      socket.connect(port, ip);
    } catch {
      done(false);
    }
  });
}

async function probePrinterTcpPorts(ip) {
  const ports = [9100, 515, 631];
  const open = [];
  await Promise.all(ports.map(async (port) => {
    if (await probeTcpOpen(ip, port, 800)) open.push(port);
  }));
  return open;
}

function parseHttpTitle(body) {
  if (!body) return null;
  const m = String(body).match(/<title[^>]*>([^<]{1,120})<\/title>/i);
  return m ? m[1].replace(/\s+/g, ' ').trim() : null;
}

function httpGetText(url, timeoutMs = 2200, redirectLeft = 2) {
  return new Promise((resolve) => {
    let settled = false;
    const done = (v) => {
      if (settled) return;
      settled = true;
      resolve(v);
    };

    let parsed;
    try {
      parsed = new URL(url);
    } catch {
      return done(null);
    }

    const lib = parsed.protocol === 'https:' ? https : http;
    const agent = parsed.protocol === 'https:'
      ? new https.Agent({ rejectUnauthorized: false, keepAlive: false })
      : undefined;

    const req = lib.get(
      url,
      {
        timeout: timeoutMs,
        agent,
        rejectUnauthorized: false,
        headers: {
          Host: parsed.hostname,
          Accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
          'User-Agent': 'Mozilla/5.0 NetScanCanon PrinterFingerprint',
          Connection: 'close'
        }
      },
      (res) => {
        const loc = res.headers.location;
        if (redirectLeft > 0 && loc && [301, 302, 303, 307, 308].includes(res.statusCode)) {
          res.resume();
          try {
            const next = new URL(loc, url).toString();
            return httpGetText(next, timeoutMs, redirectLeft - 1).then(done);
          } catch {
            return done(null);
          }
        }
        const chunks = [];
        let size = 0;
        res.on('data', (c) => {
          if (size > 8192) return;
          chunks.push(c);
          size += c.length;
        });
        res.on('end', () => {
          const body = Buffer.concat(chunks).toString('utf8', 0, 8192);
          done({
            statusCode: res.statusCode,
            server: res.headers.server || null,
            wwwAuth: res.headers['www-authenticate'] || null,
            contentType: res.headers['content-type'] || null,
            title: parseHttpTitle(body),
            bodySnippet: body.slice(0, 1500)
          });
        });
      }
    );
    req.on('timeout', () => {
      req.destroy();
      done(null);
    });
    req.on('error', () => done(null));
    setTimeout(() => {
      req.destroy();
      done(null);
    }, timeoutMs + 200);
  });
}

/**
 * Probe HTTP(S) management pages — printers often expose only 80/443/631.
 */
async function queryHttpFingerprint(ip, extraPorts = []) {
  const ports = [...new Set([80, 443, 631, 8080, 8443, ...extraPorts])];
  const targets = [];
  for (const port of ports) {
    const tls = port === 443 || port === 8443;
    const base = tls ? `https://${ip}:${port}` : `http://${ip}:${port}`;
    targets.push(`${base}/`);
    if (port === 80 || port === 443 || port === 631) {
      targets.push(`${base}/index.html`);
    }
  }

  const results = await Promise.all(
    targets.map((url) => httpGetText(url, 1400).then((res) => (res ? { url, ...res } : null)))
  );
  const scored = [];
  for (const res of results) {
    if (!res) continue;
    const blob = [res.server, res.wwwAuth, res.title, res.bodySnippet].filter(Boolean).join(' ');
    if (!blob || blob.length < 3) continue;
    const item = { ...res, blob };
    if (looksLikePrinter(blob)) return item;
    scored.push(item);
  }
  return scored[0] || null;
}

/**
 * Always-on printer fingerprint via TCP print ports + SNMP + HTTP + TLS.
 */
async function fingerprintPrinterSignals(ip) {
  const evidence = [];

  const [openPrintPorts, snmpSysName, snmpSysDescr, snmpPrinterName, tlsInfo] = await Promise.all([
    probePrinterTcpPorts(ip).catch(() => []),
    querySnmpSysName(ip, 1400).catch(() => null),
    querySnmpSysDescr(ip, 1400).catch(() => null),
    querySnmpPrinterName(ip, 1400).catch(() => null),
    queryTlsCertInfo(ip, 443, 1600).catch(() => null)
  ]);

  for (const port of openPrintPorts || []) {
    evidence.push(`tcp:${port}`);
  }
  if (snmpPrinterName) evidence.push(`snmp-prtName:${snmpPrinterName}`);
  if (looksLikePrinter(snmpSysDescr)) evidence.push(`snmp-sysDescr:${String(snmpSysDescr).slice(0, 80)}`);
  if (looksLikePrinter(snmpSysName)) evidence.push(`snmp-sysName:${snmpSysName}`);
  if (tlsInfo && looksLikePrinter(tlsInfo.blob)) {
    evidence.push(`tls:${tlsInfo.org || tlsInfo.cn || tlsInfo.ou || 'cert'}`);
  }

  // HTTP when print ports closed or to enrich model/title
  let httpFp = null;
  const needHttp = evidence.length === 0 || openPrintPorts.includes(631) || openPrintPorts.length === 0;
  if (needHttp) {
    const extra = openPrintPorts.includes(631) ? [631] : [];
    httpFp = await queryHttpFingerprint(ip, extra).catch(() => null);
    if (httpFp && looksLikePrinter(httpFp.blob)) {
      evidence.push(`http:${httpFp.title || httpFp.server || httpFp.url}`);
    }
  }

  return {
    isPrinter: evidence.length > 0,
    evidence,
    openPrintPorts: openPrintPorts || [],
    snmpSysName,
    snmpSysDescr,
    snmpPrinterName,
    httpFingerprint: httpFp,
    tlsCert: tlsInfo
  };
}

function getMacFromArp(ip) {
  return execFileAsync('arp', ['-a', ip], {
    timeout: 3000,
    windowsHide: true,
    encoding: 'utf8'
  }).then(({ stdout }) => {
    const lines = (stdout || '').split(/\r?\n/);
    for (const line of lines) {
      if (!line.includes(ip)) continue;
      const macMatch = line.match(/([0-9a-fA-F]{2}[:-]){5}([0-9a-fA-F]{2})/);
      if (macMatch) return macMatch[0].toUpperCase().replace(/:/g, '-');
    }
    return null;
  }).catch(() => null);
}

// ---------- NetBIOS ----------

function parseNbtstat(stdout) {
  const result = {
    hostname: null,
    workgroup: null,
    mac: null,
    names: []
  };

  if (!stdout) return result;
  const lines = stdout.split(/\r?\n/);

  for (const line of lines) {
    const macMatch = line.match(/Endere[cç]o\s+MAC|MAC\s+Address\s*[:=]\s*([0-9A-Fa-f:\-]{11,17})/i);
    if (macMatch) {
      result.mac = macMatch[1].toUpperCase().replace(/:/g, '-');
    }

    // NAME <00> UNIQUE / GROUP
    const nameMatch = line.match(/^\s*([^\s<]+)\s*<([0-9A-Fa-f]{2})>\s+(UNIQUE|GROUP)/i);
    if (nameMatch) {
      const name = nameMatch[1].trim();
      const suffix = nameMatch[2].toUpperCase();
      const kind = nameMatch[3].toUpperCase();
      result.names.push({ name, suffix, kind });

      if (suffix === '00' && kind === 'UNIQUE' && !name.startsWith('..')) {
        if (!result.hostname) result.hostname = name;
      }
      if (suffix === '00' && kind === 'GROUP') {
        if (!result.workgroup) result.workgroup = name;
      }
      if (suffix === '20' && kind === 'UNIQUE' && !result.hostname) {
        result.hostname = name;
      }
    }
  }

  return result;
}

async function queryNetBios(ip, timeoutMs = 8000) {
  try {
    const { stdout } = await execFileAsync('nbtstat', ['-A', ip], {
      timeout: timeoutMs,
      windowsHide: true,
      encoding: 'utf8'
    });
    return parseNbtstat(stdout);
  } catch (err) {
    // nbtstat still prints useful output on non-zero sometimes
    if (err && err.stdout) return parseNbtstat(err.stdout);
    return { hostname: null, workgroup: null, mac: null, names: [], error: err.message };
  }
}

// ---------- SMB (negotiate + NTLMSSP challenge) ----------

function readUInt16LE(buf, offset) {
  return buf.readUInt16LE(offset);
}

function readUInt32LE(buf, offset) {
  return buf.readUInt32LE(offset);
}

function parseAvPairs(buf) {
  const info = {
    netbiosComputer: null,
    netbiosDomain: null,
    dnsComputer: null,
    dnsDomain: null
  };
  let offset = 0;
  while (offset + 4 <= buf.length) {
    const avId = readUInt16LE(buf, offset);
    const avLen = readUInt16LE(buf, offset + 2);
    offset += 4;
    if (avId === 0) break; // MsvAvEOL
    if (offset + avLen > buf.length) break;
    const value = buf.slice(offset, offset + avLen).toString('utf16le').replace(/\0+$/g, '');
    offset += avLen;
    if (avId === 1) info.netbiosComputer = value;
    if (avId === 2) info.netbiosDomain = value;
    if (avId === 3) info.dnsComputer = value;
    if (avId === 4) info.dnsDomain = value;
  }
  return info;
}

function parseNtlmChallenge(message) {
  if (!message || message.length < 32) return null;
  const signature = message.slice(0, 8).toString('ascii');
  if (!signature.startsWith('NTLMSSP')) return null;

  const targetNameLen = readUInt16LE(message, 12);
  const targetNameOffset = readUInt32LE(message, 16);
  const negotiateFlags = readUInt32LE(message, 20);

  let targetName = null;
  if (targetNameLen > 0 && targetNameOffset + targetNameLen <= message.length) {
    targetName = message.slice(targetNameOffset, targetNameOffset + targetNameLen).toString('utf16le');
  }

  let version = null;
  // Version is present when NTLMSSP_NEGOTIATE_VERSION (0x02000000) is set; typically at offset 48
  if ((negotiateFlags & 0x02000000) && message.length >= 56) {
    version = {
      major: message[48],
      minor: message[49],
      build: message.readUInt16LE(50)
    };
  }

  const targetInfoLen = readUInt16LE(message, 40);
  const targetInfoOffset = readUInt32LE(message, 44);
  let av = {};
  if (targetInfoLen > 0 && targetInfoOffset + targetInfoLen <= message.length) {
    av = parseAvPairs(message.slice(targetInfoOffset, targetInfoOffset + targetInfoLen));
  }

  return {
    targetName,
    ...av,
    os: version ? mapWindowsBuild(version.major, version.minor, version.build) : null,
    osVersion: version ? `${version.major}.${version.minor}.${version.build}` : null
  };
}

function buildSmb2Negotiate() {
  // Minimal SMB2 NEGOTIATE requesting SMB 2.0.2 / 2.1 / 3.0
  const dialects = [0x0202, 0x0210, 0x0300, 0x0302, 0x0311];
  const structureSize = 36;
  const dialectCount = dialects.length;
  const bodyLen = structureSize + dialectCount * 2;
  const header = Buffer.alloc(64, 0);
  header.writeUInt8(0xfe, 0);
  header.write('SMB', 1, 'ascii');
  header.writeUInt16LE(64, 4); // StructureSize
  header.writeUInt16LE(0, 6); // CreditCharge
  header.writeUInt32LE(0, 8); // Status / ChannelSequence
  header.writeUInt16LE(0, 12); // Command NEGOTIATE
  header.writeUInt16LE(0, 14); // CreditRequest
  header.writeUInt32LE(0, 16); // Flags
  header.writeUInt32LE(0, 20); // NextCommand
  header.writeUInt32LE(0, 24); // MessageId low
  header.writeUInt32LE(0, 28); // MessageId high / AsyncId
  header.writeUInt32LE(0xFEFF, 32); // ProcessId
  header.writeUInt32LE(0, 36); // TreeId
  header.writeBigUInt64LE(0n, 40); // SessionId
  // Signature 16 bytes already zero

  const body = Buffer.alloc(bodyLen, 0);
  body.writeUInt16LE(structureSize, 0);
  body.writeUInt16LE(dialectCount, 2);
  body.writeUInt16LE(1, 4); // SecurityMode signing enabled
  body.writeUInt16LE(0, 6); // Reserved
  body.writeUInt32LE(0, 8); // Capabilities
  // ClientGuid 16 bytes zero at 12
  body.writeUInt32LE(0, 28); // NegotiateContextOffset
  body.writeUInt16LE(0, 32); // NegotiateContextCount
  body.writeUInt16LE(0, 34); // Reserved2
  for (let i = 0; i < dialectCount; i++) {
    body.writeUInt16LE(dialects[i], structureSize + i * 2);
  }

  const smb = Buffer.concat([header, body]);
  const nbss = Buffer.alloc(4);
  nbss.writeUInt32BE(smb.length, 0);
  return Buffer.concat([nbss, smb]);
}

function buildSmb2SessionSetup(sessionId, messageId) {
  // NTLMSSP Negotiate message
  const ntlm = Buffer.alloc(32, 0);
  ntlm.write('NTLMSSP\0', 0, 'ascii');
  ntlm.writeUInt32LE(1, 8); // Type 1 Negotiate
  // flags: UNICODE | NT_OEM | REQUEST_TARGET | NTLM | ALWAYS_SIGN | EXTENDED_SESSIONSECURITY | VERSION | 128 | 56
  ntlm.writeUInt32LE(0xE2088235, 12);

  const structureSize = 25;
  const securityBufferOffset = 64 + structureSize - 1; // per SMB2: offset from beginning of header
  const body = Buffer.alloc(structureSize - 1 + ntlm.length, 0);
  body.writeUInt16LE(structureSize, 0);
  body.writeUInt8(1, 2); // flags binding? 0; use 0
  body.writeUInt8(0, 3); // security mode
  body.writeUInt32LE(0, 4); // capabilities
  body.writeUInt32LE(0, 8); // channel
  body.writeUInt16LE(ntlm.length, 12); // SecurityBufferLength
  body.writeUInt32LE(64 + 24, 14); // SecurityBufferOffset (header 64 + fixed 24)
  body.writeUInt16LE(0, 18); // previous session id low part padding - actually PreviousSessionId is 8 bytes at 18
  // rewrite carefully
  const bodyFixed = Buffer.alloc(24, 0);
  bodyFixed.writeUInt16LE(25, 0);
  bodyFixed.writeUInt8(0, 2);
  bodyFixed.writeUInt8(1, 3); // Signing enabled
  bodyFixed.writeUInt32LE(0, 4);
  bodyFixed.writeUInt32LE(0, 8);
  bodyFixed.writeUInt16LE(ntlm.length, 12);
  bodyFixed.writeUInt32LE(64 + 24, 14);
  // PreviousSessionId 8 bytes zeros at 18 - but buffer only 24, so bytes 18-23 are part of PreviousSessionId low

  const header = Buffer.alloc(64, 0);
  header.writeUInt8(0xfe, 0);
  header.write('SMB', 1, 'ascii');
  header.writeUInt16LE(64, 4);
  header.writeUInt16LE(1, 6);
  header.writeUInt32LE(0, 8);
  header.writeUInt16LE(1, 12); // SESSION_SETUP
  header.writeUInt16LE(1, 14);
  header.writeUInt32LE(0, 16);
  header.writeUInt32LE(0, 20);
  header.writeUInt32LE(messageId, 24);
  header.writeUInt32LE(0, 28);
  header.writeUInt32LE(0xFEFF, 32);
  header.writeUInt32LE(0, 36);
  header.writeBigUInt64LE(BigInt(sessionId || 0), 40);

  const smb = Buffer.concat([header, bodyFixed, ntlm]);
  const nbss = Buffer.alloc(4);
  nbss.writeUInt32BE(smb.length, 0);
  return Buffer.concat([nbss, smb]);
}

function extractNtlmFromSmb2(buf) {
  // Find NTLMSSP in buffer
  const sig = Buffer.from('NTLMSSP\0', 'ascii');
  const idx = buf.indexOf(sig);
  if (idx < 0) return null;
  return parseNtlmChallenge(buf.slice(idx));
}

function querySmb(ip, timeoutMs = 4000) {
  return new Promise((resolve) => {
    const socket = new net.Socket();
    let settled = false;
    let buffer = Buffer.alloc(0);
    let stage = 'negotiate';
    let sessionId = 0;

    const done = (value) => {
      if (settled) return;
      settled = true;
      try { socket.destroy(); } catch {}
      resolve(value || {});
    };

    socket.setTimeout(timeoutMs);
    socket.on('timeout', () => done({ error: 'timeout', portOpen: stage !== 'negotiate' }));
    socket.on('error', (err) => done({ error: err.message, portOpen: false }));
    socket.on('close', () => done({ error: 'closed' }));

    socket.on('data', (chunk) => {
      buffer = Buffer.concat([buffer, chunk]);
      if (buffer.length < 8) return;

      // Need full NBSS message
      while (buffer.length >= 4) {
        const nbssLen = buffer.readUInt32BE(0) & 0xffffff;
        if (buffer.length < 4 + nbssLen) return;
        const smbMsg = buffer.slice(4, 4 + nbssLen);
        buffer = buffer.slice(4 + nbssLen);

        if (stage === 'negotiate') {
          // SessionId is at offset 40 in SMB2 header
          if (smbMsg.length >= 48 && smbMsg[0] === 0xfe && smbMsg.slice(1, 4).toString('ascii') === 'SMB') {
            sessionId = Number(smbMsg.readBigUInt64LE(40));
          }
          stage = 'session';
          socket.write(buildSmb2SessionSetup(sessionId, 1));
        } else {
          const ntlm = extractNtlmFromSmb2(smbMsg);
          done({
            portOpen: true,
            ...ntlm,
            hostname: ntlm?.dnsComputer || ntlm?.netbiosComputer || null,
            adDomain: ntlm?.dnsDomain || ntlm?.netbiosDomain || ntlm?.targetName || null
          });
          return;
        }
      }
    });

    socket.connect(445, ip, () => {
      socket.write(buildSmb2Negotiate());
    });
  });
}

function getOSFromTTL(ttl) {
  if (!ttl) return 'Desconhecido';
  if (ttl <= 64) return 'Linux / macOS / Android';
  if (ttl <= 128) return 'Windows';
  if (ttl <= 255) return 'Dispositivo de Rede (Cisco/Router/Embedded)';
  return 'Desconhecido';
}

function detectVM(mac, vendor, os) {
  return detectVirtualization({ mac, vendor, os }).vm;
}

/**
 * Create enrichment context once per scan (loads AD catalog + IP index).
 */
async function createEnrichmentContext(sendLog) {
  const log = typeof sendLog === 'function' ? sendLog : () => {};
  log('[~] Carregando catálogo AD/LDAP (computadores do domínio)...');
  const adCatalog = await loadAdCatalog();
  if (adCatalog.ok) {
    log(`[+] AD/LDAP OK: domínio=${adCatalog.domainDns || 'N/A'} | computadores=${adCatalog.computerCount}`);
    await buildAdIpIndex(adCatalog, log);
  } else {
    log(`[!] AD/LDAP indisponível: ${adCatalog.error || 'erro desconhecido'}. Seguindo com NetBIOS/SMB/DNS.`);
  }
  return { adCatalog };
}

/**
 * Enrich a single active host using cascade:
 * 1) AD/LDAP (por IP e por nome)  2) NetBIOS  3) SMB  4) DNS/TLS/SNMP
 */
async function enrichHost(ip, { ttl = null, context = null, getVendorFromMac = () => 'Desconhecido' } = {}) {
  const sources = [];
  const adCatalog = context?.adCatalog || { ok: false, byDns: new Map(), byCn: new Map(), byIp: new Map() };

  let hostname = 'N/A';
  let os = getOSFromTTL(ttl);
  let osVersion = 'N/A';
  let adDomain = adCatalog.domainDns || 'N/A';
  let mac = 'N/A';
  let vendor = 'Desconhecido';
  let description = 'N/A';
  let adDn = 'N/A';
  let adLocation = 'N/A';
  let managedBy = 'N/A';
  let adSamAccountName = 'N/A';
  let loggedOnUser = 'N/A';
  let lastLogon = 'N/A';
  let enrichmentNotes = [];

  // Helper names collected along the way for AD rematch
  const nameHints = [];

  const applyAd = (ad, note) => {
    if (!ad) return;
    hostname = pick(ad.dNSHostName, ad.cn, hostname);
    os = pick(ad.operatingSystem, os);
    osVersion = pick(
      [ad.operatingSystemVersion, ad.operatingSystemServicePack].filter(Boolean).join(' / '),
      osVersion
    );
    adDomain = pick(ad.adDomain, adCatalog.domainDns, adDomain);
    description = pick(ad.description, description);
    adDn = pick(ad.distinguishedName, adDn);
    adLocation = pick(ad.location, adLocation);
    managedBy = pick(ad.managedBy, managedBy);
    adSamAccountName = pick(ad.sAMAccountName, adSamAccountName);
    lastLogon = pick(ad.lastLogonTimestamp, lastLogon);
    if (!sources.includes('ldap-ad')) sources.push('ldap-ad');
    if (note) enrichmentNotes.push(note);
  };

  // --- 0a) AD match by IP (best for domain PCs without PTR) ---
  let ad = lookupAdByIp(adCatalog, ip);
  if (ad) {
    applyAd(ad, `AD match via IP`);
    if (!isEmpty(hostname)) nameHints.push(hostname, ad.cn, ad.dNSHostName);
  }

  // --- 0b) Reverse DNS (Node PTR + ping -a / nslookup) ---
  const ptr = await resolveDnsReverse(ip);
  if (ptr) {
    nameHints.push(ptr);
    if (isEmpty(hostname)) {
      hostname = ptr;
      sources.push('dns-ptr');
    } else if (shortName(hostname) !== shortName(ptr)) {
      enrichmentNotes.push(`PTR=${ptr}`);
      sources.push('dns-ptr');
    } else if (!sources.includes('dns-ptr')) {
      sources.push('dns-ptr');
    }
  }

  // --- 1) AD / LDAP by name hints ---
  if (!sources.includes('ldap-ad')) {
    ad = lookupAd(adCatalog, nameHints);
    if (ad) applyAd(ad, `AD match via ${ad.matchedBy}`);
  }

  // --- 2) NetBIOS ---
  const nb = await queryNetBios(ip);
  if (nb.hostname) {
    nameHints.push(nb.hostname);
    if (isEmpty(hostname) || hostname === 'N/A') {
      hostname = nb.hostname;
      sources.push('netbios-name');
    } else if (shortName(hostname) !== shortName(nb.hostname)) {
      enrichmentNotes.push(`NetBIOS=${nb.hostname}`);
    }
  }
  if (!isEmpty(nb.workgroup) && isEmpty(adDomain)) {
    adDomain = nb.workgroup;
    sources.push('netbios-domain');
  }
  if (!isEmpty(nb.mac) && isEmpty(mac)) {
    mac = nb.mac;
    sources.push('netbios-mac');
  }

  // Rematch AD after NetBIOS name
  if (!sources.includes('ldap-ad')) {
    ad = lookupAd(adCatalog, nameHints);
    if (ad) applyAd(ad, `AD rematch via NetBIOS/${ad.matchedBy}`);
  }

  // --- 3) SMB ---
  const smb = await querySmb(ip);
  if (smb && !smb.error) {
    if (!isEmpty(smb.hostname) && isEmpty(hostname)) {
      hostname = smb.dnsComputer && smb.dnsDomain
        ? `${smb.dnsComputer}.${smb.dnsDomain}`.replace(/\.\./g, '.')
        : smb.hostname;
      sources.push('smb-name');
      nameHints.push(hostname, smb.netbiosComputer, smb.dnsComputer);
    } else if (!isEmpty(smb.hostname)) {
      nameHints.push(smb.hostname, smb.netbiosComputer, smb.dnsComputer);
      // Prefer SMB FQDN over bare NetBIOS short name
      if (
        smb.dnsComputer &&
        smb.dnsDomain &&
        !String(hostname).includes('.')
      ) {
        hostname = `${smb.dnsComputer}.${smb.dnsDomain}`.replace(/\.\./g, '.');
        sources.push('smb-name');
      }
    }
    if (!isEmpty(smb.adDomain) && (isEmpty(adDomain) || adDomain === 'WORKGROUP')) {
      adDomain = smb.adDomain;
      sources.push('smb-domain');
    }
    if (!isEmpty(smb.os) && (isEmpty(os) || os === 'Windows' || os.startsWith('Linux'))) {
      if (isEmpty(os) || os === 'Windows' || os === 'Desconhecido') {
        os = smb.os;
        sources.push('smb-os');
      }
    }
    if (!isEmpty(smb.osVersion) && isEmpty(osVersion)) {
      osVersion = smb.osVersion;
      sources.push('smb-os-version');
    }

    if (!sources.includes('ldap-ad')) {
      ad = lookupAd(adCatalog, nameHints);
      if (ad) applyAd(ad, `AD rematch via SMB/${ad.matchedBy}`);
    }
  } else if (smb && smb.portOpen === false) {
    enrichmentNotes.push('SMB 445 fechado');
  }

  // --- 4) Network discovery extras ---
  if (isEmpty(mac)) {
    const arpMac = await getMacFromArp(ip);
    if (arpMac) {
      mac = arpMac;
      sources.push('arp');
    }
  }

  // If hostname is short NetBIOS and we know domain DNS, promote to FQDN
  if (!isEmpty(hostname) && !String(hostname).includes('.') && !isEmpty(adDomain) && adDomain.includes('.')) {
    hostname = `${hostname}.${adDomain}`;
    sources.push('fqdn-compose');
  }

  // Verify forward DNS if we have a name
  if (!isEmpty(hostname)) {
    const addrs = await resolveDnsForward(hostname);
    if (addrs.includes(ip)) {
      sources.push('dns-forward-ok');
    }
  }

  // Printer / appliance fingerprint (TCP 9100/515/631 + SNMP + HTTP + TLS)
  let fp = {
    isPrinter: false,
    evidence: [],
    openPrintPorts: [],
    snmpSysName: null,
    snmpSysDescr: null,
    snmpPrinterName: null,
    httpFingerprint: null,
    tlsCert: null
  };
  try {
    fp = await fingerprintPrinterSignals(ip);
  } catch (fpErr) {
    enrichmentNotes.push(`Fingerprint impressora falhou: ${fpErr.message}`);
  }

  let snmpSysDescr = fp.snmpSysDescr || null;
  let httpTitle = fp.httpFingerprint?.title || null;
  let httpServer = fp.httpFingerprint?.server || null;
  let tlsSubject = fp.tlsCert?.blob || null;
  const printerEvidence = fp.evidence || [];
  const openPrintPorts = Array.isArray(fp.openPrintPorts) ? fp.openPrintPorts : [];
  const deviceHints = {
    printer: !!fp.isPrinter,
    printerEvidence
  };

  if (fp.tlsCert?.hostCandidate && isEmpty(hostname)) {
    hostname = fp.tlsCert.hostCandidate;
    sources.push('tls-cert');
    nameHints.push(hostname);
  } else if (fp.tlsCert?.hostCandidate) {
    sources.push('tls-cert');
  }

  if (fp.snmpSysName && isEmpty(hostname)) {
    hostname = fp.snmpSysName;
    sources.push('snmp-sysname');
    nameHints.push(hostname);
  } else if (fp.snmpSysName) {
    sources.push('snmp-sysname');
  }

  if (isEmpty(hostname) && fp.snmpPrinterName) {
    const fromPrt = hostnameFromLooseCandidate(fp.snmpPrinterName);
    if (fromPrt) {
      hostname = fromPrt;
      sources.push('snmp-prtName');
      nameHints.push(hostname);
    }
  }

  if (isEmpty(hostname) && fp.httpFingerprint) {
    const fromHttp = hostnameFromLooseCandidate(fp.httpFingerprint.title || fp.httpFingerprint.server);
    if (fromHttp) {
      hostname = fromHttp;
      sources.push('http-title');
      nameHints.push(hostname);
    }
  }

  if (isEmpty(hostname)) {
    try {
      const httpAny = await queryHttpFingerprint(ip, openPrintPorts || []);
      if (httpAny) {
        const fromHttp = hostnameFromLooseCandidate(httpAny.title || httpAny.server);
        if (fromHttp) {
          hostname = fromHttp;
          sources.push('http-probe');
          nameHints.push(hostname);
        }
      }
    } catch {
      // ignore
    }
  }

  if (fp.snmpSysDescr) sources.push('snmp-sysdescr');
  if (fp.snmpPrinterName) sources.push('snmp-printer-mib');
  if (fp.httpFingerprint) sources.push('http-fingerprint');
  if (fp.isPrinter) {
    sources.push('printer-fingerprint');
    enrichmentNotes.push(`Impressora detectada: ${printerEvidence.slice(0, 3).join(' | ')}`);
    // Prefer readable printer model as OS/description when generic
    if (fp.snmpSysDescr && (isEmpty(os) || os === 'Windows' || os.startsWith('Linux') || os.startsWith('Dispositivo'))) {
      os = String(fp.snmpSysDescr).slice(0, 120);
      sources.push('snmp-os');
    }
    if (isEmpty(description) && (fp.snmpSysDescr || fp.snmpPrinterName || httpTitle)) {
      description = pick(fp.snmpPrinterName, fp.snmpSysDescr, httpTitle);
    }
    // MAC vendor unknown: infer brand from fingerprint text
    if (isEmpty(vendor) || vendor === 'Desconhecido') {
      const brandBlob = [fp.snmpSysDescr, fp.snmpPrinterName, tlsSubject, httpTitle, httpServer].join(' ');
      const brand =
        (/canon/i.test(brandBlob) && 'Canon') ||
        (/hewlett|hp\b|laserjet|deskjet|officejet/i.test(brandBlob) && 'HP') ||
        (/epson/i.test(brandBlob) && 'Epson') ||
        (/brother/i.test(brandBlob) && 'Brother') ||
        (/lexmark/i.test(brandBlob) && 'Lexmark') ||
        (/xerox/i.test(brandBlob) && 'Xerox') ||
        (/kyocera/i.test(brandBlob) && 'Kyocera') ||
        (/ricoh/i.test(brandBlob) && 'Ricoh') ||
        (/konica|minolta/i.test(brandBlob) && 'Konica Minolta') ||
        null;
      if (brand) vendor = brand;
    }
  }

  if (!sources.includes('ldap-ad') && nameHints.length) {
    ad = lookupAd(adCatalog, nameHints);
    if (ad) applyAd(ad, `AD rematch via fingerprint/${ad.matchedBy}`);
  }

  const osText = String(os || '').toLowerCase();
  if (/windows/.test(osText)) {
    const remoteUser = await queryLoggedOnUser(ip);
    if (!isEmpty(remoteUser)) {
      loggedOnUser = remoteUser;
      sources.push('remote-user');
    }
  }

  // Honest note when nothing yielded a name via discovery protocols
  let hostnameSource = sources.includes('snmp-sysname') || sources.includes('snmp-prtName') || sources.includes('ldap-ad')
    || sources.includes('dns-ptr') || sources.includes('netbios-name') || sources.includes('smb-name')
    || sources.includes('tls-cert') || sources.includes('http-title') || sources.includes('http-probe')
    ? 'discovered'
    : null;

  if (isEmpty(hostname)) {
    enrichmentNotes.push(
      'Sem hostname via PTR/AD/NetBIOS/SMB/TLS/SNMP — nome inferido pelo tipo do equipamento'
    );
  }

  if (isEmpty(vendor) || vendor === 'Desconhecido') {
    vendor = getVendorFromMac(mac);
  } else {
    // keep inferred printer brand; still allow OUI if better
    const ouiVendor = getVendorFromMac(mac);
    if (ouiVendor && ouiVendor !== 'Desconhecido') vendor = ouiVendor;
  }

  const virt = detectVirtualization({
    mac,
    vendor,
    os,
    hostname,
    description,
    adDn,
    adLocation
  });
  const vm = virt.vm;

  const deviceTypeGuess = fp.isPrinter ? 'Impressora' : (os && String(os).includes('Server') ? 'Servidor' : null);
  const resolved = resolveHostnameFinal(ip, hostname, {
    source: hostnameSource,
    snmpPrinterName: fp.snmpPrinterName,
    snmpSysName: fp.snmpSysName,
    httpTitle,
    httpServer,
    tlsHost: fp.tlsCert?.hostCandidate,
    description,
    deviceType: deviceTypeGuess,
    adDomain
  });
  hostname = resolved.hostname;
  hostnameSource = resolved.source;
  if (resolved.source === 'fallback') sources.push('hostname-fallback');

  // Compose richer OS display when we have version
  let osDisplay = os;
  if (!isEmpty(osVersion) && osVersion !== 'N/A' && !String(os).includes(String(osVersion))) {
    osDisplay = `${os} (${osVersion})`;
  }

  return {
    ip,
    hostname: pick(hostname),
    hostnameSource: hostnameSource || 'discovered',
    mac: pick(mac),
    vendor: pick(vendor, 'Desconhecido'),
    os: pick(osDisplay),
    osVersion: pick(osVersion),
    vm,
    vmType: virt.vmType,
    vmConfidence: virt.vmConfidence,
    vmEvidence: virt.vmEvidence,
    adDomain: pick(adDomain),
    description: pick(description),
    adDn: pick(adDn),
    adLocation: pick(adLocation),
    managedBy: pick(managedBy),
    adSamAccountName: pick(adSamAccountName),
    loggedOnUser: pick(loggedOnUser),
    lastLogon: pick(lastLogon),
    snmpSysDescr: snmpSysDescr || 'N/A',
    httpTitle: httpTitle || 'N/A',
    httpServer: httpServer || 'N/A',
    tlsSubject: tlsSubject || 'N/A',
    deviceHints,
    printerEvidence,
    openPrintPorts,
    enrichmentSources: sources,
    enrichmentNotes
  };
}

