const path = require('path');
const dgram = require('dgram');

const DATA_DIR = path.join(__dirname, 'data');
const VLAN_MAP_FILE = path.join(DATA_DIR, 'vlan-map.json');

const DEFAULT_VLAN_MAP = {
  version: 1,
  // When true: 172.20.100.x/24 → VLAN 100 (3º octeto)
  inferFromThirdOctet: true,
  // Optional label prefix
  labelPrefix: 'VLAN',
  // Explicit CIDR → VLAN mappings (highest priority)
