    enabled: false,
    community: 'public',
    switches: [],
    timeoutMs: 2500
  }
};

// Expanded hypervisor OUIs (MAC prefix without separators, uppercase)
const VM_MAC_OUIS = {
  // VMware
  '000569': 'VMware',
  '000C29': 'VMware',
  '001C14': 'VMware',
  '005056': 'VMware',
  // Microsoft Hyper-V / Azure
  '0003FF': 'Hyper-V',
  '00155D': 'Hyper-V',
  '7CEC79': 'Hyper-V',
  // VirtualBox
  '080027': 'VirtualBox',
  '0A0027': 'VirtualBox',
  // Xen
  '00163E': 'Xen',
  '000F4B': 'Xen',
  // QEMU/KVM / libvirt
  '525400': 'QEMU/KVM',
  // Parallels
  '001C42': 'Parallels',
  // Nutanix AHV
  '506B8D': 'Nutanix',
  // OpenStack/KVM
  'BC305B': 'OpenStack/KVM'
};

const VM_HOSTNAME_HINTS = [
  'vm-', '-vm', '_vm', 'vmware', 'hyperv', 'hyper-v', 'vdi-', '-vdi', 'citrix',
  'xen', 'kvm', 'qemu', 'proxmox', 'nutanix', 'ahv-', 'esx',
  'vcenter', 'vcsa', 'guest', 'clone',
  // Acesso remoto / VDI / RDS (muito comum em hospitais — quase sempre VM)
  'acessoremoto', 'acesso-remoto', 'acesso_remoto', 'remoteapp', 'rds-', '-rds',
  'rdsh', 'rdsgw', 'terminalserver', 'terminal-server', 'termserv', 'xenapp',
  'xendesktop', 'horizon', 'view-', 'vdi', 'virtua'
];

const VM_OS_HINTS = [
  'hyper-v', 'vmware', 'virtual machine', 'virtualization',
  'xen', 'kvm', 'qemu', 'parallels', 'nutanix'
];

const VM_VENDOR_HINTS = [
  'vmware', 'hyper-v', 'virtualbox', 'qemu', 'kvm', 'xen',
  'parallels', 'nutanix', 'proxmox', 'citrix', 'microsoft hyper-v'
];

/** Padrões de nome fortes para VM / hypervisor / RDS / acesso remoto */
const VM_STRONG_NAME_RE = /(^|[-_.])(vm|vdi|vd|guest|clone)\d{1,4}($|[-_.])|(^|[-_.])vm[-_.]?\d{1,4}($|[-_.])|vmware[-_.]?\d{1,4}|vmw[-_.]?\d{1,4}|srv[-_.]?vm|server[-_.]?vm|maq[-_]?virt|virt(ual)?[-_]?(desktop|server|pc|maq)|(acesso[-_]?remoto|remote[-_]?acesso|rds(h|gw|cb)?\d*|terminal[-_]?serv|termserv|citrix|xenapp|xendesktop|vdi[-_]?\d*)/i;

const VM_STRONG_VENDOR_NAME_RE = /(vmware|hyper[-_]?v|virtualbox|qemu|kvm|xen|proxmox|nutanix|citrix|vdi)/i;

/** OUs / DN no AD que indicam ambiente virtual */
const VM_AD_HINTS = [
  'virtual', 'vmware', 'hyper-v', 'hyperv', 'vdi', 'citrix', 'xen',
  'vnc', 'remoto', 'rds', 'virtua'
];

function ensureVlanMapFile() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
  if (!fs.existsSync(VLAN_MAP_FILE)) {
    fs.writeFileSync(VLAN_MAP_FILE, JSON.stringify(DEFAULT_VLAN_MAP, null, 2), 'utf8');
  }
}

function loadVlanMap() {
  ensureVlanMapFile();
  try {
    const raw = JSON.parse(fs.readFileSync(VLAN_MAP_FILE, 'utf8'));
    return {
      ...DEFAULT_VLAN_MAP,
      ...raw,
      subnets: { ...DEFAULT_VLAN_MAP.subnets, ...(raw.subnets || {}) },
      snmp: { ...DEFAULT_VLAN_MAP.snmp, ...(raw.snmp || {}) }
    };
  } catch (err) {
    console.warn('[VLAN] Falha ao ler vlan-map.json:', err.message);
    return { ...DEFAULT_VLAN_MAP };
  }
}

function normalizeMac(mac) {
  if (!mac || mac === 'N/A') return '';
  return String(mac).toUpperCase().replace(/[^0-9A-F]/g, '');
}

function isLocallyAdministeredMac(mac) {
  const hex = normalizeMac(mac);
  if (hex.length < 2) return false;
  const firstOctet = parseInt(hex.slice(0, 2), 16);
  // U/L bit (bit1) set → locally administered (common in VMs/clouds)
  return (firstOctet & 0x02) === 0x02;
}

function matchVmOui(mac) {
  const hex = normalizeMac(mac);
  if (hex.length < 6) return null;
  const p6 = hex.slice(0, 6);
  const p8 = hex.slice(0, 8);
  if (VM_MAC_OUIS[p8]) return VM_MAC_OUIS[p8];
  if (VM_MAC_OUIS[p6]) return VM_MAC_OUIS[p6];
  // AWS/GCP sometimes use 02:xx locally administered without known OUI
  return null;
}

/**
 * Strong VM detection with evidence + confidence.
 * Returns fields suitable for UI: vm, vmType, vmConfidence, vmEvidence
 */
function detectVirtualization(hostOrMac, vendorMaybe, osMaybe) {
  // Support legacy signature detectVM(mac, vendor, os) and object form
  let host;
  if (typeof hostOrMac === 'object' && hostOrMac !== null) {
    host = hostOrMac;
  } else {
    host = {
      mac: hostOrMac,
      vendor: vendorMaybe,
      os: osMaybe
    };
  }

  const mac = host.mac || '';
  const vendor = String(host.vendor || '');
  const os = String(host.os || '');
  const hostname = String(host.hostname || '');
  const description = String(host.description || '');
  const text = `${hostname} ${vendor} ${os} ${description} ${host.adDn || ''}`.toLowerCase();

  const evidence = [];
  let vmType = null;
  let score = 0;

  const ouiType = matchVmOui(mac);
  if (ouiType) {
    vmType = ouiType;
    score += 70;
    evidence.push(`MAC OUI=${ouiType}`);
  }

  for (const hint of VM_VENDOR_HINTS) {
    if (vendor.toLowerCase().includes(hint)) {
      score += 40;
      evidence.push(`Vendor=${hint}`);
      if (!vmType) {
        if (hint.includes('vmware')) vmType = 'VMware';
        else if (hint.includes('hyper')) vmType = 'Hyper-V';
        else if (hint.includes('virtualbox')) vmType = 'VirtualBox';
        else if (hint.includes('qemu') || hint.includes('kvm')) vmType = 'QEMU/KVM';
        else if (hint.includes('xen')) vmType = 'Xen';
        else if (hint.includes('parallels')) vmType = 'Parallels';
        else if (hint.includes('nutanix')) vmType = 'Nutanix';
        else vmType = hint;
      }
      break;
    }
  }

  for (const hint of VM_HOSTNAME_HINTS) {
    if (hostname.toLowerCase().includes(hint) || description.toLowerCase().includes(hint)) {
      score += 25;
      evidence.push(`Nome/desc contém "${hint}"`);
      break;
    }
  }

  // Nome forte (ex.: VMWARE-15, VM-001, ACESSOREMOTO04)
  if (VM_STRONG_NAME_RE.test(hostname) || VM_STRONG_NAME_RE.test(description)) {
    score += 45;
    evidence.push('Nome indica VM / VDI / acesso remoto');
    if (!vmType) {
      if (VM_STRONG_VENDOR_NAME_RE.test(hostname) || VM_STRONG_VENDOR_NAME_RE.test(description)) {
        vmType = 'VM (nome/hipervisor)';
      } else {
        vmType = 'VM (acesso remoto / RDS)';
      }
    }
  }

  // Nomes explícitos de plataformas de virtualização merecem peso alto mesmo sem MAC.
  // Ex.: VMWARE-15 pode vir sem OUI porque está fora do domínio/ARP local.
  if (VM_STRONG_VENDOR_NAME_RE.test(hostname) || VM_STRONG_VENDOR_NAME_RE.test(description)) {
    score += 35;
    evidence.push('Nome menciona plataforma de virtualização');
    if (!vmType) {
      if (/vmware/i.test(`${hostname} ${description}`)) vmType = 'VMware';
      else if (/hyper[-_]?v/i.test(`${hostname} ${description}`)) vmType = 'Hyper-V';
      else if (/virtualbox/i.test(`${hostname} ${description}`)) vmType = 'VirtualBox';
      else if (/qemu|kvm/i.test(`${hostname} ${description}`)) vmType = 'QEMU/KVM';
      else vmType = 'VM (nome/hipervisor)';
    }
  }

  // OU / DN no Active Directory
  const adBlob = `${host.adDn || ''} ${host.adLocation || ''}`.toLowerCase();
  for (const hint of VM_AD_HINTS) {
    if (adBlob.includes(hint)) {
      score += 25;
      evidence.push(`AD DN/local contém "${hint}"`);
      if (!vmType && (hint === 'vnc' || hint === 'remoto' || hint === 'rds')) {
        vmType = 'VM (AD/OU remoto)';
      }
      break;
    }
  }

  for (const hint of VM_OS_HINTS) {
    if (os.toLowerCase().includes(hint)) {
      score += 30;
      evidence.push(`OS menciona ${hint}`);
      break;
    }
  }

  // Locally administered MAC without strong physical NIC vendor → likely VM/cloud
  if (isLocallyAdministeredMac(mac) && !ouiType) {
    const physVendors = ['dell', 'hp', 'hewlett', 'lenovo', 'intel', 'realtek', 'broadcom', 'apple', 'cisco'];
    const looksPhysical = physVendors.some(v => vendor.toLowerCase().includes(v));
    if (!looksPhysical) {
      score += 20;
      evidence.push('MAC localmente administrado (bit U/L)');
      if (!vmType) vmType = 'Virtual/Cloud (LAA MAC)';
    }
  }

  // Hyper-V guest often shows Microsoft as vendor with 00-15-5D already covered
  if (text.includes('hyper-v') || text.includes('virtual machine') || text.includes('máquina virtual')) {
    score += 20;
    evidence.push('Texto indica máquina virtual');
  }

  let vm = 'Não';
  let vmConfidence = 'baixa';
  if (score >= 55) {
    // Limiar um pouco mais sensível para ambientes hospitalares (AD + nomes RDS)
    vm = 'Sim';
    vmConfidence = score >= 90 ? 'alta' : 'média';
  } else if (score >= 28) {
    vm = 'Provável';
    vmConfidence = 'média';
  }

  return {
    vm,
    vmType: vm === 'Não' ? 'N/A' : (vmType || 'Desconhecido'),
    vmConfidence,
    vmEvidence: evidence,
    vmScore: score
  };
}

// ---- VLAN helpers ----

function ipToLong(ip) {
  return ip.split('.').reduce((acc, o) => (acc << 8) + (parseInt(o, 10) || 0), 0) >>> 0;
}

function cidrContains(cidr, ip) {
  const [base, bitsStr] = String(cidr).split('/');
  const bits = parseInt(bitsStr, 10);
  if (!base || Number.isNaN(bits)) return false;
  const mask = bits === 0 ? 0 : (~0 << (32 - bits)) >>> 0;
  return ((ipToLong(ip) & mask) >>> 0) === ((ipToLong(base) & mask) >>> 0);
}

function getSubnetCidr24(ip) {
  const p = String(ip || '').split('.');
  if (p.length !== 4) return 'N/A';
  return `${p[0]}.${p[1]}.${p[2]}.0/24`;
}

function parseVlanFromText(...parts) {
  const text = parts.filter(Boolean).join(' ');
  if (!text) return null;

  const patterns = [
    /\bvlan[\s:_-]*([0-9]{1,4})\b/i,
    /\bv[\s-]?([0-9]{1,4})\b/i,
    /\bid[\s:_-]*vlan[\s:_-]*([0-9]{1,4})\b/i
  ];

  for (const re of patterns) {
    const m = text.match(re);
    if (m) {
      const id = parseInt(m[1], 10);
      if (id >= 1 && id <= 4094) {
        return { id, name: null, source: 'texto (hostname/AD/descrição)' };
      }
    }
  }
  return null;
}

function resolveVlanFromMap(ip, vlanMap) {
  const subnets = vlanMap.subnets || {};
  // Prefer longest prefix (most specific)
  const entries = Object.entries(subnets)
    .map(([cidr, meta]) => {
      const bits = parseInt(String(cidr).split('/')[1], 10) || 0;
      return { cidr, meta, bits };
    })
    .sort((a, b) => b.bits - a.bits);

  for (const e of entries) {
    if (cidrContains(e.cidr, ip)) {
      const id = e.meta.id != null ? e.meta.id : e.meta.vlan;
      return {
        id,
        name: e.meta.name || null,
        site: e.meta.site || null,
        source: `mapa (${e.cidr})`,
        subnet: e.cidr
      };
    }
  }
  return null;
}

function resolveVlanFromThirdOctet(ip, vlanMap) {
  if (!vlanMap.inferFromThirdOctet) return null;
  const p = String(ip || '').split('.');
  if (p.length !== 4) return null;
  const third = parseInt(p[2], 10);
  if (!Number.isFinite(third) || third < 1 || third > 4094) return null;
  // Skip obvious non-VLAN patterns? Keep — enterprise often maps VLAN==3rd octet
  return {
    id: third,
    name: null,
    source: 'inferido (3º octeto = VLAN ID)',
    subnet: getSubnetCidr24(ip)
  };
}

function formatVlanLabel(info, vlanMap) {
  if (!info || info.id == null) return 'N/A';
  const prefix = vlanMap.labelPrefix || 'VLAN';
  const namePart = info.name ? ` (${info.name})` : '';
  return `${prefix} ${info.id}${namePart}`;
}

/**
 * Resolve VLAN for one host using layered strategy.
 */
function resolveHostVlan(host, vlanMap, snmpByMac = new Map()) {
  const map = vlanMap || loadVlanMap();

  // 1) Explicit subnet map
  let info = resolveVlanFromMap(host.ip, map);
  if (info) {
    return {
      vlan: formatVlanLabel(info, map),
      vlanId: info.id,
      vlanName: info.name || 'N/A',
      vlanSource: info.source,
      vlanSite: info.site || 'N/A'
    };
  }

  // 2) SNMP MAC→VLAN (if preloaded)
  const macKey = normalizeMac(host.mac);
  if (macKey && snmpByMac.has(macKey)) {
    const id = snmpByMac.get(macKey);
    info = { id, name: null, source: 'SNMP (switch Q-BRIDGE)' };
    return {
      vlan: formatVlanLabel(info, map),
      vlanId: id,
      vlanName: 'N/A',
      vlanSource: info.source,
      vlanSite: 'N/A'
    };
  }

  // 3) Text hints in AD/hostname/description/location
  info = parseVlanFromText(host.hostname, host.description, host.adLocation, host.adDn);
  if (info) {
    return {
      vlan: formatVlanLabel(info, map),
      vlanId: info.id,
      vlanName: 'N/A',
      vlanSource: info.source,
      vlanSite: 'N/A'
    };
  }

  // 4) Third-octet heuristic
  info = resolveVlanFromThirdOctet(host.ip, map);
  if (info) {
    return {
      vlan: formatVlanLabel(info, map),
      vlanId: info.id,
      vlanName: 'N/A',
      vlanSource: info.source,
      vlanSite: 'N/A'
    };
  }

  // 5) Fallback: subnet label (not a real 802.1Q VLAN)
  const subnet = host.subnet || getSubnetCidr24(host.ip);
  return {
    vlan: `Sub-rede ${subnet}`,
    vlanId: null,
    vlanName: 'N/A',
    vlanSource: 'fallback (sem mapa VLAN)',
    vlanSite: 'N/A'
  };
}

/**
 * Assign VLAN fields to all hosts. Optionally tries SNMP if configured.
 */
async function assignVlansToHosts(hosts, options = {}) {
  const vlanMap = options.vlanMap || loadVlanMap();
  let snmpByMac = new Map();
  let snmpNote = null;

  if (vlanMap.snmp && vlanMap.snmp.enabled && Array.isArray(vlanMap.snmp.switches) && vlanMap.snmp.switches.length > 0) {
    try {
      snmpByMac = await querySwitchesMacVlan(vlanMap.snmp);
      snmpNote = `SNMP: ${snmpByMac.size} MAC(s) com VLAN`;
    } catch (err) {
      snmpNote = `SNMP falhou: ${err.message}`;
    }
  }

  const counts = {};
  for (const host of hosts) {
    const resolved = resolveHostVlan(host, vlanMap, snmpByMac);
    Object.assign(host, resolved);
    counts[host.vlan] = (counts[host.vlan] || 0) + 1;
  }

  return { vlanMap, counts, snmpNote };
}

/**
 * Minimal SNMP GETNEXT walker for Q-BRIDGE-MIB dot1qTpFdbPort is complex;
 * here we attempt community 'public' sysName only as connectivity check placeholder.
 * Full MAC→VLAN needs SNMPv2 walk of 1.3.6.1.2.1.17.7.1.2.2.1.2 — implemented lightly.
 */
function snmpGetNext(ip, community, oidNums, timeoutMs) {
  return new Promise((resolve) => {
    // Very small SNMPv1 GET for a single OID — used as probe; walk not fully implemented
    // For production VLAN map, prefer configuring data/vlan-map.json subnets.
    resolve(null);
  });
}

async function querySwitchesMacVlan(snmpConfig) {
  // Placeholder map: without a full SNMP library, we don't invent VLANs.
  // Users should fill vlan-map.json. This returns empty unless future SNMP walk is added.
  const map = new Map();
  if (!snmpConfig || !snmpConfig.enabled) return map;
  // Intentionally empty — subnet map + 3rd octet are the strong offline strategies.
  // Log once via caller.
  return map;
}

function applyVirtualizationToHost(host) {
  const result = detectVirtualization(host);
  host.vm = result.vm;
  host.vmType = result.vmType;
  host.vmConfidence = result.vmConfidence;
  host.vmEvidence = result.vmEvidence;
  return result;
}

module.exports = {
  detectVirtualization,
  applyVirtualizationToHost,
  assignVlansToHosts,
  resolveHostVlan,
  loadVlanMap,
  ensureVlanMapFile,
  getSubnetCidr24,
  VLAN_MAP_FILE,
  DEFAULT_VLAN_MAP
};

function detectVirtualization(hostOrMac, vendorMaybe, osMaybe) {
  // Support legacy signature detectVM(mac, vendor, os) and object form
  let host;
  if (typeof hostOrMac === 'object' && hostOrMac !== null) {
    host = hostOrMac;
  } else {
    host = {
      mac: hostOrMac,
      vendor: vendorMaybe,
      os: osMaybe
    };
  }

  const mac = host.mac || '';
  const vendor = String(host.vendor || '');
  const os = String(host.os || '');
  const hostname = String(host.hostname || '');
  const description = String(host.description || '');
  const text = `${hostname} ${vendor} ${os} ${description} ${host.adDn || ''}`.toLowerCase();

  const evidence = [];
  let vmType = null;
  let score = 0;

  const ouiType = matchVmOui(mac);
  if (ouiType) {
    vmType = ouiType;
    score += 70;
    evidence.push(`MAC OUI=${ouiType}`);
  }

  for (const hint of VM_VENDOR_HINTS) {
    if (vendor.toLowerCase().includes(hint)) {
      score += 40;
      evidence.push(`Vendor=${hint}`);
      if (!vmType) {
        if (hint.includes('vmware')) vmType = 'VMware';
        else if (hint.includes('hyper')) vmType = 'Hyper-V';
        else if (hint.includes('virtualbox')) vmType = 'VirtualBox';
        else if (hint.includes('qemu') || hint.includes('kvm')) vmType = 'QEMU/KVM';
        else if (hint.includes('xen')) vmType = 'Xen';
        else if (hint.includes('parallels')) vmType = 'Parallels';
        else if (hint.includes('nutanix')) vmType = 'Nutanix';
        else vmType = hint;
      }
      break;
    }
  }

  for (const hint of VM_HOSTNAME_HINTS) {
    if (hostname.toLowerCase().includes(hint) || description.toLowerCase().includes(hint)) {
      score += 25;
      evidence.push(`Nome/desc contém "${hint}"`);
      break;
    }
  }

  // Nome forte (ex.: VMWARE-15, VM-001, ACESSOREMOTO04)
  if (VM_STRONG_NAME_RE.test(hostname) || VM_STRONG_NAME_RE.test(description)) {
    score += 45;
    evidence.push('Nome indica VM / VDI / acesso remoto');
    if (!vmType) {
      if (VM_STRONG_VENDOR_NAME_RE.test(hostname) || VM_STRONG_VENDOR_NAME_RE.test(description)) {
        vmType = 'VM (nome/hipervisor)';
      } else {
        vmType = 'VM (acesso remoto / RDS)';
      }
    }
  }

  // Nomes explícitos de plataformas de virtualização merecem peso alto mesmo sem MAC.
  // Ex.: VMWARE-15 pode vir sem OUI porque está fora do domínio/ARP local.
  if (VM_STRONG_VENDOR_NAME_RE.test(hostname) || VM_STRONG_VENDOR_NAME_RE.test(description)) {
    score += 35;
    evidence.push('Nome menciona plataforma de virtualização');
    if (!vmType) {
      if (/vmware/i.test(`${hostname} ${description}`)) vmType = 'VMware';
      else if (/hyper[-_]?v/i.test(`${hostname} ${description}`)) vmType = 'Hyper-V';
      else if (/virtualbox/i.test(`${hostname} ${description}`)) vmType = 'VirtualBox';
      else if (/qemu|kvm/i.test(`${hostname} ${description}`)) vmType = 'QEMU/KVM';
      else vmType = 'VM (nome/hipervisor)';
    }
  }

  // OU / DN no Active Directory
  const adBlob = `${host.adDn || ''} ${host.adLocation || ''}`.toLowerCase();
  for (const hint of VM_AD_HINTS) {
    if (adBlob.includes(hint)) {
      score += 25;
      evidence.push(`AD DN/local contém "${hint}"`);
      if (!vmType && (hint === 'vnc' || hint === 'remoto' || hint === 'rds')) {
        vmType = 'VM (AD/OU remoto)';
      }
      break;
    }
  }

  for (const hint of VM_OS_HINTS) {
    if (os.toLowerCase().includes(hint)) {
      score += 30;
      evidence.push(`OS menciona ${hint}`);
      break;
    }
  }

  // Locally administered MAC without strong physical NIC vendor → likely VM/cloud
  if (isLocallyAdministeredMac(mac) && !ouiType) {
    const physVendors = ['dell', 'hp', 'hewlett', 'lenovo', 'intel', 'realtek', 'broadcom', 'apple', 'cisco'];
    const looksPhysical = physVendors.some(v => vendor.toLowerCase().includes(v));
    if (!looksPhysical) {
      score += 20;
      evidence.push('MAC localmente administrado (bit U/L)');
      if (!vmType) vmType = 'Virtual/Cloud (LAA MAC)';
    }
  }

  // Hyper-V guest often shows Microsoft as vendor with 00-15-5D already covered
  if (text.includes('hyper-v') || text.includes('virtual machine') || text.includes('máquina virtual')) {
    score += 20;
    evidence.push('Texto indica máquina virtual');
  }

  let vm = 'Não';
  let vmConfidence = 'baixa';
  if (score >= 55) {
    // Limiar um pouco mais sensível para ambientes hospitalares (AD + nomes RDS)
    vm = 'Sim';
    vmConfidence = score >= 90 ? 'alta' : 'média';
  } else if (score >= 28) {
    vm = 'Provável';
    vmConfidence = 'média';
  }

  return {
    vm,
    vmType: vm === 'Não' ? 'N/A' : (vmType || 'Desconhecido'),
    vmConfidence,
    vmEvidence: evidence,
    vmScore: score
  };
}

/**
 * Detecção urgente de loop de rede via SNMP (Aruba / Cisco / Intelbras / D-Link).
 * IF-MIB · BRIDGE-MIB (FDB/MAC flap) · STP · LLDP · CDP · correlação multi-switch.
 */
const fs = require('fs');
const path = require('path');
const snmp = require('net-snmp');

const DATA_DIR = path.join(__dirname, 'data');
const CONFIG_FILE = path.join(DATA_DIR, 'loop-monitor.json');
const ALERTS_FILE = path.join(DATA_DIR, 'loop-alerts.json');

const OID = {
  sysDescr: '1.3.6.1.2.1.1.1.0',
  sysName: '1.3.6.1.2.1.1.5.0',
  ifDescr: '1.3.6.1.2.1.2.2.1.2',
  ifOperStatus: '1.3.6.1.2.1.2.2.1.8',
  ifInNUcastPkts: '1.3.6.1.2.1.2.2.1.12',
  ifInErrors: '1.3.6.1.2.1.2.2.1.14',
  ifName: '1.3.6.1.2.1.31.1.1.1.1',
  ifHCInBroadcastPkts: '1.3.6.1.2.1.31.1.1.1.9',
  ifHCInMulticastPkts: '1.3.6.1.2.1.31.1.1.1.8',
  dot1dTpFdbPort: '1.3.6.1.2.1.17.4.3.1.2',
  dot1dBasePortIfIndex: '1.3.6.1.2.1.17.1.4.1.2',
  dot1dStpPortState: '1.3.6.1.2.1.17.2.15.1.3',
  lldpRemSysName: '1.0.8802.1.1.2.1.4.1.1.9',
  lldpLocPortIfIndex: '1.0.8802.1.1.2.1.4.9.1.3',
  cdpCacheDeviceId: '1.3.6.1.4.1.9.9.23.1.2.1.1.6',
  cdpCacheDevicePort: '1.3.6.1.4.1.9.9.23.1.2.1.1.8'
};

const STP_STATE = {
  1: 'disabled',
  2: 'blocking',
  3: 'listening',
  4: 'learning',
  5: 'forwarding',
  6: 'broken'
};

const DEFAULT_CONFIG = {
  version: 1,
  community: 'public',
  timeoutMs: 3500,
  retries: 1,
  pollIntervalSec: 12,
  quickGapSec: 5,
  maxAlerts: 200,
  thresholds: {
    broadcastPerSecWarn: 4000,
    broadcastPerSecCrit: 40000,
    multicastPerSecWarn: 8000,
    errorDeltaWarn: 50,
    macFlapMinMoves: 3
  },
  switches: []
};

/** @type {ReturnType<typeof loadConfig>} */
let runtimeConfig = null;
/** @type {Map<string, object>} previous samples by switch id */
const prevSamples = new Map();
/** @type {Map<string, Map<string, number>>} mac -> portIfIndex history for flap */
const macLastPort = new Map();
/** @type {Map<string, number>} macFlap counts per switch:ifIndex */
const flapCounters = new Map();
/** @type {Map<string, object>} última localização global de cada MAC */
const globalMacLocation = new Map();
/** @type {Map<string, { atMs: number, atIso: string, score: number }>} primeira porta que disparou alerta */
const originFirstTrigger = new Map();

let monitorTimer = null;
let monitorRunning = false;
let lastPollAt = null;
let lastPollSummary = null;
let onAlertCallback = null;
let onStatusCallback = null;

function ensureDataDir() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
}

function writeJsonAtomic(file, data) {
  ensureDataDir();
  const tmp = `${file}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(data, null, 2), 'utf8');
  fs.renameSync(tmp, file);
}

function loadConfig() {
  ensureDataDir();
  if (!fs.existsSync(CONFIG_FILE)) {
    writeJsonAtomic(CONFIG_FILE, DEFAULT_CONFIG);
    runtimeConfig = structuredClone(DEFAULT_CONFIG);
    return runtimeConfig;
  }
  try {
    const raw = JSON.parse(fs.readFileSync(CONFIG_FILE, 'utf8'));
    runtimeConfig = {
      ...DEFAULT_CONFIG,
      ...raw,
      thresholds: { ...DEFAULT_CONFIG.thresholds, ...(raw.thresholds || {}) },
      switches: Array.isArray(raw.switches) ? raw.switches : []
    };
  } catch {
    runtimeConfig = structuredClone(DEFAULT_CONFIG);
  }
  return runtimeConfig;
}

function getConfig() {
  return runtimeConfig || loadConfig();
}

function saveConfig(partial) {
  const cur = getConfig();
  const next = {
    ...cur,
    ...partial,
    thresholds: { ...cur.thresholds, ...(partial.thresholds || {}) },
    switches: Array.isArray(partial.switches) ? partial.switches : cur.switches
  };
  writeJsonAtomic(CONFIG_FILE, next);
  runtimeConfig = next;
  return next;
}

function loadAlerts() {
  ensureDataDir();
  if (!fs.existsSync(ALERTS_FILE)) return { alerts: [], updatedAt: null };
  try {
    return JSON.parse(fs.readFileSync(ALERTS_FILE, 'utf8'));
  } catch {
    return { alerts: [], updatedAt: null };
  }
}

function saveAlerts(alerts) {
  const cfg = getConfig();
  const trimmed = alerts.slice(0, cfg.maxAlerts || 200);
  writeJsonAtomic(ALERTS_FILE, { alerts: trimmed, updatedAt: new Date().toISOString() });
  return trimmed;
}

function pushAlert(alert) {
  const store = loadAlerts();
  const list = [alert, ...(store.alerts || [])];
  saveAlerts(list);
  if (typeof onAlertCallback === 'function') {
    try { onAlertCallback(alert); } catch { /* ignore */ }
  }
  return alert;
}

function clearAlerts() {
  writeJsonAtomic(ALERTS_FILE, { alerts: [], updatedAt: new Date().toISOString() });
  return { ok: true };
}

function setEventHandlers({ onAlert, onStatus } = {}) {
  if (onAlert) onAlertCallback = onAlert;
  if (onStatus) onStatusCallback = onStatus;
}

function emitStatus(payload) {
  if (typeof onStatusCallback === 'function') {
    try { onStatusCallback(payload); } catch { /* ignore */ }
  }
}

function uid() {
  return `sw_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 7)}`;
}

function detectVendor(sysDescr = '') {
  const t = String(sysDescr).toLowerCase();
  if (t.includes('aruba') || t.includes('procurve') || t.includes('hpe') || t.includes('hewlett')) return 'aruba';
  if (t.includes('cisco') || t.includes('ios') || t.includes('catalyst') || t.includes('nx-os')) return 'cisco';
  if (t.includes('intelbras')) return 'intelbras';
  if (t.includes('d-link') || t.includes('dlink')) return 'dlink';
  return 'generic';
}

function snmpSession(ip, community, timeoutMs, retries) {
  return snmp.createSession(ip, community || 'public', {
    timeout: timeoutMs || 3500,
    retries: retries == null ? 1 : retries,
    version: snmp.Version2c
  });
}

function snmpGet(session, oids) {
  return new Promise((resolve) => {
    session.get(oids, (err, varbinds) => {
      if (err) return resolve({ err: err.message, map: {} });
      const map = {};
      for (const vb of varbinds || []) {
        if (snmp.isVarbindError(vb)) continue;
        map[vb.oid] = vb.value;
      }
      resolve({ err: null, map });
    });
  });
}

function snmpWalk(session, oid, maxRep = 40) {
  return new Promise((resolve) => {
    const rows = [];
    session.subtree(
      oid,
      maxRep,
      (varbinds) => {
        for (const vb of varbinds) {
          if (snmp.isVarbindError(vb)) continue;
          rows.push({ oid: vb.oid, value: vb.value });
        }
      },
      (err) => {
        // endOfMibView / noSuchName are common on some vendors — treat as empty table
        if (err && !/NoSuch|endOfMib|RequestTimedOut/i.test(String(err))) {
          return resolve({ err: err.toString(), rows });
        }
        resolve({ err: null, rows });
      }
    );
  });
}

function toNumber(val) {
  if (val == null) return 0;
  if (typeof val === 'number') return val;
  if (typeof val === 'bigint') return Number(val);
  if (Buffer.isBuffer(val)) {
    if (val.length <= 6) {
      let n = 0;
      for (const b of val) n = (n * 256) + b;
      return n;
    }
    // Counter64 as Buffer
    try {
      return Number(BigInt('0x' + val.toString('hex')));
    } catch {
      return 0;
    }
  }
  const n = Number(val);
  return Number.isFinite(n) ? n : 0;
}

function oidIndex(oid, base) {
  const prefix = `${base}.`;
  if (!oid.startsWith(prefix)) return null;
  return oid.slice(prefix.length);
}

function decodeMacFromOidSuffix(suffix) {
  const parts = String(suffix).split('.').map((x) => parseInt(x, 10));
  if (parts.length < 6) return null;
  const macParts = parts.slice(-6);
  if (macParts.some((n) => Number.isNaN(n) || n < 0 || n > 255)) return null;
  return macParts.map((n) => n.toString(16).padStart(2, '0')).join(':');
}

function bufToString(val) {
  if (val == null) return '';
  if (typeof val === 'string') return val;
  if (Buffer.isBuffer(val)) return val.toString('utf8').replace(/\0/g, '').trim();
  return String(val);
}

function buildIfaceMap(walks) {
  const ifaces = new Map();
  const ensure = (idx) => {
    if (!ifaces.has(idx)) {
      ifaces.set(idx, {
        ifIndex: idx,
        name: `if${idx}`,
        descr: '',
        operStatus: null,
        inNUcast: 0,
        inBroadcast: 0,
        inMulticast: 0,
        inErrors: 0
      });
    }
    return ifaces.get(idx);
  };

  for (const row of walks.ifName || []) {
    const idx = oidIndex(row.oid, OID.ifName);
    if (!idx) continue;
    const iface = ensure(idx);
    const name = bufToString(row.value);
    if (name) iface.name = name;
  }
  for (const row of walks.ifDescr || []) {
    const idx = oidIndex(row.oid, OID.ifDescr);
    if (!idx) continue;
    const iface = ensure(idx);
    iface.descr = bufToString(row.value);
    if (!iface.name || iface.name === `if${idx}`) iface.name = iface.descr || iface.name;
  }
  for (const row of walks.ifOperStatus || []) {
    const idx = oidIndex(row.oid, OID.ifOperStatus);
    if (!idx) continue;
    ensure(idx).operStatus = toNumber(row.value);
  }
  for (const row of walks.ifInNUcastPkts || []) {
    const idx = oidIndex(row.oid, OID.ifInNUcastPkts);
    if (!idx) continue;
    ensure(idx).inNUcast = toNumber(row.value);
  }
  for (const row of walks.ifInErrors || []) {
    const idx = oidIndex(row.oid, OID.ifInErrors);
    if (!idx) continue;
    ensure(idx).inErrors = toNumber(row.value);
  }
  for (const row of walks.ifHCInBroadcastPkts || []) {
    const idx = oidIndex(row.oid, OID.ifHCInBroadcastPkts);
    if (!idx) continue;
    ensure(idx).inBroadcast = toNumber(row.value);
  }
  for (const row of walks.ifHCInMulticastPkts || []) {
    const idx = oidIndex(row.oid, OID.ifHCInMulticastPkts);
    if (!idx) continue;
    ensure(idx).inMulticast = toNumber(row.value);
  }

  return ifaces;
}

function isUplinkLike(name = '') {
  const n = String(name).toLowerCase();
  return /uplink|trunk|lag|po\d|port-channel|vl\d|vlan|mgmt|management|stack|stacking/.test(n);
}

function getPortName(sample, ifIndex) {
  const iface = (sample.ifaces || []).find((i) => String(i.ifIndex) === String(ifIndex));
  return iface ? (iface.name || iface.descr || `if${ifIndex}`) : `if${ifIndex}`;
}

function buildStpByIfIndex(stpByBridgePort, bridgePortToIf) {
  const stpByIfIndex = new Map();
  for (const [bp, state] of stpByBridgePort.entries()) {
    const ifIdx = bridgePortToIf.get(bp);
    if (ifIdx != null) stpByIfIndex.set(String(ifIdx), state);
  }
  return stpByIfIndex;
}

function parseLldpNeighbors(remSysNameRows, locPortIfRows) {
  const locPortToIf = new Map();
  for (const row of locPortIfRows || []) {
    const suffix = oidIndex(row.oid, OID.lldpLocPortIfIndex);
    if (!suffix) continue;
    const parts = suffix.split('.');
    const locPortNum = parts[parts.length - 1];
    locPortToIf.set(locPortNum, String(toNumber(row.value)));
  }

  const byIf = new Map();
  for (const row of remSysNameRows || []) {
    const suffix = oidIndex(row.oid, OID.lldpRemSysName);
    if (!suffix) continue;
    const parts = suffix.split('.');
    if (parts.length < 2) continue;
    const locPortNum = parts[parts.length - 2];
    const ifIndex = locPortToIf.get(locPortNum);
    if (!ifIndex) continue;
    const remoteName = bufToString(row.value);
    if (!remoteName) continue;
    if (!byIf.has(ifIndex)) byIf.set(ifIndex, []);
    byIf.get(ifIndex).push({ remoteName, protocol: 'lldp' });
  }
  return byIf;
}

function parseCdpNeighbors(cdpDeviceId, cdpDevicePort) {
  const entries = new Map();
  for (const row of cdpDeviceId.rows || []) {
    const suffix = oidIndex(row.oid, OID.cdpCacheDeviceId);
    if (!suffix) continue;
    const ifIndex = suffix.split('.')[0];
    entries.set(suffix, { ifIndex, remoteName: bufToString(row.value) });
  }
  for (const row of cdpDevicePort.rows || []) {
    const suffix = oidIndex(row.oid, OID.cdpCacheDevicePort);
    if (!suffix) continue;
    const entry = entries.get(suffix);
    if (entry) entry.remotePort = bufToString(row.value);
  }

  const byIf = new Map();
  for (const entry of entries.values()) {
    if (!entry.remoteName) continue;
    const ifIndex = String(entry.ifIndex);
    if (!byIf.has(ifIndex)) byIf.set(ifIndex, []);
    byIf.get(ifIndex).push({
      remoteName: entry.remoteName,
      remotePort: entry.remotePort || '',
      protocol: 'cdp'
    });
  }
  return byIf;
}

function mergeNeighborMaps(...maps) {
  const out = new Map();
  for (const m of maps) {
    for (const [ifIndex, list] of m.entries()) {
      if (!out.has(ifIndex)) out.set(ifIndex, []);
      out.get(ifIndex).push(...list);
    }
  }
  return out;
}

function buildMacGlobalIndex(samples) {
  const current = new Map();
  const crossFlaps = [];
  const multiHomed = [];
  const crossFlapsByPort = new Map();
  const multiHomedByPort = new Map();

  for (const sample of samples) {
    if (!sample.ok) continue;
    for (const [mac, ifIndex] of sample.macMap.entries()) {
      const loc = {
        mac,
        switchId: sample.switchId,
        switchName: sample.name,
        switchIp: sample.ip,
        ifIndex: String(ifIndex),
        port: getPortName(sample, ifIndex)
      };

      if (current.has(mac)) {
        const prev = current.get(mac);
        if (prev.switchId !== loc.switchId || prev.ifIndex !== loc.ifIndex) {
          multiHomed.push({ mac, locations: [prev, loc] });
          for (const l of [prev, loc]) {
            const key = `${l.switchId}:${l.ifIndex}`;
            multiHomedByPort.set(key, (multiHomedByPort.get(key) || 0) + 1);
          }
        }
      }

      const prevGlobal = globalMacLocation.get(mac);
      if (prevGlobal && (prevGlobal.switchId !== loc.switchId || String(prevGlobal.ifIndex) !== String(ifIndex))) {
        crossFlaps.push({ mac, from: prevGlobal, to: loc });
        const toKey = `${loc.switchId}:${loc.ifIndex}`;
        crossFlapsByPort.set(toKey, (crossFlapsByPort.get(toKey) || 0) + 1);
        const fromKey = `${prevGlobal.switchId}:${prevGlobal.ifIndex}`;
        crossFlapsByPort.set(fromKey, (crossFlapsByPort.get(fromKey) || 0) + 1);
      }

      current.set(mac, loc);
    }
  }

  return { current, crossFlaps, multiHomed, crossFlapsByPort, multiHomedByPort };
}

function buildTopologySummary(samples) {
  const links = [];
  for (const sample of samples) {
    if (!sample.ok || !sample.neighborsByIf) continue;
    for (const [ifIndex, neighbors] of sample.neighborsByIf.entries()) {
      const portName = getPortName(sample, ifIndex);
      for (const n of neighbors) {
        links.push({
          localSwitch: sample.name,
          localIp: sample.ip,
          localPort: portName,
          remoteName: n.remoteName,
          remotePort: n.remotePort || '',
          protocol: n.protocol
        });
      }
    }
  }
  return links.slice(0, 80);
}

function stpStateLabel(code) {
  return STP_STATE[code] || (code != null ? String(code) : '—');
}

function recordFirstTrigger(switchId, ifIndex, score) {
  const key = `${switchId}:${ifIndex}`;
  if (originFirstTrigger.has(key)) return;
  originFirstTrigger.set(key, {
    atMs: Date.now(),
    atIso: new Date().toISOString(),
    score
  });
}

function applyOriginRanking(allPorts, macGlobal) {
  const ranked = allPorts
    .filter((p) => p.score >= 30)
    .map((p) => {
      let originScore = p.score;
      const uplink = isUplinkLike(p.port);
      const neighbors = p.neighborCount || 0;

      if (!uplink) originScore += 12;
      if (p.crossSwitchFlaps > 0) originScore += 18 + Math.min(25, p.crossSwitchFlaps * 6);
      if (p.multiHomedMacs > 0) originScore += 10 + Math.min(15, p.multiHomedMacs * 3);
      if (p.stpState === 5 && !uplink && p.broadcastPerSec >= 1000) originScore += 12;
      if (p.stpState === 6) originScore += 20;
      if (p.stpState === 2) originScore -= 12;
      if (neighbors >= 2) originScore -= 8;
      if (uplink) originScore -= 10;

      const ft = originFirstTrigger.get(`${p.switchId}:${p.ifIndex}`);
      if (ft) {
        const ageSec = (Date.now() - ft.atMs) / 1000;
        if (ageSec <= 180) originScore += Math.max(5, 18 - Math.floor(ageSec / 15));
      }

      return { ...p, originScore: Math.min(150, Math.round(originScore)) };
    })
    .sort((a, b) => b.originScore - a.originScore);

  ranked.forEach((p, idx) => {
    p.originRank = idx + 1;
    if (idx === 0 && p.originScore >= 40) {
      p.isLikelyOrigin = true;
      const ft = originFirstTrigger.get(`${p.switchId}:${p.ifIndex}`);
      p.probabilityOrigin = `provável origem (#1 · score ${p.originScore}${ft ? ` · desde ${new Date(ft.atIso).toLocaleTimeString('pt-BR')}` : ''})`;
    } else if (p.originRank <= 3) {
      p.probabilityOrigin = `suspeita #${p.originRank} (score origem ${p.originScore})`;
    } else {
      p.probabilityOrigin = p.originScore >= 55
        ? (isUplinkLike(p.port) ? 'média (uplink)' : 'média (borda)')
        : 'baixa';
    }
  });

  return ranked;
}

function computeLikelyOrigin(rankedPorts, macGlobal) {
  const top = rankedPorts[0] || null;
  if (!top) {
    return {
      ok: false,
      message: 'Nenhuma porta candidata a origem nesta rodada.',
      crossFlapCount: macGlobal.crossFlaps.length,
      multiHomedCount: macGlobal.multiHomed.length
    };
  }

  const ft = originFirstTrigger.get(`${top.switchId}:${top.ifIndex}`);
  return {
    ok: true,
    switchName: top.switchName,
    switchIp: top.switchIp,
    port: top.port,
    score: top.score,
    originScore: top.originScore,
    firstSeenAt: ft ? ft.atIso : top.at,
    stpState: stpStateLabel(top.stpState),
    crossFlapCount: macGlobal.crossFlaps.length,
    multiHomedCount: macGlobal.multiHomed.length,
    message: `Origem provável: ${top.switchName || top.switchIp} · ${top.port}` +
      (ft ? ` (alerta desde ${new Date(ft.atIso).toLocaleString('pt-BR')})` : '') +
      (macGlobal.crossFlaps.length ? ` · ${macGlobal.crossFlaps.length} MAC(s) saltaram entre switches` : ''),
    topCandidates: rankedPorts.slice(0, 5).map((p) => ({
      switchName: p.switchName,
      switchIp: p.switchIp,
      port: p.port,
      originScore: p.originScore,
      score: p.score
    }))
  };
}

function scoreSeverity(score) {
  if (score >= 80) return { level: 'critico', label: 'Suspeita grave de loop', emoji: '🔴' };
  if (score >= 55) return { level: 'alto', label: 'Suspeita de loop', emoji: '🟠' };
  if (score >= 30) return { level: 'medio', label: 'Atenção', emoji: '🟡' };
  return { level: 'ok', label: 'Normal', emoji: '🟢' };
}

async function pollSwitch(sw, cfg) {
  const community = sw.community || cfg.community || 'public';
  const session = snmpSession(sw.ip, community, cfg.timeoutMs, cfg.retries);
  const started = Date.now();

  try {
    const meta = await snmpGet(session, [OID.sysName, OID.sysDescr]);
    const sysName = bufToString(meta.map[OID.sysName]) || sw.name || sw.ip;
    const sysDescr = bufToString(meta.map[OID.sysDescr]);
    const vendor = sw.vendor && sw.vendor !== 'auto' ? sw.vendor : detectVendor(sysDescr);

    const [
      ifName,
      ifDescr,
      ifOperStatus,
      ifInNUcastPkts,
      ifInErrors,
      ifHCInBroadcastPkts,
      ifHCInMulticastPkts,
      fdbPort,
      basePortIf,
      stpState,
      lldpRemSysName,
      lldpLocPortIf,
      cdpDeviceId,
      cdpDevicePort
    ] = await Promise.all([
      snmpWalk(session, OID.ifName),
      snmpWalk(session, OID.ifDescr),
      snmpWalk(session, OID.ifOperStatus),
      snmpWalk(session, OID.ifInNUcastPkts),
      snmpWalk(session, OID.ifInErrors),
      snmpWalk(session, OID.ifHCInBroadcastPkts),
      snmpWalk(session, OID.ifHCInMulticastPkts),
      snmpWalk(session, OID.dot1dTpFdbPort, 20),
      snmpWalk(session, OID.dot1dBasePortIfIndex, 20),
      snmpWalk(session, OID.dot1dStpPortState, 20),
      snmpWalk(session, OID.lldpRemSysName, 15),
      snmpWalk(session, OID.lldpLocPortIfIndex, 15),
      snmpWalk(session, OID.cdpCacheDeviceId, 15),
      snmpWalk(session, OID.cdpCacheDevicePort, 15)
    ]);

    const ifaces = buildIfaceMap({
      ifName: ifName.rows,
      ifDescr: ifDescr.rows,
      ifOperStatus: ifOperStatus.rows,
      ifInNUcastPkts: ifInNUcastPkts.rows,
      ifInErrors: ifInErrors.rows,
      ifHCInBroadcastPkts: ifHCInBroadcastPkts.rows,
      ifHCInMulticastPkts: ifHCInMulticastPkts.rows
    });

    // Bridge port -> ifIndex
    const bridgePortToIf = new Map();
    for (const row of basePortIf.rows || []) {
      const bp = oidIndex(row.oid, OID.dot1dBasePortIfIndex);
      if (!bp) continue;
      bridgePortToIf.set(bp, String(toNumber(row.value)));
    }

    const macsByIf = new Map();
    const macMap = new Map();
    for (const row of fdbPort.rows || []) {
      const suffix = oidIndex(row.oid, OID.dot1dTpFdbPort);
      const mac = decodeMacFromOidSuffix(suffix);
      if (!mac) continue;
      const bridgePort = String(toNumber(row.value));
      const ifIndex = bridgePortToIf.get(bridgePort) || bridgePort;
      macMap.set(mac, ifIndex);
      if (!macsByIf.has(ifIndex)) macsByIf.set(ifIndex, []);
      macsByIf.get(ifIndex).push(mac);
    }

    const stpByBridgePort = new Map();
    for (const row of stpState.rows || []) {
      const bp = oidIndex(row.oid, OID.dot1dStpPortState);
      if (!bp) continue;
      stpByBridgePort.set(bp, toNumber(row.value));
    }
    const stpByIfIndex = buildStpByIfIndex(stpByBridgePort, bridgePortToIf);
    const neighborsByIf = mergeNeighborMaps(
      parseLldpNeighbors(lldpRemSysName.rows, lldpLocPortIf.rows),
      parseCdpNeighbors(cdpDeviceId, cdpDevicePort)
    );

    const snmpNotes = [];
    if (meta.err) snmpNotes.push(`sys: ${meta.err}`);
    if (ifInNUcastPkts.err) snmpNotes.push(`nUcast: ${ifInNUcastPkts.err}`);
    if (fdbPort.err) snmpNotes.push(`fdb: ${fdbPort.err}`);
    if (lldpRemSysName.rows?.length) snmpNotes.push(`lldp: ${neighborsByIf.size} porta(s) com vizinho`);
    if (cdpDeviceId.rows?.length) snmpNotes.push(`cdp: ${cdpDeviceId.rows.length} entrada(s)`);

    return {
      ok: true,
      switchId: sw.id,
      ip: sw.ip,
      name: sw.name || sysName,
      sysName,
      sysDescr: sysDescr.slice(0, 180),
      vendor,
      polledAt: new Date().toISOString(),
      durationMs: Date.now() - started,
      ifaces: Array.from(ifaces.values()),
      macMap,
      macsByIf,
      stpByBridgePort,
      stpByIfIndex,
      bridgePortToIf,
      neighborsByIf,
      snmpNotes
    };
  } catch (err) {
    return {
      ok: false,
      switchId: sw.id,
      ip: sw.ip,
      name: sw.name || sw.ip,
      vendor: sw.vendor || 'auto',
      error: err.message || String(err),
      polledAt: new Date().toISOString(),
      durationMs: Date.now() - started,
      ifaces: [],
      macMap: new Map(),
      macsByIf: new Map(),
      stpByBridgePort: new Map(),
      stpByIfIndex: new Map(),
      bridgePortToIf: new Map(),
      neighborsByIf: new Map(),
      snmpNotes: []
    };
  } finally {
    try { session.close(); } catch { /* ignore */ }
  }
}

function analyzeSample(sample, cfg, macGlobal = null) {
  const thr = cfg.thresholds || DEFAULT_CONFIG.thresholds;
  const prev = prevSamples.get(sample.switchId);
  const nowMs = Date.now();
  const ports = [];
  const alerts = [];

  if (!sample.ok) {
    return {
      switchId: sample.switchId,
      ip: sample.ip,
      name: sample.name,
      vendor: sample.vendor,
      ok: false,
      error: sample.error,
      ports: [],
      alerts: [],
      maxScore: 0
    };
  }

  const dtSec = prev && prev.atMs
    ? Math.max(1, (nowMs - prev.atMs) / 1000)
    : null;

  // MAC flapping vs previous map
  if (!macLastPort.has(sample.switchId)) macLastPort.set(sample.switchId, new Map());
  const lastMac = macLastPort.get(sample.switchId);
  const flapThisRound = new Map();

  for (const [mac, ifIndex] of sample.macMap.entries()) {
    const prevIf = lastMac.get(mac);
    if (prevIf && prevIf !== ifIndex) {
      const key = `${sample.switchId}:${ifIndex}`;
      flapCounters.set(key, (flapCounters.get(key) || 0) + 1);
      flapThisRound.set(ifIndex, (flapThisRound.get(ifIndex) || 0) + 1);
    }
    lastMac.set(mac, ifIndex);
  }

  for (const iface of sample.ifaces) {
    // Skip down + empty special ifaces often seen as VLAN/null
    if (iface.operStatus === 2) continue;
    const name = iface.name || iface.descr || `if${iface.ifIndex}`;
    if (/^lo\b|null|vlan\s*1$|management/i.test(name) && isUplinkLike(name)) {
      // still evaluate; just note
    }

    const prevIface = prev && prev.ifaces ? prev.ifaces.get(iface.ifIndex) : null;
    let bcastPerSec = 0;
    let mcastPerSec = 0;
    let nucastPerSec = 0;
    let errorDelta = 0;
    let rateReady = false;

    if (prevIface && dtSec) {
      rateReady = true;
      const bcastDelta = Math.max(0, (iface.inBroadcast || 0) - (prevIface.inBroadcast || 0));
      const mcastDelta = Math.max(0, (iface.inMulticast || 0) - (prevIface.inMulticast || 0));
      const nucastDelta = Math.max(0, (iface.inNUcast || 0) - (prevIface.inNUcast || 0));
      errorDelta = Math.max(0, (iface.inErrors || 0) - (prevIface.inErrors || 0));

      // Prefer HC broadcast; fallback nUcast (bcast+mcast)
      if (iface.inBroadcast > 0 || prevIface.inBroadcast > 0) {
        bcastPerSec = bcastDelta / dtSec;
        mcastPerSec = mcastDelta / dtSec;
      } else {
        nucastPerSec = nucastDelta / dtSec;
        bcastPerSec = nucastPerSec; // conservative proxy
      }
    }

    const flaps = flapThisRound.get(iface.ifIndex) || 0;
    const flapTotal = flapCounters.get(`${sample.switchId}:${iface.ifIndex}`) || 0;
    const portKey = `${sample.switchId}:${iface.ifIndex}`;
    const crossSwitchFlaps = macGlobal?.crossFlapsByPort?.get(portKey) || 0;
    const multiHomedMacs = macGlobal?.multiHomedByPort?.get(portKey) || 0;
    const stpState = sample.stpByIfIndex?.get(String(iface.ifIndex)) ?? null;
    const neighbors = sample.neighborsByIf?.get(String(iface.ifIndex)) || [];
    const neighborCount = neighbors.length;

    let score = 0;
    const evidence = [];

    if (rateReady) {
      if (bcastPerSec >= thr.broadcastPerSecCrit) {
        score += 70;
        evidence.push(`Broadcast ~${Math.round(bcastPerSec)}/s (crítico)`);
      } else if (bcastPerSec >= thr.broadcastPerSecWarn) {
        score += 40;
        evidence.push(`Broadcast ~${Math.round(bcastPerSec)}/s`);
      }
      if (mcastPerSec >= (thr.multicastPerSecWarn || 8000)) {
        score += 20;
        evidence.push(`Multicast ~${Math.round(mcastPerSec)}/s`);
      }
      if (errorDelta >= thr.errorDeltaWarn) {
        score += 25;
        evidence.push(`+${errorDelta} erros de interface`);
      }
    }

    if (flaps >= thr.macFlapMinMoves) {
      score += 45;
      evidence.push(`MAC flapping local: ${flaps} MAC(s) trocaram de porta`);
    } else if (flapTotal >= thr.macFlapMinMoves * 2) {
      score += 30;
      evidence.push(`MAC flapping acumulado: ${flapTotal}`);
    }

    if (crossSwitchFlaps > 0) {
      score += Math.min(40, 15 + crossSwitchFlaps * 8);
      evidence.push(`MAC flapping entre switches: ${crossSwitchFlaps} evento(s)`);
    }
    if (multiHomedMacs > 0) {
      score += Math.min(25, 10 + multiHomedMacs * 4);
      evidence.push(`MAC visível em múltiplos pontos: ${multiHomedMacs}`);
    }

    if (stpState === 6) {
      score += 35;
      evidence.push('STP broken');
    } else if (stpState === 2 && rateReady && bcastPerSec >= (thr.broadcastPerSecWarn || 4000)) {
      score -= 8;
      evidence.push(`STP ${stpStateLabel(stpState)} (provável efeito downstream)`);
    } else if (stpState === 5 && !isUplinkLike(name) && rateReady && bcastPerSec >= (thr.broadcastPerSecWarn || 4000)) {
      score += 18;
      evidence.push('STP forwarding em porta de acesso com storm');
    } else if (stpState != null) {
      evidence.push(`STP ${stpStateLabel(stpState)}`);
    }

    if (neighborCount > 0) {
      const n0 = neighbors[0];
      evidence.push(`Vizinho ${n0.protocol.toUpperCase()}: ${n0.remoteName}${n0.remotePort ? ` (${n0.remotePort})` : ''}`);
    }

    // First sample: only flag extreme absolute counters on open ports (weak signal)
    if (!rateReady && iface.inNUcast > 50_000_000) {
      score += 15;
      evidence.push('Contador nUcast muito alto (aguarde 2ª amostra)');
    }

    // Soften score on known uplinks (broadcast storm still matters, but origin often is edge)
    let originBias = 1;
    if (isUplinkLike(name) || neighborCount >= 2) {
      originBias = 0.72;
      if (score > 0) evidence.push('Porta parece uplink/trunk (origem menos provável)');
    }

    const adjScore = Math.min(100, Math.round(score * originBias));
    if (adjScore >= 30) recordFirstTrigger(sample.switchId, iface.ifIndex, adjScore);
    const sev = scoreSeverity(adjScore);
    const macs = (sample.macsByIf.get(iface.ifIndex) || []).slice(0, 8);

    const row = {
      switchId: sample.switchId,
      switchName: sample.name,
      switchIp: sample.ip,
      vendor: sample.vendor,
      ifIndex: iface.ifIndex,
      port: name,
      operStatus: iface.operStatus === 1 ? 'up' : (iface.operStatus === 2 ? 'down' : String(iface.operStatus || '?')),
      broadcastPerSec: Math.round(bcastPerSec),
      multicastPerSec: Math.round(mcastPerSec),
      errorDelta,
      macCount: (sample.macsByIf.get(iface.ifIndex) || []).length,
      macSamples: macs,
      macFlaps: flaps,
      crossSwitchFlaps,
      multiHomedMacs,
      stpState,
      stpLabel: stpStateLabel(stpState),
      neighborCount,
      neighbors: neighbors.slice(0, 3),
      score: adjScore,
      status: sev.label,
      level: sev.level,
      emoji: sev.emoji,
      evidence,
      probabilityOrigin: 'pendente',
      rateReady,
      at: sample.polledAt
    };
    ports.push(row);

    if (adjScore >= 30) {
      alerts.push({
        id: `al_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 6)}`,
        type: 'loop_suspect',
        ...row,
        createdAt: new Date().toISOString()
      });
    }
  }

  ports.sort((a, b) => b.score - a.score);

  // Store prev for next delta
  const ifacePrev = new Map();
  for (const iface of sample.ifaces) {
    ifacePrev.set(iface.ifIndex, {
      inBroadcast: iface.inBroadcast,
      inMulticast: iface.inMulticast,
      inNUcast: iface.inNUcast,
      inErrors: iface.inErrors
    });
  }
  prevSamples.set(sample.switchId, { atMs: nowMs, ifaces: ifacePrev });

  return {
    switchId: sample.switchId,
    ip: sample.ip,
    name: sample.name,
    sysName: sample.sysName,
    vendor: sample.vendor,
    ok: true,
    durationMs: sample.durationMs,
    snmpNotes: sample.snmpNotes,
    ports,
    alerts,
    maxScore: ports.reduce((m, p) => Math.max(m, p.score), 0),
    rateReady: Boolean(dtSec)
  };
}

async function runPollCycle({ persistAlerts = true } = {}) {
  const cfg = getConfig();
  const switches = cfg.switches || [];
  if (!switches.length) {
    lastPollSummary = {
      at: new Date().toISOString(),
      ok: false,
      message: 'Nenhum switch cadastrado. Adicione IPs Aruba/Cisco/Intelbras/D-Link na aba Configuração.',
      results: [],
      suspects: []
    };
    emitStatus({ type: 'loop_status', running: monitorRunning, summary: lastPollSummary });
    return lastPollSummary;
  }

  const results = [];
  const samples = [];
  for (const sw of switches) {
    samples.push(await pollSwitch(sw, cfg));
  }

  const macGlobal = buildMacGlobalIndex(samples);
  for (const sample of samples) {
    const analyzed = analyzeSample(sample, cfg, macGlobal);
    results.push(analyzed);
  }

  const allSuspectPorts = results.flatMap((r) => (r.ports || []).filter((p) => p.score >= 30));
  const ranked = applyOriginRanking(allSuspectPorts, macGlobal);
  const likelyOrigin = computeLikelyOrigin(ranked, macGlobal);

  for (const [mac, loc] of macGlobal.current.entries()) {
    globalMacLocation.set(mac, loc);
  }

  const rankedByKey = new Map(ranked.map((p) => [`${p.switchId}:${p.ifIndex}`, p]));
  for (const result of results) {
    for (const port of result.ports || []) {
      const enriched = rankedByKey.get(`${port.switchId}:${port.ifIndex}`);
      if (enriched) {
        port.probabilityOrigin = enriched.probabilityOrigin;
        port.originScore = enriched.originScore;
        port.originRank = enriched.originRank;
        port.isLikelyOrigin = enriched.isLikelyOrigin;
      }
    }
    if (persistAlerts && result.alerts?.length) {
      for (const a of result.alerts) {
        const enriched = rankedByKey.get(`${a.switchId}:${a.ifIndex}`);
        if (enriched) {
          a.probabilityOrigin = enriched.probabilityOrigin;
          a.originScore = enriched.originScore;
          a.isLikelyOrigin = enriched.isLikelyOrigin;
        }
        if ((enriched?.originScore || a.score) >= 55) pushAlert(a);
      }
    }
  }

  const suspects = ranked.slice(0, 40);
  const topologyLinks = buildTopologySummary(samples);

  lastPollAt = new Date().toISOString();
  lastPollSummary = {
    at: lastPollAt,
    ok: true,
    message: likelyOrigin.ok
      ? likelyOrigin.message
      : (suspects.length
        ? `${suspects.length} porta(s) com indício de loop/storm`
        : 'Nenhuma anomalia crítica nesta rodada'),
    switchCount: switches.length,
    results,
    suspects,
    likelyOrigin,
    topologyLinks,
    macGlobalStats: {
      crossFlaps: macGlobal.crossFlaps.length,
      multiHomed: macGlobal.multiHomed.length
    }
  };

  emitStatus({ type: 'loop_status', running: monitorRunning, summary: lastPollSummary });
  return lastPollSummary;
}

async function quickCheck() {
  // Two spaced samples so rates exist even without continuous monitor
  const cfg = getConfig();
  await runPollCycle({ persistAlerts: false });
  const gap = Math.max(3, Number(cfg.quickGapSec) || 5) * 1000;
  await new Promise((r) => setTimeout(r, gap));
  return runPollCycle({ persistAlerts: true });
}

function getStatus() {
  return {
    running: monitorRunning,
    lastPollAt,
    summary: lastPollSummary,
    config: {
      community: getConfig().community,
      pollIntervalSec: getConfig().pollIntervalSec,
      switchCount: (getConfig().switches || []).length,
      thresholds: getConfig().thresholds
    }
  };
}

function startMonitor() {
  const cfg = getConfig();
  if (monitorRunning) return getStatus();
  monitorRunning = true;
  const intervalMs = Math.max(5, Number(cfg.pollIntervalSec) || 12) * 1000;

  const tick = async () => {
    if (!monitorRunning) return;
    try {
      await runPollCycle({ persistAlerts: true });
    } catch (err) {
      emitStatus({
        type: 'loop_status',
        running: true,
        error: err.message || String(err)
      });
    }
  };

  tick();
  monitorTimer = setInterval(tick, intervalMs);
  emitStatus({ type: 'loop_status', running: true, message: 'Monitoramento urgente iniciado' });
  return getStatus();
}

function stopMonitor() {
  monitorRunning = false;
  if (monitorTimer) {
    clearInterval(monitorTimer);
    monitorTimer = null;
  }
  emitStatus({ type: 'loop_status', running: false, message: 'Monitoramento parado' });
  return getStatus();
}

function listSwitches() {
  return getConfig().switches || [];
}

function upsertSwitch(input) {
  const cfg = getConfig();
  const switches = [...(cfg.switches || [])];
  const ip = String(input.ip || '').trim();
  if (!ip) throw new Error('IP do switch é obrigatório');

  const payload = {
    id: input.id || uid(),
    name: String(input.name || '').trim() || ip,
    ip,
    vendor: String(input.vendor || 'auto').toLowerCase(),
    community: input.community ? String(input.community).trim() : undefined
  };

  const idx = switches.findIndex((s) => s.id === payload.id || s.ip === payload.ip);
  if (idx >= 0) switches[idx] = { ...switches[idx], ...payload, id: switches[idx].id };
  else switches.push(payload);

  saveConfig({ switches });
  return payload;
}

function removeSwitch(idOrIp) {
  const cfg = getConfig();
  const key = String(idOrIp || '').trim();
  const switches = (cfg.switches || []).filter((s) => s.id !== key && s.ip !== key);
  saveConfig({ switches });
  prevSamples.delete(key);
  return { ok: true, switches };
}

function updateSettings(partial) {
  const allowed = {};
  if (partial.community != null) allowed.community = String(partial.community);
  if (partial.pollIntervalSec != null) allowed.pollIntervalSec = Number(partial.pollIntervalSec);
  if (partial.timeoutMs != null) allowed.timeoutMs = Number(partial.timeoutMs);
  if (partial.quickGapSec != null) allowed.quickGapSec = Number(partial.quickGapSec);
  if (partial.thresholds) allowed.thresholds = partial.thresholds;
  return saveConfig(allowed);
}

function listAlerts(limit = 100) {
  const store = loadAlerts();
  return {
    alerts: (store.alerts || []).slice(0, limit),
    updatedAt: store.updatedAt
  };
}

function resetRuntimeBaseline() {
  prevSamples.clear();
  macLastPort.clear();
  flapCounters.clear();
  globalMacLocation.clear();
  originFirstTrigger.clear();
  return { ok: true };
}

