  const hostname = (host.hostname || '').toLowerCase();
  const ports = Array.isArray(host.ports) ? host.ports : [];
  // Only treat confirmed-open ports for service-based classification
  const openPorts = ports.filter(p => !p.state || String(p.state).startsWith('open'));
  const portSet = new Set(openPorts.map(p => Number(p.port)));
  const services = openPorts.map(p => `${p.service || ''} ${p.version || ''}`.toLowerCase()).join(' ');

