app.post('/api/auth/login', (req, res) => {
  try {
    const username = String(req.body?.username || '').trim();
    const password = String(req.body?.password || '');
    const scope = String(req.body?.scope || 'dashboard').trim();
    if (!username || !password) {
      return res.status(400).json({ ok: false, error: 'Informe login e senha.' });
    }
    const result = canonAuth.login(username, password, scope);
    if (!result.ok) return res.status(401).json(result);
    res.json(result);
  } catch (err) {
    console.error('[AUTH] login error:', err);
    res.status(500).json({ ok: false, error: 'Falha na autenticação.' });
  }
});

app.get('/api/auth/session', (req, res) => {
  const token = canonAuth.extractToken(req);
  const scopeQuery = String(req.query.scope || '').trim();
  const requiredScope = scopeQuery === 'dashboard' || scopeQuery === 'modals' ? scopeQuery : undefined;
  const status = canonAuth.getSessionStatus(token, requiredScope);
  res.json({
    ok: true,
    authenticated: !!status,
    scope: status?.scope || null,
    expiresInMs: status?.expiresInMs || 0
  });
});

app.post('/api/auth/logout', (req, res) => {
  const token = canonAuth.extractToken(req);
  canonAuth.revokeSession(token);
  res.json({ ok: true });
});

