// Utility to parse IP Range / CIDR
function parseTarget(target) {
  target = target.trim();
  const ips = [];

  // 1. CIDR notation (e.g. 192.168.1.0/24)
  if (target.includes('/')) {
    const parts = target.split('/');
    const baseIp = parts[0];
    const mask = parseInt(parts[1], 10);
    if (mask < 0 || mask > 32) return [];

    const ipNum = ipToLong(baseIp);
    const numHosts = Math.pow(2, 32 - mask);
    const maskBuffer = mask === 0 ? 0 : (~0 << (32 - mask));
    const startIpNum = (ipNum & maskBuffer) >>> 0;

    // For large networks, limit safety size to /24 (256 hosts) to avoid crashing local scanners
    const limit = Math.min(numHosts, 1024); 
    for (let i = 0; i < limit; i++) {
      ips.push(longToIp(startIpNum + i));
    }
  } 
  // 2. Dash range (e.g. 192.168.1.1-192.168.1.50 or 192.168.1.1-50)
  else if (target.includes('-')) {
    const parts = target.split('-');
    const startIpStr = parts[0].trim();
    let endIpStr = parts[1].trim();

    if (!endIpStr.includes('.')) {
      const startOctets = startIpStr.split('.');
      startOctets[3] = endIpStr;
      endIpStr = startOctets.join('.');
    }

    const startNum = ipToLong(startIpStr);
    const endNum = ipToLong(endIpStr);

    if (startNum <= endNum && (endNum - startNum) <= 1024) {
      for (let i = startNum; i <= endNum; i++) {
        ips.push(longToIp(i));
      }
    }
  } 
  // 3. Single IP
  else if (/^(?:[0-9]{1,3}\.){3}[0-9]{1,3}$/.test(target)) {
    ips.push(target);
  }

  return ips;
}

function ipToLong(ip) {
  return ip.split('.').reduce((ipInt, octet) => (ipInt << 8) + parseInt(octet, 10), 0) >>> 0;
}

function longToIp(long) {
  return [
    (long >>> 24) & 0xFF,
    (long >>> 16) & 0xFF,
    (long >>> 8) & 0xFF,
    long & 0xFF
  ].join('.');
}

// OS Heuristics from TTL
function getOSFromTTL(ttl) {
  if (!ttl) return 'Desconhecido';
  if (ttl <= 64) return 'Linux / macOS / Android';
  if (ttl <= 128) return 'Windows';
  if (ttl <= 255) return 'Dispositivo de Rede (Cisco/Router/Embedded)';
  return 'Desconhecido';
}

// Ping sweep implementation
function pingHost(ip, timeoutMs) {
  return new Promise((resolve) => {
    // Windows ping syntax: ping -n 1 -w timeout ip
    exec(`ping -n 1 -w ${timeoutMs} ${ip}`, (error, stdout, stderr) => {
      if (error) {
        resolve({ ip, active: false, ttl: null });
        return;
      }

      // Matches TTL in English (TTL=128) or Portuguese (TTL=128)
      const ttlMatch = stdout.match(/TTL=(\d+)/i);
      if (ttlMatch) {
        const ttl = parseInt(ttlMatch[1], 10);
        resolve({ ip, active: true, ttl });
      } else {
        // Double check if output reports success but no TTL (e.g. localhost)
        if (stdout.includes('resposta de') || stdout.includes('reply from') || stdout.includes('0% de perda') || stdout.includes('0% loss')) {
          resolve({ ip, active: true, ttl: 64 }); // Default fallback TTL
        } else {
          resolve({ ip, active: false, ttl: null });
        }
      }
    });
  });
}

// DNS reverse lookup
async function resolveHostname(ip) {
  try {
    const hostnames = await dns.reverse(ip);
    return hostnames[0] || 'N/A';
  } catch (err) {
    return 'N/A';
  }
}

// MAC Address lookup via ARP table
function getMacAddress(ip) {
  return new Promise((resolve) => {
    // Windows arp command: arp -a ip
    exec(`arp -a ${ip}`, (error, stdout, stderr) => {
      if (error || !stdout) {
        resolve('N/A');
        return;
      }

      const lines = stdout.split('\n');
      for (const line of lines) {
        if (line.includes(ip)) {
          // Regex to match MAC address formats (e.g., 00-11-22-33-44-55 or 00:11:22:33:44:55)
          const macMatch = line.match(/([0-9a-fA-F]{2}[:-]){5}([0-9a-fA-F]{2})/);
          if (macMatch) {
            resolve(macMatch[0].toUpperCase().replace(/:/g, '-'));
            return;
          }
        }
      }
      resolve('N/A');
    });
  });
}

// TCP Port Scan & Service/Version Detection
function scanTcpPort(ip, port, timeoutMs, scanCtrl = null) {
  return new Promise((resolve) => {
    const socket = new net.Socket();
    let status = 'closed';
    let version = 'N/A';
    let settled = false;

    const finish = (result) => {
      if (settled) return;
      settled = true;
      if (scanCtrl && scanCtrl.sockets) scanCtrl.sockets.delete(socket);
      try { socket.destroy(); } catch (_) {}
      resolve(result);
    };

    if (scanCtrl && scanCtrl.sockets) scanCtrl.sockets.add(socket);

    socket.setTimeout(timeoutMs);

    socket.on('connect', () => {
      if (scanCtrl && scanCtrl.cancelled) {
        finish({ port, protocol: 'TCP', state: 'closed', service: 'cancelled', version: 'N/A' });
        return;
      }
      status = 'open';
      const serviceInfo = TCP_SERVICES[port];
      if (serviceInfo && serviceInfo.probe) {
        try { socket.write(serviceInfo.probe); } catch (_) {}
      }
      // Sem banner: fecha rápido para não segurar o pool
      setTimeout(() => {
        if (!settled && status === 'open') {
          finish({
            port,
            protocol: 'TCP',
            state: 'open',
            service: TCP_SERVICES[port]?.name || guessServiceName(port),
            version
          });
        }
      }, Math.min(250, timeoutMs));
    });

    socket.on('data', (data) => {
      const banner = data.toString('utf8', 0, 100).trim();
      if (port === 80 || port === 8080 || port === 443 || port === 8000 || port === 8443) {
        const serverHeader = banner.match(/Server:\s*([^\r\n]+)/i);
        version = serverHeader ? serverHeader[1] : 'HTTP Server';
      } else {
        version = banner.replace(/[\r\n]+/g, ' ').substring(0, 50);
      }
      finish({
        port,
        protocol: 'TCP',
        state: 'open',
        service: TCP_SERVICES[port]?.name || guessServiceName(port),
        version
      });
    });

    socket.on('timeout', () => {
      if (status === 'open') {
        finish({
          port,
          protocol: 'TCP',
          state: 'open',
          service: TCP_SERVICES[port]?.name || guessServiceName(port),
          version
        });
      } else {
        finish({
          port,
          protocol: 'TCP',
          state: 'filtered',
          service: TCP_SERVICES[port]?.name || guessServiceName(port),
          version: 'N/A'
        });
      }
    });

    socket.on('error', (err) => {
      if (status === 'open') {
        finish({
          port,
          protocol: 'TCP',
          state: 'open',
          service: TCP_SERVICES[port]?.name || guessServiceName(port),
          version
        });
        return;
      }
      finish({
        port,
        protocol: 'TCP',
        state: err.code === 'ECONNREFUSED' ? 'closed' : 'filtered',
        service: TCP_SERVICES[port]?.name || guessServiceName(port),
        version: 'N/A'
      });
    });

    socket.on('close', () => {
      if (!settled) {
        finish({
          port,
          protocol: 'TCP',
          state: status,
          service: TCP_SERVICES[port]?.name || guessServiceName(port),
          version
        });
      }
    });

    if (scanCtrl && scanCtrl.cancelled) {
      finish({ port, protocol: 'TCP', state: 'closed', service: 'cancelled', version: 'N/A' });
      return;
    }

    socket.connect(port, ip);
  });
}

function guessServiceName(port) {
  const known = {
    88: 'Kerberos', 389: 'LDAP', 636: 'LDAPS', 3268: 'Global Catalog', 3269: 'Global Catalog SSL',
    464: 'Kerberos Password', 902: 'VMware Auth', 903: 'VMware', 1433: 'MSSQL', 1434: 'MSSQL Browser',
    1521: 'Oracle', 3306: 'MySQL', 5432: 'PostgreSQL', 5985: 'WinRM HTTP', 5986: 'WinRM HTTPS',
    9389: 'AD Web Services', 2049: 'NFS', 2375: 'Docker', 2376: 'Docker TLS', 6443: 'Kubernetes API',
    9200: 'Elasticsearch', 27017: 'MongoDB', 5672: 'RabbitMQ', 6379: 'Redis', 11211: 'Memcached',
    5060: 'SIP', 5061: 'SIP-TLS', 1883: 'MQTT', 8883: 'MQTT-TLS', 47808: 'BACnet'
  };
  if (known[port]) return known[port];
  if (TCP_SERVICES[port]?.name) return TCP_SERVICES[port].name;
  return `TCP/${port}`;
}

// UDP Port Scan — only "open" when there is a real response
function scanUdpPort(ip, port, timeoutMs, scanCtrl = null) {
  return new Promise((resolve) => {
    const client = dgram.createSocket('udp4');
    let state = 'open | filtered';
    let serviceName = UDP_SERVICES[port] || 'Desconhecido';
    let version = 'N/A';
    let settled = false;

    const finish = (result) => {
      if (settled) return;
      settled = true;
      clearTimeout(timer);
      if (scanCtrl && scanCtrl.udpSockets) scanCtrl.udpSockets.delete(client);
      try { client.close(); } catch (_) {}
      resolve(result);
    };

    if (scanCtrl && scanCtrl.udpSockets) scanCtrl.udpSockets.add(client);

    const timer = setTimeout(() => {
      finish({ port, protocol: 'UDP', state, service: serviceName, version });
    }, timeoutMs);

    client.on('message', (msg) => {
      state = 'open';
      version = msg.toString('utf8', 0, 50).trim().replace(/[\r\n]+/g, ' ');
      finish({ port, protocol: 'UDP', state: 'open', service: serviceName, version });
    });

    client.on('error', () => {
      finish({ port, protocol: 'UDP', state: 'closed', service: serviceName, version: 'N/A' });
    });

    if (scanCtrl && scanCtrl.cancelled) {
      finish({ port, protocol: 'UDP', state: 'closed', service: 'cancelled', version: 'N/A' });
      return;
    }

    try {
      client.send(Buffer.from([0x00]), port, ip, (err) => {
        if (err) {
          finish({ port, protocol: 'UDP', state: 'closed', service: serviceName, version: 'N/A' });
        }
      });
    } catch (err) {
      finish({ port, protocol: 'UDP', state: 'closed', service: serviceName, version: 'N/A' });
    }
  });
}

// Custom Promise-based Worker Pool for Concurrency/Multi-threading
async function runConcurrent(tasks, limit, onTaskComplete, shouldCancel = null) {
  const results = [];
  const executing = new Set();

  for (const taskFn of tasks) {
    if (shouldCancel && shouldCancel()) {
      results.push(Promise.resolve(null));
      continue;
    }

    const p = Promise.resolve().then(() => {
      if (shouldCancel && shouldCancel()) return null;
      return taskFn();
    });
    results.push(p);
    executing.add(p);

    const clean = () => executing.delete(p);
    p.then(clean, clean);

    if (onTaskComplete) {
      p.then((res) => {
        if (res != null) onTaskComplete(res);
      }).catch(() => {});
    }

    if (executing.size >= limit) {
      await Promise.race(executing);
    }
  }

  return Promise.all(results);
}

function abortScanSockets(scanCtrl) {
  if (!scanCtrl) return;
  if (scanCtrl.sockets) {
    for (const socket of scanCtrl.sockets) {
      try { socket.destroy(); } catch (_) {}
    }
    scanCtrl.sockets.clear();
  }
  if (scanCtrl.udpSockets) {
    for (const udp of scanCtrl.udpSockets) {
      try { udp.close(); } catch (_) {}
    }
    scanCtrl.udpSockets.clear();
  }
}

