  ]);
  const serverPorts = hasPort(portSet, [22, 25, 53, 88, 389, 636, 1433, 1521, 3306, 5432, 5985, 5986, 8080, 8443]);
  // RDP alone on a desktop is endpoint; RDP + other server signals => server
  if (serverOs || serverName || (serverPorts && !hasAny(hostname, ['pc', 'desk', 'note', 'laptop', 'nb-', 'ws-']))) {
    if (serverOs || serverName || hasPort(portSet, [389, 636, 88, 1433, 3306, 5432, 25, 53])) {
      return 'Servidor';
    }
  }

  // --- Máquina virtual ---
  if (host.vm === 'Sim' || hasAny(vendor, ['vmware', 'hyper-v', 'virtualbox', 'qemu', 'parallels', 'xen'])) {
    // VM can still be endpoint or server; if no server signal, label as VM endpoint
    if (serverOs || serverName) return 'Servidor (VM)';
    return 'Endpoint (VM)';
  }

  // --- Endpoint / estação de trabalho ---
  const endpointHints = [
    'pc', 'desktop', 'laptop', 'notebook', 'workstation', 'endpoint', 'estacao', 'estação',
    'ws-', 'nb-', 'note-', 'user-', 'cliente', 'workstation'
  ];
  const endpointOs =
    hasAny(os, ['windows 10', 'windows 11', 'windows 7', 'windows 8', 'macos', 'mac os', 'ubuntu', 'linux']) &&
    !serverOs;
  if (
    hasAny(hostname, endpointHints) ||
    endpointOs ||
    (hasPort(portSet, [445, 139, 3389, 135]) && !serverName && !serverOs)
  ) {
    return 'Endpoint';
  }

  // Desktop OS without strong signals
  if (endpointOs) return 'Endpoint';

  // Weak server guess from common web + admin ports
  if (hasPort(portSet, [80, 443]) && hasPort(portSet, [22, 3389, 445])) {
    return 'Servidor';
  }

  if (host.status === 'Ativo') return 'Host Ativo';
  return 'Desconhecido';
}

// WebSocket handler — Etapa 7 (#18): handshake auth antes de scan/export
wss.on('connection', (ws) => {
  console.log('[WS] Novo cliente conectado');
  ws.authenticated = false;
  const authTimer = setTimeout(() => {
    if (ws.authenticated) return;
    console.warn('[WS] Auth não recebida — fechando conexão');
    try {
      ws.close(4401, 'Auth required');
    } catch (_) {}
  }, 5000);

  ws.on('message', async (message) => {
    try {
      const data = JSON.parse(message);
      console.log('[WS] Mensagem recebida:', data.type);

      if (data.type === 'auth') {
        const token = String(data.token || '').trim();
        if (canonAuth.isValidSession(token, canonAuth.SCOPES.DASHBOARD)) {
          ws.authenticated = true;
          ws.authToken = token;
          clearTimeout(authTimer);
          ws.send(JSON.stringify({ type: 'auth_ok' }));
          console.log('[WS] Cliente autenticado (dashboard)');
        } else {
          try {
            ws.send(JSON.stringify({ type: 'auth_fail', message: 'Sessão inválida ou expirada.' }));
          } catch (_) {}
          try {
            ws.close(4401, 'Auth failed');
          } catch (_) {}
        }
        return;
      }

      if (!ws.authenticated) {
        try {
          ws.send(JSON.stringify({ type: 'error', message: 'Autenticação necessária. Faça login no dashboard.' }));
        } catch (_) {}
        return;
      }

      if (data.type === 'start') {
        const { target, portsTCP, portsUDP, timeout, concurrency, scanUdp } = data;
        console.log('[WS] Iniciando varredura para alvo:', target);

        const ipList = parseTarget(target);
        console.log('[WS] IPs parseados:', ipList.length, 'IPs');
        if (ipList.length === 0) {
          ws.send(JSON.stringify({ type: 'error', message: 'Alvo inválido! Insira um IP, faixa (ex: 192.168.1.1-50) ou CIDR (ex: 192.168.1.0/24).' }));
          return;
        }

        ws.send(JSON.stringify({ type: 'scan_started', total: ipList.length }));
        ws.send(JSON.stringify({ type: 'log', message: `[*] Iniciando varredura em ${ipList.length} endereço(s)...` }));
        ws.send(JSON.stringify({ type: 'log', message: `[*] Configurações: Threads/Concorrência=${concurrency}, Timeout=${timeout}ms` }));

        const startTime = Date.now();
        ws.currentScan = {
          cancelled: false,
          startTime,
          sockets: new Set(),
          udpSockets: new Set()
        };
        const isCancelled = () => !!(ws.currentScan && ws.currentScan.cancelled);
        let activeCount = 0;
        let inactiveCount = 0;
        const hasPorts = (portsTCP && portsTCP.length > 0) || (scanUdp && portsUDP && portsUDP.length > 0);

        // Helper function to safely send messages
        const sendSafeMsg = (msg) => {
          try {
            if (ws && ws.readyState === WebSocket.OPEN) {
              ws.send(JSON.stringify(msg));
            }
          } catch (err) {
            console.error('[ERROR] Failed to send message:', err.message);
          }
        };

        // 1. Host Discovery Stage
        ws.send(JSON.stringify({ type: 'log', message: `[~] FASE 1: Varredura de Hosts Ativos...` }));

        let completedPings = 0;
        const pingTasks = ipList.map(ip => () => {
          if (ws.currentScan && ws.currentScan.cancelled) {
            return Promise.resolve({ ip, active: false, ttl: 0, cancelled: true });
          }
          return pingHost(ip, timeout);
        });

        const pingResults = await runConcurrent(pingTasks, concurrency, (res) => {
          if (isCancelled()) return;
          completedPings++;
          const phase1Progress = Math.round((completedPings / ipList.length) * (hasPorts ? 30 : 50));
          sendSafeMsg({ type: 'progress', percent: phase1Progress });
          if (res && res.active) {
            sendSafeMsg({ type: 'log', message: `[+] Host Ativo detectado: ${res.ip} (TTL=${res.ttl})` });
          }
        }, isCancelled);

        const activeHosts = [];
        const inactiveHosts = [];

        // 2. Details Enrichment Stage (AD/LDAP → NetBIOS → SMB → Discovery)
        sendSafeMsg({ type: 'log', message: `[~] FASE 2: Enriquecimento (AD/LDAP → NetBIOS → SMB → Network Discovery)...` });

        let enrichmentContext = { adCatalog: { ok: false, byDns: new Map(), byCn: new Map() } };
        let scanHostHistory = { hosts: {} };
        try {
          scanHostHistory = loadHistory();
        } catch {
          scanHostHistory = { hosts: {} };
        }
        try {
          enrichmentContext = await createEnrichmentContext((msg) => sendSafeMsg({ type: 'log', message: msg }));
        } catch (enrichCtxErr) {
          console.warn('[WARN] enrichment context failed:', enrichCtxErr.message);
          sendSafeMsg({ type: 'log', message: `[!] Contexto AD falhou: ${enrichCtxErr.message}` });
        }

        // Auditoria de usuários AD (saídas + permissões) — arquivo permanente
        try {
          const adAudit = await syncAdUserAudit((msg) => sendSafeMsg({ type: 'log', message: msg }));
          sendSafeMsg({ type: 'ad_audit_sync', audit: adAudit });
          if (adAudit.ok && adAudit.newlyDeparted > 0) {
            sendSafeMsg({
              type: 'log',
              message: `[!] ${adAudit.newlyDeparted} usuário(s) AD arquivado(s) na auditoria de saídas (permissões preservadas).`
            });
          }
        } catch (adAuditErr) {
          console.warn('[WARN] AD user audit failed:', adAuditErr.message);
          sendSafeMsg({ type: 'log', message: `[!] Auditoria AD usuários falhou: ${adAuditErr.message}` });
        }

        let completedDetails = 0;
        const detailTasks = pingResults.map(pingRes => async () => {
          try {
            if (ws.currentScan && ws.currentScan.cancelled) return;
            const { ip, active, ttl } = pingRes;

            if (active) {
              activeCount++;

              let enriched = {
                hostname: 'N/A',
                mac: 'N/A',
                vendor: 'Desconhecido',
                os: getOSFromTTL(ttl),
                osVersion: 'N/A',
                vm: 'Não',
                adDomain: 'N/A',
                description: 'N/A',
                adDn: 'N/A',
                adLocation: 'N/A',
                lastLogon: 'N/A',
                enrichmentSources: [],
                enrichmentNotes: []
              };

              try {
                enriched = await enrichHost(ip, {
                  ttl,
                  context: enrichmentContext,
                  getVendorFromMac
                });
              } catch (err) {
                console.warn(`[WARN] enrichHost failed for ${ip}:`, err.message);
                try {
                  enriched.hostname = await resolveHostname(ip);
                } catch {}
                try {
                  enriched.mac = await getMacAddress(ip);
                } catch {}
                enriched.vendor = getVendorFromMac(enriched.mac);
                const virtFallback = detectVirtualization({
                  mac: enriched.mac,
                  vendor: enriched.vendor,
                  os: enriched.os,
                  hostname: enriched.hostname
                });
                enriched.vm = virtFallback.vm;
                enriched.vmType = virtFallback.vmType;
                enriched.vmConfidence = virtFallback.vmConfidence;
                enriched.vmEvidence = virtFallback.vmEvidence;
                try {
                  enriched.adDomain = getADDomain();
                } catch {}
              }

              const hostDetails = {
                ip,
                status: 'Ativo',
                hostname: enriched.hostname || 'N/A',
                hostnameSource: enriched.hostnameSource || 'discovered',
                mac: enriched.mac || 'N/A',
                vendor: enriched.vendor || 'Desconhecido',
                os: enriched.os || getOSFromTTL(ttl),
                osVersion: enriched.osVersion || 'N/A',
                vm: enriched.vm || 'Não',
                vmType: enriched.vmType || 'N/A',
                vmConfidence: enriched.vmConfidence || 'N/A',
                vmEvidence: enriched.vmEvidence || [],
                adDomain: enriched.adDomain || 'N/A',
                description: enriched.description || 'N/A',
                adDn: enriched.adDn || 'N/A',
                adLocation: enriched.adLocation || 'N/A',
                managedBy: enriched.managedBy || 'N/A',
                adSamAccountName: enriched.adSamAccountName || 'N/A',
                loggedOnUser: enriched.loggedOnUser || 'N/A',
                lastLogon: enriched.lastLogon || 'N/A',
                enrichmentSources: enriched.enrichmentSources || [],
                enrichmentNotes: enriched.enrichmentNotes || [],
                snmpSysDescr: enriched.snmpSysDescr || 'N/A',
                httpTitle: enriched.httpTitle || 'N/A',
                httpServer: enriched.httpServer || 'N/A',
                tlsSubject: enriched.tlsSubject || 'N/A',
                deviceHints: enriched.deviceHints || { printer: false, printerEvidence: [] },
                printerEvidence: enriched.printerEvidence || [],
                openPrintPorts: enriched.openPrintPorts || [],
                vlan: null,
                vlanId: null,
                vlanSource: 'N/A',
                subnet: getSubnetCidr(ip),
                isDMZ: false,
                environment: 'IT',
                otReasons: [],
                deviceType: 'Host Ativo',
                ports: Array.isArray(enriched.openPrintPorts)
                  ? enriched.openPrintPorts.map(port => ({
                    port,
                    protocol: 'TCP',
                    state: 'open',
                    service: port === 9100 ? 'JetDirect-Printer' : (port === 515 ? 'LPD-Printer' : (port === 631 ? 'IPP-Printer' : 'Printer'))
                  }))
                  : []
              };

              // Refine VM with full host context
              applyVirtualizationToHost(hostDetails);

              hostDetails.deviceType = detectDeviceType(hostDetails);

              const histHost = scanHostHistory.hosts?.[ip];
              if (histHost?.hostname && histHost.hostname !== 'N/A' && (!hostDetails.hostname || hostDetails.hostname === 'N/A')) {
                hostDetails.hostname = histHost.hostname;
                hostDetails.hostnameSource = 'history';
              } else {
                const resolved = resolveHostnameFinal(hostDetails.ip, hostDetails.hostname, {
                  source: hostDetails.hostnameSource || enriched.hostnameSource,
                  deviceType: hostDetails.deviceType,
                  adDomain: hostDetails.adDomain,
                  description: hostDetails.description
                });
                if (resolved.hostname && resolved.hostname !== 'N/A') {
                  hostDetails.hostname = resolved.hostname;
                  hostDetails.hostnameSource = resolved.source;
                  if (resolved.source === 'fallback') {
                    hostDetails.enrichmentNotes = [...(hostDetails.enrichmentNotes || []), 'Hostname inferido (sem PTR/SNMP/SMB)'];
                  }
                }
              }

              const src = (enriched.enrichmentSources || []).join(',') || 'ttl/fallback';
              sendSafeMsg({
                type: 'host_found',
                host: hostDetails,
                log: `[i] ${ip}: Host=${hostDetails.hostname} | Tipo=${hostDetails.deviceType} | OS=${hostDetails.os} | AD=${hostDetails.adDomain} | fontes=${src}`
              });

              activeHosts.push(hostDetails);
            } else {
              inactiveCount++;
              const hostDetails = {
                ip,
                status: 'Inativo',
                hostname: 'N/A',
                mac: 'N/A',
                vendor: 'N/A',
                os: 'N/A',
                osVersion: 'N/A',
                vm: 'Não',
                adDomain: 'N/A',
                description: 'N/A',
                adDn: 'N/A',
                adLocation: 'N/A',
                lastLogon: 'N/A',
                enrichmentSources: [],
                vlan: null,
                subnet: getSubnetCidr(ip),
                isDMZ: false,
                environment: 'IT',
                otReasons: [],
                deviceType: 'Inativo',
                ports: []
              };

              sendSafeMsg({
                type: 'host_inactive',
                host: hostDetails,
                log: `[-] Host Inativo: ${ip}`
              });

              inactiveHosts.push(hostDetails);
            }

            completedDetails++;
            const phase2Start = hasPorts ? 30 : 50;
            const phase2Weight = hasPorts ? 30 : 50;
            const phase2Progress = phase2Start + Math.round((completedDetails / ipList.length) * phase2Weight);
            sendSafeMsg({ type: 'progress', percent: phase2Progress });
          } catch (err) {
            console.error('[ERROR] detailTasks error:', err.message);
            completedDetails++;
          }
        });

        await runConcurrent(detailTasks, Math.min(concurrency, 15), null, isCancelled);

        if (ws.currentScan && ws.currentScan.cancelled) {
          const duration = ((Date.now() - startTime) / 1000).toFixed(2);
          lastScanSnapshot = [...activeHosts, ...inactiveHosts];
          notifyPlatformScanComplete(lastScanSnapshot, { target });
          try {
            const hist = recordScanHosts(lastScanSnapshot, { target });
            sendSafeMsg({
              type: 'log',
              message: hist.baselineOnly
                ? `[i] Leitura base: ${hist.inactiveCount} IP(s) inativo(s) inventariados + ${hist.activeUpdated} ativo(s). Próxima varredura acumulará tempo nos que permanecerem ociosos.`
                : `[i] Ociosos: ${hist.stillInactive} seguem inativos no histórico · ${hist.newlyIdle} novos · ${hist.recoveredActive} voltaram ativo · leitura #${hist.scanCount}.`
            });
          } catch (histErr) {
            console.warn('[HISTORY] record failed on cancel:', histErr.message);
          }
          ws.send(JSON.stringify({ type: 'stopped', summary: { active: activeCount, inactive: inactiveCount, total: ipList.length, time: duration }, log: '[*] Varredura cancelada pelo usuário.' }));
          return;
        }

        // 3. Port Scanning Stage for Active Hosts
        if (activeHosts.length > 0 && hasPorts) {
          ws.send(JSON.stringify({ type: 'log', message: `[~] FASE 3: Varredura de Portas nos Hosts Ativos...` }));

          const totalPortsToScan = (portsTCP?.length || 0) + (scanUdp ? (portsUDP?.length || 0) : 0);
          const totalPortChecks = activeHosts.length * totalPortsToScan;
          let completedPortChecks = 0;

          for (const host of activeHosts) {
            if (ws.currentScan && ws.currentScan.cancelled) break;
            const portTasks = [];

            // TCP Ports
            if (portsTCP && portsTCP.length > 0) {
              portsTCP.forEach(port => {
                portTasks.push(async () => {
                  if (isCancelled()) {
                    return { port, protocol: 'TCP', state: 'closed', service: 'cancelled', version: 'N/A' };
                  }
                  const res = await scanTcpPort(host.ip, port, timeout, ws.currentScan);

                  completedPortChecks++;
                  const phase3Progress = 60 + Math.round((completedPortChecks / totalPortChecks) * 40);
                  sendSafeMsg({ type: 'progress', percent: phase3Progress });

                  // Somente portas realmente abertas entram no resultado ao vivo
                  if (res && res.state === 'open') {
                    sendSafeMsg({
                      type: 'port_result',
                      ip: host.ip,
                      portResult: res,
                      log: `[+] [TCP] ${host.ip}:${res.port} ABERTA (${res.service}${res.version !== 'N/A' ? ' | ' + res.version : ''})`
                    });
                  }
                  return res;
                });
              });
            }

            if (scanUdp && portsUDP && portsUDP.length > 0) {
              portsUDP.forEach(port => {
                portTasks.push(async () => {
                  if (isCancelled()) {
                    return { port, protocol: 'UDP', state: 'closed', service: 'cancelled', version: 'N/A' };
                  }
                  const res = await scanUdpPort(host.ip, port, timeout, ws.currentScan);

                  completedPortChecks++;
                  const phase3Progress = 60 + Math.round((completedPortChecks / totalPortChecks) * 40);
                  sendSafeMsg({ type: 'progress', percent: phase3Progress });

                  // UDP: só conta/exibe se houve resposta real (state === open)
                  if (res && res.state === 'open') {
                    sendSafeMsg({
                      type: 'port_result',
                      ip: host.ip,
                      portResult: res,
                      log: `[+] [UDP] ${host.ip}:${res.port} ABERTA (${res.service})`
                    });
                  }
                  return res;
                });
              });
            }

            const portResults = await runConcurrent(portTasks, concurrency, null, isCancelled);
            if (isCancelled()) break;

            const scannedOpen = portResults.filter(p => p && p.state === 'open');
            const byPort = new Map();
            for (const p of (host.ports || [])) {
              if (p && p.port != null) byPort.set(Number(p.port), p);
            }
            for (const p of scannedOpen) {
              byPort.set(Number(p.port), p);
            }
            // Preserve JetDirect/IPP found during enrichment even if not in the UI port list
            for (const port of (host.openPrintPorts || [])) {
              if (!byPort.has(Number(port))) {
                byPort.set(Number(port), {
                  port: Number(port),
                  protocol: 'TCP',
                  state: 'open',
                  service: Number(port) === 9100 ? 'JetDirect-Printer' : (Number(port) === 515 ? 'LPD-Printer' : 'IPP-Printer')
                });
              }
            }
            host.ports = [...byPort.values()].sort((a, b) => a.port - b.port);
            host.deviceType = detectDeviceType(host);
            const openList = host.ports.map(p => `${p.port}/${p.protocol}`).join(', ') || 'nenhuma';
            sendSafeMsg({
              type: 'log',
              message: `[+] ${host.ip}: ${host.ports.length} porta(s) aberta(s) → ${openList}`
            });
            sendSafeMsg({ type: 'host_update', host });
          }
        } else if (activeHosts.length > 0) {
          // Sem varredura de portas: classificar só com hostname/vendor/OS/AD
          activeHosts.forEach(h => {
            h.deviceType = detectDeviceType(h);
          });
        }
        // Post-processing: assign VLANs by subnet and detect DMZ / OT indicators
        if (activeHosts.length > 0) {
          if (ws.currentScan && ws.currentScan.cancelled) {
            const duration = ((Date.now() - startTime) / 1000).toFixed(2);
            lastScanSnapshot = [...activeHosts, ...inactiveHosts];
            notifyPlatformScanComplete(lastScanSnapshot, { target });
            try {
              const hist = recordScanHosts(lastScanSnapshot, { target });
              sendSafeMsg({
                type: 'log',
                message: hist.baselineOnly
                ? `[i] Leitura base: ${hist.inactiveCount} IP(s) inativo(s) inventariados + ${hist.activeUpdated} ativo(s). Próxima varredura acumulará tempo nos que permanecerem ociosos.`
                : `[i] Ociosos: ${hist.stillInactive} seguem inativos no histórico · ${hist.newlyIdle} novos · ${hist.recoveredActive} voltaram ativo · leitura #${hist.scanCount}.`
              });
            } catch (histErr) {
              console.warn('[HISTORY] record failed on cancel:', histErr.message);
            }
            ws.send(JSON.stringify({ type: 'stopped', summary: { active: activeCount, inactive: inactiveCount, total: ipList.length, time: duration }, log: '[*] Varredura cancelada pelo usuário.' }));
            return;
          }
          const vlanResult = await assignVlansToHosts(activeHosts);
          let dmzCount = 0;
          let otCount = 0;
          const typeCounts = {};
          let vmCount = 0;

          activeHosts.forEach(h => {
            applyVirtualizationToHost(h);
            if (h.vm === 'Sim' || h.vm === 'Provável') vmCount++;

            h.isDMZ = detectDMZ(h);
            if (h.isDMZ) dmzCount++;

            const ot = detectOTICS(h);
            if (ot.isOT) {
              h.environment = 'OT/ICS';
              h.otReasons = ot.reasons;
              otCount++;
            } else {
              h.environment = h.environment || 'IT';
            }

            // Reclassificar após DMZ/OT e portas
            h.deviceType = detectDeviceType(h);
            typeCounts[h.deviceType] = (typeCounts[h.deviceType] || 0) + 1;
            sendSafeMsg({ type: 'host_update', host: h });
          });

          const typeSummary = Object.entries(typeCounts)
            .sort((a, b) => b[1] - a[1])
            .map(([k, v]) => `${k}=${v}`)
            .join(', ');

          const vlanSummary = Object.entries(vlanResult.counts || {})
            .sort((a, b) => b[1] - a[1])
            .slice(0, 8)
            .map(([k, v]) => `${k}=${v}`)
            .join(', ');

          sendSafeMsg({ type: 'log', message: `[i] DMZ detectadas: ${dmzCount} | OT/ICS: ${otCount} | VM/Provável: ${vmCount}` });
          sendSafeMsg({ type: 'log', message: `[i] Tipos de dispositivo: ${typeSummary || 'n/d'}` });
          sendSafeMsg({
            type: 'log',
            message: `[i] VLANs: ${vlanSummary || 'n/d'}${vlanResult.snmpNote ? ` | ${vlanResult.snmpNote}` : ''} (edite data/vlan-map.json para ajustar)`
          });
        }

        const duration = ((Date.now() - startTime) / 1000).toFixed(2);
        lastScanSnapshot = [...activeHosts, ...inactiveHosts];
        notifyPlatformScanComplete(lastScanSnapshot, { target });

        let historyMsg = '';
        try {
          const hist = recordScanHosts(lastScanSnapshot, { target });
          historyMsg = hist.baselineOnly
            ? ` | Base salva (leitura #${hist.scanCount})`
            : ` | Histórico: leitura #${hist.scanCount}, ${hist.activeUpdated} lastSeen`;
          sendSafeMsg({
            type: 'log',
            message: hist.baselineOnly
              ? `[i] Leitura base: ${hist.inactiveCount} inativo(s) inventariados. Próxima varredura acumulará tempo nos ociosos.`
              : `[i] Relatório ociosos #${hist.scanCount}: ${hist.stillInactive} seguem inativos no histórico · ${hist.newlyIdle} novos · ${hist.recoveredActive} voltaram ativo.`
          });
        } catch (histErr) {
          console.warn('[HISTORY] record failed on complete:', histErr.message);
        }

        ws.send(JSON.stringify({
          type: 'complete',
          summary: {
            active: activeCount,
            inactive: inactiveCount,
            total: ipList.length,
            time: duration
          },
          log: `[*] Varredura Concluída! Total de IPs: ${ipList.length} | Ativos: ${activeCount} | Inativos: ${inactiveCount} | Tempo decorrido: ${duration}s${historyMsg}`
        }));
      } else if (data.type === 'stop') {
        if (ws.currentScan && !ws.currentScan.cancelled) {
          ws.currentScan.cancelled = true;
          abortScanSockets(ws.currentScan);
          try {
            ws.send(JSON.stringify({ type: 'log', message: '[*] Parada solicitada — interrompendo sockets e filas agora...' }));
          } catch (_) {}
        } else {
          try {
            ws.send(JSON.stringify({ type: 'log', message: '[i] Nenhuma varredura em andamento para parar.' }));
          } catch (_) {}
        }
      } else if (data.type === 'export_csv') {
        const { results } = data;
        let csvContent = '\uFEFF'; // Add BOM for Excel UTF-8
        csvContent += 'IP;Estado;Hostname;Endereço MAC;Fabricante;Sistema Operacional;VM;Domínio AD;VLAN;Sub-rede;DMZ;Ambiente;Tipo;Portas Abertas (Serviços)\r\n';

        results.forEach(host => {
          const ports = Array.isArray(host.ports) ? host.ports : [];
        const portsStr = ports.length > 0 
            ? ports.map(p => `${p.port}/${p.protocol} (${p.service})`).join(', ')
            : 'Nenhuma';
          const row = [
              host.ip,
              host.status,
              host.hostname,
              host.mac,
              host.vendor,
              host.os,
              host.vm,
              host.adDomain,
              (host.vlan || 'N/A'),
              (host.subnet || 'N/A'),
              (host.isDMZ ? 'Sim' : 'Não'),
              (host.environment || 'IT'),
              (host.deviceType || 'Host Ativo'),
              '"' + portsStr + '"'
            ].join(';');

          csvContent += row + '\r\n';
        });

        try {
          const targetDir = getCsvTargetDir();
          if (!fs.existsSync(targetDir)) {
            fs.mkdirSync(targetDir, { recursive: true });
          }

          const now = new Date();
          const dateStr = now.toISOString().slice(0, 10);
          const timeStr = now.toTimeString().slice(0, 8).replace(/:/g, '-');
          const fileName = `redes_scan_${dateStr}_${timeStr}.csv`;
          const filePath = path.join(targetDir, fileName);

          fs.writeFileSync(filePath, csvContent, 'utf8');
          ws.send(JSON.stringify({ 
            type: 'log', 
            message: `[+] CSV salvo com sucesso localmente em:\n    ${filePath}` 
          }));
        } catch (err) {
          ws.send(JSON.stringify({ 
            type: 'log', 
            message: `[!] Erro ao salvar arquivo CSV no caminho especificado: ${err.message}` 
          }));
        }
      }
    } catch (err) {
      console.error('[ERROR] WebSocket message handler error:', err);
      console.error('[ERROR] Stack:', err.stack);
      try {
        ws.send(JSON.stringify({ type: 'error', message: `Erro no servidor: ${err.message}` }));
      } catch (sendErr) {
        console.error('[ERROR] Failed to send error message to client:', sendErr.message);
      }
    }
  });

  ws.on('close', () => {
    clearTimeout(authTimer);
    console.log('[WS] Cliente desconectado');
  });

  ws.on('error', (err) => {
    clearTimeout(authTimer);
    console.error('[WS] WebSocket error:', err.message);
  });
});

// Start Express server
function startServer(preferredPort, maxRetries = 5) {
  let bound = false;

  const bind = (port, retriesLeft) => {
    server.removeAllListeners('error');
    server.removeAllListeners('listening');

    server.once('error', (err) => {
      if (err.code === 'EADDRINUSE' && retriesLeft > 0) {
        const nextPort = port + 1;
        console.warn(`[HTTP] Porta ${port} em uso — tentando ${nextPort}...`);
        if (port === preferredPort) {
          console.warn('[HTTP] Dica: outra instância do NetScan (ou Node) já está rodando.');
          console.warn('[HTTP] Para reiniciar limpo: Get-Process node -ErrorAction SilentlyContinue | Stop-Process -Force');
        }
        setImmediate(() => bind(nextPort, retriesLeft - 1));
        return;
      }
      if (err.code === 'EADDRINUSE') {
        console.error(`[HTTP] Nenhuma porta livre entre ${preferredPort} e ${port}.`);
        console.error('[HTTP] Encerre processos Node antigos e rode npm start novamente.');
      } else {
        console.error('[HTTP] Erro ao iniciar servidor:', err);
      }
      process.exit(1);
    });

    server.listen(port, () => {
      if (bound) return;
      bound = true;
      server.removeAllListeners('error');
      const addr = server.address();
      const boundPort = addr && addr.port ? addr.port : port;
      if (boundPort !== preferredPort) {
        console.warn(`[HTTP] Porta preferida ${preferredPort} ocupada — servindo em http://localhost:${boundPort}`);
        console.warn('[HTTP] Use essa URL no navegador (não a porta anterior).');
      }
      console.log(`[HTTP] Servidor rodando em http://localhost:${boundPort}`);
    });
  };

  bind(preferredPort, maxRetries);
}

