      'carestream', 'agfa', 'fuji medical', 'fujifilm medical', 'ge healthcare',
      'siemens health', 'philips medical', 'sectra', 'vista imaging', 'synapse'
    ]) ||
    hasPort(portSet, [104, 11112, 2761, 2762]) ||
    hasAny(services, ['dicom'])
  ) {
    return 'Imagem / PACS / Raio-X';
  }

  // --- Monitor multiparamétrico / UTI / centro cirúrgico ---
  if (
    hasAny(text, [
      'multiparam', 'multiparâmetr', 'monitor patient', 'patient monitor',
      'uti-', '-uti', 'uti_', 'cti-', 'centro cirurgico', 'centro cirúrgico',
      'mindray', 'drager', 'dräger', 'philips monitor', 'ge monitor',
      'spacelabs', 'nihon kohden', 'datascope', 'bedside monitor',
