    return;
  }

  const data = {
    nodes: new vis.DataSet(nodes),
    edges: new vis.DataSet(edges)
  };

  const options = {
    nodes: {
      shape: 'dot',
      size: 18,
      font: { color: '#ffffff', size: 12, face: 'Plus Jakarta Sans' }
    },
    edges: {
      color: { color: '#8e96b5', highlight: '#f59e0b' },
      width: 2,
      smooth: { type: 'cubicBezier' }
    },
    layout: {
      improvedLayout: true
    },
    physics: {
      enabled: true,
      stabilization: {
        enabled: true,
        iterations: 300,
        updateInterval: 50
      },
      barnesHut: {
        gravitationalConstant: -2000,
        centralGravity: 0.18,
        springLength: 180,
        springConstant: 0.04,
        damping: 0.09
      }
    },
    interaction: {
      hover: true,
      tooltipDelay: 100,
      dragView: true,
      zoomView: true,
      multiselect: false
    }
  };

  networkInstance = new vis.Network(container, data, options);
  networkInstance.once('stabilizationIterationsDone', () => {
