function formatAdDate(iso) {
  if (!iso) return '—';
  try { return new Date(iso).toLocaleString('pt-BR'); } catch { return String(iso); }
}

function initialsFromName(name) {
  const parts = String(name || '?').trim().split(/\s+/).filter(Boolean);
  if (!parts.length) return '?';
  if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
}

function reasonLabel(reason) {
  if (reason === 'account_disabled') return 'Conta desabilitada';
  if (reason === 'removed_from_ad') return 'Removido do AD';
  return reason || 'Saída';
}

function ouFromDn(dn) {
  if (!dn) return '—';
  const parts = String(dn).split(',').slice(1).filter((p) => /^OU=/i.test(p));
  if (!parts.length) return '—';
  return parts.map((p) => p.replace(/^OU=/i, '')).reverse().join(' › ');
}

function buildComputerCardHtml(computer, { alternates = [], matchCount = 1 } = {}) {
  const hostname = escapeHtml(computer.name || computer.cn || computer.dnsHostName || 'N/A');
  const dns = escapeHtml(computer.dnsHostName || '—');
  const sam = escapeHtml(computer.sAMAccountName || '—');
  const groups = computer.groupNames || (computer.groups || []).map((g) => g.name || g) || [];
  const groupCount = computer.groupCount || groups.length;
  const pill = `<span class="ad-pill ${computer.disabled ? '' : 'ok'}">${computer.disabled ? 'Desabilitado' : 'Ativo no AD'}</span>`;
  const osLine = [computer.operatingSystem, computer.operatingSystemVersion]
    .filter(Boolean)
    .join(' · ');
  const chips = groups.map((g) => `<span class="ad-group-chip${String(g).includes('(primário)') ? ' ad-group-chip-primary' : ''}">${escapeHtml(g)}</span>`).join('')
    || '<span class="ad-empty">Nenhum grupo secundário — no AD, máquinas costumam ter só o grupo primário (ex.: Domain Computers).</span>';

  const copyPayload = encodeURIComponent(JSON.stringify({
    name: computer.name,
    dnsHostName: computer.dnsHostName,
    sAMAccountName: computer.sAMAccountName,
    operatingSystem: computer.operatingSystem,
    groups,
    distinguishedName: computer.distinguishedName,
    lastLogon: computer.lastLogon,
    disabled: computer.disabled
  }, null, 2));

  const altHtml = alternates.length
    ? `<div class="ad-section-title ad-section-title--inline">Outros resultados (${matchCount - 1})</div>
       <div class="ad-groups ad-computer-alts">
         ${alternates.map((alt) => {
      const label = escapeHtml(alt.dnsHostName || alt.name || alt.sAMAccountName || '?');
      const q = encodeURIComponent(alt.dnsHostName || alt.name || alt.sAMAccountName || '');
      return `<button type="button" class="ad-group-chip ad-computer-alt" data-ad-computer-pick="${q}">${label}</button>`;
    }).join('')}
       </div>`
    : '';

  return `
    <article class="ad-user-card ad-computer-card" data-hostname="${hostname}">
      <button type="button" class="ad-user-card-head" data-ad-toggle>
        <div class="ad-user-avatar ad-computer-avatar" aria-hidden="true">PC</div>
        <div class="ad-user-meta">
          <strong>${hostname}</strong>
          <span>${dns !== hostname ? dns + ' · ' : ''}${sam} · ${groupCount} grupo(s)</span>
        </div>
        ${pill}
      </button>
      <div class="ad-user-card-body">
        <dl class="ad-info-grid">
          <div><dt>Hostname</dt><dd>${hostname}</dd></div>
          <div><dt>DNS (AD)</dt><dd>${dns}</dd></div>
          <div><dt>Conta AD</dt><dd>${sam}</dd></div>
          <div><dt>Sistema</dt><dd>${escapeHtml(osLine || '—')}</dd></div>
          <div><dt>Service Pack</dt><dd>${escapeHtml(computer.operatingSystemServicePack || '—')}</dd></div>
          <div><dt>Descrição</dt><dd>${escapeHtml(computer.description || '—')}</dd></div>
          <div><dt>Local</dt><dd>${escapeHtml(computer.location || '—')}</dd></div>
          <div><dt>Gerenciado por</dt><dd>${escapeHtml(computer.managedBy || '—')}</dd></div>
          <div><dt>OU</dt><dd>${escapeHtml(ouFromDn(computer.distinguishedName))}</dd></div>
          <div><dt>Último logon</dt><dd>${escapeHtml(formatAdDate(computer.lastLogon))}</dd></div>
          <div><dt>Senha alterada</dt><dd>${escapeHtml(formatAdDate(computer.passwordLastSet))}</dd></div>
          <div><dt>Criado em</dt><dd>${escapeHtml(formatAdDate(computer.whenCreated))}</dd></div>
          <div><dt>Alterado em</dt><dd>${escapeHtml(formatAdDate(computer.whenChanged))}</dd></div>
          <div><dt>DN</dt><dd>${escapeHtml(computer.distinguishedName || '—')}</dd></div>
        </dl>
        <div class="ad-section-title ad-section-title--inline">Grupos / permissões</div>
        <div class="ad-groups">${chips}</div>
        ${altHtml}
        <div class="ad-card-actions">
          <button type="button" class="btn btn-secondary btn-sm" data-ad-computer-copy="${copyPayload}">Copiar dados</button>
        </div>
