          <span class="ad-dept-group-meta">${escapeHtml(String(g.coveragePct))}% · ${escapeHtml(String(g.count))}/${escapeHtml(String(data.enabledCount))} · ${escapeHtml(tierLabel(g.tier))}</span>
        </div>
      `).join('') : '<div class="ad-empty">Nenhum grupo atingiu o percentual mínimo. Diminua o “Mín. %”.</div>'}
    </div>
    <div class="ad-dept-peers-title">Colegas do departamento (${escapeHtml(String(peers.length))})</div>
    <div class="ad-dept-peers">
      ${peers.map((p) => `
        <article class="ad-user-card ad-dept-peer">
          <button type="button" class="ad-user-card-head" data-ad-toggle>
            <div class="ad-user-avatar">${escapeHtml(initialsFromName(p.displayName || p.sAMAccountName))}</div>
            <div class="ad-user-meta">
              <strong>${escapeHtml(p.displayName || p.sAMAccountName)}</strong>
              <span>${escapeHtml(p.sAMAccountName)}${p.title ? ' · ' + escapeHtml(p.title) : ''} · match ${escapeHtml(String(p.recommendedCoveragePct))}%</span>
            </div>
            <span class="ad-pill ${p.recommendedCoveragePct >= 80 ? 'ok' : ''}">${escapeHtml(String(p.recommendedMatch))}/${escapeHtml(String(p.recommendedTotal))}</span>
          </button>
          <div class="ad-user-card-body">
            <div class="ad-section-title ad-section-title--inline">Grupos</div>
            <div class="ad-groups">
              ${(p.groups || []).map((g) => `<span class="ad-group-chip">${escapeHtml(g)}</span>`).join('') || '<span class="ad-empty">Sem grupos</span>'}
            </div>
            ${p.extraGroups?.length ? `<div style="margin-top:8px;font-size:0.75rem;color:var(--text-secondary)">Extras (fora do padrão): ${escapeHtml(p.extraGroups.join(', '))}</div>` : ''}
          </div>
        </article>
      `).join('') || '<div class="ad-empty">Nenhum usuário ativo neste departamento.</div>'}
    </div>
  `;

  box.querySelectorAll('[data-ad-toggle]').forEach((btn) => {
    btn.addEventListener('click', () => {
      const card = btn.closest('.ad-user-card');
      if (card) card.classList.toggle('open');
    });
  });
}

async function loadAdGroups() {
  const status = document.getElementById('ad-group-status');
  const datalist = document.getElementById('ad-group-datalist');
  const box = document.getElementById('ad-group-results');
