  }
  const url = filter ? `/api/ad/groups?q=${encodeURIComponent(filter)}` : '/api/ad/groups';
  const res = await fetch(url);
  const data = await res.json().catch(() => ({}));
  if (!res.ok || data.ok === false) {
    if (status) {
      status.textContent = data.error || 'Falha ao listar grupos';
      status.className = 'ad-status-bar err';
    }
    return;
  }
  if (datalist) {
    datalist.innerHTML = (data.groups || [])
      .map((g) => `<option value="${escapeHtml(g.name)}"></option>`)
      .join('');
  }
  if (status) {
    status.textContent = data.count
      ? `${data.count} grupo(s) · ${data.gPrefixCount || 0} com prefixo G_${data.capturedAt ? ' · snapshot ' + new Date(data.capturedAt).toLocaleString('pt-BR') : ''}`
      : 'Nenhum grupo no snapshot — rode uma varredura.';
    status.className = `ad-status-bar${data.count ? ' ok' : ''}`;
  }
  if (box && data.groups?.length) {
    const shown = Math.min(data.groups.length, 120);
    box.innerHTML = `
      <h3 class="ad-section-title">Grupos${filter ? ' filtrados' : ''} (${escapeHtml(String(shown))}${data.groups.length > 120 ? '+' : ''})</h3>
      <div class="ad-chip-grid">
        ${(data.groups || []).slice(0, 120).map((g) => `
          <button type="button" class="ad-dept-chip" data-ad-group-pick="${escapeHtml(g.name)}">
            <strong>${escapeHtml(g.name)}</strong>
            <span>${escapeHtml(String(g.enabledCount || 0))} ativos · ${escapeHtml(String(g.memberCount || 0))} total</span>
          </button>
        `).join('')}
      </div>
    `;
  } else if (box && !filter) {
    box.innerHTML = '<div class="ad-empty">Sem grupos no snapshot.</div>';
  }
}

async function searchAdGroupMembers() {
  const group = document.getElementById('ad-group-query')?.value?.trim() || '';
  const live = document.getElementById('ad-group-live')?.checked === true;
  const includeDisabled = document.getElementById('ad-group-include-disabled')?.checked === true;
  const status = document.getElementById('ad-group-status');
  const box = document.getElementById('ad-group-results');
  const btn = document.getElementById('ad-group-search');

  if (!group) {
    if (status) {
      status.textContent = 'Informe o nome do grupo (ex: G_HEBO…).';
      status.className = 'ad-status-bar err';
    }
    return;
  }

  if (status) {
    status.textContent = live ? 'Consultando AD ao vivo…' : 'Buscando membros no snapshot…';
    status.className = 'ad-status-bar';
  }
  if (btn) btn.disabled = true;

  try {
    const url = `/api/ad/group-members?group=${encodeURIComponent(group)}&live=${live ? '1' : '0'}&includeDisabled=${includeDisabled ? '1' : '0'}`;
    const res = await fetch(url);
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) throw new Error(data.error || 'Falha na busca');

    renderGroupMembers(data);
    if (status) {
      status.textContent = `${data.group}: ${data.enabledCount} membro(s) ativo(s) · ${data.memberCount} total · fonte ${data.source}`;
      status.className = 'ad-status-bar ok';
    }
  } catch (err) {
    if (status) {
      status.textContent = err.message;
      status.className = 'ad-status-bar err';
    }
    if (box) box.innerHTML = `<div class="ad-empty">${escapeHtml(err.message)}</div>`;
  } finally {
    if (btn) btn.disabled = false;
  }
}

function renderGroupMembers(data) {
  const box = document.getElementById('ad-group-results');
  if (!box) return;

  const members = data.members || [];
  const logins = members.map((m) => m.sAMAccountName).filter(Boolean).join('\n');
