        <strong>Membros de ${escapeHtml(data.group)}</strong>
        <p>${escapeHtml(String(data.enabledCount))} ativo(s) · ${escapeHtml(String(data.memberCount))} total · fonte ${escapeHtml(data.source || 'snapshot')}</p>
