function setLoopBanner(text, kind = '') {
  const el = document.getElementById('loop-status-banner');
  if (!el) return;
  el.textContent = text;
  el.className = `loop-banner${kind ? ` ${kind}` : ''}`;
}

function applyLoopStatusPayload(data) {
  const summary = data.summary;
  let bannerText = '';
  let bannerKind = '';

  if (data.running) {
    bannerText = summary?.message
      ? `MONITOR ATIVO — ${summary.message}${summary.at ? ` · ${new Date(summary.at).toLocaleTimeString()}` : ''}`
      : 'MONITOR ATIVO — aguardando amostragens SNMP…';
    bannerKind = summary?.suspects?.length || summary?.likelyOrigin?.ok ? 'warn' : 'ok';
  } else if (summary) {
    bannerText = summary.message || 'Monitor parado';
    if (summary.likelyOrigin?.ok) {
      bannerText = summary.likelyOrigin.message;
      bannerKind = 'warn';
    } else if (summary.at) {
      bannerText += ` · ${new Date(summary.at).toLocaleTimeString()}`;
    }
    if (!bannerKind) bannerKind = summary.suspects?.length ? 'warn' : '';
  } else if (data.message) {
    bannerText = data.message;
    bannerKind = data.running ? 'ok' : '';
  }

  if (bannerText) setLoopBanner(bannerText, bannerKind);

  if (summary?.suspects) renderLoopSuspects(summary.suspects, summary.likelyOrigin);
  else if (summary?.results) {
    const ports = summary.results.flatMap((r) => r.ports || []).filter((p) => p.score >= 30);
    ports.sort((a, b) => (b.originScore || b.score) - (a.originScore || a.score));
    renderLoopSuspects(ports.slice(0, 40), summary.likelyOrigin);
  }
}

async function refreshLoopStatus() {
  const res = await fetch('/api/loop/status');
  if (!res.ok) throw new Error('Falha ao obter status do loop');
  const data = await res.json();
  applyLoopStatusPayload(data);
  return data;
}

function renderLoopSuspects(rows, likelyOrigin) {
  const body = document.getElementById('loop-suspects-body');
  if (!body) return;
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) {
    const hint = likelyOrigin?.ok
      ? `<tr class="empty-row"><td colspan="9">${escapeHtml(likelyOrigin.message)}</td></tr>`
      : '<tr><td colspan="9" class="loop-empty">Nenhuma porta suspeita nesta rodada.</td></tr>';
    body.innerHTML = hint;
    return;
  }
  body.innerHTML = list.map((r) => `
    <tr class="level-${escapeHtml(r.level || 'ok')}${r.isLikelyOrigin ? ' loop-origin-row' : ''}">
      <td>${escapeHtml(r.emoji || '')} ${escapeHtml(r.status || '')} <small>(${escapeHtml(String(r.score ?? 0))}${r.originScore ? ` · orig ${escapeHtml(String(r.originScore))}` : ''})</small></td>
      <td><strong>${escapeHtml(r.switchName || r.switchIp || '')}</strong><br><span>${escapeHtml(r.switchIp || '')} · ${escapeHtml(r.vendor || '')}</span></td>
      <td>${escapeHtml(r.port || '')}${r.originRank ? `<br><small>#${escapeHtml(String(r.originRank))}</small>` : ''}</td>
      <td>${escapeHtml(String(r.broadcastPerSec ?? 0))}</td>
      <td>${escapeHtml(String(r.errorDelta ?? 0))}</td>
      <td>${escapeHtml(String(r.macFlaps ?? 0))}${r.crossSwitchFlaps ? `<br><small>+${escapeHtml(String(r.crossSwitchFlaps))} x-sw</small>` : ''}</td>
      <td>${escapeHtml(r.stpLabel || '—')}</td>
      <td>${escapeHtml(r.probabilityOrigin || '—')}</td>
      <td class="loop-evidence">${escapeHtml((r.evidence || []).join(' · ') || '—')}</td>
    </tr>
  `).join('');
}

async function loadLoopConfig() {
  const res = await fetch('/api/loop/config');
  if (!res.ok) throw new Error('Falha ao carregar config de loop');
  const cfg = await res.json();
  const community = document.getElementById('loop-community');
  const interval = document.getElementById('loop-interval');
  const timeout = document.getElementById('loop-timeout');
  if (community) community.value = cfg.community || 'public';
  if (interval) interval.value = cfg.pollIntervalSec || 12;
  if (timeout) timeout.value = cfg.timeoutMs || 3500;
  window.__loopSwitches = cfg.switches || [];
  renderLoopSwitchList(window.__loopSwitches);
  return cfg;
}

function renderLoopSwitchList(switches) {
  const box = document.getElementById('loop-switch-list');
  if (!box) return;
  const list = switches || [];
  if (!list.length) {
    box.innerHTML = '<div class="ad-empty">Nenhum switch cadastrado. Adicione IPs gerenciáveis (community SNMP habilitada).</div>';
