    const ip = result.remoteAgent.ip ? ` (${result.remoteAgent.ip})` : '';
    parts.push(`<strong>Remoto:</strong> ${escapeHtml(result.remoteAgent.hostname)}${escapeHtml(ip)}`);
  }
