async function exportAutoTestFile(apiPath, ext, result) {
  const res = await fetch(apiPath, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ result })
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.error || 'Falha na exportação');
  }
  const blob = await res.blob();
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  const stamp = (result.ranAt || new Date().toISOString()).slice(0, 10);
  a.href = url;
  a.download = `autotest-${result.profileName || 'rede'}-${stamp}.${ext}`.replace(/\s+/g, '-');
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

