    return;
  }

  box.innerHTML = `
    <h3 class="ad-section-title">${escapeHtml(String(list.length))} resultado(s)</h3>
    ${list.map((u) => {
    const sugs = (u.suggestions || []).map((s) => {
      let badge = '<span class="oracle-badge unknown">AD não checado</span>';
      if (s.adExists === true) {
        const name = s.adUser?.displayName ? ` · ${s.adUser.displayName}` : '';
        const st = s.adUser?.enabled === false ? ' (desabilitado)' : '';
        badge = `<span class="oracle-badge exists">Já existe no AD${st}${escapeHtml(name)}</span>`;
      } else if (s.adExists === false) {
        badge = '<span class="oracle-badge free">Livre no AD</span>';
