// Connect to WebSocket Server (Etapa 7 — auth handshake após login dashboard)
function updateConnectionBadgeWaitingLogin() {
  connectionBadge.textContent = 'Aguardando login';
  connectionBadge.className = 'badge badge-disconnected';
}

function disconnectWebSocket() {
  wsAuthenticated = false;
  if (wsReconnectTimer) {
    clearTimeout(wsReconnectTimer);
    wsReconnectTimer = null;
  }
  if (socket) {
    try {
      socket.onclose = null;
      socket.close();
    } catch (_) {}
    socket = null;
  }
  connectionBadge.textContent = 'Desconectado';
  connectionBadge.className = 'badge badge-disconnected';
}

function connectWebSocket() {
  if (!canonBootToken) {
    updateConnectionBadgeWaitingLogin();
    return;
  }

  if (socket && (socket.readyState === WebSocket.OPEN || socket.readyState === WebSocket.CONNECTING)) {
    return;
  }

  if (wsReconnectTimer) {
    clearTimeout(wsReconnectTimer);
    wsReconnectTimer = null;
  }

  wsAuthenticated = false;
  const wsProtocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
  const wsUrl = `${wsProtocol}//${window.location.host}`;

  connectionBadge.textContent = 'Conectando...';
  connectionBadge.className = 'badge badge-connecting';
  socket = new WebSocket(wsUrl);

  socket.onopen = () => {
    try {
      socket.send(JSON.stringify({ type: 'auth', token: canonBootToken }));
    } catch (err) {
      console.error('WebSocket auth send failed:', err);
      connectionBadge.textContent = 'Erro de conexão';
      connectionBadge.className = 'badge badge-disconnected';
    }
  };

  socket.onclose = (event) => {
    wsAuthenticated = false;
    connectionBadge.textContent = 'Desconectado';
    connectionBadge.className = 'badge badge-disconnected';
    if (event.code === 4401) {
      logToConsole('[!] Sessão WebSocket recusada — faça login novamente.', 'error-msg');
      if (canonBootToken) {
        setCanonBootToken('');
        openCanonLoginModal({ target: 'boot' });
      }
      return;
    }
    if (!canonBootToken) return;
    logToConsole(
      `[!] Conexão perdida (code=${event.code}${event.reason ? `, reason=${event.reason}` : ''}). Tentando reconectar...`,
      'error-msg'
    );
    wsReconnectTimer = setTimeout(connectWebSocket, 3000);
  };

  socket.onerror = (err) => {
    console.error('WebSocket Error:', err);
    if (!socket || socket.readyState !== WebSocket.OPEN) {
      connectionBadge.textContent = 'Erro de conexão';
      connectionBadge.className = 'badge badge-disconnected';
      logToConsole(`[!] Erro no WebSocket: readyState=${socket?.readyState ?? 'n/a'}`, 'error-msg');
    }
  };

  socket.onmessage = (event) => {
    try {
      const data = JSON.parse(event.data);
      handleServerMessage(data);
    } catch (e) {
      console.error('Failed to parse WebSocket message:', e);
    }
  };
}

// Handle WebSocket messages
function handleServerMessage(data) {
  switch (data.type) {
    case 'auth_ok':
      wsAuthenticated = true;
      connectionBadge.textContent = 'Conectado';
      connectionBadge.className = 'badge badge-connected';
      logToConsole('[i] Conexão autenticada com o servidor de varredura.', 'system-msg');
      break;

    case 'auth_fail':
      wsAuthenticated = false;
      connectionBadge.textContent = 'Auth recusada';
      connectionBadge.className = 'badge badge-disconnected';
      logToConsole(`[!] ${data.message || 'Autenticação WebSocket recusada.'}`, 'error-msg');
      break;

    case 'log':
      const logClass = getLogClass(data.message);
      logToConsole(data.message, logClass);
      break;

    case 'scan_started':
      totalIps = data.total;
      scannedIps = 0;
      progressContainer.classList.remove('hidden');
      updateProgressBar(0);
      if (typeof window.setInventoryScanProgress === 'function') window.setInventoryScanProgress(1);
      break;

    case 'host_found':
      scannedIps++;
      if (totalIps > 0) {
        updateProgressBar(Math.round((scannedIps / totalIps) * 100));
      }
      // Add or update active host
      addOrUpdateHost(data.host);
      if (data.log) logToConsole(data.log, 'success-msg');
      updateStats();
      break;

    case 'host_inactive':
      scannedIps++;
      if (totalIps > 0) {
        updateProgressBar(Math.round((scannedIps / totalIps) * 100));
      }
      // Add or update inactive host
      addOrUpdateHost(data.host);
      if (data.log) logToConsole(data.log, 'system-msg');
      updateStats();
      break;

    case 'host_update':
      addOrUpdateHost(data.host);
      if (data.log) logToConsole(data.log, 'accent-msg');
      updateStats();
      break;

    case 'port_result':
      {
        const { ip, portResult } = data;
        // Só portas realmente abertas entram na UI / contagem / verde
        if (!portResult || portResult.state !== 'open') break;
        const host = scanResults.find(h => h.ip === ip);
        if (host) {
          if (!Array.isArray(host.ports)) host.ports = [];
          if (!host.ports.some(p => p.port === portResult.port && p.protocol === portResult.protocol)) {
            host.ports.push(portResult);
            host.ports.sort((a, b) => a.port - b.port);
            updateHostRow(host);
          }
        }
        if (data.log) logToConsole(data.log, 'success-msg');
      }
      break;

    case 'ad_audit_sync':
      if (data.audit) {
        window.__lastAdAudit = data.audit;
        if (data.audit.newlyDeparted > 0) {
          const badge = document.getElementById('ad-audit-open-btn');
          if (badge) badge.classList.add('pulse');
        }
      }
      break;

    case 'loop_alert':
      if (data.alert) {
        const btn = document.getElementById('loop-detect-open-btn');
        if (btn) btn.classList.add('pulse');
        logToConsole(
          `[LOOP] ${data.alert.emoji || '⚠'} ${data.alert.switchName || data.alert.switchIp} ${data.alert.port}: ${data.alert.status} (score ${data.alert.score})`,
          'error-msg'
        );
        if (window.__loopUiActive) {
          prependLoopAlert(data.alert);
          refreshLoopStatus().catch(() => {});
        }
      }
      break;

    case 'loop_status':
      if (window.__loopUiActive || data.running) {
        applyLoopStatusPayload(data);
      }
      break;

    case 'progress':
      if (typeof data.percent === 'number') {
        updateProgressBar(data.percent);
        if (typeof window.setInventoryScanProgress === 'function') window.setInventoryScanProgress(data.percent);
      }
      break;

    case 'complete':
      updateProgressBar(100);
      if (typeof window.setInventoryScanProgress === 'function') window.setInventoryScanProgress(100);
      setTimeout(() => {
        progressContainer.classList.add('hidden');
        if (typeof window.setInventoryScanProgress === 'function') window.setInventoryScanProgress(0);
      }, 1500);
      if (data.log) logToConsole(data.log, 'success-msg');
      endScan(data.summary);
      break;

    case 'stopped':
      updateProgressBar(100);
      setTimeout(() => {
        progressContainer.classList.add('hidden');
      }, 1500);
      if (data.log) logToConsole(data.log, 'system-msg');
      endScan(data.summary);
      break;

    case 'error':
      progressContainer.classList.add('hidden');
      logToConsole(`[!] ERRO: ${data.message}`, 'error-msg');
      endScan(null, true);
      break;
  }
}

// Logger helper
function logToConsole(message, className = '') {
  const line = document.createElement('div');
  line.className = `terminal-line ${className}`;
  line.textContent = message;
  consoleOutput.appendChild(line);
  consoleOutput.scrollTop = consoleOutput.scrollHeight;
}

// Update progress bar UI
function updateProgressBar(percent) {
  percent = Math.min(100, Math.max(0, percent));
  progressBar.style.width = `${percent}%`;
  progressText.textContent = `${percent}%`;
}

// Get CSS class based on log content
function getLogClass(msg) {
  if (msg.startsWith('[+]')) return 'success-msg';
  if (msg.startsWith('[-]')) return 'system-msg';
  if (msg.startsWith('[*]')) return 'accent-msg';
  if (msg.startsWith('[~]')) return 'accent-msg';
  if (msg.startsWith('[!]')) return 'error-msg';
  return '';
}

// Fill Target Input from suggestion links
function fillTarget(val) {
  targetInput.value = val;
  targetInput.focus();
}

// Toggle Visibility of Custom Ports Input
function toggleCustomPorts() {
  if (portsPreset.value === 'custom') {
    customPortsGroup.classList.remove('hidden');
    customPortsInput.required = true;
  } else {
    customPortsGroup.classList.add('hidden');
    customPortsInput.required = false;
  }
}

// Start Scan process
function startScan() {
  if (!canonBootToken) {
    openCanonLoginModal({ target: 'boot' });
    return;
  }
  if (!socket || socket.readyState !== WebSocket.OPEN || !wsAuthenticated) {
    alert('Aguardando autenticação WebSocket. Faça login e aguarde o badge "Conectado".');
    if (canonBootToken && (!socket || socket.readyState !== WebSocket.OPEN)) connectWebSocket();
    return;
  }

  const target = targetInput.value.trim();
  if (!target) {
    alert('Por favor, insira um endereço IP, faixa ou CIDR.');
    return;
  }

  // Parse TCP ports selection
  let portsTCP = [];
  const preset = portsPreset.value;
  if (preset === 'integra') {
    portsTCP = typeof buildIntegraPorts === 'function' ? buildIntegraPorts() : (PORT_PRESETS?.integra || []);
  } else if (preset === 'wellknown') {
    portsTCP = typeof buildWellKnownPorts === 'function' ? buildWellKnownPorts() : [];
  } else if (preset === 'common') {
    portsTCP = PORT_PRESETS?.common || [21, 22, 23, 25, 53, 80, 110, 135, 139, 143, 443, 445, 3389, 8080];
  } else if (preset === 'web') {
    portsTCP = PORT_PRESETS?.web || [80, 443, 8080];
  } else if (preset === 'devices') {
    portsTCP = PORT_PRESETS?.devices || [80, 443, 515, 554, 9100];
  } else if (preset === 'custom') {
    const rawPorts = customPortsInput.value.split(',');
    for (let p of rawPorts) {
      const portNum = parseInt(p.trim(), 10);
      if (!isNaN(portNum) && portNum >= 1 && portNum <= 65535) {
        portsTCP.push(portNum);
      }
    }
    if (portsTCP.length === 0) {
      alert('Por favor, insira portas TCP válidas (1-65535).');
      return;
    }
  }

  // Parse UDP ports selection
  const scanUdp = scanUdpCheckbox.checked;
  const portsUDP = scanUdp
    ? (typeof UDP_INTEGRA !== 'undefined' ? UDP_INTEGRA : [53, 123, 137, 138, 161, 162, 1900, 5353])
    : [];

  if (preset !== 'none' && portsTCP.length === 0) {
    alert('Não foi possível montar a lista de portas. Recarregue a página (Ctrl+F5).');
    return;
  }

  logToConsole(
    `[*] Portas TCP selecionadas: ${portsTCP.length || 0} | UDP: ${portsUDP.length || 0}`,
    'accent-msg'
  );

  const timeout = parseInt(timeoutInput.value, 10);
  const concurrency = parseInt(concurrencyInput.value, 10);

  // UI Updates for starting scan
  startBtn.disabled = true;
  startBtn.classList.add('pulse');
  startBtn.querySelector('.loader').classList.remove('hidden');
  startBtn.querySelector('.btn-text').textContent = 'Escaneando...';
  stopBtn.disabled = false;
  exportBtn.disabled = true;

  // Clear previous results
  scanResults = [];
  resultsPage = 1;
  renderTable();
  logToConsole('[*] Iniciando nova varredura de rede...', 'accent-msg');

  // Timer Initialization
  scanStartTime = Date.now();
  scanTimer.textContent = '0.00s';
  clearInterval(scanTimerInterval);
  scanTimerInterval = setInterval(() => {
    const elapsed = ((Date.now() - scanStartTime) / 1000).toFixed(2);
    scanTimer.textContent = `${elapsed}s`;
  }, 100);

  // Send start payload to backend
  socket.send(JSON.stringify({
    type: 'start',
    target,
    portsTCP,
    portsUDP,
    timeout,
    concurrency,
    scanUdp
  }));
}

function stopScan() {
  if (!socket || socket.readyState !== WebSocket.OPEN || !wsAuthenticated) {
    alert('Erro: servidor desconectado ou não autenticado. Não é possível parar a varredura.');
    return;
  }
  stopBtn.disabled = true;
  stopBtn.textContent = 'Parando...';
  logToConsole('[*] Solicitando parada imediata da varredura...', 'system-msg');
  socket.send(JSON.stringify({ type: 'stop' }));
}

// End Scan process
function endScan(summary, isError = false) {
  clearInterval(scanTimerInterval);

  // UI Restore
  startBtn.disabled = false;
  startBtn.classList.remove('pulse');
  startBtn.querySelector('.loader').classList.add('hidden');
  startBtn.querySelector('.btn-text').textContent = 'Iniciar Varredura';

  if (!isError && scanResults.length > 0) {
    exportBtn.disabled = false;
  }
  stopBtn.disabled = true;
  stopBtn.textContent = 'Parar Varredura';

  if (summary) {
    statTime.textContent = `${summary.time}s`;
    scanTimer.textContent = `${summary.time}s`;
  }
  updateStats();

  if (!isError) {
    loadIdleHosts().catch(() => {});
    if (typeof window.refreshInventoryIfOpen === 'function') window.refreshInventoryIfOpen();
  }
}

// Add host to results memory and render to table
function addOrUpdateHost(host) {
  if (Array.isArray(host.ports)) {
    host.ports = host.ports.filter(isTrulyOpenPort);
  }
  const index = scanResults.findIndex(h => h.ip === host.ip);
  if (index !== -1) {
    scanResults[index] = { ...scanResults[index], ...host };
    if (Array.isArray(host.ports)) {
      scanResults[index].ports = host.ports.filter(isTrulyOpenPort);
    }
  } else {
    scanResults.push(host);
  }

  // Sort IP range before rendering (ascending order)
  scanResults.sort((a, b) => {
    const aNum = a.ip.split('.').reduce((ipInt, octet) => (ipInt << 8) + parseInt(octet, 10), 0) >>> 0;
    const bNum = b.ip.split('.').reduce((ipInt, octet) => (ipInt << 8) + parseInt(octet, 10), 0) >>> 0;
    return aNum - bNum;
  });

  renderTable();
}

// Render the results table
function isTrulyOpenPort(p) {
  return p && p.state === 'open';
}

function renderPortsHtml(host) {
  const ports = Array.isArray(host.ports) ? host.ports.filter(isTrulyOpenPort) : [];
  if (ports.length === 0) {
    return host.status === 'Ativo'
      ? '<span class="text-muted">Nenhuma porta aberta encontrada</span>'
      : '<span class="text-muted">—</span>';
  }

  const ordered = [...ports].sort((a, b) => a.port - b.port);
  const badges = ordered.map(p => {
    const titleText = `${p.service || ''} ${p.version && p.version !== 'N/A' ? '(' + p.version + ')' : ''} [aberta]`;
    return `<span class="port-badge open" title="${escapeHtml(titleText)}">${escapeHtml(String(p.port))}/${escapeHtml(p.protocol || 'TCP')}${p.service ? ' · ' + escapeHtml(p.service) : ''}</span>`;
  }).join(' ');

  return `<div class="ports-open-count">${ordered.length} aberta(s)</div>${badges}`;
}

function getFilteredResults() {
  const filterVal = searchInput.value.toLowerCase();
  return scanResults.filter(host => {
    return host.ip.toLowerCase().includes(filterVal) ||
           host.status.toLowerCase().includes(filterVal) ||
           host.hostname.toLowerCase().includes(filterVal) ||
           host.os.toLowerCase().includes(filterVal) ||
           (host.vm || '').toLowerCase().includes(filterVal) ||
           (host.adDomain || '').toLowerCase().includes(filterVal) ||
           (host.description || '').toLowerCase().includes(filterVal) ||
           (host.vlan || '').toLowerCase().includes(filterVal) ||
           (host.subnet || '').toLowerCase().includes(filterVal) ||
           ((host.isDMZ ? 'dmz' : '')).toLowerCase().includes(filterVal) ||
           (host.environment || '').toLowerCase().includes(filterVal) ||
           (host.deviceType || '').toLowerCase().includes(filterVal);
  });
}

function compareScanHostsForSort(a, b, columnIndex, asc) {
  let valA = '';
  let valB = '';

  switch (columnIndex) {
    case 0:
      valA = a.ip.split('.').reduce((ipInt, octet) => (ipInt << 8) + parseInt(octet, 10), 0) >>> 0;
      valB = b.ip.split('.').reduce((ipInt, octet) => (ipInt << 8) + parseInt(octet, 10), 0) >>> 0;
      return asc ? valA - valB : valB - valA;
    case 1:
      valA = a.status.toLowerCase();
      valB = b.status.toLowerCase();
      break;
    case 2:
      valA = a.hostname.toLowerCase();
      valB = b.hostname.toLowerCase();
      break;
    case 3:
      valA = a.os.toLowerCase();
      valB = b.os.toLowerCase();
      break;
    case 4:
      valA = (a.vm || '').toLowerCase();
      valB = (b.vm || '').toLowerCase();
      break;
    case 5:
      valA = (a.adDomain || '').toLowerCase();
      valB = (b.adDomain || '').toLowerCase();
      break;
    case 6:
      valA = (a.description || '').toLowerCase();
      valB = (b.description || '').toLowerCase();
      break;
    case 7:
      valA = (a.vlan || '').toLowerCase();
      valB = (b.vlan || '').toLowerCase();
      break;
    case 8:
      valA = (a.subnet || '').toLowerCase();
      valB = (b.subnet || '').toLowerCase();
      break;
    case 9:
      valA = a.isDMZ ? 'sim' : 'nao';
      valB = b.isDMZ ? 'sim' : 'nao';
      break;
    case 10:
      valA = (a.environment || '').toLowerCase();
      valB = (b.environment || '').toLowerCase();
      break;
    case 11:
      valA = (a.deviceType || '').toLowerCase();
      valB = (b.deviceType || '').toLowerCase();
      break;
    default:
      return 0;
  }

  if (valA < valB) return asc ? -1 : 1;
  if (valA > valB) return asc ? 1 : -1;
  return 0;
}

function updateResultsTableMeta(totalFiltered, page, pageCount, rangeStart, rangeEnd) {
  if (resultsTableMeta) {
    if (totalFiltered === 0) {
      resultsTableMeta.textContent = scanResults.length === 0 && !searchInput.value.trim()
        ? 'Nenhum registro'
        : 'Nenhum registro corresponde ao filtro';
    } else {
      const plural = totalFiltered !== 1 ? 's' : '';
      resultsTableMeta.textContent = `Mostrando ${rangeStart}–${rangeEnd} de ${totalFiltered} registro${plural}`;
    }
  }
  if (resultsPageIndicator) {
    resultsPageIndicator.textContent = `${page} / ${Math.max(pageCount, 1)}`;
  }
  if (resultsPagePrev) resultsPagePrev.disabled = page <= 1;
  if (resultsPageNext) resultsPageNext.disabled = page >= pageCount || totalFiltered === 0;
}

function updateSortHeaders() {
  if (!resultsTable) return;
  const ths = resultsTable.querySelectorAll('thead th');
  ths.forEach((th, idx) => {
    th.classList.remove('canon-ds-sorted-asc', 'canon-ds-sorted-desc');
    if (idx === resultsSortColumn) {
      th.classList.add(resultsSortAsc ? 'canon-ds-sorted-asc' : 'canon-ds-sorted-desc');
    }
  });
}

function appendHostRow(host) {
  const row = document.createElement('tr');
  row.id = `row-${host.ip.replace(/\./g, '_')}`;

  const statusClass = host.status === 'Ativo' ? 'state-active' : 'state-inactive';
  const portsHtml = renderPortsHtml(host);

  const vmLabel = host.vm === 'Sim'
    ? `Sim${host.vmType && host.vmType !== 'N/A' ? ' (' + host.vmType + ')' : ''}`
    : (host.vm === 'Provável'
      ? `Provável${host.vmType && host.vmType !== 'N/A' ? ' (' + host.vmType + ')' : ''}`
      : 'Não');
  const vmBadge = host.vm === 'Sim'
    ? `<span class="state-badge" style="background:rgba(255,165,0,0.2);color:#ffa500;" title="${escapeHtml((host.vmEvidence || []).join('; '))}">${escapeHtml(vmLabel)}</span>`
    : (host.vm === 'Provável'
      ? `<span class="state-badge" style="background:rgba(245,158,11,0.15);color:#f59e0b;" title="${escapeHtml((host.vmEvidence || []).join('; '))}">${escapeHtml(vmLabel)}</span>`
      : '<span class="text-muted">Não</span>');
  const sources = Array.isArray(host.enrichmentSources) ? host.enrichmentSources.join(', ') : '';
  const detailTitle = [
    host.adDn && host.adDn !== 'N/A' ? `DN: ${host.adDn}` : null,
    host.lastLogon && host.lastLogon !== 'N/A' ? `LastLogon: ${host.lastLogon}` : null,
    host.adLocation && host.adLocation !== 'N/A' ? `Local: ${host.adLocation}` : null,
    sources ? `Fontes: ${sources}` : null
  ].filter(Boolean).join(' | ');
  const vlanTitle = [
    host.vlanId != null ? `ID: ${host.vlanId}` : null,
    host.vlanSource && host.vlanSource !== 'N/A' ? `Fonte: ${host.vlanSource}` : null,
    host.vlanName && host.vlanName !== 'N/A' ? `Nome: ${host.vlanName}` : null
  ].filter(Boolean).join(' | ');

  const hostnameTitle = [
    host.hostnameSource === 'fallback' ? 'Nome inferido — dispositivo não expõe DNS/SNMP/SMB' : null,
    host.hostnameSource === 'history' ? 'Hostname do histórico de varreduras' : null,
    detailTitle
  ].filter(Boolean).join(' | ');

  row.innerHTML = `
    <td><strong>${escapeHtml(host.ip)}</strong></td>
    <td><span class="state-badge ${statusClass}">${escapeHtml(host.status)}</span></td>
    <td title="${escapeHtml(hostnameTitle)}">${escapeHtml(host.hostname)}</td>
    <td title="${escapeHtml(host.osVersion && host.osVersion !== 'N/A' ? host.osVersion : '')}">${escapeHtml(host.os)}</td>
    <td>${vmBadge}</td>
    <td>${escapeHtml(host.adDomain || 'N/A')}</td>
    <td title="${escapeHtml(host.description || '')}">${escapeHtml(host.description || 'N/A')}</td>
    <td title="${escapeHtml(vlanTitle)}">${escapeHtml(host.vlan || 'N/A')}</td>
    <td class="cell-subnet">${escapeHtml(host.subnet || 'N/A')}</td>
    <td>${host.isDMZ ? '<span class="state-badge dmz">Sim</span>' : '<span class="text-muted">Não</span>'}</td>
    <td>${escapeHtml(host.environment || 'IT')}</td>
    <td>${escapeHtml(host.deviceType || 'Host Ativo')}</td>
    <td><div class="ports-list">${portsHtml}</div></td>
  `;
  resultsBody.appendChild(row);
}

function renderTable() {
  resultsBody.innerHTML = '';

  const filtered = getFilteredResults();
  const totalFiltered = filtered.length;
  const pageCount = totalFiltered === 0 ? 1 : Math.ceil(totalFiltered / resultsPageSize);

  if (resultsPage > pageCount) resultsPage = pageCount;
  if (resultsPage < 1) resultsPage = 1;

  const start = (resultsPage - 1) * resultsPageSize;
  const end = Math.min(start + resultsPageSize, totalFiltered);
  const rangeStart = totalFiltered === 0 ? 0 : start + 1;
  const rangeEnd = end;

  updateResultsTableMeta(totalFiltered, resultsPage, pageCount, rangeStart, rangeEnd);
  updateSortHeaders();

  if (totalFiltered === 0) {
    const emptyMsg = scanResults.length === 0 && !searchInput.value.trim()
      ? 'Nenhum dado de varredura disponível. Configure o scanner acima para iniciar.'
      : 'Nenhum host corresponde aos filtros ou à varredura atual.';
    resultsBody.innerHTML = `
      <tr class="empty-row">
        <td colspan="13">${emptyMsg}</td>
      </tr>
    `;
    return;
  }

  filtered.slice(start, end).forEach(appendHostRow);
}

// Update single host row in DOM without full re-render (smooth real-time update)
function updateHostRow(host) {
  const rowId = `row-${host.ip.replace(/\./g, '_')}`;
  const row = document.getElementById(rowId);
  if (row) {
