function escapeHtml(value) {
  return String(value == null ? '' : value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function formatLocalDateTime(isoOrMs) {
  if (isoOrMs == null || isoOrMs === '') return '—';
  const d = typeof isoOrMs === 'number' ? new Date(isoOrMs) : new Date(isoOrMs);
  if (Number.isNaN(d.getTime())) return '—';
  return d.toLocaleString('pt-BR');
}

function buildIdleQueryParams() {
  const raw = parseInt(document.getElementById('idle-value').value, 10);
  const value = Number.isFinite(raw) && raw >= 0 ? raw : 0;
  const unit = document.getElementById('idle-unit').value;
  const params = new URLSearchParams();
  if (unit === 'minutes') params.set('minutes', String(value));
  else if (unit === 'hours') params.set('hours', String(value));
  else params.set('days', String(value));
  return params;
}

