function formatIdleAuditLogLine(data) {
  if (!data) return '';
  const idle = data.idleCount ?? 0;
  const still = data.stillInactive ?? data.inactiveNow ?? idle;
  const subnets = data.subnetCount ?? 0;
  const thr = data.thresholdLabel || '—';
  const neu = data.newlyIdle ?? 0;
  const recPersisted = data.recoveredActivePersisted ?? 0;
  const recLastScan = data.recoveredActive ?? 0;

  if ((data.scanCount ?? 0) === 0) {
    return 'Nenhuma varredura salva ainda. Rode uma varredura para inventariar os IPs ociosos.';
  }
  if (idle === 0) {
    return data.message || `Nenhum IP ocioso para o limiar ${thr}.`;
  }

  let line = `Auditoria global: ${idle} ocioso(s) ≥ ${thr} · ${subnets} faixa(s)`;
  if (still !== idle) line += ` · ${still} inativos no histórico`;
  if (neu > 0) line += ` · ${neu} novos na última varredura`;
  if (recPersisted > 0) line += ` · ${recPersisted} ativos de novo`;
  else if (recLastScan > 0) line += ` · ${recLastScan} voltaram ativo na última varredura`;
  return line;
}

