    </button>`,
    `<button type="button" class="idle-chip idle-chip-history" data-idle-action="scroll-table" title="IPs já vistos em varreduras">
      <span class="idle-chip-value">${(data.totalTracked || 0).toLocaleString('pt-BR')}</span>
      <span class="idle-chip-label">no histórico</span>
    </button>`,
    `<span class="idle-chip idle-chip-scans" title="Varreduras salvas no histórico">
      <span class="idle-chip-value">${scans.toLocaleString('pt-BR')}</span>
      <span class="idle-chip-label">leituras</span>
    </span>`,
    `<span class="idle-chip idle-chip-threshold" title="Limiar de inatividade aplicado na consulta">
      <span class="idle-chip-value">${escapeHtml(thr)}</span>
      <span class="idle-chip-label">limiar</span>
    </span>`
  ];

  if (neu > 0) {
    chips.push(`<span class="idle-chip idle-chip-new" title="Novos inativos na última varredura">
      <span class="idle-chip-value">+${neu}</span>
      <span class="idle-chip-label">novos</span>
    </span>`);
  }
  if (recPersisted > 0) {
    chips.push(`<div class="idle-chip-group idle-chip-group-recovered">
      <span class="idle-chip idle-chip-recovered" title="IPs que voltaram a ativo e permanecem na lista até ficarem inativos de novo">
        <span class="idle-chip-value">${recPersisted.toLocaleString('pt-BR')}</span>
        <span class="idle-chip-label">ativos de novo</span>
      </span>
      <button type="button" class="btn btn-tertiary btn-sm idle-recovered-toggle" data-idle-action="toggle-recovered" title="Ver lista de IPs ativos de novo">
        Ver IPs
      </button>
    </div>`);
  }

  el.innerHTML = `
    <div class="idle-status-bar">
      <div class="idle-status-head">
        <span class="idle-status-title">Auditoria global</span>
        <span class="idle-status-scan" title="${scans} leitura(s) salva(s)">
          Última leitura · ${escapeHtml(scanLabel)}
        </span>
      </div>
      <div class="idle-status-chips">${chips.join('')}</div>
    </div>`;

  el.classList.remove('idle-status-error');
  el.classList.add('idle-status-rich', 'idle-status-flash');
  setTimeout(() => el.classList.remove('idle-status-flash'), 700);
  wireIdleStatusInteractions(el);
  renderRecoveredActivePanel(data);
}

function updateIdleTableMeta(totalFiltered, page, pageCount, rangeStart, rangeEnd) {
  const meta = document.getElementById('idle-table-meta');
  const indicator = document.getElementById('idle-page-indicator');
  const prevBtn = document.getElementById('idle-page-prev');
  const nextBtn = document.getElementById('idle-page-next');

  if (meta) {
    if (totalFiltered === 0) {
      meta.textContent = idleHostsCache.length === 0 ? 'Nenhum registro' : 'Nenhum registro na página';
    } else {
      const plural = totalFiltered !== 1 ? 's' : '';
      meta.textContent = `Mostrando ${rangeStart}–${rangeEnd} de ${totalFiltered} registro${plural}`;
    }
  }
  if (indicator) indicator.textContent = `${page} / ${Math.max(pageCount, 1)}`;
  if (prevBtn) prevBtn.disabled = page <= 1;
  if (nextBtn) nextBtn.disabled = page >= pageCount || totalFiltered === 0;
}

function appendIdleHostRow(host) {
  const sinceLabel = host.inactiveSinceIso || host.inactiveSince
    ? formatLocalDateTime(host.inactiveSinceIso || host.inactiveSince)
    : (host.lastSeenIso || host.lastSeen ? formatLocalDateTime(host.lastSeenIso || host.lastSeen) : '—');
  const wasActive = host.neverActive ? 'Não (sempre inativo)' : `Sim (${host.timesSeenActive || 0}×)`;
  const row = document.createElement('tr');
  row.innerHTML = `
    <td>${escapeHtml(host.ip)}</td>
    <td>${escapeHtml(host.hostname || 'N/A')}</td>
    <td>${escapeHtml(sinceLabel)}</td>
    <td><span class="text-danger">${escapeHtml(host.idleFor || '—')}</span></td>
    <td>${escapeHtml(formatLocalDateTime(host.lastCheckedIso || host.lastChecked))}</td>
    <td>${escapeHtml(host.deviceType || 'N/A')}</td>
    <td class="cell-subnet">${escapeHtml(host.subnet || 'N/A')}</td>
    <td>${escapeHtml(wasActive)}</td>
  `;
  return row;
}

function renderIdleTablePage(emptyMsg) {
  const idleBody = document.getElementById('idle-body');
  if (!idleBody) return;

  idleBody.innerHTML = '';
  const totalFiltered = idleHostsCache.length;
  const pageCount = totalFiltered === 0 ? 1 : Math.ceil(totalFiltered / idlePageSize);

  if (idlePage > pageCount) idlePage = pageCount;
  if (idlePage < 1) idlePage = 1;

  const start = (idlePage - 1) * idlePageSize;
  const end = Math.min(start + idlePageSize, totalFiltered);
  const rangeStart = totalFiltered === 0 ? 0 : start + 1;
  const rangeEnd = end;

  updateIdleTableMeta(totalFiltered, idlePage, pageCount, rangeStart, rangeEnd);

  if (totalFiltered === 0) {
    idleBody.innerHTML = `
      <tr class="empty-row">
        <td colspan="8">${escapeHtml(emptyMsg || 'Nenhum IP ocioso para o limiar atual.')}</td>
      </tr>`;
    return;
  }

  idleHostsCache.slice(start, end).forEach((host) => {
    idleBody.appendChild(appendIdleHostRow(host));
  });
}

async function loadIdleHosts() {
  const idleBody = document.getElementById('idle-body');
  const idleExportBtnEl = document.getElementById('idle-export-btn');
  const idleExportXlsxBtnEl = document.getElementById('idle-export-xlsx-btn');

  if (!idleBody) return;

  if (!canonBootToken) {
    setIdleStatus('Faça login para consultar IPs ociosos.', false);
    return;
  }

  setIdleStatus('Consultando histórico de leituras...');

  const params = buildIdleQueryParams();
  const res = await fetch(`/api/idle-hosts?${params.toString()}`);
  if (res.status === 401) {
    setCanonBootToken('');
    setIdleStatus('Sessão expirada — faça login novamente.', true);
    openCanonLoginModal({ target: 'boot' });
    return;
  }
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.error || `HTTP ${res.status}`);
  }

  const data = await res.json();
  lastIdlePayload = data;

  const hosts = Array.isArray(data.hosts) ? data.hosts : [];
  idleHostsCache = hosts;
  idlePage = 1;
  if (idleExportBtnEl) idleExportBtnEl.disabled = hosts.length === 0;
  if (idleExportXlsxBtnEl) idleExportXlsxBtnEl.disabled = hosts.length === 0;

  if (hosts.length === 0) {
    const tracked = data.totalTracked || 0;
    const emptyMsg = tracked === 0
      ? 'Histórico vazio — rode uma varredura para popular IPs ociosos.'
      : (data.message || `Nenhum IP ocioso para o limiar ${data.thresholdLabel || '—'}.`);

    renderIdleTablePage(emptyMsg);
    if (data.totalTracked > 0 && (data.stillInactive > 0 || data.inactiveNow > 0)) {
      renderIdleStatusDashboard(data);
    } else {
      setIdleStatus(emptyMsg);
    }
    logToConsole(`[i] Inatividade: ${emptyMsg}`, 'system-msg');
    return;
  }

  renderIdleTablePage();
  renderIdleStatusDashboard(data);
  logToConsole(`[+] ${formatIdleAuditLogLine(data)}`, 'success-msg');

  const panel = document.querySelector('.idle-panel');
  if (panel) panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

function exportIdleJson() {
  if (!lastIdlePayload || !Array.isArray(lastIdlePayload.hosts) || lastIdlePayload.hosts.length === 0) {
    alert('Nenhum resultado de ociosos para exportar. Clique em Analisar primeiro.');
    return;
  }

  const blob = new Blob([JSON.stringify(lastIdlePayload, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-');
  a.href = url;
  a.download = `ips_ociosos_${stamp}.json`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

async function exportIdleExcel() {
  if (!lastIdlePayload || !Array.isArray(lastIdlePayload.hosts) || lastIdlePayload.hosts.length === 0) {
    alert('Nenhum resultado de ociosos para exportar. Clique em Analisar primeiro.');
    return;
  }

  if (!canonBootToken) {
    openCanonLoginModal({ target: 'boot' });
    alert('Faça login (IPs ociosos) para exportar Excel.');
    return;
  }

  const btn = document.getElementById('idle-export-xlsx-btn');
  if (btn) btn.disabled = true;
  try {
    logToConsole('[*] Gerando Excel de IPs ociosos...', 'accent-msg');
    const response = await fetch('/api/idle-hosts/export-xlsx', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(lastIdlePayload)
    });
    if (response.status === 401) {
      setCanonBootToken('');
      openCanonLoginModal({ target: 'boot' });
      alert('Sessão expirada — faça login novamente.');
      return;
    }
    if (!response.ok) {
      const err = await response.json().catch(() => ({}));
      throw new Error(err.error || `HTTP ${response.status}`);
    }
    const blob = await response.blob();
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-');
    link.download = `NetScan_Canon_ips_ociosos_${stamp}.xlsx`;
    document.body.appendChild(link);
    link.click();
    link.remove();
    URL.revokeObjectURL(url);
    logToConsole('[+] Excel de IPs ociosos exportado com sucesso.', 'success-msg');
  } catch (err) {
    alert(`Falha ao exportar Excel: ${err.message}`);
    logToConsole(`[!] Erro ao exportar Excel de ociosos: ${err.message}`, 'error-msg');
  } finally {
    if (btn) btn.disabled = !lastIdlePayload?.hosts?.length;
  }
}

function wireIdleControls() {
  const idleRefreshBtn = document.getElementById('idle-refresh-btn');
  const idleExportBtn = document.getElementById('idle-export-btn');
  const idleExportXlsxBtn = document.getElementById('idle-export-xlsx-btn');

  if (idleRefreshBtn && !idleRefreshBtn.dataset.wired) {
    idleRefreshBtn.dataset.wired = '1';
    idleRefreshBtn.addEventListener('click', async () => {
      idleRefreshBtn.disabled = true;
      try {
        await loadIdleHosts();
      } catch (err) {
        setIdleStatus(`Falha: ${err.message}`, true);
        alert(`Falha ao analisar ociosos: ${err.message}`);
        logToConsole(`[!] Falha ao analisar ociosos: ${err.message}`, 'error-msg');
      } finally {
        idleRefreshBtn.disabled = false;
      }
    });
  }

  if (idleExportBtn && !idleExportBtn.dataset.wired) {
    idleExportBtn.dataset.wired = '1';
    idleExportBtn.addEventListener('click', exportIdleJson);
  }

  if (idleExportXlsxBtn && !idleExportXlsxBtn.dataset.wired) {
    idleExportXlsxBtn.dataset.wired = '1';
    idleExportXlsxBtn.addEventListener('click', () => exportIdleExcel());
  }

  const idlePageSizeSelect = document.getElementById('idle-page-size');
  const idlePagePrev = document.getElementById('idle-page-prev');
  const idlePageNext = document.getElementById('idle-page-next');

  if (idlePageSizeSelect && !idlePageSizeSelect.dataset.wired) {
    idlePageSizeSelect.dataset.wired = '1';
    idlePageSize = parseInt(idlePageSizeSelect.value, 10) || 50;
    idlePageSizeSelect.addEventListener('change', () => {
      idlePageSize = parseInt(idlePageSizeSelect.value, 10) || 50;
      idlePage = 1;
      renderIdleTablePage();
    });
  }
  if (idlePagePrev && !idlePagePrev.dataset.wired) {
    idlePagePrev.dataset.wired = '1';
    idlePagePrev.addEventListener('click', () => {
      if (idlePage > 1) {
        idlePage -= 1;
        renderIdleTablePage();
      }
    });
  }
  if (idlePageNext && !idlePageNext.dataset.wired) {
    idlePageNext.dataset.wired = '1';
    idlePageNext.addEventListener('click', () => {
      idlePage += 1;
      renderIdleTablePage();
    });
  }
}

wireIdleControls();
window.addEventListener('DOMContentLoaded', wireIdleControls);

// --- Mapa por Ala ---
let lastAlaMapPayload = null;
let alaPage = 1;
let alaPageSize = 50;
let alaHostsCache = [];

function setAlaStatus(message, isError = false) {
  const el = document.getElementById('ala-status');
  if (!el) return;
  el.textContent = message;
  el.classList.toggle('idle-status-error', !!isError);
}

function buildAlaQueryParams() {
  const params = new URLSearchParams();
  if (document.getElementById('ala-include-inactive')?.checked) params.set('includeInactive', '1');
  else params.set('includeInactive', '0');
  if (document.getElementById('ala-poll-switches')?.checked) params.set('pollSwitches', '1');
  else params.set('pollSwitches', '0');
  return params;
}

function renderAlaFilterOptions(report) {
  const sel = document.getElementById('ala-filter-select');
  if (!sel) return;
  const current = sel.value;
  const opts = ['<option value="">Todas as alas</option>'];
  for (const ala of report.alas || []) {
    opts.push(`<option value="${escapeHtml(ala.id)}">${escapeHtml(ala.name)} (${ala.hostCount})</option>`);
  }
  if (report.unassigned?.hostCount) {
    opts.push(`<option value="${escapeHtml(report.unassigned.id)}">${escapeHtml(report.unassigned.name)} (${report.unassigned.hostCount})</option>`);
  }
  sel.innerHTML = opts.join('');
  if (current) sel.value = current;
}

function renderAlaGroups(report) {
  const box = document.getElementById('ala-groups');
  if (!box) return;
  const cards = (report.alas || [])
    .filter((a) => a.hostCount > 0)
    .map((a) => `
      <article class="ala-group-card canon-ds-ala-card">
        <strong>${escapeHtml(a.name)}</strong>
        <span>${a.hostCount}</span>
      </article>
    `).join('');
  const unassigned = report.unassigned?.hostCount
    ? `<article class="ala-group-card canon-ds-ala-card"><strong>${escapeHtml(report.unassigned.name)}</strong><span>${report.unassigned.hostCount}</span></article>`
    : '';
  box.innerHTML = cards + unassigned || '<div class="ad-empty">Nenhum host classificado ainda.</div>';
}

function updateAlaTableMeta(totalFiltered, page, pageCount, rangeStart, rangeEnd) {
  const meta = document.getElementById('ala-table-meta');
  const indicator = document.getElementById('ala-page-indicator');
  const prevBtn = document.getElementById('ala-page-prev');
  const nextBtn = document.getElementById('ala-page-next');

  if (meta) {
    if (totalFiltered === 0) {
      meta.textContent = alaHostsCache.length === 0 ? 'Nenhum registro' : 'Nenhum registro na página';
    } else {
      const plural = totalFiltered !== 1 ? 's' : '';
      meta.textContent = `Mostrando ${rangeStart}–${rangeEnd} de ${totalFiltered} registro${plural}`;
    }
  }
  if (indicator) indicator.textContent = `${page} / ${Math.max(pageCount, 1)}`;
  if (prevBtn) prevBtn.disabled = page <= 1;
  if (nextBtn) nextBtn.disabled = page >= pageCount || totalFiltered === 0;
}

function buildAlaHostRowHtml(h) {
  const swPort = h.switchPort && h.switchPort !== '—'
    ? `${escapeHtml(h.switchName !== '—' ? h.switchName : h.switchIp)} · ${escapeHtml(h.switchPort)}`
    : '—';
  const confCls = h.confidence === 'alta' ? 'text-accent' : (h.confidence === 'baixa' ? 'text-danger' : '');
  return `
    <tr>
      <td>${escapeHtml(h.alaName)}</td>
      <td>${escapeHtml(h.ip)}</td>
      <td>${escapeHtml(h.hostname || 'N/A')}</td>
      <td>${escapeHtml(h.status || '—')}</td>
      <td>${escapeHtml(h.vlan || 'N/A')}</td>
      <td>${swPort}</td>
      <td>${escapeHtml(h.adLocation || '—')}</td>
      <td><span class="${confCls}">${escapeHtml(h.confidence || '—')}</span></td>
    </tr>
  `;
}

function renderAlaTablePage(emptyMsg) {
  const body = document.getElementById('ala-body');
  if (!body) return;

  const totalFiltered = alaHostsCache.length;
  const pageCount = totalFiltered === 0 ? 1 : Math.ceil(totalFiltered / alaPageSize);

  if (alaPage > pageCount) alaPage = pageCount;
  if (alaPage < 1) alaPage = 1;

  const start = (alaPage - 1) * alaPageSize;
  const end = Math.min(start + alaPageSize, totalFiltered);
  const rangeStart = totalFiltered === 0 ? 0 : start + 1;
  const rangeEnd = end;

  updateAlaTableMeta(totalFiltered, alaPage, pageCount, rangeStart, rangeEnd);

  if (totalFiltered === 0) {
    body.innerHTML = `<tr class="empty-row"><td colspan="8">${escapeHtml(emptyMsg || 'Nenhum host para exibir.')}</td></tr>`;
    return;
  }

  body.innerHTML = alaHostsCache.slice(start, end).map(buildAlaHostRowHtml).join('');
}

function renderAlaTable(report, resetPage = true) {
  const filterId = document.getElementById('ala-filter-select')?.value || '';
  let hosts = Array.isArray(report.hosts) ? report.hosts : [];
  if (filterId) hosts = hosts.filter((h) => h.alaId === filterId);
  alaHostsCache = hosts;
  if (resetPage) alaPage = 1;
  renderAlaTablePage(report.message || 'Nenhum host para exibir.');
}

function renderAlaMapReport(report) {
  lastAlaMapPayload = report;
  const total = document.getElementById('ala-stat-total');
  const classified = document.getElementById('ala-stat-classified');
  const unclassified = document.getElementById('ala-stat-unclassified');
  const alas = document.getElementById('ala-stat-alas');
  const exportBtn = document.getElementById('ala-export-xlsx-btn');

  if (total) total.textContent = String(report.totalHosts || 0);
  if (classified) classified.textContent = String(report.classifiedCount || 0);
  if (unclassified) unclassified.textContent = String(report.unclassifiedCount || 0);
  if (alas) alas.textContent = String(report.alaCount || 0);
  if (exportBtn) exportBtn.disabled = !(report.hosts || []).length;

  renderAlaFilterOptions(report);
  renderAlaGroups(report);
  renderAlaTable(report);
  setAlaStatus(report.message || 'Mapa gerado.');
}

async function loadAlaMapReport() {
  const btn = document.getElementById('ala-refresh-btn');
