async function saveAlaMapConfigEditor() {
  const editor = document.getElementById('ala-config-editor');
  if (!editor) return;
  if (!canonBootToken) {
    setAlaStatus('Faça login (IPs ociosos) para salvar a configuração.', true);
    openCanonLoginModal({ target: 'boot' });
    return;
  }
  let parsed;
  try {
    parsed = JSON.parse(editor.value);
  } catch (err) {
    alert(`JSON inválido: ${err.message}`);
    return;
  }
  const res = await fetch('/api/ala-map/config', {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ config: parsed })
  });
  if (res.status === 401) {
    setCanonBootToken('');
    setAlaStatus('Sessão expirada — faça login novamente.', true);
    openCanonLoginModal({ target: 'boot' });
    return;
  }
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.error || 'Falha ao salvar');
  editor.value = JSON.stringify(data.config || parsed, null, 2);
  setAlaStatus('Configuração de alas salva.', false);
}

