function wireAlaMapControls() {
  const refreshBtn = document.getElementById('ala-refresh-btn');
  const exportBtn = document.getElementById('ala-export-xlsx-btn');
  const filterSel = document.getElementById('ala-filter-select');
  const loadCfgBtn = document.getElementById('ala-config-load-btn');
  const saveCfgBtn = document.getElementById('ala-config-save-btn');

  if (refreshBtn && !refreshBtn.dataset.wired) {
    refreshBtn.dataset.wired = '1';
