  if (exportBtn && !exportBtn.dataset.wired) {
    exportBtn.dataset.wired = '1';
    exportBtn.addEventListener('click', () => exportAlaMapExcel());
  }
  if (filterSel && !filterSel.dataset.wired) {
    filterSel.dataset.wired = '1';
    filterSel.addEventListener('change', () => {
      if (lastAlaMapPayload) renderAlaTable(lastAlaMapPayload, true);
    });
  }
  if (loadCfgBtn && !loadCfgBtn.dataset.wired) {
    loadCfgBtn.dataset.wired = '1';
    loadCfgBtn.addEventListener('click', () => {
      loadAlaMapConfigEditor().catch((e) => alert(e.message));
    });
  }
  if (saveCfgBtn && !saveCfgBtn.dataset.wired) {
    saveCfgBtn.dataset.wired = '1';
    saveCfgBtn.addEventListener('click', () => {
      saveAlaMapConfigEditor().catch((e) => alert(e.message));
    });
  }

  const alaPageSizeSelect = document.getElementById('ala-page-size');
  const alaPagePrev = document.getElementById('ala-page-prev');
  const alaPageNext = document.getElementById('ala-page-next');

  if (alaPageSizeSelect && !alaPageSizeSelect.dataset.wired) {
    alaPageSizeSelect.dataset.wired = '1';
    alaPageSize = parseInt(alaPageSizeSelect.value, 10) || 50;
    alaPageSizeSelect.addEventListener('change', () => {
      alaPageSize = parseInt(alaPageSizeSelect.value, 10) || 50;
      alaPage = 1;
      renderAlaTablePage();
    });
  }
  if (alaPagePrev && !alaPagePrev.dataset.wired) {
    alaPagePrev.dataset.wired = '1';
    alaPagePrev.addEventListener('click', () => {
      if (alaPage > 1) {
        alaPage -= 1;
        renderAlaTablePage();
      }
    });
  }
  if (alaPageNext && !alaPageNext.dataset.wired) {
    alaPageNext.dataset.wired = '1';
    alaPageNext.addEventListener('click', () => {
      alaPage += 1;
      renderAlaTablePage();
    });
  }
}

