  `;
}

function buildUserCardHtml(user, { live = false } = {}) {
  const sam = escapeHtml(user.sAMAccountName || 'N/A');
  const display = escapeHtml(user.displayName || user.sAMAccountName || 'N/A');
  const groups = (user.permissionsAtDeparture && user.permissionsAtDeparture.groupNames)
    || user.groupNames
    || (user.groups || []).map((g) => g.name || g)
    || [];
  const groupCount = user.permissionsAtDeparture?.groupCount
    || user.groupCount
    || groups.length;
  const departedAt = user.departedAt || user.lastDepartedAt;
  const reason = user.departReason || user.lastDepartReason;
  const pill = live
    ? `<span class="ad-pill ${user.disabled ? '' : 'ok'}">${user.disabled ? 'Desabilitado' : 'Ativo no AD'}</span>`
    : `<span class="ad-pill">${escapeHtml(reasonLabel(reason))}</span>`;

  const chips = groups.map((g) => `<span class="ad-group-chip">${escapeHtml(g)}</span>`).join('')
    || '<span class="ad-empty">Sem grupos registrados</span>';

  const copyPayload = encodeURIComponent(JSON.stringify({
    sAMAccountName: user.sAMAccountName,
    displayName: user.displayName,
    groups,
    department: user.department,
    title: user.title,
    mail: user.mail,
    departedAt,
    reason
  }, null, 2));

  return `
    <article class="ad-user-card" data-sam="${sam}">
      <button type="button" class="ad-user-card-head" data-ad-toggle>
        <div class="ad-user-avatar">${escapeHtml(initialsFromName(user.displayName || user.sAMAccountName))}</div>
        <div class="ad-user-meta">
          <strong>${display}</strong>
          <span>${sam}${user.department ? ' · ' + escapeHtml(user.department) : ''} · ${groupCount} grupo(s)</span>
        </div>
        ${pill}
      </button>
      <div class="ad-user-card-body">
        <dl class="ad-info-grid">
          <div><dt>Login</dt><dd>${sam}</dd></div>
          <div><dt>UPN</dt><dd>${escapeHtml(user.userPrincipalName || '—')}</dd></div>
          <div><dt>E-mail</dt><dd>${escapeHtml(user.mail || '—')}</dd></div>
          <div><dt>Cargo</dt><dd>${escapeHtml(user.title || '—')}</dd></div>
          <div><dt>Departamento</dt><dd>${escapeHtml(user.department || '—')}</dd></div>
          <div><dt>Gestor</dt><dd>${escapeHtml(user.manager || '—')}</dd></div>
          ${!live ? `<div><dt>Saiu em</dt><dd>${escapeHtml(formatAdDate(departedAt))}</dd></div>` : ''}
          ${!live ? `<div><dt>Motivo</dt><dd>${escapeHtml(reasonLabel(reason))}</dd></div>` : ''}
          <div><dt>Último logon</dt><dd>${escapeHtml(formatAdDate(user.lastLogon))}</dd></div>
          <div><dt>DN</dt><dd>${escapeHtml(user.distinguishedName || '—')}</dd></div>
        </dl>
        <div class="ad-section-title ad-section-title--inline">Permissões / grupos</div>
        <div class="ad-groups">${chips}</div>
        <div class="ad-card-actions">
          <button type="button" class="btn btn-secondary btn-sm" data-ad-copy="${copyPayload}">Copiar permissões</button>
          ${!live ? `<button type="button" class="btn btn-tertiary btn-sm" data-ad-remove="${sam}">Remover desta lista</button>` : ''}
        </div>
      </div>
    </article>
  `;
}

function normalizeSearchText(value) {
  return String(value || '')
    .replace(/\uFFFD/g, '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function renderDepartedList(filterText = '') {
  const list = document.getElementById('ad-departed-list');
  const stats = document.getElementById('ad-departed-stats');
  if (!list) return;

  const q = normalizeSearchText(filterText).trim();
  const filtered = adDepartedCache.filter((u) => {
    if (!q) return true;
    const blob = normalizeSearchText([
      u.sAMAccountName, u.displayName, u.department, u.title, u.mail,
      ...(u.groupNames || []), u.departReason
    ].join(' '));
    return blob.includes(q);
  });

  if (stats) {
    stats.innerHTML = `<span class="ad-stat-badge">${filtered.length} exibidos</span><span class="ad-stat-badge">${adDepartedCache.length} arquivados</span><span class="ad-stat-badge">Arquivo local permanente</span>`;
  }

  if (!filtered.length) {
    list.innerHTML = `<div class="ad-empty">${adDepartedCache.length ? 'Nenhum resultado para o filtro.' : 'Nenhuma saída arquivada ainda. Rode varreduras para gerar a base e detectar saídas.'}</div>`;
    return;
  }

  list.innerHTML = filtered.map((u) => buildUserCardHtml(u, { live: false })).join('');
}

async function refreshDepartedList({ importDisabled = false } = {}) {
  const qs = importDisabled ? '?refreshDisabled=1' : '';
  const res = await fetch(`/api/ad/departed${qs}`);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  const data = await readApiJson(res);
  adDepartedCache = Array.isArray(data.users) ? data.users : [];
  const filter = document.getElementById('ad-departed-filter');
  renderDepartedList(filter ? filter.value : '');
}

async function lookupLiveAdUser(query) {
  const box = document.getElementById('ad-live-result');
  if (!box) return;
  const q = String(query || '').trim();
  if (!q) {
    box.innerHTML = '<div class="ad-empty">Digite um login AD.</div>';
    return;
  }
  box.innerHTML = '<div class="ad-empty">Consultando Active Directory...</div>';
  try {
    const res = await fetch(`/api/ad/user?q=${encodeURIComponent(q)}`);
    const data = await readApiJson(res);
    if (!res.ok || !data.ok) {
      box.innerHTML = `<div class="ad-empty">${escapeHtml(data.error || 'Usuário não encontrado')}</div>`;
      return;
    }
    box.innerHTML = buildUserCardHtml(data.user, { live: true });
  } catch (err) {
    box.innerHTML = `<div class="ad-empty">${escapeHtml(err.message)}</div>`;
  }
}

async function lookupLiveAdComputer(query) {
  const box = document.getElementById('ad-computer-result');
  const status = document.getElementById('ad-computer-status');
  if (!box) return;
  const q = String(query || '').trim();
  if (!q) {
    box.innerHTML = '<div class="ad-empty">Digite o hostname da máquina.</div>';
    if (status) status.textContent = 'Informe o hostname para consultar o AD.';
    return;
  }
  box.innerHTML = '<div class="ad-empty">Consultando computador no Active Directory...</div>';
  if (status) status.textContent = `Buscando "${q}" no AD...`;
  try {
    const res = await fetch(`/api/ad/computer?q=${encodeURIComponent(q)}`);
    const data = await readApiJson(res);
    if (res.status === 401 || data.code === 'AUTH_REQUIRED') {
      box.innerHTML = '<div class="ad-empty">Sessão expirada — faça login novamente em Login ADUC.</div>';
      if (status) {
        status.textContent = 'Autenticação necessária.';
        status.className = 'ad-status-bar error';
      }
      return;
    }
    if (!res.ok || !data.ok) {
      box.innerHTML = `<div class="ad-empty">${escapeHtml(data.error || 'Computador não encontrado')}</div>`;
      if (status) {
        status.textContent = data.error || 'Computador não encontrado.';
        status.className = 'ad-status-bar error';
      }
      return;
    }
    box.innerHTML = buildComputerCardHtml(data.computer, {
      alternates: data.alternates || [],
      matchCount: data.matchCount || 1
    });
    if (status) {
      const host = data.computer?.dnsHostName || data.computer?.name || q;
      const extra = (data.matchCount || 1) > 1 ? ` · ${data.matchCount} resultado(s) no AD` : '';
      status.textContent = `Encontrado: ${host}${extra}`;
      status.className = 'ad-status-bar ok';
    }
  } catch (err) {
    box.innerHTML = `<div class="ad-empty">${escapeHtml(err.message)}</div>`;
    if (status) {
      status.textContent = err.message;
      status.className = 'ad-status-bar error';
    }
  }
}

function wireAdAuditUi() {
  const openBtn = document.getElementById('ad-audit-open-btn');
  const closeBtn = document.getElementById('ad-modal-close');
  const backdrop = document.getElementById('ad-modal-backdrop');
  const lookupBtn = document.getElementById('ad-user-lookup-btn');
  const lookupInput = document.getElementById('ad-user-query');

  if (openBtn && !openBtn.dataset.wired) {
    openBtn.dataset.wired = '1';
    openBtn.addEventListener('click', () => openAdModal('departed'));
  }
  if (closeBtn && !closeBtn.dataset.wired) {
    closeBtn.dataset.wired = '1';
    closeBtn.addEventListener('click', closeAdModal);
  }
  if (backdrop && !backdrop.dataset.wired) {
    backdrop.dataset.wired = '1';
    backdrop.addEventListener('click', (e) => {
      if (e.target === backdrop) closeAdModal();
    });
  }

  document.querySelectorAll('#ad-modal-backdrop .ad-tab').forEach((tab) => {
    if (tab.dataset.wired) return;
    tab.dataset.wired = '1';
    tab.addEventListener('click', () => switchAdTab(tab.dataset.adTab));
  });

  const filter = document.getElementById('ad-departed-filter');
  if (filter && !filter.dataset.wired) {
    filter.dataset.wired = '1';
    filter.addEventListener('input', () => renderDepartedList(filter.value));
  }

  const refresh = document.getElementById('ad-departed-refresh');
  if (refresh && !refresh.dataset.wired) {
    refresh.dataset.wired = '1';
    refresh.addEventListener('click', () => {
      refreshDepartedList({ importDisabled: true }).catch((err) => alert(err.message));
    });
  }

  const clearBtn = document.getElementById('ad-departed-clear');
  if (clearBtn && !clearBtn.dataset.wired) {
    clearBtn.dataset.wired = '1';
    clearBtn.addEventListener('click', async () => {
      if (!confirm('Apagar o arquivo permanente de saídas AD? Esta ação não pode ser desfeita.')) return;
      const res = await fetch('/api/ad/departed', { method: 'DELETE' });
      const data = await res.json().catch(() => ({}));
      if (handleDestructiveAuthFailure(res, data, { modalTarget: 'ad' })) return;
      if (!res.ok) return alert(data.error || 'Falha ao apagar arquivo.');
      await refreshDepartedList();
      logToConsole('[i] Arquivo de auditoria AD apagado pelo operador.', 'system-msg');
    });
  }

  const liveSearch = document.getElementById('ad-live-search');
  const liveInput = document.getElementById('ad-live-query');
  if (liveSearch && !liveSearch.dataset.wired) {
    liveSearch.dataset.wired = '1';
    liveSearch.addEventListener('click', () => lookupLiveAdUser(liveInput?.value));
  }
  if (liveInput && !liveInput.dataset.wired) {
    liveInput.dataset.wired = '1';
    liveInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') lookupLiveAdUser(liveInput.value);
    });
  }

  const computerSearch = document.getElementById('ad-computer-search');
  const computerInput = document.getElementById('ad-computer-query');
  if (computerSearch && !computerSearch.dataset.wired) {
    computerSearch.dataset.wired = '1';
    computerSearch.addEventListener('click', () => lookupLiveAdComputer(computerInput?.value));
  }
  if (computerInput && !computerInput.dataset.wired) {
    computerInput.dataset.wired = '1';
    computerInput.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') lookupLiveAdComputer(computerInput.value);
    });
  }

  if (lookupBtn && !lookupBtn.dataset.wired) {
    lookupBtn.dataset.wired = '1';
    lookupBtn.addEventListener('click', () => {
      const q = lookupInput ? lookupInput.value : '';
      openAdModal('live', {
        afterOpen: () => {
          const live = document.getElementById('ad-live-query');
          if (live) live.value = q;
          lookupLiveAdUser(q);
        }
      });
    });
  }
  if (lookupInput && !lookupInput.dataset.wired) {
    lookupInput.dataset.wired = '1';
    lookupInput.addEventListener('keydown', (e) => {
      if (e.key !== 'Enter') return;
      e.preventDefault();
      lookupBtn?.click();
    });
  }

  // Departamento → padrão de permissões
  const deptAnalyze = document.getElementById('ad-dept-analyze');
  const deptQuery = document.getElementById('ad-dept-query');
  const deptRefresh = document.getElementById('ad-dept-refresh-list');
  if (deptAnalyze && !deptAnalyze.dataset.wired) {
    deptAnalyze.dataset.wired = '1';
    deptAnalyze.addEventListener('click', () => analyzeAdDepartment());
  }
  if (deptQuery && !deptQuery.dataset.wired) {
    deptQuery.dataset.wired = '1';
    deptQuery.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') analyzeAdDepartment();
    });
  }
  if (deptRefresh && !deptRefresh.dataset.wired) {
    deptRefresh.dataset.wired = '1';
    deptRefresh.addEventListener('click', () => loadAdDepartments().catch((e) => alert(e.message)));
  }

  const groupSearch = document.getElementById('ad-group-search');
  const groupQuery = document.getElementById('ad-group-query');
  const groupRefresh = document.getElementById('ad-group-refresh-list');
  if (groupSearch && !groupSearch.dataset.wired) {
    groupSearch.dataset.wired = '1';
    groupSearch.addEventListener('click', () => searchAdGroupMembers());
  }
  if (groupQuery && !groupQuery.dataset.wired) {
    groupQuery.dataset.wired = '1';
    groupQuery.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') searchAdGroupMembers();
    });
    groupQuery.addEventListener('input', () => {
      clearTimeout(groupQuery._filterTimer);
      groupQuery._filterTimer = setTimeout(() => loadAdGroups().catch(() => {}), 280);
    });
  }
  if (groupRefresh && !groupRefresh.dataset.wired) {
    groupRefresh.dataset.wired = '1';
    groupRefresh.addEventListener('click', () => loadAdGroups().catch((e) => alert(e.message)));
  }

  const groupResults = document.getElementById('ad-group-results');
  if (groupResults && !groupResults.dataset.wiredDeleg) {
    groupResults.dataset.wiredDeleg = '1';
    groupResults.addEventListener('click', async (e) => {
      const copyBtn = e.target.closest('[data-ad-group-copy]');
      if (copyBtn) {
        try {
          const raw = decodeURIComponent(copyBtn.getAttribute('data-ad-group-copy') || '');
          await navigator.clipboard.writeText(raw);
          const prev = copyBtn.textContent;
          copyBtn.textContent = 'Copiado!';
          setTimeout(() => { copyBtn.textContent = prev; }, 1200);
        } catch {
          alert('Não foi possível copiar.');
        }
        return;
      }
      const pick = e.target.closest('[data-ad-group-pick]');
      if (pick) {
        const name = pick.getAttribute('data-ad-group-pick') || '';
        const input = document.getElementById('ad-group-query');
        if (input) input.value = name;
        searchAdGroupMembers();
      }
    });
  }

  const deptResults = document.getElementById('ad-dept-results');
  if (deptResults && !deptResults.dataset.wiredDeleg) {
    deptResults.dataset.wiredDeleg = '1';
    deptResults.addEventListener('click', async (e) => {
      const copyBtn = e.target.closest('[data-ad-dept-copy]');
      if (copyBtn) {
        try {
          const raw = decodeURIComponent(copyBtn.getAttribute('data-ad-dept-copy') || '');
          await navigator.clipboard.writeText(raw);
          const prev = copyBtn.textContent;
          copyBtn.textContent = 'Copiado!';
          setTimeout(() => { copyBtn.textContent = prev; }, 1200);
        } catch {
          alert('Não foi possível copiar.');
        }
      }
      const pick = e.target.closest('[data-ad-dept-pick]');
      if (pick) {
        const name = pick.getAttribute('data-ad-dept-pick') || '';
        const input = document.getElementById('ad-dept-query');
        if (input) input.value = name;
        analyzeAdDepartment();
      }
    });
  }

  const list = document.getElementById('ad-departed-list');
  const liveBox = document.getElementById('ad-live-result');
  const computerBox = document.getElementById('ad-computer-result');
  const binder = (root) => {
    if (!root || root.dataset.wiredDeleg) return;
    root.dataset.wiredDeleg = '1';
    root.addEventListener('click', async (e) => {
      const toggle = e.target.closest('[data-ad-toggle]');
      if (toggle) {
        const card = toggle.closest('.ad-user-card');
        if (card) card.classList.toggle('open');
        return;
      }
      const copyBtn = e.target.closest('[data-ad-copy]');
      if (copyBtn) {
        try {
          const raw = decodeURIComponent(copyBtn.getAttribute('data-ad-copy') || '');
          await navigator.clipboard.writeText(raw);
          copyBtn.textContent = 'Copiado!';
          setTimeout(() => { copyBtn.textContent = 'Copiar permissões'; }, 1200);
        } catch {
          alert('Não foi possível copiar.');
        }
        return;
      }
      const removeBtn = e.target.closest('[data-ad-remove]');
      if (removeBtn) {
        const sam = removeBtn.getAttribute('data-ad-remove');
        if (!confirm(`Remover ${sam} da auditoria de saídas?`)) return;
        const res = await fetch(`/api/ad/departed/${encodeURIComponent(sam)}`, { method: 'DELETE' });
        const data = await res.json().catch(() => ({}));
        if (handleDestructiveAuthFailure(res, data, { modalTarget: 'ad' })) return;
        if (!res.ok) return alert(data.error || 'Falha ao remover.');
        await refreshDepartedList();
      }
    });
  };
  binder(list);
  binder(liveBox);
  binder(computerBox);
  binder(groupResults);

  if (computerBox && !computerBox.dataset.wiredComputerDeleg) {
    computerBox.dataset.wiredComputerDeleg = '1';
    computerBox.addEventListener('click', async (e) => {
      const copyBtn = e.target.closest('[data-ad-computer-copy]');
      if (copyBtn) {
        try {
          const raw = decodeURIComponent(copyBtn.getAttribute('data-ad-computer-copy') || '');
          await navigator.clipboard.writeText(raw);
          const prev = copyBtn.textContent;
          copyBtn.textContent = 'Copiado!';
          setTimeout(() => { copyBtn.textContent = prev; }, 1200);
        } catch {
          alert('Não foi possível copiar.');
        }
        return;
      }
      const pick = e.target.closest('[data-ad-computer-pick]');
      if (pick) {
        const q = decodeURIComponent(pick.getAttribute('data-ad-computer-pick') || '');
        const input = document.getElementById('ad-computer-query');
        if (input) input.value = q;
        lookupLiveAdComputer(q);
      }
    });
  }

  document.addEventListener('keydown', (e) => {
    if (e.key !== 'Escape') return;
    const oracleOpen = document.getElementById('oracle-modal-backdrop');
    if (oracleOpen && !oracleOpen.classList.contains('hidden')) {
      closeOracleModal();
      return;
    }
    const loopOpen = document.getElementById('loop-modal-backdrop');
    if (loopOpen && !loopOpen.classList.contains('hidden')) {
      closeLoopModal();
      return;
    }
    const autotestOpen = document.getElementById('autotest-modal-backdrop');
    if (autotestOpen && !autotestOpen.classList.contains('hidden')) {
      closeAutoTestModal();
      return;
    }
    closeAdModal();
  });
}

async function loadAdDepartments() {
  const status = document.getElementById('ad-dept-status');
  const datalist = document.getElementById('ad-dept-datalist');
  const box = document.getElementById('ad-dept-results');
  if (status) {
    status.textContent = 'Carregando departamentos do snapshot AD…';
    status.className = 'ad-status-bar';
  }
  const res = await fetch('/api/ad/departments');
  const data = await res.json().catch(() => ({}));
  if (!res.ok || data.ok === false) {
    if (status) {
      status.textContent = data.error || data.hint || 'Falha ao listar departamentos';
      status.className = 'ad-status-bar err';
    }
    return;
  }
  if (datalist) {
    datalist.innerHTML = (data.departments || [])
      .slice()
      .sort((a, b) => String(a.name).localeCompare(String(b.name), 'pt-BR', { sensitivity: 'base' }))
      .map((d) => `<option value="${escapeHtml(d.name)}"></option>`)
      .join('');
  }
  if (status) {
    status.textContent = data.count
      ? `${data.count} setor(es): ${data.departamentosFromOu || 0} pela árvore OU · ${data.departamentosFromUsuariosNode || 0} nós "Usuarios - …"${data.capturedAt ? ' · ' + new Date(data.capturedAt).toLocaleString('pt-BR') : ''}`
      : (data.hint || 'Sem departamentos — marque AD ao vivo ou rode uma varredura.');
    status.className = `ad-status-bar${data.count ? ' ok' : ''}`;
  }
  if (box && data.departments?.length) {
    box.innerHTML = `
      <h3 class="ad-section-title">Setores disponíveis (${escapeHtml(String(data.count))})</h3>
      <div class="ad-chip-grid">
        ${(data.departments || [])
          .slice()
          .sort((a, b) => String(a.name).localeCompare(String(b.name), 'pt-BR', { sensitivity: 'base' }))
          .map((d) => `
          <button type="button" class="ad-dept-chip" data-ad-dept-pick="${escapeHtml(d.name)}">
            <strong>${escapeHtml(d.name)}</strong>
            <span>${escapeHtml(String(d.enabledCount || d.userCount || 0))} usuários${d.source === 'usuarios-node' ? ' · nó Usuarios' : d.source === 'cn-container' ? ' · CN' : d.path?.length > 1 ? ' · árvore OU' : ''}</span>
          </button>
        `).join('')}
      </div>
    `;
  }
}

async function analyzeAdDepartment() {
  const dept = document.getElementById('ad-dept-query')?.value?.trim() || '';
  const minPct = Number(document.getElementById('ad-dept-mincov')?.value || 50);
  const live = document.getElementById('ad-dept-live')?.checked === true;
  const status = document.getElementById('ad-dept-status');
  const box = document.getElementById('ad-dept-results');
  const btn = document.getElementById('ad-dept-analyze');

  if (!dept) {
    if (status) {
      status.textContent = 'Informe o departamento.';
      status.className = 'ad-status-bar err';
    }
    return;
  }

  if (status) {
    status.textContent = live ? 'Consultando AD ao vivo…' : 'Analisando snapshot / AD…';
    status.className = 'ad-status-bar';
  }
  if (btn) btn.disabled = true;

  try {
    const url = `/api/ad/department-permissions?department=${encodeURIComponent(dept)}&minCoverage=${(minPct / 100).toFixed(2)}&live=${live ? '1' : '0'}`;
    const res = await fetch(url);
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) throw new Error(data.error || 'Falha na análise');

    renderAdDepartmentAnalysis(data);
    if (status) {
      status.textContent = `${data.department}: ${data.enabledCount} colega(s) · ${data.recommendedCount} grupo(s) sugeridos · fonte ${data.source}`;
      status.className = 'ad-status-bar ok';
    }
  } catch (err) {
    if (box) box.innerHTML = `<div class="ad-empty">${escapeHtml(err.message)}</div>`;
    if (status) {
      status.textContent = err.message;
      status.className = 'ad-status-bar err';
    }
  } finally {
    if (btn) btn.disabled = false;
  }
}

function renderAdDepartmentAnalysis(data) {
  const box = document.getElementById('ad-dept-results');
  if (!box) return;

  const rec = [...(data.recommendedGroups || [])].sort((a, b) =>
    String(a.name).localeCompare(String(b.name), 'pt-BR', { sensitivity: 'base' })
  );
  const peers = data.peers || [];
  const copyPayload = encodeURIComponent(data.copyText || (data.suggestedForNewUser || []).join('\n'));

  const tierLabel = (t) => {
    if (t === 'nucleo') return 'Núcleo';
    if (t === 'recomendado') return 'Recomendado';
    if (t === 'parcial') return 'Parcial';
    return 'Raro';
  };

  box.innerHTML = `
    <div class="ad-dept-summary">
      <div>
        <strong>Sugestão para novo usuário</strong>
        <p>${escapeHtml(String(rec.length))} grupos presentes em ≥ ${escapeHtml(String(Math.round((data.minCoverage || 0.5) * 100)))}% dos colegas ativos</p>
      </div>
      <button type="button" class="btn btn-secondary btn-sm" data-ad-dept-copy="${copyPayload}">Copiar grupos sugeridos</button>
    </div>
    <h3 class="ad-section-title">Grupos sugeridos</h3>
    <div class="ad-dept-groups">
      ${rec.length ? rec.map((g) => `
