async function searchAdGroupMembers() {
  const group = document.getElementById('ad-group-query')?.value?.trim() || '';
  const live = document.getElementById('ad-group-live')?.checked === true;
  const includeDisabled = document.getElementById('ad-group-include-disabled')?.checked === true;
  const status = document.getElementById('ad-group-status');
  const box = document.getElementById('ad-group-results');
  const btn = document.getElementById('ad-group-search');

  if (!group) {
    if (status) {
      status.textContent = 'Informe o nome do grupo (ex: G_HEBO…).';
      status.className = 'ad-status-bar err';
    }
    return;
  }

  if (status) {
    status.textContent = live ? 'Consultando AD ao vivo…' : 'Buscando membros no snapshot…';
    status.className = 'ad-status-bar';
  }
  if (btn) btn.disabled = true;

  try {
    const url = `/api/ad/group-members?group=${encodeURIComponent(group)}&live=${live ? '1' : '0'}&includeDisabled=${includeDisabled ? '1' : '0'}`;
    const res = await fetch(url);
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) throw new Error(data.error || 'Falha na busca');

    renderGroupMembers(data);
    if (status) {
      status.textContent = `${data.group}: ${data.enabledCount} membro(s) ativo(s) · ${data.memberCount} total · fonte ${data.source}`;
      status.className = 'ad-status-bar ok';
    }
  } catch (err) {
    if (status) {
      status.textContent = err.message;
      status.className = 'ad-status-bar err';
    }
    if (box) box.innerHTML = `<div class="ad-empty">${escapeHtml(err.message)}</div>`;
  } finally {
    if (btn) btn.disabled = false;
  }
}

function renderGroupMembers(data) {
  const box = document.getElementById('ad-group-results');
