function parseLegacyAutoTestSummary(summary) {
  const text = String(summary || '').trim();
  const legacy = text.match(/^([A-F])\s·\s(\d+)\sOK\s·\s(\d+)\saviso\(s\)\s·\s(\d+)\sfalha\(s\)\s·\s(\d+)\sms$/i);
  if (legacy) {
    const fail = Number(legacy[4]);
    const warn = Number(legacy[3]);
    return {
      grade: legacy[1],
      pass: Number(legacy[2]),
      warn,
      fail,
      durationMs: Number(legacy[5]),
      durationSec: (Number(legacy[5]) / 1000).toFixed(1),
      verdict: fail > 0 ? 'REPROVADO' : (warn > 0 ? 'APROVADO COM RESSALVAS' : 'APROVADO'),
      verdictShort: fail > 0 ? 'FALHA' : (warn > 0 ? 'RESSALVAS' : 'OK')
    };
  }
  const modern = text.match(/^(\w+)\s\|\sNota\s([A-F])\s\|\s(\d+)P\s·\s(\d+)W\s·\s(\d+)F\s\|\s([\d.]+)s/i);
  if (modern) {
    const fail = Number(modern[5]);
    const warn = Number(modern[4]);
    return {
      grade: modern[2],
      pass: Number(modern[3]),
      warn,
      fail,
      durationSec: modern[6],
      durationMs: Math.round(Number(modern[6]) * 1000),
      verdict: modern[1] === 'FALHA' ? 'REPROVADO' : (modern[1] === 'RESSALVAS' ? 'APROVADO COM RESSALVAS' : 'APROVADO'),
      verdictShort: modern[1]
    };
  }
  return null;
}

function normalizeAutoTestHistoryEntry(run) {
  const eng = run.engineering;
  if (eng) {
    return {
      grade: eng.grade || run.grade || '—',
      pass: eng.pass ?? run.stats?.pass ?? 0,
      warn: eng.warn ?? run.stats?.warn ?? 0,
      fail: eng.fail ?? run.stats?.fail ?? 0,
      durationSec: eng.durationSec || (run.durationMs ? (run.durationMs / 1000).toFixed(1) : '—'),
      verdict: eng.verdict || (run.ok ? 'APROVADO' : 'REPROVADO'),
      verdictShort: eng.verdictShort || (run.ok ? 'OK' : 'FALHA'),
      rootCause: eng.rootCause || null,
      profileName: eng.profileName || run.profileName || run.profileId || 'AutoTest'
    };
  }
  const parsed = parseLegacyAutoTestSummary(run.summary);
  if (parsed) {
    return {
      ...parsed,
      rootCause: null,
      profileName: run.profileName || run.profileId || 'AutoTest'
    };
  }
  return {
    grade: run.grade || '—',
    pass: run.stats?.pass ?? 0,
    warn: run.stats?.warn ?? 0,
    fail: run.stats?.fail ?? 0,
    durationSec: run.durationMs ? (run.durationMs / 1000).toFixed(1) : '—',
    verdict: run.ok ? 'APROVADO' : 'REPROVADO',
    verdictShort: run.ok ? 'OK' : 'FALHA',
    rootCause: null,
    profileName: run.profileName || run.profileId || 'AutoTest'
  };
}

function autotestHistoryVerdictClass(verdictShort) {
  if (verdictShort === 'OK') return 'autotest-eng-verdict-ok';
  if (verdictShort === 'RESSALVAS') return 'autotest-eng-verdict-warn';
  return 'autotest-eng-verdict-fail';
}

function renderAutoTestHistory(runs) {
  const list = document.getElementById('autotest-history-list');
  if (!list) return;
  if (!runs.length) {
    list.innerHTML = '<div class="autotest-empty">Nenhuma execução registrada ainda.</div>';
    return;
  }
  list.innerHTML = runs.map((r) => {
    const when = r.ranAt ? new Date(r.ranAt).toLocaleString('pt-BR') : '—';
    const port = r.connectedPort?.portName ? `<span class="autotest-eng-tag">Porta ${escapeHtml(r.connectedPort.portName)}</span>` : '';
    const remote = r.remote && r.agentHostname
      ? `<span class="autotest-eng-tag">Remoto · ${escapeHtml(r.agentHostname)}</span>`
      : '';
    const cls = r.ok ? 'autotest-history-ok' : 'autotest-history-fail';
    const m = normalizeAutoTestHistoryEntry(r);
    const verdictCls = autotestHistoryVerdictClass(m.verdictShort);
    const cause = m.rootCause
      ? `<p class="autotest-history-cause"><span>Causa provável</span> ${escapeHtml(m.rootCause.label)} — ${escapeHtml(m.rootCause.detail)}</p>`
      : '';
    const network = r.localIp
      ? `<span class="autotest-eng-tag">${escapeHtml(r.localIp)}${r.gateway ? ` · GW ${escapeHtml(r.gateway)}` : ''}</span>`
      : '';
    return `
      <article class="autotest-history-item ${cls}">
