let autoTestRemoteAgentsCache = [];
let autoTestRemotePollToken = 0;

function normalizeAutoTestRemoteTarget(value) {
  return String(value || '').trim().toLowerCase().replace(/[^a-z0-9._-]+/g, '-').slice(0, 64);
}

function resolveAutoTestRemoteTarget(input) {
  const raw = String(input || '').trim();
  if (!raw) return { ok: false, error: 'Digite o IP ou hostname da estação remota.' };

  const agents = autoTestRemoteAgentsCache;
  const ipMatch = agents.find((a) => a.ip && a.ip === raw);
  if (ipMatch) return { ok: true, agent: ipMatch, matchedBy: 'ip' };

  const norm = normalizeAutoTestRemoteTarget(raw);
  const idMatch = agents.find((a) => a.agentId === norm || normalizeAutoTestRemoteTarget(a.hostname) === norm);
  if (idMatch) return { ok: true, agent: idMatch, matchedBy: 'agentId' };

  const hostLower = raw.toLowerCase();
  const hostMatch = agents.find((a) =>
    (a.hostname && a.hostname.toLowerCase() === hostLower)
    || (a.agentId && a.agentId.toLowerCase() === hostLower)
  );
  if (hostMatch) return { ok: true, agent: hostMatch, matchedBy: 'hostname' };

  return {
    ok: false,
    error: `Estação "${raw}" não encontrada. Atualize a lista — o agente precisa estar pareado e online naquela máquina.`
  };
}

function updateAutoTestRemoteTargetHint(input) {
  const hint = document.getElementById('autotest-remote-target-hint');
  if (!hint) return;
  const raw = String(input || '').trim();
  if (!raw) {
    hint.classList.add('hidden');
    hint.textContent = '';
    return;
  }
  const resolved = resolveAutoTestRemoteTarget(raw);
  if (!resolved.ok) {
    hint.textContent = resolved.error;
    hint.className = 'ad-section-hint autotest-remote-target-hint warn';
    return;
  }
  const a = resolved.agent;
  const st = a.online ? '● online' : '○ offline';
  const lastSeen = a.lastSeen ? new Date(a.lastSeen).toLocaleString('pt-BR') : 'nunca';
  hint.textContent = `${a.hostname} (${a.ip || '?'}) · ${st} · visto ${lastSeen}${a.online ? '' : ' — job aguardará o agente conectar'}`;
  hint.className = `ad-section-hint autotest-remote-target-hint${a.online ? '' : ' warn'}`;
}

const AUTOTEST_REMOTE_GHOST_HINT = 'Digite o ip da máquina';
const AUTOTEST_REMOTE_GHOST_EXAMPLES = ['192.168.1.100', '10.0.0.50', '172.16.0.25', '192.168.0.15'];

function wireAutoTestRemoteAgentPlaceholder(input) {
  const wrap = document.getElementById('autotest-remote-agent-input-wrap');
  const ghost = document.getElementById('autotest-remote-agent-ghost');
  if (!input || !wrap || !ghost || input.dataset.placeholderWired) return;
  input.dataset.placeholderWired = '1';

  let phase = 'hint';
  let exampleIdx = 0;
  let timer = null;

  function isActive() {
    return !!input.value.trim() || document.activeElement === input;
  }

  function setGhost(text, asExample) {
    ghost.textContent = text;
    ghost.classList.toggle('is-example', !!asExample);
  }

  function fadeTo(text, asExample) {
    ghost.classList.add('is-fading');
    setTimeout(() => {
      setGhost(text, asExample);
      ghost.classList.remove('is-fading');
    }, 400);
  }

  function scheduleNext() {
    clearTimeout(timer);
    if (isActive()) return;
    timer = setTimeout(() => {
      if (isActive()) return;
      if (phase === 'hint') {
        fadeTo(AUTOTEST_REMOTE_GHOST_EXAMPLES[exampleIdx], true);
        exampleIdx = (exampleIdx + 1) % AUTOTEST_REMOTE_GHOST_EXAMPLES.length;
        phase = 'example';
      } else {
        fadeTo(AUTOTEST_REMOTE_GHOST_HINT, false);
        phase = 'hint';
      }
      scheduleNext();
    }, phase === 'hint' ? 2800 : 3200);
  }

  function syncGhost() {
    wrap.classList.toggle('is-active', isActive());
    clearTimeout(timer);
    if (isActive()) return;
    setGhost(phase === 'hint' ? AUTOTEST_REMOTE_GHOST_HINT : AUTOTEST_REMOTE_GHOST_EXAMPLES[(exampleIdx + AUTOTEST_REMOTE_GHOST_EXAMPLES.length - 1) % AUTOTEST_REMOTE_GHOST_EXAMPLES.length], phase === 'example');
    scheduleNext();
  }

  setGhost(AUTOTEST_REMOTE_GHOST_HINT, false);
  scheduleNext();
  input.addEventListener('focus', syncGhost);
  input.addEventListener('blur', syncGhost);
  input.addEventListener('input', syncGhost);
}

async function loadAutoTestRemoteAgents() {
  const input = document.getElementById('autotest-remote-agent');
  const list = document.getElementById('autotest-remote-agent-list');
  if (!input) return [];
  const res = await fetch('/api/autotest/remote/agents');
  const data = await res.json().catch(() => ({}));
  if (res.status === 401 || data.code === 'REMOTE_AD_AUTH_REQUIRED' || data.code === 'AUTH_REQUIRED') {
    autoTestRemoteAgentsCache = [];
    if (list) list.innerHTML = '';
    updateAutoTestRemoteTargetHint(input.value);
    return [];
  }
  if (!res.ok) throw new Error(data.error || 'Falha ao listar agentes');
  autoTestRemoteAgentsCache = data.agents || [];
  const current = input.value;
  if (list) {
    list.innerHTML = autoTestRemoteAgentsCache.map((a) => {
      const when = a.lastSeen ? new Date(a.lastSeen).toLocaleString('pt-BR') : '—';
      const status = a.online ? 'online' : 'offline';
      const value = a.ip || a.hostname || a.agentId;
      const label = `${a.hostname} (${a.ip || '?'}) · ${status} · ${when}`;
      return `<option value="${escapeHtml(value)}" label="${escapeHtml(label)}"></option>`;
    }).join('');
  }
  if (current) updateAutoTestRemoteTargetHint(current);
  return autoTestRemoteAgentsCache;
}

async function pollRemoteAutoTestJob(jobId, maxWaitMs = 20 * 60 * 1000) {
  const pollToken = ++autoTestRemotePollToken;
  const started = Date.now();
  while (Date.now() - started < maxWaitMs) {
    if (pollToken !== autoTestRemotePollToken) {
      throw new Error('Aguardo do job remoto cancelado.');
    }
    const res = await fetch(`/api/autotest/remote/jobs/${encodeURIComponent(jobId)}`);
    const data = await res.json().catch(() => ({}));
    if (!res.ok) throw new Error(data.error || `HTTP ${res.status}`);
    const job = data.job;
    if (job.status === 'done' && job.result) return job.result;
    if (job.status === 'failed') throw new Error(job.error || 'AutoTest remoto falhou.');
    if (job.status === 'timeout') throw new Error(job.error || 'Agente não respondeu a tempo.');
    const waited = Math.round((Date.now() - started) / 1000);
    setAutoTestEngineeringBanner(null, { mode: 'progress', detail: `Aguardando agente remoto · ${waited}s · ${job.status}` });
    await new Promise((r) => setTimeout(r, 2000));
  }
  throw new Error('Tempo esgotado aguardando resultado do agente remoto.');
}

async function runRemoteAutoTest() {
  const run = async () => {
    const target = document.getElementById('autotest-remote-agent')?.value?.trim();
    const resolved = resolveAutoTestRemoteTarget(target);
    if (!resolved.ok) {
      alert(resolved.error);
      updateAutoTestRemoteTargetHint(target);
      return;
    }
    const agent = resolved.agent;
    if (!agent.online) {
      const go = confirm(
        `A estação ${agent.hostname} (${agent.ip || '?'}) está offline.\n\n`
        + 'O job ficará aguardando até o agente conectar (até ~10 min).\n\nEnfileirar mesmo assim?'
      );
      if (!go) return;
    }
    const profileId = document.getElementById('autotest-profile-select')?.value || 'escritorio';
    const nic = readAutoTestRunInterface();
    const btn = document.getElementById('autotest-run-remote-btn');
    setAutoTestEngineeringBanner(null, { mode: 'progress', detail: 'Enfileirando job remoto…' });
    if (btn) btn.disabled = true;
    try {
      const res = await fetch('/api/autotest/remote/jobs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ target, agentId: agent.agentId, profileId, ...nic })
      });
      const created = await res.json().catch(() => ({}));
      if (res.status === 401 || created.code === 'REMOTE_AD_AUTH_REQUIRED' || created.code === 'AUTH_REQUIRED') {
        await ensureAutoTestRemoteAuth(() => runRemoteAutoTest(), { freshLogin: true });
        return;
      }
      if (!res.ok || !created.job?.id) throw new Error(created.error || 'Falha ao enfileirar job.');
      const label = agent.ip || agent.hostname || agent.agentId;
      setAutoTestEngineeringBanner(null, { mode: 'progress', detail: `Job enviado · aguardando ${label}` });
      const result = await pollRemoteAutoTestJob(created.job.id);
      applyAutoTestResult(result);
    } catch (err) {
      setAutoTestEngineeringBanner(null, { mode: 'error', detail: err.message });
      alert(err.message);
    } finally {
      if (btn) btn.disabled = false;
    }
  };
  await ensureAutoTestRemoteAuth(run, { freshLogin: true });
}

async function revokeAutoTestRemoteAgent() {
  const run = async () => {
    const target = document.getElementById('autotest-remote-agent')?.value?.trim();
    const resolved = resolveAutoTestRemoteTarget(target);
    if (!resolved.ok) {
      alert(resolved.error);
      return;
    }
    const agent = resolved.agent;
    if (!confirm(`Revogar o agente pareado "${agent.hostname}" (${agent.ip || agent.agentId})?\n\nA estação precisará parear novamente.`)) {
      return;
    }
    const res = await fetch(`/api/autotest/remote/agents/${encodeURIComponent(agent.agentId)}`, { method: 'DELETE' });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || !data.ok) throw new Error(data.error || 'Falha ao revogar agente.');
    await loadAutoTestRemoteAgents();
    alert(`Agente ${agent.hostname} revogado.`);
  };
  await ensureAutoTestRemoteAuth(run);
}

