async function loadOracleConfig() {
  const res = await fetch('/api/oracle/config');
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.error || 'Falha ao carregar config Oracle');
  const cfg = data.config || {};
  const user = document.getElementById('oracle-cfg-user');
  const pass = document.getElementById('oracle-cfg-password');
  const connect = document.getElementById('oracle-cfg-connect');
  const table = document.getElementById('oracle-cfg-table');
  const max = document.getElementById('oracle-cfg-max');
  if (user) user.value = cfg.user || '';
  if (pass) pass.value = '';
  if (pass) pass.placeholder = cfg.hasPassword ? '••••••••' : 'Senha Oracle';
  if (connect) connect.value = cfg.connectString || '';
  if (table) table.value = cfg.table || 'dbasgu.usuarios';
  if (max) max.value = cfg.maxRows || 50;
  const libdir = document.getElementById('oracle-cfg-libdir');
  if (libdir) libdir.value = cfg.libDir || cfg.suggestedLibDir || '';
  if (!cfg.connectString) {
    setOracleStatus('oracle-cfg-status', 'Configure o Connect String (TNS sem jdbc: ou host:1521/SERVICE).', 'err');
  } else if (cfg.thickError) {
    setOracleStatus('oracle-cfg-status', `Thick mode: ${cfg.thickError}`, 'err');
  } else {
    setOracleStatus('oracle-cfg-status', `Pronto · user=${cfg.user || '?'} · ${cfg.connectString}`, 'ok');
  }
  return cfg;
}

