  const box = document.getElementById('oracle-results');
  if (!box) return;
  const list = Array.isArray(users) ? users : [];
  if (!list.length) {
    box.innerHTML = '<div class="ad-empty">Nenhum usuário encontrado no Oracle.</div>';
    return;
  }

  box.innerHTML = `
    <h3 class="ad-section-title">${escapeHtml(String(list.length))} resultado(s)</h3>
    ${list.map((u) => {
    const sugs = (u.suggestions || []).map((s) => {
      let badge = '<span class="oracle-badge unknown">AD não checado</span>';
      if (s.adExists === true) {
        const name = s.adUser?.displayName ? ` · ${s.adUser.displayName}` : '';
        const st = s.adUser?.enabled === false ? ' (desabilitado)' : '';
        badge = `<span class="oracle-badge exists">Já existe no AD${st}${escapeHtml(name)}</span>`;
      } else if (s.adExists === false) {
        badge = '<span class="oracle-badge free">Livre no AD</span>';
      }
      return `
        <div class="oracle-sug${s.preferred ? ' preferred' : ''}">
          <span class="oracle-sug-login">${escapeHtml(s.login)}</span>
          <span class="oracle-sug-rule">${escapeHtml(s.rule || '')}</span>
          ${badge}
          <button type="button" class="btn btn-tertiary btn-sm" data-oracle-copy="${escapeHtml(s.login)}">Copiar</button>
        </div>
      `;
    }).join('');

    return `
      <div class="oracle-card">
        <div class="oracle-card-head">
          <div>
            <strong>${escapeHtml(u.nmUsuario || '—')}</strong>
            <span>Oracle · dbasgu.usuarios</span>
          </div>
          <div class="oracle-code" title="cd_usuario">${escapeHtml(u.cdUsuario || '—')}</div>
        </div>
        <div class="oracle-suggestions">${sugs || '<span class="oracle-sug-rule">Sem sugestões</span>'}</div>
      </div>
    `;
  }).join('')}
  `;
}

