app.post('/api/idle-hosts/export-xlsx', requireDashboardAuth, async (req, res) => {
  try {
    const payload = req.body && typeof req.body === 'object' ? req.body : {};
    const hosts = Array.isArray(payload.hosts) ? payload.hosts : [];
    if (!hosts.length) {
      return res.status(400).json({ error: 'Nenhum IP ocioso para exportar.' });
    }

    const buffer = await generateIdleHostsXlsx(payload);
    const now = new Date();
    const dateStr = now.toISOString().slice(0, 10);
    const timeStr = now.toTimeString().slice(0, 8).replace(/:/g, '-');
    const fileName = `NetScan_Canon_ips_ociosos_${dateStr}_${timeStr}.xlsx`;

    res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
    res.setHeader('Content-Disposition', `attachment; filename="${fileName}"`);
    res.send(Buffer.from(buffer));
  } catch (err) {
    console.error('[HISTORY] idle-hosts export-xlsx error:', err);
    res.status(500).json({ error: 'Falha ao gerar o arquivo Excel de IPs ociosos.' });
