function requireAutoTestAgentToken(req, res, next) {
  const token = req.headers['x-autotest-agent-token'] || req.body?.token;
  if (!autoTestRemote.verifyAgentToken(token)) {
    return res.status(401).json({ error: 'Token de agente inválido.' });
  }
  next();
}

function requireSignedAutoTestAgent(req, res, next) {
  const agentId = req.headers['x-autotest-agent-id'];
  const timestamp = req.headers['x-autotest-agent-ts'];
  const signature = req.headers['x-autotest-agent-sign'];
  if (agentId && timestamp && signature) {
    const out = autoTestRemote.verifySignedAgentRequest(agentId, timestamp, req.body || {}, signature);
    if (!out.ok) return res.status(401).json(out);
    req.autotestAgent = out.agent;
    return next();
  }
  return requireAutoTestAgentToken(req, res, next);
}

