app.get('/api/oracle/users', async (req, res) => {
  try {
    const q = req.query.q || req.query.nome || req.query.name || '';
    const mode = req.query.mode || 'auto';
    const checkAd = String(req.query.checkAd || '1') !== '0';
    const result = await oracleUserLookup.searchUsers(q, {
      mode,
      checkAd: checkAd
        ? async (login) => {
          try {
            const ad = await lookupAdUser(login);
            if (!ad || !ad.ok || !ad.user) return { ok: false };
            const uac = Number(ad.user.userAccountControl) || 0;
            const disabled = (uac & 0x0002) === 0x0002;
            return {
              ok: true,
              user: {
                sam: ad.user.sAMAccountName || login,
                displayName: ad.user.displayName || ad.user.cn || null,
                enabled: !disabled,
                disabled
              }
            };
          } catch {
            return { ok: false };
          }
        }
        : null
    });
    res.json({ ok: true, ...result });
  } catch (err) {
    console.error('[ORACLE] search error:', err);
    const status = err.code === 'BAD_QUERY' || err.code === 'ORACLE_CONFIG' ? 400 : 500;
    res.status(status).json({
      ok: false,
      error: err.message || 'Falha ao consultar Oracle.',
      code: err.code || null
    });
  }
});

