    Array.isArray(host.enrichmentNotes) ? host.enrichmentNotes.join(' ') : ''
  ].filter(Boolean).join(' ').toLowerCase();
}

function hasAny(text, keywords) {
  return keywords.some(k => text.includes(k));
}

function hasPort(portSet, ports) {
  return ports.some(p => portSet.has(p));
}

