function scanStats(results) {
  const total = results.length;
  const active = results.filter((h) => h.status === 'Ativo').length;
  const inactive = total - active;
  const vm = results.filter((h) => h.vm === 'Sim').length;
  return { total, active, inactive, vm };
}

async function generateScanXlsx(results) {
  const stats = scanStats(results);
  const workbook = new ExcelJS.Workbook();
  workbook.creator = 'NetScan Canon';
  workbook.created = new Date();

  const ws = workbook.addWorksheet('Varredura', {
    views: [{ state: 'frozen', ySplit: 8 }],
    properties: { defaultRowHeight: 18 }
  });
  ws.columns = SCAN_HEADERS.map((h) => ({ key: h.key, width: h.width }));
  const colN = SCAN_HEADERS.length;
  const now = new Date().toISOString();

  let r = applyReportHeader(ws, colN,
    'NetScan Canon — Varredura de Rede',
    `Data/Hora: ${fmtDatePt(now)}  ·  Relatório ${fmtReportId(now)}`,
    []
  );

  r = addStatCardsRow(ws, r, 1, [
    { label: 'Total', value: stats.total, argb: ARGB.brand },
    { label: 'Ativos', value: stats.active, argb: ARGB.pass },
    { label: 'Inativos', value: stats.inactive, argb: ARGB.fail },
    { label: 'VMs', value: stats.vm, argb: ARGB.warn }
  ]);

  ws.mergeCells(r, 1, r, colN);
  styleSectionTitle(ws.getCell(r, 1), 'Hosts descobertos');
  ws.getRow(r).height = 22;
  r += 1;

  const hdr = ws.getRow(r);
  SCAN_HEADERS.forEach((h, i) => {
    hdr.getCell(i + 1).value = h.header;
    styleTableHeader(hdr.getCell(i + 1));
  });
  hdr.height = 26;
  ws.autoFilter = { from: { row: r, column: 1 }, to: { row: r, column: colN } };
  r += 1;

  results.forEach((host, index) => {
    const ports = Array.isArray(host.ports) ? host.ports.filter((p) => p && p.state === 'open') : [];
    const portsStr = ports.length
      ? ports.map((p) => `${p.port}/${p.protocol || 'TCP'}${p.service ? ` (${p.service})` : ''}`).join(', ')
      : 'Nenhuma';

    const row = ws.addRow({
      ip: host.ip,
      status: host.status,
      hostname: host.hostname,
      mac: host.mac,
      vendor: host.vendor,
      os: host.os,
      osVersion: host.osVersion || 'N/A',
      vm: host.vm || 'Não',
      vmType: host.vmType || 'N/A',
      vmConfidence: host.vmConfidence || 'N/A',
      adDomain: host.adDomain || 'N/A',
      description: host.description || 'N/A',
      adDn: host.adDn || 'N/A',
      lastLogon: host.lastLogon || 'N/A',
      vlan: host.vlan || 'N/A',
      vlanId: host.vlanId != null ? host.vlanId : 'N/A',
      vlanSource: host.vlanSource || 'N/A',
      subnet: host.subnet || 'N/A',
      dmz: host.isDMZ ? 'Sim' : 'Não',
      environment: host.environment || 'IT',
      deviceType: host.deviceType || 'Host Ativo',
      sources: Array.isArray(host.enrichmentSources) ? host.enrichmentSources.join(', ') : '',
      ports: portsStr
    });
    styleDataRow(row, index, 'status');
    if (host.status === 'Ativo') row.getCell('status').font = { bold: true, color: { argb: ARGB.pass } };
    else row.getCell('status').font = { color: { argb: ARGB.fail } };
    if (host.vm === 'Sim') row.getCell('vm').font = { bold: true, color: { argb: ARGB.warn } };
    row.height = Math.max(18, Math.ceil(portsStr.length / 50) * 14);
  });

  addStatsSheet(workbook, 'Resumo Varredura', [
    ['Total hosts', stats.total],
    ['Ativos', stats.active],
    ['Inativos', stats.inactive],
    ['Máquinas virtuais', stats.vm]
  ]);

  return workbook.xlsx.writeBuffer();
}

