      wasActive: wasActiveLabel(host)
    });
    styleDataRow(row, index);
    row.getCell('idleFor').font = { bold: true, color: { argb: ARGB.fail } };
  });

  addStatsSheet(workbook, 'Resumo Ociosos', [
    ['Limiar', thresholdLabel],
    ['IPs ociosos', payload.idleCount ?? hosts.length],
    ['Total rastreados', payload.totalTracked ?? '—'],
    ['Leituras', payload.scanCount ?? '—']
  ]);

  return workbook.xlsx.writeBuffer();
}

