    { header: 'VLAN', key: 'vlan', width: 18 },
    { header: 'Sub-rede', key: 'subnet', width: 16 },
    { header: 'Switch', key: 'switchName', width: 22 },
    { header: 'Porta', key: 'switchPort', width: 16 },
    { header: 'Local AD', key: 'adLocation', width: 24 },
    { header: 'Tipo', key: 'deviceType', width: 18 },
    { header: 'Confiança', key: 'confidence', width: 12 },
    { header: 'Critério', key: 'reasons', width: 32 }
  ];

  const ws = workbook.addWorksheet('Hosts por Ala', {
    views: [{ state: 'frozen', ySplit: 2 }],
    properties: { defaultRowHeight: 18 }
  });
  ws.columns = hostHeaders.map((h) => ({ key: h.key, width: h.width }));
  const colN = hostHeaders.length;

  ws.mergeCells(1, 1, 1, colN);
  styleSectionTitle(ws.getCell(1, 1), 'Detalhamento de hosts');
  ws.getRow(1).height = 22;

  const hdr = ws.getRow(2);
  hostHeaders.forEach((h, i) => {
    hdr.getCell(i + 1).value = h.header;
    styleTableHeader(hdr.getCell(i + 1));
  });
  ws.autoFilter = { from: { row: 2, column: 1 }, to: { row: 2, column: colN } };

  hosts.forEach((host, index) => {
    const row = ws.addRow({
      alaName: host.alaName,
      ip: host.ip,
      hostname: host.hostname,
      status: host.status,
      vlan: host.vlan,
      subnet: host.subnet,
      switchName: host.switchName,
      switchPort: host.switchPort,
      adLocation: host.adLocation,
      deviceType: host.deviceType,
      confidence: host.confidence,
      reasons: Array.isArray(host.reasons) ? host.reasons.join(', ') : ''
    });
    styleDataRow(row, index, 'status');
  });

  return workbook.xlsx.writeBuffer();
}

