  body: 'FF334155'
};

const STATUS = {
  pass: { label: 'OK', badge: '🟢 OK', icon: '✔', color: C.pass, argb: ARGB.pass },
  warn: { label: 'AVISO', badge: '🟡 AVISO', icon: '⚠', color: C.warn, argb: ARGB.warn },
  fail: { label: 'FALHA', badge: '🔴 FALHA', icon: '✖', color: C.fail, argb: ARGB.fail },
  skip: { label: 'PULADO', badge: '⚪ PULADO', icon: '○', color: C.skip, argb: ARGB.skip }
};

const L2_IDS = new Set(['local', 'link', 'vlan', 'duplicate-ip', 'dhcp', 'switch', 'wifi-scan']);
const L3_IDS = new Set(['gateway', 'subnet', 'traceroute']);
const L4_PREFIX = ['tcp-', 'http-'];

const STEP_ICONS = {
  local: '🌐 Interface',
  link: '📶 Link',
  vlan: '🏷 VLAN',
  'duplicate-ip': '🔁 IP duplicado',
  dhcp: '🔐 DHCP',
  switch: '🖧 Switch',
  'wifi-scan': '🛜 Wi-Fi',
  gateway: '🖧 Gateway',
  subnet: '🖥 Descoberta',
  traceroute: '🛤 Traceroute',
  default: '📋 Teste'
};

function fmtDatePt(iso) {
  if (!iso) return '—';
  try { return new Date(iso).toLocaleString('pt-BR'); } catch { return String(iso); }
}

function fmtReportId(iso) {
  const t = iso ? new Date(iso).getTime() : Date.now();
  return `#${String(t % 1000000).padStart(6, '0')}`;
}

function formatDetailText(detail) {
  const s = String(detail ?? '').trim();
  if (!s) return '—';
  if (s.length > 48 && s.includes(',')) return s.replace(/,\s*/g, '\n');
  return s;
}

function stepLayer(step) {
  const id = String(step?.id || '');
  if (L2_IDS.has(id)) return 'L2';
  if (L3_IDS.has(id)) return 'L3';
  if (L4_PREFIX.some((p) => id.startsWith(p))) return 'L4';
  if (id.startsWith('dns') || id.startsWith('ping-')) return 'L3';
  return '—';
}

function stepIconLabel(step) {
  const id = String(step?.id || '');
  for (const [key, label] of Object.entries(STEP_ICONS)) {
    if (key !== 'default' && id.startsWith(key.replace(/-.*/, '')) && (id === key || id.startsWith(key.split('-')[0]))) {
      /* fallthrough */
    }
  }
  if (STEP_ICONS[id]) return STEP_ICONS[id];
  if (id.startsWith('dns')) return '📡 DNS';
  if (id.startsWith('ping-')) return '📡 Ping';
  if (id.startsWith('tcp-')) return '🔌 TCP';
  if (id.startsWith('http-')) return '🌍 HTTP';
  return `${STEP_ICONS.default} ${step?.label || id}`;
}

function stepDisplayLabel(step) {
  const base = step?.label || step?.id || 'Teste';
  const id = String(step?.id || '');
  if (STEP_ICONS[id]) return STEP_ICONS[id];
  if (id.startsWith('dns')) return `📡 ${base}`;
  if (id.startsWith('ping-')) return `📡 ${base}`;
  if (id.startsWith('tcp-')) return `🔌 ${base}`;
  if (id.startsWith('http-')) return `🌍 ${base}`;
  if (id === 'local') return '🌐 Interface';
  if (id === 'link') return '📶 Link';
  if (id === 'gateway') return '🖧 Gateway';
  if (id === 'dhcp') return '🔐 DHCP';
  if (id === 'subnet') return '🖥 Descoberta';
  if (id === 'vlan') return '🏷 VLAN';
  if (id === 'traceroute') return '🛤 Traceroute';
  if (id === 'wifi-scan') return '🛜 Wi-Fi';
  return `📋 ${base}`;
}

function groupStepsByLayer(steps) {
  const groups = { L2: [], L3: [], L4: [], '—': [] };
  for (const s of steps || []) {
    if (s.status === 'skip') continue;
    const layer = stepLayer(s);
    (groups[layer] || groups['—']).push(s);
  }
  return groups;
}

function layerTitle(layer) {
  if (layer === 'L2') return 'L2 — Camada Física / Enlace';
  if (layer === 'L3') return 'L3 — Camada de Rede';
  if (layer === 'L4') return 'L4 — Camada de Transporte / Aplicação';
  return 'Outros testes';
}

function statusInfo(status) {
  return STATUS[status] || { label: status, badge: status, icon: '•', color: C.muted, argb: ARGB.skip };
}

function hostnameFromLocal(local) {
  try {
    return require('os').hostname();
  } catch {
    return local?.interfaceAlias || '—';
  }
}

