  REPORT_SITE,
  REPORT_YEAR,
  C,
  ARGB,
  STATUS,
  fmtDatePt,
  fmtReportId,
  formatDetailText,
  stepLayer,
  stepDisplayLabel,
  groupStepsByLayer,
  layerTitle,
  statusInfo,
  hostnameFromLocal
};

/**
 * Utilitários PDF compartilhados — relatórios NetScan Canon
 */
const {
  C, REPORT_VERSION, REPORT_SITE, REPORT_YEAR, fmtDatePt, statusInfo
} = require('./canonReportTheme');

const PAGE = { left: 42, right: 553, width: 511, footerY: 762, contentBottom: 735 };

function createPdfContext(doc) {
  let pageNum = 0;
  const ctx = {
    doc,
    pageNum,
    PAGE,
    y: 0,

    ensureSpace(needed) {
      if (doc.y + needed > PAGE.contentBottom) ctx.newPage(false);
    },

    newPage(isFirst = false) {
      if (!isFirst) doc.addPage();
      pageNum += 1;
      ctx.pageNum = pageNum;
      doc.save();
      doc.rect(0, 0, 595, 44).fill(C.brand);
      doc.fillColor(C.white).font('Helvetica-Bold').fontSize(11).text('NetScan Canon', PAGE.left, 14);
      doc.fillColor(C.accent).font('Helvetica').fontSize(8).text(ctx._topSubtitle || 'Relatório Profissional', PAGE.left, 28);
      doc.fillColor('#bae6fd').fontSize(7).text(`v${REPORT_VERSION}`, PAGE.left, PAGE.width, 14, { align: 'right', width: PAGE.width });
      doc.restore();
      doc.y = 52;
    },

    drawMetaBox(title, rows) {
      const h = 28 + rows.length * 14 + 8;
      ctx.ensureSpace(h);
      const x = PAGE.left;
      const y = doc.y;
      const w = PAGE.width;
      doc.rect(x, y, w, 22).fill(C.brandDark);
      doc.fillColor(C.white).font('Helvetica-Bold').fontSize(11).text(title, x + 8, y + 6);
      doc.rect(x, y + 22, w, rows.length * 14 + 8).strokeColor(C.border).lineWidth(1).stroke();
      let ry = y + 28;
      rows.forEach(([label, value]) => {
        doc.fillColor(C.muted).font('Helvetica-Bold').fontSize(8).text(`${label}`, x + 10, ry, { continued: true, width: 110 });
        doc.fillColor(C.body).font('Helvetica').fontSize(8).text(String(value ?? '—'), { width: w - 130 });
        ry += 14;
      });
      doc.y = y + h + 10;
    },

    drawVerdictBanner(verdict, grade, pct, tested, ok) {
      const h = 88;
      ctx.ensureSpace(h + 10);
      const x = PAGE.left;
      const y = doc.y;
      const w = PAGE.width;
      const bg = ok ? C.pass : (verdict.includes('RESSALV') ? C.warn : C.fail);
      doc.roundedRect(x, y, w, h, 6).fill(bg);
      doc.fillColor(C.white).font('Helvetica-Bold').fontSize(11)
        .text(ok ? '✔ RESULTADO FINAL' : '❌ RESULTADO FINAL', x, y + 10, { width: w, align: 'center' });
      doc.fontSize(20).text(String(verdict).toUpperCase(), { align: 'center' });
      doc.fontSize(10).font('Helvetica')
        .text(`Nota: ${grade}   ·   Taxa de sucesso: ${pct != null ? pct + '%' : '—'}   ·   ${tested || 0} testes executados`, { align: 'center' });
      doc.y = y + h + 14;
    },

    drawStatCards(cards) {
      const cardW = (PAGE.width - (cards.length - 1) * 8) / cards.length;
      const h = 46;
      ctx.ensureSpace(h + 8);
      const y = doc.y;
      cards.forEach((card, i) => {
        const x = PAGE.left + i * (cardW + 8);
        doc.roundedRect(x, y, cardW, h, 4).fill(C.bg).strokeColor(C.border).stroke();
        doc.fillColor(C.muted).font('Helvetica').fontSize(7).text(card.label, x + 6, y + 8, { width: cardW - 12, align: 'center' });
        doc.fillColor(card.color || C.title).font('Helvetica-Bold').fontSize(card.small ? 10 : 14)
          .text(String(card.value), x + 6, y + 22, { width: cardW - 12, align: 'center' });
      });
      doc.y = y + h + 12;
    },

    drawProgressBar(label, pct, color) {
      ctx.ensureSpace(22);
      doc.fillColor(C.body).font('Helvetica-Bold').fontSize(8).text(label, PAGE.left, doc.y);
      const barY = doc.y + 12;
      const barW = PAGE.width;
      doc.rect(PAGE.left, barY, barW, 10).fill('#e2e8f0');
      const fillW = Math.max(0, Math.min(barW, (barW * (pct || 0)) / 100));
      if (fillW > 0) doc.rect(PAGE.left, barY, fillW, 10).fill(color || C.pass);
      doc.fillColor(C.body).font('Helvetica').fontSize(7)
        .text(`${pct != null ? pct + '%' : ''}`, PAGE.left + barW - 30, barY + 1);
      doc.y = barY + 16;
    },

    drawCountBars(pass, warn, fail, total) {
      const max = Math.max(pass, warn, fail, 1);
      const items = [
        { label: 'OK', count: pass, color: C.pass },
        { label: 'Avisos', count: warn, color: C.warn },
        { label: 'Falhas', count: fail, color: C.fail }
      ];
      items.forEach((item) => {
        ctx.ensureSpace(16);
        doc.fillColor(C.body).font('Helvetica-Bold').fontSize(8).text(item.label.padEnd(8), PAGE.left, doc.y, { continued: true, width: 50 });
        const barX = PAGE.left + 52;
        const barMaxW = PAGE.width - 80;
        const barW = Math.round((item.count / max) * barMaxW);
        doc.rect(barX, doc.y + 2, barMaxW, 8).fill('#e2e8f0');
        if (barW > 0) doc.rect(barX, doc.y + 2, barW, 8).fill(item.color);
        doc.fillColor(C.body).font('Helvetica').fontSize(8).text(String(item.count), barX + barMaxW + 6, doc.y);
        doc.y += 14;
      });
    },

    drawSectionTitle(text) {
      ctx.ensureSpace(24);
      doc.font('Helvetica-Bold').fontSize(11).fillColor(C.brand).text(text);
      const y = doc.y;
      doc.moveTo(PAGE.left, y).lineTo(PAGE.right, y).strokeColor(C.accent).lineWidth(1.5).stroke();
      doc.lineWidth(1);
      doc.moveDown(0.5);
    },

    drawKeyValueTable(rows) {
      ctx.ensureSpace(rows.length * 16 + 8);
      const colKey = 130;
      let y = doc.y;
      rows.forEach(([k, v], i) => {
        if (i % 2 === 0) doc.rect(PAGE.left, y - 1, PAGE.width, 15).fill(C.bg);
        doc.fillColor(C.muted).font('Helvetica-Bold').fontSize(8).text(k, PAGE.left + 6, y, { width: colKey });
        doc.fillColor(C.body).font('Helvetica').fontSize(8).text(String(v ?? '—'), PAGE.left + colKey, y, { width: PAGE.width - colKey - 6 });
        y += 15;
      });
      doc.y = y + 6;
    },

    drawAlertBox(title, lines, type = 'warn') {
      const color = type === 'fail' ? C.fail : C.warn;
      const h = 20 + lines.length * 12 + 10;
      ctx.ensureSpace(h);
      const y = doc.y;
      doc.rect(PAGE.left, y, PAGE.width, h).fill('#fffbeb').strokeColor(color).lineWidth(1).stroke();
      doc.fillColor(color).font('Helvetica-Bold').fontSize(9).text(title, PAGE.left + 8, y + 6);
      let ly = y + 20;
      lines.forEach((line) => {
        doc.fillColor(C.body).font('Helvetica').fontSize(8).text(line, PAGE.left + 10, ly, { width: PAGE.width - 20 });
        ly += 12;
      });
      doc.y = y + h + 8;
    },

    drawFinalBox(lines) {
      const h = 24 + lines.length * 13 + 16;
      ctx.ensureSpace(h);
      const x = PAGE.left;
      const y = doc.y;
      const w = PAGE.width;
      doc.rect(x, y, w, h).strokeColor(C.brand).lineWidth(1.5).stroke();
      doc.rect(x, y, w, 20).fill(C.brand);
      doc.fillColor(C.white).font('Helvetica-Bold').fontSize(10)
        .text('RESULTADO DO AUTOTESTE', x, y + 5, { width: w, align: 'center' });
      let ly = y + 26;
      lines.forEach((line) => {
        doc.fillColor(C.title).font('Helvetica').fontSize(9).text(line, x + 12, ly, { width: w - 24 });
        ly += 13;
      });
      doc.y = y + h + 10;
    },

    drawPieChart(pass, warn, fail, skip, cx, cy, r) {
      const total = pass + warn + fail + skip || 1;
      const slices = [
        { n: pass, c: C.pass },
        { n: warn, c: C.warn },
        { n: fail, c: C.fail },
        { n: skip, c: C.skip }
      ].filter((s) => s.n > 0);
      let start = -Math.PI / 2;
      slices.forEach((s) => {
        const angle = (s.n / total) * Math.PI * 2;
        doc.save();
        doc.moveTo(cx, cy);
        doc.fillColor(s.c);
        doc.arc(cx, cy, r, start, start + angle).lineTo(cx, cy).fill();
        doc.restore();
        start += angle;
      });
      doc.circle(cx, cy, r).strokeColor(C.border).lineWidth(0.5).stroke();
    },

    stampFooters(reportTitle) {
      const range = doc.bufferedPageRange();
      for (let i = range.start; i < range.start + range.count; i++) {
        doc.switchToPage(i);
        doc.moveTo(PAGE.left, PAGE.footerY).lineTo(PAGE.right, PAGE.footerY).strokeColor(C.border).stroke();
        doc.fillColor(C.muted).font('Helvetica').fontSize(6.5);
        doc.text('Relatório gerado automaticamente pelo NetScan Canon Professional', PAGE.left, PAGE.footerY + 6, { width: PAGE.width, align: 'center' });
        doc.text(`Versão ${REPORT_VERSION} · ${REPORT_SITE} · © ${REPORT_YEAR} · ${reportTitle || 'Relatório'} · Página ${i - range.start + 1}/${range.count}`, PAGE.left, PAGE.footerY + 14, { width: PAGE.width, align: 'center' });
      }
    }
  };
  return ctx;
}

