const { ARGB, fmtDatePt, REPORT_VERSION, statusInfo } = require('./canonReportTheme');

function styleTitleBand(cell, text) {
  cell.value = text;
  cell.font = { bold: true, size: 14, color: { argb: ARGB.white } };
  cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: ARGB.brand } };
  cell.alignment = { vertical: 'middle', horizontal: 'left', indent: 1, wrapText: true };
}

function styleMetaBand(cell, text) {
  cell.value = text;
  cell.font = { size: 10, color: { argb: ARGB.body } };
  cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: ARGB.accentLight } };
  cell.alignment = { vertical: 'middle', horizontal: 'left', indent: 1, wrapText: true };
}

function styleSectionTitle(cell, text) {
  cell.value = text;
  cell.font = { bold: true, size: 11, color: { argb: ARGB.brand } };
  cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: ARGB.accentLight } };
  cell.alignment = { vertical: 'middle', horizontal: 'left', indent: 1 };
}

function styleTableHeader(cell) {
  cell.font = { bold: true, color: { argb: ARGB.white }, size: 10 };
  cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF0E7490' } };
  cell.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };
  cell.border = { bottom: { style: 'thin', color: { argb: 'FF067A8A' } } };
}

function applyReportHeader(ws, colCount, title, metaLine, extraMetaRows = []) {
  ws.mergeCells(1, 1, 1, colCount);
  styleTitleBand(ws.getCell(1, 1), title);
  ws.getRow(1).height = 32;

  ws.mergeCells(2, 1, 2, colCount);
  styleMetaBand(ws.getCell(2, 1), `${metaLine}  ·  Layout LinkWare v${REPORT_VERSION}`);
  ws.getRow(2).height = 22;

  let r = 3;
  for (const row of extraMetaRows) {
    ws.mergeCells(r, 1, r, Math.min(3, colCount));
    ws.getCell(r, 1).value = row[0];
    ws.getCell(r, 1).font = { bold: true, size: 9, color: { argb: ARGB.body } };
    if (row[1] != null) {
      ws.mergeCells(r, 4, r, colCount);
      ws.getCell(r, 4).value = row[1];
      ws.getCell(r, 4).font = { size: 9, color: { argb: ARGB.title } };
    }
    ws.getRow(r).height = 18;
    r += 1;
  }
  return r;
}

function addStatCardsRow(ws, startRow, startCol, cards) {
  cards.forEach((card, i) => {
    const col = startCol + i * 2;
    const labelCell = ws.getCell(startRow, col);
    const valCell = ws.getCell(startRow + 1, col);
    labelCell.value = card.label;
    labelCell.font = { size: 9, color: { argb: ARGB.body } };
    labelCell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: ARGB.bg } };
    valCell.value = card.value;
    valCell.font = { bold: true, size: 14, color: { argb: card.argb || ARGB.brand } };
    valCell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: ARGB.bg } };
    valCell.alignment = { horizontal: 'center' };
    ws.mergeCells(startRow, col, startRow, col + 1);
    ws.mergeCells(startRow + 1, col, startRow + 1, col + 1);
  });
  ws.getRow(startRow).height = 18;
  ws.getRow(startRow + 1).height = 28;
  return startRow + 3;
}

/** Faixa grande APROVADO / REPROVADO — estilo LinkWare */
function addVerdictBannerRow(ws, startRow, colCount, { verdict, grade, pct, tested, ok }) {
  ws.mergeCells(startRow, 1, startRow, colCount);
  const cell = ws.getCell(startRow, 1);
  const bg = ok ? ARGB.pass : (String(verdict).includes('RESSALV') ? ARGB.warn : ARGB.fail);
  cell.value = `RESULTADO FINAL: ${String(verdict).toUpperCase()}  ·  Nota ${grade}  ·  ${pct != null ? pct + '% sucesso' : '—'}  ·  ${tested || 0} testes`;
  cell.font = { bold: true, size: 13, color: { argb: ARGB.white } };
  cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: bg } };
  cell.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };
  ws.getRow(startRow).height = 36;
  return startRow + 2;
}

/** Barra de progresso visual com células preenchidas */
function addProgressBarRow(ws, startRow, colCount, label, pct, colorArgb) {
  ws.mergeCells(startRow, 1, startRow, 2);
  ws.getCell(startRow, 1).value = label;
  ws.getCell(startRow, 1).font = { bold: true, size: 9, color: { argb: ARGB.body } };
  const barCols = Math.min(colCount - 2, 20);
  const filled = Math.round(((pct || 0) / 100) * barCols);
  for (let c = 0; c < barCols; c++) {
    const cell = ws.getCell(startRow, 3 + c);
    cell.value = c === barCols - 1 ? `${pct != null ? pct + '%' : ''}` : '';
    cell.fill = {
      type: 'pattern', pattern: 'solid',
      fgColor: { argb: c < filled ? (colorArgb || ARGB.pass) : 'FFE2E8F0' }
    };
    cell.font = { size: 8, color: { argb: c < filled ? ARGB.white : ARGB.body } };
    cell.alignment = { horizontal: 'center' };
  }
  ws.getRow(startRow).height = 16;
  return startRow + 1;
}

/** Barras horizontais OK / Aviso / Falha */
function addCountBarsRow(ws, startRow, colCount, pass, warn, fail) {
  const max = Math.max(pass, warn, fail, 1);
  const items = [
    { label: 'OK', count: pass, argb: ARGB.pass },
    { label: 'Avisos', count: warn, argb: ARGB.warn },
    { label: 'Falhas', count: fail, argb: ARGB.fail }
  ];
  let r = startRow;
  for (const item of items) {
    ws.getCell(r, 1).value = item.label;
    ws.getCell(r, 1).font = { bold: true, size: 9 };
    const barW = Math.min(colCount - 3, 18);
    const filled = Math.round((item.count / max) * barW);
    for (let c = 0; c < barW; c++) {
      ws.getCell(r, 2 + c).fill = {
        type: 'pattern', pattern: 'solid',
        fgColor: { argb: c < filled ? item.argb : 'FFE2E8F0' }
      };
    }
    ws.getCell(r, colCount).value = item.count;
    ws.getCell(r, colCount).font = { bold: true };
    ws.getRow(r).height = 14;
    r += 1;
  }
  return r + 1;
}

function addStatsSheet(workbook, title, statsRows) {
  const sh = workbook.addWorksheet('Estatísticas');
  sh.columns = [{ width: 32 }, { width: 16 }];
  sh.mergeCells(1, 1, 1, 2);
  styleTitleBand(sh.getCell(1, 1), title);
  sh.getRow(1).height = 28;
  let r = 3;
  statsRows.forEach(([k, v]) => {
    sh.getCell(r, 1).value = k;
    sh.getCell(r, 1).font = { bold: true };
    sh.getCell(r, 2).value = v;
    r += 1;
  });
  sh.getCell(r + 1, 1).value = `NetScan Canon v${REPORT_VERSION}`;
  sh.getCell(r + 1, 1).font = { size: 8, color: { argb: ARGB.body } };
}

function styleDataRow(row, index, statusKey) {
  row.alignment = { vertical: 'top', wrapText: true };
  row.eachCell((cell) => {
    cell.border = {
      top: { style: 'hair', color: { argb: 'FFE2E8F0' } },
      bottom: { style: 'hair', color: { argb: 'FFE2E8F0' } }
    };
  });
  if (index % 2 === 0) {
    row.eachCell((cell) => {
      cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFF0FDFA' } };
    });
  }
  if (statusKey && row.getCell(statusKey).value) {
    const v = String(row.getCell(statusKey).value).toLowerCase();
    let argb = ARGB.title;
    if (v.includes('ok') || v.includes('online') || v.includes('ativo')) argb = ARGB.pass;
    else if (v.includes('aviso') || v.includes('warn')) argb = ARGB.warn;
    else if (v.includes('falha') || v.includes('reprov') || v.includes('inacess') || v.includes('inativo')) argb = ARGB.fail;
    row.getCell(statusKey).font = { bold: true, color: { argb } };
  }
}

