const fs = require('fs');
const path = require('path');
const { execFile } = require('child_process');
const { promisify } = require('util');

const execFileAsync = promisify(execFile);

const DATA_DIR = path.join(__dirname, 'data');
const SNAPSHOT_FILE = path.join(DATA_DIR, 'ad-users-snapshot.json');
const DEPARTED_FILE = path.join(DATA_DIR, 'ad-departed-users.json');

const UAC_ACCOUNTDISABLE = 0x0002;

function ensureDataDir() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
}

function decodePowerShellOutput(buf) {
  if (!buf || !buf.length) return '';
  if (Buffer.isBuffer(buf)) {
    if (buf[0] === 0xef && buf[1] === 0xbb && buf[2] === 0xbf) {
      return buf.slice(3).toString('utf8');
    }
    const asUtf8 = buf.toString('utf8');
    if (!asUtf8.includes('\uFFFD')) return asUtf8;
    return buf.toString('latin1');
  }
  return String(buf);
}

function wrapPowerShellScript(script) {
  return `[Console]::OutputEncoding = [System.Text.Encoding]::UTF8
$OutputEncoding = [System.Text.Encoding]::UTF8
chcp 65001 | Out-Null
${script}`;
}

function repairPtText(value) {
  if (value == null) return value;
  const str = String(value);
  if (!str) return str;
  if (str.includes('\uFFFD')) return str;
  if (!/[\u0080-\u00ff]|Ã/.test(str)) return str;
  try {
    const fixed = Buffer.from(str, 'latin1').toString('utf8');
    if (fixed && fixed !== str && !fixed.includes('\uFFFD')) return fixed;
  } catch { /* ignore */ }
  return str;
}

function normalizeSamLookupKey(sam) {
  return String(sam || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\uFFFD/g, '')
    .toLowerCase()
    .trim();
}

function hasCorruptText(value) {
  return String(value || '').includes('\uFFFD');
}

function findSnapshotUser(snapUsers, query) {
  if (!snapUsers || !query) return null;
  const want = normalizeSamLookupKey(query);
  if (!want) return null;
  if (snapUsers[want]) return snapUsers[want];
  for (const [key, u] of Object.entries(snapUsers)) {
    if (normalizeSamLookupKey(key) === want) return u;
    if (normalizeSamLookupKey(u.sAMAccountName) === want) return u;
  }
  for (const u of Object.values(snapUsers)) {
    const sam = normalizeSamLookupKey(u.sAMAccountName);
    if (sam && (sam.startsWith(want) || want.startsWith(sam)) && Math.min(sam.length, want.length) >= 5) {
      return u;
    }
    const dn = String(u.displayName || u.cn || '').toLowerCase();
    if (dn.includes(String(query).toLowerCase())) return u;
  }
  return null;
}

function departDisplayMatchScore(a, b) {
  const clean = (v) => String(v || '')
    .replace(/\uFFFD/g, '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
  const da = clean(a?.displayName || a?.cn || a?.sAMAccountName);
  const db = clean(b?.displayName || b?.cn || b?.sAMAccountName);
  if (!da || !db) return 0;
  if (da === db) return 100;
  const pa = da.split(/\s+/).filter(Boolean);
  const pb = db.split(/\s+/).filter(Boolean);
  if (pa[0] && pb[0] && pa[0] === pb[0] && pa[pa.length - 1] === pb[pb.length - 1]) return 85;
  if (da.includes(db) || db.includes(da)) return 75;
  return 0;
}

function enrichDepartedUser(user, snapUsers) {
  if (!user) return user;
  let out = repairUserTextFields({ ...user });
  let snap = findSnapshotUser(snapUsers, out.sAMAccountName);
  if (!snap && (hasCorruptText(out.displayName) || hasCorruptText(out.sAMAccountName))) {
    let best = null;
    let bestScore = 0;
    for (const candidate of Object.values(snapUsers || {})) {
      const score = departDisplayMatchScore(out, candidate);
      if (score > bestScore) {
        bestScore = score;
        best = candidate;
      }
    }
    if (bestScore >= 75) snap = best;
  }
  if (!snap) return out;

  out.sAMAccountName = snap.sAMAccountName || out.sAMAccountName;
  if (!out.displayName || hasCorruptText(out.displayName)) out.displayName = snap.displayName || snap.cn;
  if (!out.cn || hasCorruptText(out.cn)) out.cn = snap.cn;
  if (!out.mail && snap.mail) out.mail = snap.mail;
  if (!out.department && snap.department) out.department = snap.department;
  if (!out.title && snap.title) out.title = snap.title;
  if (!(out.groupNames || []).length && (snap.groupNames || []).length) {
    out.groups = snap.groups;
    out.groupNames = snap.groupNames;
    out.groupCount = snap.groupCount;
  }
  const perm = out.permissionsAtDeparture && typeof out.permissionsAtDeparture === 'object'
    ? { ...out.permissionsAtDeparture }
    : {};
  if (!(perm.groupNames || []).length && (snap.groupNames || []).length) {
    perm.groups = snap.groups;
    perm.groupNames = snap.groupNames;
    perm.groupCount = snap.groupCount;
    out.permissionsAtDeparture = perm;
  }
  return repairUserTextFields(out);
}

function migrateDepartedEncoding(store, snap) {
  const snapUsers = snap?.users || {};
  const next = {};
  let changed = false;

  for (const [key, rawUser] of Object.entries(store.users || {})) {
    const enriched = enrichDepartedUser(rawUser, snapUsers);
    const canonKey = String(enriched.sAMAccountName || key).toLowerCase();
    next[canonKey] = enriched;
    if (canonKey !== key) changed = true;
    if (JSON.stringify(enriched) !== JSON.stringify(rawUser)) changed = true;
  }

  if (changed) {
    store.users = next;
    saveDepartedStore(store);
  }
  return store;
}

function repairUserTextFields(user) {
  if (!user || typeof user !== 'object') return user;
  for (const key of [
    'displayName', 'cn', 'mail', 'department', 'title', 'description',
    'company', 'office', 'distinguishedName', 'userPrincipalName'
  ]) {
    if (user[key] != null) user[key] = repairPtText(user[key]);
  }
  if (Array.isArray(user.groupNames)) {
    user.groupNames = user.groupNames.map((g) => repairPtText(g));
  }
  if (Array.isArray(user.groups)) {
    user.groups = user.groups.map((g) => {
      if (!g || typeof g !== 'object') return repairPtText(g);
      return { ...g, name: repairPtText(g.name), dn: repairPtText(g.dn) };
    });
  }
  return user;
}

function runPowerShell(script, timeoutMs = 60000) {
  const encoded = Buffer.from(wrapPowerShellScript(script), 'utf16le').toString('base64');
  return execFileAsync(
    'powershell.exe',
    ['-NoProfile', '-NonInteractive', '-ExecutionPolicy', 'Bypass', '-EncodedCommand', encoded],
    {
      timeout: timeoutMs,
      windowsHide: true,
      maxBuffer: 40 * 1024 * 1024,
      encoding: 'buffer'
    }
  ).then(({ stdout, stderr }) => ({
    stdout: decodePowerShellOutput(stdout),
    stderr: decodePowerShellOutput(stderr)
  }));
}

function filetimeToIso(filetime) {
  const n = Number(filetime);
  if (!Number.isFinite(n) || n <= 0) return null;
  const ms = (n / 10000) - 11644473600000;
  const d = new Date(ms);
  return Number.isNaN(d.getTime()) ? null : d.toISOString();
}

function parseAdDateTime(value) {
  if (value == null || value === '') return null;
  const s = String(value).trim();
  const gt = s.match(/^(\d{4})(\d{2})(\d{2})(\d{2})(\d{2})(\d{2})/);
  if (gt) {
    const d = new Date(Date.UTC(+gt[1], +gt[2] - 1, +gt[3], +gt[4], +gt[5], +gt[6]));
    return Number.isNaN(d.getTime()) ? null : d.toISOString();
  }
  try {
    const d = new Date(s);
    return Number.isNaN(d.getTime()) ? null : d.toISOString();
  } catch {
    return null;
  }
}

function departedSortKey(user) {
  return user?.disabledAt || user?.departedAt || user?.lastDepartedAt || parseAdDateTime(user?.whenChanged) || '';
}

function cnFromDn(dn) {
  if (!dn) return null;
  const m = String(dn).match(/^CN=([^,]+)/i);
  return m ? m[1].replace(/\\/g, '') : String(dn);
}

function parseMemberOf(raw) {
  if (!raw) return [];
  const list = Array.isArray(raw) ? raw : [raw];
  return list
    .map((dn) => ({ dn: String(dn), name: cnFromDn(dn) }))
    .filter((g) => g.name)
    .sort((a, b) => a.name.localeCompare(b.name, 'pt-BR'));
}

function isDisabledUac(uac) {
  const n = Number(uac) || 0;
  return (n & UAC_ACCOUNTDISABLE) === UAC_ACCOUNTDISABLE;
}

function readJsonSafe(file, fallback) {
  try {
    if (!fs.existsSync(file)) return fallback;
    return JSON.parse(fs.readFileSync(file, 'utf8'));
  } catch {
    return fallback;
  }
}

function writeJsonAtomic(file, data) {
  ensureDataDir();
  const tmp = `${file}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(data, null, 2), 'utf8');
  fs.renameSync(tmp, file);
}

/**
 * Load all domain users (person accounts) with group membership via ADSI.
 */
async function loadAdUsers(timeoutMs = 90000) {
  const script = `
$ErrorActionPreference = 'Stop'
try {
  $rootDse = [ADSI]'LDAP://RootDSE'
  $defaultNc = $rootDse.defaultNamingContext.ToString()
  $domainDns = $null
  try {
    $domainDns = ([ADSI]("LDAP://$defaultNc")).dnsRoot
    if ($domainDns -is [System.DirectoryServices.PropertyValueCollection]) { $domainDns = $domainDns[0] }
  } catch {}
  if (-not $domainDns) {
    try { $domainDns = [System.DirectoryServices.ActiveDirectory.Domain]::GetCurrentDomain().Name } catch {}
  }

  $searcher = New-Object System.DirectoryServices.DirectorySearcher
  $searcher.SearchRoot = [ADSI]("LDAP://$defaultNc")
  $searcher.Filter = '(&(objectCategory=person)(objectClass=user))'
  $searcher.PageSize = 800
  $props = @(
    'sAMAccountName','userPrincipalName','displayName','cn','mail','department','title',
    'description','telephoneNumber','mobile','company','physicalDeliveryOfficeName',
    'distinguishedName','memberOf','userAccountControl','whenCreated','whenChanged',
    'lastLogonTimestamp','accountExpires','manager','employeeID','info'
  )
  foreach ($p in $props) { [void]$searcher.PropertiesToLoad.Add($p) }

  $users = @()
  foreach ($r in $searcher.FindAll()) {
    $get = {
      param($key)
      if ($r.Properties[$key] -and $r.Properties[$key].Count -gt 0) {
        if ($r.Properties[$key].Count -eq 1) { return [string]$r.Properties[$key][0] }
        $arr = @()
        foreach ($v in $r.Properties[$key]) { $arr += [string]$v }
        return $arr
      }
      return $null
    }
    $sam = & $get 'sAMAccountName'
    if (-not $sam) { continue }
    if ($sam.ToString().EndsWith('$')) { continue }

    $users += [PSCustomObject]@{
      sAMAccountName = $sam
      userPrincipalName = & $get 'userPrincipalName'
      displayName = & $get 'displayName'
      cn = & $get 'cn'
      mail = & $get 'mail'
      department = & $get 'department'
      title = & $get 'title'
      description = & $get 'description'
      telephoneNumber = & $get 'telephoneNumber'
      mobile = & $get 'mobile'
      company = & $get 'company'
      office = & $get 'physicalDeliveryOfficeName'
      distinguishedName = & $get 'distinguishedName'
      memberOf = & $get 'memberOf'
      userAccountControl = & $get 'userAccountControl'
      whenCreated = & $get 'whenCreated'
      whenChanged = & $get 'whenChanged'
      lastLogonTimestamp = & $get 'lastLogonTimestamp'
      accountExpires = & $get 'accountExpires'
      manager = & $get 'manager'
      employeeID = & $get 'employeeID'
      info = & $get 'info'
    }
  }

  (@{
    ok = $true
    domainDns = $domainDns
    defaultNamingContext = $defaultNc
    userCount = $users.Count
    users = $users
  }) | ConvertTo-Json -Depth 8 -Compress
} catch {
  (@{ ok = $false; error = $_.Exception.Message }) | ConvertTo-Json -Compress
}
`;

  try {
    const { stdout } = await runPowerShell(script, timeoutMs);
    const jsonStart = stdout.indexOf('{');
    if (jsonStart < 0) return { ok: false, error: 'Resposta AD usuários vazia', users: [], bySam: new Map() };
    const parsed = JSON.parse(stdout.slice(jsonStart));
    if (!parsed.ok) return { ok: false, error: parsed.error || 'Falha AD', users: [], bySam: new Map() };

    const bySam = new Map();
    const users = [];
    const list = Array.isArray(parsed.users) ? parsed.users : [];
    for (const u of list) {
      const sam = String(u.sAMAccountName || '').trim();
      if (!sam) continue;
      const groups = parseMemberOf(u.memberOf);
      const entry = repairUserTextFields({
        sAMAccountName: sam,
        userPrincipalName: u.userPrincipalName || null,
        displayName: u.displayName || u.cn || sam,
        mail: u.mail || null,
        department: u.department || null,
        title: u.title || null,
        description: u.description || null,
        telephoneNumber: u.telephoneNumber || null,
        mobile: u.mobile || null,
        company: u.company || null,
        office: u.office || null,
        distinguishedName: u.distinguishedName || null,
        groups,
        groupNames: groups.map((g) => g.name),
        groupCount: groups.length,
        userAccountControl: u.userAccountControl != null ? Number(u.userAccountControl) : null,
        disabled: isDisabledUac(u.userAccountControl),
        whenCreated: u.whenCreated || null,
        whenChanged: u.whenChanged || null,
        lastLogon: filetimeToIso(u.lastLogonTimestamp) || null,
        accountExpires: u.accountExpires || null,
        manager: u.manager ? cnFromDn(u.manager) : null,
        managerDn: u.manager || null,
        employeeID: u.employeeID || null,
        info: u.info || null,
        domainDns: parsed.domainDns || null
      });
      const key = sam.toLowerCase();
      bySam.set(key, entry);
      users.push(entry);
    }

    return {
      ok: true,
      domainDns: parsed.domainDns || null,
      defaultNamingContext: parsed.defaultNamingContext || null,
      userCount: users.length,
      users,
      bySam
    };
  } catch (err) {
    return { ok: false, error: err.message, users: [], bySam: new Map() };
  }
}

const DISABLED_OU_DN_RE = /(?:^|,)OU=(?:Disabled Users|Disabled User|Usuarios Desabilitados|Usuários Desabilitados|Disable Users|Disable User)(?:,|$)/i;

function mapAdUserFromRaw(u, domainDns) {
  const sam = String(u.sAMAccountName || '').trim();
  if (!sam) return null;
  const groups = parseMemberOf(u.memberOf);
  return repairUserTextFields({
    sAMAccountName: sam,
    userPrincipalName: u.userPrincipalName || null,
    displayName: u.displayName || u.cn || sam,
    mail: u.mail || null,
    department: u.department || null,
    title: u.title || null,
    description: u.description || null,
    telephoneNumber: u.telephoneNumber || null,
    mobile: u.mobile || null,
    company: u.company || null,
    office: u.office || null,
    distinguishedName: u.distinguishedName || null,
    groups,
    groupNames: groups.map((g) => g.name),
    groupCount: groups.length,
    userAccountControl: u.userAccountControl != null ? Number(u.userAccountControl) : null,
    disabled: isDisabledUac(u.userAccountControl),
    whenCreated: u.whenCreated || null,
    whenChanged: u.whenChanged || null,
    lastLogon: filetimeToIso(u.lastLogonTimestamp) || null,
    accountExpires: u.accountExpires || null,
    manager: u.manager ? cnFromDn(u.manager) : null,
    managerDn: u.manager || null,
    employeeID: u.employeeID || null,
    info: u.info || null,
    domainDns: domainDns || null
  });
}

/**
 * Carrega funcionários desabilitados dentro da OU "Disabled Users" (e equivalentes).
 */
async function loadDisabledOuUsers(timeoutMs = 90000) {
  const script = `
$ErrorActionPreference = 'Stop'
try {
  $rootDse = [ADSI]'LDAP://RootDSE'
  $defaultNc = $rootDse.defaultNamingContext.ToString()
  $domainDns = $null
  try {
    $domainDns = ([ADSI]("LDAP://$defaultNc")).dnsRoot
    if ($domainDns -is [System.DirectoryServices.PropertyValueCollection]) { $domainDns = $domainDns[0] }
  } catch {}

  $disabledOuPattern = '(?i)(^|,)(OU=(Disabled Users|Disabled User|Disable Users|Disable User|Usuarios Desabilitados|Usuários Desabilitados))(?=,|$)'

  function Get-LdapProp {
    param($Result, [string]$Key)
    if ($Result.Properties[$Key] -and $Result.Properties[$Key].Count -gt 0) {
      if ($Result.Properties[$Key].Count -eq 1) { return [string]$Result.Properties[$Key][0] }
      $arr = @()
      foreach ($v in $Result.Properties[$Key]) { $arr += [string]$v }
      return $arr
    }
    return $null
  }

  $searcher = New-Object System.DirectoryServices.DirectorySearcher
  $searcher.SearchRoot = [ADSI]("LDAP://$defaultNc")
  $searcher.Filter = '(&(objectCategory=person)(objectClass=user)(userAccountControl:1.2.840.113556.1.4.803:=2))'
  $searcher.PageSize = 800
  $props = @(
    'sAMAccountName','userPrincipalName','displayName','cn','mail','department','title',
    'description','telephoneNumber','mobile','company','physicalDeliveryOfficeName',
    'distinguishedName','memberOf','userAccountControl','whenCreated','whenChanged',
    'lastLogonTimestamp','accountExpires','manager','employeeID','info'
  )
  foreach ($p in $props) { [void]$searcher.PropertiesToLoad.Add($p) }

  $users = @()
  foreach ($hit in $searcher.FindAll()) {
    $dn = Get-LdapProp $hit 'distinguishedName'
    if (-not $dn -or ($dn -notmatch $disabledOuPattern)) { continue }
    $sam = Get-LdapProp $hit 'sAMAccountName'
    if (-not $sam -or $sam.ToString().EndsWith('$')) { continue }
    $users += [PSCustomObject]@{
      sAMAccountName = $sam
      userPrincipalName = Get-LdapProp $hit 'userPrincipalName'
      displayName = Get-LdapProp $hit 'displayName'
      cn = Get-LdapProp $hit 'cn'
      mail = Get-LdapProp $hit 'mail'
      department = Get-LdapProp $hit 'department'
      title = Get-LdapProp $hit 'title'
      description = Get-LdapProp $hit 'description'
      telephoneNumber = Get-LdapProp $hit 'telephoneNumber'
      mobile = Get-LdapProp $hit 'mobile'
      company = Get-LdapProp $hit 'company'
      office = Get-LdapProp $hit 'physicalDeliveryOfficeName'
      distinguishedName = $dn
      memberOf = Get-LdapProp $hit 'memberOf'
      userAccountControl = Get-LdapProp $hit 'userAccountControl'
      whenCreated = Get-LdapProp $hit 'whenCreated'
      whenChanged = Get-LdapProp $hit 'whenChanged'
      lastLogonTimestamp = Get-LdapProp $hit 'lastLogonTimestamp'
      accountExpires = Get-LdapProp $hit 'accountExpires'
      manager = Get-LdapProp $hit 'manager'
      employeeID = Get-LdapProp $hit 'employeeID'
      info = Get-LdapProp $hit 'info'
    }
  }

  (@{
    ok = $true
    domainDns = $domainDns
    userCount = $users.Count
    users = $users
  }) | ConvertTo-Json -Depth 8 -Compress
} catch {
  (@{ ok = $false; error = $_.Exception.Message }) | ConvertTo-Json -Compress
}
`;

  try {
    const { stdout } = await runPowerShell(script, timeoutMs);
    const jsonStart = stdout.indexOf('{');
    if (jsonStart < 0) return { ok: false, error: 'Resposta AD Disabled OU vazia', users: [] };
    const parsed = JSON.parse(stdout.slice(jsonStart));
    if (!parsed.ok) return { ok: false, error: parsed.error || 'Falha ao ler Disabled Users', users: [] };

    const users = [];
    const list = Array.isArray(parsed.users) ? parsed.users : [];
    for (const u of list) {
      const dn = String(u.distinguishedName || '');
      if (!DISABLED_OU_DN_RE.test(dn)) continue;
      const entry = mapAdUserFromRaw(u, parsed.domainDns || null);
      if (entry) users.push(entry);
    }

    users.sort((a, b) => {
      const ta = parseAdDateTime(a.whenChanged) || '';
      const tb = parseAdDateTime(b.whenChanged) || '';
      return tb.localeCompare(ta);
    });

    return { ok: true, domainDns: parsed.domainDns || null, userCount: users.length, users };
  } catch (err) {
    return { ok: false, error: err.message, users: [] };
  }
}

function buildDepartedFromDisabledOuUser(user) {
  const disabledAt = parseAdDateTime(user.whenChanged) || new Date().toISOString();
  return {
    ...user,
    disabledAt,
    departedAt: disabledAt,
    departReason: 'account_disabled',
    importSource: 'disabled_ou',
    lastSeenInAd: new Date().toISOString(),
    permissionsAtDeparture: {
      groups: Array.isArray(user.groups) ? user.groups : [],
      groupNames: Array.isArray(user.groupNames) ? user.groupNames : [],
      groupCount: user.groupCount != null ? user.groupCount : (user.groupNames || []).length,
      department: user.department || null,
      title: user.title || null,
      description: user.description || null
    }
  };
}

/**
 * Importa funcionários da OU Disabled Users para saídas arquivadas (somente adiciona novos).
 */
async function importDisabledOuUsersToDeparted(sendLog) {
  const log = typeof sendLog === 'function' ? sendLog : () => {};
  const loaded = await loadDisabledOuUsers();
  if (!loaded.ok) {
    log(`[!] Disabled Users: ${loaded.error || 'falha ao importar'}`);
    return { ok: false, error: loaded.error || 'Falha ao importar Disabled Users', imported: 0 };
  }

  const store = loadDepartedStore();
  let imported = 0;
  for (const user of loaded.users) {
    const key = String(user.sAMAccountName || '').toLowerCase();
    if (!key || store.users[key]) continue;
    store.users[key] = buildDepartedFromDisabledOuUser(user);
    imported++;
  }

  if (imported > 0) saveDepartedStore(store);
  const total = Object.keys(store.users).length;
  log(`[+] Disabled Users: ${loaded.userCount} no AD · ${imported} novo(s) arquivado(s) · total=${total}`);
  return { ok: true, imported, scanned: loaded.userCount, total };
}

async function lookupAdUser(query, timeoutMs = 30000) {
  const q = String(query || '').trim();
  if (!q) return { ok: false, error: 'Informe um login (sAMAccountName) ou UPN.' };

  const snap = loadSnapshot();
  const snapHit = findSnapshotUser(snap.users || {}, q);
  if (snapHit && (
    normalizeSamLookupKey(snapHit.sAMAccountName) === normalizeSamLookupKey(q)
    || String(snapHit.sAMAccountName || '').toLowerCase() === q.toLowerCase()
    || String(snapHit.userPrincipalName || '').toLowerCase() === q.toLowerCase()
  )) {
    return { ok: true, domainDns: snap.domainDns || null, source: 'snapshot', user: snapHit };
  }

  const escaped = q.replace(/\\/g, '\\5c').replace(/\*/g, '\\2a').replace(/\(/g, '\\28').replace(/\)/g, '\\29');

  const script = `
$ErrorActionPreference = 'Stop'
try {
  $rootDse = [ADSI]'LDAP://RootDSE'
  $defaultNc = $rootDse.defaultNamingContext.ToString()
  $domainDns = $null
  try {
    $domainDns = ([ADSI]("LDAP://$defaultNc")).dnsRoot
    if ($domainDns -is [System.DirectoryServices.PropertyValueCollection]) { $domainDns = $domainDns[0] }
  } catch {}

  $searcher = New-Object System.DirectoryServices.DirectorySearcher
  $searcher.SearchRoot = [ADSI]("LDAP://$defaultNc")
  $q = '${escaped.replace(/'/g, "''")}'
  $searcher.Filter = "(&(objectCategory=person)(objectClass=user)(|(sAMAccountName=$q)(userPrincipalName=$q)(mail=$q)(cn=$q)))"
  $searcher.PageSize = 20
  $props = @(
    'sAMAccountName','userPrincipalName','displayName','cn','mail','department','title',
    'description','telephoneNumber','mobile','company','physicalDeliveryOfficeName',
    'distinguishedName','memberOf','userAccountControl','whenCreated','whenChanged',
    'lastLogonTimestamp','accountExpires','manager','employeeID','info'
  )
  foreach ($p in $props) { [void]$searcher.PropertiesToLoad.Add($p) }

  $hit = $searcher.FindOne()
  if (-not $hit) {
    (@{ ok = $false; error = "Usuário não encontrado: $q" }) | ConvertTo-Json -Compress
    return
  }

  $get = {
    param($key)
    if ($hit.Properties[$key] -and $hit.Properties[$key].Count -gt 0) {
      if ($hit.Properties[$key].Count -eq 1) { return [string]$hit.Properties[$key][0] }
      $arr = @()
      foreach ($v in $hit.Properties[$key]) { $arr += [string]$v }
      return $arr
    }
    return $null
  }

  $user = [PSCustomObject]@{
    sAMAccountName = & $get 'sAMAccountName'
    userPrincipalName = & $get 'userPrincipalName'
    displayName = & $get 'displayName'
    cn = & $get 'cn'
    mail = & $get 'mail'
    department = & $get 'department'
    title = & $get 'title'
    description = & $get 'description'
    telephoneNumber = & $get 'telephoneNumber'
    mobile = & $get 'mobile'
    company = & $get 'company'
    office = & $get 'physicalDeliveryOfficeName'
    distinguishedName = & $get 'distinguishedName'
    memberOf = & $get 'memberOf'
    userAccountControl = & $get 'userAccountControl'
    whenCreated = & $get 'whenCreated'
    whenChanged = & $get 'whenChanged'
    lastLogonTimestamp = & $get 'lastLogonTimestamp'
    accountExpires = & $get 'accountExpires'
    manager = & $get 'manager'
    employeeID = & $get 'employeeID'
    info = & $get 'info'
  }

  (@{ ok = $true; domainDns = $domainDns; user = $user }) | ConvertTo-Json -Depth 8 -Compress
} catch {
  (@{ ok = $false; error = $_.Exception.Message }) | ConvertTo-Json -Compress
}
`;

  try {
    const { stdout } = await runPowerShell(script, timeoutMs);
    const jsonStart = stdout.indexOf('{');
    if (jsonStart < 0) return { ok: false, error: 'Resposta AD vazia' };
    const parsed = JSON.parse(stdout.slice(jsonStart));
    if (!parsed.ok || !parsed.user) {
      if (snapHit) {
        return { ok: true, domainDns: snap.domainDns || null, source: 'snapshot', user: snapHit };
      }
      return { ok: false, error: parsed.error || 'Usuário não encontrado' };
    }

    const u = parsed.user;
    const groups = parseMemberOf(u.memberOf);
    return {
      ok: true,
      domainDns: parsed.domainDns || null,
      user: repairUserTextFields({
        sAMAccountName: u.sAMAccountName,
        userPrincipalName: u.userPrincipalName || null,
        displayName: u.displayName || u.cn || u.sAMAccountName,
        mail: u.mail || null,
        department: u.department || null,
        title: u.title || null,
        description: u.description || null,
        telephoneNumber: u.telephoneNumber || null,
        mobile: u.mobile || null,
        company: u.company || null,
        office: u.office || null,
        distinguishedName: u.distinguishedName || null,
        groups,
        groupNames: groups.map((g) => g.name),
        groupCount: groups.length,
        userAccountControl: u.userAccountControl != null ? Number(u.userAccountControl) : null,
        disabled: isDisabledUac(u.userAccountControl),
        whenCreated: u.whenCreated || null,
        whenChanged: u.whenChanged || null,
        lastLogon: filetimeToIso(u.lastLogonTimestamp) || null,
        accountExpires: u.accountExpires || null,
        manager: u.manager ? cnFromDn(u.manager) : null,
        managerDn: u.manager || null,
        employeeID: u.employeeID || null,
        info: u.info || null,
        domainDns: parsed.domainDns || null
      })
    };
  } catch (err) {
    return { ok: false, error: err.message };
  }
}

function escapeLdapFilter(value) {
  return String(value || '')
    .replace(/\\/g, '\\5c')
    .replace(/\*/g, '\\2a')
    .replace(/\(/g, '\\28')
    .replace(/\)/g, '\\29');
}

function normalizeComputerQuery(query) {
  let raw = String(query || '').trim();
  if (!raw) return { raw: '', short: '', sam: '' };
  raw = raw.replace(/^\\\\+/, '');
  const short = raw.split('.')[0].replace(/\$$/i, '').trim();
  const sam = short ? `${short}$` : '';
  return { raw, short, sam };
}

function repairComputerTextFields(computer) {
  if (!computer || typeof computer !== 'object') return computer;
  for (const key of [
    'name', 'cn', 'dnsHostName', 'description', 'operatingSystem',
    'operatingSystemVersion', 'operatingSystemServicePack', 'distinguishedName',
    'location', 'managedBy'
  ]) {
    if (computer[key] != null) computer[key] = repairPtText(computer[key]);
  }
  if (Array.isArray(computer.groupNames)) {
    computer.groupNames = computer.groupNames.map((g) => repairPtText(g));
  }
  if (Array.isArray(computer.groups)) {
    computer.groups = computer.groups.map((g) => {
      if (!g || typeof g !== 'object') return repairPtText(g);
      return { ...g, name: repairPtText(g.name), dn: repairPtText(g.dn) };
    });
  }
  return computer;
}

function scoreComputerMatch(computer, norm) {
  const raw = norm.raw.toLowerCase();
  const short = norm.short.toLowerCase();
  const dns = String(computer.dnsHostName || '').toLowerCase();
  const name = String(computer.name || computer.cn || '').toLowerCase();
  const sam = String(computer.sAMAccountName || '').toLowerCase();
  if (!short) return 0;
  if (dns === raw || dns === short) return 100;
  if (name === short) return 95;
  if (sam === norm.sam.toLowerCase()) return 90;
  if (dns.startsWith(`${short}.`)) return 80;
  if (dns.includes(short)) return 70;
  if (name.startsWith(short)) return 60;
  if (sam.startsWith(`${short}$`)) return 55;
  return 10;
}

async function lookupAdComputer(query, timeoutMs = 30000) {
  const norm = normalizeComputerQuery(query);
  if (!norm.short) return { ok: false, error: 'Informe o hostname da máquina (ex.: WS-12345 ou SRV01.dominio.local).' };

  const escapedRaw = escapeLdapFilter(norm.raw);
  const escapedShort = escapeLdapFilter(norm.short);
  const escapedSam = escapeLdapFilter(norm.sam);

  const script = `
$ErrorActionPreference = 'Stop'
try {
  $rootDse = [ADSI]'LDAP://RootDSE'
  $defaultNc = $rootDse.defaultNamingContext.ToString()
  $domainDns = $null
  try {
    $domainDns = ([ADSI]("LDAP://$defaultNc")).dnsRoot
    if ($domainDns -is [System.DirectoryServices.PropertyValueCollection]) { $domainDns = $domainDns[0] }
  } catch {}

  $searcher = New-Object System.DirectoryServices.DirectorySearcher
  $searcher.SearchRoot = [ADSI]("LDAP://$defaultNc")
  $short = '${escapedShort.replace(/'/g, "''")}'
  $sam = '${escapedSam.replace(/'/g, "''")}'
  $raw = '${escapedRaw.replace(/'/g, "''")}'
  $searcher.Filter = "(&(objectCategory=computer)(|(name=$short)(cn=$short)(sAMAccountName=$sam)(dnsHostName=$raw)(dnsHostName=$short)))"
  $searcher.PageSize = 50
  $props = @(
    'name','cn','sAMAccountName','dnsHostName','distinguishedName','description',
    'operatingSystem','operatingSystemVersion','operatingSystemServicePack',
    'memberOf','primaryGroupID','objectSid','userAccountControl','whenCreated','whenChanged',
    'lastLogonTimestamp','pwdLastSet','managedBy','location'
  )
  foreach ($p in $props) { [void]$searcher.PropertiesToLoad.Add($p) }

  function Get-LdapProp {
    param($Result, [string]$Key)
    if ($Result.Properties[$Key] -and $Result.Properties[$Key].Count -gt 0) {
      if ($Result.Properties[$Key].Count -eq 1) { return [string]$Result.Properties[$Key][0] }
      $arr = @()
      foreach ($v in $Result.Properties[$Key]) { $arr += [string]$v }
      return $arr
    }
    return $null
  }

  function Resolve-PrimaryGroupName {
    param($Result)
    try {
      if (-not $Result.Properties['objectsid'] -or -not $Result.Properties['primarygroupid']) { return $null }
      $sidBytes = $Result.Properties['objectsid'][0]
      $pgid = [int]$Result.Properties['primarygroupid'][0]
      $sid = New-Object System.Security.Principal.SecurityIdentifier($sidBytes, 0)
      $groupSid = New-Object System.Security.Principal.SecurityIdentifier($sid.AccountDomainSid, $pgid)
      $gs = New-Object System.DirectoryServices.DirectorySearcher
      $gs.SearchRoot = [ADSI]("LDAP://$defaultNc")
      $gs.Filter = "(&(objectCategory=group)(objectSid=$($groupSid.Value)))"
      [void]$gs.PropertiesToLoad.Add('cn')
      [void]$gs.PropertiesToLoad.Add('distinguishedName')
      $gr = $gs.FindOne()
      if ($gr) {
        return @{
          name = [string]$gr.Properties['cn'][0]
          dn = [string]$gr.Properties['distinguishedname'][0]
        }
      }
    } catch {}
    return $null
  }

  $hits = @($searcher.FindAll())
  if (-not $hits -or $hits.Count -eq 0) {
    (@{ ok = $false; error = "Computador não encontrado: $raw" }) | ConvertTo-Json -Compress
    return
  }

  $computers = @()
  foreach ($hit in $hits) {
    $memberOf = Get-LdapProp $hit 'memberOf'
    if (-not $memberOf -and $hit.Properties['distinguishedname']) {
      try {
        $dn = [string]$hit.Properties['distinguishedname'][0]
        $ad = [ADSI]"LDAP://$dn"
        if ($ad.Properties['memberOf']) {
          $mo = @($ad.Properties['memberOf'] | ForEach-Object { [string]$_ })
          if ($mo.Count -gt 0) { $memberOf = $mo }
        }
      } catch {}
    }
    $primaryGroup = Resolve-PrimaryGroupName $hit
    $computers += [PSCustomObject]@{
      name = Get-LdapProp $hit 'name'
      cn = Get-LdapProp $hit 'cn'
      sAMAccountName = Get-LdapProp $hit 'sAMAccountName'
      dnsHostName = Get-LdapProp $hit 'dnsHostName'
      distinguishedName = Get-LdapProp $hit 'distinguishedName'
      description = Get-LdapProp $hit 'description'
      operatingSystem = Get-LdapProp $hit 'operatingSystem'
      operatingSystemVersion = Get-LdapProp $hit 'operatingSystemVersion'
      operatingSystemServicePack = Get-LdapProp $hit 'operatingSystemServicePack'
      memberOf = $memberOf
      primaryGroupName = $(if ($primaryGroup) { $primaryGroup.name } else { $null })
      primaryGroupDn = $(if ($primaryGroup) { $primaryGroup.dn } else { $null })
      userAccountControl = Get-LdapProp $hit 'userAccountControl'
      whenCreated = Get-LdapProp $hit 'whenCreated'
      whenChanged = Get-LdapProp $hit 'whenChanged'
      lastLogonTimestamp = Get-LdapProp $hit 'lastLogonTimestamp'
      pwdLastSet = Get-LdapProp $hit 'pwdLastSet'
      managedBy = Get-LdapProp $hit 'managedBy'
      location = Get-LdapProp $hit 'location'
    }
  }

  (@{ ok = $true; domainDns = $domainDns; computers = $computers }) | ConvertTo-Json -Depth 8 -Compress
} catch {
  (@{ ok = $false; error = $_.Exception.Message }) | ConvertTo-Json -Compress
}
`;

  try {
    const { stdout } = await runPowerShell(script, timeoutMs);
    const jsonStart = stdout.indexOf('{');
    if (jsonStart < 0) return { ok: false, error: 'Resposta AD vazia' };
    const parsed = JSON.parse(stdout.slice(jsonStart));
    if (!parsed.ok) return { ok: false, error: parsed.error || 'Computador não encontrado' };

    const rawList = Array.isArray(parsed.computers)
      ? parsed.computers
      : (parsed.computers ? [parsed.computers] : []);
    if (!rawList.length) return { ok: false, error: 'Computador não encontrado' };

    const mapped = rawList.map((c) => {
      const groups = parseMemberOf(c.memberOf);
      if (c.primaryGroupName) {
        const pgLower = String(c.primaryGroupName).toLowerCase();
        const hasPrimary = groups.some((g) => String(g.name || '').toLowerCase() === pgLower);
        if (!hasPrimary) {
          groups.unshift({
            dn: c.primaryGroupDn || '',
            name: c.primaryGroupName,
            primary: true
          });
        }
      }
      groups.sort((a, b) => {
        if (a.primary && !b.primary) return -1;
        if (!a.primary && b.primary) return 1;
        return String(a.name).localeCompare(String(b.name), 'pt-BR');
      });
      const groupNames = groups.map((g) => (g.primary ? `${g.name} (primário)` : g.name));
      return repairComputerTextFields({
        name: c.name || c.cn || null,
        cn: c.cn || c.name || null,
        sAMAccountName: c.sAMAccountName || null,
        dnsHostName: c.dnsHostName || null,
        description: c.description || null,
        operatingSystem: c.operatingSystem || null,
        operatingSystemVersion: c.operatingSystemVersion || null,
        operatingSystemServicePack: c.operatingSystemServicePack || null,
        distinguishedName: c.distinguishedName || null,
        location: c.location || null,
        managedBy: c.managedBy ? cnFromDn(c.managedBy) : null,
        managedByDn: c.managedBy || null,
        groups,
        groupNames,
        groupCount: groups.length,
        userAccountControl: c.userAccountControl != null ? Number(c.userAccountControl) : null,
        disabled: isDisabledUac(c.userAccountControl),
        whenCreated: c.whenCreated || null,
        whenChanged: c.whenChanged || null,
        lastLogon: filetimeToIso(c.lastLogonTimestamp) || null,
        passwordLastSet: filetimeToIso(c.pwdLastSet) || null,
        domainDns: parsed.domainDns || null
      });
    });

    mapped.sort((a, b) => scoreComputerMatch(b, norm) - scoreComputerMatch(a, norm));
    const computer = mapped[0];
    const alternates = mapped.slice(1, 6).map((c) => ({
      name: c.name,
      dnsHostName: c.dnsHostName,
      sAMAccountName: c.sAMAccountName,
      operatingSystem: c.operatingSystem,
      disabled: c.disabled
    }));

    return {
      ok: true,
      domainDns: parsed.domainDns || null,
      source: 'live',
      matchCount: mapped.length,
      computer,
      alternates
    };
  } catch (err) {
    return { ok: false, error: err.message };
  }
}

function loadDepartedStore() {
  const raw = readJsonSafe(DEPARTED_FILE, null);
  const store = !raw || typeof raw !== 'object'
    ? { version: 1, updatedAt: null, users: {} }
    : {
      version: 1,
      updatedAt: raw.updatedAt || null,
      users: raw.users && typeof raw.users === 'object' ? raw.users : {}
    };
  return migrateDepartedEncoding(store, loadSnapshot());
}

function saveDepartedStore(store) {
  writeJsonAtomic(DEPARTED_FILE, {
    version: 1,
    updatedAt: new Date().toISOString(),
    users: store.users || {}
  });
}

function loadSnapshot() {
  const snap = readJsonSafe(SNAPSHOT_FILE, { version: 1, capturedAt: null, domainDns: null, users: {} });
  if (snap.users && typeof snap.users === 'object') {
    for (const [key, u] of Object.entries(snap.users)) {
      snap.users[key] = repairUserTextFields(u);
    }
  }
  return snap;
}

function saveSnapshot(domainDns, bySam) {
  const users = {};
  for (const [key, u] of bySam.entries()) {
    users[key] = u;
  }
  writeJsonAtomic(SNAPSHOT_FILE, {
    version: 1,
    capturedAt: new Date().toISOString(),
    domainDns: domainDns || null,
    userCount: Object.keys(users).length,
    users
  });
}

async function ensureAdUserSnapshot(timeoutMs = 120000) {
  try {
    if (fs.existsSync(SNAPSHOT_FILE)) {
      const raw = JSON.parse(fs.readFileSync(SNAPSHOT_FILE, 'utf8'));
      const count = raw.userCount || Object.keys(raw.users || {}).length;
      if (count > 0) {
        return { ok: true, userCount: count, source: 'snapshot', capturedAt: raw.capturedAt || null };
      }
    }
  } catch {
    // refresh below
  }
  const cur = await loadAdUsers(timeoutMs);
  if (!cur.ok) return { ok: false, error: cur.error || 'Falha ao carregar usuários AD' };
  saveSnapshot(cur.domainDns, cur.bySam);
  return { ok: true, userCount: cur.userCount, source: 'live', capturedAt: new Date().toISOString() };
}

function detectDepartures(previousSnapshot, currentBySam) {
  const prevUsers = (previousSnapshot && previousSnapshot.users) || {};
  const found = [];

  for (const [key, prev] of Object.entries(prevUsers)) {
    const cur = currentBySam.get(key);
    let reason = null;

    if (!cur) {
      reason = 'removed_from_ad';
    } else if (!prev.disabled && cur.disabled) {
      reason = 'account_disabled';
    }

    if (!reason) continue;

    found.push({
      ...prev,
      departedAt: new Date().toISOString(),
      departReason: reason,
      lastSeenInAd: previousSnapshot.capturedAt || null,
      permissionsAtDeparture: {
        groups: Array.isArray(prev.groups) ? prev.groups : [],
        groupNames: Array.isArray(prev.groupNames) ? prev.groupNames : (prev.groups || []).map((g) => g.name || g),
        groupCount: prev.groupCount != null ? prev.groupCount : (prev.groups || []).length,
        department: prev.department || null,
        title: prev.title || null,
        description: prev.description || null
      }
    });
  }

  return found;
}

/**
 * Sync during scan: archive leavers, refresh snapshot. Never auto-deletes departed file.
 */
async function syncAdUserAudit(sendLog) {
  const log = typeof sendLog === 'function' ? sendLog : () => {};
  log('[~] AD Usuários: sincronizando catálogo e auditando saídas...');

  const current = await loadAdUsers();
  if (!current.ok) {
    log(`[!] AD Usuários indisponível: ${current.error || 'erro'}`);
    return {
      ok: false,
      error: current.error || 'Falha ao ler usuários AD',
      newlyDeparted: 0,
      departedTotal: Object.keys(loadDepartedStore().users).length,
      userCount: 0
    };
  }

  const previous = loadSnapshot();
  const hasPrevious = previous.users && Object.keys(previous.users).length > 0;
  const departedStore = loadDepartedStore();
  let newlyDeparted = 0;

  if (hasPrevious) {
    const leavers = detectDepartures(previous, current.bySam);
    for (const leaver of leavers) {
      const key = String(leaver.sAMAccountName || '').toLowerCase();
      if (!key) continue;
      if (!departedStore.users[key]) {
        departedStore.users[key] = leaver;
        newlyDeparted++;
      } else {
        const existing = departedStore.users[key];
        const events = Array.isArray(existing.departEvents) ? existing.departEvents : [];
        events.push({
          at: leaver.departedAt,
          reason: leaver.departReason,
          groupCount: leaver.permissionsAtDeparture.groupCount
        });
        existing.departEvents = events.slice(-20);
        existing.lastDepartedAt = leaver.departedAt;
        existing.lastDepartReason = leaver.departReason;
        const oldCount = (existing.permissionsAtDeparture && existing.permissionsAtDeparture.groupCount) || 0;
        const newCount = leaver.permissionsAtDeparture.groupCount || 0;
        if (newCount >= oldCount) {
          existing.permissionsAtDeparture = leaver.permissionsAtDeparture;
          existing.groups = leaver.groups;
          existing.groupNames = leaver.groupNames;
          existing.groupCount = leaver.groupCount;
        }
        departedStore.users[key] = existing;
      }
    }
    if (newlyDeparted > 0 || leavers.length > 0) {
      saveDepartedStore(departedStore);
    }
    log(`[+] AD Usuários: ${current.userCount} no domínio · ${newlyDeparted} nova(s) saída(s) · arquivados=${Object.keys(departedStore.users).length}`);
  } else {
    log(`[+] AD Usuários: leitura base com ${current.userCount} usuário(s). Próximas varreduras detectarão saídas.`);
  }

  saveSnapshot(current.domainDns, current.bySam);

  const disabledImport = await importDisabledOuUsersToDeparted(log);

  return {
    ok: true,
    domainDns: current.domainDns,
    userCount: current.userCount,
    newlyDeparted,
    departedTotal: Object.keys(loadDepartedStore().users).length,
    disabledOuImported: disabledImport.imported || 0,
    disabledOuScanned: disabledImport.scanned || 0,
    baselineOnly: !hasPrevious
  };
}

function listDepartedUsers() {
  const store = loadDepartedStore();
  const users = Object.values(store.users || {}).sort((a, b) =>
    departedSortKey(b).localeCompare(departedSortKey(a))
  );
  return {
    ok: true,
    updatedAt: store.updatedAt,
    file: DEPARTED_FILE,
    count: users.length,
    users
  };
}

function clearDepartedUsers() {
  ensureDataDir();
  if (fs.existsSync(DEPARTED_FILE)) fs.unlinkSync(DEPARTED_FILE);
  return { ok: true, cleared: true, file: DEPARTED_FILE };
}

function removeDepartedUser(sam) {
  const key = String(sam || '').toLowerCase().trim();
  if (!key) return { ok: false, error: 'Login inválido' };
  const store = loadDepartedStore();
  if (!store.users[key]) return { ok: false, error: 'Usuário não está na auditoria de saídas' };
  delete store.users[key];
  saveDepartedStore(store);
  return { ok: true, removed: key, count: Object.keys(store.users).length };
}

function normalizeDeptKey(name) {
  return String(name || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ');
}

const SKIP_OU_NAMES = new Set([
  'usuarios', 'users', 'user', 'computers', 'computadores', 'computer',
  'groups', 'grupos', 'domain controllers', 'builtin', 'microsoft exchange system objects',
  'system', 'foreignsecurityprincipals', 'managed service accounts',
  'com_usb', 'com usb', 'comusb', 'computadores_internet', 'computadores internet',
  'active', 'disabled user', 'disabled users', 'sccm', 'servidores',
  'totem', 'painel_totem', 'painel totem', 'nao-desliga-monitor', 'nao desliga monitor',
  'naodesligamonitor', 'funcionarios', 'chefia', 'sem_aceite_vnc', 'sem aceite vnc'
]);

/** Contas compartilhadas "Usuarios - Setor" dentro de OU=Usuarios */
const USUARIOS_NODE_RE = /^(?:usu[aá]rios|users)\s*[-–—:]\s*(.+)$/i;

const SKIP_SIGNATURE_GROUP_RE = /sistemafamesp|domain users|authenticated users|^users$/i;

/** Grupos base que todo login AD costuma ter / deve receber */
const BASELINE_AD_GROUPS = ['Domain Users', 'Users', 'Usuarios'];

const SKIP_GROUP_NAMES = new Set([
  'domain guests',
  'authenticated users',
  'everyone'
]);

function sortGroupsAlpha(names) {
  return [...names].sort((a, b) =>
    String(a).localeCompare(String(b), 'pt-BR', { sensitivity: 'base' })
  );
}

function ensureBaselineGroups(groupStats, peers, enabledCount) {
  for (const gName of BASELINE_AD_GROUPS) {
    const low = gName.toLowerCase();
    if (groupStats.has(low)) continue;
    groupStats.set(low, {
      name: gName,
      dn: null,
      count: enabledCount,
      users: peers.map((p) => p.sAMAccountName)
    });
  }
}

function mergeBaselineGroupNames(names) {
  const out = sortGroupsAlpha(names.filter(Boolean).map(String));
  const seen = new Set(out.map((n) => n.toLowerCase()));
  for (const gName of BASELINE_AD_GROUPS) {
    if (!seen.has(gName.toLowerCase())) out.push(gName);
  }
  return sortGroupsAlpha(out);
}

function parseOusFromDn(dn) {
  return String(dn || '')
    .split(',')
    .map((p) => p.trim())
    .filter((p) => /^OU=/i.test(p))
    .map((p) => p.replace(/^OU=/i, '').replace(/\\/g, ''));
}

function isGenericOuKey(key) {
  if (!key) return true;
  // Snapshot às vezes grava "Usuários" com byte inválido (U+FFFD)
  const cleaned = String(key).replace(/\uFFFD/g, 'a').replace(/[^a-z0-9]+/g, ' ').trim();
  if (SKIP_OU_NAMES.has(key) || SKIP_OU_NAMES.has(cleaned)) return true;
  if (/^usu.?rios$/.test(cleaned) || /^users?$/.test(cleaned)) return true;
  if (cleaned.endsWith('usuarios') || cleaned.endsWith(' users')) return true;
  if (/^usuarios\b/.test(cleaned) || /^users\b/.test(cleaned)) return true;
  return false;
}

function getUserTreeLocation(user) {
  const dn = user?.distinguishedName;
  if (!dn) return null;
  const parts = String(dn).split(',').map((p) => p.trim());
  const chain = [];
  let skippedSelf = false;
  for (const p of parts) {
    if (/^DC=/i.test(p)) break;
    const m = p.match(/^(OU|CN)=([^,]+)$/i);
    if (!m) continue;
    // Primeiro RDN é o próprio usuário (CN=login)
    if (!skippedSelf && m[1].toUpperCase() === 'CN') {
      skippedSelf = true;
      continue;
    }
    chain.push({
      kind: m[1].toUpperCase(),
      name: repairPtText(m[2].replace(/\\/g, ''))
    });
  }
  if (!chain.length) return null;

  const ousFromUser = chain.filter((c) => c.kind === 'OU').map((c) => c.name);
  if (!ousFromUser.length) {
    const container = chain[0]?.name || '';
    if (!container) return null;
    return {
      name: container,
      path: [],
      leaf: container,
      source: 'cn-container'
    };
  }

  const path = ousFromUser.slice().reverse();
  return {
    name: path.join(' > '),
    path,
    leaf: ousFromUser[0],
    source: 'ou-path'
  };
}

function isFlatUsuariosPath(loc) {
  if (!loc || loc.source !== 'ou-path') return false;
  return loc.path.length === 1 && /^usu[aá]rios$/i.test(String(loc.path[0]).replace(/\uFFFD/g, 'a'));
}

function parseUsuariosNodeName(user) {
  for (const field of [user?.displayName, user?.cn]) {
    const m = String(field || '').match(USUARIOS_NODE_RE);
    if (m) return m[1].trim();
  }
  return null;
}

function isUsuariosNodeAccount(user) {
  return Boolean(parseUsuariosNodeName(user));
}

/**
 * Infer setor/departamento: atributo department, OU da árvore, ou nó "Usuarios - X".
 */
function inferDepartment(user) {
  const attr = String(user?.department || '').trim();
  if (attr && !['distinguishedname', 'first name', 'lastname', 'n/a'].includes(attr.toLowerCase())) {
    return { name: attr, source: 'department' };
  }
  const ous = parseOusFromDn(user?.distinguishedName);

  // Nó da árvore: OU que realmente agrupa o usuário (pula containers genéricos tipo Usuarios)
  for (const ou of ous) {
    const key = normalizeDeptKey(ou);
    if (!isGenericOuKey(key)) return { name: ou, source: 'ou' };
  }
  // CIMED_Usuarios → CIMED
  for (const ou of ous) {
    const m = String(ou).match(/^(.+?)_usuarios$/i);
    if (m) return { name: m[1], source: 'ou-prefix' };
  }
  // Só OU=Usuarios: o "a mais" são contas CN=Usuarios - Setor
  const nodeName = parseUsuariosNodeName(user);
  if (nodeName) return { name: nodeName, source: 'usuarios-node' };

  return { name: '', source: 'none' };
}

function buildGroupFrequency(users) {
  const freq = new Map();
  for (const u of users) {
    if (!u || u.disabled) continue;
    for (const g of u.groupNames || []) {
      const name = String(g || '').trim();
      if (!name) continue;
      freq.set(name, (freq.get(name) || 0) + 1);
    }
  }
  return freq;
}

function pickSignatureGroups(groupNames, freq, enabledCount) {
  // Grupos "de setor": raros o bastante para não vazar Farmácia/PS inteiro
  const maxFreq = Math.max(20, Math.floor((enabledCount || 1) * 0.008));
  const candidates = [];
  for (const g of groupNames || []) {
    const name = String(g || '').trim();
    if (!name) continue;
    const low = name.toLowerCase();
    if (SKIP_GROUP_NAMES.has(low) || /^domain users$|^users$|^usu[aá]rios$/i.test(name) || SKIP_SIGNATURE_GROUP_RE.test(name)) continue;
    const f = freq.get(name) || 0;
    if (f > 0 && f <= maxFreq) candidates.push({ name, f });
  }
  candidates.sort((a, b) => a.f - b.f || a.name.localeCompare(b.name));
  // Fica com o cluster raro (até ~3x o grupo mais raro, máx. 6)
  if (!candidates.length) return [];
  const rarest = candidates[0].f;
  const cap = Math.max(rarest * 3, rarest + 8);
  return candidates.filter((c) => c.f <= cap).slice(0, 6).map((c) => c.name);
}

function userMatchesUsuariosNode(user, marker) {
  if (!user || !marker) return false;
  if (isUsuariosNodeAccount(user)) return false;
  const groups = user.groupNames || [];
  if (!groups.length || !marker.signatureGroups.size) return false;
  let hits = 0;
  for (const g of groups) {
    if (marker.signatureGroups.has(String(g).toLowerCase())) hits += 1;
  }
  // 1 grupo característico basta (já são filtrados para raros)
  return hits >= 1;
}

/**
 * Índice dos nós "Usuarios - Setor" + grupos característicos para achar pares.
 */
function buildUsuariosNodeIndex(users) {
  const enabled = users.filter((u) => u && !u.disabled);
  const freq = buildGroupFrequency(enabled);
  const markers = new Map();

  for (const u of users) {
    if (!u) continue;
    const label = parseUsuariosNodeName(u);
    if (!label) continue;
    const key = normalizeDeptKey(label);
    if (!key || isGenericOuKey(key)) continue;

    const sigs = pickSignatureGroups(u.groupNames || [], freq, enabled.length);
    if (!markers.has(key)) {
      markers.set(key, {
        name: label,
        sam: u.sAMAccountName,
        disabled: Boolean(u.disabled),
        signatureGroups: new Set(sigs.map((g) => g.toLowerCase())),
        source: 'usuarios-node'
      });
    } else {
      const row = markers.get(key);
      for (const g of sigs) row.signatureGroups.add(g.toLowerCase());
      if (!row.disabled && u.disabled) {/* keep enabled marker */}
      else if (row.disabled && !u.disabled) {
        row.sam = u.sAMAccountName;
        row.disabled = false;
      }
    }
  }
  return { markers, freq, enabledCount: enabled.length };
}

const EXACT_ONLY_DEPT_KEYS = new Set([
  'usuarios', 'users', 'user', 'disabled user', 'disabled users',
  'active', 'builtin', 'genericos', 'computers', 'computadores'
]);

function userMatchesDepartment(user, department, nodeIndex = null) {
  const want = normalizeDeptKey(department);
  const wantRaw = String(department || '').trim();
  if (!want || !user) return false;
  if (isUsuariosNodeAccount(user) && normalizeDeptKey(parseUsuariosNodeName(user)) === want) {
    return false;
  }

  const loc = getUserTreeLocation(user);
  if (loc) {
    if (normalizeDeptKey(loc.name) === want) return true;
    if (!wantRaw.includes('>') && !EXACT_ONLY_DEPT_KEYS.has(want)) {
      if (normalizeDeptKey(loc.leaf) === want) return true;
      if (loc.path.some((p) => normalizeDeptKey(p) === want)) return true;
    }
  }

  if (normalizeDeptKey(user?.department) === want) return true;

  const index = nodeIndex || buildUsuariosNodeIndex(
    (() => {
      try {
        const snap = loadSnapshot();
        return Object.values(snap.users || {});
      } catch {
        return [];
      }
    })()
  );
  const marker = index.markers.get(want);
  if (marker && userMatchesUsuariosNode(user, marker)) return true;

  return false;
}

/**
 * Lista todos os nós da árvore hcfmb.ad que contêm usuários:
 * caminho OU completo, containers CN (Builtin, …) e nós "Usuarios - Setor".
 */
/** Containers CN conhecidos do domínio (mesmo sem contas no snapshot) */
const KNOWN_CN_CONTAINERS = ['Users', 'Builtin'];

function listDepartments(filter = '') {
  const snap = loadSnapshot();
  const users = snap.users && typeof snap.users === 'object' ? Object.values(snap.users) : [];
  const nodeIndex = buildUsuariosNodeIndex(users);
  const map = new Map();

  function ensureDept(name, source, path = []) {
    const key = normalizeDeptKey(name);
    if (!key) return null;
    if (!map.has(key)) {
      map.set(key, {
        name: repairPtText(name),
        path: Array.isArray(path) ? path : [],
        userCount: 0,
        enabledCount: 0,
        source
      });
    }
    return map.get(key);
  }

  // 1) Cada nó folha da árvore onde o usuário está (caminho OU ou container CN)
  for (const u of users) {
    if (!u) continue;
    const loc = getUserTreeLocation(u);
    if (!loc) continue;
    const row = ensureDept(loc.name, loc.source, loc.path);
    if (!row) continue;
    row.userCount += 1;
    if (!u.disabled) row.enabledCount += 1;
  }

  // 1b) Nós-pai na árvore (ex.: HEBO dentro de HEBO > Usuarios)
  for (const u of users) {
    if (!u) continue;
    const loc = getUserTreeLocation(u);
    if (!loc || loc.source !== 'ou-path' || loc.path.length < 2) continue;
    for (let i = 0; i < loc.path.length - 1; i++) {
      const subPath = loc.path.slice(0, i + 1);
      const name = subPath.join(' > ');
      const row = ensureDept(name, 'ou-path', subPath);
      if (!row) continue;
      row.userCount += 1;
      if (!u.disabled) row.enabledCount += 1;
    }
  }

  // 2) Nós "Usuarios - Setor" (setores dentro de OU=Usuarios)
  for (const marker of nodeIndex.markers.values()) {
    if (marker.disabled) continue;
    const row = ensureDept(marker.name, 'usuarios-node');
    if (!row) continue;
    if (row.source !== 'ou-path' && row.source !== 'cn-container') {
      row.source = 'usuarios-node';
    }
  }

  // 3) Contar pares dos nós Usuarios - Setor (grupos característicos)
  for (const u of users) {
    if (!u || u.disabled || isUsuariosNodeAccount(u)) continue;
    for (const [key, marker] of nodeIndex.markers) {
      const row = map.get(key);
      if (!row || row.source !== 'usuarios-node') continue;
      if (!userMatchesUsuariosNode(u, marker)) continue;
      row.userCount += 1;
      row.enabledCount += 1;
    }
  }

  // Containers CN conhecidos (Users, Builtin…) mesmo vazios no snapshot
  for (const cn of KNOWN_CN_CONTAINERS) {
    ensureDept(cn, 'cn-container', []);
  }

  let list = Array.from(map.values())
    .filter((d) => d.enabledCount > 0 || d.userCount > 0 || KNOWN_CN_CONTAINERS.includes(d.name))
    .sort((a, b) => a.name.localeCompare(b.name, 'pt-BR', { sensitivity: 'base' }));

  const q = String(filter || '').trim();
  if (q) {
    const nq = normalizeDeptKey(q);
    list = list.filter((d) => normalizeDeptKey(d.name).includes(nq));
  }

  return {
    ok: true,
    source: 'snapshot',
    capturedAt: snap.capturedAt || null,
    domainDns: snap.domainDns || null,
    count: list.length,
    departamentosFromOu: list.filter((d) => d.source === 'ou-path' || d.source === 'cn-container').length,
    departamentosFromUsuariosNode: list.filter((d) => d.source === 'usuarios-node').length,
    departments: list,
    hint: list.length
      ? null
      : 'Nenhum setor no snapshot. Rode uma varredura (sync AD) ou analise com “AD ao vivo”.'
  };
}

function usersFromSnapshotByDepartment(department) {
  const snap = loadSnapshot();
  const all = Object.values(snap.users || {});
  const nodeIndex = buildUsuariosNodeIndex(all);
  const users = [];
  for (const u of all) {
    if (!u) continue;
    if (!userMatchesDepartment(u, department, nodeIndex)) continue;
    users.push(u);
  }
  return { snap, users };
}

function escapeLdapValue(value) {
  return String(value || '')
    .replace(/\\/g, '\\5c')
    .replace(/\*/g, '\\2a')
    .replace(/\(/g, '\\28')
    .replace(/\)/g, '\\29')
    .replace(/\0/g, '\\00');
}

function buildDepartmentLdapFilter(dept) {
  const trimmed = String(dept || '').trim();
  if (!trimmed) return '(&(objectCategory=person)(objectClass=user))';

  if (/^builtin$/i.test(trimmed)) {
    return '(&(objectCategory=person)(objectClass=user)(distinguishedName=*CN=Builtin,*))';
  }
  if (/^users$/i.test(trimmed)) {
    return '(&(objectCategory=person)(objectClass=user)(distinguishedName=*CN=Users,*))';
  }

  if (trimmed.includes(' > ')) {
    const dnSuffix = trimmed.split('>')
      .map((s) => s.trim())
      .filter(Boolean)
      .reverse()
      .map((p) => `OU=${escapeLdapValue(p)}`)
      .join(',');
    return `(&(objectCategory=person)(objectClass=user)(distinguishedName=*${escapeLdapValue(dnSuffix)}*))`;
  }

  const esc = escapeLdapValue(trimmed);
  return `(&(objectCategory=person)(objectClass=user)(|(department=${esc})(distinguishedName=*OU=${esc},*)(distinguishedName=*OU=${esc}*)(distinguishedName=*CN=${esc},*)))`;
}

/**
 * Busca ao vivo no AD usuários do departamento (LDAP).
 */
async function loadUsersByDepartmentLive(department, timeoutMs = 90000) {
  const dept = String(department || '').trim();
  if (!dept) return { ok: false, error: 'Informe o departamento', users: [] };

  const ldapFilter = buildDepartmentLdapFilter(dept);
  const filterEscaped = ldapFilter.replace(/'/g, "''");

  const script = `
$ErrorActionPreference = 'Stop'
try {
  $rootDse = [ADSI]'LDAP://RootDSE'
  $defaultNc = $rootDse.defaultNamingContext.ToString()
  $dept = '${dept.replace(/'/g, "''")}'

  $searcher = New-Object System.DirectoryServices.DirectorySearcher
  $searcher.SearchRoot = [ADSI]("LDAP://$defaultNc")
  $searcher.Filter = '${filterEscaped}'
  $searcher.PageSize = 500
  $props = @('sAMAccountName','displayName','cn','mail','department','title','memberOf','userAccountControl','distinguishedName')
  foreach ($p in $props) { [void]$searcher.PropertiesToLoad.Add($p) }

  $users = @()
  foreach ($r in $searcher.FindAll()) {
    $get = {
      param($key)
      if ($r.Properties[$key] -and $r.Properties[$key].Count -gt 0) {
        if ($r.Properties[$key].Count -eq 1) { return [string]$r.Properties[$key][0] }
        $arr = @()
        foreach ($v in $r.Properties[$key]) { $arr += [string]$v }
        return $arr
      }
      return $null
    }
    $sam = & $get 'sAMAccountName'
    if (-not $sam) { continue }
    if ($sam.ToString().EndsWith('$')) { continue }
    $users += [PSCustomObject]@{
      sAMAccountName = $sam
      displayName = & $get 'displayName'
      cn = & $get 'cn'
      mail = & $get 'mail'
      department = & $get 'department'
      title = & $get 'title'
      memberOf = & $get 'memberOf'
      userAccountControl = & $get 'userAccountControl'
      distinguishedName = & $get 'distinguishedName'
    }
  }

  (@{ ok = $true; userCount = $users.Count; users = $users }) | ConvertTo-Json -Depth 8 -Compress
} catch {
  (@{ ok = $false; error = $_.Exception.Message }) | ConvertTo-Json -Compress
}
`;

  try {
    const { stdout } = await runPowerShell(script, timeoutMs);
    const jsonStart = stdout.indexOf('{');
    if (jsonStart < 0) return { ok: false, error: 'Resposta AD vazia', users: [] };
    const parsed = JSON.parse(stdout.slice(jsonStart));
    if (!parsed.ok) return { ok: false, error: parsed.error || 'Falha AD', users: [] };

    const users = [];
    for (const u of (parsed.users || [])) {
      const sam = String(u.sAMAccountName || '').trim();
      if (!sam) continue;
      const groups = parseMemberOf(u.memberOf);
      users.push(repairUserTextFields({
        sAMAccountName: sam,
        displayName: u.displayName || u.cn || sam,
        mail: u.mail || null,
        department: u.department || dept,
        title: u.title || null,
        distinguishedName: u.distinguishedName || null,
        groups,
        groupNames: groups.map((g) => g.name),
        groupCount: groups.length,
        disabled: isDisabledUac(u.userAccountControl),
        userAccountControl: u.userAccountControl != null ? Number(u.userAccountControl) : null
      }));
    }
    return { ok: true, users };
  } catch (err) {
    return { ok: false, error: err.message, users: [] };
  }
}

/**
 * Compara funcionários do departamento e sugere grupos-padrão para o novo login.
 * @param {string} department
 * @param {{ minCoverage?: number, live?: boolean, includeDisabled?: boolean }} options
 */
async function analyzeDepartmentPermissions(department, options = {}) {
  const dept = String(department || '').trim();
  if (!dept) return { ok: false, error: 'Informe o departamento' };

  const minCoverage = Math.min(1, Math.max(0.1, Number(options.minCoverage) || 0.5));
  const coreCoverage = Math.min(1, Math.max(minCoverage, Number(options.coreCoverage) || 0.8));
  const includeDisabled = Boolean(options.includeDisabled);
  const live = Boolean(options.live);

  let source = 'snapshot';
  let capturedAt = null;
  let users = [];

  if (live) {
    const liveRes = await loadUsersByDepartmentLive(dept);
    if (!liveRes.ok) return { ok: false, error: liveRes.error || 'Falha ao consultar AD' };
    users = liveRes.users;
    source = 'live';
  } else {
    const fromSnap = usersFromSnapshotByDepartment(dept);
    users = fromSnap.users;
    capturedAt = fromSnap.snap.capturedAt || null;
    // Se snapshot vazio para o dept, tenta live automaticamente
    if (!users.length) {
      const liveRes = await loadUsersByDepartmentLive(dept);
      if (liveRes.ok && liveRes.users.length) {
        users = liveRes.users;
        source = 'live';
      }
    }
  }

  const peers = users.filter((u) => includeDisabled || !u.disabled);
  const enabledCount = peers.length;

  const groupStats = new Map(); // name -> { name, dn, count, users: [] }

  for (const u of peers) {
    const names = Array.isArray(u.groupNames) && u.groupNames.length
      ? u.groupNames
      : (u.groups || []).map((g) => g.name || g);
    const seen = new Set();
    for (let i = 0; i < names.length; i++) {
      const rawName = String(names[i] || '').trim();
      if (!rawName) continue;
      const low = rawName.toLowerCase();
      if (SKIP_GROUP_NAMES.has(low)) continue;
      if (seen.has(low)) continue;
      seen.add(low);

      if (!groupStats.has(low)) {
        const gObj = (u.groups || []).find((g) => (g.name || g) === rawName);
        groupStats.set(low, {
          name: rawName,
          dn: gObj && gObj.dn ? gObj.dn : null,
          count: 0,
          users: []
        });
      }
      const st = groupStats.get(low);
      st.count += 1;
      st.users.push(u.sAMAccountName);
    }
  }

  ensureBaselineGroups(groupStats, peers, enabledCount);

  const groups = Array.from(groupStats.values()).map((g) => {
    const coverage = enabledCount ? g.count / enabledCount : 0;
    const isBaseline = BASELINE_AD_GROUPS.some((b) => b.toLowerCase() === g.name.toLowerCase());
    let tier = 'raro';
    if (isBaseline || coverage >= coreCoverage) tier = 'nucleo';
    else if (coverage >= minCoverage) tier = 'recomendado';
    else if (coverage >= 0.25) tier = 'parcial';
    return {
      name: g.name,
      dn: g.dn,
      count: g.count,
      coverage,
      coveragePct: Math.round(coverage * 100),
      tier,
      sampleUsers: g.users.slice(0, 8)
    };
  }).sort((a, b) => a.name.localeCompare(b.name, 'pt-BR', { sensitivity: 'base' }));

  const recommended = groups.filter((g) => g.tier === 'nucleo' || g.tier === 'recomendado');
  const recommendedNames = sortGroupsAlpha(recommended.map((g) => g.name));

  const peerSummaries = peers
    .map((u) => {
      const names = mergeBaselineGroupNames(
        Array.isArray(u.groupNames) && u.groupNames.length
          ? u.groupNames
          : (u.groups || []).map((g) => g.name || g)
      );
      const set = new Set(names.map((n) => String(n).toLowerCase()));
      const matchRec = recommendedNames.filter((n) => set.has(n.toLowerCase())).length;
      const extra = sortGroupsAlpha(names.filter((n) => {
        const low = String(n).toLowerCase();
        if (SKIP_GROUP_NAMES.has(low)) return false;
        return !recommendedNames.some((r) => r.toLowerCase() === low);
      }));
      return {
        sAMAccountName: u.sAMAccountName,
        displayName: u.displayName || u.sAMAccountName,
        title: u.title || null,
        disabled: Boolean(u.disabled),
        groupCount: names.length,
        recommendedMatch: matchRec,
        recommendedTotal: recommendedNames.length,
        recommendedCoveragePct: recommendedNames.length
          ? Math.round((matchRec / recommendedNames.length) * 100)
          : 0,
        extraGroups: extra.slice(0, 20),
        groups: names
      };
    })
    .sort((a, b) => b.recommendedCoveragePct - a.recommendedCoveragePct
      || String(a.displayName).localeCompare(String(b.displayName), 'pt-BR'));

  return {
    ok: true,
    department: dept,
    source,
    capturedAt,
    minCoverage,
    coreCoverage,
    userCount: users.length,
    enabledCount,
    groupCount: groups.length,
    recommendedCount: recommended.length,
    recommendedGroups: recommended,
    allGroups: groups,
    peers: peerSummaries,
    suggestedForNewUser: recommendedNames,
    copyText: recommendedNames.join('\n')
  };
}

function userInGroup(user, groupName) {
  const want = normalizeDeptKey(groupName);
  if (!want || !user) return false;
  const names = Array.isArray(user.groupNames) && user.groupNames.length
    ? user.groupNames
    : (user.groups || []).map((g) => g.name || g);
  return names.some((n) => normalizeDeptKey(n) === want);
}

function buildGroupIndexFromSnapshot(snap) {
  const map = new Map();
  for (const u of Object.values(snap?.users || {})) {
    if (!u) continue;
    const names = Array.isArray(u.groupNames) && u.groupNames.length
      ? u.groupNames
      : (u.groups || []).map((g) => g.name || g);
    const seen = new Set();
    for (const raw of names) {
      const name = repairPtText(String(raw || '').trim());
      if (!name) continue;
      const low = name.toLowerCase();
      if (SKIP_GROUP_NAMES.has(low)) continue;
      if (seen.has(low)) continue;
      seen.add(low);
      if (!map.has(low)) {
        const gObj = (u.groups || []).find((g) => (g.name || g) === name);
        map.set(low, {
          name,
          dn: gObj && gObj.dn ? gObj.dn : null,
          memberCount: 0,
          enabledCount: 0
        });
      }
      const row = map.get(low);
      row.memberCount += 1;
      if (!u.disabled) row.enabledCount += 1;
    }
  }
  return map;
}

function groupSortPrefix(name) {
  if (/^G_/i.test(name)) return 0;
  if (/^Grupo_/i.test(name)) return 1;
  return 2;
}

/**
 * Lista grupos AD do snapshot (prioriza G_ e Grupo_).
 */
function listAdGroups(filter = '') {
  const snap = loadSnapshot();
  const index = buildGroupIndexFromSnapshot(snap);
  let list = Array.from(index.values()).map((g) => ({
    name: g.name,
    dn: g.dn,
    memberCount: g.memberCount,
    enabledCount: g.enabledCount,
    prefix: groupSortPrefix(g.name)
  }));

  list.sort((a, b) =>
    a.prefix - b.prefix
    || a.name.localeCompare(b.name, 'pt-BR', { sensitivity: 'base' })
  );

  const q = normalizeDeptKey(filter);
  if (q) {
    list = list.filter((g) => normalizeDeptKey(g.name).includes(q));
  }

  return {
    ok: true,
    source: 'snapshot',
    capturedAt: snap.capturedAt || null,
    domainDns: snap.domainDns || null,
    count: list.length,
    gPrefixCount: list.filter((g) => g.prefix === 0).length,
    groups: list
  };
}

function usersByGroupFromSnapshot(groupName) {
  const snap = loadSnapshot();
  const users = [];
  let groupDn = null;
  for (const u of Object.values(snap.users || {})) {
    if (!u || !userInGroup(u, groupName)) continue;
    users.push(u);
    if (!groupDn && Array.isArray(u.groups)) {
      const hit = u.groups.find((g) => normalizeDeptKey(g.name) === normalizeDeptKey(groupName));
      if (hit && hit.dn) groupDn = hit.dn;
    }
  }
  return { snap, users, groupDn };
}

async function loadUsersByGroupLive(groupName, timeoutMs = 90000) {
  const group = String(groupName || '').trim();
  if (!group) return { ok: false, error: 'Informe o grupo', users: [] };

  const ldapFilter = `(&(objectCategory=person)(objectClass=user)(memberOf=*CN=${escapeLdapValue(group)},*))`;
  const filterEscaped = ldapFilter.replace(/'/g, "''");

  const script = `
$ErrorActionPreference = 'Stop'
try {
  $rootDse = [ADSI]'LDAP://RootDSE'
  $defaultNc = $rootDse.defaultNamingContext.ToString()
  $group = '${group.replace(/'/g, "''")}'

  $searcher = New-Object System.DirectoryServices.DirectorySearcher
  $searcher.SearchRoot = [ADSI]("LDAP://$defaultNc")
  $searcher.Filter = '${filterEscaped}'
  $searcher.PageSize = 500
  $props = @('sAMAccountName','displayName','cn','mail','department','title','memberOf','userAccountControl','distinguishedName')
  foreach ($p in $props) { [void]$searcher.PropertiesToLoad.Add($p) }

  $users = @()
  foreach ($r in $searcher.FindAll()) {
    $get = {
      param($key)
      if ($r.Properties[$key] -and $r.Properties[$key].Count -gt 0) {
        if ($r.Properties[$key].Count -eq 1) { return [string]$r.Properties[$key][0] }
        $arr = @()
        foreach ($v in $r.Properties[$key]) { $arr += [string]$v }
        return $arr
      }
      return $null
    }
    $sam = & $get 'sAMAccountName'
    if (-not $sam) { continue }
    if ($sam.ToString().EndsWith('$')) { continue }
    $users += [PSCustomObject]@{
      sAMAccountName = $sam
      displayName = & $get 'displayName'
      cn = & $get 'cn'
      mail = & $get 'mail'
      department = & $get 'department'
      title = & $get 'title'
      memberOf = & $get 'memberOf'
      userAccountControl = & $get 'userAccountControl'
      distinguishedName = & $get 'distinguishedName'
    }
  }

  (@{ ok = $true; group = $group; userCount = $users.Count; users = $users }) | ConvertTo-Json -Depth 8 -Compress
} catch {
  (@{ ok = $false; error = $_.Exception.Message }) | ConvertTo-Json -Compress
}
`;

  try {
    const { stdout } = await runPowerShell(script, timeoutMs);
    const jsonStart = stdout.indexOf('{');
    if (jsonStart < 0) return { ok: false, error: 'Resposta AD vazia', users: [] };
    const parsed = JSON.parse(stdout.slice(jsonStart));
    if (!parsed.ok) return { ok: false, error: parsed.error || 'Falha AD', users: [] };

    const users = [];
    for (const u of (parsed.users || [])) {
      const sam = String(u.sAMAccountName || '').trim();
      if (!sam) continue;
      const groups = parseMemberOf(u.memberOf);
      users.push(repairUserTextFields({
        sAMAccountName: sam,
        displayName: u.displayName || u.cn || sam,
        mail: u.mail || null,
        department: u.department || null,
        title: u.title || null,
        distinguishedName: u.distinguishedName || null,
        groups,
        groupNames: groups.map((g) => g.name),
        groupCount: groups.length,
        disabled: isDisabledUac(u.userAccountControl),
        userAccountControl: u.userAccountControl != null ? Number(u.userAccountControl) : null
      }));
    }
    return { ok: true, users };
  } catch (err) {
    return { ok: false, error: err.message, users: [] };
  }
}

/**
 * Usuários membros de um grupo AD (snapshot ou consulta ao vivo).
 */
async function searchGroupMembers(groupName, options = {}) {
  const group = String(groupName || '').trim();
  if (!group) return { ok: false, error: 'Informe o grupo' };

  const includeDisabled = Boolean(options.includeDisabled);
  const live = Boolean(options.live);

  let source = 'snapshot';
  let capturedAt = null;
  let users = [];
  let groupDn = null;

  const fromSnap = usersByGroupFromSnapshot(group);
  capturedAt = fromSnap.snap.capturedAt || null;
  groupDn = fromSnap.groupDn || null;
  users = fromSnap.users;

  if (live) {
    const liveRes = await loadUsersByGroupLive(group);
    if (!liveRes.ok) return { ok: false, error: liveRes.error || 'Falha ao consultar AD' };
    users = liveRes.users;
    source = 'live';
  } else if (!users.length) {
    const liveRes = await loadUsersByGroupLive(group);
    if (liveRes.ok && liveRes.users.length) {
      users = liveRes.users;
      source = 'live';
    }
  }

  const filtered = users.filter((u) => includeDisabled || !u.disabled);
  const members = filtered
    .map((u) => ({
      sAMAccountName: u.sAMAccountName,
      displayName: u.displayName || u.sAMAccountName,
      disabled: Boolean(u.disabled),
      department: u.department || null,
      title: u.title || null,
      mail: u.mail || null,
      groupCount: u.groupCount != null ? u.groupCount : (u.groupNames || []).length,
      groups: u.groupNames || (u.groups || []).map((g) => g.name || g)
    }))
    .sort((a, b) =>
      String(a.displayName).localeCompare(String(b.displayName), 'pt-BR', { sensitivity: 'base' })
    );

  return {
    ok: true,
    group,
    groupDn,
    source,
    capturedAt,
    includeDisabled,
    memberCount: users.length,
    enabledCount: filtered.length,
    members
  };
}

