function formatPsExecError(err, timeoutMs = 15000) {
  const msg = err?.message || String(err);
  if (err?.killed || /ETIMEDOUT|timed out|timeout/i.test(msg)) {
    const sec = Math.round((timeoutMs || 15000) / 1000);
    return `Tempo esgotado (${sec}s). Para teste DHCP, execute o NetScan como administrador.`;
  }
  if (/EPERM|EACCES|access denied|acesso negado|elevated|administrator/i.test(msg)) {
    return 'Acesso negado — execute o NetScan como administrador para o teste DHCP.';
  }
  if (/Command failed.*powershell/i.test(msg) || /powershell/i.test(msg)) {
    return 'Falha no PowerShell de rede (permissão, timeout ou política de execução). Tente como administrador.';
  }
  return 'Falha ao executar comando de rede local.';
}

async function runPowerShell(script, timeoutMs = 15000) {
  const scriptPath = path.join(os.tmpdir(), `netscan-autotest-${process.pid}-${Date.now()}.ps1`);
  try {
    fs.writeFileSync(scriptPath, script, 'utf8');
    const { stdout } = await execAsync(
      `powershell -NoProfile -ExecutionPolicy Bypass -File "${scriptPath}"`,
      { timeout: timeoutMs, maxBuffer: 1024 * 1024 }
    );
    const jsonStart = stdout.indexOf('{');
    if (jsonStart < 0) return { ok: false, error: 'Resposta PowerShell vazia' };
    return JSON.parse(stdout.slice(jsonStart));
  } catch (err) {
    return { ok: false, error: formatPsExecError(err, timeoutMs) };
  } finally {
    try { fs.unlinkSync(scriptPath); } catch { /* ignore */ }
  }
}

async function tcpConnect(ip, port, timeoutMs) {
  const t0 = Date.now();
  return new Promise((resolve) => {
    const socket = new net.Socket();
    let settled = false;
    const finish = (result) => {
      if (settled) return;
      settled = true;
      try { socket.destroy(); } catch { /* ignore */ }
      resolve(result);
    };
    socket.setTimeout(timeoutMs);
    socket.on('connect', () => finish({ ok: true, ms: Date.now() - t0 }));
    socket.on('timeout', () => finish({ ok: false, ms: Date.now() - t0 }));
    socket.on('error', () => finish({ ok: false, ms: Date.now() - t0 }));
    try {
      socket.connect(port, ip);
    } catch {
      finish({ ok: false, ms: Date.now() - t0 });
    }
  });
}

async function getLocalNetwork() {
  const script = `$ErrorActionPreference = 'SilentlyContinue'
$cfg = Get-NetIPConfiguration | Where-Object { $_.IPv4DefaultGateway -ne $null -and $_.NetAdapter.Status -eq 'Up' } | Select-Object -First 1
if (-not $cfg) {
  @{ ok = $false; error = 'Nenhuma interface IPv4 ativa com gateway encontrada.' } | ConvertTo-Json -Compress
  exit
}
$gw = $cfg.IPv4DefaultGateway.NextHop
$ip = ($cfg.IPv4Address | Select-Object -First 1).IPAddress
$prefix = ($cfg.IPv4Address | Select-Object -First 1).PrefixLength
$dns = @($cfg.DNSServer | ForEach-Object { $_.ServerAddresses }) | Where-Object { $_ }
$dhcp = $false
try { $dhcp = (Get-NetIPAddress -InterfaceIndex $cfg.InterfaceIndex -AddressFamily IPv4).PrefixOrigin -eq 'Dhcp' } catch {}
@{
  ok = $true
  interfaceAlias = $cfg.InterfaceAlias
  interfaceIndex = $cfg.InterfaceIndex
  ip = $ip
  prefixLength = $prefix
  gateway = $gw
  dnsServers = @($dns)
  dhcp = [bool]$dhcp
  macAddress = ($cfg.NetAdapter | Select-Object -First 1).MacAddress
  linkSpeed = ($cfg.NetAdapter | Select-Object -First 1).LinkSpeed
  mediaType = ($cfg.NetAdapter | Select-Object -First 1).MediaType
  isPrimary = $true
} | ConvertTo-Json -Compress
`;
  try {
    return await runPowerShell(script, 15000);
  } catch (err) {
    return { ok: false, error: err.message || 'Falha ao ler configuração de rede local' };
  }
}

function isWifiInterface(i) {
  const blob = `${i.interfaceAlias || ''} ${i.mediaType || ''}`.toLowerCase();
  return /wi-?fi|wireless|802\.11|wlan/.test(blob);
}

function pickTestInterface(cfg, ifaces) {
  const list = ifaces?.interfaces || [];
  const mode = cfg.testInterfaceMode || 'auto';
  const custom = (cfg.testInterface || '').trim();

  if (mode === 'custom' && custom) {
    return list.find((i) => i.interfaceAlias === custom) || null;
  }
  if (mode === 'secondary') {
    return list.find((i) => !i.isPrimary && i.ip) || list.find((i) => !i.isPrimary) || null;
  }
  if (mode === 'wifi') {
    return list.find((i) => isWifiInterface(i) && i.ip) || list.find(isWifiInterface) || null;
  }
  if (mode === 'primary') {
    return list.find((i) => i.isPrimary) || list.find((i) => i.gateway) || null;
  }
  return null;
}

function ifaceToLocal(entry, modeLabel) {
  if (!entry) {
    return { ok: false, error: `Nenhuma placa de rede encontrada${modeLabel ? ` (modo: ${modeLabel})` : ''}.` };
  }
  if (!entry.ip) {
    return {
      ok: false,
      error: `A placa "${entry.interfaceAlias}" está ativa mas sem IPv4.`,
      interfaceAlias: entry.interfaceAlias
    };
  }
  return { ok: true, ...entry };
}

async function resolveLocalNetwork(cfg = {}) {
  const mode = cfg.testInterfaceMode || 'auto';
  const custom = (cfg.testInterface || '').trim();

  if (mode === 'auto' && !custom) {
    return getLocalNetwork();
  }

  const ifaces = await listNetworkInterfaces();
  if (!ifaces.ok) return { ok: false, error: ifaces.error || 'Falha ao listar interfaces' };

  if (mode === 'auto') {
    const picked = ifaces.interfaces.find((i) => i.isPrimary && i.gateway)
      || ifaces.interfaces.find((i) => i.gateway)
      || ifaces.interfaces.find((i) => i.isPrimary)
      || ifaces.interfaces[0];
    return ifaceToLocal(picked);
  }

  const modeLabels = { primary: 'primária', secondary: 'secundária', wifi: 'Wi-Fi', custom: 'específica' };
  const picked = pickTestInterface(cfg, ifaces);
  if (mode === 'custom' && custom && !picked) {
    return { ok: false, error: `Interface "${custom}" não encontrada ou indisponível.` };
  }
  return ifaceToLocal(picked, modeLabels[mode] || mode);
}

async function listNetworkInterfaces() {
  const script = `$ErrorActionPreference = 'SilentlyContinue'
$primary = Get-NetIPConfiguration | Where-Object { $_.IPv4DefaultGateway -ne $null -and $_.NetAdapter.Status -eq 'Up' } | Select-Object -First 1
$primaryAlias = if ($primary) { $primary.InterfaceAlias } else { $null }
$items = @()
Get-NetIPConfiguration | Where-Object { $_.NetAdapter.Status -eq 'Up' } | ForEach-Object {
  $ipObj = $_.IPv4Address | Select-Object -First 1
  $dhcp = $false
  try { $dhcp = (Get-NetIPAddress -InterfaceIndex $_.InterfaceIndex -AddressFamily IPv4).PrefixOrigin -eq 'Dhcp' } catch {}
  $items += @{
    interfaceAlias = $_.InterfaceAlias
    interfaceIndex = $_.InterfaceIndex
    ip = if ($ipObj) { $ipObj.IPAddress } else { $null }
    prefixLength = if ($ipObj) { $ipObj.PrefixLength } else { $null }
    gateway = if ($_.IPv4DefaultGateway) { $_.IPv4DefaultGateway.NextHop } else { $null }
    dnsServers = @($_.DNSServer | ForEach-Object { $_.ServerAddresses }) | Where-Object { $_ }
    dhcp = [bool]$dhcp
    macAddress = $_.NetAdapter.MacAddress
    isPrimary = ($_.InterfaceAlias -eq $primaryAlias)
    mediaType = $_.NetAdapter.MediaType
    linkSpeed = $_.NetAdapter.LinkSpeed
  }
}
@{ ok = $true; primaryAlias = $primaryAlias; interfaces = $items } | ConvertTo-Json -Depth 5 -Compress
`;
  try {
    const data = await runPowerShell(script, 20000);
    if (!data.ok) return data;
    if (!Array.isArray(data.interfaces)) data.interfaces = data.interfaces ? [data.interfaces] : [];
    return data;
  } catch (err) {
    return { ok: false, error: err.message || 'Falha ao listar interfaces', interfaces: [] };
  }
}

function pickDhcpTestInterface(cfg, local, ifaces) {
  const list = ifaces?.interfaces || [];
  const mode = cfg.dhcpTestMode || 'secondary';
  const custom = (cfg.dhcpTestInterface || '').trim();

  if (custom) {
    const found = list.find((i) => i.interfaceAlias === custom);
    return found || { interfaceAlias: custom };
  }
  if (mode === 'primary') {
    return list.find((i) => i.isPrimary) || local;
  }
  const secondary = list.find((i) => !i.isPrimary && i.interfaceAlias);
  return secondary || null;
}

async function testDhcpRenewal(interfaceAlias, timeoutMs) {
  const safeAlias = String(interfaceAlias || '').replace(/'/g, "''");
  const waitSec = Math.min(8, Math.max(3, Math.ceil((timeoutMs || 4000) / 1000)));
  const script = `$ErrorActionPreference = 'SilentlyContinue'
$alias = '${safeAlias}'
$adapter = Get-NetAdapter -Name $alias -ErrorAction SilentlyContinue
if (-not $adapter -or $adapter.Status -ne 'Up') {
  @{ ok = $false; error = "Interface '$alias' indisponível ou desligada." } | ConvertTo-Json -Compress
  exit
}
Register-DhcpClient -InterfaceAlias $alias -ErrorAction SilentlyContinue | Out-Null
Start-Sleep -Seconds ${waitSec}
$addr = Get-NetIPAddress -InterfaceAlias $alias -AddressFamily IPv4 -ErrorAction SilentlyContinue | Select-Object -First 1
$lease = Get-DhcpClientv4Lease -InterfaceAlias $alias -ErrorAction SilentlyContinue | Where-Object { $_.AddressFamily -eq 'IPv4' } | Select-Object -First 1
$gw = (Get-NetIPConfiguration -InterfaceAlias $alias -ErrorAction SilentlyContinue).IPv4DefaultGateway.NextHop
@{
  ok = ($null -ne $addr -and $addr.IPAddress)
  interfaceAlias = $alias
  ip = if ($addr) { $addr.IPAddress } else { $null }
  prefixLength = if ($addr) { $addr.PrefixLength } else { $null }
  prefixOrigin = if ($addr) { [string]$addr.PrefixOrigin } else { $null }
  dhcp = if ($addr) { $addr.PrefixOrigin -eq 'Dhcp' } else { $false }
  gateway = $gw
  leaseExpiry = if ($lease -and $lease.LeaseExpiryTime) { $lease.LeaseExpiryTime.ToString('o') } else { $null }
  leaseObtained = if ($lease -and $lease.LeaseObtainedTime) { $lease.LeaseObtainedTime.ToString('o') } else { $null }
} | ConvertTo-Json -Compress
`;
  try {
    return await runPowerShell(script, (waitSec + 8) * 1000);
  } catch (err) {
    return { ok: false, error: formatPsExecError(err, (waitSec + 8) * 1000) };
  }
}

async function runTraceroute(target, maxHops, timeoutMs) {
  const t0 = Date.now();
  try {
    const { stdout } = await execAsync(
      `tracert -d -h ${maxHops} -w ${Math.min(timeoutMs, 3000)} ${target}`,
      { timeout: Math.max(30000, maxHops * timeoutMs + 5000), maxBuffer: 1024 * 1024 }
    );
    const hops = [];
    for (const line of stdout.split('\n')) {
      const m = line.match(/^\s*(\d+)\s+(?:(\d+)\s+ms|\*)/);
      if (m) {
        const hop = Number(m[1]);
        const ms = m[2] ? Number(m[2]) : null;
        const ipMatch = line.match(/(\d{1,3}(?:\.\d{1,3}){3})/);
        hops.push({ hop, ms, ip: ipMatch ? ipMatch[1] : null });
      }
    }
    const reached = hops.some((h) => h.ip === target);
    return {
      ok: hops.length > 0,
      reached,
      hops: hops.slice(0, maxHops),
      ms: Date.now() - t0,
      raw: stdout.split('\n').slice(0, maxHops + 4).join('\n')
    };
  } catch (err) {
    return { ok: false, reached: false, hops: [], ms: Date.now() - t0, error: err.message };
  }
}

function resolveTarget(name, local) {
  if (name === 'gateway') return local?.gateway || null;
  if (name === 'local') return local?.ip || null;
  return name;
}

async function runAutoTest(options = {}) {
  const cfg = resolveRunConfig(options);
  const timeoutMs = Number(cfg.timeoutMs) || 2500;
  const pingCount = Math.min(Math.max(Number(cfg.pingCount) || 4, 1), 10);
  const steps = [];
  const started = Date.now();
  let stop = false;

  const local = await resolveLocalNetwork(cfg);
  if (!local.ok) {
    steps.push(step('local', 'Interface local', 'fail', local.error || 'Sem rede', Date.now() - started));
    return finalize(steps, started, local, cfg);
  }

  const linkLabel = formatLinkSpeed(local.linkSpeed);
  steps.push(step('local', 'Interface local', 'pass',
    `${local.interfaceAlias} · ${local.ip}/${local.prefixLength} · ${local.dhcp ? 'DHCP' : 'Estático'}` +
    (local.macAddress ? ` · ${local.macAddress}` : ''),
    null,
    { ip: local.ip, gateway: local.gateway, dnsServers: local.dnsServers, macAddress: local.macAddress }));

  if (linkLabel || local.mediaType) {
    steps.push(step('link', 'Link / velocidade', linkLabel ? 'pass' : 'warn',
      [linkLabel, local.mediaType].filter(Boolean).join(' · ') || 'Velocidade não detectada',
      null,
      { linkSpeed: local.linkSpeed, linkLabel, mediaType: local.mediaType }));
  }

  if (cfg.vlanCheckEnabled && !stop) {
    const t0 = Date.now();
    const vlan = await netTests.checkVlanOnInterface(local.interfaceAlias);
    if (!vlan.ok) {
      steps.push(step('vlan', 'VLAN / 802.1Q', 'warn', vlan.error || 'Não foi possível ler VLAN', Date.now() - t0));
    } else if (vlan.vlanId) {
      steps.push(step('vlan', 'VLAN / 802.1Q', 'pass', `VLAN ${vlan.vlanId} em ${local.interfaceAlias}`, Date.now() - t0, vlan));
    } else if (vlan.isWifi) {
      steps.push(step('vlan', 'VLAN / 802.1Q', 'pass', 'Interface Wi-Fi — VLAN gerenciada pelo AP', Date.now() - t0, vlan));
    } else {
      steps.push(step('vlan', 'VLAN / 802.1Q', 'pass', 'Acesso untagged (sem VLAN ID na NIC)', Date.now() - t0, vlan));
    }
  }

  if (cfg.duplicateIpCheckEnabled && !stop) {
    const t0 = Date.now();
    const dup = await netTests.checkDuplicateIp(local);
    steps.push(step('duplicate-ip', 'IP duplicado (ARP)', dup.duplicate ? 'fail' : 'pass',
      dup.detail || (dup.ok ? 'Sem conflito' : 'Falha'), Date.now() - t0, dup));
    if (dup.duplicate && cfg.stopOnFail) stop = true;
  }

  if (cfg.wifiScanEnabled && !stop) {
    const t0 = Date.now();
    const wifi = await netTests.scanWifiNetworks();
    if (wifi.skip) {
      steps.push(step('wifi-scan', 'Scan Wi-Fi', 'skip', wifi.error || 'Wi-Fi indisponível', Date.now() - t0));
    } else if (!wifi.ok) {
      steps.push(step('wifi-scan', 'Scan Wi-Fi', 'warn', wifi.error || 'Nenhuma rede detectada', Date.now() - t0));
    } else {
      const top = (wifi.networks || []).slice(0, 3).map((n) => `${n.ssid} ${n.signal || '?'}%`).join(' · ');
      steps.push(step('wifi-scan', 'Scan Wi-Fi', 'pass',
        `${wifi.count} rede(s) · ${top}`, Date.now() - t0, { networks: wifi.networks }));
    }
  }

  if (cfg.dhcpTestEnabled && !stop) {
    const t0 = Date.now();
    const ifaces = await listNetworkInterfaces();
    const target = pickDhcpTestInterface(cfg, local, ifaces);
    if (!target?.interfaceAlias) {
      steps.push(step('dhcp', 'Teste DHCP (renovação)', 'warn',
        cfg.dhcpTestMode === 'secondary'
          ? 'Nenhuma interface secundária ativa encontrada'
          : 'Interface alvo não encontrada',
        Date.now() - t0));
    } else {
      const ifaceDetail = (ifaces.interfaces || []).find((i) => i.interfaceAlias === target.interfaceAlias);
      if (ifaceDetail && ifaceDetail.dhcp === false && ifaceDetail.ip) {
        steps.push(step('dhcp', `DHCP · ${target.interfaceAlias}`, 'warn',
          `IP estático (${ifaceDetail.ip}) — renovação DHCP não aplicável`,
          Date.now() - t0, { mode: cfg.dhcpTestMode, staticIp: true }));
      } else {
      const dh = await testDhcpRenewal(target.interfaceAlias, timeoutMs + 2000);
      const modeLabel = cfg.dhcpTestMode === 'primary' ? 'primária' : (cfg.dhcpTestInterface ? 'custom' : 'secundária');
      if (!dh.ok) {
        steps.push(step('dhcp', `DHCP · ${target.interfaceAlias}`, 'fail',
          dh.error || 'Renovação sem endereço IPv4', Date.now() - t0, { mode: modeLabel }));
        if (cfg.stopOnFail) stop = true;
      } else {
        const leaseTxt = dh.leaseExpiry ? ` · lease até ${new Date(dh.leaseExpiry).toLocaleString('pt-BR')}` : '';
        steps.push(step('dhcp', `DHCP · ${target.interfaceAlias}`, dh.dhcp ? 'pass' : 'warn',
          `${dh.ip}/${dh.prefixLength} · ${dh.dhcp ? 'DHCP confirmado' : 'IP estático'} · ${modeLabel}${leaseTxt}`,
          Date.now() - t0, { ...dh, mode: modeLabel }));
        if (!dh.dhcp && cfg.dhcpTestMode !== 'primary') {
          /* still ok as warn */
        }
      }
      }
    }
  }

  if (local.gateway) {
    const t0 = Date.now();
    const ping = await pingHostStats(local.gateway, pingCount, timeoutMs);
    steps.push(step('gateway', 'Gateway padrão', pingStatusFromStats(ping),
      formatPingStatsDetail(ping, local.gateway),
      Date.now() - t0, { pingStats: ping }));
    if (!ping.ok && cfg.stopOnFail) stop = true;
  } else {
    steps.push(step('gateway', 'Gateway padrão', 'warn', 'Gateway não detectado'));
  }

  if (!stop && local.dnsServers?.length) {
    for (const dnsIp of local.dnsServers.slice(0, 3)) {
      const t0 = Date.now();
      const ping = await pingHostStats(dnsIp, Math.min(pingCount, 3), timeoutMs);
      steps.push(step(`dns-ping-${dnsIp}`, `DNS server ${dnsIp}`, pingStatusFromStats(ping),
        formatPingStatsDetail(ping, dnsIp),
        Date.now() - t0, { pingStats: ping }));
    }
  }

  if (!stop) {
    for (const host of (cfg.dnsHosts || []).slice(0, 5)) {
      const t0 = Date.now();
      try {
        const addrs = await dns.resolve4(host);
        steps.push(step(`dns-${host}`, `DNS · ${host}`, 'pass',
          addrs.slice(0, 3).join(', '), Date.now() - t0, { addresses: addrs }));
      } catch (err) {
        steps.push(step(`dns-${host}`, `DNS · ${host}`, 'fail', err.code || err.message, Date.now() - t0));
        if (cfg.stopOnFail) { stop = true; break; }
      }
    }
  }

  if (!stop && cfg.dnsViaServerEnabled && local.dnsServers?.length) {
    const host = (cfg.dnsHosts || [])[0] || 'google.com';
    for (const dnsIp of local.dnsServers.slice(0, 2)) {
      const t0 = Date.now();
      try {
        const addrs = await netTests.resolveViaDnsServer(dnsIp, host);
        steps.push(step(`dns-via-${dnsIp}`, `DNS via ${dnsIp} · ${host}`, 'pass',
          addrs.slice(0, 3).join(', '), Date.now() - t0, { server: dnsIp, host, addresses: addrs }));
      } catch (err) {
        steps.push(step(`dns-via-${dnsIp}`, `DNS via ${dnsIp} · ${host}`, 'fail',
          err.code || err.message, Date.now() - t0));
      }
    }
  }

  if (!stop && cfg.subnetDiscoveryEnabled && local.ip && local.prefixLength) {
    const t0 = Date.now();
    const disc = await netTests.scanLocalSubnet(
      local,
      cfg.subnetDiscoveryMaxHosts || 32,
      Math.min(timeoutMs, 1200)
    );
    if (!disc.ok) {
      steps.push(step('subnet', 'Discovery subnet', 'warn', disc.error || 'Falha', Date.now() - t0));
    } else {
      const sample = (disc.alive || []).slice(0, 6).map((h) => h.ip).join(', ');
      steps.push(step('subnet', `Discovery ${disc.cidr}`, disc.aliveCount > 0 ? 'pass' : 'warn',
        `${disc.aliveCount}/${disc.scanned} host(s) ativo(s)${sample ? ` · ${sample}` : ''}`,
        Date.now() - t0, disc));
    }
  }

  if (!stop) {
    for (const targetName of (cfg.pingTargets || []).slice(0, 6)) {
      const ip = resolveTarget(targetName, local);
      if (!ip) continue;
      if (targetName === 'gateway' && ip === local.gateway) continue;
      const t0 = Date.now();
      const ping = await pingHostStats(ip, pingCount, timeoutMs);
      const label = targetName === 'gateway' ? 'Ping gateway' : `Ping ${targetName}`;
      steps.push(step(`ping-${targetName}`, label, pingStatusFromStats(ping),
        formatPingStatsDetail(ping, ip),
        Date.now() - t0, { pingStats: ping }));
      if (!ping.ok && cfg.stopOnFail && targetName === 'gateway') stop = true;
    }
  }

  if (!stop) {
    const tcpHost = cfg.tcpTarget === 'custom'
      ? (cfg.customTcpTarget || '').trim()
      : resolveTarget(cfg.tcpTarget || 'gateway', local);
    if (tcpHost) {
      for (const port of (cfg.tcpPorts || []).slice(0, 8)) {
        const t0 = Date.now();
        const conn = await tcpConnect(tcpHost, port, timeoutMs);
        const svc = TCP_NAMES[port] || `TCP/${port}`;
        steps.push(step(`tcp-${port}`, `TCP ${svc} · ${tcpHost}:${port}`, conn.ok ? 'pass' : 'fail',
          conn.ok ? 'porta aberta' : 'porta fechada ou filtrada',
          conn.ok ? conn.ms : (Date.now() - t0)));
        if (!conn.ok && cfg.stopOnFail) { stop = true; break; }
      }
    }
  }

  if (!stop && cfg.httpTestEnabled) {
    const urls = Array.isArray(cfg.httpTestUrls) ? cfg.httpTestUrls : [cfg.httpTestUrls].filter(Boolean);
    for (const url of urls.slice(0, 3)) {
      const t0 = Date.now();
      const httpRes = await netTests.httpGetCheck(url, timeoutMs + 2000);
      const urlPath = url.replace(/^https?:\/\//, '');
      const host = urlPath.split('/')[0];
      steps.push(step(`http-${url}`, `HTTP · ${host}`,
        httpRes.ok ? 'pass' : 'fail',
        httpRes.ok
          ? `${urlPath} · status ${httpRes.statusCode}`
          : (httpRes.error || `HTTP ${httpRes.statusCode || '?'}`),
        httpRes.ms ?? (Date.now() - t0), httpRes));
      if (!httpRes.ok && cfg.stopOnFail) { stop = true; break; }
    }
  }

  if (!stop && cfg.tracerouteTarget) {
    const t0 = Date.now();
    const tr = await runTraceroute(cfg.tracerouteTarget, cfg.tracerouteMaxHops || 12, timeoutMs);
    const hopCount = tr.hops.filter((h) => h.ip).length;
    steps.push(step('traceroute', `Traceroute ${cfg.tracerouteTarget}`, tr.reached ? 'pass' : (hopCount ? 'warn' : 'fail'),
      tr.reached
        ? `${hopCount} salto(s) · destino alcançado`
        : (hopCount ? `${hopCount} salto(s) · destino não confirmado` : (tr.error || 'Falha')),
      Date.now() - t0,
      { hops: tr.hops }));
  }

  const switchIp = (cfg.switchIp || '').trim();
  if (!stop && switchIp) {
    const swStep = await runSwitchDiscovery(switchIp, cfg.switchCommunity, timeoutMs, local.macAddress);
    steps.push(swStep);
  }

  return finalize(steps, started, local, cfg, !options.skipHistory);
}

function buildEngineeringReport(steps, g, durationMs, cfg, ok) {
  const tested = steps.filter((s) => s.status !== 'skip');
  const failed = tested.filter((s) => s.status === 'fail');
  const warned = tested.filter((s) => s.status === 'warn');
  const root = failed[0] || warned[0] || null;
  const verdict = ok ? (g.warn > 0 ? 'APROVADO COM RESSALVAS' : 'APROVADO') : 'REPROVADO';
  const verdictShort = ok ? (g.warn > 0 ? 'RESSALVAS' : 'OK') : 'FALHA';
  const nicLabels = { auto: 'Automática', primary: 'Primária', secondary: 'Secundária', wifi: 'Wi-Fi', custom: 'Específica' };
  const nicMode = cfg.testInterfaceMode || 'auto';
  return {
    verdict,
    verdictShort,
    grade: g.grade,
    pass: g.pass,
    fail: g.fail,
    warn: g.warn,
    skip: steps.filter((s) => s.status === 'skip').length,
    tested: tested.length,
    pct: g.pct,
    durationMs,
    durationSec: (durationMs / 1000).toFixed(1),
    profileName: cfg.profileName || cfg.profileId || '—',
    nicMode,
    nicModeLabel: nicLabels[nicMode] || nicMode,
    rootCause: root
      ? { id: root.id, label: root.label, detail: root.detail, status: root.status }
      : null
  };
}

function finalize(steps, started, local, cfg = {}, saveHistory = false) {
  const g = gradeFromSteps(steps);
  const durationMs = Date.now() - started;
  const ok = g.fail === 0;
  const switchStep = steps.find((s) => s.id === 'switch');
  const connectedPort = switchStep?.connectedPort || null;
  const engineering = buildEngineeringReport(steps, g, durationMs, cfg, ok);
  const result = {
    ok,
    grade: g.grade,
    summary: `${engineering.verdictShort} | Nota ${g.grade} | ${g.pass}P · ${g.warn}W · ${g.fail}F | ${engineering.durationSec}s | ${engineering.profileName}`,
    engineering,
    steps,
    stats: g,
    durationMs,
    local,
    profileId: cfg.profileId || null,
    profileName: cfg.profileName || null,
    connectedPort,
    ranAt: new Date().toISOString()
  };
  if (saveHistory) {
    try { appendHistory(result); } catch { /* ignore */ }
  }
  return result;
}

async function runSwitchDiscovery(switchIp, community, timeoutMs, localMac) {
  const t0 = Date.now();
  const loopCfg = loopDetection.getConfig();
  const comm = (community || loopCfg.community || 'public').trim();
  try {
    const sample = await loopDetection.pollSwitch({
      id: 'autotest_switch',
      ip: switchIp,
      name: switchIp,
      vendor: 'auto'
    }, { community: comm, timeoutMs: timeoutMs || 3500, retries: 1 });

    if (!sample.ok) {
      return step('switch', 'Switch SNMP', 'fail', sample.error || 'SNMP indisponível', Date.now() - t0);
    }

    const connectedPort = localMac ? findMacOnSwitch(sample, localMac) : null;
    const neighbors = [];
    if (sample.neighborsByIf) {
      for (const [ifIndex, list] of sample.neighborsByIf.entries()) {
        const iface = sample.ifaces.find((i) => String(i.ifIndex) === String(ifIndex));
        const portName = iface ? (iface.name || iface.descr) : `if${ifIndex}`;
        for (const n of list) {
          neighbors.push({
            localPort: portName,
            remoteName: n.remoteName,
            remotePort: n.remotePort || '',
            protocol: n.protocol
          });
        }
      }
    }

    const stpPorts = [];
    if (sample.stpByIfIndex) {
      for (const iface of sample.ifaces || []) {
        const st = sample.stpByIfIndex.get(String(iface.ifIndex));
        if (st != null && st !== 5) {
          stpPorts.push({ port: iface.name || iface.descr, stp: st });
        }
      }
    }

    const parts = [`${sample.sysName || switchIp}`, sample.vendor];
    if (connectedPort) {
      parts.push(`porta desta estação: ${connectedPort.portName}`);
      if (connectedPort.stpLabel) parts.push(`STP ${connectedPort.stpLabel}`);
    } else if (localMac) {
      parts.push('MAC local não encontrado na FDB (pode levar alguns segundos para aprender)');
    }
    parts.push(`${neighbors.length} vizinho(s) LLDP/CDP`);
    if (stpPorts.length) parts.push(`${stpPorts.length} porta(s) STP ≠ forwarding`);

    let status = 'pass';
    if (connectedPort && connectedPort.stpState != null && connectedPort.stpState !== 5) status = 'warn';
    else if (!connectedPort && localMac) status = 'warn';
    else if (!neighbors.length && !sample.sysName) status = 'warn';

    return step('switch', 'Switch SNMP · porta + LLDP/CDP', status,
      parts.join(' · '), Date.now() - t0, {
        switchIp,
        sysName: sample.sysName,
        vendor: sample.vendor,
        sysDescr: sample.sysDescr,
        connectedPort,
        neighbors: neighbors.slice(0, 40),
        stpAlerts: stpPorts.slice(0, 15),
        snmpNotes: sample.snmpNotes
      });
  } catch (err) {
    return step('switch', 'Switch SNMP', 'fail', err.message, Date.now() - t0);
  }
}

