function clone(obj) {
  return JSON.parse(JSON.stringify(obj));
}

function pickProfileSettings(src) {
  const out = {};
  for (const key of PROFILE_SETTINGS_KEYS) {
    if (src[key] !== undefined) out[key] = src[key];
  }
  return out;
}

function buildDefaultConfigV2() {
  const profiles = {};
  for (const [id, def] of Object.entries(BUILTIN_PROFILE_DEFAULTS)) {
    profiles[id] = clone(def);
  }
  return {
    version: 2,
    activeProfileId: 'escritorio',
    profiles
  };
}

function migrateConfig(raw) {
  if (raw && raw.version >= 2 && raw.profiles) {
    const base = buildDefaultConfigV2();
    const profiles = { ...base.profiles };
    for (const [id, def] of Object.entries(BUILTIN_PROFILE_DEFAULTS)) {
      if (raw.profiles[id]) {
        profiles[id] = { ...def, ...pickProfileSettings(raw.profiles[id]), id, name: raw.profiles[id].name || def.name };
      }
    }
    if (raw.profiles.custom) {
      profiles.custom = {
        ...BUILTIN_PROFILE_DEFAULTS.custom,
        ...pickProfileSettings(raw.profiles.custom),
        id: 'custom',
        name: raw.profiles.custom.name || 'Personalizado'
      };
    }
    return {
      version: 2,
      activeProfileId: raw.activeProfileId && profiles[raw.activeProfileId] ? raw.activeProfileId : 'escritorio',
      profiles
    };
  }

  const legacy = pickProfileSettings({ ...BUILTIN_PROFILE_DEFAULTS.custom, ...raw });
  const cfg = buildDefaultConfigV2();
  cfg.profiles.custom = { ...cfg.profiles.custom, ...legacy };
  cfg.activeProfileId = raw?.activeProfileId || 'escritorio';
  return cfg;
}

function ensureDataDir() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
}

function writeJsonAtomic(file, data) {
  ensureDataDir();
  const tmp = `${file}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(data, null, 2), 'utf8');
  fs.renameSync(tmp, file);
}

function loadConfig() {
  ensureDataDir();
  if (!fs.existsSync(CONFIG_FILE)) {
    const cfg = buildDefaultConfigV2();
    writeJsonAtomic(CONFIG_FILE, cfg);
    return cfg;
  }
  try {
    const raw = JSON.parse(fs.readFileSync(CONFIG_FILE, 'utf8'));
    const cfg = migrateConfig(raw);
    if (!raw.version || raw.version < 2) writeJsonAtomic(CONFIG_FILE, cfg);
    return cfg;
  } catch {
    return buildDefaultConfigV2();
  }
}

function listProfiles() {
  const cfg = loadConfig();
  return {
