      description: p.description || ''
    }))
  };
}

function getProfile(profileId) {
  const cfg = loadConfig();
  const id = profileId || cfg.activeProfileId || 'escritorio';
  return cfg.profiles[id] || cfg.profiles.escritorio;
}

function saveConfig(partial) {
  const cur = loadConfig();
  const body = partial || {};

  if (body.activeProfileId && cur.profiles[body.activeProfileId]) {
    cur.activeProfileId = body.activeProfileId;
  }

  const profileId = body.profileId || body.activeProfileId || cur.activeProfileId;
  if (profileId && cur.profiles[profileId]) {
    const settings = pickProfileSettings(body);
    cur.profiles[profileId] = {
      ...cur.profiles[profileId],
      ...settings,
      id: profileId,
      name: body.name || cur.profiles[profileId].name
    };
    if (body.description != null) cur.profiles[profileId].description = body.description;
  }

  cur.version = 2;
  writeJsonAtomic(CONFIG_FILE, cur);
  return {
    ...cur,
    activeProfile: cur.profiles[cur.activeProfileId],
    profile: cur.profiles[profileId] || cur.profiles[cur.activeProfileId]
  };
}

function sanitizeNetworkTarget(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  if (/^\d{1,3}(?:\.\d{1,3}){3}$/.test(raw)) return raw;
  if (/^[a-zA-Z0-9][a-zA-Z0-9._-]{0,253}$/.test(raw)) return raw.slice(0, 253);
  return '';
}

function buildProfileSnapshot(profileId) {
  const cfg = resolveRunConfig({ profileId });
  return {
    ...pickProfileSettings(cfg),
    profileId: cfg.profileId || profileId || 'escritorio',
    profileName: cfg.profileName || profileId || 'escritorio'
  };
}

function resolveRunConfig(options = {}) {
  if (options.profileSnapshot && typeof options.profileSnapshot === 'object') {
    const snap = options.profileSnapshot;
    const profileId = snap.profileId || options.profileId || 'escritorio';
    return {
      ...pickProfileSettings(snap),
      ...pickProfileSettings(options),
      profileId,
      profileName: snap.profileName || profileId
    };
  }
  const cfg = loadConfig();
  const profileId = options.profileId || cfg.activeProfileId || 'escritorio';
  const profile = cfg.profiles[profileId] || cfg.profiles.escritorio;
  const merged = { ...pickProfileSettings(profile), ...pickProfileSettings(options), profileId, profileName: profile.name };
  if (options.switchIp != null) merged.switchIp = sanitizeNetworkTarget(options.switchIp);
  if (options.testInterface != null) merged.testInterface = sanitizeNetworkTarget(options.testInterface);
  return merged;
}

function step(id, label, status, detail, ms = null, extra = {}) {
  return {
    id,
    label,
    status,
    detail: detail || '',
    ms: ms != null ? Math.round(ms) : null,
    ...extra
  };
}

function gradeFromSteps(steps) {
  const tested = steps.filter((s) => s.status !== 'skip');
  if (!tested.length) return { grade: '—', pass: 0, fail: 0, warn: 0 };
  const pass = tested.filter((s) => s.status === 'pass').length;
  const fail = tested.filter((s) => s.status === 'fail').length;
  const warn = tested.filter((s) => s.status === 'warn').length;
  const pct = Math.round((pass / tested.length) * 100);
  let grade = 'F';
  if (pct >= 90 && fail === 0) grade = 'A';
  else if (pct >= 75 && fail === 0) grade = 'B';
  else if (pct >= 55) grade = 'C';
  else if (fail === 0 && warn > 0) grade = 'C';
  return { grade, pass, fail, warn, pct };
}

function normalizeMac(mac) {
  if (!mac) return null;
  const hex = String(mac).replace(/[^a-fA-F0-9]/g, '').toLowerCase();
  return hex.length === 12 ? hex : null;
}

function formatLinkSpeed(linkSpeed) {
  if (linkSpeed == null || linkSpeed === '') return null;
  if (typeof linkSpeed === 'number') {
    if (linkSpeed >= 1e9) return `${(linkSpeed / 1e9).toFixed(linkSpeed % 1e9 === 0 ? 0 : 1)} Gbps`;
    if (linkSpeed >= 1e6) return `${Math.round(linkSpeed / 1e6)} Mbps`;
    return `${linkSpeed} bps`;
  }
  const s = String(linkSpeed).trim();
  if (/^\d+$/.test(s)) return formatLinkSpeed(Number(s));
  return s;
}

function findMacOnSwitch(sample, macAddress) {
  const target = normalizeMac(macAddress);
  if (!target || !sample?.macMap) return null;
  for (const [mac, ifIndex] of sample.macMap.entries()) {
    if (normalizeMac(mac) !== target) continue;
    const iface = (sample.ifaces || []).find((i) => String(i.ifIndex) === String(ifIndex));
    const stp = sample.stpByIfIndex?.get(String(ifIndex));
    return {
      ifIndex: String(ifIndex),
      portName: iface ? (iface.name || iface.descr) : `if${ifIndex}`,
      operStatus: iface?.operStatus ?? null,
      stpState: stp ?? null,
      stpLabel: STP_LABELS[stp] || (stp != null ? String(stp) : null),
      mac
    };
  }
  return null;
}

function formatPingStatsDetail(ping, ip) {
  if (!ping.ok) return `${ip} sem resposta (${ping.received}/${ping.sent}, perda ${ping.lossPct}%)`;
  const parts = [`${ip}`, `avg ${ping.avg ?? '?'} ms`];
  if (ping.min != null && ping.max != null) parts.push(`min ${ping.min} / max ${ping.max} ms`);
  parts.push(`perda ${ping.lossPct}% (${ping.received}/${ping.sent})`);
  return parts.join(' · ');
}

function pingStatusFromStats(ping) {
  if (!ping.ok) return 'fail';
  if (ping.lossPct > 0) return 'warn';
  return 'pass';
}

async function pingHostStats(ip, count = 4, timeoutMs = 2500) {
  const n = Math.min(Math.max(Number(count) || 4, 1), 10);
  const t0 = Date.now();
  try {
    const { stdout } = await execAsync(
      `ping -n ${n} -w ${timeoutMs} ${ip}`,
      { timeout: n * timeoutMs + 8000 }
    );
    const pktLine = stdout.match(/(?:Pacotes|Packets)[^\r\n]+/i)?.[0] || '';
    const lossMatch = pktLine.match(/\((\d+)%[^\)]*(?:de perda|loss)/i)
      || stdout.match(/(\d+)\s*%\s*(?:de perda|loss)/i);
    const avgMatch = stdout.match(/(?:M[íi]dia|Média|Average)\s*=?\s*(\d+)\s*ms/i);
    const minMatch = stdout.match(/(?:M[íi]nimo|Mínimo|Minimum)\s*=?\s*(\d+)\s*ms/i);
    const maxMatch = stdout.match(/(?:M[áa]ximo|Máximo|Maximum)\s*=?\s*(\d+)\s*ms/i);
    const sentMatch = pktLine.match(/(?:Enviados|Sent)\s*=\s*(\d+)/i)
      || stdout.match(/(?:Enviados|Sent)\s*=\s*(\d+)/i);
    const recvMatch = pktLine.match(/(?:Recebidos|Received)\s*=\s*(\d+)/i)
      || stdout.match(/(?:Recebidos|Received)\s*=\s*(\d+)/i);
    const received = recvMatch ? Number(recvMatch[1]) : 0;
    const sent = sentMatch ? Number(sentMatch[1]) : n;
    let lossPct = lossMatch ? Number(lossMatch[1]) : (sent ? Math.round(((sent - received) / sent) * 100) : 100);
    if (!Number.isFinite(lossPct)) lossPct = received > 0 ? 0 : 100;
    const ok = received > 0;
    return {
      ok,
      lossPct,
      sent,
      received,
      min: minMatch ? Number(minMatch[1]) : null,
      avg: avgMatch ? Number(avgMatch[1]) : null,
      max: maxMatch ? Number(maxMatch[1]) : null,
      ms: Date.now() - t0
    };
  } catch {
    return {
      ok: false, lossPct: 100, sent: n, received: 0, min: null, avg: null, max: null, ms: Date.now() - t0
    };
  }
}

async function pingHost(ip, timeoutMs) {
