/**
 * Testes de rede avançados para AutoTest (estilo LinkXpert M3 — parte software).
 */
const dns = require('dns');
const http = require('http');
const https = require('https');
const { exec } = require('child_process');
const { promisify } = require('util');
const fs = require('fs');
const os = require('os');
const path = require('path');

const execAsync = promisify(exec);
const dnsResolve4 = promisify(dns.resolve4);

function normalizeMac(mac) {
  if (!mac) return null;
  const hex = String(mac).replace(/[^a-fA-F0-9]/g, '').toLowerCase();
  return hex.length === 12 ? hex : null;
}

async function runPowerShell(script, timeoutMs = 15000) {
  const scriptPath = path.join(os.tmpdir(), `netscan-net-${process.pid}-${Date.now()}.ps1`);
  try {
    fs.writeFileSync(scriptPath, script, 'utf8');
    const { stdout } = await execAsync(
      `powershell -NoProfile -ExecutionPolicy Bypass -File "${scriptPath}"`,
      { timeout: timeoutMs, maxBuffer: 1024 * 1024 }
    );
    const jsonStart = stdout.indexOf('{');
    if (jsonStart < 0) return { ok: false, error: 'Resposta PowerShell vazia' };
    return JSON.parse(stdout.slice(jsonStart));
  } finally {
    try { fs.unlinkSync(scriptPath); } catch { /* ignore */ }
  }
}

async function checkVlanOnInterface(interfaceAlias) {
  const safe = String(interfaceAlias || '').replace(/'/g, "''");
  const script = `$ErrorActionPreference = 'SilentlyContinue'
$alias = '${safe}'
$props = @()
Get-NetAdapterAdvancedProperty -Name $alias -ErrorAction SilentlyContinue | Where-Object {
  $_.DisplayName -match 'VLAN|802\\.1|Virtual LAN|Priority & VLAN'
} | ForEach-Object {
  $props += @{ name = $_.DisplayName; value = [string]$_.DisplayValue }
}
$native = Get-NetAdapter -Name $alias -ErrorAction SilentlyContinue | Select-Object -First 1
$isWifi = $false
if ($native) { $isWifi = $native.MediaType -match '802\\.11|Native802\\.11' }
@{ ok = $true; props = $props; isWifi = [bool]$isWifi; interfaceAlias = $alias } | ConvertTo-Json -Depth 4 -Compress
`;
  try {
    const data = await runPowerShell(script, 12000);
    const vlanProps = (data.props || []).filter((p) => /vlan/i.test(p.name));
    const vlanId = vlanProps.find((p) => /vlan\s*id/i.test(p.name) && p.value && p.value !== '0');
    return {
      ok: true,
      interfaceAlias,
      vlanId: vlanId?.value || null,
      props: data.props || [],
      isWifi: Boolean(data.isWifi),
      untagged: !vlanId
    };
  } catch (err) {
    return { ok: false, error: err.message };
  }
}

async function checkDuplicateIp(local) {
  const ip = local?.ip;
  const localMac = normalizeMac(local?.macAddress);
  if (!ip) return { ok: false, error: 'IP local indisponível' };
  try {
    await execAsync(`ping -n 1 -w 800 ${ip}`, { timeout: 3000 });
    const { stdout } = await execAsync('arp -a', { timeout: 5000 });
    const line = stdout.split('\n').find((l) => l.includes(ip));
    const macMatch = line?.match(/([0-9a-fA-F]{2}(?:-[0-9a-fA-F]{2}){5})/);
    const arpMac = macMatch ? normalizeMac(macMatch[1]) : null;
    if (!arpMac) {
      return { ok: true, duplicate: false, detail: 'Sem entrada ARP — provável IP único', ip, localMac };
    }
    if (!localMac) {
      return { ok: true, duplicate: false, detail: `ARP ${macMatch[1]} — MAC local não comparado`, ip, arpMac: macMatch[1] };
    }
    const duplicate = arpMac !== localMac;
    return {
      ok: !duplicate,
      duplicate,
      ip,
      arpMac: macMatch[1],
      localMac: local.macAddress,
      detail: duplicate
        ? `Conflito: ARP ${macMatch[1]} ≠ NIC ${local.macAddress}`
        : `MAC ARP coincide com esta estação (${local.macAddress})`
    };
  } catch (err) {
    return { ok: true, duplicate: false, detail: `Verificação ARP inconclusiva: ${err.message}` };
  }
}

function ipToInt(ip) {
  return ip.split('.').reduce((acc, oct) => (acc << 8) + Number(oct), 0) >>> 0;
}

function intToIp(n) {
  return [24, 16, 8, 0].map((s) => (n >>> s) & 255).join('.');
}

function getSubnetScanList(ip, prefixLength, maxHosts) {
  const pl = Number(prefixLength) || 24;
  const max = Math.min(Math.max(Number(maxHosts) || 32, 4), 64);
  const ipInt = ipToInt(ip);
  const mask = pl >= 32 ? 0xFFFFFFFF : ((~0 << (32 - pl)) >>> 0);
  const network = (ipInt & mask) >>> 0;
  const broadcast = (network | (~mask >>> 0)) >>> 0;
  const hosts = [];
  for (let h = network + 1; h < broadcast; h++) {
    hosts.push(intToIp(h));
  }
  hosts.sort((a, b) => Math.abs(ipToInt(a) - ipInt) - Math.abs(ipToInt(b) - ipInt));
  return { cidr: `${intToIp(network)}/${pl}`, hosts: hosts.slice(0, max) };
}

async function pingOnce(ip, timeoutMs) {
  try {
    const { stdout } = await execAsync(`ping -n 1 -w ${Math.min(timeoutMs, 1200)} ${ip}`, { timeout: timeoutMs + 2000 });
    const ok = /TTL=|0%\s*(de perda|loss)|resposta de|reply from/i.test(stdout);
    const timeMatch = stdout.match(/(?:tempo=|time[<=])(\d+)\s*ms/i);
    return { ok, ms: timeMatch ? Number(timeMatch[1]) : null };
  } catch {
    return { ok: false, ms: null };
  }
}

async function scanLocalSubnet(local, maxHosts, timeoutMs) {
  const pl = local.prefixLength || 24;
  if (pl < 16) {
    return { ok: false, error: 'Sub-rede muito grande — discovery limitado a /16 ou menor' };
  }
  const { cidr, hosts } = getSubnetScanList(local.ip, pl, maxHosts);
  const batchSize = 12;
  const alive = [];
  for (let i = 0; i < hosts.length; i += batchSize) {
    const batch = hosts.slice(i, i + batchSize);
    const results = await Promise.all(batch.map(async (ip) => {
      const p = await pingOnce(ip, timeoutMs);
      return p.ok ? { ip, ms: p.ms } : null;
    }));
    for (const r of results) if (r) alive.push(r);
  }
  alive.sort((a, b) => (a.ms ?? 9999) - (b.ms ?? 9999));
  return {
    ok: true,
    cidr,
    scanned: hosts.length,
    aliveCount: alive.length,
    alive: alive.slice(0, 25)
  };
}

function resolveViaDnsServer(serverIp, host) {
  return new Promise((resolve, reject) => {
    const resolver = new dns.Resolver();
    resolver.setServers([serverIp]);
    resolver.resolve4(host, (err, addresses) => {
      if (err) reject(err);
      else resolve(addresses);
    });
  });
}

function httpGetCheck(url, timeoutMs) {
  return new Promise((resolve) => {
    let lib;
    let target = url;
    try {
      lib = target.startsWith('https') ? https : http;
      if (!/^https?:\/\//i.test(target)) target = `http://${target}`;
    } catch {
      resolve({ ok: false, error: 'URL inválida' });
      return;
    }
    const t0 = Date.now();
    const req = lib.get(target, { timeout: timeoutMs, rejectUnauthorized: false }, (res) => {
      const ok = res.statusCode >= 200 && res.statusCode < 400;
      res.resume();
      resolve({ ok, statusCode: res.statusCode, ms: Date.now() - t0, url: target });
    });
    req.on('error', (err) => resolve({ ok: false, error: err.message, ms: Date.now() - t0, url: target }));
    req.on('timeout', () => {
      req.destroy();
      resolve({ ok: false, error: 'timeout', ms: Date.now() - t0, url: target });
    });
  });
}

async function hasWifiAdapter() {
  try {
    const { stdout } = await execAsync('netsh wlan show interfaces', { timeout: 8000, maxBuffer: 256 * 1024 });
    const blob = stdout.toLowerCase();
    if (/there is no wireless interface|não há interface wireless|no wireless interface/i.test(blob)) {
      return false;
    }
    return /^\s*name\s*:/im.test(stdout) || /^\s*nome\s*:/im.test(stdout);
  } catch {
    return false;
  }
}

async function scanWifiNetworks() {
  const hasWifi = await hasWifiAdapter();
  if (!hasWifi) {
    return {
      ok: false,
      skip: true,
      error: 'Adaptador Wi-Fi não encontrado ou desligado — teste ignorado.',
      networks: []
    };
  }
  try {
    const { stdout } = await execAsync('netsh wlan show networks mode=bssid', { timeout: 15000, maxBuffer: 512 * 1024 });
    const networks = [];
    let current = null;
    for (const line of stdout.split('\n')) {
      const ssidMatch = line.match(/^\s*SSID\s*\d+\s*:\s*(.+)$/i);
      if (ssidMatch) {
        if (current?.ssid) networks.push(current);
        current = { ssid: ssidMatch[1].trim(), signal: null, channel: null, auth: null, bssid: null };
        continue;
      }
      if (!current) continue;
      const sig = line.match(/^\s*Signal\s*:\s*(\d+)%/i);
      if (sig) current.signal = Number(sig[1]);
      const ch = line.match(/^\s*Channel\s*:\s*(\d+)/i);
      if (ch) current.channel = Number(ch[1]);
      const auth = line.match(/^\s*Authentication\s*:\s*(.+)$/i);
      if (auth) current.auth = auth[1].trim();
      const bssid = line.match(/^\s*BSSID\s*\d+\s*:\s*([0-9a-f:]+)/i);
      if (bssid) current.bssid = bssid[1].trim();
    }
    if (current?.ssid) networks.push(current);
    const dedup = new Map();
    for (const n of networks) {
      const key = n.ssid;
      const prev = dedup.get(key);
      if (!prev || (n.signal || 0) > (prev.signal || 0)) dedup.set(key, n);
    }
    const list = Array.from(dedup.values()).sort((a, b) => (b.signal || 0) - (a.signal || 0));
    if (!list.length) {
      return {
        ok: false,
        error: 'Nenhuma rede Wi-Fi visível (rádio ativo, mas sem SSIDs no alcance).',
        networks: []
      };
    }
    return { ok: true, count: list.length, networks: list.slice(0, 15) };
  } catch (err) {
    const msg = err?.message || '';
    if (/not supported|não suportado|wireless/i.test(msg)) {
      return { ok: false, skip: true, error: 'Wi-Fi não suportado nesta estação.', networks: [] };
    }
    return { ok: false, error: 'Falha ao listar redes Wi-Fi (netsh). Verifique se o serviço WLAN está ativo.', networks: [] };
  }
}

module.exports = {
  checkVlanOnInterface,
  checkDuplicateIp,
  scanLocalSubnet,
  resolveViaDnsServer,
  httpGetCheck,
  scanWifiNetworks,
  dnsResolve4
};

/**
 * Relatório PDF AutoTest — layout limpo, sem sobreposição
 */
const PDFDocument = require('pdfkit');
const { C, REPORT_VERSION, REPORT_SITE, REPORT_YEAR, fmtDatePt, formatDetailText } = require('./canonReportTheme');

const M = 48;
const PAGE_W = 595;
const CONTENT_W = PAGE_W - M * 2;
const BOTTOM = 750;

const STATUS_LABEL = { pass: 'OK', fail: 'FALHA', warn: 'AVISO', skip: 'PULADO' };
const STATUS_COLOR = { pass: C.pass, fail: C.fail, warn: C.warn, skip: C.skip };

function ensurePage(doc, y, needed) {
  if (y + needed > BOTTOM) {
    doc.addPage();
    return M;
  }
  return y;
}

function drawTopBar(doc, subtitle) {
  doc.save();
  doc.rect(0, 0, PAGE_W, 36).fill(C.brand);
  doc.fillColor(C.white).font('Helvetica-Bold').fontSize(11).text('NetScan Canon', M, 12);
  doc.font('Helvetica').fontSize(8).fillColor('#bae6fd').text(subtitle || 'AutoTest', M, 24);
  doc.fontSize(7).text(`v${REPORT_VERSION}`, M, 12, { width: CONTENT_W, align: 'right' });
  doc.restore();
  return 48;
}

function drawMetaRow(doc, y, label, value) {
  doc.font('Helvetica-Bold').fontSize(8).fillColor(C.muted).text(label, M, y, { width: 110 });
  doc.font('Helvetica').fontSize(8).fillColor(C.body).text(String(value ?? '—'), M + 112, y, { width: CONTENT_W - 112 });
  return y + 14;
}

function drawSection(doc, y, title) {
  y = ensurePage(doc, y, 28);
  doc.font('Helvetica-Bold').fontSize(11).fillColor(C.brand).text(title, M, y);
  y += 14;
  doc.moveTo(M, y).lineTo(M + CONTENT_W, y).strokeColor(C.accent).lineWidth(1).stroke();
  return y + 10;
}

function drawVerdictBox(doc, y, verdict, grade, pct, ok) {
  y = ensurePage(doc, y, 56);
  const bg = ok ? C.pass : (String(verdict).includes('RESSALV') ? C.warn : C.fail);
  doc.roundedRect(M, y, CONTENT_W, 50, 4).fill(bg);
  doc.fillColor(C.white).font('Helvetica-Bold').fontSize(10)
    .text('RESULTADO FINAL', M, y + 8, { width: CONTENT_W, align: 'center' });
  doc.fontSize(16).text(String(verdict).toUpperCase(), M, y + 22, { width: CONTENT_W, align: 'center' });
  doc.fontSize(9).font('Helvetica')
    .text(`Nota ${grade}  ·  ${pct != null ? pct + '% sucesso' : '—'}`, M, y + 40, { width: CONTENT_W, align: 'center' });
  return y + 58;
}

function stepRowHeight(doc, s, colLabel, colDetail) {
  const label = `${s.label || '—'}${s.ms != null ? ` (${s.ms} ms)` : ''}`;
  const detail = formatDetailText(s.detail);
  doc.font('Helvetica-Bold').fontSize(8);
  const h1 = doc.heightOfString(label, { width: colLabel });
  doc.font('Helvetica').fontSize(8);
  const h2 = doc.heightOfString(detail, { width: colDetail });
  return Math.max(h1, h2, 12) + 10;
}

function drawStepsTable(doc, y, steps) {
  const colStatus = 52;
  const colLabel = 175;
  const colDetail = CONTENT_W - colStatus - colLabel;

  y = drawSection(doc, y, 'Resultados dos testes');

  y = ensurePage(doc, y, 24);
  doc.font('Helvetica-Bold').fontSize(8).fillColor(C.muted);
  doc.text('Status', M, y, { width: colStatus });
  doc.text('Teste', M + colStatus, y, { width: colLabel });
  doc.text('Detalhe', M + colStatus + colLabel, y, { width: colDetail });
  y += 12;
  doc.moveTo(M, y).lineTo(M + CONTENT_W, y).strokeColor(C.border).stroke();
  y += 6;

  for (const s of steps) {
    const rowH = stepRowHeight(doc, s, colLabel, colDetail);
    y = ensurePage(doc, y, rowH);

    const label = `${s.label || '—'}${s.ms != null ? ` (${s.ms} ms)` : ''}`;
    const detail = formatDetailText(s.detail);
    const stColor = STATUS_COLOR[s.status] || C.body;

    doc.font('Helvetica-Bold').fontSize(8).fillColor(stColor)
      .text(STATUS_LABEL[s.status] || s.status || '—', M, y, { width: colStatus });
    doc.fillColor(C.title).text(label, M + colStatus, y, { width: colLabel });
    doc.font('Helvetica').fillColor(C.body).text(detail, M + colStatus + colLabel, y, { width: colDetail });

    y += rowH;
  }
  return y + 8;
}

function stampFooters(doc, title) {
  const range = doc.bufferedPageRange();
  for (let i = range.start; i < range.start + range.count; i++) {
    doc.switchToPage(i);
    doc.moveTo(M, 780).lineTo(M + CONTENT_W, 780).strokeColor(C.border).stroke();
    doc.font('Helvetica').fontSize(7).fillColor(C.muted)
      .text('Relatório gerado automaticamente pelo NetScan Canon Professional', M, 786, { width: CONTENT_W, align: 'center' })
      .text(`Versão ${REPORT_VERSION} · ${REPORT_SITE} · © ${REPORT_YEAR} · ${title}`, M, 796, { width: CONTENT_W, align: 'center' });
  }
}

function generateAutoTestPdf(result) {
  return new Promise((resolve, reject) => {
    const doc = new PDFDocument({ margin: 0, size: 'A4', bufferPages: true });
    const chunks = [];
    doc.on('data', (c) => chunks.push(c));
    doc.on('end', () => resolve(Buffer.concat(chunks)));
    doc.on('error', reject);

    const steps = result.steps || [];
    const eng = result.engineering || {};
    const local = result.local || {};
    const profileName = result.profileName || eng.profileName || 'AutoTest';
    const grade = result.grade || eng.grade || '—';
    const ok = result.ok;
    const verdict = eng.verdict || (ok ? 'APROVADO' : 'COM FALHAS');
    const pct = eng.pct != null ? eng.pct : null;

    let y = drawTopBar(doc, `AutoTest · ${profileName}`);

    doc.font('Helvetica-Bold').fontSize(14).fillColor(C.title)
      .text('Relatório AutoTest', M, y, { width: CONTENT_W, align: 'center' });
    y += 22;

    y = drawMetaRow(doc, y, 'Data/Hora', fmtDatePt(result.ranAt));
    y = drawMetaRow(doc, y, 'Perfil', profileName);
    y = drawMetaRow(doc, y, 'Nota / Veredito', `${grade} · ${verdict}`);
    if (result.summary) y = drawMetaRow(doc, y, 'Resumo', result.summary);
    y += 6;

    y = drawVerdictBox(doc, y, verdict, grade, pct, ok);

    if (eng.pass != null || eng.fail != null) {
      y = drawMetaRow(doc, y, 'Contagem', `OK ${eng.pass ?? 0}  ·  Avisos ${eng.warn ?? 0}  ·  Falhas ${eng.fail ?? 0}  ·  Pulados ${eng.skip ?? 0}`);
    }
    if (eng.rootCause) {
      y = drawMetaRow(doc, y, 'Causa provável', `${eng.rootCause.label || '—'}: ${eng.rootCause.detail || '—'}`);
    }
    y += 4;

    if (local.ok) {
      y = drawSection(doc, y, 'Interface principal');
      const linkStep = steps.find((s) => s.id === 'link');
      y = drawMetaRow(doc, y, 'Adaptador', local.interfaceAlias);
      y = drawMetaRow(doc, y, 'IP', local.ip ? `${local.ip}/${local.prefixLength ?? '—'}` : '—');
      y = drawMetaRow(doc, y, 'Gateway', local.gateway);
      y = drawMetaRow(doc, y, 'DHCP', local.dhcp ? 'Sim' : 'Não');
      y = drawMetaRow(doc, y, 'DNS', (local.dnsServers || []).join(', ') || '—');
      if (local.macAddress || local.mac) y = drawMetaRow(doc, y, 'MAC', local.macAddress || local.mac);
      if (linkStep?.detail) y = drawMetaRow(doc, y, 'Link', linkStep.detail);
      if (result.connectedPort?.portName) {
        y = drawMetaRow(doc, y, 'Porta no switch', result.connectedPort.portName);
        if (result.connectedPort.stpLabel) y = drawMetaRow(doc, y, 'STP', result.connectedPort.stpLabel);
      }
      y += 4;
    }

    y = drawStepsTable(doc, y, steps);

    const swStep = steps.find((s) => s.id === 'switch' && s.neighbors?.length);
    if (swStep) {
      doc.addPage();
      y = drawTopBar(doc, 'Vizinhos LLDP / CDP');
      y = drawSection(doc, y, 'Vizinhos LLDP / CDP');
      for (const n of swStep.neighbors) {
        y = ensurePage(doc, y, 14);
        doc.font('Helvetica').fontSize(8).fillColor(C.body)
          .text(`${n.localPort || '—'} · ${n.protocol || '—'} → ${n.remoteName || '—'} (${n.remotePort || '—'})`, M, y, { width: CONTENT_W });
        y += 14;
      }
    }

    stampFooters(doc, 'AutoTest');
    doc.end();
  });
}

module.exports = { generateAutoTestPdf };

/**
 * Export CSV do relatório AutoTest — UTF-16 LE (Excel Windows)
 */
const {
  fmtDatePt, formatDetailText, stepLayer, stepDisplayLabel,
  groupStepsByLayer, layerTitle, statusInfo, REPORT_VERSION
} = require('./canonReportTheme');

function sanitizeCell(val) {
  return formatDetailText(val)
    .replace(/\r\n/g, ' | ')
    .replace(/[\r\n]+/g, ' | ')
    .replace(/\s+/g, ' ')
    .trim();
}

function csvCell(val) {
  const s = sanitizeCell(val);
  return `"${s.replace(/"/g, '""')}"`;
}

function csvRow(cells) {
  return cells.map(csvCell).join(';');
}

function toUtf16LeBuffer(text) {
  const buf = Buffer.alloc(2 + text.length * 2);
  buf[0] = 0xFF;
  buf[1] = 0xFE;
  for (let i = 0; i < text.length; i++) {
    buf.writeUInt16LE(text.charCodeAt(i), 2 + i * 2);
  }
  return buf;
}

function generateAutoTestCsv(result) {
  const eng = result.engineering || {};
  const local = result.local || {};
  const steps = result.steps || [];
  const lines = ['sep=;'];

  lines.push(csvRow(['NetScan Canon — Relatório AutoTest v' + REPORT_VERSION]));
  lines.push(csvRow(['Campo', 'Valor']));
  lines.push(csvRow(['Executado em', fmtDatePt(result.ranAt)]));
  lines.push(csvRow(['Perfil', result.profileName || result.profileId || '']));
  lines.push(csvRow(['Nota', result.grade || eng.grade || '']));
  lines.push(csvRow(['Veredito', eng.verdict || (result.ok ? 'APROVADO' : 'REPROVADO')]));
  lines.push(csvRow(['Resumo', result.summary || '']));
  lines.push(csvRow(['Duração (s)', eng.durationSec || (result.durationMs ? (result.durationMs / 1000).toFixed(1) : '')]));
  lines.push(csvRow(['Testes OK', eng.pass ?? '']));
  lines.push(csvRow(['Testes AVISO', eng.warn ?? '']));
  lines.push(csvRow(['Testes FALHA', eng.fail ?? '']));
  lines.push(csvRow(['Taxa sucesso (%)', eng.pct ?? '']));

  if (local.ok) {
    lines.push(csvRow(['Adaptador', local.interfaceAlias || '']));
    lines.push(csvRow(['IP', local.ip || '']));
    lines.push(csvRow(['Gateway', local.gateway || '']));
    lines.push(csvRow(['DNS', (local.dnsServers || []).join(', ')]));
  }

  const groups = groupStepsByLayer(steps);
  for (const layer of ['L2', 'L3', 'L4']) {
    if (!groups[layer].length) continue;
    lines.push('');
    lines.push(csvRow([layerTitle(layer)]));
    lines.push(csvRow(['Seq', 'Status', 'Camada', 'Teste', 'Detalhe', 'Duração (ms)', 'ID']));
    groups[layer].forEach((s, idx) => {
      const st = statusInfo(s.status);
      lines.push(csvRow([
        idx + 1,
        st.label,
        layer,
        stepDisplayLabel(s),
        s.detail || '',
        s.ms != null ? s.ms : '',
        s.id || ''
      ]));
    });
  }

  return toUtf16LeBuffer(`${lines.join('\r\n')}\r\n`);
}

module.exports = { generateAutoTestCsv };

/**
 * Export Excel (.xlsx) profissional do relatório AutoTest.
 */
const ExcelJS = require('exceljs');

const STATUS_LABEL = {
  pass: 'OK',
  fail: 'FALHA',
  warn: 'AVISO',
  skip: 'PULADO'
};

const STATUS_COLORS = {
  pass: 'FF16A34A',
  fail: 'FFDC2626',
  warn: 'FFD97706',
  skip: 'FF94A3B8'
};

const L2_IDS = new Set(['local', 'link', 'vlan', 'duplicate-ip', 'dhcp', 'switch', 'wifi-scan']);
const L3_IDS = new Set(['gateway', 'subnet', 'traceroute']);
const L4_PREFIX = ['tcp-', 'http-'];

const COL_WIDTHS = {
  seq: 8,
  status: 12,
  layer: 10,
  test: 36,
  detail: 110,
  ms: 14,
  id: 20
};

function fmtDate(iso) {
  if (!iso) return '—';
  try {
    return new Date(iso).toLocaleString('pt-BR');
  } catch {
    return iso;
  }
}

function formatDetailText(detail) {
  const s = String(detail ?? '').trim();
  if (!s) return '—';
  if (s.length > 48 && s.includes(',')) {
    return s.replace(/,\s*/g, ',\n');
  }
  return s;
}

function estimateWrappedLines(text, colWidth) {
  const s = String(text ?? '');
  if (!s) return 1;
  const charsPerLine = Math.max(14, Math.floor(colWidth * 1.05));
  const parts = s.split(/\r?\n/);
  let lines = 0;
  for (const part of parts) {
    lines += Math.max(1, Math.ceil(part.length / charsPerLine));
  }
  return lines;
}

function rowHeightForText(text, colWidth, min = 22) {
  const lines = estimateWrappedLines(text, colWidth);
  return Math.min(409, Math.max(min, lines * 15 + 8));
}

function mergedMetaWidth() {
  return COL_WIDTHS.status + COL_WIDTHS.layer + COL_WIDTHS.test
    + COL_WIDTHS.detail + COL_WIDTHS.ms + COL_WIDTHS.id;
}

function stepLayer(step) {
  const id = String(step?.id || '');
  if (L2_IDS.has(id)) return 'L2';
  if (L3_IDS.has(id)) return 'L3';
  if (L4_PREFIX.some((p) => id.startsWith(p))) return 'L4';
  if (id.startsWith('dns') || id.startsWith('ping-')) return 'L3';
  return '—';
}

function styleTitleBand(cell, text) {
  cell.value = text;
  cell.font = { bold: true, size: 14, color: { argb: 'FFF8FAFC' } };
  cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF0C4A6E' } };
  cell.alignment = { vertical: 'middle', horizontal: 'left', indent: 1, wrapText: true };
}

function styleSectionTitle(cell, text) {
  cell.value = text;
  cell.font = { bold: true, size: 11, color: { argb: 'FF0C4A6E' } };
  cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE0F2FE' } };
  cell.alignment = { vertical: 'middle', horizontal: 'left', indent: 1 };
}

function styleTableHeader(cell) {
  cell.font = { bold: true, color: { argb: 'FFFFFFFF' }, size: 10 };
  cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF0E7490' } };
  cell.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true };
  cell.border = { bottom: { style: 'thin', color: { argb: 'FF067A8A' } } };
}

function styleMetaLabel(cell) {
  cell.font = { bold: true, size: 10, color: { argb: 'FF475569' } };
  cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFF8FAFC' } };
  cell.alignment = { vertical: 'top', horizontal: 'left', indent: 1, wrapText: true };
}

function styleMetaValue(cell) {
  cell.font = { size: 10, color: { argb: 'FF0F172A' } };
  cell.alignment = { vertical: 'top', horizontal: 'left', wrapText: true, indent: 1 };
}

function addMetaRow(ws, rowNum, label, value) {
  ws.mergeCells(rowNum, 2, rowNum, 7);
  const labelCell = ws.getCell(rowNum, 1);
  const valueCell = ws.getCell(rowNum, 2);
  const display = formatDetailText(value);
  labelCell.value = label;
  valueCell.value = display;
  styleMetaLabel(labelCell);
  styleMetaValue(valueCell);
  ws.getRow(rowNum).height = rowHeightForText(display, mergedMetaWidth(), 22);
}

async function generateAutoTestXlsx(result) {
  const eng = result.engineering || {};
  const local = result.local || {};
  const steps = result.steps || [];

  const workbook = new ExcelJS.Workbook();
  workbook.creator = 'NetScan Canon';
  workbook.created = new Date();

  const ws = workbook.addWorksheet('AutoTest', {
    views: [{ state: 'frozen', ySplit: 1 }],
    properties: { defaultRowHeight: 18 }
  });

  ws.columns = [
    { key: 'a', width: COL_WIDTHS.seq },
    { key: 'b', width: COL_WIDTHS.status },
    { key: 'c', width: COL_WIDTHS.layer },
    { key: 'd', width: COL_WIDTHS.test },
    { key: 'e', width: COL_WIDTHS.detail },
    { key: 'f', width: COL_WIDTHS.ms },
    { key: 'g', width: COL_WIDTHS.id }
  ];

  ws.mergeCells(1, 1, 1, 7);
  styleTitleBand(ws.getCell(1, 1), `NetScan Canon — Relatório AutoTest · ${fmtDate(result.ranAt)}`);
  ws.getRow(1).height = 30;

  let r = 3;
  ws.mergeCells(r, 1, r, 7);
  styleSectionTitle(ws.getCell(r, 1), 'Resumo do teste');
  ws.getRow(r).height = 22;
  r += 1;

  const meta = [
    ['Perfil', result.profileName || result.profileId || '—'],
    ['Nota', result.grade || eng.grade || '—'],
    ['Veredito', eng.verdict || (result.ok ? 'APROVADO' : 'COM FALHAS')],
    ['Resumo', result.summary || '—'],
    ['Duração (s)', eng.durationSec || (result.durationMs ? (result.durationMs / 1000).toFixed(1) : '—')],
    ['Placa de rede', eng.nicModeLabel || '—'],
    ['Testes OK', eng.pass ?? '—'],
    ['Testes AVISO', eng.warn ?? '—'],
    ['Testes FALHA', eng.fail ?? '—'],
    ['Testes pulados', eng.skip ?? '—'],
    ['Taxa de sucesso (%)', eng.pct != null ? `${eng.pct}%` : '—']
  ];

  if (eng.rootCause) {
    meta.push(['Causa provável', `${eng.rootCause.label || '—'}: ${eng.rootCause.detail || '—'}`]);
  }

  for (const [label, value] of meta) {
    addMetaRow(ws, r, label, value);
    r += 1;
  }

  if (local.ok) {
    r += 1;
    ws.mergeCells(r, 1, r, 7);
    styleSectionTitle(ws.getCell(r, 1), 'Interface principal');
    ws.getRow(r).height = 22;
    r += 1;

    const iface = [
      ['Adaptador', local.interfaceAlias],
      ['Endereço IP', local.ip ? `${local.ip}/${local.prefixLength ?? '—'}` : '—'],
      ['Gateway', local.gateway],
      ['DHCP', local.dhcp ? 'Sim' : 'Não'],
      ['DNS', (local.dnsServers || []).join(', ') || '—'],
      ['MAC', local.macAddress || local.mac]
    ];
    if (result.connectedPort?.portName) {
      iface.push(['Porta no switch', result.connectedPort.portName]);
      iface.push(['STP', result.connectedPort.stpLabel || '—']);
    }
    for (const [label, value] of iface) {
      addMetaRow(ws, r, label, value);
      r += 1;
    }
  }

  r += 1;
  ws.mergeCells(r, 1, r, 7);
  styleSectionTitle(ws.getCell(r, 1), 'Resultados dos testes');
  ws.getRow(r).height = 22;
  r += 1;

  const stepHeaders = ['Seq', 'Status', 'Camada', 'Teste', 'Detalhe', 'Duração (ms)', 'ID interno'];
  const headerRow = ws.getRow(r);
  stepHeaders.forEach((h, i) => {
    const cell = headerRow.getCell(i + 1);
    cell.value = h;
    styleTableHeader(cell);
  });
  headerRow.height = 24;
  const tableStart = r;
  r += 1;

  steps.forEach((s, idx) => {
    const detailText = formatDetailText(s.detail);
    const labelText = s.label || '—';
    const row = ws.getRow(r);

    row.getCell(1).value = idx + 1;
    row.getCell(2).value = STATUS_LABEL[s.status] || s.status || '—';
    row.getCell(3).value = stepLayer(s);
    row.getCell(4).value = labelText;
    row.getCell(5).value = detailText;
    row.getCell(6).value = s.ms != null ? s.ms : '';
    row.getCell(7).value = s.id || '—';

    const statusColor = STATUS_COLORS[s.status] || 'FF0F172A';
    row.getCell(2).font = { bold: true, color: { argb: statusColor } };
    row.getCell(5).alignment = { vertical: 'top', horizontal: 'left', wrapText: true, indent: 1 };
    row.getCell(4).alignment = { vertical: 'top', horizontal: 'left', wrapText: true, indent: 1 };
    row.alignment = { vertical: 'top', wrapText: true };

    row.eachCell((cell) => {
      cell.border = {
        top: { style: 'hair', color: { argb: 'FFE2E8F0' } },
        bottom: { style: 'hair', color: { argb: 'FFE2E8F0' } }
      };
    });

    if (idx % 2 === 0) {
      row.eachCell((cell) => {
        cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFF0FDFA' } };
      });
    }

    const hDetail = rowHeightForText(detailText, COL_WIDTHS.detail);
    const hLabel = rowHeightForText(labelText, COL_WIDTHS.test);
    row.height = Math.max(hDetail, hLabel, 22);
    r += 1;
  });

  ws.autoFilter = {
    from: { row: tableStart, column: 1 },
    to: { row: tableStart, column: 7 }
  };

  const swStep = steps.find((s) => s.id === 'switch' && s.neighbors?.length);
  if (swStep) {
    r += 1;
    ws.mergeCells(r, 1, r, 5);
    styleSectionTitle(ws.getCell(r, 1), 'Vizinhos LLDP / CDP');
    ws.getRow(r).height = 22;
    r += 1;

    const neiHeaders = ['Seq', 'Porta local', 'Protocolo', 'Equipamento remoto', 'Porta remota'];
    const neiHeaderRow = ws.getRow(r);
    neiHeaders.forEach((h, i) => {
      const cell = neiHeaderRow.getCell(i + 1);
      cell.value = h;
      styleTableHeader(cell);
    });
    neiHeaderRow.height = 24;
    r += 1;

    swStep.neighbors.forEach((n, idx) => {
      const remote = n.remoteName || '—';
      const row = ws.getRow(r);
      row.getCell(1).value = idx + 1;
      row.getCell(2).value = n.localPort || '—';
      row.getCell(3).value = n.protocol || '—';
      row.getCell(4).value = remote;
      row.getCell(5).value = n.remotePort || '—';
      row.alignment = { vertical: 'top', wrapText: true };
      row.getCell(4).alignment = { vertical: 'top', horizontal: 'left', wrapText: true, indent: 1 };
      row.height = rowHeightForText(remote, COL_WIDTHS.test, 22);
      if (idx % 2 === 0) {
        row.eachCell({ includeEmpty: true }, (cell, col) => {
          if (col <= 5) {
            cell.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFF0FDFA' } };
          }
        });
      }
      r += 1;
    });
  }

  return workbook.xlsx.writeBuffer();
}

module.exports = { generateAutoTestXlsx };

/**
 * AutoTest remoto — fila de jobs + registro de agentes nas estações de campo.
 * Segurança estilo Veyon: chave por agente + jobs assinados pelo servidor.
 */
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const os = require('os');
const remoteSec = require('./autoTestRemoteSecurity');
const autoTest = require('./autoTest');

const DATA_DIR = path.join(__dirname, 'data');
const STORE_FILE = path.join(DATA_DIR, 'autotest-remote.json');

const ONLINE_MS = 90 * 1000;
const JOB_PENDING_TIMEOUT_MS = Number(process.env.AUTOTEST_REMOTE_PENDING_MS) || 10 * 60 * 1000;
const JOB_CLAIMED_TIMEOUT_MS = Number(process.env.AUTOTEST_REMOTE_CLAIMED_MS) || 15 * 60 * 1000;
const MAX_RESULT_BYTES = 2 * 1024 * 1024;
const MAX_JOBS = 200;
const LEGACY_TOKEN_ENABLED = process.env.AUTOTEST_REMOTE_LEGACY !== '0';

function ensureStore() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
}

function defaultStore() {
  return {
    version: 2,
    securityMode: 'veyon',
    agentToken: crypto.randomBytes(24).toString('hex'),
    agents: {},
    jobs: []
  };
}

function loadStore() {
  ensureStore();
  if (!fs.existsSync(STORE_FILE)) {
    const s = defaultStore();
    saveStore(s);
    return s;
  }
  try {
    const raw = JSON.parse(fs.readFileSync(STORE_FILE, 'utf8'));
    return {
      ...defaultStore(),
      ...raw,
      agentToken: raw.agentToken || crypto.randomBytes(24).toString('hex'),
      agents: raw.agents && typeof raw.agents === 'object' ? raw.agents : {},
      jobs: Array.isArray(raw.jobs) ? raw.jobs : []
    };
  } catch {
    const s = defaultStore();
    saveStore(s);
    return s;
  }
}

function saveStore(store) {
  ensureStore();
  const tmp = `${STORE_FILE}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(store, null, 2), 'utf8');
  fs.renameSync(tmp, STORE_FILE);
}

function getAgent(agentId) {
  const store = loadStore();
  return store.agents[normalizeAgentId(agentId)] || null;
}

function verifyAgentToken(token) {
  if (!LEGACY_TOKEN_ENABLED) return false;
  const store = loadStore();
  return token && token === store.agentToken;
}

function normalizeAgentId(hostname) {
  return String(hostname || '').trim().toLowerCase().replace(/[^a-z0-9._-]+/g, '-').slice(0, 64);
}

function sanitizeAgent(agent, online) {
  return {
    agentId: agent.agentId,
    hostname: agent.hostname,
    ip: agent.ip,
    user: agent.user,
    agentVersion: agent.agentVersion,
    securityMode: agent.publicKey ? 'veyon' : 'legacy',
    firstSeen: agent.firstSeen,
    lastSeen: agent.lastSeen,
    lastJobAt: agent.lastJobAt,
    online
  };
}

function touchAgent(payload = {}, opts = {}) {
  const store = loadStore();
  const hostname = String(payload.hostname || os.hostname()).trim();
  const agentId = normalizeAgentId(payload.agentId || hostname);
  if (!agentId) return { ok: false, error: 'Hostname inválido.' };

  const prev = store.agents[agentId] || {};
  if (opts.requireRegistered && !prev.publicKey && !prev.legacy && !opts.legacy) {
    return { ok: false, error: 'Agente não pareado. Gere código na sala TI e execute -Enroll na estação.' };
  }

  const agent = {
    ...prev,
    agentId,
    hostname,
    ip: payload.ip || prev.ip || null,
    user: payload.user || prev.user || null,
    agentVersion: payload.agentVersion || prev.agentVersion || '1.0',
    firstSeen: prev.firstSeen || new Date().toISOString(),
    lastSeen: new Date().toISOString(),
    lastJobAt: prev.lastJobAt || null,
    legacy: opts.legacy ? true : (prev.legacy || false)
  };
  store.agents[agentId] = agent;
  saveStore(store);
  return { ok: true, agent };
}

function enrollAgent(payload = {}) {
  const code = String(payload.pairingCode || '').trim().toUpperCase();
  const publicKey = String(payload.publicKey || '').trim();
  if (!code) return { ok: false, error: 'Informe o código de pareamento.' };
  if (!publicKey.includes('BEGIN PUBLIC KEY')) {
    return { ok: false, error: 'Chave pública inválida.' };
  }
  if (!remoteSec.consumePairingCode(code)) {
    return { ok: false, error: 'Código de pareamento inválido ou expirado.' };
  }

  const hostname = String(payload.hostname || os.hostname()).trim();
  const agentId = normalizeAgentId(payload.agentId || hostname);
  if (!agentId) return { ok: false, error: 'Hostname inválido.' };

  const store = loadStore();
  const prev = store.agents[agentId] || {};
  store.agents[agentId] = {
    ...prev,
    agentId,
    hostname,
    ip: payload.ip || prev.ip || null,
    publicKey,
    legacy: false,
    enrolledAt: new Date().toISOString(),
    firstSeen: prev.firstSeen || new Date().toISOString(),
    lastSeen: new Date().toISOString(),
    agentVersion: payload.agentVersion || '2.0'
  };
  saveStore(store);

  remoteSec.ensureServerKeys();
  return {
    ok: true,
    agentId,
    hostname,
    serverPublicKey: remoteSec.getServerPublicKey(),
    securityMode: 'veyon'
  };
}

function expireStaleJobs(store) {
  const now = Date.now();
  let changed = false;
  for (const job of store.jobs) {
    if (!job || (job.status !== 'pending' && job.status !== 'claimed')) continue;
    const base = job.status === 'claimed' && job.claimedAt ? job.claimedAt : job.createdAt;
    const limit = job.status === 'claimed' ? JOB_CLAIMED_TIMEOUT_MS : JOB_PENDING_TIMEOUT_MS;
    const age = now - new Date(base).getTime();
    if (age > limit) {
      const wasClaimed = job.status === 'claimed';
      job.status = 'timeout';
      job.error = wasClaimed
        ? 'Tempo esgotado durante execução remota.'
        : 'Tempo esgotado aguardando agente remoto.';
      job.completedAt = new Date().toISOString();
      changed = true;
    }
  }
  return changed;
}

function listAgents() {
  const store = loadStore();
  expireStaleJobs(store);
  saveStore(store);
  const now = Date.now();
  const agents = Object.values(store.agents)
    .map((a) => sanitizeAgent(a, (now - new Date(a.lastSeen).getTime()) <= ONLINE_MS))
    .sort((a, b) => {
      if (a.online !== b.online) return a.online ? -1 : 1;
      return (b.lastSeen || '').localeCompare(a.lastSeen || '');
    });
  return {
    ok: true,
    agents,
    securityMode: 'veyon',
    legacyTokenEnabled: LEGACY_TOKEN_ENABLED
  };
}

function resolveAgentTarget(target) {
  const store = loadStore();
  const raw = String(target || '').trim();
  if (!raw) return { ok: false, error: 'Informe IP ou hostname da estação.' };

  const agents = Object.values(store.agents);
  const ipMatch = agents.find((a) => a.ip && a.ip === raw);
  if (ipMatch) return { ok: true, agent: ipMatch, matchedBy: 'ip' };

  const norm = normalizeAgentId(raw);
  if (store.agents[norm]) return { ok: true, agent: store.agents[norm], matchedBy: 'agentId' };

  const hostLower = raw.toLowerCase();
  const hostMatch = agents.find((a) =>
    (a.hostname && a.hostname.toLowerCase() === hostLower)
    || (a.agentId && a.agentId.toLowerCase() === hostLower)
  );
  if (hostMatch) return { ok: true, agent: hostMatch, matchedBy: 'hostname' };

  // Permite digitar IP/hostname antes do primeiro poll — agente deve existir após pareamento
  if (/^\d{1,3}(?:\.\d{1,3}){3}$/.test(raw)) {
    return {
      ok: false,
      error: `Nenhum agente pareado com IP ${raw}. Inicie o agente na estação remota primeiro.`
    };
  }

  return {
    ok: false,
    error: `Estação "${raw}" não encontrada. Digite o IP, hostname ou escolha da lista (agente pareado).`
  };
}

function createJob(options = {}) {
  const store = loadStore();
  expireStaleJobs(store);

  let agent = null;
  if (options.agentId) {
    agent = store.agents[normalizeAgentId(options.agentId)] || null;
  }
  if (!agent && (options.target || options.ip || options.hostname)) {
    const resolved = resolveAgentTarget(options.target || options.ip || options.hostname);
    if (!resolved.ok) return resolved;
    agent = resolved.agent;
  }
  if (!agent) {
    return { ok: false, error: 'Informe IP, hostname ou estação da lista.' };
  }

  const agentId = agent.agentId;
  const profileId = options.profileId || 'escritorio';
  const profileSnapshot = options.profileSnapshot || autoTest.buildProfileSnapshot(profileId);

  const job = {
    id: `job_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    agentId,
    hostname: options.hostname || agent.hostname || agentId,
    status: 'pending',
    profileId,
    profileSnapshot,
    options: {
      testInterfaceMode: options.testInterfaceMode || 'auto',
      testInterface: autoTest.sanitizeNetworkTarget(options.testInterface || ''),
      switchIp: autoTest.sanitizeNetworkTarget(options.switchIp || ''),
      switchCommunity: String(options.switchCommunity || '').trim().slice(0, 64)
    },
    createdAt: new Date().toISOString(),
    claimedAt: null,
    completedAt: null,
    result: null,
    error: null,
    requestedBy: options.requestedBy || null
  };

  store.jobs.unshift(job);
  store.jobs = store.jobs.slice(0, MAX_JOBS);
  saveStore(store);
  return { ok: true, job };
}

function getJob(jobId) {
  const store = loadStore();
  expireStaleJobs(store);
  saveStore(store);
  const job = store.jobs.find((j) => j.id === jobId);
  if (!job) return { ok: false, error: 'Job não encontrado.' };
  return { ok: true, job };
}

function buildSignedJob(pending) {
  const keys = remoteSec.ensureServerKeys();
  return remoteSec.signJobPayload(
    {
      id: pending.id,
      profileId: pending.profileId,
      profileSnapshot: pending.profileSnapshot,
      options: pending.options
    },
    keys.privateKeyPem
  );
}

function pollJobForAgent(payload = {}, opts = {}) {
  const requireRegistered = !opts.legacy;
  const touch = touchAgent(payload, { requireRegistered, legacy: !!opts.legacy });
  if (!touch.ok) return touch;

  const store = loadStore();
  expireStaleJobs(store);
  const agentId = touch.agent.agentId;

  const pending = store.jobs.find((j) => j.agentId === agentId && j.status === 'pending');
  if (pending) {
    pending.status = 'claimed';
    pending.claimedAt = new Date().toISOString();
    saveStore(store);
    return {
      ok: true,
      agent: sanitizeAgent(touch.agent, true),
      job: buildSignedJob(pending)
    };
  }

  saveStore(store);
  return { ok: true, agent: sanitizeAgent(touch.agent, true), job: null };
}

function truncateResult(payload) {
  try {
    const raw = JSON.stringify(payload);
    if (raw.length <= MAX_RESULT_BYTES) return payload;
    return {
      ok: false,
      error: 'Resultado remoto excedeu o limite de tamanho.',
      truncated: true
    };
  } catch {
    return { ok: false, error: 'Resultado remoto inválido.' };
  }
}

function completeJob(jobId, payload = {}, agentId = null) {
  const store = loadStore();
  const job = store.jobs.find((j) => j.id === jobId);
  if (!job) return { ok: false, error: 'Job não encontrado.' };
  if (job.status !== 'pending' && job.status !== 'claimed') {
    return { ok: false, error: 'Job já finalizado.' };
  }
  if (agentId && job.agentId !== normalizeAgentId(agentId)) {
    return { ok: false, error: 'Job não pertence a este agente.' };
  }

  if (payload.ok === false || payload.error) {
    job.status = 'failed';
    job.error = payload.error || 'Falha reportada pelo agente.';
    job.result = truncateResult(payload.result || null);
  } else {
    job.status = 'done';
    job.result = truncateResult(payload.result || payload);
    job.error = null;
  }
  job.completedAt = new Date().toISOString();

  if (store.agents[job.agentId]) {
    store.agents[job.agentId].lastJobAt = job.completedAt;
    store.agents[job.agentId].lastSeen = job.completedAt;
  }

  saveStore(store);
  return { ok: true, job };
}

function revokeAgent(agentId) {
  const store = loadStore();
  const norm = normalizeAgentId(agentId);
  if (!store.agents[norm]) return { ok: false, error: 'Agente não encontrado.' };
  delete store.agents[norm];
  saveStore(store);
  return { ok: true, agentId: norm };
}

function getPublicConfig() {
  remoteSec.ensureServerKeys();
  return {
    ok: true,
    securityMode: 'veyon',
    serverPublicKey: remoteSec.getServerPublicKey(),
    onlineWindowSec: Math.round(ONLINE_MS / 1000),
    jobPendingTimeoutSec: Math.round(JOB_PENDING_TIMEOUT_MS / 1000),
    jobClaimedTimeoutSec: Math.round(JOB_CLAIMED_TIMEOUT_MS / 1000),
    legacyTokenEnabled: LEGACY_TOKEN_ENABLED,
    pairingTtlSec: 900
  };
}

function createPairingCode() {
  return remoteSec.createPairingCode();
}

function verifySignedAgentRequest(agentId, timestamp, body, signature) {
  const agent = getAgent(agentId);
  if (!agent) return { ok: false, error: 'Agente desconhecido.' };
  if (!agent.publicKey) {
    return { ok: false, error: 'Agente sem chave pareada.' };
  }
  if (!remoteSec.verifyAgentRequest(agent, timestamp, body, signature)) {
    return { ok: false, error: 'Assinatura do agente inválida ou expirada.' };
  }
  return { ok: true, agent };
}

module.exports = {
  loadStore,
  getAgent,
  verifyAgentToken,
  touchAgent,
  enrollAgent,
  listAgents,
  createJob,
  getJob,
  pollJobForAgent,
  completeJob,
  getPublicConfig,
  createPairingCode,
  verifySignedAgentRequest,
  resolveAgentTarget,
  revokeAgent,
  STORE_FILE
};

/**
 * Segurança AutoTest remoto — estilo Veyon (chaves assimétricas + assinatura).
 */
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const KEY_DIR = path.join(__dirname, 'data', 'autotest-remote-keys');
const PAIRING_FILE = path.join(__dirname, 'data', 'autotest-remote-pairing.json');
const SERVER_PRIVATE = path.join(KEY_DIR, 'server-private.pem');
const SERVER_PUBLIC = path.join(KEY_DIR, 'server-public.pem');
const SIGN_ALG = 'ed25519';
const REPLAY_MS = 120 * 1000;

const pairingCodes = new Map();

function ensureKeyDir() {
  if (!fs.existsSync(KEY_DIR)) fs.mkdirSync(KEY_DIR, { recursive: true });
}

function loadPairingCodes() {
  try {
    if (!fs.existsSync(PAIRING_FILE)) return;
    const raw = JSON.parse(fs.readFileSync(PAIRING_FILE, 'utf8'));
    for (const [code, meta] of Object.entries(raw.codes || {})) {
      pairingCodes.set(code, meta);
    }
  } catch {
    // ignore corrupt file
  }
}

function savePairingCodes() {
  try {
    const dir = path.dirname(PAIRING_FILE);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    const codes = {};
    for (const [code, meta] of pairingCodes) codes[code] = meta;
    const tmp = `${PAIRING_FILE}.tmp`;
    fs.writeFileSync(tmp, JSON.stringify({ version: 1, codes }, null, 2), 'utf8');
    fs.renameSync(tmp, PAIRING_FILE);
  } catch {
    // ignore
  }
}

loadPairingCodes();

function generateKeyPair() {
  const { publicKey, privateKey } = crypto.generateKeyPairSync(SIGN_ALG);
  return {
    publicKeyPem: publicKey.export({ type: 'spki', format: 'pem' }),
    privateKeyPem: privateKey.export({ type: 'pkcs8', format: 'pem' })
  };
}

function ensureServerKeys() {
  ensureKeyDir();
  if (fs.existsSync(SERVER_PRIVATE) && fs.existsSync(SERVER_PUBLIC)) {
    return {
      publicKeyPem: fs.readFileSync(SERVER_PUBLIC, 'utf8'),
      privateKeyPem: fs.readFileSync(SERVER_PRIVATE, 'utf8')
    };
  }
  const pair = generateKeyPair();
  fs.writeFileSync(SERVER_PRIVATE, pair.privateKeyPem, { mode: 0o600 });
  fs.writeFileSync(SERVER_PUBLIC, pair.publicKeyPem, 'utf8');
  return pair;
}

function canonicalJson(obj) {
  return JSON.stringify(obj, Object.keys(obj).sort());
}

function signMessage(privateKeyPem, message) {
  const key = crypto.createPrivateKey(privateKeyPem);
  return crypto.sign(null, Buffer.from(message, 'utf8'), key).toString('base64');
}

function verifyMessage(publicKeyPem, message, signatureB64) {
  if (!publicKeyPem || !signatureB64) return false;
  try {
    const key = crypto.createPublicKey(publicKeyPem);
    const sig = Buffer.from(signatureB64, 'base64');
    return crypto.verify(null, Buffer.from(message, 'utf8'), key, sig);
  } catch {
    return false;
  }
}

function buildAgentMessage(timestamp, body) {
  return `${timestamp}.${canonicalJson(body || {})}`;
}

function verifyAgentRequest(agent, timestamp, body, signature) {
  if (!agent?.publicKey) return false;
  const ts = Number(timestamp);
  if (!Number.isFinite(ts) || Math.abs(Date.now() - ts) > REPLAY_MS) return false;
  return verifyMessage(agent.publicKey, buildAgentMessage(ts, body), signature);
}

function signJobPayload(jobPayload, privateKeyPem) {
  const issuedAt = new Date().toISOString();
  const payload = {
    id: jobPayload.id,
    profileId: jobPayload.profileId,
    profileSnapshot: jobPayload.profileSnapshot || null,
    options: jobPayload.options || {},
    issuedAt
  };
  const signature = signMessage(privateKeyPem, canonicalJson(payload));
  return { ...payload, signature };
}

function verifyJobPayload(job, serverPublicKeyPem) {
  if (!job?.signature || !job.id) return false;
  const payload = {
    id: job.id,
    profileId: job.profileId,
    profileSnapshot: job.profileSnapshot || null,
    options: job.options || {},
    issuedAt: job.issuedAt
  };
  if (job.issuedAt) {
    const age = Date.now() - new Date(job.issuedAt).getTime();
    if (age > 20 * 60 * 1000) return false;
  }
  return verifyMessage(serverPublicKeyPem, canonicalJson(payload), job.signature);
}

function createPairingCode(ttlMs = 15 * 60 * 1000) {
  purgePairingCodes();
  const code = crypto.randomBytes(4).toString('hex').toUpperCase();
  pairingCodes.set(code, { expiresAt: Date.now() + ttlMs, used: false });
  savePairingCodes();
  return { code, expiresAt: new Date(Date.now() + ttlMs).toISOString(), ttlSec: Math.round(ttlMs / 1000) };
}

function purgePairingCodes() {
  const now = Date.now();
  let changed = false;
  for (const [code, meta] of pairingCodes) {
    if (meta.used || meta.expiresAt <= now) {
      pairingCodes.delete(code);
      changed = true;
    }
  }
  if (changed) savePairingCodes();
}

function consumePairingCode(code) {
  purgePairingCodes();
  const key = String(code || '').trim().toUpperCase();
  const meta = pairingCodes.get(key);
  if (!meta || meta.used || meta.expiresAt <= Date.now()) return false;
  meta.used = true;
  pairingCodes.set(key, meta);
  savePairingCodes();
  return true;
}

function getServerPublicKey() {
  return ensureServerKeys().publicKeyPem;
}

module.exports = {
  ensureServerKeys,
  generateKeyPair,
  signMessage,
  verifyMessage,
  buildAgentMessage,
  verifyAgentRequest,
  signJobPayload,
  verifyJobPayload,
  createPairingCode,
  consumePairingCode,
  getServerPublicKey,
  KEY_DIR,
  REPLAY_MS
};

/**
 * Autenticação AD para AutoTest remoto — somente domínios HCFMB e UNESP.
 */
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');
const { execFile } = require('child_process');
const { promisify } = require('util');
const { checkRateLimit } = require('./rateLimit');

const execFileAsync = promisify(execFile);

const DATA_DIR = path.join(__dirname, 'data');
const SESSION_FILE = path.join(DATA_DIR, 'autotest-remote-ad-sessions.json');

const ALLOWED_DOMAINS = String(process.env.AUTOTEST_REMOTE_AD_DOMAINS || 'hcfmb,unesp')
  .split(',')
  .map((d) => d.trim().toLowerCase())
  .filter(Boolean);

const ADMIN_GROUPS = String(process.env.AUTOTEST_REMOTE_AD_ADMIN_GROUPS
  || 'Domain Admins,Administradores do Domínio,Enterprise Admins')
  .split(',')
  .map((g) => g.trim().toLowerCase())
  .filter(Boolean);

const SESSION_TTL_MS = Number(process.env.AUTOTEST_REMOTE_AD_SESSION_MS) || 30 * 60 * 1000;
const LOGIN_RATE_MAX = Number(process.env.AUTOTEST_REMOTE_LOGIN_RATE_MAX) || 8;
const LOGIN_RATE_WINDOW_MS = Number(process.env.AUTOTEST_REMOTE_LOGIN_RATE_MS) || 5 * 60 * 1000;

const sessions = new Map();

function ensureDataDir() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
}

function loadSessionsFromDisk() {
  ensureDataDir();
  if (!fs.existsSync(SESSION_FILE)) return;
  try {
    const raw = JSON.parse(fs.readFileSync(SESSION_FILE, 'utf8'));
    const now = Date.now();
    for (const [token, session] of Object.entries(raw.sessions || {})) {
      if (session?.expiresAt && now <= session.expiresAt) {
        sessions.set(token, session);
      }
    }
  } catch {
    // ignore corrupt file
  }
}

function saveSessionsToDisk() {
  try {
    ensureDataDir();
    const sessionsObj = {};
    for (const [token, session] of sessions) sessionsObj[token] = session;
    const tmp = `${SESSION_FILE}.tmp`;
    fs.writeFileSync(tmp, JSON.stringify({ version: 1, sessions: sessionsObj }, null, 2), 'utf8');
    fs.renameSync(tmp, SESSION_FILE);
  } catch {
    // ignore
  }
}

loadSessionsFromDisk();

function normalizeDomainKey(domain) {
  const d = String(domain || '').trim().toLowerCase();
  if (!d) return '';
  const first = d.split('.')[0];
  return first || d;
}

function parseDomainUser(input) {
  const raw = String(input || '').trim();
  if (!raw) return { ok: false, error: 'Informe login e senha.' };

  let domainRaw = null;
  let sam = null;

  if (raw.includes('\\')) {
    const idx = raw.indexOf('\\');
    domainRaw = raw.slice(0, idx).trim();
    sam = raw.slice(idx + 1).trim();
  } else if (raw.includes('@')) {
    const idx = raw.indexOf('@');
    sam = raw.slice(0, idx).trim();
    domainRaw = raw.slice(idx + 1).trim();
  } else {
    return {
      ok: false,
      error: 'Use o formato HCFMB\\usuario ou UNESP\\usuario (conta de administrador do domínio).'
    };
  }

  if (!domainRaw || !sam) {
    return { ok: false, error: 'Login inválido. Use HCFMB\\usuario ou UNESP\\usuario.' };
  }

  const domainKey = normalizeDomainKey(domainRaw);
  if (!ALLOWED_DOMAINS.includes(domainKey)) {
    return {
      ok: false,
      error: `AutoTest remoto aceita somente contas ${ALLOWED_DOMAINS.map((d) => d.toUpperCase()).join(' ou ')}.`
    };
  }

  return {
    ok: true,
    domainKey,
    domainDns: domainRaw,
    samAccountName: sam,
    login: `${domainKey.toUpperCase()}\\${sam}`
  };
}

function decodePowerShellOutput(buf) {
  if (!buf || !buf.length) return '';
  if (Buffer.isBuffer(buf)) {
    if (buf[0] === 0xef && buf[1] === 0xbb && buf[2] === 0xbf) return buf.slice(3).toString('utf8');
    const asUtf8 = buf.toString('utf8');
    if (!asUtf8.includes('\uFFFD')) return asUtf8;
    return buf.toString('latin1');
  }
  return String(buf);
}

async function validateDomainCredentials(username, password, timeoutMs = 20000) {
  const parsed = parseDomainUser(username);
  if (!parsed.ok) return parsed;
  if (!password) return { ok: false, error: 'Informe login e senha.' };

  const groupsPs = ADMIN_GROUPS.map((g) => `'${String(g).replace(/'/g, "''")}'`).join(',');
  const script = `
$ErrorActionPreference = 'Stop'
[Console]::OutputEncoding = [System.Text.Encoding]::UTF8
$OutputEncoding = [System.Text.Encoding]::UTF8
chcp 65001 | Out-Null
Add-Type -AssemblyName System.DirectoryServices.AccountManagement
$domain = $env:NETSCAN_AD_DOMAIN
$user = $env:NETSCAN_AD_USER
$pass = $env:NETSCAN_AD_PASS
$requiredGroups = @(${groupsPs}) | ForEach-Object { $_.ToLowerInvariant() }
try {
  $ctx = New-Object System.DirectoryServices.AccountManagement.PrincipalContext(
    [System.DirectoryServices.AccountManagement.ContextType]::Domain, $domain
  )
  if (-not $ctx.ValidateCredentials($user, $pass)) {
    @{ ok = $false; error = 'Login ou senha inválidos no domínio.' } | ConvertTo-Json -Compress
    exit 0
  }
  $up = [System.DirectoryServices.AccountManagement.UserPrincipal]::FindByIdentity($ctx, [System.DirectoryServices.AccountManagement.IdentityType]::SamAccountName, $user)
  if ($null -eq $up -or $up.Enabled -eq $false) {
    @{ ok = $false; error = 'Conta desabilitada ou não encontrada no domínio.' } | ConvertTo-Json -Compress
    exit 0
  }
  $groupNames = New-Object System.Collections.Generic.List[string]
  try {
    $authGroups = $up.GetAuthorizationGroups()
    foreach ($g in $authGroups) {
      if ($g.Name) { [void]$groupNames.Add([string]$g.Name) }
    }
  } catch {
    try {
      $de = New-Object System.DirectoryServices.DirectoryEntry(("LDAP://" + $domain), ($domain + "\\" + $user), $pass)
      $searcher = New-Object System.DirectoryServices.DirectorySearcher($de)
      $searcher.Filter = "(sAMAccountName=$user)"
      $searcher.PropertiesToLoad.Add('memberOf') | Out-Null
      $searcher.PropertiesToLoad.Add('displayName') | Out-Null
      $hit = $searcher.FindOne()
      if ($hit) {
        foreach ($m in $hit.Properties['memberOf']) {
          $dn = [string]$m
          if ($dn -match '^CN=([^,]+)') { [void]$groupNames.Add($matches[1]) }
        }
      }
    } catch { }
  }
  $lowerGroups = @($groupNames | ForEach-Object { $_.ToLowerInvariant() })
  $isAdmin = $false
  foreach ($req in $requiredGroups) {
    if ($lowerGroups -contains $req) { $isAdmin = $true; break }
  }
  if (-not $isAdmin) {
    @{ ok = $false; error = 'Conta válida, mas sem permissão de administrador de domínio para AutoTest remoto.' } | ConvertTo-Json -Compress
    exit 0
  }
  @{
    ok = $true
    samAccountName = [string]$up.SamAccountName
    displayName = [string]$up.DisplayName
    userPrincipalName = [string]$up.UserPrincipalName
    groups = @($groupNames)
  } | ConvertTo-Json -Compress -Depth 4
} catch {
  @{ ok = $false; error = ($_.Exception.Message -replace '[\\r\\n]+', ' ').Trim() } | ConvertTo-Json -Compress
}
`;

  try {
    const { stdout, stderr } = await execFileAsync(
      'powershell.exe',
      ['-NoProfile', '-ExecutionPolicy', 'Bypass', '-Command', script],
      {
        timeout: timeoutMs,
        windowsHide: true,
        maxBuffer: 1024 * 1024,
        env: {
          ...process.env,
          NETSCAN_AD_DOMAIN: parsed.domainDns,
          NETSCAN_AD_USER: parsed.samAccountName,
          NETSCAN_AD_PASS: password
        }
      }
    );
    const text = decodePowerShellOutput(stdout).trim();
    if (!text) {
      const errText = decodePowerShellOutput(stderr).trim();
      return { ok: false, error: errText || 'Falha ao validar credenciais no Active Directory.' };
    }
    const data = JSON.parse(text);
    if (!data.ok) return data;
    return {
      ok: true,
      user: {
        login: parsed.login,
        domain: parsed.domainKey.toUpperCase(),
        samAccountName: data.samAccountName || parsed.samAccountName,
        displayName: data.displayName || parsed.samAccountName,
        userPrincipalName: data.userPrincipalName || null,
        groups: Array.isArray(data.groups) ? data.groups : []
      }
    };
  } catch (err) {
    return { ok: false, error: err.message || 'Falha ao consultar o Active Directory.' };
  }
}

function extractToken(req) {
  const hdr = req.headers['x-autotest-remote-session'];
  if (hdr && typeof hdr === 'string') return hdr.trim();
  return null;
}

function createSession(user) {
  const token = crypto.randomBytes(32).toString('hex');
  sessions.set(token, {
    user,
    createdAt: Date.now(),
    expiresAt: Date.now() + SESSION_TTL_MS
  });
  saveSessionsToDisk();
  return token;
}

function getSession(token) {
  if (!token) return null;
  const session = sessions.get(token);
  if (!session) return null;
  if (Date.now() > session.expiresAt) {
    sessions.delete(token);
    saveSessionsToDisk();
    return null;
  }
  return session;
}

function revokeSession(token) {
  if (token) {
    sessions.delete(token);
    saveSessionsToDisk();
  }
}

function requireAuth(req, res, next) {
  const token = extractToken(req);
  const session = getSession(token);
  if (!session) {
    return res.status(401).json({
      ok: false,
      error: 'Autenticação AD necessária (HCFMB ou UNESP).',
      code: 'REMOTE_AD_AUTH_REQUIRED'
    });
  }
  req.autoTestRemoteSession = session;
  req.autoTestRemoteUser = session.user;
  next();
}

async function login(username, password, clientKey = 'global') {
  const rl = checkRateLimit(`autotest-ad-login:${clientKey}`, LOGIN_RATE_MAX, LOGIN_RATE_WINDOW_MS);
  if (!rl.allowed) {
    return { ok: false, error: 'Muitas tentativas de login. Aguarde alguns minutos.' };
  }
  const validated = await validateDomainCredentials(username, password);
  if (!validated.ok) return validated;
  const token = createSession(validated.user);
  return {
    ok: true,
    token,
    user: validated.user,
    expiresInMs: SESSION_TTL_MS,
    allowedDomains: ALLOWED_DOMAINS.map((d) => d.toUpperCase())
  };
}

setInterval(() => {
  const now = Date.now();
  let changed = false;
  for (const [token, session] of sessions) {
    if (now > session.expiresAt) {
      sessions.delete(token);
      changed = true;
    }
  }
  if (changed) saveSessionsToDisk();
}, 10 * 60 * 1000).unref();

module.exports = {
  ALLOWED_DOMAINS,
  ADMIN_GROUPS,
  SESSION_TTL_MS,
  parseDomainUser,
  validateDomainCredentials,
  login,
  requireAuth,
  extractToken,
  getSession,
  revokeSession
};

/**
 * Rate limit simples em memória (por chave / janela deslizante).
 */
const buckets = new Map();

function checkRateLimit(key, maxAttempts = 10, windowMs = 60 * 1000) {
  const safeKey = String(key || 'global').slice(0, 128);
  const now = Date.now();
  let bucket = buckets.get(safeKey);
  if (!bucket || now > bucket.resetAt) {
    bucket = { count: 0, resetAt: now + windowMs };
  }
  bucket.count += 1;
  buckets.set(safeKey, bucket);
  return {
    allowed: bucket.count <= maxAttempts,
    remaining: Math.max(0, maxAttempts - bucket.count),
    resetAt: bucket.resetAt
  };
}

function clientIp(req) {
  return String(req.headers['x-forwarded-for'] || req.socket?.remoteAddress || 'local').split(',')[0].trim();
}

setInterval(() => {
  const now = Date.now();
  for (const [key, bucket] of buckets) {
    if (now > bucket.resetAt) buckets.delete(key);
  }
}, 5 * 60 * 1000).unref();

module.exports = { checkRateLimit, clientIp };

#!/usr/bin/env node
/**
 * Agente AutoTest remoto — estação de campo (serviço Windows / modo manual).
 */
const fs = require('fs');
const path = require('path');
const os = require('os');
const autoTest = require('./autoTest');
const remoteSec = require('./autoTestRemoteSecurity');

const args = process.argv.slice(2);
function arg(name, def = '') {
  const i = args.indexOf(name);
  return i >= 0 && args[i + 1] ? args[i + 1] : def;
}
function hasFlag(name) {
  return args.includes(name);
}

const installRoot = path.dirname(__filename);
const configPath = path.resolve(arg('--config', path.join(installRoot, 'data', 'agent-config.json')));
const credentialsPath = path.resolve(arg('--credentials', path.join(installRoot, 'data', 'autotest-agent-credentials.json')));
const logFilePath = arg('--log-file', process.env.NETSCAN_AGENT_LOG || '');
const pairingCode = arg('--pairing-code', process.env.NETSCAN_PAIRING_CODE || '');
const pollSec = Math.max(3, Number(arg('--interval', '5')) || 5);
const agentVersion = arg('--version', '2.1');
const legacyToken = arg('--token', process.env.NETSCAN_AGENT_TOKEN || '');

function loadAgentConfig() {
  if (!fs.existsSync(configPath)) return {};
  try {
    return JSON.parse(fs.readFileSync(configPath, 'utf8'));
  } catch {
    return {};
  }
}

const agentConfig = loadAgentConfig();
const serverUrl = (
  arg('--server', '')
  || agentConfig.serverUrl
  || process.env.NETSCAN_SERVER
  || 'http://localhost:3000'
).replace(/\/$/, '');

function localIp() {
  const ifaces = os.networkInterfaces();
  for (const list of Object.values(ifaces)) {
    for (const i of list || []) {
      if (i.family === 'IPv4' && !i.internal) return i.address;
    }
  }
  return null;
}

function setupFileLogging(filePath) {
  if (!filePath) return;
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  try {
    const stat = fs.statSync(filePath);
    if (stat.size > 5 * 1024 * 1024) {
      const lines = fs.readFileSync(filePath, 'utf8').split('\n');
      fs.writeFileSync(filePath, lines.slice(-2000).join('\n'), 'utf8');
    }
  } catch { /* novo */ }

  const write = (level, parts) => {
    const line = `[${new Date().toISOString()}] [${level}] ${parts.map(String).join(' ')}\n`;
    try { fs.appendFileSync(filePath, line, 'utf8'); } catch { /* ignore */ }
  };

  const wrap = (orig, level) => (...a) => {
    write(level, a);
    orig(...a);
  };
  console.log = wrap(console.log, 'INFO');
  console.warn = wrap(console.warn, 'WARN');
  console.error = wrap(console.error, 'ERROR');
  write('INFO', [`Log iniciado · ${filePath}`]);
}

function loadCredentials() {
  if (!fs.existsSync(credentialsPath)) return null;
  try {
    return JSON.parse(fs.readFileSync(credentialsPath, 'utf8'));
  } catch {
    return null;
  }
}

function saveCredentials(creds) {
  const dir = path.dirname(credentialsPath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(credentialsPath, JSON.stringify(creds, null, 2), { mode: 0o600 });
}

function signBody(creds, timestamp, body) {
  return remoteSec.signMessage(creds.privateKeyPem, remoteSec.buildAgentMessage(timestamp, body));
}

async function fetchJson(url, init = {}) {
  const res = await fetch(url, init);
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.error || `HTTP ${res.status}`);
  return data;
}

async function enroll() {
  if (!pairingCode) {
    console.error('[AutoTest Agent] Código de pareamento obrigatório (--pairing-code).');
    process.exit(1);
  }
  const pair = remoteSec.generateKeyPair();
  const hostname = os.hostname();
  const body = {
    pairingCode,
    hostname,
    ip: localIp(),
    agentVersion,
    publicKey: pair.publicKeyPem
  };
  const data = await fetchJson(`${serverUrl}/api/autotest/remote/agent/enroll`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body)
  });
  const creds = {
    version: 2,
    securityMode: 'veyon',
    agentId: data.agentId,
    hostname: data.hostname || hostname,
    serverUrl,
    serverPublicKey: data.serverPublicKey,
    privateKeyPem: pair.privateKeyPem,
    publicKeyPem: pair.publicKeyPem,
    enrolledAt: new Date().toISOString()
  };
  saveCredentials(creds);
  console.log(`[AutoTest Agent] Pareamento OK · ${creds.agentId} · ${credentialsPath}`);
  return creds;
}

async function apiSigned(creds, apiPath, body) {
  const timestamp = Date.now();
  const signature = signBody(creds, timestamp, body);
  const base = (creds.serverUrl || serverUrl).replace(/\/$/, '');
  return fetchJson(`${base}${apiPath}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-AutoTest-Agent-Id': creds.agentId,
      'X-AutoTest-Agent-Ts': String(timestamp),
      'X-AutoTest-Agent-Sign': signature
    },
    body: JSON.stringify(body)
  });
}

async function apiLegacy(apiPath, body) {
  return fetchJson(`${serverUrl}${apiPath}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'X-AutoTest-Agent-Token': legacyToken
    },
    body: JSON.stringify(body)
  });
}

async function runJob(job, creds) {
  if (creds?.serverPublicKey && job.signature) {
    if (!remoteSec.verifyJobPayload(job, creds.serverPublicKey)) {
      throw new Error('Job rejeitado — assinatura do servidor inválida.');
    }
  }
  console.log(`[AutoTest Agent] Executando job ${job.id} · perfil ${job.profileId}`);
  const result = await autoTest.runAutoTest({
    profileId: job.profileId,
    profileSnapshot: job.profileSnapshot,
    ...(job.options || {}),
    skipHistory: true
  });
  result.remoteAgent = {
    hostname: os.hostname(),
    ip: localIp(),
    ranAt: new Date().toISOString(),
    agentVersion,
    securityMode: creds?.securityMode || 'legacy'
  };
  return result;
}

async function loopSecure(creds) {
  const hostname = os.hostname();
  const ip = localIp();
  const base = (creds.serverUrl || serverUrl).replace(/\/$/, '');
  console.log(`[AutoTest Agent] ${creds.agentId} (${hostname}) → ${base} · serviço · poll ${pollSec}s`);

  for (;;) {
    try {
      const body = {
        hostname,
        ip,
        user: process.env.USERNAME || process.env.USER || null,
        agentVersion,
        agentId: creds.agentId
      };
      const data = await apiSigned(creds, '/api/autotest/remote/agent/poll', body);
      if (data.job) {
        try {
          const result = await runJob(data.job, creds);
          await apiSigned(creds, '/api/autotest/remote/agent/complete', {
            jobId: data.job.id,
            ok: true,
            result
          });
          console.log(`[AutoTest Agent] Job ${data.job.id} concluído · ${result.summary || 'OK'}`);
        } catch (err) {
          await apiSigned(creds, '/api/autotest/remote/agent/complete', {
            jobId: data.job.id,
            ok: false,
            error: err.message || 'Falha no AutoTest local'
          }).catch(() => {});
          console.error(`[AutoTest Agent] Job ${data.job.id} falhou:`, err.message);
        }
      }
    } catch (err) {
      console.error('[AutoTest Agent] Poll erro:', err.message);
    }
    await new Promise((r) => setTimeout(r, pollSec * 1000));
  }
}

async function loopLegacy() {
  const hostname = os.hostname();
  const ip = localIp();
  console.log(`[AutoTest Agent] ${hostname} (${ip || '?'}) → ${serverUrl} · legado · poll ${pollSec}s`);

  for (;;) {
    try {
      const data = await apiLegacy('/api/autotest/remote/agent/poll', {
        hostname, ip, user: process.env.USERNAME || process.env.USER || null, agentVersion
      });
      if (data.job) {
        try {
          const result = await runJob(data.job, null);
          await apiLegacy('/api/autotest/remote/agent/complete', { jobId: data.job.id, ok: true, result });
          console.log(`[AutoTest Agent] Job ${data.job.id} concluído · ${result.summary || 'OK'}`);
        } catch (err) {
          await apiLegacy('/api/autotest/remote/agent/complete', {
            jobId: data.job.id, ok: false, error: err.message || 'Falha'
          }).catch(() => {});
          console.error(`[AutoTest Agent] Job ${data.job.id} falhou:`, err.message);
        }
      }
    } catch (err) {
      console.error('[AutoTest Agent] Poll erro:', err.message);
    }
    await new Promise((r) => setTimeout(r, pollSec * 1000));
  }
}

async function main() {
  setupFileLogging(logFilePath ? path.resolve(logFilePath) : '');

  if (hasFlag('--enroll')) {
    await enroll();
    if (hasFlag('--enroll-only')) return;
  }

  const creds = loadCredentials();
  if (creds?.agentId && creds.privateKeyPem) {
    if (!creds.serverUrl && serverUrl) creds.serverUrl = serverUrl;
    await loopSecure(creds);
    return;
  }

  if (legacyToken) {
    console.warn('[AutoTest Agent] Modo legado (token).');
    await loopLegacy();
    return;
  }

  console.error('[AutoTest Agent] Sem credenciais. Instale o serviço ou pareie primeiro.');
  process.exit(1);
}

