function findDefaultLibDir() {
  const candidates = [
    process.env.ORACLE_CLIENT_LIB,
    process.env.OCI_LIB_DIR,
    'C:\\app\\erikah\\product\\11.2.0\\client_1',
    'C:\\oracle\\instantclient_21_13',
    'C:\\oracle\\instantclient_19_23',
