    } catch { /* ignore */ }
  }
  return '';
}

function initThickMode(odb, cfg) {
  if (thickInitialized) return { ok: true, thin: odb.thin };
  if (cfg.thickMode === false) return { ok: false, thin: true };

  const libDir = (cfg.libDir && String(cfg.libDir).trim()) || findDefaultLibDir();
  try {
    if (libDir) {
      odb.initOracleClient({ libDir });
    } else {
      odb.initOracleClient();
    }
    thickInitialized = true;
    thickInitError = null;
    return { ok: true, thin: odb.thin, libDir: libDir || '(PATH/ORACLE_HOME)' };
  } catch (err) {
    // Já inicializado em outro ponto
    if (/already been initialized|NJS-067/i.test(String(err.message))) {
      thickInitialized = true;
      thickInitError = null;
      return { ok: true, thin: odb.thin, libDir, note: err.message };
    }
    thickInitError = err;
    // Não bloqueia o módulo: deixa Thin e a mensagem clara sobe na conexão
    return { ok: false, thin: true, error: err.message, libDir };
  }
}

function loadOracleDriver(cfg = null) {
  if (oracledb) {
    if (cfg && cfg.thickMode !== false && oracledb.thin) {
      initThickMode(oracledb, cfg || loadConfig());
    }
    return oracledb;
  }
  if (oracledbLoadError) throw oracledbLoadError;
  try {
    // eslint-disable-next-line global-require
    oracledb = require('oracledb');
    oracledb.outFormat = oracledb.OUT_FORMAT_OBJECT;
    oracledb.fetchAsString = [oracledb.CLOB];
    if (!cfg) cfg = loadConfig();
    if (cfg.thickMode !== false) {
      initThickMode(oracledb, cfg);
    }
    return oracledb;
  } catch (err) {
    oracledbLoadError = err;
    throw err;
  }
}

function writeJsonAtomic(file, data) {
  ensureDataDir();
  const tmp = `${file}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(data, null, 2), 'utf8');
  fs.renameSync(tmp, file);
}

function loadConfig() {
  ensureDataDir();
  if (!fs.existsSync(CONFIG_FILE)) {
    writeJsonAtomic(CONFIG_FILE, DEFAULT_CONFIG);
    return { ...DEFAULT_CONFIG };
  }
  try {
    const raw = JSON.parse(fs.readFileSync(CONFIG_FILE, 'utf8'));
    const cfg = { ...DEFAULT_CONFIG, ...raw };
    cfg.connectString = normalizeConnectString(cfg.connectString);
    return cfg;
  } catch {
    return { ...DEFAULT_CONFIG };
  }
}

/**
 * Aceita JDBC / Easy Connect / TNS e devolve string válida para node-oracledb.
 * Ex. JDBC (causa NJS-515):
 *   jdbc:oracle:thin:@(DESCRIPTION=(ADDRESS=...)(CONNECT_DATA=(SERVICE_NAME=PRDMV)))
 * →
 *   (DESCRIPTION=(ADDRESS=...)(CONNECT_DATA=(SERVICE_NAME=PRDMV)))
 */
function normalizeConnectString(raw) {
  let s = String(raw || '').trim();
  if (!s) return '';

  s = s.replace(/^jdbc:oracle:thin:@/i, '');
  s = s.replace(/^jdbc:oracle:oci:@/i, '');
  s = s.replace(/^jdbc:oracle:@/i, '');

  // Compacta espaços dentro de descritor TNS
  if (s.startsWith('(')) {
    s = s.replace(/\s+/g, '');
  }

  return s.trim();
}

function saveConfig(partial = {}) {
  const cur = loadConfig();
  const next = {
    ...cur,
    ...partial,
    user: partial.user != null ? String(partial.user).trim() : cur.user,
    password: partial.password != null ? String(partial.password) : cur.password,
    connectString: partial.connectString != null
      ? normalizeConnectString(partial.connectString)
      : normalizeConnectString(cur.connectString),
    table: partial.table != null ? String(partial.table).trim() : cur.table,
    maxRows: partial.maxRows != null
      ? Math.min(200, Math.max(1, Number(partial.maxRows) || 50))
      : cur.maxRows,
    thickMode: partial.thickMode != null ? Boolean(partial.thickMode) : cur.thickMode !== false,
    libDir: partial.libDir != null ? String(partial.libDir).trim() : (cur.libDir || '')
  };
  writeJsonAtomic(CONFIG_FILE, next);
  return sanitizeConfig(next);
}

function sanitizeConfig(cfg) {
  return {
    version: cfg.version || 1,
    user: cfg.user || '',
    connectString: cfg.connectString || '',
    table: cfg.table || DEFAULT_CONFIG.table,
    maxRows: cfg.maxRows || 50,
    thickMode: cfg.thickMode !== false,
    libDir: cfg.libDir || '',
    hasPassword: Boolean(cfg.password),
    passwordSet: Boolean(cfg.password)
  };
}

function getPublicConfig() {
  const cfg = sanitizeConfig(loadConfig());
  cfg.thickReady = thickInitialized && oracledb && !oracledb.thin;
  cfg.thickError = thickInitError ? thickInitError.message : null;
  cfg.suggestedLibDir = findDefaultLibDir();
  cfg.sqlplusPath = findSqlPlus(loadConfig()) || '';
  cfg.sqlplusTarget = toSqlPlusTarget(cfg.connectString || '');
  cfg.driverPreferred = cfg.sqlplusPath ? 'sqlplus' : (cfg.thickReady ? 'oracledb' : 'none');
  return cfg;
}

function normalizeNameParts(fullName) {
  return String(fullName || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toUpperCase()
    .replace(/[^A-Z\s]/g, ' ')
    .split(/\s+/)
    .filter(Boolean);
}

function significantParts(fullName) {
  return normalizeNameParts(fullName).filter((p) => !NAME_SKIP.has(p));
}

/**
 * Monta candidatos de login AD a partir do nome (e do cd_usuario Oracle).
 * Padrão principal de iniciais: 1ª letra de cada parte significativa
 * (ex.: Andressa Vizotto Riberto → avr).
 */
function suggestAdLogins(nmUsuario, cdUsuario) {
  const parts = significantParts(nmUsuario);
  const all = normalizeNameParts(nmUsuario);
  const suggestions = [];
  const seen = new Set();

  const push = (login, rule, preferred = false) => {
    const s = String(login || '').toLowerCase().replace(/[^a-z0-9._-]/g, '');
    if (!s || seen.has(s)) return;
    seen.add(s);
    suggestions.push({ login: s, rule, preferred });
  };

  if (cdUsuario) {
    push(cdUsuario, 'cd_usuario (Oracle)', true);
  }

  if (parts.length >= 1) {
    push(parts.map((p) => p[0]).join(''), 'iniciais de cada nome', true);
  }

  if (parts.length >= 2) {
    const first = parts[0];
    const last = parts[parts.length - 1];
    push(first[0] + last.toLowerCase(), '1ª letra + último sobrenome');
    push(first.toLowerCase() + last[0].toLowerCase(), 'primeiro nome + 1ª do último');
    if (parts.length >= 3) {
      push(
        first[0] + parts[1][0] + last.toLowerCase(),
        'iniciais + último sobrenome'
      );
    }
  }

  if (all.length >= 2 && all.length !== parts.length) {
    push(all.map((p) => p[0]).join(''), 'iniciais incluindo partículas');
  }

  return suggestions;
}

function buildLikePattern(query) {
  const q = String(query || '').trim();
  if (!q) return null;
  // "Sandra Picelli" → %SANDRA%PICELLI%
  const parts = q.split(/\s+/).filter(Boolean);
  if (parts.length > 1) {
    return `%${parts.join('%')}%`;
  }
  return `%${q}%`;
}

function rowToUser(row) {
  const keys = Object.keys(row || {});
  const find = (...names) => {
    for (const name of names) {
      const hit = keys.find((k) => k.toUpperCase() === name.toUpperCase());
      if (hit != null && row[hit] != null) return String(row[hit]).trim();
    }
    return '';
  };

  const cd = find('CD_USUARIO', 'cd_usuario');
  const nm = find('NM_USUARIO', 'nm_usuario');
  const extras = {};
  for (const k of keys) {
    const up = k.toUpperCase();
    if (up === 'CD_USUARIO' || up === 'NM_USUARIO') continue;
    const v = row[k];
    if (v == null || v === '') continue;
    if (typeof v === 'object' && !(v instanceof Date)) continue;
    extras[k] = v instanceof Date ? v.toISOString() : String(v);
  }

  return {
    cdUsuario: cd,
    nmUsuario: nm,
    suggestions: suggestAdLogins(nm, cd),
    extras
  };
}

async function withConnection(fn) {
  const cfg = loadConfig();
  const connectString = normalizeConnectString(cfg.connectString);
  if (!connectString) {
    const err = new Error(
      'Configure o Connect String Oracle (ex.: host:1521/SERVICE ou descritor TNS sem jdbc:).'
    );
    err.code = 'ORACLE_CONFIG';
    throw err;
  }
  if (!cfg.user || !cfg.password) {
    const err = new Error('Usuário/senha Oracle não configurados.');
    err.code = 'ORACLE_CONFIG';
    throw err;
  }

  // Persiste forma normalizada se veio JDBC antigo
  if (connectString !== cfg.connectString) {
    try { saveConfig({ connectString }); } catch { /* ignore */ }
  }

  const odb = loadOracleDriver(cfg);
  if (odb.thin) {
    const detail = thickInitError
      ? thickInitError.message
      : 'Oracle Client 64-bit não carregado.';
    const err = new Error(
      `Thick mode necessário (banco antigo / NJS-138). ${detail} Instale Instant Client Basic 64-bit 19+ e informe o libDir.`
    );
    err.code = 'ORACLE_THICK';
    throw err;
  }
  let connection;
  try {
    connection = await odb.getConnection({
      user: cfg.user,
      password: cfg.password,
      connectString
    });
    return await fn(connection, { ...cfg, connectString }, odb);
  } catch (err) {
    const msg = String(err && err.message || err);
    if (/NJS-138/i.test(msg)) {
      const e = new Error(
        'Banco Oracle antigo demais para Thin mode. Use Instant Client 19/21/23 64-bit no campo libDir.'
      );
      e.code = 'ORACLE_THIN';
      throw e;
    }
    throw err;
  } finally {
    if (connection) {
      try { await connection.close(); } catch { /* ignore */ }
    }
  }
}

async function testConnection() {
  const cfg = loadConfig();
  // Preferir sqlplus (client 11g já instalado) — funciona sem Instant Client 64-bit
  if (findSqlPlus(cfg) && toSqlPlusTarget(cfg.connectString)) {
    try {
      return await testWithSqlPlus(cfg);
    } catch (err) {
      // cai para oracledb se possível
      if (!/ORA-|TNS-|SP2-|invalid username|sqlplus/i.test(String(err.message))) {
        /* continue */
      } else {
        throw err;
      }
    }
  }

  return withConnection(async (connection) => {
    const result = await connection.execute('SELECT 1 AS OK FROM DUAL');
    return {
      ok: true,
      message: 'Conexão Oracle OK (node-oracledb)',
      driver: 'oracledb',
      sample: result.rows?.[0] || null
    };
  });
}

/**
 * Busca por nome e/ou código de usuário.
 * @param {string} query
 * @param {{ mode?: 'auto'|'name'|'code', checkAd?: function }} options
 */
async function searchUsers(query, options = {}) {
  const q = String(query || '').trim();
  if (q.length < 2) {
    const err = new Error('Digite ao menos 2 caracteres para buscar.');
    err.code = 'BAD_QUERY';
    throw err;
  }

  const mode = options.mode || 'auto';
  const pattern = buildLikePattern(q);
  const checkAd = typeof options.checkAd === 'function' ? options.checkAd : null;
  const cfg = loadConfig();

  let users = [];
  let driver = 'sqlplus';

  if (findSqlPlus(cfg) && toSqlPlusTarget(cfg.connectString || '')) {
    const result = await queryUsersWithSqlPlus(cfg, { mode, pattern });
    users = (result.rows || []).map(rowToUser);
    driver = result.driver || 'sqlplus';
  } else {
    const payload = await withConnection(async (connection, c) => {
      const table = c.table || DEFAULT_CONFIG.table;
      const maxRows = c.maxRows || 50;
      let sql;
      const binds = { pattern: pattern.toUpperCase(), maxRows };

      if (mode === 'name') {
        sql = `
          SELECT * FROM (
            SELECT u.cd_usuario, u.nm_usuario
            FROM ${table} u
            WHERE UPPER(u.nm_usuario) LIKE :pattern
            ORDER BY u.nm_usuario
          ) WHERE ROWNUM <= :maxRows
        `;
      } else if (mode === 'code') {
        sql = `
          SELECT * FROM (
            SELECT u.cd_usuario, u.nm_usuario
            FROM ${table} u
            WHERE UPPER(u.cd_usuario) LIKE :pattern
            ORDER BY u.cd_usuario
          ) WHERE ROWNUM <= :maxRows
        `;
      } else {
        sql = `
          SELECT * FROM (
            SELECT u.cd_usuario, u.nm_usuario
            FROM ${table} u
            WHERE UPPER(u.nm_usuario) LIKE :pattern
               OR UPPER(u.cd_usuario) LIKE :pattern
            ORDER BY u.nm_usuario
          ) WHERE ROWNUM <= :maxRows
        `;
      }

      const result = await connection.execute(sql, binds);
      return (result.rows || []).map(rowToUser);
    });
    users = payload;
    driver = 'oracledb';
  }

  if (checkAd && users.length) {
    for (const user of users) {
      for (const sug of user.suggestions) {
        try {
          const ad = await checkAd(sug.login);
          sug.adExists = Boolean(ad && ad.ok);
          sug.adUser = ad && ad.ok ? {
            sam: ad.user?.samAccountName || ad.user?.sam || sug.login,
            displayName: ad.user?.displayName || ad.user?.name || null,
            enabled: ad.user?.enabled !== false && !ad.user?.disabled
          } : null;
        } catch {
          sug.adExists = null;
          sug.adUser = null;
        }
      }
    }
  }

  return { users, query: q, mode, pattern, count: users.length, driver };
}

module.exports = {
  loadConfig,
  saveConfig,
  getPublicConfig,
  normalizeConnectString,
  testConnection,
  searchUsers,
  suggestAdLogins,
  CONFIG_FILE
};

/**
 * Bridge Oracle via sqlplus.exe já instalado (client 11g).
 * Evita Instant Client 64-bit / javac.
 */
const fs = require('fs');
const path = require('path');
const os = require('os');
const { execFile } = require('child_process');
const { promisify } = require('util');

const execFileAsync = promisify(execFile);

const DEFAULT_SQLPLUS = 'C:\\app\\erikah\\product\\11.2.0\\client_1\\sqlplus.exe';

function findSqlPlus(cfg = {}) {
  const candidates = [
    cfg.sqlplusPath,
    process.env.SQLPLUS_PATH,
    DEFAULT_SQLPLUS,
    'sqlplus'
  ].filter(Boolean);

  for (const c of candidates) {
    try {
      if (c === 'sqlplus') return c;
      if (fs.existsSync(c)) return c;
    } catch { /* ignore */ }
  }
  return null;
}

/**
 * Converte TNS/JDBC/EasyConnect em target sqlplus user/pass@target
 * Ex.: 172.20.100.12:1521/PRDMV
 */
function toSqlPlusTarget(connectString) {
  let s = String(connectString || '').trim();
  if (!s) return '';

  s = s.replace(/^jdbc:oracle:thin:@/i, '');
  s = s.replace(/^jdbc:oracle:oci:@/i, '');

  // Já é Easy Connect?
  if (/^[\w.-]+:\d+\/[\w.-]+$/i.test(s) || /^\/\/[\w.-]+:\d+\/[\w.-]+$/i.test(s)) {
    return s.replace(/^\/\//, '');
  }
  if (/^[\w.-]+\/[\w.-]+$/i.test(s) && !s.includes('(')) {
    return s;
  }

  // Descritor TNS → pega 1º host/port + service_name
  if (s.startsWith('(')) {
    const compact = s.replace(/\s+/g, '');
    const host = (compact.match(/\(host=([^)]+)\)/i) || [])[1];
    const port = (compact.match(/\(port=([^)]+)\)/i) || [])[1] || '1521';
    const service =
      (compact.match(/\(service_name=([^)]+)\)/i) || [])[1] ||
      (compact.match(/\(sid=([^)]+)\)/i) || [])[1];
    if (host && service) return `${host}:${port}/${service}`;
  }

  return s;
}

function toJdbcUrl(connectString) {
  let s = String(connectString || '').trim();
  if (!s) return '';
  if (/^jdbc:oracle:/i.test(s)) return s.replace(/\s+/g, s.includes('(') ? '' : ' ').trim();
  const normalized = s.replace(/^jdbc:oracle:thin:@/i, '');
  if (normalized.startsWith('(')) {
    return `jdbc:oracle:thin:@${normalized.replace(/\s+/g, '')}`;
  }
  // Easy connect
  const easy = toSqlPlusTarget(normalized);
  return easy ? `jdbc:oracle:thin:@${easy}` : '';
}

function escapeSqlLiteral(v) {
  return String(v == null ? '' : v).replace(/'/g, "''");
}

async function runSqlPlus({ sqlplusPath, user, password, target, sqlBody, timeoutMs = 30000 }) {
  const dir = fs.mkdtempSync(path.join(os.tmpdir(), 'netscan-ora-'));
  const scriptPath = path.join(dir, 'q.sql');
  const outPath = path.join(dir, 'out.txt');

  const script = [
    'SET PAGESIZE 50000',
    'SET LINESIZE 32767',
    'SET LONG 100000',
    'SET LONGCHUNKSIZE 100000',
    'SET FEEDBACK OFF',
    'SET VERIFY OFF',
    'SET HEADING OFF',
    'SET ECHO OFF',
    'SET COLSEP |',
    'SET TRIMSPOOL ON',
    'SET TRIMOUT ON',
    `SPOOL ${outPath}`,
    sqlBody.trim(),
    'SPOOL OFF',
    'EXIT'
  ].join('\n');

  fs.writeFileSync(scriptPath, script, 'utf8');

  const connect = `${user}/${password}@${target}`;
  try {
    const { stdout, stderr } = await execFileAsync(
      sqlplusPath,
      ['-L', '-S', connect, `@${scriptPath}`],
      {
        timeout: timeoutMs,
        windowsHide: true,
        encoding: 'utf8',
        maxBuffer: 20 * 1024 * 1024
      }
    );

    let out = '';
    if (fs.existsSync(outPath)) out = fs.readFileSync(outPath, 'utf8');
    const combined = `${out}\n${stdout || ''}\n${stderr || ''}`;

    if (/ORA-\d{5}|SP2-\d{4}|TNS-|invalid username|ERROR:/i.test(combined) &&
        !/OK\|/.test(combined) && !/__ROW__/i.test(combined)) {
      const m = combined.match(/ORA-\d{5}[^\r\n]*/i) ||
        combined.match(/SP2-\d{4}[^\r\n]*/i) ||
        combined.match(/TNS-[^\r\n]*/i);
      const err = new Error((m && m[0]) || 'Falha sqlplus Oracle');
      err.code = 'ORACLE_SQLPLUS';
      err.detail = combined.slice(0, 800);
      throw err;
    }

    return { out: out || stdout || '', raw: combined };
  } finally {
    try { fs.rmSync(dir, { recursive: true, force: true }); } catch { /* ignore */ }
  }
}

async function testWithSqlPlus(cfg) {
  const sqlplusPath = findSqlPlus(cfg);
  if (!sqlplusPath) {
    const err = new Error('sqlplus.exe não encontrado');
    err.code = 'ORACLE_SQLPLUS';
    throw err;
  }
  const target = toSqlPlusTarget(cfg.connectString);
  if (!target) {
    const err = new Error('Connect string inválida para sqlplus');
    err.code = 'ORACLE_CONFIG';
    throw err;
  }

  const { out } = await runSqlPlus({
    sqlplusPath,
    user: cfg.user,
    password: cfg.password,
    target,
    sqlBody: "SELECT 'OK|' || TO_CHAR(SYSDATE,'YYYY-MM-DD HH24:MI:SS') FROM DUAL;"
  });

  const line = String(out).split(/\r?\n/).map((l) => l.trim()).find((l) => l.startsWith('OK|'));
  if (!line) {
    const err = new Error('Teste sqlplus sem resposta OK');
    err.code = 'ORACLE_SQLPLUS';
    err.detail = out.slice(0, 500);
    throw err;
  }
  return {
    ok: true,
    message: 'Conexão Oracle OK (sqlplus)',
    driver: 'sqlplus',
    target,
    sample: { OK: 1, WHEN: line.split('|')[1] || null }
  };
}

async function queryUsersWithSqlPlus(cfg, { mode, pattern }) {
  const sqlplusPath = findSqlPlus(cfg);
  if (!sqlplusPath) {
    const err = new Error('sqlplus.exe não encontrado');
    err.code = 'ORACLE_SQLPLUS';
    throw err;
  }
  const target = toSqlPlusTarget(cfg.connectString);
  const table = cfg.table || 'dbasgu.usuarios';
  const maxRows = cfg.maxRows || 50;
  const pat = escapeSqlLiteral(String(pattern || '').toUpperCase());

  let where;
  if (mode === 'name') {
    where = `UPPER(u.nm_usuario) LIKE '${pat}'`;
  } else if (mode === 'code') {
    where = `UPPER(u.cd_usuario) LIKE '${pat}'`;
  } else {
    where = `(UPPER(u.nm_usuario) LIKE '${pat}' OR UPPER(u.cd_usuario) LIKE '${pat}')`;
  }

  // Marcadores para parse estável
  const sqlBody = `
SELECT '__ROW__|' || NVL(u.cd_usuario,'') || '|' || REPLACE(REPLACE(NVL(u.nm_usuario,''), CHR(10), ' '), '|', '/')
FROM (
  SELECT u.cd_usuario, u.nm_usuario
  FROM ${table} u
  WHERE ${where}
  ORDER BY u.nm_usuario
) u
WHERE ROWNUM <= ${Number(maxRows)};
`;

  const { out } = await runSqlPlus({
    sqlplusPath,
    user: cfg.user,
    password: cfg.password,
    target,
    sqlBody,
    timeoutMs: 45000
  });

  const rows = [];
  for (const line of String(out).split(/\r?\n/)) {
    const t = line.trim();
    if (!t.startsWith('__ROW__|')) continue;
    const parts = t.split('|');
    // __ROW__ | cd | nm...
    const cd = parts[1] || '';
    const nm = parts.slice(2).join('|') || '';
    rows.push({ CD_USUARIO: cd, NM_USUARIO: nm });
  }

  return { rows, target, driver: 'sqlplus' };
}

module.exports = {
  findSqlPlus,
  toSqlPlusTarget,
  toJdbcUrl,
  testWithSqlPlus,
  queryUsersWithSqlPlus,
  DEFAULT_SQLPLUS
};

import java.io.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.sql.*;
import java.util.*;

/**
 * Bridge JDBC para Oracle 11g usando ojdbc*.jar local (sem Instant Client 64-bit).
 * Entrada: arquivo JSON (caminho em args[0])
 * Saída: JSON em stdout
 */
public class OracleJdbcBridge {
  public static void main(String[] args) {
    try {
      if (args.length < 1) {
        fail("Uso: OracleJdbcBridge <request.json>");
        return;
      }
      String raw = new String(Files.readAllBytes(Paths.get(args[0])), StandardCharsets.UTF_8);
      Map<String, Object> req = parseFlatJson(raw);
      String action = str(req.get("action"));
      String url = str(req.get("url"));
      String user = str(req.get("user"));
      String password = str(req.get("password"));

      if (url.isEmpty() || user.isEmpty()) {
        fail("url/user obrigatórios");
        return;
      }

      Class.forName("oracle.jdbc.OracleDriver");
      try (Connection conn = DriverManager.getConnection(url, user, password)) {
        if ("test".equalsIgnoreCase(action)) {
          try (Statement st = conn.createStatement();
               ResultSet rs = st.executeQuery("SELECT 1 AS OK FROM DUAL")) {
            Map<String, Object> sample = null;
            if (rs.next()) sample = rowToMap(rs);
            okTest(sample);
          }
          return;
        }

        if ("query".equalsIgnoreCase(action)) {
          String sql = str(req.get("sql"));
          @SuppressWarnings("unchecked")
          List<String> binds = (List<String>) req.get("binds");
          if (binds == null) binds = Collections.emptyList();
          if (sql.isEmpty()) {
            fail("sql obrigatório");
            return;
          }
          try (PreparedStatement ps = conn.prepareStatement(sql)) {
            for (int i = 0; i < binds.size(); i++) {
              ps.setString(i + 1, binds.get(i));
            }
            try (ResultSet rs = ps.executeQuery()) {
              List<Map<String, Object>> rows = new ArrayList<Map<String, Object>>();
              while (rs.next()) rows.add(rowToMap(rs));
              okQuery(rows);
            }
          }
          return;
        }

        fail("action inválida: " + action);
      }
    } catch (Throwable t) {
      fail(t.getMessage() == null ? t.toString() : t.getMessage());
    }
  }

  static Map<String, Object> rowToMap(ResultSet rs) throws SQLException {
    ResultSetMetaData md = rs.getMetaData();
    int n = md.getColumnCount();
    Map<String, Object> row = new LinkedHashMap<String, Object>();
    for (int i = 1; i <= n; i++) {
      String label = md.getColumnLabel(i);
      Object val = rs.getObject(i);
      if (val == null) row.put(label, null);
      else if (val instanceof java.sql.Date || val instanceof java.sql.Timestamp || val instanceof java.util.Date)
        row.put(label, val.toString());
      else if (val instanceof Number || val instanceof Boolean) row.put(label, val);
      else row.put(label, String.valueOf(val));
    }
    return row;
  }

  static void okTest(Map<String, Object> sample) {
    StringBuilder sb = new StringBuilder();
    sb.append("{\"ok\":true,\"message\":\"Conexão Oracle OK (JDBC)\",\"driver\":\"jdbc\"");
    if (sample != null) {
      sb.append(",\"sample\":");
      sb.append(toJson(sample));
    }
    sb.append("}");
    System.out.println(sb.toString());
  }

  static void okQuery(List<Map<String, Object>> rows) {
    StringBuilder sb = new StringBuilder();
    sb.append("{\"ok\":true,\"driver\":\"jdbc\",\"count\":").append(rows.size()).append(",\"rows\":[");
    for (int i = 0; i < rows.size(); i++) {
      if (i > 0) sb.append(',');
      sb.append(toJson(rows.get(i)));
    }
    sb.append("]}");
    System.out.println(sb.toString());
  }

  static void fail(String msg) {
    System.out.println("{\"ok\":false,\"error\":" + quote(msg) + "}");
  }

  static String toJson(Map<String, Object> map) {
    StringBuilder sb = new StringBuilder();
    sb.append('{');
    boolean first = true;
    for (Map.Entry<String, Object> e : map.entrySet()) {
      if (!first) sb.append(',');
      first = false;
      sb.append(quote(e.getKey())).append(':');
      Object v = e.getValue();
      if (v == null) sb.append("null");
      else if (v instanceof Number || v instanceof Boolean) sb.append(String.valueOf(v));
      else sb.append(quote(String.valueOf(v)));
    }
    sb.append('}');
    return sb.toString();
  }

  static String quote(String s) {
    if (s == null) return "null";
    StringBuilder sb = new StringBuilder("\"");
    for (int i = 0; i < s.length(); i++) {
      char c = s.charAt(i);
      switch (c) {
        case '\\': sb.append("\\\\"); break;
        case '"': sb.append("\\\""); break;
        case '\n': sb.append("\\n"); break;
        case '\r': sb.append("\\r"); break;
        case '\t': sb.append("\\t"); break;
        default:
          if (c < 0x20) sb.append(String.format("\\u%04x", (int) c));
          else sb.append(c);
      }
    }
    sb.append('"');
    return sb.toString();
  }

  static String str(Object o) {
    return o == null ? "" : String.valueOf(o).trim();
  }

  /**
   * Parser mínimo para JSON flat gerado pelo Node:
   * { "action":"...", "url":"...", "user":"...", "password":"...", "sql":"...", "binds":["a","b"] }
   */
  @SuppressWarnings("unchecked")
  static Map<String, Object> parseFlatJson(String raw) {
    Map<String, Object> out = new HashMap<String, Object>();
    String s = raw.trim();
    if (s.startsWith("{")) s = s.substring(1);
    if (s.endsWith("}")) s = s.substring(0, s.length() - 1);

    // Extrai binds array primeiro
    int bindsIdx = indexOfKey(s, "binds");
    if (bindsIdx >= 0) {
      int colon = s.indexOf(':', bindsIdx);
      int lb = s.indexOf('[', colon);
      int rb = findMatching(s, lb, '[', ']');
      if (lb >= 0 && rb > lb) {
        String arr = s.substring(lb + 1, rb);
        List<String> binds = new ArrayList<String>();
        for (String part : splitTopLevel(arr, ',')) {
          String p = part.trim();
          if (p.isEmpty()) continue;
          binds.add(unquote(p));
        }
        out.put("binds", binds);
        s = s.substring(0, bindsIdx) + s.substring(Math.min(s.length(), rb + 1));
      }
    }

    for (String part : splitTopLevel(s, ',')) {
      String p = part.trim();
      if (p.isEmpty()) continue;
      int colon = findTopColon(p);
      if (colon < 0) continue;
      String key = unquote(p.substring(0, colon).trim());
      String val = p.substring(colon + 1).trim();
      if ("null".equals(val)) out.put(key, null);
      else out.put(key, unquote(val));
    }
    return out;
  }

  static int indexOfKey(String s, String key) {
    String pat = "\"" + key + "\"";
    return s.indexOf(pat);
  }

  static int findMatching(String s, int openIdx, char open, char close) {
    if (openIdx < 0) return -1;
    int depth = 0;
    boolean inStr = false;
    for (int i = openIdx; i < s.length(); i++) {
      char c = s.charAt(i);
      if (c == '"' && (i == 0 || s.charAt(i - 1) != '\\')) inStr = !inStr;
      if (inStr) continue;
      if (c == open) depth++;
      else if (c == close) {
        depth--;
        if (depth == 0) return i;
      }
    }
    return -1;
  }

  static int findTopColon(String s) {
    boolean inStr = false;
    for (int i = 0; i < s.length(); i++) {
      char c = s.charAt(i);
      if (c == '"' && (i == 0 || s.charAt(i - 1) != '\\')) inStr = !inStr;
      if (!inStr && c == ':') return i;
    }
    return -1;
  }

  static List<String> splitTopLevel(String s, char sep) {
    List<String> parts = new ArrayList<String>();
    StringBuilder cur = new StringBuilder();
    boolean inStr = false;
    int depth = 0;
    for (int i = 0; i < s.length(); i++) {
      char c = s.charAt(i);
      if (c == '"' && (i == 0 || s.charAt(i - 1) != '\\')) inStr = !inStr;
      if (!inStr) {
        if (c == '[' || c == '{') depth++;
        if (c == ']' || c == '}') depth--;
        if (c == sep && depth == 0) {
          parts.add(cur.toString());
          cur.setLength(0);
          continue;
        }
      }
      cur.append(c);
    }
    parts.add(cur.toString());
    return parts;
  }

  static String unquote(String s) {
    s = s.trim();
    if (s.length() >= 2 && s.startsWith("\"") && s.endsWith("\"")) {
      StringBuilder sb = new StringBuilder();
      for (int i = 1; i < s.length() - 1; i++) {
        char c = s.charAt(i);
        if (c == '\\' && i + 1 < s.length() - 1) {
          char n = s.charAt(++i);
          switch (n) {
            case 'n': sb.append('\n'); break;
            case 'r': sb.append('\r'); break;
            case 't': sb.append('\t'); break;
            case '"': sb.append('"'); break;
            case '\\': sb.append('\\'); break;
            case 'u':
              if (i + 4 < s.length() - 1) {
                String hex = s.substring(i + 1, i + 5);
                sb.append((char) Integer.parseInt(hex, 16));
                i += 4;
              }
              break;
            default: sb.append(n);
          }
        } else sb.append(c);
      }
      return sb.toString();
    }
    return s;
  }
}

const express = require('express');
const { loadPlatformConfig, savePlatformConfig, getActiveSite } = require('./platformConfig');
const { getDriftReport } = require('./networkDrift');
const { correlateHost, correlateScanResults } = require('./assetCorrelation');
const { scanTlsForHosts } = require('./tlsCertScan');
const { assessNacReadiness, assessNacForScan } = require('./nacReadiness');
const { deepFingerprintScan } = require('./deepFingerprint');
const { passiveDiscoverySnapshot } = require('./passiveDiscovery');
const { ingestAgentReport, listAgentReports } = require('./canonAgent');
const { listAssets, setAssetState, STATES } = require('./assetLifecycle');
const { buildDailyReport, runScheduledReport } = require('./scheduledReports');
const { dispatchWebhook } = require('./webhookDispatcher');
const { requirePlatformAuth, getPublicRbacInfo } = require('./canonRbac');
const { isFeatureEnabled } = require('./platformConfig');

function mountPlatformRoutes(app, ctx = {}) {
  const router = express.Router();
  const getResults = () => (typeof ctx.getLastScanSnapshot === 'function' ? ctx.getLastScanSnapshot() : []);

  if (typeof ctx.requireModalsAuth === 'function') {
    router.use((req, res, next) => {
      // Etapa 5 — agente nas estações envia report sem login Canon UI
      if (req.method === 'POST' && req.path === '/agent/report') return next();
      return ctx.requireModalsAuth(req, res, next);
    });
  }

  router.get('/health', (req, res) => {
    res.json({ ok: true, service: 'NetScan Canon Platform', version: 1 });
  });

  router.get('/config', requirePlatformAuth('platform.read'), (req, res) => {
    res.json({ ok: true, config: loadPlatformConfig(), rbac: getPublicRbacInfo() });
  });

  router.put('/config', requirePlatformAuth('platform.admin'), (req, res) => {
    try {
      const saved = savePlatformConfig(req.body || {});
      res.json({ ok: true, config: saved });
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/sites', requirePlatformAuth('platform.read'), (req, res) => {
    const cfg = loadPlatformConfig();
    res.json({ ok: true, activeSiteId: cfg.activeSiteId, sites: cfg.sites || [] });
  });

  router.put('/sites/active', requirePlatformAuth('platform.admin'), (req, res) => {
    const id = String(req.body?.siteId || '').trim();
    const cfg = loadPlatformConfig();
    if (!(cfg.sites || []).some((s) => s.id === id)) {
      return res.status(400).json({ ok: false, error: 'Site não encontrado.' });
    }
    res.json({ ok: true, config: savePlatformConfig({ activeSiteId: id }) });
  });

  router.get('/v1/hosts', requirePlatformAuth('platform.read'), (req, res) => {
    const results = getResults();
    res.json({ ok: true, updatedAt: Date.now(), count: results.length, hosts: results });
  });

  router.get('/drift', requirePlatformAuth('platform.drift'), (req, res) => {
    if (!isFeatureEnabled('drift')) return res.status(404).json({ ok: false, error: 'Drift desabilitado.' });
    res.json(getDriftReport());
  });

  router.get('/correlation', requirePlatformAuth('platform.correlation'), async (req, res) => {
    if (!isFeatureEnabled('correlation')) return res.status(404).json({ ok: false, error: 'Correlação desabilitada.' });
    try {
      const ip = req.query.ip;
      const results = getResults();
      if (ip) {
        const host = results.find((h) => h.ip === ip) || { ip };
        return res.json(await correlateHost(host, {
          switchIp: req.query.switchIp,
          community: req.query.community
        }));
      }
      const out = await correlateScanResults(results, {
        maxHosts: Number(req.query.limit) || 25,
        switchIp: req.query.switchIp,
        community: req.query.community,
        includeInactive: req.query.includeInactive === '1'
      });
      res.json(out);
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.post('/tls-scan', requirePlatformAuth('platform.read'), async (req, res) => {
    if (!isFeatureEnabled('tlsScan')) return res.status(404).json({ ok: false, error: 'TLS scan desabilitado.' });
    try {
      const ips = req.body?.ips || req.body?.hosts;
      const hosts = ips || getResults();
      const out = await scanTlsForHosts(hosts, {
        ports: req.body?.ports || [443],
        maxHosts: Number(req.body?.maxHosts) || 32,
        timeoutMs: Number(req.body?.timeoutMs) || 5000
      });
      res.json(out);
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/nac', requirePlatformAuth('platform.read'), async (req, res) => {
    if (!isFeatureEnabled('nacReadiness')) return res.status(404).json({ ok: false, error: 'NAC desabilitado.' });
    try {
      const ip = req.query.ip;
      const results = getResults();
      if (ip) {
        const host = results.find((h) => h.ip === ip) || { ip };
        return res.json(await assessNacReadiness(host));
      }
      res.json(await assessNacForScan(results, { maxHosts: Number(req.query.limit) || 40 }));
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/fingerprint', requirePlatformAuth('platform.read'), (req, res) => {
    if (!isFeatureEnabled('deepFingerprint')) return res.status(404).json({ ok: false, error: 'Fingerprint desabilitado.' });
    res.json(deepFingerprintScan(getResults(), Number(req.query.limit) || 100));
  });

  router.get('/passive', requirePlatformAuth('platform.read'), async (req, res) => {
    if (!isFeatureEnabled('passiveDiscovery')) return res.status(404).json({ ok: false, error: 'Passivo desabilitado.' });
    try {
      res.json(await passiveDiscoverySnapshot());
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/lifecycle', requirePlatformAuth('platform.lifecycle'), (req, res) => {
    if (!isFeatureEnabled('assetLifecycle')) return res.status(404).json({ ok: false, error: 'Lifecycle desabilitado.' });
    res.json(listAssets({ state: req.query.state }));
  });

  router.put('/lifecycle/:ip', requirePlatformAuth('platform.lifecycle'), (req, res) => {
    if (!isFeatureEnabled('assetLifecycle')) return res.status(404).json({ ok: false, error: 'Lifecycle desabilitado.' });
    const result = setAssetState(req.params.ip, req.body?.state, {
      note: req.body?.note,
      operator: req.body?.operator,
      hostname: req.body?.hostname
    });
    if (!result.ok) return res.status(400).json(result);
    res.json(result);
  });

  router.get('/lifecycle/states', (req, res) => {
    res.json({ ok: true, states: STATES });
  });

  router.post('/agent/report', (req, res) => {
    if (!isFeatureEnabled('canonAgent')) return res.status(404).json({ ok: false, error: 'Agent desabilitado.' });
    const result = ingestAgentReport(req.body || {}, { agentVersion: req.headers['x-canon-agent-version'] });
    if (!result.ok) return res.status(400).json(result);
    dispatchWebhook('agent.report', { hostname: result.report.hostname, ip: result.report.ip }).catch(() => {});
    res.json(result);
  });

  router.get('/agent/reports', requirePlatformAuth('platform.read'), (req, res) => {
    res.json(listAgentReports(Number(req.query.limit) || 50));
  });

  router.get('/reports/daily', requirePlatformAuth('platform.read'), (req, res) => {
    res.json(buildDailyReport(getResults));
  });

  router.post('/reports/run', requirePlatformAuth('platform.admin'), async (req, res) => {
    try {
      res.json(await runScheduledReport({ getLastScanSnapshot: getResults }));
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.post('/webhooks/test', requirePlatformAuth('platform.admin'), async (req, res) => {
    try {
      res.json(await dispatchWebhook(req.body?.event || 'test.ping', { message: 'NetScan Canon webhook test' }));
    } catch (err) {
      res.status(500).json({ ok: false, error: err.message });
    }
  });

  router.get('/summary', requirePlatformAuth('platform.read'), async (req, res) => {
    const results = getResults();
    const cfg = loadPlatformConfig();
    const drift = isFeatureEnabled('drift') ? getDriftReport() : null;
    const lifecycle = isFeatureEnabled('assetLifecycle') ? listAssets() : null;
    let passive = null;
    if (isFeatureEnabled('passiveDiscovery')) {
      try { passive = await passiveDiscoverySnapshot(); } catch { /* ignore */ }
    }
    res.json({
      ok: true,
      site: getActiveSite(),
      features: cfg.features,
      scan: { total: results.length, active: results.filter((h) => h.status === 'Ativo').length },
      drift: drift?.drift?.summary || null,
      lifecycle: lifecycle ? { total: lifecycle.count } : null,
      passive: passive ? { count: passive.count } : null
    });
  });

  app.use('/api/platform', router);
}

