const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, 'data');
const BASELINE_FILE = path.join(DATA_DIR, 'network-baselines.json');
const MAX_SNAPSHOTS = 50;

function ensureStore() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
}

function loadBaselines() {
  ensureStore();
  if (!fs.existsSync(BASELINE_FILE)) {
    return { version: 1, snapshots: [] };
  }
  try {
    const raw = JSON.parse(fs.readFileSync(BASELINE_FILE, 'utf8'));
    return { version: 1, snapshots: Array.isArray(raw.snapshots) ? raw.snapshots : [] };
  } catch {
    return { version: 1, snapshots: [] };
  }
}

function saveBaselines(store) {
  ensureStore();
  const tmp = `${BASELINE_FILE}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(store, null, 2), 'utf8');
  fs.renameSync(tmp, BASELINE_FILE);
}

function hostFingerprint(h) {
  if (!h || !h.ip) return null;
  return {
    ip: h.ip,
    status: h.status || h.lastStatus || 'Desconhecido',
    hostname: h.hostname || 'N/A',
    mac: h.mac || 'N/A',
    os: h.os || 'N/A',
    deviceType: h.deviceType || 'N/A',
    vlan: h.vlan || h.vlanId || null,
    adDomain: h.adDomain || null
  };
}

function recordScanSnapshot(results, meta = {}) {
  const list = Array.isArray(results) ? results : [];
  const snap = {
    id: `snap_${Date.now()}`,
    at: Date.now(),
    atIso: new Date().toISOString(),
    target: meta.target || null,
    siteId: meta.siteId || 'default',
    total: list.length,
    active: list.filter((h) => h.status === 'Ativo').length,
    hosts: list.map(hostFingerprint).filter(Boolean)
  };

  const store = loadBaselines();
  store.snapshots.unshift(snap);
  store.snapshots = store.snapshots.slice(0, MAX_SNAPSHOTS);
  saveBaselines(store);
  return snap;
}

function compareSnapshots(prev, curr) {
  const prevMap = new Map((prev?.hosts || []).map((h) => [h.ip, h]));
  const currMap = new Map((curr?.hosts || []).map((h) => [h.ip, h]));

  const added = [];
  const removed = [];
  const changed = [];

  for (const [ip, cur] of currMap) {
    const old = prevMap.get(ip);
    if (!old) {
      added.push({ ip, host: cur });
      continue;
    }
    const diffs = [];
    for (const key of ['hostname', 'mac', 'os', 'deviceType', 'vlan', 'status', 'adDomain']) {
      const a = String(old[key] ?? '');
      const b = String(cur[key] ?? '');
      if (a !== b && !(a === 'N/A' && b === 'N/A')) {
        diffs.push({ field: key, before: old[key], after: cur[key] });
      }
    }
    if (diffs.length) changed.push({ ip, before: old, after: cur, diffs });
  }

  for (const [ip, old] of prevMap) {
    if (!currMap.has(ip)) removed.push({ ip, host: old });
  }

  return {
    added,
    removed,
    changed,
    summary: {
      added: added.length,
      removed: removed.length,
      changed: changed.length
    }
  };
}

function getDriftReport() {
  const store = loadBaselines();
  const snapshots = store.snapshots || [];
  if (snapshots.length < 2) {
    return {
      ok: true,
      hasBaseline: snapshots.length >= 1,
      message: snapshots.length === 0
        ? 'Nenhuma varredura registrada ainda.'
        : 'Apenas uma varredura registrada — execute outra para ver drift.',
      snapshots: snapshots.slice(0, 10),
      drift: null
    };
  }

  const current = snapshots[0];
  const previous = snapshots[1];
  const drift = compareSnapshots(previous, current);

  return {
    ok: true,
    hasBaseline: true,
    current,
    previous,
    drift,
    snapshots: snapshots.slice(0, 10)
  };
}

module.exports = {
  BASELINE_FILE,
  recordScanSnapshot,
  getDriftReport,
  compareSnapshots,
  hostFingerprint
};

const { lookupAdUser } = require('./adUserAudit');
const autoTest = require('./autoTest');
const { getActiveSite } = require('./platformConfig');

async function correlateHost(host, options = {}) {
  const ip = host?.ip;
  if (!ip) return { ok: false, error: 'Host sem IP' };

  const site = getActiveSite();
  const switchIp = options.switchIp || site?.switchIp || null;
  const community = options.community || site?.snmpCommunity || 'public';

  const result = {
    ok: true,
    ip,
    hostname: host.hostname || 'N/A',
    mac: host.mac || null,
    os: host.os || null,
    deviceType: host.deviceType || null,
    vlan: host.vlan || host.vlanId || null,
    ad: null,
    switch: null,
    correlationScore: 0
  };

  const adLogin = host.adSamAccountName || host.adUser || host.hostname?.split('.')?.[0];
  if (adLogin && adLogin !== 'N/A') {
    try {
      const ad = await lookupAdUser(adLogin);
      if (ad.ok && ad.user) {
        result.ad = {
          sAMAccountName: ad.user.sAMAccountName,
          displayName: ad.user.displayName,
          department: ad.user.department,
          disabled: ad.user.disabled,
          groupCount: ad.user.groupCount,
          lastLogon: ad.user.lastLogon
        };
        result.correlationScore += 40;
      }
    } catch { /* ignore */ }
  }

  if (host.adDomain) {
    result.ad = result.ad || { domain: host.adDomain };
    result.correlationScore += 10;
  }

  if (switchIp && result.mac) {
    try {
      const step = await autoTest.discoverSwitchOnly(switchIp, community, options.timeoutMs || 8000, result.mac);
      const cp = step?.connectedPort;
      if (cp) {
        result.switch = {
          switchIp,
          port: cp.portName,
          ifIndex: cp.ifIndex,
          stpState: cp.stpLabel || null,
          neighbors: step?.neighbors || [],
          detail: step?.detail || null
        };
        result.correlationScore += 50;
      } else {
        result.switch = { switchIp, polled: true, detail: step?.detail || 'MAC não encontrado na FDB' };
        result.correlationScore += 15;
      }
    } catch (err) {
      result.switch = { switchIp, error: err.message };
    }
  }

  if (result.hostname && result.hostname !== 'N/A') result.correlationScore += 10;
  if (result.vlan) result.correlationScore += 10;

  return result;
}

async function correlateScanResults(results, options = {}) {
  const hosts = (Array.isArray(results) ? results : [])
    .filter((h) => h?.status === 'Ativo' || options.includeInactive)
    .slice(0, options.maxHosts || 40);

  const correlated = [];
  for (const host of hosts) {
    correlated.push(await correlateHost(host, options));
  }

  return {
    ok: true,
    site: getActiveSite(),
    count: correlated.length,
    hosts: correlated
  };
}

module.exports = { correlateHost, correlateScanResults };

const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, 'data');
const LIFECYCLE_FILE = path.join(DATA_DIR, 'asset-lifecycle.json');

const STATES = ['ativo', 'ocioso', 'quarentena', 'liberado', 'desconhecido'];

function ensureStore() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
}

function loadLifecycle() {
  ensureStore();
  if (!fs.existsSync(LIFECYCLE_FILE)) {
    return { version: 1, updatedAt: null, assets: {} };
  }
  try {
    return JSON.parse(fs.readFileSync(LIFECYCLE_FILE, 'utf8'));
  } catch {
    return { version: 1, updatedAt: null, assets: {} };
  }
}

function saveLifecycle(store) {
  ensureStore();
  store.updatedAt = new Date().toISOString();
  const tmp = `${LIFECYCLE_FILE}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(store, null, 2), 'utf8');
  fs.renameSync(tmp, LIFECYCLE_FILE);
}

function getAsset(ip) {
  const store = loadLifecycle();
  return store.assets?.[ip] || null;
}

function setAssetState(ip, state, meta = {}) {
  if (!ip) return { ok: false, error: 'IP inválido' };
  const normalized = String(state || '').toLowerCase();
  if (!STATES.includes(normalized)) {
    return { ok: false, error: `Estado inválido. Use: ${STATES.join(', ')}` };
  }

  const store = loadLifecycle();
  const prev = store.assets[ip] || { ip, history: [] };
  const entry = {
    ip,
    state: normalized,
    note: meta.note || null,
    operator: meta.operator || null,
    updatedAt: new Date().toISOString(),
    hostname: meta.hostname || prev.hostname || null,
    history: Array.isArray(prev.history) ? prev.history : []
  };
  entry.history.unshift({
    at: entry.updatedAt,
    from: prev.state || null,
    to: normalized,
    note: meta.note || null,
    operator: meta.operator || null
  });
  entry.history = entry.history.slice(0, 30);
  store.assets[ip] = entry;
  saveLifecycle(store);
  return { ok: true, asset: entry };
}

function syncFromScanResults(results) {
  const store = loadLifecycle();
  let updated = 0;
  for (const h of (Array.isArray(results) ? results : [])) {
    if (!h?.ip) continue;
    const cur = store.assets[h.ip];
    const inferred = h.status === 'Ativo' ? 'ativo' : (h.status === 'Inativo' ? 'ocioso' : 'desconhecido');
    if (!cur) {
      store.assets[h.ip] = {
        ip: h.ip,
        state: inferred,
        hostname: h.hostname || null,
        updatedAt: new Date().toISOString(),
        auto: true,
        history: [{ at: new Date().toISOString(), from: null, to: inferred, note: 'auto: scan', operator: 'system' }]
      };
      updated++;
    } else if (cur.auto !== false && !['quarentena', 'liberado'].includes(cur.state)) {
      if (cur.state !== inferred) {
        cur.history = cur.history || [];
        cur.history.unshift({ at: new Date().toISOString(), from: cur.state, to: inferred, note: 'auto: scan', operator: 'system' });
        cur.history = cur.history.slice(0, 30);
        cur.state = inferred;
        cur.updatedAt = new Date().toISOString();
        updated++;
      }
      cur.hostname = h.hostname || cur.hostname;
    }
  }
  if (updated > 0) saveLifecycle(store);
  return { ok: true, updated, total: Object.keys(store.assets).length };
}

function listAssets(filter = {}) {
  const store = loadLifecycle();
  let assets = Object.values(store.assets || {});
  if (filter.state) {
    assets = assets.filter((a) => a.state === String(filter.state).toLowerCase());
  }
  assets.sort((a, b) => (b.updatedAt || '').localeCompare(a.updatedAt || ''));
  return { ok: true, count: assets.length, assets, states: STATES };
}

module.exports = {
  LIFECYCLE_FILE,
  STATES,
  getAsset,
  setAssetState,
  syncFromScanResults,
  listAssets
};

const { loadPlatformConfig } = require('./platformConfig');

async function assessNacReadiness(host) {
  const cfg = loadPlatformConfig();
  const nacCfg = cfg.nac || {};
  const expectedVlans = nacCfg.expectedVlanIds || [];
  const quarantineVlans = nacCfg.quarantineVlanIds || [];

  const result = {
    ok: true,
    ip: host?.ip || null,
    hostname: host?.hostname || null,
    checks: [],
    score: 0,
    maxScore: 0,
    grade: '—'
  };

  const addCheck = (id, label, pass, detail, weight = 10) => {
    result.maxScore += weight;
    if (pass) result.score += weight;
    result.checks.push({ id, label, pass, detail, weight });
  };

  const vlanId = host?.vlan || host?.vlanId || null;
  if (expectedVlans.length) {
    addCheck('vlan-expected', 'VLAN esperada', expectedVlans.includes(Number(vlanId)), `VLAN observada: ${vlanId ?? '—'}`, 20);
  } else {
    addCheck('vlan-present', 'VLAN identificada', vlanId != null, vlanId != null ? `VLAN ${vlanId}` : 'Sem VLAN na NIC/scan', 10);
  }

  if (quarantineVlans.length) {
    addCheck('vlan-not-quarantine', 'Fora de quarentena', !quarantineVlans.includes(Number(vlanId)), `VLAN ${vlanId ?? '—'}`, 20);
  }

  addCheck('ad-enriched', 'Enriquecimento AD', !!(host?.adDomain || host?.adSamAccountName), host?.adDomain || host?.adSamAccountName || 'Sem dados AD', 15);
  addCheck('hostname', 'Hostname resolvido', !!(host?.hostname && host.hostname !== 'N/A'), host?.hostname || '—', 10);
  addCheck('mac-known', 'MAC conhecido', !!(host?.mac && host.mac !== 'N/A'), host?.mac || '—', 10);

  const pct = result.maxScore ? Math.round((result.score / result.maxScore) * 100) : 0;
  result.pct = pct;
  if (pct >= 85) result.grade = 'A';
  else if (pct >= 70) result.grade = 'B';
  else if (pct >= 50) result.grade = 'C';
  else result.grade = 'D';

  return result;
}

async function assessNacForScan(results, options = {}) {
  const hosts = (Array.isArray(results) ? results : []).filter((h) => h?.ip).slice(0, options.maxHosts || 50);
  const assessments = [];
  for (const h of hosts) {
    assessments.push(await assessNacReadiness(h, options));
  }
  return { ok: true, count: assessments.length, assessments };
}

module.exports = { assessNacReadiness, assessNacForScan };

const tls = require('tls');
const net = require('net');

function parseCertSubject(cert) {
  if (!cert?.subject) return null;
  const s = cert.subject;
  return s.CN || s.O || Object.values(s)[0] || null;
}

function daysUntil(isoDate) {
  if (!isoDate) return null;
  const d = new Date(isoDate);
  if (Number.isNaN(d.getTime())) return null;
  return Math.ceil((d.getTime() - Date.now()) / (24 * 60 * 60 * 1000));
}

function scanTlsCert(host, port = 443, timeoutMs = 5000) {
  return new Promise((resolve) => {
    const started = Date.now();
    let settled = false;
    const finish = (result) => {
      if (settled) return;
      settled = true;
      try { socket.destroy(); } catch { /* ignore */ }
      resolve({ ...result, ms: Date.now() - started });
    };

    const socket = tls.connect({
      host,
      port,
      servername: host,
      rejectUnauthorized: false,
      timeout: timeoutMs
    });

    socket.on('secureConnect', () => {
      try {
        const cert = socket.getPeerCertificate(true);
        const validFrom = cert?.valid_from ? new Date(cert.valid_from).toISOString() : null;
        const validTo = cert?.valid_to ? new Date(cert.valid_to).toISOString() : null;
        const daysLeft = daysUntil(validTo);
        const ok = daysLeft != null && daysLeft > 0;
        finish({
          ok,
          host,
          port,
          subject: parseCertSubject(cert),
          issuer: cert?.issuer?.O || cert?.issuer?.CN || null,
          validFrom,
          validTo,
          daysLeft,
          san: Array.isArray(cert?.subjectaltname)
            ? cert.subjectaltname
            : (cert?.subjectaltname ? String(cert.subjectaltname).split(', ') : []),
          protocol: socket.getProtocol?.() || null,
          authorized: socket.authorized,
          authorizationError: socket.authorizationError || null
        });
      } catch (err) {
        finish({ ok: false, host, port, error: err.message });
      }
    });

    socket.on('timeout', () => finish({ ok: false, host, port, error: 'timeout' }));
    socket.on('error', (err) => finish({ ok: false, host, port, error: err.message }));
  });
}

async function scanTlsForHosts(hosts, { ports = [443], maxHosts = 32, timeoutMs = 5000 } = {}) {
  const ips = (Array.isArray(hosts) ? hosts : [])
    .map((h) => (typeof h === 'string' ? h : h?.ip))
    .filter(Boolean)
    .slice(0, maxHosts);

  const results = [];
  for (const ip of ips) {
    for (const port of ports) {
      const open = await new Promise((resolve) => {
        const s = new net.Socket();
        let done = false;
        const end = (v) => { if (!done) { done = true; try { s.destroy(); } catch { /* ignore */ } resolve(v); } };
        s.setTimeout(timeoutMs);
        s.once('connect', () => end(true));
        s.once('timeout', () => end(false));
        s.once('error', () => end(false));
        s.connect(port, ip);
      });
      if (!open) {
        results.push({ ok: false, host: ip, port, error: 'porta fechada ou filtrada' });
        continue;
      }
      results.push(await scanTlsCert(ip, port, timeoutMs));
    }
  }

  const expiring = results.filter((r) => r.ok && r.daysLeft != null && r.daysLeft <= 30);
  const failed = results.filter((r) => !r.ok);

  return {
    ok: true,
    scanned: results.length,
    expiringCount: expiring.length,
    failedCount: failed.length,
    results
  };
}

module.exports = { scanTlsCert, scanTlsForHosts };

const HTTP_SIGNATURES = {
  printer: [/ipp|print|canon|hp|epson|brother|kyocera|xerox/i, /\/ipp\//i],
  camera: [/hikvision|axis|onvif|ipcam|nvr|dvr/i],
  tv: [/webos|tizen|smarttv|roku|android tv|google tv/i],
  nas: [/synology|qnap|netgear readynas|diskstation/i],
  iot: [/mqtt|coap|esphome|tasmota|shelly/i]
};

const BANNER_HINTS = {
  ssh: { server: /openssh|libssh|dropbear/i },
  http: { server: /nginx|apache|iis|lighttpd|caddy/i }
};

function deepFingerprintHost(host) {
  const fp = {
    ip: host?.ip,
    hostname: host?.hostname || 'N/A',
    baseType: host?.deviceType || 'Host Ativo',
    signals: [],
    suggestedType: host?.deviceType || 'Host Ativo',
    confidence: 'low'
  };

  const textBlob = [
    host?.hostname, host?.os, host?.deviceType, host?.vendor,
    ...(host?.ports || []).map((p) => `${p.port} ${p.service || ''} ${p.version || ''}`)
  ].filter(Boolean).join(' ');

  for (const [type, patterns] of Object.entries(HTTP_SIGNATURES)) {
    if (patterns.some((re) => re.test(textBlob))) {
      fp.signals.push({ kind: 'signature', type, source: 'ports/banners' });
      fp.suggestedType = type.charAt(0).toUpperCase() + type.slice(1);
      fp.confidence = 'medium';
    }
  }

  for (const p of (host?.ports || [])) {
    if (p.state !== 'open') continue;
    if ([515, 631, 9100].includes(p.port)) {
      fp.signals.push({ kind: 'port', type: 'printer', port: p.port });
      fp.suggestedType = 'Impressora';
      fp.confidence = 'high';
    }
    if ([554, 8554, 37777].includes(p.port)) {
      fp.signals.push({ kind: 'port', type: 'camera', port: p.port });
      if (fp.confidence !== 'high') { fp.suggestedType = 'Câmera/NVR'; fp.confidence = 'high'; }
    }
    if ([3389].includes(p.port) && /server|windows server/i.test(textBlob)) {
      fp.signals.push({ kind: 'port', type: 'server', port: p.port });
      fp.suggestedType = 'Servidor';
      fp.confidence = 'medium';
    }
    if (p.version && p.version !== 'N/A') {
      fp.signals.push({ kind: 'banner', port: p.port, version: p.version });
    }
  }

  if (host?.vm?.isVirtual) {
    fp.signals.push({ kind: 'vm', hypervisor: host.vm.hypervisor || true });
  }
  if (host?.otReasons?.length) {
    fp.signals.push({ kind: 'ot', reasons: host.otReasons });
    fp.suggestedType = 'OT/Industrial';
    fp.confidence = 'medium';
  }

  fp.signals = fp.signals.slice(0, 12);
  return fp;
}

function deepFingerprintScan(results, maxHosts = 100) {
  const hosts = (Array.isArray(results) ? results : []).slice(0, maxHosts);
  return {
    ok: true,
    count: hosts.length,
    fingerprints: hosts.map(deepFingerprintHost)
  };
}

module.exports = { deepFingerprintHost, deepFingerprintScan };

const { execFile } = require('child_process');
const { promisify } = require('util');

const execFileAsync = promisify(execFile);

function parseArpTable(stdout) {
  const entries = [];
  const lines = String(stdout || '').split(/\r?\n/);
  for (const line of lines) {
    const m = line.match(/([0-9a-f]{2}(?:[:\-][0-9a-f]{2}){5})\s+(?:[0-9a-f\-]{36}\s+)?(\d+\.\d+\.\d+\.\d+)/i)
      || line.match(/(\d+\.\d+\.\d+\.\d+)\s+([0-9a-f]{2}(?:[:\-][0-9a-f]{2}){5})/i);
    if (!m) continue;
    let mac; let ip;
    if (m[1].includes('.')) { ip = m[1]; mac = m[2]; }
    else { mac = m[1]; ip = m[2]; }
    entries.push({ ip, mac: mac.replace(/-/g, ':').toUpperCase(), source: 'arp-cache' });
  }
  const seen = new Set();
  return entries.filter((e) => {
    if (seen.has(e.ip)) return false;
    seen.add(e.ip);
    return true;
  });
}

async function readLocalArpCache() {
  if (process.platform === 'win32') {
    const { stdout } = await execFileAsync('arp', ['-a'], { windowsHide: true, timeout: 15000, maxBuffer: 4 * 1024 * 1024 });
    return parseArpTable(stdout);
  }
  try {
    const { stdout } = await execFileAsync('ip', ['neigh', 'show'], { timeout: 15000, maxBuffer: 4 * 1024 * 1024 });
    return parseArpTable(stdout);
  } catch {
    const { stdout } = await execFileAsync('arp', ['-an'], { timeout: 15000, maxBuffer: 4 * 1024 * 1024 });
    return parseArpTable(stdout);
  }
}

async function passiveDiscoverySnapshot() {
  try {
    const entries = await readLocalArpCache();
    return {
      ok: true,
      at: new Date().toISOString(),
      source: 'local-arp-cache',
      count: entries.length,
      hosts: entries
    };
  } catch (err) {
    return { ok: false, error: err.message, hosts: [] };
  }
}

module.exports = { passiveDiscoverySnapshot, readLocalArpCache };

const fs = require('fs');
const path = require('path');
const { loadPlatformConfig, savePlatformConfig } = require('./platformConfig');
const { dispatchWebhook } = require('./webhookDispatcher');
const { getDriftReport } = require('./networkDrift');
const { listAssets } = require('./assetLifecycle');
const { getIdleHosts, parseThresholdMs } = require('./hostHistory');

const REPORT_DIR = path.join(__dirname, 'data', 'reports');

function ensureReportDir() {
  if (!fs.existsSync(REPORT_DIR)) fs.mkdirSync(REPORT_DIR, { recursive: true });
}

function buildDailyReport(getLastScanSnapshot) {
  const results = typeof getLastScanSnapshot === 'function' ? getLastScanSnapshot() : [];
  const drift = getDriftReport();
  const lifecycle = listAssets();
  const idle = getIdleHosts(parseThresholdMs({ days: 30 }) || 30 * 24 * 60 * 60 * 1000);

  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    scan: {
      total: results.length,
      active: results.filter((h) => h.status === 'Ativo').length
    },
    drift: drift.drift?.summary || null,
    lifecycle: { total: lifecycle.count, byState: lifecycle.assets.reduce((acc, a) => {
      acc[a.state] = (acc[a.state] || 0) + 1;
      return acc;
    }, {}) },
    idle: { count: (idle.hosts || []).length }
  };
}

async function runScheduledReport(ctx = {}) {
  const cfg = loadPlatformConfig();
  if (!cfg.features?.scheduledReports || !cfg.schedule?.enabled) {
    return { ok: true, skipped: true, reason: 'Agendamento desabilitado' };
  }

  const report = buildDailyReport(ctx.getLastScanSnapshot);
  ensureReportDir();
  const file = path.join(REPORT_DIR, `daily-${Date.now()}.json`);
  fs.writeFileSync(file, JSON.stringify(report, null, 2), 'utf8');

  const nextCfg = loadPlatformConfig();
  nextCfg.schedule.lastRunAt = new Date().toISOString();
  savePlatformConfig(nextCfg);

  await dispatchWebhook('report.daily', { report, file });

  return { ok: true, file, report };
}

let schedulerTimer = null;

function startScheduler(ctx = {}) {
  if (schedulerTimer) return;
  const tick = async () => {
    try {
      const cfg = loadPlatformConfig();
      if (!cfg.schedule?.enabled) return;
      const hours = Math.max(1, Number(cfg.schedule.intervalHours) || 24);
      const last = cfg.schedule.lastRunAt ? new Date(cfg.schedule.lastRunAt).getTime() : 0;
      if (Date.now() - last < hours * 60 * 60 * 1000) return;
      await runScheduledReport(ctx);
    } catch (err) {
      console.warn('[PLATFORM] scheduler tick failed:', err.message);
    }
  };
  schedulerTimer = setInterval(tick, 15 * 60 * 1000);
  schedulerTimer.unref?.();
  setTimeout(tick, 5000).unref?.();
}

module.exports = {
  REPORT_DIR,
  buildDailyReport,
  runScheduledReport,
  startScheduler
};

const http = require('http');
const https = require('https');
const { loadPlatformConfig } = require('./platformConfig');

async function dispatchWebhook(event, payload) {
  const cfg = loadPlatformConfig();
  if (!cfg.features?.webhooks) return { ok: true, dispatched: 0 };

  const hooks = (cfg.webhooks || []).filter((h) => h?.enabled && h?.url);
  let dispatched = 0;
  const results = [];

  for (const hook of hooks) {
    const events = Array.isArray(hook.events) ? hook.events : ['*'];
    if (!events.includes('*') && !events.includes(event)) continue;

    try {
      const body = JSON.stringify({
        event,
        at: new Date().toISOString(),
        source: 'NetScan Canon',
        payload
      });
      const url = new URL(hook.url);
      const mod = url.protocol === 'https:' ? https : http;
      await new Promise((resolve, reject) => {
        const req = mod.request({
          hostname: url.hostname,
          port: url.port || (url.protocol === 'https:' ? 443 : 80),
          path: `${url.pathname}${url.search}`,
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Content-Length': Buffer.byteLength(body),
            'User-Agent': 'NetScan-Canon-Webhook/1.0'
          },
          timeout: 10000
        }, (res) => {
          res.resume();
          res.on('end', resolve);
        });
        req.on('error', reject);
        req.on('timeout', () => req.destroy(new Error('timeout')));
        req.write(body);
        req.end();
      });
      dispatched++;
      results.push({ url: hook.url, ok: true });
    } catch (err) {
      results.push({ url: hook.url, ok: false, error: err.message });
    }
  }

  return { ok: true, dispatched, results };
}

module.exports = { dispatchWebhook };

