}

function loadReports() {
  ensureStore();
  if (!fs.existsSync(AGENT_FILE)) return { version: 1, reports: [] };
  try {
    const raw = JSON.parse(fs.readFileSync(AGENT_FILE, 'utf8'));
    return { version: 1, reports: Array.isArray(raw.reports) ? raw.reports : [] };
  } catch {
    return { version: 1, reports: [] };
