function ingestAgentReport(payload, meta = {}) {
  const hostname = String(payload?.hostname || payload?.computerName || '').trim();
  if (!hostname) return { ok: false, error: 'Informe hostname no report do agente.' };

  const report = {
    id: `agent_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    at: new Date().toISOString(),
    hostname,
    ip: payload.ip || payload.primaryIp || null,
    os: payload.os || payload.operatingSystem || null,
    osVersion: payload.osVersion || null,
    user: payload.user || payload.loggedOnUser || null,
