    software: payload.software || payload.installedSoftware || null,
    agentVersion: payload.agentVersion || meta.agentVersion || '1.0',
    raw: payload
  };

  const store = loadReports();
  store.reports.unshift(report);
  store.reports = store.reports.slice(0, MAX_REPORTS);
