};

function ensureDataDir() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
}

function writeJsonAtomic(file, data) {
  ensureDataDir();
  const tmp = `${file}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(data, null, 2), 'utf8');
  fs.renameSync(tmp, file);
}

function loadAlaMap() {
  ensureDataDir();
  if (!fs.existsSync(ALA_MAP_FILE)) {
    writeJsonAtomic(ALA_MAP_FILE, DEFAULT_ALA_MAP);
    return structuredClone(DEFAULT_ALA_MAP);
  }
  try {
    const raw = JSON.parse(fs.readFileSync(ALA_MAP_FILE, 'utf8'));
    return {
      ...DEFAULT_ALA_MAP,
      ...raw,
      alas: Array.isArray(raw.alas) && raw.alas.length ? raw.alas : DEFAULT_ALA_MAP.alas
    };
  } catch {
    return structuredClone(DEFAULT_ALA_MAP);
  }
}

function saveAlaMap(partial) {
  const cur = loadAlaMap();
  const next = {
    ...cur,
    ...partial,
    version: 1,
    alas: Array.isArray(partial?.alas) ? partial.alas : cur.alas
  };
  writeJsonAtomic(ALA_MAP_FILE, next);
  return next;
}

function normalizeMac(mac) {
  if (!mac) return null;
  const hex = String(mac).replace(/[^a-fA-F0-9]/g, '').toLowerCase();
  return hex.length === 12 ? hex : null;
}

function ipToLong(ip) {
  return String(ip || '').split('.').reduce((acc, o) => (acc << 8) + (parseInt(o, 10) || 0), 0) >>> 0;
}

function cidrContains(cidr, ip) {
  const [base, bitsStr] = String(cidr).split('/');
  const bits = parseInt(bitsStr, 10);
  if (!base || Number.isNaN(bits) || !ip) return false;
  const mask = bits === 0 ? 0 : (~0 << (32 - bits)) >>> 0;
  return ((ipToLong(ip) & mask) >>> 0) === ((ipToLong(base) & mask) >>> 0);
}

function textHasKeyword(text, keywords) {
  const blob = String(text || '').toLowerCase();
  if (!blob) return false;
  for (const kw of keywords || []) {
    const k = String(kw || '').trim().toLowerCase();
    if (k && blob.includes(k)) return true;
  }
  return false;
}

async function buildSwitchMacIndex(options = {}) {
  const loopCfg = loopDetection.getConfig();
  const switches = loopDetection.listSwitches();
  const community = options.community || loopCfg.community || 'public';
  const timeoutMs = options.timeoutMs || loopCfg.timeoutMs || 3500;
  const macIndex = new Map();
  const switchResults = [];

  for (const sw of switches) {
    const sample = await loopDetection.pollSwitch(sw, { community, timeoutMs, retries: 1 });
    switchResults.push({
      id: sw.id,
      ip: sw.ip,
      name: sw.name || sw.ip,
      ok: !!sample.ok,
      error: sample.error || null,
      macCount: sample.ok ? sample.macMap.size : 0
    });
    if (!sample.ok) continue;
    for (const [mac, ifIndex] of sample.macMap.entries()) {
      const norm = normalizeMac(mac);
      if (!norm) continue;
      const iface = (sample.ifaces || []).find((i) => String(i.ifIndex) === String(ifIndex));
      const portName = iface ? (iface.name || iface.descr) : `if${ifIndex}`;
      macIndex.set(norm, {
        switchId: sw.id,
        switchName: sw.name || sw.ip,
        switchIp: sw.ip,
        port: portName,
        ifIndex: String(ifIndex)
      });
    }
  }

  return {
    macIndex,
    switchCount: switches.length,
    macsFound: macIndex.size,
    switches: switchResults
  };
}

function mergeHostSources(scanResults, includeInactive) {
  const byIp = new Map();
  for (const h of (Array.isArray(scanResults) ? scanResults : [])) {
    if (!h?.ip) continue;
    byIp.set(h.ip, { ...h });
  }
  if (includeInactive) {
    const hist = readHistoryHosts();
    for (const [ip, rec] of Object.entries(hist)) {
      if (byIp.has(ip)) continue;
      byIp.set(ip, {
        ip,
        hostname: rec.hostname || 'N/A',
        mac: rec.mac || null,
        status: rec.lastStatus === 'Ativo' ? 'Ativo' : 'Inativo',
        subnet: rec.subnet || getSubnetCidr24(ip),
        deviceType: rec.deviceType || 'N/A',
        adLocation: rec.adLocation || null,
        description: rec.description || null,
        vlan: rec.vlan || null,
        vlanId: rec.vlanId != null ? rec.vlanId : null
      });
    }
  }
  return Array.from(byIp.values());
}

function scoreAlaForHost(host, ala, ctx) {
  if (ala.id === ctx.defaultAlaId) return { score: 0, reasons: [] };

  let score = 0;
  const reasons = [];

  for (const cidr of ala.subnets || []) {
    if (cidrContains(cidr, host.ip)) {
      score += 50;
      reasons.push(`sub-rede ${cidr}`);
      break;
    }
  }

  const vlanId = host.vlanId != null ? Number(host.vlanId) : null;
  if (vlanId != null && (ala.vlanIds || []).some((v) => Number(v) === vlanId)) {
    score += 40;
    reasons.push(`VLAN ${vlanId}`);
  }

  const macLoc = ctx.macIndex?.get(normalizeMac(host.mac));
  if (macLoc && (ala.switchIps || []).includes(macLoc.switchIp)) {
    score += 45;
    reasons.push(`switch ${macLoc.switchIp}`);
  }

  if (textHasKeyword(host.adLocation, ala.keywords)) {
    score += 35;
    reasons.push('AD local');
  }
  if (textHasKeyword(host.description, ala.keywords)) {
    score += 20;
    reasons.push('AD descrição');
  }
  if (textHasKeyword(host.hostname, ala.keywords)) {
    score += 15;
    reasons.push('hostname');
  }

  return { score, reasons };
}

function resolveAlaForHost(host, alaMap, ctx) {
  const candidates = (alaMap.alas || []).filter((a) => a.id !== alaMap.defaultAlaId);
  let best = null;
  let bestScore = 0;
  let bestReasons = [];

  for (const ala of candidates) {
    const { score, reasons } = scoreAlaForHost(host, ala, ctx);
    if (score > bestScore) {
      bestScore = score;
      best = ala;
      bestReasons = reasons;
    }
  }

  const defaultAla = (alaMap.alas || []).find((a) => a.id === alaMap.defaultAlaId)
    || { id: 'nao-classificado', name: 'Não classificado' };

  if (!best || bestScore < 15) {
    return {
      alaId: defaultAla.id,
      alaName: defaultAla.name,
      confidence: bestScore > 0 ? 'baixa' : 'nenhuma',
      score: bestScore,
      reasons: bestReasons
    };
  }

  let confidence = 'média';
  if (bestScore >= 45) confidence = 'alta';
  else if (bestScore < 25) confidence = 'baixa';

  return {
    alaId: best.id,
    alaName: best.name,
    confidence,
    score: bestScore,
    reasons: bestReasons
  };
}

function enrichHostNetwork(host, vlanMap) {
  const out = { ...host };
  if (!out.subnet || out.subnet === 'N/A') out.subnet = getSubnetCidr24(out.ip);
  if (out.vlanId == null || !out.vlan) {
    try {
      const vlanInfo = resolveHostVlan(out, vlanMap);
      if (vlanInfo) {
        out.vlan = out.vlan || vlanInfo.vlan;
        out.vlanId = out.vlanId != null ? out.vlanId : vlanInfo.vlanId;
        out.vlanSource = vlanInfo.vlanSource || out.vlanSource;
      }
    } catch { /* ignore */ }
  }
  return out;
}

async function buildAlaMapReport(scanResults, options = {}) {
  const alaMap = options.alaMap || loadAlaMap();
  const includeInactive = options.includeInactive != null
    ? !!options.includeInactive
    : !!alaMap.includeInactive;
  const pollSwitches = options.pollSwitches != null
    ? !!options.pollSwitches
    : !!alaMap.pollSwitches;

  const vlanMap = loadVlanMap();
  let switchPoll = { switchCount: 0, macsFound: 0, switches: [], skipped: !pollSwitches };
  let macIndex = new Map();

  if (pollSwitches) {
    switchPoll = await buildSwitchMacIndex(options);
    macIndex = switchPoll.macIndex;
    delete switchPoll.macIndex;
  }

  const sources = mergeHostSources(scanResults, includeInactive);
  const ctx = { macIndex, defaultAlaId: alaMap.defaultAlaId || 'nao-classificado' };
  const mapped = [];

  for (const raw of sources) {
    const host = enrichHostNetwork(raw, vlanMap);
    const ala = resolveAlaForHost(host, alaMap, ctx);
    const macLoc = macIndex.get(normalizeMac(host.mac));
    mapped.push({
      ip: host.ip,
      hostname: host.hostname || 'N/A',
      status: host.status || '—',
      mac: host.mac || '—',
      vlan: host.vlan || 'N/A',
      vlanId: host.vlanId != null ? host.vlanId : null,
      subnet: host.subnet || getSubnetCidr24(host.ip),
      deviceType: host.deviceType || 'N/A',
      adLocation: host.adLocation && host.adLocation !== 'N/A' ? host.adLocation : '—',
      switchName: macLoc?.switchName || '—',
      switchIp: macLoc?.switchIp || '—',
      switchPort: macLoc?.port || '—',
      alaId: ala.alaId,
      alaName: ala.alaName,
      confidence: ala.confidence,
      score: ala.score,
      reasons: ala.reasons
    });
  }

  mapped.sort((a, b) => {
    const alaCmp = a.alaName.localeCompare(b.alaName, 'pt-BR');
    if (alaCmp !== 0) return alaCmp;
    return a.ip.localeCompare(b.ip);
  });

  const byAla = new Map();
  for (const h of mapped) {
    if (!byAla.has(h.alaId)) {
      byAla.set(h.alaId, {
        id: h.alaId,
        name: h.alaName,
        hostCount: 0,
        hosts: []
      });
    }
    const bucket = byAla.get(h.alaId);
    bucket.hostCount++;
    bucket.hosts.push(h);
  }

  const alas = (alaMap.alas || [])
    .map((def) => {
      const bucket = byAla.get(def.id);
      return {
        id: def.id,
        name: def.name,
        description: def.description || '',
        hostCount: bucket?.hostCount || 0,
        hosts: bucket?.hosts || []
      };
    })
    .filter((a) => a.hostCount > 0 || a.id !== alaMap.defaultAlaId);

  const unassigned = byAla.get(alaMap.defaultAlaId) || { hostCount: 0, hosts: [] };
  const classified = mapped.filter((h) => h.alaId !== alaMap.defaultAlaId).length;

  return {
    ok: true,
    generatedAt: new Date().toISOString(),
    totalHosts: mapped.length,
    classifiedCount: classified,
    unclassifiedCount: unassigned.hostCount,
    alaCount: alas.filter((a) => a.id !== alaMap.defaultAlaId).length,
    includeInactive,
    pollSwitches,
    switchPoll,
    alas,
    unassigned: {
      id: alaMap.defaultAlaId,
      name: 'Não classificado',
      hostCount: unassigned.hostCount,
      hosts: unassigned.hosts || []
    },
    hosts: mapped,
    message: mapped.length
      ? `${mapped.length} host(s) · ${classified} classificado(s) em ${alas.filter((a) => a.id !== alaMap.defaultAlaId).length} ala(s)` +
        (pollSwitches ? ` · ${switchPoll.macsFound} MAC(s) em ${switchPoll.switchCount} switch(es)` : '')
      : 'Nenhum host no scan ou histórico. Rode uma varredura primeiro.'
  };
}

module.exports = {
  loadAlaMap,
  saveAlaMap,
  buildAlaMapReport,
  buildSwitchMacIndex,
  ALA_MAP_FILE,
  DEFAULT_ALA_MAP
};

