function ensureStore() {
  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
}

function loadStore() {
  ensureStore();
  if (!fs.existsSync(INVENTORY_FILE)) {
    return { version: 2, updatedAt: null, lastScanAt: null, lastScanTarget: null, items: {} };
  }
  try {
    const raw = JSON.parse(fs.readFileSync(INVENTORY_FILE, 'utf8'));
    return {
      version: 2,
      updatedAt: raw.updatedAt || null,
      lastScanAt: raw.lastScanAt || null,
      lastScanTarget: raw.lastScanTarget || null,
      items: raw.items || {}
    };
  } catch {
    return { version: 2, updatedAt: null, lastScanAt: null, lastScanTarget: null, items: {} };
  }
}

function saveStore(store) {
  ensureStore();
  store.updatedAt = new Date().toISOString();
  const tmp = `${INVENTORY_FILE}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(store, null, 2), 'utf8');
  fs.renameSync(tmp, INVENTORY_FILE);
}

function normalizeMacDisplay(mac) {
  if (!mac) return null;
  const s = String(mac).trim().toUpperCase().replace(/:/g, '-');
  if (!/^([0-9A-F]{2}-){5}[0-9A-F]{2}$/.test(s)) return null;
  return s;
}

async function resolveMacViaPingArp(ip) {
  const safeIp = String(ip || '').trim();
  if (!/^\d+\.\d+\.\d+\.\d+$/.test(safeIp)) return null;
  try {
    await execFileAsync('ping', ['-n', '1', '-w', '400', safeIp], { windowsHide: true, timeout: 4000 });
    const { stdout } = await execFileAsync('arp', ['-a', safeIp], { windowsHide: true, timeout: 4000, encoding: 'utf8' });
    const m = String(stdout || '').match(/([0-9a-fA-F]{2}[:-]){5}[0-9a-fA-F]{2}/);
    if (m) return normalizeMacDisplay(m[0]);
  } catch {
    // segue para nbtstat
  }
  try {
    const { stdout } = await execFileAsync('nbtstat', ['-A', safeIp], { windowsHide: true, timeout: 6000, encoding: 'utf8' });
    const m = String(stdout || '').match(/MAC Address\s*=\s*([0-9A-F-]{17})/i);
    return m ? normalizeMacDisplay(m[1]) : null;
  } catch {
    return null;
  }
}

function loadHostHistory() {
  if (!fs.existsSync(HISTORY_FILE)) return { hosts: {} };
  try {
    return JSON.parse(fs.readFileSync(HISTORY_FILE, 'utf8'));
  } catch {
    return { hosts: {} };
  }
}

function loadLastScanIndex() {
  const map = new Map();
  if (!fs.existsSync(LAST_SCAN_FILE)) return map;
  try {
    const raw = JSON.parse(fs.readFileSync(LAST_SCAN_FILE, 'utf8'));
    for (const h of raw.hosts || []) {
      if (h?.ip) map.set(h.ip, h);
    }
  } catch {
    // ignore corrupt snapshot
  }
  return map;
}

function saveLastScanSnapshot(results, meta = {}) {
  const list = Array.isArray(results) ? results : [];
  if (!list.length) return null;
  ensureStore();
  const payload = {
    savedAt: new Date().toISOString(),
    target: meta.target || null,
    total: list.length,
    hosts: list.map((h) => ({
      ip: h.ip,
      status: h.status,
      hostname: h.hostname,
      mac: h.mac,
      vendor: h.vendor,
      os: h.os,
      osVersion: h.osVersion,
      ports: Array.isArray(h.ports) ? h.ports : [],
      adDomain: h.adDomain,
      adDn: h.adDn,
      adOu: h.adOu,
      adLocation: h.adLocation,
      managedBy: h.managedBy,
      loggedOnUser: h.loggedOnUser,
      deviceType: h.deviceType,
      vlan: h.vlan || h.vlanId,
      subnet: h.subnet,
      description: h.description
    }))
  };
  const tmp = `${LAST_SCAN_FILE}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(payload, null, 2), 'utf8');
  fs.renameSync(tmp, LAST_SCAN_FILE);
  return payload;
}

function loadAdSnapshotIndex() {
  if (!fs.existsSync(SNAPSHOT_FILE)) return {};
  try {
    const raw = JSON.parse(fs.readFileSync(SNAPSHOT_FILE, 'utf8'));
    const users = raw.users || raw.bySam || {};
    const index = {};
    for (const u of Object.values(users)) {
      if (!u?.sAMAccountName) continue;
      index[String(u.sAMAccountName).toLowerCase()] = u;
    }
    return index;
  } catch {
    return {};
  }
}

function shortHost(name) {
  return String(name || '').trim().toLowerCase().split('.')[0];
}

function isBlank(val) {
  if (val == null) return true;
  const s = String(val).trim();
  if (!s) return true;
  return EMPTY_MARKERS.has(s.toLowerCase());
}

function pickVal(...vals) {
  for (const v of vals) {
    if (isBlank(v)) continue;
    return String(v).trim();
  }
  return null;
}

function displayVal(val) {
  return pickVal(val) || '—';
}

function normalizeOuKey(name) {
  return String(name || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim()
    .toLowerCase();
}

function isGenericOu(name) {
  const key = normalizeOuKey(name);
  return !key || GENERIC_OU.has(key);
}

function loadAdComputerIndex() {
  const byIp = new Map();
  const byDns = new Map();
  const byCn = new Map();
  const byDn = new Map();

  if (!fs.existsSync(AD_COMPUTERS_CACHE_FILE)) {
    return { byIp, byDns, byCn, byDn, ok: false };
  }

  try {
    const raw = JSON.parse(fs.readFileSync(AD_COMPUTERS_CACHE_FILE, 'utf8'));
    const computers = Array.isArray(raw.computers) ? raw.computers : [];
    for (const c of computers) {
      const entry = {
        cn: c.cn || c.name || null,
        name: c.name || c.cn || null,
        sAMAccountName: c.sAMAccountName || null,
        dNSHostName: c.dNSHostName || null,
        distinguishedName: c.distinguishedName || null,
        description: c.description || null,
        location: c.location || null,
        managedBy: c.managedBy || null,
        adDomain: c.adDomain || raw.domainDns || null
      };
      if (entry.distinguishedName) byDn.set(String(entry.distinguishedName).toLowerCase(), entry);
      if (entry.dNSHostName) byDns.set(String(entry.dNSHostName).toLowerCase(), entry);
      const cn = shortHost(entry.cn || entry.name);
      if (cn) byCn.set(cn, entry);
    }

    const ipMap = raw.ipMap && typeof raw.ipMap === 'object' ? raw.ipMap : {};
    for (const [ip, key] of Object.entries(ipMap)) {
      const entry =
        (key && byDns.get(String(key).toLowerCase())) ||
        (key && byCn.get(shortHost(key))) ||
        null;
      if (entry) byIp.set(ip, entry);
    }

    if (fs.existsSync(AD_IP_INDEX_FILE)) {
      try {
        const ipRaw = JSON.parse(fs.readFileSync(AD_IP_INDEX_FILE, 'utf8'));
        const map = ipRaw.map && typeof ipRaw.map === 'object' ? ipRaw.map : {};
        for (const [ip, key] of Object.entries(map)) {
          if (byIp.has(ip)) continue;
          const entry =
            (key && byDns.get(String(key).toLowerCase())) ||
            (key && byCn.get(shortHost(key))) ||
            null;
          if (entry) byIp.set(ip, entry);
        }
      } catch {
        // ignore
      }
    }

    return { byIp, byDns, byCn, byDn, ok: computers.length > 0, domainDns: raw.domainDns || null };
  } catch {
    return { byIp, byDns, byCn, byDn, ok: false };
  }
}

function buildAgentIndex() {
  const data = listAgentReports(500);
  const byIp = new Map();
  const byHost = new Map();
  for (const r of data.reports || []) {
    if (r.ip) byIp.set(r.ip, r);
    const h = String(r.hostname || '').toLowerCase().split('.')[0];
    if (h) byHost.set(h, r);
  }
  return { byIp, byHost };
}

function samFromDn(dn) {
  const m = String(dn || '').match(/^CN=([^,\\/]+)/i);
  return m ? m[1].trim() : null;
}

function lookupSnapshotUser(adUsers, query) {
  if (!query || !adUsers) return null;
  const direct = adUsers[String(query).toLowerCase()];
  if (direct) return direct;
  return findSnapshotUser(adUsers, query);
}

function resolveAdComputer(host, ctx) {
  const computers = ctx.computers || { byIp: new Map(), byDns: new Map(), byCn: new Map(), byDn: new Map() };

  if (host.ip && computers.byIp.has(host.ip)) {
    return { ...computers.byIp.get(host.ip), matchedBy: 'ip' };
  }

  const fqdn = pickVal(host.hostname);
  if (fqdn) {
    const lower = fqdn.toLowerCase();
    if (computers.byDns.has(lower)) return { ...computers.byDns.get(lower), matchedBy: 'dnsHostName' };
    const short = shortHost(fqdn);
    if (short && computers.byCn.has(short)) return { ...computers.byCn.get(short), matchedBy: 'cn' };
    const domain = pickVal(host.adDomain, computers.domainDns);
    if (domain && !lower.includes('.') && computers.byDns.has(`${lower}.${domain.toLowerCase()}`)) {
      return { ...computers.byDns.get(`${lower}.${domain.toLowerCase()}`), matchedBy: 'dnsHostName+domain' };
    }
  }

  const dn = pickVal(host.adDn);
  if (dn && computers.byDn.has(dn.toLowerCase())) {
    return { ...computers.byDn.get(dn.toLowerCase()), matchedBy: 'dn' };
  }

  if (dn) {
    return {
      distinguishedName: dn,
      location: pickVal(host.adLocation),
      managedBy: pickVal(host.managedBy),
      adDomain: pickVal(host.adDomain),
      dNSHostName: fqdn,
      matchedBy: 'scan-dn'
    };
  }

  return null;
}

function resolveAdUserSam(host, agent, computer, ctx) {
  const fromAgent = normalizeSamFromUser(agent?.user);
  if (fromAgent && !fromAgent.endsWith('$')) return { sam: fromAgent, source: 'agent' };

  for (const candidate of [
    host.loggedOnUser,
    host.adUser,
    host.lastLoggedOnUser,
    host.currentUser
  ]) {
    const sam = normalizeSamFromUser(candidate);
    if (sam && !sam.endsWith('$')) return { sam, source: 'scan' };
  }

  const managedBy = pickVal(computer?.managedBy, host.managedBy);
  if (managedBy) {
    const fromDn = samFromDn(managedBy);
    if (fromDn) {
      const snap = lookupSnapshotUser(ctx.adUsers, fromDn);
      if (snap?.sAMAccountName) return { sam: snap.sAMAccountName, source: 'managedBy' };
      const sam = normalizeSamFromUser(fromDn);
      if (sam && !sam.endsWith('$')) return { sam, source: 'managedBy' };
    }
  }

  const desc = pickVal(computer?.description, host.description);
  if (desc) {
    const patterns = [
      /(?:usu[aá]rio|user|login|conta)\s*[:=\-]\s*([A-Za-z0-9._-]+)/i,
      /\b([A-Za-z0-9._-]{3,})\b/
    ];
    for (const re of patterns) {
      const m = desc.match(re);
      if (!m) continue;
      const sam = normalizeSamFromUser(m[1]);
      if (sam && !sam.endsWith('$') && lookupSnapshotUser(ctx.adUsers, sam)) {
        return { sam, source: 'description' };
      }
    }
  }

  if (fromAgent) return { sam: fromAgent, source: 'agent' };
  return { sam: null, source: 'none' };
}

function inferDepartmentForHost(host, user, computer) {
  if (user) {
    const dept = inferDepartment(user);
    if (dept.name) return dept;
  }

  const location = pickVal(computer?.location, host.adLocation);
  if (location) {
    const dept = inferDepartment({ department: location, distinguishedName: computer?.distinguishedName || host.adDn });
    if (dept.name) return { ...dept, source: dept.source === 'none' ? 'location' : dept.source };
  }

  const dn = pickVal(computer?.distinguishedName, host.adDn);
  if (dn) {
    const dept = inferDepartment({ distinguishedName: dn });
    if (dept.name) return dept;
  }

  const vlan = pickVal(host.vlan, host.vlanId);
  if (vlan) {
    const paren = String(vlan).match(/\(([^)]+)\)/);
    if (paren?.[1]) return { name: paren[1].trim(), source: 'vlan' };
  }

  const ouText = parseOusFromDn(dn);
  for (let i = ouText.length - 1; i >= 0; i--) {
    if (!isGenericOu(ouText[i])) return { name: ouText[i], source: 'ou' };
  }

  const ouField = pickVal(host.adOu);
  if (ouField) {
    for (const part of ouField.split('/').map((s) => s.trim()).filter(Boolean)) {
      if (!isGenericOu(part)) return { name: part, source: 'ou-scan' };
    }
  }

  return { name: '', source: 'none' };
}

function inferUnitForHost(host, user, computer, dept) {
  if (user?.department && dept?.source !== 'department') {
    const unit = pickVal(user.department);
    if (unit) return { name: unit, source: 'user-department' };
  }

  if (dept?.source === 'vlan') {
    const domain = pickVal(host.adDomain, computer?.adDomain);
    if (domain) {
      const short = domain.split('.')[0];
      if (short && short.length > 2) return { name: short.toUpperCase(), source: 'domain' };
    }
  }

  const location = pickVal(computer?.location, host.adLocation);
  if (location && dept?.name && normalizeOuKey(location) !== normalizeOuKey(dept.name)) {
    return { name: location, source: 'location' };
  }

  const dn = pickVal(computer?.distinguishedName, host.adDn);
  const ous = parseOusFromDn(dn);
  for (let i = ous.length - 1; i >= 0; i--) {
    if (!isGenericOu(ous[i])) return { name: ous[i], source: 'ou-root' };
  }
  for (const ou of ous) {
    if (!isGenericOu(ou)) return { name: ou, source: 'ou' };
  }

  const ouField = pickVal(host.adOu);
  if (ouField) {
    for (const part of ouField.split('/').map((s) => s.trim()).filter(Boolean)) {
      if (!isGenericOu(part)) return { name: part, source: 'ou-scan' };
    }
  }

  const vlan = pickVal(host.vlan, host.vlanId);
  if (vlan) {
    const paren = String(vlan).match(/\(([^)]+)\)/);
    if (paren?.[1]) return { name: paren[1].trim(), source: 'vlan' };
  }

  const domain = pickVal(host.adDomain, computer?.adDomain);
  if (domain) {
    const short = domain.split('.')[0];
    if (short && short.length > 2) return { name: short.toUpperCase(), source: 'domain' };
  }

  const env = pickVal(host.environment);
  if (env && !GENERIC_ENV.has(env.toLowerCase())) return { name: env, source: 'environment' };

  const subnet = pickVal(host.subnet);
  if (subnet) return { name: subnet, source: 'subnet' };

  return { name: '', source: 'none' };
}

function mergePreferFilled(prev, next, keys) {
  const out = { ...prev, ...next };
  for (const key of keys) {
    if (isBlank(next[key]) && !isBlank(prev[key])) out[key] = prev[key];
  }
  return out;
}

function normalizePorts(ports) {
  if (!Array.isArray(ports)) return [];
  return ports
    .map((p) => ({
      port: Number(p?.port),
      protocol: String(p?.protocol || 'TCP').toUpperCase(),
      state: p?.state || 'open',
      service: p?.service || null
    }))
    .filter((p) => Number.isFinite(p.port) && p.port > 0);
}

function summarizeOpenPorts(ports) {
  const list = normalizePorts(ports)
    .filter((p) => !p.state || String(p.state).startsWith('open'))
    .map((p) => p.port)
    .sort((a, b) => a - b);
  return list.length ? list.join(', ') : '—';
}

function summarizeServices(ports) {
  const list = normalizePorts(ports)
    .filter((p) => p.service && (!p.state || String(p.state).startsWith('open')))
    .map((p) => `${p.port}/${p.protocol}:${p.service}`);
  return list.length ? list.join('; ') : '—';
}

function mergePorts(...lists) {
  const map = new Map();
  for (const list of lists) {
    for (const p of normalizePorts(list)) map.set(`${p.protocol}:${p.port}`, p);
  }
  return [...map.values()].sort((a, b) => a.port - b.port);
}

function valuesEqual(a, b) {
  return String(a ?? '') === String(b ?? '');
}

function appendChangeLog(prev, changes, scanAt) {
  const log = Array.isArray(prev.changeLog) ? [...prev.changeLog] : [];
  if (!changes.length) return log;
  log.unshift({ at: scanAt, changes: changes.slice(0, 12) });
  return log.slice(0, 40);
}

/**
 * Merge incremental: preserva dados históricos; atualiza somente campos com valor novo ou alterado.
 */
function mergeInventoryRecord(prev, next, opts = {}) {
  const scanAt = opts.scanAt || new Date().toISOString();
  const fromScan = opts.fromScan === true;
  const out = { ...prev, ip: next.ip || prev.ip };
  const changes = [];

  if (!out.firstSeenAt) out.firstSeenAt = scanAt;
  if (fromScan) {
    out.lastSeenAt = scanAt;
    out.consecutiveAbsentScans = 0;
    out.absentSince = null;
    out.inventoryStatus = 'registrado';
    out.scanCount = (Number(prev.scanCount) || 0) + 1;
    out.lastScanAt = scanAt;
  }

  for (const key of MERGE_ALWAYS_FROM_SCAN) {
    if (next[key] !== undefined) {
      if (!valuesEqual(prev[key], next[key])) changes.push({ field: key, from: prev[key], to: next[key] });
      out[key] = next[key];
    }
  }

  for (const key of MERGE_PRESERVE_IF_EMPTY) {
    if (!isBlank(next[key])) {
      if (!valuesEqual(prev[key], next[key])) changes.push({ field: key, from: prev[key], to: next[key] });
      out[key] = next[key];
    } else if (!isBlank(prev[key])) {
      out[key] = prev[key];
    }
  }

  if (fromScan && next.lastScanAt) out.lastScanAt = next.lastScanAt;

  const mergedPorts = fromScan ? mergePorts(prev.ports, next.ports) : (prev.ports || next.ports || []);
  if (fromScan && JSON.stringify(prev.ports) !== JSON.stringify(mergedPorts)) {
    changes.push({ field: 'ports', from: summarizeOpenPorts(prev.ports), to: summarizeOpenPorts(mergedPorts) });
  }
  out.ports = mergedPorts;
  out.openPorts = summarizeOpenPorts(out.ports);
  out.services = summarizeServices(out.ports);

  if (fromScan && opts.scanTarget && !out.registeredScanTarget) {
    out.registeredScanTarget = opts.scanTarget;
  }

  out.lastUpdatedAt = scanAt;
  out.updatedAt = scanAt;
  if (fromScan && changes.length) {
    out.changeLog = appendChangeLog(prev, changes, scanAt);
  } else if (prev.changeLog) {
    out.changeLog = prev.changeLog;
  }

  return out;
}

function isIpInTargetScope(ip, target) {
  if (!ip || !target) return true;
  const t = String(target).trim();
  if (t.includes('/')) return cidrContains(t, ip);
  if (t.includes('-')) {
    const start = t.split('-')[0]?.trim();
    if (start && /^\d+\.\d+\.\d+\.\d+$/.test(start)) {
      return getSubnetCidr24(ip) === getSubnetCidr24(start);
    }
  }
  if (/^\d+\.\d+\.\d+\.\d+$/.test(t)) return ip === t;
  return true;
}

function markAbsentFromScan(item, ctx, meta = {}) {
  const historyRec = ctx.history?.hosts?.[item.ip];
  const scanAt = ctx.scanAt || new Date().toISOString();
  const out = { ...item };

  out.consecutiveAbsentScans = (Number(out.consecutiveAbsentScans) || 0) + 1;
  if (!out.absentSince) out.absentSince = scanAt;

  const normalizedScan = normalizeScanStatus(out.scanStatus);
  if (normalizedScan) out.scanStatus = normalizedScan;

  out.status = 'Ausente';
  out.inventoryStatus = out.consecutiveAbsentScans >= 3 ? 'ausente' : (out.inventoryStatus || 'registrado');

  if (historyRec?.lastChecked) {
    out.lastCommunication = fmtLocale(historyRec.lastChecked);
    out.lastCommunicationIso = fmtIso(historyRec.lastChecked);
  }

  out.lastInventorySyncAt = scanAt;
  out.lastUpdatedAt = scanAt;
  return out;
}

function shouldRemoveInventoryItem(item, ctx, meta = {}) {
  const absent = Number(item.consecutiveAbsentScans) || 0;
  if (absent < MIN_ABSENT_SCANS_FOR_REMOVAL) return false;

  const lifecycle = getAsset(item.ip);
  if (lifecycle?.state === 'liberado') {
    return { remove: true, reason: 'lifecycle-liberado' };
  }

  const scanTarget = meta.target || meta.scanTarget;
  if (scanTarget && item.ip && !isIpInTargetScope(item.ip, scanTarget)) {
    return { remove: true, reason: 'fora-escopo-monitorado' };
  }

  const hist = ctx.history?.hosts?.[item.ip];
  if (hist && (Number(hist.consecutiveInactiveScans) || 0) >= MIN_ABSENT_SCANS_FOR_REMOVAL) {
    const seenActive = Number(hist.timesSeenActive) || 0;
    if (seenActive === 0) return { remove: true, reason: 'nunca-ativo-ausente-prolongado' };
  }

  return false;
}

function loadRemovedArchive() {
  ensureStore();
  if (!fs.existsSync(INVENTORY_REMOVED_FILE)) return { version: 1, items: [] };
  try {
    const raw = JSON.parse(fs.readFileSync(INVENTORY_REMOVED_FILE, 'utf8'));
    return { version: 1, items: Array.isArray(raw.items) ? raw.items : [] };
  } catch {
    return { version: 1, items: [] };
  }
}

function archiveRemovedItem(store, item, meta = {}, reason = 'unknown') {
  const archive = loadRemovedArchive();
  archive.items.unshift({
    ...item,
    removedAt: new Date().toISOString(),
    removedReason: reason,
    removedAfterAbsentScans: item.consecutiveAbsentScans || 0,
    lastScanTarget: meta.target || store.lastScanTarget || null
  });
  archive.items = archive.items.slice(0, 5000);
  fs.writeFileSync(INVENTORY_REMOVED_FILE, JSON.stringify(archive, null, 2), 'utf8');
}

function normalizeSamFromUser(userStr) {
  if (!userStr) return '';
  const s = String(userStr).trim();
  const backslash = s.lastIndexOf('\\');
  if (backslash >= 0) return s.slice(backslash + 1);
  return s.split('@')[0];
}

/** Normaliza rótulos legados (Online/Offline) para Ativo/Inativo do motor de scan. */
function normalizeScanStatus(raw) {
  const s = String(raw || '').trim();
  if (!s || s === '—' || s === '-') return null;
  if (s === 'Ativo' || s === 'Online') return 'Ativo';
  if (s === 'Inativo' || s === 'Offline') return 'Inativo';
  return null;
}

/** Status exibido na UI — Ausente ≠ Offline confirmado. */
function resolveInventoryDisplayStatus(item, scanStatus) {
  const absent = (Number(item?.consecutiveAbsentScans) || 0) > 0;
  if (absent) return 'Ausente';
  const scan = normalizeScanStatus(scanStatus);
  if (scan === 'Ativo') return 'Online';
  if (scan === 'Inativo') return 'Offline';
  return 'Inacessível';
}

function mapMachineStatus(host) {
  return resolveInventoryDisplayStatus(host, host?.status);
}

function fmtIso(msOrIso) {
  if (msOrIso == null) return null;
  try {
    const d = typeof msOrIso === 'number' ? new Date(msOrIso) : new Date(msOrIso);
    if (Number.isNaN(d.getTime())) return null;
    return d.toISOString();
  } catch {
    return null;
  }
}

function fmtLocale(msOrIso) {
  const iso = fmtIso(msOrIso);
  if (!iso) return '—';
  try {
    return new Date(iso).toLocaleString('pt-BR');
  } catch {
    return iso;
  }
}

function computeUptime(historyRec, isOnline) {
  if (!historyRec) return '—';
  if (isOnline && historyRec.lastSeen) {
    const since = historyRec.inactiveSince || historyRec.firstSeen || historyRec.lastSeen;
    if (!since) return '—';
    const ms = Date.now() - since;
    if (ms < 0) return '—';
    const h = Math.floor(ms / 3600000);
    const d = Math.floor(h / 24);
    if (d > 0) return `${d}d ${h % 24}h`;
    const m = Math.floor((ms % 3600000) / 60000);
    return h > 0 ? `${h}h ${m}m` : `${m}m`;
  }
  return '—';
}

function buildInventoryItem(host, ctx = {}) {
  const historyRec = ctx.history?.hosts?.[host.ip] || null;
  const scanRec = ctx.scanByIp?.get?.(host.ip) || null;
  const agent = ctx.agents.byIp.get(host.ip)
    || ctx.agents.byHost.get(shortHost(host.hostname))
    || null;

  const computer = resolveAdComputer(host, ctx);
  const userResolved = resolveAdUserSam(host, agent, computer, ctx);
  const adUserSam = userResolved.sam;
  const adUser = adUserSam ? lookupSnapshotUser(ctx.adUsers, adUserSam) : null;
  const dept = inferDepartmentForHost(host, adUser, computer);
  const unit = inferUnitForHost(host, adUser, computer, dept);

  const normalizedScan = normalizeScanStatus(host.status) || normalizeScanStatus(scanRec?.status);
  const machineStatus = resolveInventoryDisplayStatus(
    { consecutiveAbsentScans: host.consecutiveAbsentScans || 0 },
    normalizedScan
  );
  const lastComm = historyRec?.lastChecked || historyRec?.lastSeen || null;
  const dn = pickVal(computer?.distinguishedName, host.adDn, scanRec?.adDn);
  const ouParts = parseOusFromDn(dn);
  const adOu = ouParts.length ? ouParts.join(' / ') : pickVal(host.adOu, scanRec?.adOu);
  const ports = mergePorts(
    normalizePorts(host.ports),
    normalizePorts(scanRec?.ports),
    normalizePorts(historyRec?.ports)
  );
  const macRaw = pickVal(host.mac, scanRec?.mac, historyRec?.mac, ctx.arpByIp?.get?.(host.ip));
  const mac = normalizeMacDisplay(macRaw) || pickVal(macRaw);
  const vendor = pickVal(host.vendor, scanRec?.vendor, historyRec?.vendor)
    || (mac ? getVendorFromMac(mac) : null);
  const firstSeenAt = fmtIso(pickVal(host.firstSeenAt, historyRec?.firstSeen));
  const hostnameRaw = pickVal(host.hostname, computer?.dNSHostName, computer?.cn, scanRec?.hostname, historyRec?.hostname);
  const resolvedHost = resolveHostnameFinal(host.ip, hostnameRaw, {
    deviceType: pickVal(host.deviceType, scanRec?.deviceType, historyRec?.deviceType),
    adDomain: pickVal(host.adDomain, computer?.adDomain, ctx.computers?.domainDns),
    description: pickVal(host.description, computer?.description, scanRec?.description)
  });

  return {
    ip: host.ip,
    hostname: displayVal(resolvedHost.hostname),
    hostnameSource: resolvedHost.source,
    adUser: displayVal(adUserSam),
    adUserFullName: displayVal(adUser?.displayName, adUser?.cn),
    adUserSource: userResolved.source,
    os: pickVal(host.os, scanRec?.os, historyRec?.os) || '—',
    osVersion: pickVal(host.osVersion, scanRec?.osVersion) || '—',
    mac: displayVal(mac),
    vendor: displayVal(vendor),
    adDomain: displayVal(pickVal(host.adDomain, computer?.adDomain, scanRec?.adDomain, ctx.computers?.domainDns)),
    adDn: dn || '—',
    adOu: displayVal(adOu),
    adLocation: displayVal(pickVal(computer?.location, host.adLocation, scanRec?.adLocation)),
    managedBy: displayVal(pickVal(computer?.managedBy, host.managedBy, scanRec?.managedBy)),
    status: machineStatus,
    uptime: computeUptime(historyRec, machineStatus === 'Online'),
    lastCommunication: fmtLocale(lastComm),
    lastCommunicationIso: fmtIso(lastComm),
    lastScanAt: host.lastScanAt || null,
    firstSeenAt,
    department: displayVal(dept.name),
    departmentSource: dept.source || 'none',
    unit: displayVal(unit.name),
    unitSource: unit.source || 'none',
    deviceType: pickVal(host.deviceType, scanRec?.deviceType, historyRec?.deviceType) || '—',
    vlan: displayVal(pickVal(host.vlan, host.vlanId, scanRec?.vlan, historyRec?.vlan)),
    subnet: pickVal(host.subnet, scanRec?.subnet, historyRec?.subnet) || '—',
    ports,
    openPorts: summarizeOpenPorts(ports),
    services: summarizeServices(ports),
    description: pickVal(host.description, scanRec?.description) || '—',
    flags: [],
    scanStatus: normalizedScan || '—',
    consecutiveAbsentScans: Number(host.consecutiveAbsentScans) || 0,
    lifecycleState: ctx.lifecycle?.state || null,
    inventoryStatus: 'registrado'
  };
}

function enrichInventoryItem(item, ctx) {
  const historyRec = ctx.history?.hosts?.[item.ip] || null;
  const scanRec = ctx.scanByIp?.get?.(item.ip) || null;
  const normalizedScan = normalizeScanStatus(item.scanStatus) || normalizeScanStatus(scanRec?.status);
  const host = {
    ip: item.ip,
    hostname: pickVal(item.hostname, historyRec?.hostname, scanRec?.hostname),
    status: normalizedScan,
    consecutiveAbsentScans: item.consecutiveAbsentScans,
    lastScanAt: item.lastScanAt,
    os: pickVal(item.os, historyRec?.os, scanRec?.os),
    osVersion: pickVal(item.osVersion, scanRec?.osVersion),
    mac: pickVal(item.mac, scanRec?.mac, historyRec?.mac, ctx.arpByIp?.get?.(item.ip)),
    vendor: pickVal(item.vendor, scanRec?.vendor, historyRec?.vendor),
    adDomain: pickVal(item.adDomain, scanRec?.adDomain),
    adDn: pickVal(item.adDn, scanRec?.adDn),
    adLocation: pickVal(item.adLocation, scanRec?.adLocation),
    adOu: pickVal(item.adOu, scanRec?.adOu),
    managedBy: pickVal(item.managedBy, scanRec?.managedBy),
    vlan: pickVal(item.vlan, historyRec?.vlan, scanRec?.vlan),
    vlanId: pickVal(item.vlan, historyRec?.vlan, scanRec?.vlan),
    subnet: pickVal(item.subnet, historyRec?.subnet, scanRec?.subnet),
    environment: historyRec?.environment,
    deviceType: pickVal(item.deviceType, historyRec?.deviceType, scanRec?.deviceType),
    description: pickVal(item.description, scanRec?.description),
    loggedOnUser: pickVal(item.loggedOnUser, scanRec?.loggedOnUser),
    ports: mergePorts(item.ports, scanRec?.ports, historyRec?.ports),
    firstSeenAt: pickVal(item.firstSeenAt, historyRec?.firstSeen),
    lastScanAt: item.lastScanAt
  };
  const enriched = buildInventoryItem(host, ctx);
  enriched.status = resolveInventoryDisplayStatus(item, normalizedScan);
  enriched.scanStatus = normalizedScan || '—';
  enriched.consecutiveAbsentScans = Number(item.consecutiveAbsentScans) || 0;
  enriched.inventoryStatus = item.inventoryStatus || enriched.inventoryStatus;
  enriched.lastScanAt = item.lastScanAt || null;
  enriched.absentSince = item.absentSince || enriched.absentSince || null;
  const merged = mergePreferFilled(item, enriched, ENRICH_PRESERVE_KEYS);
  if (!isBlank(item.adUser)) {
    merged.adUser = item.adUser;
    merged.adUserFullName = item.adUserFullName;
    if (!isBlank(item.adUserSource) && item.adUserSource !== 'none') {
      merged.adUserSource = item.adUserSource;
    }
    if (!isBlank(item.department)) merged.department = item.department;
    if (!isBlank(item.departmentSource) && item.departmentSource !== 'none') {
      merged.departmentSource = item.departmentSource;
    }
    if (!isBlank(item.unit)) merged.unit = item.unit;
  }
  if (isBlank(merged.firstSeenAt) && historyRec?.firstSeen) {
    merged.firstSeenAt = fmtIso(historyRec.firstSeen);
  }
  if ((!merged.ports || !merged.ports.length) && (item.ports?.length || scanRec?.ports?.length)) {
    merged.ports = mergePorts(item.ports, scanRec?.ports);
    merged.openPorts = summarizeOpenPorts(merged.ports);
    merged.services = summarizeServices(merged.ports);
  }
  return merged;
}

function applyAdUserRecord(item, sam, adUsers, source) {
  const login = normalizeSamFromUser(sam);
  if (!login || login.endsWith('$')) return false;
  const adUser = lookupSnapshotUser(adUsers, login);
  item.adUser = login;
  item.adUserFullName = adUser?.displayName || adUser?.cn || login;
  item.adUserSource = source;
  if (adUser) {
    const dept = inferDepartment(adUser);
    if (dept.name && isBlank(item.department)) {
      item.department = dept.name;
      item.departmentSource = dept.source;
    }
    if (dept.name && isBlank(item.unit)) {
      item.unit = adUser.company || adUser.office || item.unit;
    }
  }
  return true;
}

async function enrichInventoryNetworkData(items, options = {}) {
  let arpByIp = new Map();
  try {
    const entries = await readLocalArpCache();
    for (const e of entries) {
      const mac = normalizeMacDisplay(e.mac);
      if (mac) arpByIp.set(e.ip, mac);
    }
  } catch {
    // ARP indisponível
  }

  const list = Array.isArray(items) ? items : [];
  const history = loadHostHistory();
  const probeLimit = Number(options.portProbeLimit) || 100;
  const macLimit = Number(options.macProbeLimit) || 120;
  const concurrency = Number(options.concurrency) || 8;
  let macFilled = 0;
  let firstSeenFilled = 0;
  let snmpMacFilled = 0;
  let snmpEntries = 0;

  let snmpByIp = new Map();
  if (options.snmpMac !== false) {
    try {
      const snmp = await buildSnmpIpMacIndex({
        timeoutMs: options.snmpTimeoutMs || 4500,
        autoGateway: options.snmpAutoGateway !== false,
        community: options.snmpCommunity
      });
      snmpByIp = snmp.byIp;
      snmpEntries = snmp.entries || 0;
    } catch {
      // SNMP indisponível
    }
  }

  for (const item of list) {
    if (isBlank(item.firstSeenAt)) {
      const hist = history.hosts?.[item.ip];
      if (hist?.firstSeen) {
        item.firstSeenAt = fmtIso(hist.firstSeen);
        firstSeenFilled++;
      }
    }
    if (isBlank(item.mac)) {
      const snmpRec = snmpByIp.get(item.ip);
      const mac = snmpRec?.mac || arpByIp.get(item.ip);
      if (mac) {
        item.mac = normalizeMacDisplay(mac) || mac;
        item.vendor = getVendorFromMac(item.mac);
        if (snmpRec) {
          item.macSource = 'snmp-ipNetToMedia';
          item.switchIp = snmpRec.switchIp || '—';
          item.switchPort = item.switchPort || '—';
          snmpMacFilled++;
        }
        macFilled++;
      }
    } else if (isBlank(item.vendor)) {
      const vendor = getVendorFromMac(item.mac);
      if (!isBlank(vendor)) item.vendor = vendor;
    }
    item.openPorts = summarizeOpenPorts(item.ports);
    item.services = summarizeServices(item.ports);
  }

  const macTargets = list.filter((i) => i.status === 'Online' && isBlank(i.mac)).slice(0, macLimit);
  for (let i = 0; i < macTargets.length; i += concurrency) {
    const batch = macTargets.slice(i, i + concurrency);
    await Promise.all(batch.map(async (item) => {
      const mac = await resolveMacViaPingArp(item.ip);
      if (!mac) return;
      item.mac = mac;
      item.vendor = getVendorFromMac(mac);
      macFilled++;
    }));
  }

  const probeTargets = list.filter((i) =>
    i.status === 'Online' && (!Array.isArray(i.ports) || !i.ports.length)
  ).slice(0, probeLimit);

  let portsFilled = 0;
  for (let i = 0; i < probeTargets.length; i += concurrency) {
    const batch = probeTargets.slice(i, i + concurrency);
    await Promise.all(batch.map(async (item) => {
      try {
        const found = [];
        await Promise.all(INVENTORY_PROBE_PORTS.map(async (port) => {
          if (await probeTcpOpen(item.ip, port, options.portTimeoutMs || 700)) {
            found.push({
              port,
              protocol: 'TCP',
              state: 'open',
              service: PORT_SERVICE_NAMES[port] || `TCP-${port}`
            });
          }
        }));
        if (!found.length) return;
        item.ports = mergePorts(item.ports, found);
        item.openPorts = summarizeOpenPorts(item.ports);
        item.services = summarizeServices(item.ports);
        portsFilled++;
      } catch {
        // skip host
      }
    }));
  }

  return {
    macFilled,
    snmpMacFilled,
    snmpEntries,
    portsFilled,
    firstSeenFilled,
    arpEntries: arpByIp.size,
    portProbes: probeTargets.length
  };
}

async function enrichRemoteAdUsers(items, ctx, options = {}) {
  const limit = Number(options.limit) || 300;
  const concurrency = Number(options.concurrency) || 10;
  const adUsers = ctx?.adUsers || loadAdSnapshotIndex();
  const targets = (Array.isArray(items) ? items : []).filter((i) =>
    i.status === 'Online'
    && isBlank(i.adUser)
    && /windows/i.test(String(i.os || ''))
  ).slice(0, limit);

  let resolved = 0;
  for (let i = 0; i < targets.length; i += concurrency) {
    const batch = targets.slice(i, i + concurrency);
    await Promise.all(batch.map(async (item) => {
      try {
        const remote = await queryLoggedOnUser(item.ip, options.timeoutMs || 4500);
        if (!remote) return;
        if (applyAdUserRecord(item, remote, adUsers, 'quser')) resolved++;
      } catch {
        // skip host
      }
    }));
  }
  return { resolved, scanned: targets.length };
}

async function resolveInventoryAdUsers(store, ctx, options = {}) {
  const snap = await ensureAdUserSnapshot(options.snapshotTimeoutMs || 120000);
  ctx.adUsers = loadAdSnapshotIndex();
  const items = Object.values(store.items || {});
  const network = await enrichInventoryNetworkData(items, options);
  const remote = await enrichRemoteAdUsers(items, ctx, options);
  return { snapshot: snap, ...remote, ...network };
}

function buildInventoryContext(scanAt = null, extra = {}) {
  return {
    history: loadHostHistory(),
    adUsers: loadAdSnapshotIndex(),
    agents: buildAgentIndex(),
    computers: loadAdComputerIndex(),
    scanByIp: loadLastScanIndex(),
    arpByIp: extra.arpByIp || new Map(),
    scanAt: scanAt || new Date().toISOString()
  };
}

function enrichAllItems(items, ctx = null) {
  const context = ctx || buildInventoryContext();
  return items.map((item) => enrichInventoryItem(item, context));
}

function normalizeInventorySubnet(subnet) {
  const s = String(subnet || '').trim().toLowerCase();
  if (!s || s === '—' || s === '-') return null;
  return s;
}

function normalizeInventoryHostnameKey(hostname) {
  const raw = String(hostname || '').trim().toLowerCase();
  if (!raw || raw === '—' || raw === '-') return null;
  const short = raw.split('.')[0];
  return short || null;
}

function isGenericInventoryHostname(hostname, item = {}) {
  const raw = String(hostname || '').trim().toLowerCase();
  const key = normalizeInventoryHostnameKey(hostname);
  if (!key || key.length < 2) return true;
  if (GENERIC_HOSTNAME_EXACT.has(key)) return true;
  if (item.hostnameSource === 'fallback') return true;
  if (/^inativo-\d+(\.|$)/.test(raw) || /^inativo-\d+$/.test(key)) return true;
  if (/^(equipamento|impressora|switch|router|servidor|desktop|notebook|scanner|host)-\d+$/.test(key)) return true;
  if (/^odahcfmb\d+$/.test(key)) return true;
  return false;
}

function detectFlags(items) {
  const macGroups = new Map();
  const hostGroups = new Map();

  for (const item of items) {
    const subnet = normalizeInventorySubnet(item.subnet);
    const mac = normalizeMacDisplay(item.mac);
    if (mac && subnet) {
      const macKey = `${subnet}|${mac}`;
      if (!macGroups.has(macKey)) macGroups.set(macKey, []);
      macGroups.get(macKey).push(item.ip);
    }

    const hostKey = normalizeInventoryHostnameKey(item.hostname);
    if (hostKey && subnet && !isGenericInventoryHostname(item.hostname, item)) {
      const groupKey = `${subnet}|${hostKey}`;
      if (!hostGroups.has(groupKey)) hostGroups.set(groupKey, []);
      hostGroups.get(groupKey).push({ ip: item.ip, mac });
    }
  }

  const macConflictIps = new Set();
  for (const ips of macGroups.values()) {
    if ((new Set(ips)).size > 1) ips.forEach((ip) => macConflictIps.add(ip));
  }

  const hostnameConflictIps = new Set();
  const hostnameRepeatIps = new Set();
  for (const rows of hostGroups.values()) {
    const byIp = new Map();
    for (const row of rows) {
      if (!byIp.has(row.ip)) byIp.set(row.ip, row.mac || null);
    }
    const ips = [...byIp.keys()];
    if (ips.length < 2) continue;

    const macs = [...byIp.values()].filter(Boolean);
    const uniqueMacs = new Set(macs);
    if (uniqueMacs.size >= 2) {
      ips.forEach((ip) => hostnameConflictIps.add(ip));
    } else {
      ips.forEach((ip) => hostnameRepeatIps.add(ip));
    }
  }

  for (const item of items) {
    const flags = new Set(item.flags || []);
    if (item.status === 'Offline') flags.add('offline');
    if (macConflictIps.has(item.ip)) flags.add('duplicate-mac');
    if (hostnameConflictIps.has(item.ip)) flags.add('duplicate-hostname');
    else if (hostnameRepeatIps.has(item.ip)) flags.add('duplicate-hostname-repeat');
    if (item.adUser === '—' && item.status === 'Online') flags.add('no-ad-user');
    item.flags = [...flags];
  }
  return items;
}

function syncInventoryFromScan(results, meta = {}) {
  return syncInventoryFromScanAsync(results, meta);
}

async function syncInventoryFromScanAsync(results, meta = {}) {
  const scanList = Array.isArray(results) ? results : [];
  if (scanList.length) saveLastScanSnapshot(scanList, meta);

  const store = loadStore();
  const ctx = buildInventoryContext(new Date().toISOString());
  const scanAt = ctx.scanAt;
  const scannedIps = new Set();

  let added = 0;
  let updated = 0;
  let absent = 0;
  let removed = 0;

  for (const h of scanList) {
    if (!h?.ip) continue;
    scannedIps.add(h.ip);
    const prev = store.items[h.ip] || {};
    const built = buildInventoryItem(h, ctx);
    const merged = mergeInventoryRecord(prev, built, {
      fromScan: true,
      scanAt,
      scanTarget: meta.target || store.lastScanTarget || null
    });
    store.items[h.ip] = merged;
    if (!prev.ip) added++;
    else updated++;
  }

  for (const ip of Object.keys(store.items)) {
    if (scannedIps.has(ip)) continue;
    absent++;
    let item = markAbsentFromScan(store.items[ip], ctx, meta);
    const removal = shouldRemoveInventoryItem(item, ctx, meta);
    if (removal && removal.remove) {
      archiveRemovedItem(store, item, meta, removal.reason);
      delete store.items[ip];
      removed++;
    } else {
      store.items[ip] = item;
    }
  }

  store.lastScanAt = scanAt;
  if (meta.target) store.lastScanTarget = meta.target;

  let adResolve = { resolved: 0, scanned: 0 };
  let networkEnrich = { macFilled: 0, portsFilled: 0, firstSeenFilled: 0 };
  if (meta.resolveAdUsers !== false) {
    try {
      adResolve = await resolveInventoryAdUsers(store, ctx, meta.adResolveOptions || {});
      networkEnrich = {
        macFilled: adResolve.macFilled || 0,
        portsFilled: adResolve.portsFilled || 0,
        firstSeenFilled: adResolve.firstSeenFilled || 0
      };
    } catch (err) {
      adResolve = { resolved: 0, scanned: 0, error: err.message };
    }
  } else {
    try {
      networkEnrich = await enrichInventoryNetworkData(Object.values(store.items || {}), meta.adResolveOptions || {});
    } catch {
      // ignore
    }
  }

  let allItems = detectFlags(enrichAllItems(Object.values(store.items), ctx));
  store.items = Object.fromEntries(allItems.map((i) => [i.ip, i]));
  saveStore(store);

  return {
    ok: true,
    added,
    updated,
    absent,
    removed,
    adUsersResolved: adResolve.resolved || 0,
    adUsersScanned: adResolve.scanned || 0,
    macEnriched: networkEnrich.macFilled || 0,
    snmpMacFilled: networkEnrich.snmpMacFilled || 0,
    snmpEntries: networkEnrich.snmpEntries || 0,
    portsEnriched: networkEnrich.portsFilled || 0,
    firstSeenBackfilled: networkEnrich.firstSeenFilled || 0,
    adSnapshot: adResolve.snapshot || null,
    total: allItems.length,
    lastScanAt: store.lastScanAt,
    lastScanTarget: store.lastScanTarget,
    policy: {
      persistent: true,
      minAbsentScansForRemoval: MIN_ABSENT_SCANS_FOR_REMOVAL
    }
  };
}

function computeStats(items) {
  const list = Array.isArray(items) ? items : [];
  const online = list.filter((i) => i.status === 'Online').length;
  const offline = list.filter((i) => i.status === 'Offline').length;
  const absent = list.filter((i) => i.status === 'Ausente').length;
  const inaccessible = list.filter((i) => i.status === 'Inacessível').length;
  const users = new Set(list.map((i) => i.adUser).filter((u) => u && u !== '—')).size;
  const osCounts = {};
  const deptCounts = {};
  const unitCounts = {};
  for (const i of list) {
    const os = i.os || '—';
    osCounts[os] = (osCounts[os] || 0) + 1;
    const dept = i.department || '—';
    deptCounts[dept] = (deptCounts[dept] || 0) + 1;
    const unit = i.unit || '—';
    unitCounts[unit] = (unitCounts[unit] || 0) + 1;
  }
  return {
    total: list.length,
    online,
    offline,
    absent,
    inaccessible,
    absentMarked: list.filter((i) => i.inventoryStatus === 'ausente').length,
    connectedUsers: users,
    duplicates: list.filter((i) => (i.flags || []).some((f) => f === 'duplicate-hostname' || f === 'duplicate-mac')).length,
    duplicateRepeats: list.filter((i) => (i.flags || []).includes('duplicate-hostname-repeat')).length,
    osCounts,
    departmentCounts: deptCounts,
    unitCounts,
    lastScanAt: list[0]?.lastScanAt || null
  };
}

function filterInventory(items, query = {}) {
  let list = [...items];
  const q = String(query.q || query.search || '').trim().toLowerCase();
  if (q) {
    list = list.filter((i) =>
      [i.ip, i.hostname, i.adUser, i.adUserFullName, i.mac, i.os, i.department, i.unit, i.adOu]
        .some((v) => String(v || '').toLowerCase().includes(q))
    );
  }
  if (query.status) {
    const st = String(query.status);
    list = list.filter((i) => i.status === st);
  }
  if (query.os) {
    const os = String(query.os).toLowerCase();
    list = list.filter((i) => String(i.os || '').toLowerCase().includes(os));
  }
  if (query.department) {
    const d = String(query.department).toLowerCase();
    list = list.filter((i) => String(i.department || '').toLowerCase().includes(d));
  }
  if (query.unit) {
    const u = String(query.unit).toLowerCase();
    list = list.filter((i) => String(i.unit || '').toLowerCase().includes(u));
  }
  if (query.flag) {
    list = list.filter((i) => (i.flags || []).includes(String(query.flag)));
  }

  const sort = String(query.sort || 'ip');
  const dir = String(query.dir || 'asc').toLowerCase() === 'desc' ? -1 : 1;
  list.sort((a, b) => {
    const av = a[sort] ?? '';
    const bv = b[sort] ?? '';
    return String(av).localeCompare(String(bv), 'pt-BR', { numeric: true }) * dir;
  });

  const limit = query.limit != null ? Number(query.limit) : null;
  const offset = Number(query.offset) || 0;
  const total = list.length;
  if (limit != null && limit > 0) {
    list = list.slice(offset, offset + limit);
  }

  return { items: list, total, offset, limit };
}

function getInventory(query = {}) {
  const store = loadStore();
  const ctx = buildInventoryContext(store.lastScanAt);
  let items = detectFlags(enrichAllItems(Object.values(store.items || {}), ctx));
  const filtered = filterInventory(items, query);
  const stats = computeStats(items);
  return {
    ok: true,
    stats,
    lastScanAt: store.lastScanAt,
    updatedAt: store.updatedAt,
    adSnapshotAvailable: Object.keys(ctx.adUsers).length > 0,
    adComputersCached: ctx.computers?.ok === true,
    ...filtered
  };
}

function getAllInventoryItems() {
  const store = loadStore();
  const ctx = buildInventoryContext(store.lastScanAt);
  return detectFlags(enrichAllItems(Object.values(store.items || {}), ctx));
}

