  const ws = workbook.addWorksheet('Inventário UNESP', {
    views: [{ state: 'frozen', ySplit: 8 }],
    properties: { defaultRowHeight: 18 }
  });

  ws.columns = HEADERS.map((h) => ({ key: h.key, width: h.width }));
  const colN = HEADERS.length;

  let r = applyReportHeader(ws, colN,
    'Inventário Corporativo — Complexo UNESP',
    `Gerado em ${fmtDatePt(new Date().toISOString())}  ·  Última varredura: ${fmtDatePt(meta.lastScanAt)}  ·  ${fmtReportId(meta.lastScanAt)}`,
    []
  );

  r = addStatCardsRow(ws, r, 1, [
    { label: 'Total', value: stats.total || 0, argb: ARGB.brand },
    { label: 'Online', value: stats.online || 0, argb: ARGB.pass },
    { label: 'Offline', value: stats.offline || 0, argb: ARGB.skip },
    { label: 'Ausente', value: stats.absent || 0, argb: ARGB.info },
    { label: 'Inacessível', value: stats.inaccessible || 0, argb: ARGB.fail },
    { label: 'Usuários', value: stats.connectedUsers || 0, argb: ARGB.info }
  ]);

  ws.mergeCells(r, 1, r, colN);
  styleSectionTitle(ws.getCell(r, 1), 'Equipamentos');
  ws.getRow(r).height = 22;
  r += 1;

  const hdr = ws.getRow(r);
  HEADERS.forEach((h, i) => {
    hdr.getCell(i + 1).value = h.header;
    styleTableHeader(hdr.getCell(i + 1));
  });
  hdr.height = 26;
  ws.autoFilter = { from: { row: r, column: 1 }, to: { row: r, column: colN } };
  r += 1;

  (items || []).forEach((item, idx) => {
    const row = ws.addRow({ ...item, lastScanAt: fmtDatePt(item.lastScanAt) });
    styleDataRow(row, idx, 'status');
    if ((item.flags || []).some((f) => f.startsWith('duplicate'))) {
      row.eachCell((c) => { c.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFFEF3C7' } }; });
    }
    row.height = Math.max(22, Math.ceil(String(item.adOu || '').length / 40) * 15);
  });

  addStatsSheet(workbook, 'Estatísticas UNESP', [
    ['Total', stats.total || 0],
    ['Online', stats.online || 0],
    ['Offline (confirmado)', stats.offline || 0],
    ['Ausente (não varrido)', stats.absent || 0],
    ['Inacessível', stats.inaccessible || 0],
    ['Usuários conectados', stats.connectedUsers || 0],
    ['Duplicidades (conflitos)', stats.duplicates || 0],
    ['Nomes repetidos (informativo)', stats.duplicateRepeats || 0]
  ]);

  return workbook.xlsx.writeBuffer();
}

