/**
 * Relatório PDF Inventário UNESP — tema LinkWare
 */
const PDFDocument = require('pdfkit');
const { createPdfContext } = require('./canonReportPdf');
const { C, fmtDatePt, fmtReportId } = require('./canonReportTheme');

function generateInventoryPdf(items, stats = {}, meta = {}) {
  return new Promise((resolve, reject) => {
    const doc = new PDFDocument({ margin: 0, size: 'A4', bufferPages: true });
    const chunks = [];
    doc.on('data', (c) => chunks.push(c));
    doc.on('end', () => resolve(Buffer.concat(chunks)));
    doc.on('error', reject);

    const ctx = createPdfContext(doc);
    ctx._topSubtitle = 'Inventário Corporativo · Complexo UNESP';
    ctx.newPage(true);

    ctx.drawMetaBox('NetScan Canon — Inventário UNESP', [
      ['Data/Hora', fmtDatePt(new Date().toISOString())],
      ['Última varredura', fmtDatePt(meta.lastScanAt)],
      ['Relatório', fmtReportId(meta.lastScanAt)],
      ['Operador', process.env.USERNAME || process.env.USER || '—']
    ]);

    ctx.drawStatCards([
      { label: 'Total', value: stats.total || 0 },
      { label: 'Online', value: stats.online || 0, color: C.pass },
      { label: 'Offline', value: stats.offline || 0, color: C.muted },
      { label: 'Ausente', value: stats.absent || 0, color: C.info },
      { label: 'Inacessível', value: stats.inaccessible || 0, color: C.fail },
      { label: 'Usuários', value: stats.connectedUsers || 0, color: C.info }
    ]);

    if (stats.total) {
      const onlinePct = Math.round(((stats.online || 0) / stats.total) * 100);
      ctx.drawProgressBar('Máquinas online', onlinePct, C.pass);
    }

    ctx.drawSectionTitle('Equipamentos inventariados');
    const cols = [52, 78, 58, 82, 48, 48, 95];
    const headers = ['IP', 'Hostname', 'Usuário', 'Nome', 'Status', 'SO', 'Departamento'];

    function drawHdr() {
      const y = doc.y;
      doc.rect(ctx.PAGE.left, y, ctx.PAGE.width, 16).fill(C.brand);
      doc.fillColor('#fff').fontSize(7);
      let x = ctx.PAGE.left + 3;
      headers.forEach((h, i) => { doc.text(h, x, y + 4, { width: cols[i] }); x += cols[i]; });
      doc.y = y + 18;
    }

    drawHdr();
    (items || []).forEach((item, i) => {
      if (doc.y > ctx.PAGE.contentBottom) {
        ctx.newPage(false);
        drawHdr();
      }
      const y = doc.y;
      if (i % 2 === 0) doc.rect(ctx.PAGE.left, y, ctx.PAGE.width, 14).fill('#f1f5f9');
      const stColor = item.status === 'Online' ? C.pass
        : item.status === 'Offline' ? C.muted
          : item.status === 'Ausente' ? C.info
            : C.fail;
      const vals = [item.ip, item.hostname, item.adUser, item.adUserFullName, item.status, item.os, item.department];
      let x = ctx.PAGE.left + 3;
      vals.forEach((v, ci) => {
        doc.fillColor(ci === 4 ? stColor : C.body).fontSize(6.5).text(String(v || '—').slice(0, ci === 6 ? 50 : 22), x, y + 3, { width: cols[ci] });
        x += cols[ci];
      });
      doc.y = y + 14;
    });

    ctx.stampFooters('Inventário UNESP');
    doc.end();
  });
}

module.exports = { generateInventoryPdf };

/**
 * Export CSV Inventário UNESP — UTF-16 LE para Excel Windows
 */
const { fmtDatePt, REPORT_VERSION } = require('./canonReportTheme');

const HEADERS = [
  'IP', 'Hostname', 'Usuário AD', 'Nome completo', 'Sistema operacional', 'MAC', 'Fabricante',
  'Domínio AD', 'OU', 'Status', 'Uptime', 'Última comunicação', 'Última varredura',
  'Departamento', 'Unidade'
];

function csvCell(val) {
  const s = String(val ?? '').replace(/"/g, '""');
  return `"${s}"`;
}

function toUtf16LeBuffer(text) {
  const buf = Buffer.alloc(2 + text.length * 2);
  buf[0] = 0xFF;
  buf[1] = 0xFE;
  for (let i = 0; i < text.length; i++) {
    buf.writeUInt16LE(text.charCodeAt(i), 2 + i * 2);
  }
  return buf;
}

function csvRow(cells) {
  return cells.map(csvCell).join(';');
}

function generateInventoryCsv(items, stats = {}) {
  const lines = ['sep=;'];
  lines.push(csvRow(['NetScan Canon — Inventário UNESP v' + REPORT_VERSION]));
  lines.push(csvRow(['Total', stats.total ?? (items || []).length]));
  lines.push(csvRow(['Online', stats.online ?? '']));
  lines.push(csvRow(['Offline (confirmado)', stats.offline ?? '']));
  lines.push(csvRow(['Ausente (não varrido)', stats.absent ?? '']));
  lines.push(csvRow(['Inacessível', stats.inaccessible ?? 0]));
  lines.push('');
  lines.push(HEADERS.map(csvCell).join(';'));
  for (const i of items || []) {
    lines.push([
      i.ip, i.hostname, i.adUser, i.adUserFullName, i.os, i.mac, i.vendor,
      i.adDomain, i.adOu, i.status, i.uptime, i.lastCommunication,
      fmtDatePt(i.lastScanAt), i.department, i.unit
    ].map(csvCell).join(';'));
  }
  return toUtf16LeBuffer(`${lines.join('\r\n')}\r\n`);
}

module.exports = { generateInventoryCsv };

/* Inventário Corporativo UNESP — UI */
(function () {
  const COLS = [
    { key: 'ip', label: 'IP' },
    { key: 'hostname', label: 'Hostname' },
    { key: 'adUser', label: 'Usuário AD' },
    { key: 'adUserFullName', label: 'Nome completo' },
    { key: 'os', label: 'SO' },
    { key: 'mac', label: 'MAC' },
    { key: 'vendor', label: 'Fabricante' },
    { key: 'adDomain', label: 'Domínio' },
    { key: 'adOu', label: 'OU' },
    { key: 'status', label: 'Status' },
    { key: 'uptime', label: 'Uptime' },
    { key: 'lastCommunication', label: 'Última com.' },
    { key: 'lastScanAt', label: 'Última varredura' },
    { key: 'department', label: 'Departamento' },
    { key: 'unit', label: 'Unidade' },
    { key: 'openPorts', label: 'Portas abertas', colClass: 'col-ports' },
    { key: 'services', label: 'Serviços', colClass: 'col-services' },
    { key: 'firstSeenAt', label: '1ª detecção', colClass: 'col-first-seen' }
  ];

  const FLAG_LABELS = {
    'duplicate-hostname': 'conflito hostname',
    'duplicate-hostname-repeat': 'hostname repetido',
    'duplicate-mac': 'MAC duplicado'
  };

  function formatInventoryFlag(flag) {
    return FLAG_LABELS[flag] || flag;
  }

  let state = { items: [], stats: {}, sort: 'ip', dir: 'asc', loading: false, page: 1, pageSize: 50, total: 0 };
  let refreshTimer = null;

  function esc(s) {
    if (typeof escapeHtml === 'function') return escapeHtml(s);
    return String(s ?? '').replace(/[&<>"']/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
  }

  function fmtScan(iso) {
    if (!iso) return '—';
    try { return new Date(iso).toLocaleString('pt-BR'); } catch { return iso; }
  }

  function fmtFirstSeen(iso) {
    return fmtScan(iso);
  }

  function statusClass(st) {
    if (st === 'Online') return 'inv-status-online';
    if (st === 'Offline') return 'inv-status-offline';
    if (st === 'Ausente') return 'inv-status-ausente';
    return 'inv-status-inacessível';
  }

  function rowClass(item) {
    const st = item.status;
    if (st === 'Inacessível') return 'row-inaccessible';
    if (st === 'Ausente') return 'row-absent';
    if (item.flags?.includes('duplicate-hostname') || item.flags?.includes('duplicate-mac')) return 'row-duplicate';
    if (item.flags?.includes('duplicate-hostname-repeat')) return 'row-duplicate-repeat';
    if (st === 'Offline') return 'row-offline';
    return '';
  }

  async function apiGet(path) {
    const res = await fetch(path);
    if (res.status === 401) {
      if (typeof window.gateCanonModalsArea === 'function') {
        window.gateCanonModalsArea({ target: 'inventory' });
      }
      throw new Error('Autenticação necessária — faça login.');
    }
    const data = await res.json().catch(() => ({}));
    if (!res.ok) throw new Error(data.error || `HTTP ${res.status}`);
    return data;
  }

  async function apiPost(path, body = {}) {
    const res = await fetch(path, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
    if (res.status === 401) {
      if (typeof window.gateCanonModalsArea === 'function') {
        window.gateCanonModalsArea({ target: 'inventory' });
      }
      throw new Error('Autenticação necessária — faça login.');
    }
    const data = await res.json().catch(() => ({}));
    if (!res.ok) throw new Error(data.error || `HTTP ${res.status}`);
    return data;
  }

  async function loadInventory(syncFirst = false) {
    const statusEl = document.getElementById('inventory-status');
    if (statusEl) statusEl.textContent = syncFirst ? 'Sincronizando inventário…' : 'Carregando…';
    state.loading = true;
    try {
      if (syncFirst) {
        if (statusEl) statusEl.textContent = 'Sincronizando inventário e usuários AD…';
        let adResolved = null;
        let syncMode = null;
        let syncMeta = {};
        try {
          syncMeta = await apiPost('/api/inventory/sync', {});
          adResolved = syncMeta.adUsersResolved;
          syncMode = syncMeta.mode || 'scan';
        } catch (err) {
          if (!/scan disponível|varredura/i.test(String(err.message || ''))) throw err;
          if (statusEl) statusEl.textContent = 'Resolvendo usuários AD (query user)…';
          syncMeta = await apiPost('/api/inventory/resolve-ad-users', {});
          adResolved = syncMeta.resolved;
          syncMode = 'ad-only';
        }
        if (adResolved == null) {
          if (statusEl) statusEl.textContent = 'Resolvendo usuários AD (query user)…';
          syncMeta = await apiPost('/api/inventory/resolve-ad-users', {});
          adResolved = syncMeta.resolved;
        }
        if (statusEl && adResolved != null) {
          const extras = [];
          if (syncMeta.macEnriched > 0) extras.push(`MAC: ${syncMeta.macEnriched}`);
          if (syncMeta.macFilled > 0) extras.push(`MAC: ${syncMeta.macFilled}`);
          if (syncMeta.snmpMacFilled > 0) extras.push(`MAC SNMP: ${syncMeta.snmpMacFilled}`);
          if (syncMeta.snmpEntries > 0) extras.push(`tabela SNMP: ${syncMeta.snmpEntries}`);
          if (syncMeta.portsEnriched > 0) extras.push(`portas: ${syncMeta.portsEnriched}`);
          if (syncMeta.portsFilled > 0) extras.push(`portas: ${syncMeta.portsFilled}`);
          if (syncMeta.firstSeenBackfilled > 0) extras.push(`1ª detecção: ${syncMeta.firstSeenBackfilled}`);
          if (syncMeta.firstSeenFilled > 0) extras.push(`1ª detecção: ${syncMeta.firstSeenFilled}`);
          const modeHint = syncMode === 'ad-only' ? ' (sem varredura em memória)' : '';
          const extraHint = extras.length ? ` · ${extras.join(' · ')}` : '';
          statusEl.textContent = `Usuários AD resolvidos: ${adResolved}${modeHint}${extraHint} · carregando tabela…`;
        }
      }
      const q = new URLSearchParams();
      const search = document.getElementById('inventory-search')?.value?.trim();
      const status = document.getElementById('inventory-filter-status')?.value;
      const os = document.getElementById('inventory-filter-os')?.value?.trim();
      const dept = document.getElementById('inventory-filter-dept')?.value?.trim();
      const unit = document.getElementById('inventory-filter-unit')?.value?.trim();
      if (search) q.set('q', search);
      if (status) q.set('status', status);
      if (os) q.set('os', os);
      if (dept) q.set('department', dept);
      if (unit) q.set('unit', unit);
      q.set('sort', state.sort);
      q.set('dir', state.dir);
      q.set('limit', String(state.pageSize));
      q.set('offset', String((state.page - 1) * state.pageSize));
      const data = await apiGet(`/api/inventory?${q}`);
      state.items = data.items || [];
      state.total = data.total != null ? data.total : state.items.length;
      state.stats = data.stats || {};
      state.lastScanAt = data.lastScanAt;
      renderStats();
      renderTable();
      if (statusEl) {
        const snapHint = data.adSnapshotAvailable === false ? ' · Snapshot AD ausente (rode varredura ou sync AD)' : '';
        const policyHint = ' · Inventário persistente (registros não são removidos automaticamente)';
        statusEl.textContent = `${data.total || 0} equipamento(s) · Última varredura: ${fmtScan(data.lastScanAt)}${snapHint}${policyHint}`;
        statusEl.className = 'ad-status-bar ok';
      }
    } catch (err) {
      if (statusEl) {
        statusEl.textContent = err.message;
        statusEl.className = 'ad-status-bar error';
      }
    } finally {
      state.loading = false;
    }
  }

  function renderStats() {
    const grid = document.getElementById('inventory-stats-grid');
    if (!grid) return;
    const s = state.stats;
    grid.innerHTML = `
      <div class="inventory-stat-card canon-ds-stat-card"><strong>${s.total ?? 0}</strong><span>Total</span></div>
      <div class="inventory-stat-card canon-ds-stat-card"><strong>${s.online ?? 0}</strong><span>Online</span></div>
      <div class="inventory-stat-card offline canon-ds-stat-card"><strong>${s.offline ?? 0}</strong><span>Offline</span></div>
      <div class="inventory-stat-card absent canon-ds-stat-card"><strong>${s.absent ?? 0}</strong><span>Ausente</span></div>
      <div class="inventory-stat-card danger canon-ds-stat-card"><strong>${s.inaccessible ?? 0}</strong><span>Inacessível</span></div>
      <div class="inventory-stat-card canon-ds-stat-card"><strong>${s.connectedUsers ?? 0}</strong><span>Usuários</span></div>
      <div class="inventory-stat-card warn canon-ds-stat-card"><strong>${s.duplicates ?? 0}</strong><span>Conflitos</span></div>
      <div class="inventory-stat-card canon-ds-stat-card"><strong>${s.duplicateRepeats ?? 0}</strong><span>Nomes repetidos</span></div>
    `;
  }

  function updateInventoryTableMeta() {
    const meta = document.getElementById('inventory-table-meta');
    const indicator = document.getElementById('inventory-page-indicator');
    const prevBtn = document.getElementById('inventory-page-prev');
    const nextBtn = document.getElementById('inventory-page-next');
    const total = state.total || 0;
    const pageCount = total === 0 ? 1 : Math.ceil(total / state.pageSize);

    if (state.page > pageCount) state.page = pageCount;
    if (state.page < 1) state.page = 1;

    const start = total === 0 ? 0 : (state.page - 1) * state.pageSize + 1;
    const end = Math.min(state.page * state.pageSize, total);

    if (meta) {
      if (total === 0) {
        meta.textContent = 'Nenhum registro';
      } else {
        const plural = total !== 1 ? 's' : '';
        meta.textContent = `Mostrando ${start}–${end} de ${total} registro${plural}`;
      }
    }
    if (indicator) indicator.textContent = `${state.page} / ${Math.max(pageCount, 1)}`;
    if (prevBtn) prevBtn.disabled = state.page <= 1;
    if (nextBtn) nextBtn.disabled = state.page >= pageCount || total === 0;
  }

  function renderTable() {
    const wrap = document.getElementById('inventory-table-wrap');
    if (!wrap) return;
    updateInventoryTableMeta();
    if (!state.items.length) {
      wrap.innerHTML = '<div class="inventory-empty">Nenhum equipamento no inventário.<br>Execute uma <strong>varredura</strong> e clique em <strong>Sincronizar</strong>.</div>';
      return;
    }
    const head = COLS.map((c) => {
      const cls = [
        state.sort === c.key ? `sorted-${state.dir}` : '',
        c.colClass || (c.wide ? 'col-wide' : '')
      ].filter(Boolean).join(' ');
      return `<th data-inv-sort="${c.key}" class="${cls}">${esc(c.label)}</th>`;
    }).join('');
    const body = state.items.map((item) => {
      const flags = (item.flags || []).filter((f) => f.startsWith('duplicate')).map((f) =>
        `<span class="inventory-flag-badge inventory-flag-${esc(f.replace(/[^a-z-]/g, ''))}" title="${esc(f)}">${esc(formatInventoryFlag(f))}</span>`).join('');
      const ports = esc(item.openPorts);
      const services = esc(item.services);
      const firstSeen = fmtFirstSeen(item.firstSeenAt);
      return `<tr class="${rowClass(item)}">
        <td>${esc(item.ip)}</td>
        <td>${esc(item.hostname)}${flags}</td>
        <td>${esc(item.adUser)}</td>
        <td>${esc(item.adUserFullName)}</td>
        <td>${esc(item.os)}</td>
        <td>${esc(item.mac)}</td>
        <td>${esc(item.vendor)}</td>
        <td>${esc(item.adDomain)}</td>
        <td>${esc(item.adOu)}</td>
        <td><span class="inv-status ${statusClass(item.status)}">${esc(item.status)}</span></td>
        <td>${esc(item.uptime)}</td>
        <td>${esc(item.lastCommunication)}</td>
        <td>${esc(fmtScan(item.lastScanAt))}</td>
        <td>${esc(item.department)}</td>
        <td>${esc(item.unit)}</td>
        <td class="col-ports inv-cell-expandable" data-full-text="${ports}">${ports}</td>
        <td class="col-services inv-cell-expandable" data-full-text="${services}">${services}</td>
        <td class="col-first-seen">${firstSeen}</td>
      </tr>`;
    }).join('');
    wrap.innerHTML = `<table class="inventory-table"><thead><tr>${head}</tr></thead><tbody>${body}</tbody></table>`;
    wrap.querySelectorAll('[data-inv-sort]').forEach((th) => {
      th.addEventListener('click', () => {
        const key = th.getAttribute('data-inv-sort');
        if (state.sort === key) state.dir = state.dir === 'asc' ? 'desc' : 'asc';
        else { state.sort = key; state.dir = 'asc'; }
        state.page = 1;
        loadInventory(false);
      });
    });
    requestAnimationFrame(() => wireExpandableInventoryCells(wrap));
  }

  function wireExpandableInventoryCells(root) {
    if (!root) return;

    root.querySelectorAll('td.inv-cell-expandable').forEach((td) => {
      td.classList.remove('is-truncated', 'is-expanded');
      td.removeAttribute('tabindex');
      td.removeAttribute('role');
      td.removeAttribute('aria-expanded');
      td.removeAttribute('title');

      const text = (td.getAttribute('data-full-text') || td.textContent || '').trim();
      if (!text || text === '—') return;

      if (td.scrollWidth > td.clientWidth + 1) {
        td.classList.add('is-truncated');
        td.setAttribute('tabindex', '0');
        td.setAttribute('role', 'button');
        td.setAttribute('aria-expanded', 'false');
        td.setAttribute('title', 'Clique para ver tudo');
      }
    });

    if (root.dataset.expandBound === '1') return;
    root.dataset.expandBound = '1';

    root.addEventListener('click', (e) => {
      const td = e.target.closest('td.inv-cell-expandable.is-truncated');
      if (!td || !root.contains(td)) return;
      e.stopPropagation();

      const willExpand = !td.classList.contains('is-expanded');
      root.querySelectorAll('td.inv-cell-expandable.is-expanded').forEach((el) => {
        if (el === td) return;
        el.classList.remove('is-expanded');
        el.setAttribute('aria-expanded', 'false');
        el.setAttribute('title', 'Clique para ver tudo');
      });

      td.classList.toggle('is-expanded', willExpand);
      td.setAttribute('aria-expanded', willExpand ? 'true' : 'false');
      td.setAttribute('title', willExpand ? 'Clique para recolher' : 'Clique para ver tudo');
    });

    root.addEventListener('keydown', (e) => {
      if (e.key !== 'Enter' && e.key !== ' ') return;
      const td = e.target.closest('td.inv-cell-expandable.is-truncated');
      if (!td || !root.contains(td)) return;
      e.preventDefault();
      td.click();
    });
  }

  async function exportFile(path, ext) {
    const res = await fetch(path, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: '{}' });
    if (res.status === 401) {
      if (typeof window.gateCanonModalsArea === 'function') {
        window.gateCanonModalsArea({ target: 'inventory' });
      }
      throw new Error('Autenticação necessária — faça login.');
    }
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.error || 'Falha na exportação');
    }
    const blob = await res.blob();
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `inventario-unesp-${new Date().toISOString().slice(0, 10)}.${ext}`;
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
  }

  function openInventoryModalDirect() {
    const backdrop = document.getElementById('inventory-modal-backdrop');
    if (!backdrop) return;
    backdrop.classList.remove('hidden');
    backdrop.setAttribute('aria-hidden', 'false');
    loadInventory(false);
    if (refreshTimer) clearInterval(refreshTimer);
    refreshTimer = setInterval(() => {
      if (!backdrop.classList.contains('hidden')) loadInventory(false);
    }, 60000);
  }

  function openInventoryModal() {
    if (typeof window.gateCanonModalsArea === 'function') {
      window.gateCanonModalsArea({ target: 'inventory' });
      return;
    }
    openInventoryModalDirect();
  }

  window.openInventoryModalDirect = openInventoryModalDirect;

  function closeInventoryModal() {
    const backdrop = document.getElementById('inventory-modal-backdrop');
    if (!backdrop) return;
    backdrop.classList.add('hidden');
    backdrop.setAttribute('aria-hidden', 'true');
    if (refreshTimer) { clearInterval(refreshTimer); refreshTimer = null; }
  }

  function setScanProgress(percent) {
    const bar = document.getElementById('inventory-scan-progress');
    const wrap = document.getElementById('inventory-scan-progress-wrap');
    if (!bar || !wrap) return;
    if (percent > 0 && percent < 100) {
      wrap.classList.remove('hidden');
      bar.style.width = `${percent}%`;
    } else {
      wrap.classList.add('hidden');
      bar.style.width = '0%';
    }
  }

  function wireInventoryUi() {
    const openBtn = document.getElementById('inventory-open-btn');
    const closeBtn = document.getElementById('inventory-modal-close');
    const backdrop = document.getElementById('inventory-modal-backdrop');
    if (openBtn && !openBtn.dataset.wired) {
      openBtn.dataset.wired = '1';
      openBtn.addEventListener('click', openInventoryModal);
    }
    if (closeBtn && !closeBtn.dataset.wired) {
      closeBtn.dataset.wired = '1';
      closeBtn.addEventListener('click', closeInventoryModal);
    }
    if (backdrop && !backdrop.dataset.wired) {
      backdrop.dataset.wired = '1';
      backdrop.addEventListener('click', (e) => { if (e.target === backdrop) closeInventoryModal(); });
    }
    document.getElementById('inventory-sync-btn')?.addEventListener('click', () => loadInventory(true));
    document.getElementById('inventory-export-xlsx-btn')?.addEventListener('click', () =>
      exportFile('/api/inventory/export-xlsx', 'xlsx').catch((e) => alert(e.message)));
    document.getElementById('inventory-export-pdf-btn')?.addEventListener('click', () =>
      exportFile('/api/inventory/export-pdf', 'pdf').catch((e) => alert(e.message)));
    document.getElementById('inventory-export-csv-btn')?.addEventListener('click', () =>
      exportFile('/api/inventory/export-csv', 'csv').catch((e) => alert(e.message)));

    let debounce;
    ['inventory-search', 'inventory-filter-os', 'inventory-filter-dept', 'inventory-filter-unit'].forEach((id) => {
      document.getElementById(id)?.addEventListener('input', () => {
        clearTimeout(debounce);
        debounce = setTimeout(() => {
          state.page = 1;
          loadInventory(false);
        }, 300);
      });
    });
    document.getElementById('inventory-filter-status')?.addEventListener('change', () => {
      state.page = 1;
      loadInventory(false);
    });

    const pageSizeSelect = document.getElementById('inventory-page-size');
    const pagePrev = document.getElementById('inventory-page-prev');
    const pageNext = document.getElementById('inventory-page-next');

    if (pageSizeSelect && !pageSizeSelect.dataset.wired) {
      pageSizeSelect.dataset.wired = '1';
      state.pageSize = parseInt(pageSizeSelect.value, 10) || 50;
      pageSizeSelect.addEventListener('change', () => {
        state.pageSize = parseInt(pageSizeSelect.value, 10) || 50;
        state.page = 1;
        loadInventory(false);
      });
    }
    if (pagePrev && !pagePrev.dataset.wired) {
      pagePrev.dataset.wired = '1';
      pagePrev.addEventListener('click', () => {
        if (state.page > 1) {
          state.page -= 1;
          loadInventory(false);
        }
      });
    }
    if (pageNext && !pageNext.dataset.wired) {
      pageNext.dataset.wired = '1';
      pageNext.addEventListener('click', () => {
        state.page += 1;
        loadInventory(false);
      });
    }
  }

  window.refreshInventoryIfOpen = function () {
    const backdrop = document.getElementById('inventory-modal-backdrop');
    if (backdrop && !backdrop.classList.contains('hidden')) {
      loadInventory(true);
    }
  };

  window.setInventoryScanProgress = setScanProgress;

  window.wireInventoryUi = wireInventoryUi;
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', wireInventoryUi);
  } else {
    wireInventoryUi();
  }
})();

