const crypto = require('crypto');

const USERNAME = process.env.CANON_AUTH_USER || 'Canon*@';const PBKDF2_ITERATIONS = 120000;
const PBKDF2_KEYLEN = 32;
const PBKDF2_DIGEST = 'sha256';
const SALT = process.env.CANON_AUTH_SALT || 'netscan-canon-auth-v1';
/** Hash PBKDF2 da senha padrão (10 chars: letras, números, símbolos). Sobrescreva via CANON_AUTH_PASSWORD_HASH. */
const PASSWORD_HASH = process.env.CANON_AUTH_PASSWORD_HASH
  || 'b9341581a23078331a293268da1982c23440d8959457f7cc7bcfa5468cc798db';

const SESSION_TTL_MS = Number(process.env.CANON_AUTH_SESSION_MS) || 2 * 60 * 60 * 1000;

const SCOPES = {
  DASHBOARD: 'dashboard',
  MODALS: 'modals'
};

const sessions = new Map();

function timingSafeEqualText(a, b) {
  const ba = Buffer.from(String(a), 'utf8');
  const bb = Buffer.from(String(b), 'utf8');
  if (ba.length !== bb.length) return false;
  return crypto.timingSafeEqual(ba, bb);
}

function hashPassword(password) {
  return crypto.pbkdf2Sync(
    String(password),
    SALT,
    PBKDF2_ITERATIONS,
    PBKDF2_KEYLEN,
    PBKDF2_DIGEST
  ).toString('hex');
}

function verifyPassword(password) {
  const hash = hashPassword(password);
  const a = Buffer.from(hash, 'hex');
  const b = Buffer.from(PASSWORD_HASH, 'hex');
  if (a.length !== b.length) return false;
  return crypto.timingSafeEqual(a, b);
}

function verifyUsername(username) {
  return timingSafeEqualText(username, USERNAME);
}

function extractToken(req) {
  const hdr = req.headers['x-canon-session'];
  if (hdr && typeof hdr === 'string') return hdr.trim();
  const auth = req.headers.authorization;
  if (auth && auth.startsWith('Bearer ')) return auth.slice(7).trim();
  return null;
}

function normalizeScope(scope) {
  return scope === SCOPES.MODALS ? SCOPES.MODALS : SCOPES.DASHBOARD;
}

function createSession(scope) {
  const normalized = normalizeScope(scope);
  const token = crypto.randomBytes(32).toString('hex');
  sessions.set(token, {
    createdAt: Date.now(),
    expiresAt: Date.now() + SESSION_TTL_MS,
    scope: normalized
  });
  return token;
}

function getSessionStatus(token, requiredScope) {
  if (!token) return null;
  const session = sessions.get(token);
  if (!session) return null;
  if (Date.now() > session.expiresAt) {
    sessions.delete(token);
    return null;
  }
  if (requiredScope && session.scope !== requiredScope) return null;
  return {
    scope: session.scope,
    expiresInMs: Math.max(0, session.expiresAt - Date.now())
  };
}

function isValidSession(token, requiredScope) {
  return !!getSessionStatus(token, requiredScope);
}

function revokeSession(token) {
  if (!token) return;
  sessions.delete(token);
}

setInterval(() => {
  const now = Date.now();
  for (const [token, session] of sessions) {
    if (now > session.expiresAt) sessions.delete(token);
  }
}, 10 * 60 * 1000).unref();

function requireAuth(requiredScope) {
  return (req, res, next) => {
    const token = extractToken(req);
    if (!isValidSession(token, requiredScope)) {
      return res.status(401).json({
        ok: false,
        error: 'Autenticação necessária.',
        code: 'AUTH_REQUIRED'
      });
    }
    req.canonSession = token;
    next();
  };
}

function login(username, password, scope) {
  if (!verifyUsername(username) || !verifyPassword(password)) {
    return { ok: false, error: 'Login ou senha inválidos.' };
  }
  const normalized = normalizeScope(scope);
  const token = createSession(normalized);
  return { ok: true, token, scope: normalized, expiresInMs: SESSION_TTL_MS };
}

module.exports = {
  requireAuth,
  login,
  revokeSession,
  isValidSession,
  getSessionStatus,
  extractToken,
  SESSION_TTL_MS,
  SCOPES
};

