function exportMapImage(format) {
  if (!networkInstance || !latestTopology) {
    logToConsole('[!] Mapa indisponível para exportação.', 'error-msg');
    return;
  }

  const canvas = document.querySelector('#map-canvas canvas');
  if (!canvas) {
    logToConsole('[!] Canvas do mapa não encontrado.', 'error-msg');
    return;
  }

  if (format === 'png') {
    const url = canvas.toDataURL('image/png');
    const link = document.createElement('a');
    link.href = url;
    link.download = `topologia_rede_${new Date().toISOString().replace(/[:.]/g, '-')}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    return;
  }

  if (format === 'svg') {
    const svgText = generateSvgExport();
    if (!svgText) {
      logToConsole('[!] Não foi possível gerar SVG do mapa.', 'error-msg');
      return;
    }
    const blob = new Blob([svgText], { type: 'image/svg+xml;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `topologia_rede_${new Date().toISOString().replace(/[:.]/g, '-')}.svg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  }
}

function generateSvgExport() {
  if (!networkInstance || !latestTopology) return null;

  const positions = networkInstance.getPositions();
  const padding = 50;
  const points = Object.values(positions);
  if (points.length === 0) return null;

  let minX = Math.min(...points.map(p => p.x));
  let maxX = Math.max(...points.map(p => p.x));
  let minY = Math.min(...points.map(p => p.y));
  let maxY = Math.max(...points.map(p => p.y));
  const width = Math.round(maxX - minX + padding * 2);
  const height = Math.round(maxY - minY + padding * 2);

  const getPoint = (id) => {
    const pos = positions[id];
    return {
      x: Math.round(pos.x - minX + padding),
      y: Math.round(pos.y - minY + padding)
    };
  };

  const escapeXml = (str) => str.replace(/[&<>"']/g, c => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' })[c]);

  const edgeSvg = latestTopology.edges.map(edge => {
    const from = getPoint(edge.from);
    const to = getPoint(edge.to);
    return `<line x1="${from.x}" y1="${from.y}" x2="${to.x}" y2="${to.y}" stroke="#888" stroke-width="2" opacity="0.75"/>`;
  }).join('');

  const nodeSvg = latestTopology.nodes.map(node => {
    const pos = getPoint(node.id);
    const fill = (node.color && node.color.background) || '#4facfe';
    return `
      <g>
        <circle cx="${pos.x}" cy="${pos.y}" r="18" fill="${fill}" stroke="#fff" stroke-width="2" opacity="0.95" />
        <text x="${pos.x}" y="${pos.y + 5}" text-anchor="middle" font-family="Arial, Helvetica, sans-serif" font-size="10" fill="#fff">${escapeXml(node.label)}</text>
      </g>`;
  }).join('');

  return `<?xml version="1.0" encoding="UTF-8"?>\n<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">\n  <rect width="100%" height="100%" fill="#05070a" />\n  ${edgeSvg}\n  ${nodeSvg}\n</svg>`;
}

let visNetworkLoadPromise = null;

function loadVisNetwork() {
  if (window.vis?.Network) return Promise.resolve(window.vis);
  if (visNetworkLoadPromise) return visNetworkLoadPromise;
  visNetworkLoadPromise = new Promise((resolve, reject) => {
    const script = document.createElement('script');
    script.src = 'https://unpkg.com/vis-network/standalone/umd/vis-network.min.js';
    script.async = true;
    script.onload = () => resolve(window.vis);
    script.onerror = () => reject(new Error('Falha ao carregar biblioteca do mapa (vis-network).'));
    document.head.appendChild(script);
  });
  return visNetworkLoadPromise;
}

async function renderNetworkMap() {
  const { nodes, edges } = buildTopologyFromResults(scanResults);
  latestTopology = { nodes, edges };

  const container = document.getElementById('map-canvas');
  container.innerHTML = '';

  if (nodes.length === 0) {
    container.innerHTML = '<div class="terminal-line error-msg">Nenhum resultado de varredura disponível para gerar o mapa.</div>';
    return;
  }

  let vis;
  try {
    vis = await loadVisNetwork();
  } catch (err) {
    container.innerHTML = `<div class="terminal-line error-msg">${escapeHtml(err.message)}</div>`;
    return;
  }

  const data = {
    nodes: new vis.DataSet(nodes),
    edges: new vis.DataSet(edges)
  };

  const options = {
    nodes: {
      shape: 'dot',
      size: 18,
      font: { color: '#ffffff', size: 12, face: 'Plus Jakarta Sans' }
    },
    edges: {
      color: { color: '#8e96b5', highlight: '#f59e0b' },
      width: 2,
      smooth: { type: 'cubicBezier' }
    },
    layout: {
      improvedLayout: true
    },
    physics: {
      enabled: true,
      stabilization: {
        enabled: true,
        iterations: 300,
        updateInterval: 50
      },
      barnesHut: {
        gravitationalConstant: -2000,
        centralGravity: 0.18,
        springLength: 180,
        springConstant: 0.04,
        damping: 0.09
      }
    },
    interaction: {
      hover: true,
      tooltipDelay: 100,
      dragView: true,
      zoomView: true,
      multiselect: false
    }
  };

  networkInstance = new vis.Network(container, data, options);
  networkInstance.once('stabilizationIterationsDone', () => {
    networkInstance.fit({ animation: true, easingFunction: 'easeInOutQuad', duration: 600 });
  });
  networkInstance.on('resize', () => networkInstance.fit({ animation: { duration: 400, easingFunction: 'easeInOutQuad' } }));

  networkInstance.on('click', (params) => {
    if (params.nodes && params.nodes.length > 0) {
      const nodeId = params.nodes[0];
      const node = nodes.find(n => n.id === nodeId);
      if (node && node.data && node.data.ip) {
        // Scroll table to host row
        const row = document.getElementById(`row-${node.data.ip.replace(/\./g, '_')}`);
        if (row) {
          row.scrollIntoView({ behavior: 'smooth', block: 'center' });
          row.classList.add('highlight-row');
          setTimeout(() => row.classList.remove('highlight-row'), 2500);
        }
      }
    }
  });
}

function buildTopologyFromResults(results) {
  const nodes = [];
  const edges = [];

  // Map VLAN/subnet groups to colors
  const vlanMap = {};
  const vlanColors = ['#4facfe','#00f2fe','#10b981','#f59e0b','#ef4444','#8b5cf6','#fb7185'];
  let vlanIdx = 0;

  // Create subnet nodes
  const subnets = {};
  results.forEach(h => {
    const subnet = h.subnet || 'unknown';
    if (!subnets[subnet]) subnets[subnet] = { id: `subnet:${subnet}`, hosts: [] };
    subnets[subnet].hosts.push(h);
  });

  Object.keys(subnets).forEach((subnet, idx) => {
    nodes.push({ id: `subnet:${subnet}`, label: subnet, shape: 'box', color: '#222', font: { color: '#fff' }, data: { subnet } });
  });

  // Host nodes
  results.forEach(host => {
    const id = `host:${host.ip}`;
    const label = `${host.ip}\n${host.hostname !== 'N/A' ? host.hostname : ''}`;
    const vlan = host.vlan || 'default';
    if (!vlanMap[vlan]) vlanMap[vlan] = vlanColors[vlanIdx++ % vlanColors.length];

    const color = host.environment === 'OT/ICS' ? '#ff8a65' : (host.isDMZ ? '#f59e0b' : vlanMap[vlan]);

    nodes.push({ id, label, title: `${host.ip}\n${host.vendor}\n${host.os}`, group: vlan, color: { background: color }, data: { ip: host.ip, host } });

    // Edge to subnet
    const subnetId = `subnet:${host.subnet || 'unknown'}`;
    edges.push({ from: id, to: subnetId });
  });

  return { nodes, edges };
}

// --- Idle hosts analysis ---
let lastIdlePayload = null;
let idlePage = 1;
let idlePageSize = 50;
let idleHostsCache = [];

function escapeHtml(value) {
  return String(value == null ? '' : value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function formatLocalDateTime(isoOrMs) {
  if (isoOrMs == null || isoOrMs === '') return '—';
  const d = typeof isoOrMs === 'number' ? new Date(isoOrMs) : new Date(isoOrMs);
  if (Number.isNaN(d.getTime())) return '—';
  return d.toLocaleString('pt-BR');
}

function buildIdleQueryParams() {
  const raw = parseInt(document.getElementById('idle-value').value, 10);
  const value = Number.isFinite(raw) && raw >= 0 ? raw : 0;
  const unit = document.getElementById('idle-unit').value;
  const params = new URLSearchParams();
  if (unit === 'minutes') params.set('minutes', String(value));
  else if (unit === 'hours') params.set('hours', String(value));
  else params.set('days', String(value));
  return params;
}

function setIdleStatus(message, isError = false) {
  const el = document.getElementById('idle-status');
  if (!el) return;
  el.innerHTML = `<span class="idle-status-placeholder${isError ? ' idle-status-error-text' : ''}">${escapeHtml(message)}</span>`;
  el.classList.toggle('idle-status-error', !!isError);
  el.classList.toggle('idle-status-rich', false);
  el.classList.add('idle-status-flash');
  setTimeout(() => el.classList.remove('idle-status-flash'), 700);
}

function flashIdleChip(chip) {
  if (!chip) return;
  chip.classList.add('idle-stat-pulse');
  setTimeout(() => chip.classList.remove('idle-stat-pulse'), 900);
}

function wireIdleStatusInteractions(root) {
  if (!root) return;
  root.querySelectorAll('[data-idle-action]').forEach((chip) => {
    chip.addEventListener('click', () => {
      const action = chip.getAttribute('data-idle-action');
      flashIdleChip(chip);
      if (action === 'scroll-table') {
        document.getElementById('idle-table')?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
        document.querySelector('.idle-panel .table-wrapper')?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
      } else if (action === 'toggle-recovered') {
        toggleRecoveredActivePanel();
      }
    });
  });
}

function toggleRecoveredActivePanel(forceOpen) {
  const panel = document.getElementById('idle-recovered-panel');
  if (!panel) return;
  const shouldOpen = typeof forceOpen === 'boolean'
    ? forceOpen
    : panel.classList.contains('hidden');
  panel.classList.toggle('hidden', !shouldOpen);
  panel.setAttribute('aria-hidden', shouldOpen ? 'false' : 'true');
  if (shouldOpen) {
    panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  }
}

function renderRecoveredActivePanel(data) {
  const body = document.getElementById('idle-recovered-body');
  const panel = document.getElementById('idle-recovered-panel');
  if (!body || !panel) return;

  const hosts = Array.isArray(data?.recoveredActiveHosts) ? data.recoveredActiveHosts : [];
  if (hosts.length === 0) {
    body.innerHTML = `
      <tr class="empty-row">
        <td colspan="7">Nenhum IP ativo de novo no momento.</td>
      </tr>`;
    panel.classList.add('hidden');
    panel.setAttribute('aria-hidden', 'true');
    return;
  }

  body.innerHTML = '';
  for (const host of hosts) {
    const sinceLabel = host.recoveredSinceIso || host.recoveredSince
      ? formatLocalDateTime(host.recoveredSinceIso || host.recoveredSince)
      : '—';
    const row = document.createElement('tr');
    row.innerHTML = `
      <td>${escapeHtml(host.ip)}</td>
      <td>${escapeHtml(host.hostname || 'N/A')}</td>
      <td>${escapeHtml(sinceLabel)}</td>
      <td><span class="text-success">${escapeHtml(host.activeFor || '—')}</span></td>
      <td>${escapeHtml(formatLocalDateTime(host.lastCheckedIso || host.lastChecked))}</td>
      <td>${escapeHtml(host.deviceType || 'N/A')}</td>
      <td class="cell-subnet">${escapeHtml(host.subnet || 'N/A')}</td>
    `;
    body.appendChild(row);
  }
}

function formatIdleAuditLogLine(data) {
  if (!data) return '';
  const idle = data.idleCount ?? 0;
  const still = data.stillInactive ?? data.inactiveNow ?? idle;
  const subnets = data.subnetCount ?? 0;
  const thr = data.thresholdLabel || '—';
  const neu = data.newlyIdle ?? 0;
  const recPersisted = data.recoveredActivePersisted ?? 0;
  const recLastScan = data.recoveredActive ?? 0;

  if ((data.scanCount ?? 0) === 0) {
    return 'Nenhuma varredura salva ainda. Rode uma varredura para inventariar os IPs ociosos.';
  }
  if (idle === 0) {
    return data.message || `Nenhum IP ocioso para o limiar ${thr}.`;
  }

  let line = `Auditoria global: ${idle} ocioso(s) ≥ ${thr} · ${subnets} faixa(s)`;
  if (still !== idle) line += ` · ${still} inativos no histórico`;
  if (neu > 0) line += ` · ${neu} novos na última varredura`;
  if (recPersisted > 0) line += ` · ${recPersisted} ativos de novo`;
  else if (recLastScan > 0) line += ` · ${recLastScan} voltaram ativo na última varredura`;
  return line;
}

function renderIdleStatusDashboard(data) {
  const el = document.getElementById('idle-status');
  if (!el || !data) return;

  const idle = data.idleCount ?? 0;
  const subnets = data.subnetCount ?? 0;
  const scans = data.scanCount ?? 0;
  const thr = data.thresholdLabel || '—';
