  const recPersisted = data.recoveredActivePersisted ?? 0;
  const scanLabel = data.latestScanAtIso
    ? formatLocalDateTime(data.latestScanAtIso)
    : (scans > 0 ? `${scans} leitura(s)` : '—');

  const chips = [
    `<button type="button" class="idle-chip idle-chip-accent" data-idle-action="scroll-table" title="IPs ociosos no limiar atual — clique para ir à tabela">
      <span class="idle-chip-value">${idle.toLocaleString('pt-BR')}</span>
      <span class="idle-chip-label">ociosos ≥ ${escapeHtml(thr)}</span>
    </button>`,
    `<button type="button" class="idle-chip idle-chip-faixas" data-idle-action="scroll-table" title="Faixas / sub-redes no histórico">
      <span class="idle-chip-value">${subnets}</span>
      <span class="idle-chip-label">faixa(s)</span>
    </button>`,
    `<button type="button" class="idle-chip idle-chip-history" data-idle-action="scroll-table" title="IPs já vistos em varreduras">
      <span class="idle-chip-value">${(data.totalTracked || 0).toLocaleString('pt-BR')}</span>
      <span class="idle-chip-label">no histórico</span>
    </button>`,
    `<span class="idle-chip idle-chip-scans" title="Varreduras salvas no histórico">
      <span class="idle-chip-value">${scans.toLocaleString('pt-BR')}</span>
      <span class="idle-chip-label">leituras</span>
    </span>`,
    `<span class="idle-chip idle-chip-threshold" title="Limiar de inatividade aplicado na consulta">
      <span class="idle-chip-value">${escapeHtml(thr)}</span>
      <span class="idle-chip-label">limiar</span>
    </span>`
  ];

  if (neu > 0) {
    chips.push(`<span class="idle-chip idle-chip-new" title="Novos inativos na última varredura">
      <span class="idle-chip-value">+${neu}</span>
      <span class="idle-chip-label">novos</span>
    </span>`);
  }
  if (recPersisted > 0) {
    chips.push(`<div class="idle-chip-group idle-chip-group-recovered">
      <span class="idle-chip idle-chip-recovered" title="IPs que voltaram a ativo e permanecem na lista até ficarem inativos de novo">
        <span class="idle-chip-value">${recPersisted.toLocaleString('pt-BR')}</span>
        <span class="idle-chip-label">ativos de novo</span>
      </span>
      <button type="button" class="btn btn-tertiary btn-sm idle-recovered-toggle" data-idle-action="toggle-recovered" title="Ver lista de IPs ativos de novo">
        Ver IPs
      </button>
    </div>`);
  }

  el.innerHTML = `
    <div class="idle-status-bar">
      <div class="idle-status-head">
        <span class="idle-status-title">Auditoria global</span>
        <span class="idle-status-scan" title="${scans} leitura(s) salva(s)">
          Última leitura · ${escapeHtml(scanLabel)}
        </span>
      </div>
      <div class="idle-status-chips">${chips.join('')}</div>
    </div>`;

  el.classList.remove('idle-status-error');
  el.classList.add('idle-status-rich', 'idle-status-flash');
  setTimeout(() => el.classList.remove('idle-status-flash'), 700);
  wireIdleStatusInteractions(el);
  renderRecoveredActivePanel(data);
}

function updateIdleTableMeta(totalFiltered, page, pageCount, rangeStart, rangeEnd) {
  const meta = document.getElementById('idle-table-meta');
  const indicator = document.getElementById('idle-page-indicator');
  const prevBtn = document.getElementById('idle-page-prev');
  const nextBtn = document.getElementById('idle-page-next');

  if (meta) {
    if (totalFiltered === 0) {
      meta.textContent = idleHostsCache.length === 0 ? 'Nenhum registro' : 'Nenhum registro na página';
    } else {
      const plural = totalFiltered !== 1 ? 's' : '';
      meta.textContent = `Mostrando ${rangeStart}–${rangeEnd} de ${totalFiltered} registro${plural}`;
    }
  }
  if (indicator) indicator.textContent = `${page} / ${Math.max(pageCount, 1)}`;
  if (prevBtn) prevBtn.disabled = page <= 1;
  if (nextBtn) nextBtn.disabled = page >= pageCount || totalFiltered === 0;
}

