function wireIdleControls() {
  const idleRefreshBtn = document.getElementById('idle-refresh-btn');
  const idleExportBtn = document.getElementById('idle-export-btn');
  const idleExportXlsxBtn = document.getElementById('idle-export-xlsx-btn');

  if (idleRefreshBtn && !idleRefreshBtn.dataset.wired) {
    idleRefreshBtn.dataset.wired = '1';
    idleRefreshBtn.addEventListener('click', async () => {
      idleRefreshBtn.disabled = true;
      try {
        await loadIdleHosts();
      } catch (err) {
        setIdleStatus(`Falha: ${err.message}`, true);
        alert(`Falha ao analisar ociosos: ${err.message}`);
        logToConsole(`[!] Falha ao analisar ociosos: ${err.message}`, 'error-msg');
      } finally {
        idleRefreshBtn.disabled = false;
      }
    });
  }

  if (idleExportBtn && !idleExportBtn.dataset.wired) {
    idleExportBtn.dataset.wired = '1';
    idleExportBtn.addEventListener('click', exportIdleJson);
  }

  if (idleExportXlsxBtn && !idleExportXlsxBtn.dataset.wired) {
    idleExportXlsxBtn.dataset.wired = '1';
    idleExportXlsxBtn.addEventListener('click', () => exportIdleExcel());
  }

  const idlePageSizeSelect = document.getElementById('idle-page-size');
  const idlePagePrev = document.getElementById('idle-page-prev');
  const idlePageNext = document.getElementById('idle-page-next');

  if (idlePageSizeSelect && !idlePageSizeSelect.dataset.wired) {
    idlePageSizeSelect.dataset.wired = '1';
    idlePageSize = parseInt(idlePageSizeSelect.value, 10) || 50;
    idlePageSizeSelect.addEventListener('change', () => {
      idlePageSize = parseInt(idlePageSizeSelect.value, 10) || 50;
      idlePage = 1;
      renderIdleTablePage();
    });
  }
  if (idlePagePrev && !idlePagePrev.dataset.wired) {
    idlePagePrev.dataset.wired = '1';
    idlePagePrev.addEventListener('click', () => {
      if (idlePage > 1) {
        idlePage -= 1;
        renderIdleTablePage();
      }
    });
  }
  if (idlePageNext && !idlePageNext.dataset.wired) {
    idlePageNext.dataset.wired = '1';
    idlePageNext.addEventListener('click', () => {
      idlePage += 1;
      renderIdleTablePage();
    });
  }
}

