      <button type="button" class="btn btn-secondary btn-sm" data-ad-group-copy="${copyPayload}">Copiar logins</button>
    </div>
    <div class="ad-dept-peers">
      ${members.length
    ? members.map((m) => buildUserCardHtml({
      ...m,
      groupNames: m.groups || [],
      groupCount: m.groupCount || (m.groups || []).length
    }, { live: true })).join('')
    : '<div class="ad-empty">Nenhum membro encontrado neste grupo.</div>'}
