function fillAutoTestInterfaceSelects(interfaces) {
  const selects = [
    { id: 'autotest-cfg-dhcp-interface', emptyLabel: '— Selecione —' },
    { id: 'autotest-cfg-test-interface', emptyLabel: '— Selecione —' },
    { id: 'autotest-run-interface', emptyLabel: interfaces?.length ? '— Selecione a NIC —' : '— Nenhuma interface ativa —' }
  ];
  for (const { id, emptyLabel } of selects) {
    const sel = document.getElementById(id);
    if (!sel) continue;
    const current = sel.value;
    const opts = [`<option value="">${emptyLabel}</option>`];
    for (const iface of interfaces || []) {
      const label = `${iface.interfaceAlias}${iface.isPrimary ? ' (primária)' : ''}${iface.ip ? ` · ${iface.ip}` : ''}`;
      opts.push(`<option value="${escapeHtml(iface.interfaceAlias)}">${escapeHtml(label)}</option>`);
    }
    sel.innerHTML = opts.join('');
    if (current) sel.value = current;
  }
}

