function fillAutoTestConfigForm(cfg) {
  const c = cfg || {};
  const set = (id, val) => {
    const el = document.getElementById(id);
    if (el) el.value = val ?? '';
  };
  set('autotest-cfg-ping', (c.pingTargets || []).join(', '));
  set('autotest-cfg-dns', (c.dnsHosts || []).join(', '));
  set('autotest-cfg-tcp-ports', (c.tcpPorts || []).join(', '));
  const tcpSel = document.getElementById('autotest-cfg-tcp-target');
  const t = c.tcpTarget || 'gateway';
  if (tcpSel) {
    if (t === 'gateway' || t === '8.8.8.8') tcpSel.value = t;
    else tcpSel.value = 'custom';
  }
  set('autotest-cfg-tcp-custom', c.customTcpTarget || (t !== 'gateway' && t !== '8.8.8.8' ? t : ''));
  set('autotest-cfg-traceroute', c.tracerouteTarget || '8.8.8.8');
  set('autotest-cfg-timeout', c.timeoutMs || 2500);
  set('autotest-cfg-ping-count', c.pingCount || 4);
  set('autotest-cfg-switch-ip', c.switchIp || '');
  set('autotest-cfg-switch-community', c.switchCommunity || '');
  const swIp = document.getElementById('autotest-sw-ip');
  const swComm = document.getElementById('autotest-sw-community');
  if (swIp && c.switchIp) swIp.value = c.switchIp;
  if (swComm && c.switchCommunity) swComm.value = c.switchCommunity;
  const stop = document.getElementById('autotest-cfg-stop-on-fail');
  if (stop) stop.checked = Boolean(c.stopOnFail);
  const setChk = (id, val, def = false) => {
    const el = document.getElementById(id);
    if (el) el.checked = val !== undefined ? Boolean(val) : def;
  };
  setChk('autotest-cfg-vlan', c.vlanCheckEnabled, true);
  setChk('autotest-cfg-dup-ip', c.duplicateIpCheckEnabled, true);
  setChk('autotest-cfg-subnet', c.subnetDiscoveryEnabled, true);
  setChk('autotest-cfg-dns-via', c.dnsViaServerEnabled, true);
  setChk('autotest-cfg-http', c.httpTestEnabled, true);
  setChk('autotest-cfg-wifi-scan', c.wifiScanEnabled, false);
  set('autotest-cfg-subnet-max', c.subnetDiscoveryMaxHosts || 32);
  set('autotest-cfg-http-urls', (c.httpTestUrls || []).join(', '));
  const dhcpEnabled = document.getElementById('autotest-cfg-dhcp-enabled');
  if (dhcpEnabled) dhcpEnabled.checked = Boolean(c.dhcpTestEnabled);
  const dhcpMode = document.getElementById('autotest-cfg-dhcp-mode');
  if (dhcpMode) {
    if (c.dhcpTestInterface) dhcpMode.value = 'alias';
    else dhcpMode.value = c.dhcpTestMode || 'secondary';
  }
  const dhcpIf = document.getElementById('autotest-cfg-dhcp-interface');
  if (dhcpIf && c.dhcpTestInterface) dhcpIf.value = c.dhcpTestInterface;
  const testMode = document.getElementById('autotest-cfg-test-interface-mode');
  if (testMode) testMode.value = c.testInterfaceMode || 'auto';
  const testIf = document.getElementById('autotest-cfg-test-interface');
  if (testIf && c.testInterface) testIf.value = c.testInterface;
  toggleAutoTestCustomInterface('autotest-cfg-test-interface-mode', 'autotest-cfg-test-interface-wrap');
  syncAutoTestRunInterface(c);
}

