let autoTestRemoteAgentsCache = [];
let autoTestRemotePollToken = 0;

function normalizeAutoTestRemoteTarget(value) {
  return String(value || '').trim().toLowerCase().replace(/[^a-z0-9._-]+/g, '-').slice(0, 64);
}

function resolveAutoTestRemoteTarget(input) {
  const raw = String(input || '').trim();
  if (!raw) return { ok: false, error: 'Digite o IP ou hostname da estação remota.' };

  const agents = autoTestRemoteAgentsCache;
  const ipMatch = agents.find((a) => a.ip && a.ip === raw);
  if (ipMatch) return { ok: true, agent: ipMatch, matchedBy: 'ip' };

  const norm = normalizeAutoTestRemoteTarget(raw);
  const idMatch = agents.find((a) => a.agentId === norm || normalizeAutoTestRemoteTarget(a.hostname) === norm);
  if (idMatch) return { ok: true, agent: idMatch, matchedBy: 'agentId' };

  const hostLower = raw.toLowerCase();
  const hostMatch = agents.find((a) =>
    (a.hostname && a.hostname.toLowerCase() === hostLower)
    || (a.agentId && a.agentId.toLowerCase() === hostLower)
  );
  if (hostMatch) return { ok: true, agent: hostMatch, matchedBy: 'hostname' };

  return {
    ok: false,
    error: `Estação "${raw}" não encontrada. Atualize a lista — o agente precisa estar pareado e online naquela máquina.`
  };
}

function updateAutoTestRemoteTargetHint(input) {
  const hint = document.getElementById('autotest-remote-target-hint');
  if (!hint) return;
  const raw = String(input || '').trim();
  if (!raw) {
    hint.classList.add('hidden');
    hint.textContent = '';
    return;
  }
  const resolved = resolveAutoTestRemoteTarget(raw);
  if (!resolved.ok) {
    hint.textContent = resolved.error;
    hint.className = 'ad-section-hint autotest-remote-target-hint warn';
    return;
  }
  const a = resolved.agent;
  const st = a.online ? '● online' : '○ offline';
  const lastSeen = a.lastSeen ? new Date(a.lastSeen).toLocaleString('pt-BR') : 'nunca';
  hint.textContent = `${a.hostname} (${a.ip || '?'}) · ${st} · visto ${lastSeen}${a.online ? '' : ' — job aguardará o agente conectar'}`;
  hint.className = `ad-section-hint autotest-remote-target-hint${a.online ? '' : ' warn'}`;
}

const AUTOTEST_REMOTE_GHOST_HINT = 'Digite o ip da máquina';
const AUTOTEST_REMOTE_GHOST_EXAMPLES = ['192.168.1.100', '10.0.0.50', '172.16.0.25', '192.168.0.15'];

function wireAutoTestRemoteAgentPlaceholder(input) {
  const wrap = document.getElementById('autotest-remote-agent-input-wrap');
  const ghost = document.getElementById('autotest-remote-agent-ghost');
  if (!input || !wrap || !ghost || input.dataset.placeholderWired) return;
  input.dataset.placeholderWired = '1';

  let phase = 'hint';
  let exampleIdx = 0;
  let timer = null;

  function isActive() {
    return !!input.value.trim() || document.activeElement === input;
  }

  function setGhost(text, asExample) {
    ghost.textContent = text;
    ghost.classList.toggle('is-example', !!asExample);
  }

  function fadeTo(text, asExample) {
    ghost.classList.add('is-fading');
    setTimeout(() => {
      setGhost(text, asExample);
      ghost.classList.remove('is-fading');
    }, 400);
  }

  function scheduleNext() {
    clearTimeout(timer);
    if (isActive()) return;
    timer = setTimeout(() => {
      if (isActive()) return;
      if (phase === 'hint') {
        fadeTo(AUTOTEST_REMOTE_GHOST_EXAMPLES[exampleIdx], true);
        exampleIdx = (exampleIdx + 1) % AUTOTEST_REMOTE_GHOST_EXAMPLES.length;
        phase = 'example';
      } else {
        fadeTo(AUTOTEST_REMOTE_GHOST_HINT, false);
        phase = 'hint';
      }
      scheduleNext();
    }, phase === 'hint' ? 2800 : 3200);
  }

  function syncGhost() {
    wrap.classList.toggle('is-active', isActive());
    clearTimeout(timer);
    if (isActive()) return;
    setGhost(phase === 'hint' ? AUTOTEST_REMOTE_GHOST_HINT : AUTOTEST_REMOTE_GHOST_EXAMPLES[(exampleIdx + AUTOTEST_REMOTE_GHOST_EXAMPLES.length - 1) % AUTOTEST_REMOTE_GHOST_EXAMPLES.length], phase === 'example');
    scheduleNext();
  }

  setGhost(AUTOTEST_REMOTE_GHOST_HINT, false);
  scheduleNext();
  input.addEventListener('focus', syncGhost);
  input.addEventListener('blur', syncGhost);
  input.addEventListener('input', syncGhost);
}

async function loadAutoTestRemoteAgents() {
  const input = document.getElementById('autotest-remote-agent');
  const list = document.getElementById('autotest-remote-agent-list');
  if (!input) return [];
  const res = await fetch('/api/autotest/remote/agents');
