  if (res.status === 401 || data.code === 'REMOTE_AD_AUTH_REQUIRED' || data.code === 'AUTH_REQUIRED') {
    autoTestRemoteAgentsCache = [];
    if (list) list.innerHTML = '';
    updateAutoTestRemoteTargetHint(input.value);
    return [];
  }
  if (!res.ok) throw new Error(data.error || 'Falha ao listar agentes');
  autoTestRemoteAgentsCache = data.agents || [];
  const current = input.value;
  if (list) {
    list.innerHTML = autoTestRemoteAgentsCache.map((a) => {
      const when = a.lastSeen ? new Date(a.lastSeen).toLocaleString('pt-BR') : '—';
      const status = a.online ? 'online' : 'offline';
      const value = a.ip || a.hostname || a.agentId;
      const label = `${a.hostname} (${a.ip || '?'}) · ${status} · ${when}`;
      return `<option value="${escapeHtml(value)}" label="${escapeHtml(label)}"></option>`;
    }).join('');
  }
  if (current) updateAutoTestRemoteTargetHint(current);
  return autoTestRemoteAgentsCache;
}

async function pollRemoteAutoTestJob(jobId, maxWaitMs = 20 * 60 * 1000) {
  const pollToken = ++autoTestRemotePollToken;
  const started = Date.now();
  while (Date.now() - started < maxWaitMs) {
    if (pollToken !== autoTestRemotePollToken) {
      throw new Error('Aguardo do job remoto cancelado.');
    }
    const res = await fetch(`/api/autotest/remote/jobs/${encodeURIComponent(jobId)}`);
    const data = await res.json().catch(() => ({}));
    if (!res.ok) throw new Error(data.error || `HTTP ${res.status}`);
    const job = data.job;
    if (job.status === 'done' && job.result) return job.result;
    if (job.status === 'failed') throw new Error(job.error || 'AutoTest remoto falhou.');
    if (job.status === 'timeout') throw new Error(job.error || 'Agente não respondeu a tempo.');
    const waited = Math.round((Date.now() - started) / 1000);
    setAutoTestEngineeringBanner(null, { mode: 'progress', detail: `Aguardando agente remoto · ${waited}s · ${job.status}` });
    await new Promise((r) => setTimeout(r, 2000));
  }
  throw new Error('Tempo esgotado aguardando resultado do agente remoto.');
}

async function runRemoteAutoTest() {
  const run = async () => {
    const target = document.getElementById('autotest-remote-agent')?.value?.trim();
    const resolved = resolveAutoTestRemoteTarget(target);
    if (!resolved.ok) {
      alert(resolved.error);
      updateAutoTestRemoteTargetHint(target);
      return;
    }
    const agent = resolved.agent;
    if (!agent.online) {
      const go = confirm(
        `A estação ${agent.hostname} (${agent.ip || '?'}) está offline.\n\n`
        + 'O job ficará aguardando até o agente conectar (até ~10 min).\n\nEnfileirar mesmo assim?'
      );
      if (!go) return;
    }
    const profileId = document.getElementById('autotest-profile-select')?.value || 'escritorio';
    const nic = readAutoTestRunInterface();
    const btn = document.getElementById('autotest-run-remote-btn');
    setAutoTestEngineeringBanner(null, { mode: 'progress', detail: 'Enfileirando job remoto…' });
    if (btn) btn.disabled = true;
    try {
      const res = await fetch('/api/autotest/remote/jobs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ target, agentId: agent.agentId, profileId, ...nic })
      });
      const created = await res.json().catch(() => ({}));
      if (res.status === 401 || created.code === 'REMOTE_AD_AUTH_REQUIRED' || created.code === 'AUTH_REQUIRED') {
        await ensureAutoTestRemoteAuth(() => runRemoteAutoTest(), { freshLogin: true });
        return;
      }
      if (!res.ok || !created.job?.id) throw new Error(created.error || 'Falha ao enfileirar job.');
      const label = agent.ip || agent.hostname || agent.agentId;
      setAutoTestEngineeringBanner(null, { mode: 'progress', detail: `Job enviado · aguardando ${label}` });
      const result = await pollRemoteAutoTestJob(created.job.id);
      applyAutoTestResult(result);
    } catch (err) {
      setAutoTestEngineeringBanner(null, { mode: 'error', detail: err.message });
      alert(err.message);
    } finally {
      if (btn) btn.disabled = false;
    }
  };
  await ensureAutoTestRemoteAuth(run, { freshLogin: true });
}

async function revokeAutoTestRemoteAgent() {
  const run = async () => {
    const target = document.getElementById('autotest-remote-agent')?.value?.trim();
    const resolved = resolveAutoTestRemoteTarget(target);
    if (!resolved.ok) {
      alert(resolved.error);
      return;
    }
    const agent = resolved.agent;
    if (!confirm(`Revogar o agente pareado "${agent.hostname}" (${agent.ip || agent.agentId})?\n\nA estação precisará parear novamente.`)) {
      return;
    }
    const res = await fetch(`/api/autotest/remote/agents/${encodeURIComponent(agent.agentId)}`, { method: 'DELETE' });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || !data.ok) throw new Error(data.error || 'Falha ao revogar agente.');
    await loadAutoTestRemoteAgents();
    alert(`Agente ${agent.hostname} revogado.`);
  };
  await ensureAutoTestRemoteAuth(run);
}

