async function loadOracleConfig() {
  const res = await fetch('/api/oracle/config');
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.error || 'Falha ao carregar config Oracle');
  const cfg = data.config || {};
  const user = document.getElementById('oracle-cfg-user');
  const pass = document.getElementById('oracle-cfg-password');
  const connect = document.getElementById('oracle-cfg-connect');
  const table = document.getElementById('oracle-cfg-table');
  const max = document.getElementById('oracle-cfg-max');
  if (user) user.value = cfg.user || '';
  if (pass) pass.value = '';
  if (pass) pass.placeholder = cfg.hasPassword ? '••••••••' : 'Senha Oracle';
  if (connect) connect.value = cfg.connectString || '';
  if (table) table.value = cfg.table || 'dbasgu.usuarios';
  if (max) max.value = cfg.maxRows || 50;
  const libdir = document.getElementById('oracle-cfg-libdir');
  if (libdir) libdir.value = cfg.libDir || cfg.suggestedLibDir || '';
  if (!cfg.connectString) {
    setOracleStatus('oracle-cfg-status', 'Configure o Connect String (TNS sem jdbc: ou host:1521/SERVICE).', 'err');
  } else if (cfg.thickError) {
    setOracleStatus('oracle-cfg-status', `Thick mode: ${cfg.thickError}`, 'err');
  } else {
    setOracleStatus('oracle-cfg-status', `Pronto · user=${cfg.user || '?'} · ${cfg.connectString}`, 'ok');
  }
  return cfg;
}

function renderOracleResults(users) {
  const box = document.getElementById('oracle-results');
  if (!box) return;
  const list = Array.isArray(users) ? users : [];
  if (!list.length) {
    box.innerHTML = '<div class="ad-empty">Nenhum usuário encontrado no Oracle.</div>';
    return;
  }

  box.innerHTML = `
    <h3 class="ad-section-title">${escapeHtml(String(list.length))} resultado(s)</h3>
    ${list.map((u) => {
    const sugs = (u.suggestions || []).map((s) => {
      let badge = '<span class="oracle-badge unknown">AD não checado</span>';
      if (s.adExists === true) {
        const name = s.adUser?.displayName ? ` · ${s.adUser.displayName}` : '';
        const st = s.adUser?.enabled === false ? ' (desabilitado)' : '';
        badge = `<span class="oracle-badge exists">Já existe no AD${st}${escapeHtml(name)}</span>`;
      } else if (s.adExists === false) {
        badge = '<span class="oracle-badge free">Livre no AD</span>';
      }
      return `
        <div class="oracle-sug${s.preferred ? ' preferred' : ''}">
          <span class="oracle-sug-login">${escapeHtml(s.login)}</span>
          <span class="oracle-sug-rule">${escapeHtml(s.rule || '')}</span>
          ${badge}
          <button type="button" class="btn btn-tertiary btn-sm" data-oracle-copy="${escapeHtml(s.login)}">Copiar</button>
        </div>
      `;
    }).join('');

    return `
      <div class="oracle-card">
        <div class="oracle-card-head">
          <div>
            <strong>${escapeHtml(u.nmUsuario || '—')}</strong>
            <span>Oracle · dbasgu.usuarios</span>
          </div>
          <div class="oracle-code" title="cd_usuario">${escapeHtml(u.cdUsuario || '—')}</div>
        </div>
        <div class="oracle-suggestions">${sugs || '<span class="oracle-sug-rule">Sem sugestões</span>'}</div>
      </div>
    `;
  }).join('')}
  `;
}

