  try {
    const url = `/api/oracle/users?q=${encodeURIComponent(q)}&mode=${encodeURIComponent(mode)}&checkAd=${checkAd ? '1' : '0'}`;
    const res = await fetch(url);
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) {
      throw new Error(data.error || 'Falha na consulta Oracle');
    }
    renderOracleResults(data.users || []);
    setOracleStatus(
      'oracle-search-status',
      `${data.count || 0} resultado(s) · padrão ${data.pattern || ''}${checkAd ? ' · AD verificado' : ''}`,
