const { loadPlatformConfig } = require('./platformConfig');

function getSessionRole(token) {
  const cfg = loadPlatformConfig();
  if (!cfg.features?.rbac || !cfg.rbac?.enabled) return 'admin';
  // Sessions created before RBAC still get admin unless we store role on login
  return 'admin';
}

function roleAllows(role, permission) {
  const cfg = loadPlatformConfig();
  const roles = cfg.rbac?.roles || {};
  const perms = roles[role] || roles.admin || ['*'];
  if (perms.includes('*')) return true;
  if (perms.includes(permission)) return true;
  return perms.some((p) => {
    if (p.endsWith('.*')) {
      const prefix = p.slice(0, -2);
      return permission === prefix || permission.startsWith(`${prefix}.`);
    }
    return false;
  });
}

function requirePlatformAuth(permission = 'platform.read') {
  return (req, res, next) => next();
}

function getPublicRbacInfo() {
  const cfg = loadPlatformConfig();
  return {
    enabled: !!cfg.features?.rbac && !!cfg.rbac?.enabled,
    roles: Object.keys(cfg.rbac?.roles || {})
  };
}

module.exports = {
  requirePlatformAuth,
  getPublicRbacInfo,
  roleAllows
};

