function renderIdleTablePage(emptyMsg) {
  const idleBody = document.getElementById('idle-body');
  if (!idleBody) return;

  idleBody.innerHTML = '';
  const totalFiltered = idleHostsCache.length;
  const pageCount = totalFiltered === 0 ? 1 : Math.ceil(totalFiltered / idlePageSize);

  if (idlePage > pageCount) idlePage = pageCount;
  if (idlePage < 1) idlePage = 1;

  const start = (idlePage - 1) * idlePageSize;
  const end = Math.min(start + idlePageSize, totalFiltered);
  const rangeStart = totalFiltered === 0 ? 0 : start + 1;
  const rangeEnd = end;

  updateIdleTableMeta(totalFiltered, idlePage, pageCount, rangeStart, rangeEnd);

  if (totalFiltered === 0) {
    idleBody.innerHTML = `
      <tr class="empty-row">
        <td colspan="8">${escapeHtml(emptyMsg || 'Nenhum IP ocioso para o limiar atual.')}</td>
      </tr>`;
    return;
  }

  idleHostsCache.slice(start, end).forEach((host) => {
    idleBody.appendChild(appendIdleHostRow(host));
  });
}

async function loadIdleHosts() {
  const idleBody = document.getElementById('idle-body');
  const idleExportBtnEl = document.getElementById('idle-export-btn');
  const idleExportXlsxBtnEl = document.getElementById('idle-export-xlsx-btn');

  if (!idleBody) return;

  if (!canonBootToken) {
    setIdleStatus('Faça login para consultar IPs ociosos.', false);
    return;
  }

  setIdleStatus('Consultando histórico de leituras...');

  const params = buildIdleQueryParams();
  const res = await fetch(`/api/idle-hosts?${params.toString()}`);
  if (res.status === 401) {
    setCanonBootToken('');
    setIdleStatus('Sessão expirada — faça login novamente.', true);
    openCanonLoginModal({ target: 'boot' });
    return;
  }
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.error || `HTTP ${res.status}`);
  }

  const data = await res.json();
  lastIdlePayload = data;

  const hosts = Array.isArray(data.hosts) ? data.hosts : [];
  idleHostsCache = hosts;
  idlePage = 1;
  if (idleExportBtnEl) idleExportBtnEl.disabled = hosts.length === 0;
  if (idleExportXlsxBtnEl) idleExportXlsxBtnEl.disabled = hosts.length === 0;

  if (hosts.length === 0) {
    const tracked = data.totalTracked || 0;
    const emptyMsg = tracked === 0
      ? 'Histórico vazio — rode uma varredura para popular IPs ociosos.'
      : (data.message || `Nenhum IP ocioso para o limiar ${data.thresholdLabel || '—'}.`);

    renderIdleTablePage(emptyMsg);
    if (data.totalTracked > 0 && (data.stillInactive > 0 || data.inactiveNow > 0)) {
      renderIdleStatusDashboard(data);
    } else {
      setIdleStatus(emptyMsg);
    }
    logToConsole(`[i] Inatividade: ${emptyMsg}`, 'system-msg');
    return;
  }

  renderIdleTablePage();
  renderIdleStatusDashboard(data);
  logToConsole(`[+] ${formatIdleAuditLogLine(data)}`, 'success-msg');

  const panel = document.querySelector('.idle-panel');
  if (panel) panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
}

function exportIdleJson() {
  if (!lastIdlePayload || !Array.isArray(lastIdlePayload.hosts) || lastIdlePayload.hosts.length === 0) {
    alert('Nenhum resultado de ociosos para exportar. Clique em Analisar primeiro.');
    return;
  }

  const blob = new Blob([JSON.stringify(lastIdlePayload, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-');
  a.href = url;
  a.download = `ips_ociosos_${stamp}.json`;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

