  const unclassified = document.getElementById('ala-stat-unclassified');
  const alas = document.getElementById('ala-stat-alas');
  const exportBtn = document.getElementById('ala-export-xlsx-btn');

  if (total) total.textContent = String(report.totalHosts || 0);
  if (classified) classified.textContent = String(report.classifiedCount || 0);
  if (unclassified) unclassified.textContent = String(report.unclassifiedCount || 0);
  if (alas) alas.textContent = String(report.alaCount || 0);
