// ——— Autenticação (boot ociosos + modais Oracle/AD/Loop) ———
/** Etapas 1–2 — dashboard (ociosos, exports, ALA); modais (AD/Oracle/Loop). */
const CANON_AUTH_CONFIG = {
  dashboardApi: [
    /^\/api\/scan-results$/,
    /^\/api\/host-history\/stats$/,
    /^\/api\/host-history$/,
    /^\/api\/report-info$/,
    /^\/api\/idle-hosts$/,
    // Etapa 2 — exports e mapa por ala (mesmo login do boot)
    /^\/api\/idle-hosts\/export-xlsx$/,
    /^\/api\/ala-map\/config$/,
    /^\/api\/ala-map\/report$/,
    /^\/api\/ala-map\/export-xlsx$/,
    /^\/export-xlsx$/,
    /^\/export-json$/,
    /^\/topology-json$/
  ],
  modalsApi: [
    /^\/api\/ad(?:\/|$)/,
    /^\/api\/oracle(?:\/|$)/,
    /^\/api\/loop(?:\/|$)/
  ],
  remoteAdApi: [
    /^\/api\/autotest\/remote(?:\/(?!agent\/(?:enroll|poll|complete)|config))(?:\/|$)/
  ]
};

function apiPathname(url) {
  try {
    return new URL(url, window.location.origin).pathname;
  } catch {
    return String(url || '').split('?')[0].split('#')[0];
  }
}

function urlNeedsDashboardAuth(url) {
  const path = apiPathname(url);
  return CANON_AUTH_CONFIG.dashboardApi.some((re) => re.test(path));
}

function urlNeedsModalsAuth(url) {
  const path = apiPathname(url);
  if (CANON_AUTH_CONFIG.modalsApi.some((re) => re.test(path))) return true;
  // Etapa 3 — AutoTest local (exceto /api/autotest/remote/*)
  if (path.startsWith('/api/autotest/') && !path.startsWith('/api/autotest/remote')) return true;
  // Etapa 4 — Inventário UNESP
  if (path.startsWith('/api/inventory')) return true;
  // Etapa 5 — Plataforma Canon (exceto ingest do agente)
  if (path.startsWith('/api/platform')) {
    if (path === '/api/platform/agent/report') return false;
    return true;
  }
  return false;
}

function urlNeedsRemoteAdAuth(url) {
  const path = apiPathname(url);
  return CANON_AUTH_CONFIG.remoteAdApi.some((re) => re.test(path));
}

/** Boot — só memória (Ctrl+F5 e restart pedem login de novo para ociosos). */
let canonBootToken = '';
/** Modais — só memória (Ctrl+F5 pede login; um login libera todos até recarregar). */
let canonModalToken = '';
let autoTestRemoteAuthToken = '';
let canonLoginPending = null;
let dashboardStarted = false;

try {
  sessionStorage.removeItem('canonAuthToken');
  sessionStorage.removeItem('canonModalAuthToken');
  autoTestRemoteAuthToken = sessionStorage.getItem('autoTestRemoteAuthToken') || '';
} catch {
  autoTestRemoteAuthToken = '';
}

function canonBootAuthHeaders() {
  return canonBootToken ? { 'X-Canon-Session': canonBootToken } : {};
}

function canonModalAuthHeaders() {
  return canonModalToken ? { 'X-Canon-Session': canonModalToken } : {};
}

async function readApiJson(res) {
  const ct = (res.headers.get('content-type') || '').toLowerCase();
  if (ct.includes('application/json')) {
    return res.json().catch(() => ({}));
  }
  const text = await res.text().catch(() => '');
  const trimmed = text.trimStart();
  if (trimmed.startsWith('<!DOCTYPE') || trimmed.startsWith('<html')) {
    throw new Error('Servidor retornou HTML em vez de JSON. Reinicie com npm start e atualize a página (Ctrl+F5).');
  }
  throw new Error(text.slice(0, 240) || `HTTP ${res.status}`);
}
window.readApiJson = readApiJson;

function setAutoTestRemoteAuthToken(token) {
  autoTestRemoteAuthToken = token || '';
  try {
    if (token) sessionStorage.setItem('autoTestRemoteAuthToken', token);
    else sessionStorage.removeItem('autoTestRemoteAuthToken');
  } catch {
    /* ignore */
  }
}

function autoTestRemoteAuthHeaders() {
  return autoTestRemoteAuthToken ? { 'X-AutoTest-Remote-Session': autoTestRemoteAuthToken } : {};
}

function setCanonBootToken(token) {
  const hadToken = !!canonBootToken;
  canonBootToken = token || '';
  if (hadToken && !canonBootToken) {
    disconnectWebSocket();
  }
}

function setCanonModalToken(token) {
  canonModalToken = token || '';
  try {
    sessionStorage.removeItem('canonModalAuthToken');
  } catch {
    /* ignore */
  }
}

function installCanonFetch() {
  if (window.__canonFetchInstalled) return;
  window.__canonFetchInstalled = true;
  const nativeFetch = window.fetch.bind(window);
  window.fetch = (input, init = {}) => {
    const url = typeof input === 'string' ? input : (input?.url || '');
    const needsDashboard = urlNeedsDashboardAuth(url);
    const needsModals = urlNeedsModalsAuth(url);
    const needsRemoteAd = urlNeedsRemoteAdAuth(url);
    const headers = new Headers(init.headers || {});
    const sentBoot = !!(needsDashboard && canonBootToken);
    const sentModal = !!(needsModals && canonModalToken);
    if (sentBoot) headers.set('X-Canon-Session', canonBootToken);
    if (sentModal) headers.set('X-Canon-Session', canonModalToken);
    if (needsRemoteAd && autoTestRemoteAuthToken) headers.set('X-AutoTest-Remote-Session', autoTestRemoteAuthToken);
    if (needsDashboard || needsModals || needsRemoteAd) init = { ...init, headers };
    return nativeFetch(input, init).then((res) => {
      if (res.status === 401) {
        if (sentBoot) setCanonBootToken('');
        if (sentModal) setCanonModalToken('');
        if (needsRemoteAd && autoTestRemoteAuthToken) setAutoTestRemoteAuthToken('');
      }
      return res;
    });
  };
}

function startDashboard(options = {}) {
  const loadIdle = options.loadIdle !== false;
  if (dashboardStarted) {
    if (loadIdle && canonBootToken) loadIdleHosts().catch(() => {});
    if (canonBootToken) connectWebSocket();
    else updateConnectionBadgeWaitingLogin();
    return;
  }
  dashboardStarted = true;
  if (canonBootToken) connectWebSocket();
  else updateConnectionBadgeWaitingLogin();
  toggleCustomPorts();
  updateStats();
  if (loadIdle && canonBootToken) {
    loadIdleHosts().catch(() => {});
  } else if (loadIdle && !canonBootToken) {
    setIdleStatus('Faça login para consultar IPs ociosos.', false);
  }
}

/** Boot — login obrigatório a cada carga (Ctrl+F5 / restart) para ociosos. */
async function bootCanonApp() {
  installCanonFetch();
  setCanonBootToken('');
  openCanonLoginModal({ target: 'boot' });
  startDashboard({ loadIdle: false });
}

async function checkAutoTestRemoteAuthSession() {
  if (!autoTestRemoteAuthToken) return false;
  try {
    const res = await fetch('/api/autotest/remote/auth/session', { headers: autoTestRemoteAuthHeaders() });
    const data = await res.json().catch(() => ({}));
    if (!data.authenticated) {
      setAutoTestRemoteAuthToken('');
      return false;
    }
    return true;
  } catch {
    return false;
  }
}

async function checkCanonBootSession() {
  if (!canonBootToken) return false;
  try {
    const res = await fetch('/api/auth/session?scope=dashboard', { headers: canonBootAuthHeaders() });
    const data = await res.json().catch(() => ({}));
    if (!data.authenticated || data.scope !== 'dashboard') {
      setCanonBootToken('');
      return false;
    }
    return true;
  } catch {
    return false;
  }
}

async function checkCanonModalSession() {
  if (!canonModalToken) return false;
  try {
    const res = await fetch('/api/auth/session?scope=modals', { headers: canonModalAuthHeaders() });
    const data = await res.json().catch(() => ({}));
    if (!data.authenticated || data.scope !== 'modals') {
      setCanonModalToken('');
      return false;
    }
    return true;
  } catch {
    return false;
  }
}

function setCanonLoginStatus(text, kind = '') {
  const el = document.getElementById('canon-login-status');
  if (!el) return;
  if (!text) {
    el.textContent = '';
    el.className = 'ad-status-bar hidden';
    return;
  }
  el.textContent = text;
  el.className = `ad-status-bar${kind ? ` ${kind}` : ''}`;
}

function openCanonLoginModal(pending) {
  const backdrop = document.getElementById('canon-login-backdrop');
  if (!backdrop) return;
  canonLoginPending = pending;
  const sub = document.getElementById('canon-login-subtitle');
  if (sub) {
    if (pending?.target === 'oracle') {
      sub.textContent = 'Consulta ao Banco de Dados Oracle';
    } else if (pending?.target === 'loop') {
      sub.textContent = 'Acesso ao Monitor Loop Rede';
    } else if (pending?.target === 'autotest-remote') {
      sub.textContent = 'AutoTest remoto — login AD (HCFMB ou UNESP) com permissão de administrador de domínio';
    } else if (pending?.target === 'boot') {
      sub.textContent = 'IPs ociosos — informe login e senha para consultar o histórico';
    } else if (pending?.target === 'platform') {
      sub.textContent = 'Acesso Centralizado à Plataforma de Informações';
    } else if (pending?.target === 'inventory') {
      sub.textContent = 'Acesso ao Inventário';
    } else if (pending?.target === 'autotest') {
      sub.textContent = 'Login para executar AutoTest';
    } else {
      sub.textContent = 'Consulta no Active Directory';
    }
  }
  setCanonLoginStatus('');
  backdrop.classList.remove('hidden');
  backdrop.setAttribute('aria-hidden', 'false');
  const user = document.getElementById('canon-login-user');
  const pass = document.getElementById('canon-login-pass');
  if (user) user.value = '';
  if (pass) pass.value = '';
  setTimeout(() => { if (user) user.focus(); }, 50);
}

function closeCanonLoginModal() {
  const backdrop = document.getElementById('canon-login-backdrop');
  if (!backdrop) return;
  backdrop.classList.add('hidden');
  backdrop.setAttribute('aria-hidden', 'true');
  canonLoginPending = null;
  setCanonLoginStatus('');
}

function openPendingProtectedModal(pending) {
  if (!pending) return;
  if (pending.target === 'boot') {
    startDashboard({ loadIdle: true });
    loadIdleHosts().catch(() => {});
    return;
  }
  if (pending.target === 'oracle') {
    openOracleModalDirect(pending.tab || 'search');
  } else if (pending.target === 'loop') {
    openLoopModalDirect(pending.tab || 'monitor');
  } else if (pending.target === 'autotest') {
    openAutoTestModalDirect(pending.tab || 'run');
  } else if (pending.target === 'inventory') {
    if (typeof window.openInventoryModalDirect === 'function') {
      window.openInventoryModalDirect();
    }
  } else if (pending.target === 'platform') {
    if (typeof window.openPlatformModalDirect === 'function') {
      window.openPlatformModalDirect(pending.tab || 'summary');
    }
  } else {
    openAdModalDirect(pending.tab || 'departed');
    if (typeof pending.afterOpen === 'function') pending.afterOpen();
  }
}

async function gateProtectedArea(pending) {
  installCanonFetch();
  if (await checkCanonModalSession()) {
    openPendingProtectedModal(pending);
    return;
  }
  openCanonLoginModal(pending);
}
window.gateCanonModalsArea = gateProtectedArea;

/** Etapa 6 — operações DELETE: 401 reabre login do escopo (boot ou modals). */
function handleDestructiveAuthFailure(res, data, { scope = 'modals', modalTarget = 'ad' } = {}) {
  if (res.status !== 401 && data?.code !== 'AUTH_REQUIRED') return false;
  if (scope === 'dashboard') {
    setCanonBootToken('');
    openCanonLoginModal({ target: 'boot' });
  } else {
    setCanonModalToken('');
    openCanonLoginModal({ target: modalTarget });
  }
  alert('Sessão expirada — faça login novamente.');
  return true;
}

async function submitCanonLogin(event) {
  if (event) event.preventDefault();
  const user = document.getElementById('canon-login-user')?.value?.trim() || '';
  const pass = document.getElementById('canon-login-pass')?.value || '';
  const btn = document.getElementById('canon-login-submit');
  if (!user || !pass) {
    setCanonLoginStatus('Informe login e senha.', 'err');
    return;
  }
  const pending = canonLoginPending;
  const isRemoteAd = pending?.target === 'autotest-remote';
  const isBoot = pending?.target === 'boot';
  setCanonLoginStatus(isRemoteAd ? 'Validando no Active Directory (HCFMB/UNESP)…' : 'Validando…');
  if (btn) btn.disabled = true;
  try {
    const loginUrl = isRemoteAd ? '/api/autotest/remote/auth/login' : '/api/auth/login';
    const loginBody = isRemoteAd
      ? { username: user, password: pass }
      : { username: user, password: pass, scope: isBoot ? 'dashboard' : 'modals' };
    const res = await fetch(loginUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginBody)
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok || !data.ok) {
      if (res.status === 404) {
        setCanonLoginStatus('Servidor desatualizado — reinicie o NetScan (npm start) e tente de novo.', 'err');
        return;
      }
      setCanonLoginStatus(data.error || 'Login ou senha inválidos.', 'err');
      return;
    }
    if (isRemoteAd) setAutoTestRemoteAuthToken(data.token);
    else if (isBoot) setCanonBootToken(data.token);
    else setCanonModalToken(data.token);
    closeCanonLoginModal();
    if (isRemoteAd) {
      if (typeof pending?.afterLogin === 'function') pending.afterLogin();
      return;
    }
    if (pending?.target === 'boot') {
      connectWebSocket();
      startDashboard({ loadIdle: true });
      try {
        await loadIdleHosts();
      } catch (err) {
        setIdleStatus(`Falha ao carregar ociosos: ${err.message}`, true);
        logToConsole(`[!] Ociosos: ${err.message}`, 'error-msg');
      }
      loadAlaMapConfigEditor().catch(() => {});
      return;
    }
    openPendingProtectedModal(pending);
  } catch (err) {
    setCanonLoginStatus(err.message || 'Falha na autenticação.', 'err');
  } finally {
    if (btn) btn.disabled = false;
  }
}

function wireCanonLoginUi() {
  installCanonFetch();
  const form = document.getElementById('canon-login-form');
  const closeBtn = document.getElementById('canon-login-close');
  const cancelBtn = document.getElementById('canon-login-cancel');
  const backdrop = document.getElementById('canon-login-backdrop');
  if (form && !form.dataset.wired) {
    form.dataset.wired = '1';
    form.addEventListener('submit', submitCanonLogin);
  }
  if (closeBtn && !closeBtn.dataset.wired) {
    closeBtn.dataset.wired = '1';
    closeBtn.addEventListener('click', closeCanonLoginModal);
  }
  if (cancelBtn && !cancelBtn.dataset.wired) {
    cancelBtn.dataset.wired = '1';
    cancelBtn.addEventListener('click', closeCanonLoginModal);
  }
  if (backdrop && !backdrop.dataset.wired) {
    backdrop.dataset.wired = '1';
    backdrop.addEventListener('click', (e) => {
      if (e.target === backdrop) closeCanonLoginModal();
    });
  }
}

wireCanonLoginUi();
window.addEventListener('DOMContentLoaded', wireCanonLoginUi);

