function wireLoopDetectUi() {
  const openBtn = document.getElementById('loop-detect-open-btn');
  const closeBtn = document.getElementById('loop-modal-close');
  const backdrop = document.getElementById('loop-modal-backdrop');
  if (!openBtn || openBtn.dataset.wired) return;
  openBtn.dataset.wired = '1';

  openBtn.addEventListener('click', () => openLoopModal('monitor'));
  if (closeBtn) closeBtn.addEventListener('click', closeLoopModal);
  if (backdrop) {
    backdrop.addEventListener('click', (e) => {
      if (e.target === backdrop) closeLoopModal();
    });
  }

  document.querySelectorAll('.loop-tab').forEach((tab) => {
    tab.addEventListener('click', () => switchLoopTab(tab.dataset.loopTab));
  });

  const saveSettings = document.getElementById('loop-save-settings');
  if (saveSettings) {
    saveSettings.addEventListener('click', async () => {
      const body = {
        community: document.getElementById('loop-community')?.value || 'public',
        pollIntervalSec: Number(document.getElementById('loop-interval')?.value || 12),
        timeoutMs: Number(document.getElementById('loop-timeout')?.value || 3500)
      };
      const res = await fetch('/api/loop/config', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
      });
      if (!res.ok) return alert('Falha ao salvar ajustes.');
      setLoopBanner('Ajustes SNMP salvos.', 'ok');
    });
  }

  const addBtn = document.getElementById('loop-sw-add');
  if (addBtn) {
    addBtn.addEventListener('click', async () => {
      const ip = document.getElementById('loop-sw-ip')?.value?.trim();
      if (!ip) return alert('Informe o IP do switch.');
      const body = {
        name: document.getElementById('loop-sw-name')?.value?.trim() || ip,
        ip,
        vendor: document.getElementById('loop-sw-vendor')?.value || 'auto',
        community: document.getElementById('loop-sw-community')?.value?.trim() || undefined
      };
      const res = await fetch('/api/loop/switches', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) return alert(data.error || 'Falha ao adicionar switch.');
      document.getElementById('loop-sw-ip').value = '';
      document.getElementById('loop-sw-name').value = '';
      document.getElementById('loop-sw-community').value = '';
      renderLoopSwitchList(data.switches || []);
    });
  }

  const list = document.getElementById('loop-switch-list');
  if (list) {
    list.addEventListener('click', async (e) => {
      const btn = e.target.closest('[data-loop-remove]');
      if (!btn) return;
      const id = btn.getAttribute('data-loop-remove');
      if (!confirm('Remover este switch do monitor?')) return;
      const res = await fetch(`/api/loop/switches/${encodeURIComponent(id)}`, { method: 'DELETE' });
      const data = await res.json().catch(() => ({}));
      if (handleDestructiveAuthFailure(res, data, { modalTarget: 'loop' })) return;
      if (!res.ok) return alert(data.error || 'Falha ao remover.');
      renderLoopSwitchList(data.switches || []);
    });
  }

  const quick = document.getElementById('loop-quick-check');
  if (quick) {
    quick.addEventListener('click', async () => {
      setLoopBanner('Checagem rápida em andamento (2 amostras SNMP)…', 'warn');
      quick.disabled = true;
      try {
        const res = await fetch('/api/loop/quick-check', { method: 'POST' });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Falha na checagem');
        applyLoopStatusPayload({ running: false, summary: data });
        logToConsole(`[LOOP] Checagem rápida: ${data.message}`, data.suspects?.length ? 'error-msg' : 'success-msg');
      } catch (err) {
        setLoopBanner(err.message, '');
        alert(err.message);
      } finally {
        quick.disabled = false;
      }
    });
  }

  const start = document.getElementById('loop-start');
  if (start) {
    start.addEventListener('click', async () => {
      const res = await fetch('/api/loop/start', { method: 'POST' });
      const data = await res.json();
      if (!res.ok) return alert(data.error || 'Falha ao iniciar');
      applyLoopStatusPayload(data);
      logToConsole('[LOOP] Monitoramento urgente iniciado.', 'accent-msg');
    });
  }

  const stop = document.getElementById('loop-stop');
  if (stop) {
    stop.addEventListener('click', async () => {
      const res = await fetch('/api/loop/stop', { method: 'POST' });
      const data = await res.json();
      if (!res.ok) return alert(data.error || 'Falha ao parar');
      applyLoopStatusPayload(data);
      logToConsole('[LOOP] Monitoramento parado.', 'system-msg');
    });
  }

  const refresh = document.getElementById('loop-refresh-status');
  if (refresh) {
    refresh.addEventListener('click', () => refreshLoopStatus().catch((e) => alert(e.message)));
  }

  const alertsRefresh = document.getElementById('loop-alerts-refresh');
  if (alertsRefresh) {
    alertsRefresh.addEventListener('click', () => refreshLoopAlerts().catch((e) => alert(e.message)));
  }

  const alertsClear = document.getElementById('loop-alerts-clear');
  if (alertsClear) {
    alertsClear.addEventListener('click', async () => {
      if (!confirm('Limpar histórico de alertas de loop?')) return;
      const res = await fetch('/api/loop/alerts', { method: 'DELETE' });
      const data = await res.json().catch(() => ({}));
      if (handleDestructiveAuthFailure(res, data, { modalTarget: 'loop' })) return;
      if (!res.ok) return alert(data.error || 'Falha ao limpar.');
      window.__loopAlertsCache = [];
      renderLoopAlerts([]);
    });
  }
}

