const AUTOTEST_STATUS_LABELS = {
  pass: 'PASS',
  fail: 'FALHA',
  warn: 'AVISO',
  skip: 'N/A'
};

function autotestNicModeLabel() {
  const mode = document.getElementById('autotest-run-interface-mode')?.value || 'auto';
  const labels = { auto: 'Automática', primary: 'Primária', secondary: 'Secundária', wifi: 'Wi-Fi', custom: 'Específica' };
  return labels[mode] || mode;
}

function autotestStepRemediation(step) {
  if (!step) return '';
  const d = String(step.detail || '').toLowerCase();
  if (step.id === 'local') {
    if (/wi-?fi/.test(d)) return 'Selecione Placa → Automática ou Primária em PCs sem wireless, ou ative o adaptador Wi-Fi no Windows.';
    if (/sem ipv4|sem rede/.test(d)) return 'Verifique cabo/Wi-Fi, DHCP ou IP estático na placa selecionada.';
    return 'Confirme adaptador ativo em Configurações → Rede e clique em Atualizar interface.';
  }
  if (step.id === 'gateway') return 'Verifique gateway, VLAN, cabo ou rota padrão na interface de teste.';
  if (step.id === 'dhcp') return 'Execute como administrador ou confirme se a interface usa DHCP.';
  if (step.id === 'switch') return 'Confirme IP SNMP, community e conectividade L3 até o switch.';
  if (step.id === 'wifi-scan') return 'Instale/adote adaptador Wi-Fi ou desative Scan Wi-Fi no perfil.';
  if (String(step.id || '').startsWith('dns')) return 'Valide DNS local, firewall ou proxy corporativo.';
  if (String(step.id || '').startsWith('tcp')) return 'Confirme serviço, ACL/firewall ou segmento de rede.';
  if (step.status === 'warn') return 'Revise o detalhe técnico — impacto parcial na conectividade.';
  if (step.status === 'fail') return 'Corrija este passo antes de considerar o posto operacional.';
  return '';
}

function autotestLocalRemediation(local) {
  const err = String(local?.error || '').toLowerCase();
  if (/wi-?fi/.test(err)) return 'Modo Wi-Fi sem adaptador detectado — use Automática/Primária ou habilite wireless.';
  if (/não encontrada|nao encontrada/.test(err)) return 'Nenhuma NIC compatível com o modo selecionado — ajuste o campo Placa.';
  if (/sem ipv4/.test(err)) return 'Interface up porém sem IPv4 — verifique DHCP ou configuração estática.';
  return 'Verifique adaptadores de rede ativos e clique em Atualizar interface.';
}

function formatAutoTestStepMeta(step) {
  const rows = [];
  if (step.pingStats) {
    const p = step.pingStats;
    if (p.avg != null) rows.push(['Latência média', `${p.avg} ms`]);
    if (p.lossPct != null) rows.push(['Perda', `${p.lossPct}%`]);
    else if (p.loss != null) rows.push(['Perda', `${p.loss}%`]);
  }
  if (step.ip) rows.push(['IPv4', step.ip]);
  if (step.gateway) rows.push(['Gateway', step.gateway]);
  if (step.macAddress) rows.push(['MAC', step.macAddress]);
  if (step.linkLabel) rows.push(['Link', step.linkLabel]);
  if (step.connectedPort?.portName) rows.push(['Porta switch', step.connectedPort.portName]);
  return rows;
}

function buildAutoTestBannerMetrics(result) {
  const parsed = parseLegacyAutoTestSummary(result?.summary);
  const rootStep = (result?.steps || []).find((s) => s.status === 'fail')
    || (result?.steps || []).find((s) => s.status === 'warn');
  const rootCause = rootStep ? { label: rootStep.label, detail: rootStep.detail || '—' } : null;
  if (parsed) {
    return {
      ...parsed,
      tested: parsed.pass + parsed.warn + parsed.fail,
      profileName: result?.profileName || result?.profileId || 'AutoTest',
      nicModeLabel: '—',
      rootCause
    };
  }
  const stats = result?.stats;
  if (!stats && !result?.grade) return null;
  const pass = stats?.pass ?? 0;
  const warn = stats?.warn ?? 0;
  const fail = stats?.fail ?? 0;
  const ok = result?.ok ?? fail === 0;
  return {
    grade: result?.grade || stats?.grade || '—',
    pass,
    warn,
    fail,
    durationSec: result?.durationMs ? (result.durationMs / 1000).toFixed(1) : '—',
    verdict: ok ? (warn > 0 ? 'APROVADO COM RESSALVAS' : 'APROVADO') : 'REPROVADO',
    verdictShort: ok ? (warn > 0 ? 'RESSALVAS' : 'OK') : 'FALHA',
    tested: pass + warn + fail,
    profileName: result?.profileName || result?.profileId || 'AutoTest',
    nicModeLabel: '—',
    rootCause
  };
}

function renderAutoTestEngineeringBanner(result, options = {}) {
  const eng = result?.engineering;
  if (options.mode === 'progress') {
    const detail = escapeHtml(options.detail || 'Executando sequência de testes…');
    return `
      <div class="autotest-eng-banner autotest-eng-banner-running">
        <div class="autotest-eng-head autotest-eng-head-running">
          <span class="autotest-eng-spinner" aria-hidden="true"></span>
          <span class="autotest-eng-verdict autotest-eng-verdict-running">EXECUTANDO</span>
          <span class="autotest-eng-running-layers">L2 · L3 · L4</span>
        </div>
        <p class="autotest-eng-line autotest-eng-line-running">
          <span class="autotest-eng-running-detail">${detail}</span>
          <span class="autotest-eng-dots" aria-hidden="true"><i></i><i></i><i></i></span>
        </p>
        <div class="autotest-eng-progress-track" role="progressbar" aria-label="Executando AutoTest">
          <div class="autotest-eng-progress-bar"></div>
        </div>
      </div>`;
  }
  if (options.mode === 'error') {
    return `
      <div class="autotest-eng-banner">
        <div class="autotest-eng-head">
          <span class="autotest-eng-verdict autotest-eng-verdict-fail">ERRO</span>
        </div>
        <p class="autotest-eng-line">${escapeHtml(options.detail || 'Falha na execução')}</p>
      </div>`;
  }
  if (!eng) {
    const metrics = buildAutoTestBannerMetrics(result);
    if (!metrics) {
      return `<div class="autotest-eng-banner"><p class="autotest-eng-line">${escapeHtml(result?.summary || 'Concluído')}</p></div>`;
    }
    const ok = result?.ok ?? metrics.fail === 0;
    const verdictCls = ok ? (metrics.warn > 0 ? 'autotest-eng-verdict-warn' : 'autotest-eng-verdict-ok') : 'autotest-eng-verdict-fail';
    const root = metrics.rootCause
      ? `<p class="autotest-eng-cause"><span>Causa provável</span> ${escapeHtml(metrics.rootCause.label)} — ${escapeHtml(metrics.rootCause.detail)}</p>`
      : '';
    const remote = result?.remoteAgent?.hostname
      ? `<span class="autotest-eng-tag">Remoto · ${escapeHtml(result.remoteAgent.hostname)}</span>`
      : '';
    return `
    <div class="autotest-eng-banner">
      <div class="autotest-eng-head">
        <span class="autotest-eng-verdict ${verdictCls}">${escapeHtml(metrics.verdict)}</span>
        <span class="autotest-eng-grade">Nota ${escapeHtml(metrics.grade)}</span>
        <span class="autotest-eng-duration">${escapeHtml(metrics.durationSec)} s</span>
      </div>
      ${root}
      <div class="autotest-eng-metrics">
        <span class="autotest-eng-metric autotest-eng-metric-pass">${metrics.pass} PASS</span>
        <span class="autotest-eng-metric autotest-eng-metric-warn">${metrics.warn} AVISO</span>
        <span class="autotest-eng-metric autotest-eng-metric-fail">${metrics.fail} FALHA</span>
        <span class="autotest-eng-metric">${metrics.tested} testes</span>
        <span class="autotest-eng-tag">${escapeHtml(metrics.profileName)}</span>
        ${remote}
      </div>
    </div>`;
  }
  const verdictCls = result.ok ? (eng.warn > 0 ? 'autotest-eng-verdict-warn' : 'autotest-eng-verdict-ok') : 'autotest-eng-verdict-fail';
  const root = eng.rootCause
    ? `<p class="autotest-eng-cause"><span>Causa provável</span> ${escapeHtml(eng.rootCause.label)} — ${escapeHtml(eng.rootCause.detail)}</p>`
    : '<p class="autotest-eng-cause"><span>Resultado</span> Todos os passos executados sem falha crítica.</p>';
  const remote = result.remoteAgent?.hostname
    ? `<span class="autotest-eng-tag">Remoto · ${escapeHtml(result.remoteAgent.hostname)}</span>`
    : '';
  return `
    <div class="autotest-eng-banner">
      <div class="autotest-eng-head">
        <span class="autotest-eng-verdict ${verdictCls}">${escapeHtml(eng.verdict)}</span>
        <span class="autotest-eng-grade">Nota ${escapeHtml(eng.grade)}</span>
        <span class="autotest-eng-duration">${escapeHtml(eng.durationSec)} s</span>
      </div>
      ${root}
      <div class="autotest-eng-metrics">
        <span class="autotest-eng-metric autotest-eng-metric-pass">${eng.pass} PASS</span>
        <span class="autotest-eng-metric autotest-eng-metric-warn">${eng.warn} AVISO</span>
        <span class="autotest-eng-metric autotest-eng-metric-fail">${eng.fail} FALHA</span>
        <span class="autotest-eng-metric">${eng.tested} testes</span>
        <span class="autotest-eng-tag">${escapeHtml(eng.profileName)}</span>
        <span class="autotest-eng-tag">NIC ${escapeHtml(eng.nicModeLabel)}</span>
        ${remote}
      </div>
    </div>`;
}

function setAutoTestBanner(text, kind = '', options = {}) {
  const el = document.getElementById('autotest-status-banner');
  if (!el) return;
  if (options.html) el.innerHTML = text;
  else el.textContent = text;
  el.className = `autotest-banner autotest-banner-footer autotest-banner-visible${kind ? ` autotest-banner-${kind}` : ''}${options.html ? ' autotest-banner-rich' : ''}${options.running ? ' autotest-banner-running' : ''}`;
  startAutoTestBannerPulse(el);
}

function setAutoTestEngineeringBanner(result, options = {}) {
  const metrics = result?.engineering || buildAutoTestBannerMetrics(result);
  const kind = options.kind
    || (options.mode === 'error' ? 'fail'
      : options.mode === 'progress' ? 'warn'
        : (result?.ok === false || metrics?.fail > 0 ? 'fail'
          : (metrics?.warn > 0 || result?.stats?.warn ? 'warn' : 'ok')));
  setAutoTestBanner(renderAutoTestEngineeringBanner(result, options), kind, {
    html: true,
    running: options.mode === 'progress'
  });
}

function setAutoTestCfgStatus(text, kind = '') {
  const el = document.getElementById('autotest-cfg-status');
  if (!el) return;
  el.textContent = text;
  el.className = `ad-status-bar${kind ? ` ${kind}` : ''}`;
}

function parseCsvList(raw) {
  return String(raw || '')
    .split(/[,;\s]+/)
    .map((s) => s.trim())
    .filter(Boolean);
}

function parsePortList(raw) {
  return parseCsvList(raw)
    .map((p) => Number(p))
    .filter((n) => Number.isFinite(n) && n > 0 && n <= 65535);
}

function toggleAutoTestCustomInterface(modeId, wrapId) {
  const mode = document.getElementById(modeId)?.value;
  const wrap = document.getElementById(wrapId);
  if (wrap) wrap.classList.toggle('hidden', mode !== 'custom');
}

function readAutoTestRunInterface() {
  const mode = document.getElementById('autotest-run-interface-mode')?.value || 'auto';
  const iface = document.getElementById('autotest-run-interface')?.value?.trim() || '';
  return {
    testInterfaceMode: mode,
    testInterface: mode === 'custom' ? iface : ''
  };
}

function syncAutoTestRunInterface(profile) {
  const modeEl = document.getElementById('autotest-run-interface-mode');
  const ifEl = document.getElementById('autotest-run-interface');
  if (modeEl) modeEl.value = profile?.testInterfaceMode || 'auto';
  if (ifEl && profile?.testInterface) ifEl.value = profile.testInterface;
  toggleAutoTestCustomInterface('autotest-run-interface-mode', 'autotest-run-interface-wrap');
}

function fillAutoTestInterfaceSelects(interfaces) {
  const selects = [
    { id: 'autotest-cfg-dhcp-interface', emptyLabel: '— Selecione —' },
    { id: 'autotest-cfg-test-interface', emptyLabel: '— Selecione —' },
    { id: 'autotest-run-interface', emptyLabel: interfaces?.length ? '— Selecione a NIC —' : '— Nenhuma interface ativa —' }
  ];
  for (const { id, emptyLabel } of selects) {
    const sel = document.getElementById(id);
    if (!sel) continue;
    const current = sel.value;
    const opts = [`<option value="">${emptyLabel}</option>`];
    for (const iface of interfaces || []) {
      const label = `${iface.interfaceAlias}${iface.isPrimary ? ' (primária)' : ''}${iface.ip ? ` · ${iface.ip}` : ''}`;
      opts.push(`<option value="${escapeHtml(iface.interfaceAlias)}">${escapeHtml(label)}</option>`);
    }
    sel.innerHTML = opts.join('');
    if (current) sel.value = current;
  }
}

