    timeoutMs: Number(document.getElementById('autotest-cfg-timeout')?.value || 2500),
    switchIp: document.getElementById('autotest-cfg-switch-ip')?.value?.trim() || '',
    switchCommunity: document.getElementById('autotest-cfg-switch-community')?.value?.trim() || '',
    stopOnFail: Boolean(document.getElementById('autotest-cfg-stop-on-fail')?.checked),
    dhcpTestEnabled: Boolean(document.getElementById('autotest-cfg-dhcp-enabled')?.checked),
    dhcpTestMode: dhcpMode === 'alias' ? 'secondary' : dhcpMode,
    dhcpTestInterface: dhcpMode === 'alias' ? dhcpInterface : '',
    testInterfaceMode: testMode,
