      ? `<span class="autotest-eng-tag">${escapeHtml(r.localIp)}${r.gateway ? ` · GW ${escapeHtml(r.gateway)}` : ''}</span>`
      : '';
    return `
      <article class="autotest-history-item ${cls}">
        <div class="autotest-history-head">
          <span class="autotest-eng-verdict ${verdictCls}">${escapeHtml(m.verdict)}</span>
          <span class="autotest-history-grade">Nota ${escapeHtml(m.grade)}</span>
          <strong class="autotest-history-profile">${escapeHtml(m.profileName)}</strong>
