  if (runBtn) runBtn.addEventListener('click', () => runAutoTest());

  const runRemoteBtn = document.getElementById('autotest-run-remote-btn');
  if (runRemoteBtn) runRemoteBtn.addEventListener('click', () => runRemoteAutoTest());

  const remoteRefresh = document.getElementById('autotest-remote-refresh-agents');
  if (remoteRefresh) {
    remoteRefresh.addEventListener('click', () => {
      ensureAutoTestRemoteAuth(() => loadAutoTestRemoteAgents().catch((e) => alert(e.message)));
    });
  }

  const pairingBtn = document.getElementById('autotest-remote-pairing-btn');
  if (pairingBtn) {
    pairingBtn.addEventListener('click', () => {
      ensureAutoTestRemoteAuth(() => createAutoTestPairingCode());
    });
  }

  const revokeBtn = document.getElementById('autotest-remote-revoke-agent');
  if (revokeBtn) {
    revokeBtn.addEventListener('click', () => {
      revokeAutoTestRemoteAgent().catch((e) => alert(e.message));
    });
  }

  const remoteTargetInput = document.getElementById('autotest-remote-agent');
  if (remoteTargetInput && !remoteTargetInput.dataset.wired) {
    remoteTargetInput.dataset.wired = '1';
    remoteTargetInput.addEventListener('input', () => updateAutoTestRemoteTargetHint(remoteTargetInput.value));
    remoteTargetInput.addEventListener('change', () => updateAutoTestRemoteTargetHint(remoteTargetInput.value));
    wireAutoTestRemoteAgentPlaceholder(remoteTargetInput);
  }

  const exportPdf = document.getElementById('autotest-export-pdf-btn');
  if (exportPdf) exportPdf.addEventListener('click', () => exportAutoTestPdf());

  const exportXlsx = document.getElementById('autotest-export-xlsx-btn');
  if (exportXlsx) exportXlsx.addEventListener('click', () => exportAutoTestXlsx());

  const profileRun = document.getElementById('autotest-profile-select');
  if (profileRun) {
    profileRun.addEventListener('change', async () => {
      const id = profileRun.value;
      try {
        const profile = await loadAutoTestProfile(id);
        updateAutoTestProfileDesc(profile);
        syncAutoTestRunInterface(profile);
        const cfgSel = document.getElementById('autotest-cfg-profile');
