  const editProfile = document.getElementById('autotest-edit-profile-btn');
  if (editProfile) {
    editProfile.addEventListener('click', () => {
      openAutoTestConfigTab(document.getElementById('autotest-profile-select')?.value);
    });
  }

  const customHintGo = document.getElementById('autotest-custom-hint-go');
  if (customHintGo) {
    customHintGo.addEventListener('click', () => openAutoTestConfigTab('custom'));
  }

  const profileCfg = document.getElementById('autotest-cfg-profile');
  if (profileCfg) {
    profileCfg.addEventListener('change', () => {
      loadAutoTestProfile(profileCfg.value).catch((e) => alert(e.message));
    });
  }

  const loadIfaces = document.getElementById('autotest-cfg-load-interfaces');
  if (loadIfaces) {
    loadIfaces.addEventListener('click', () => {
      loadAutoTestInterfaces().catch((e) => alert(e.message));
    });
  }

  const cfgTestMode = document.getElementById('autotest-cfg-test-interface-mode');
