    runTestMode.addEventListener('change', () => {
      toggleAutoTestCustomInterface('autotest-run-interface-mode', 'autotest-run-interface-wrap');
      if (runTestMode.value === 'custom') {
        ensureAutoTestInterfacesLoaded().catch((e) => alert(e.message));
      }
      refreshAutoTestLocal().catch(() => {});
    });
  }

  const runTestIf = document.getElementById('autotest-run-interface');
  if (runTestIf) {
    runTestIf.addEventListener('focus', () => {
      ensureAutoTestInterfacesLoaded().catch(() => {});
    });
    runTestIf.addEventListener('change', () => {
      refreshAutoTestLocal().catch(() => {});
    });
  }

  const loopPick = document.getElementById('autotest-loop-switch-pick');
  if (loopPick) {
    loopPick.addEventListener('change', () => {
      applyAutoTestLoopSwitch(loopPick, 'autotest-sw-ip', 'autotest-sw-community');
    });
