  const histRefresh = document.getElementById('autotest-history-refresh');
  if (histRefresh) {
    histRefresh.addEventListener('click', () => loadAutoTestHistory().catch((e) => alert(e.message)));
  }

  const histClear = document.getElementById('autotest-history-clear');
  if (histClear) {
    histClear.addEventListener('click', async () => {
      if (!confirm('Limpar todo o histórico de AutoTest?')) return;
      const res = await fetch('/api/autotest/history', { method: 'DELETE' });
      const data = await res.json().catch(() => ({}));
      if (handleDestructiveAuthFailure(res, data, { modalTarget: 'autotest' })) return;
      if (!res.ok) return alert(data.error || 'Falha ao limpar histórico.');
      renderAutoTestHistory([]);
    });
