  const refreshLocal = document.getElementById('autotest-refresh-local');
  if (refreshLocal) {
    refreshLocal.addEventListener('click', () => {
      Promise.all([
        loadAutoTestInterfaces().catch((e) => alert(e.message)),
        refreshAutoTestLocal().catch((e) => alert(e.message))
      ]).catch(() => {});
    });
  }

  const saveCfg = document.getElementById('autotest-cfg-save');
  if (saveCfg) {
    saveCfg.addEventListener('click', async () => {
      const body = readAutoTestConfigForm();
      const res = await fetch('/api/autotest/config', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) return alert(data.error || 'Falha ao salvar.');
      window.__autotestState = data;
      renderAutoTestProfileSelects(data.profiles, data.activeProfileId);
      syncAutoTestProfileFromConfig(data, body.profileId);
      setAutoTestCfgStatus(`Perfil "${data.activeProfile?.name || body.profileId}" salvo.`, 'ok');
    });
  }

  const discover = document.getElementById('autotest-sw-discover');
  if (discover) {
    discover.addEventListener('click', async () => {
      const switchIp = document.getElementById('autotest-sw-ip')?.value?.trim();
      if (!switchIp) return alert('Informe o IP do switch.');
      const switchCommunity = document.getElementById('autotest-sw-community')?.value?.trim();
      discover.disabled = true;
      try {
        const res = await fetch('/api/autotest/switch', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ switchIp, switchCommunity })
        });
        const data = await res.json().catch(() => ({}));
        if (!res.ok) throw new Error(data.error || 'Falha SNMP');
        renderAutoTestNeighbors(data.step);
      } catch (err) {
        alert(err.message);
      } finally {
        discover.disabled = false;
      }
    });
  }
}

