/* ——— Modal Oracle / Login AD ——— */
function openOracleModalDirect(tab = 'search') {
  const backdrop = document.getElementById('oracle-modal-backdrop');
  if (!backdrop) return;
  backdrop.classList.remove('hidden');
  backdrop.setAttribute('aria-hidden', 'false');
  switchOracleTab(tab);
  loadOracleConfig().catch(() => {});
  const q = document.getElementById('oracle-query');
  if (q) setTimeout(() => q.focus(), 50);
}

function openOracleModal(tab = 'search') {
  gateProtectedArea({ target: 'oracle', tab });
}

function closeOracleModal() {
  const backdrop = document.getElementById('oracle-modal-backdrop');
  if (!backdrop) return;
  backdrop.classList.add('hidden');
  backdrop.setAttribute('aria-hidden', 'true');
}

function switchOracleTab(tab) {
  document.querySelectorAll('.oracle-tab').forEach((el) => {
    const active = el.dataset.oracleTab === tab;
    el.classList.toggle('active', active);
    el.setAttribute('aria-selected', active ? 'true' : 'false');
  });
  ['search', 'config'].forEach((id) => {
    const panel = document.getElementById(`oracle-tab-${id}`);
    if (!panel) return;
    panel.classList.toggle('hidden', id !== tab);
  });
}

function setOracleStatus(elId, text, kind = '') {
  const el = document.getElementById(elId);
  if (!el) return;
  el.textContent = text;
  el.className = `ad-status-bar${kind ? ` ${kind}` : ''}`;
}

async function loadOracleConfig() {
  const res = await fetch('/api/oracle/config');
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.error || 'Falha ao carregar config Oracle');
  const cfg = data.config || {};
  const user = document.getElementById('oracle-cfg-user');
  const pass = document.getElementById('oracle-cfg-password');
  const connect = document.getElementById('oracle-cfg-connect');
  const table = document.getElementById('oracle-cfg-table');
  const max = document.getElementById('oracle-cfg-max');
  if (user) user.value = cfg.user || '';
  if (pass) pass.value = '';
  if (pass) pass.placeholder = cfg.hasPassword ? '••••••••' : 'Senha Oracle';
  if (connect) connect.value = cfg.connectString || '';
  if (table) table.value = cfg.table || 'dbasgu.usuarios';
  if (max) max.value = cfg.maxRows || 50;
  const libdir = document.getElementById('oracle-cfg-libdir');
  if (libdir) libdir.value = cfg.libDir || cfg.suggestedLibDir || '';
  if (!cfg.connectString) {
    setOracleStatus('oracle-cfg-status', 'Configure o Connect String (TNS sem jdbc: ou host:1521/SERVICE).', 'err');
  } else if (cfg.thickError) {
    setOracleStatus('oracle-cfg-status', `Thick mode: ${cfg.thickError}`, 'err');
  } else {
    setOracleStatus('oracle-cfg-status', `Pronto · user=${cfg.user || '?'} · ${cfg.connectString}`, 'ok');
  }
  return cfg;
}

function renderOracleResults(users) {
  const box = document.getElementById('oracle-results');
  if (!box) return;
  const list = Array.isArray(users) ? users : [];
  if (!list.length) {
    box.innerHTML = '<div class="ad-empty">Nenhum usuário encontrado no Oracle.</div>';
    return;
  }

  box.innerHTML = `
    <h3 class="ad-section-title">${escapeHtml(String(list.length))} resultado(s)</h3>
    ${list.map((u) => {
    const sugs = (u.suggestions || []).map((s) => {
      let badge = '<span class="oracle-badge unknown">AD não checado</span>';
      if (s.adExists === true) {
        const name = s.adUser?.displayName ? ` · ${s.adUser.displayName}` : '';
        const st = s.adUser?.enabled === false ? ' (desabilitado)' : '';
        badge = `<span class="oracle-badge exists">Já existe no AD${st}${escapeHtml(name)}</span>`;
      } else if (s.adExists === false) {
        badge = '<span class="oracle-badge free">Livre no AD</span>';
      }
      return `
        <div class="oracle-sug${s.preferred ? ' preferred' : ''}">
          <span class="oracle-sug-login">${escapeHtml(s.login)}</span>
          <span class="oracle-sug-rule">${escapeHtml(s.rule || '')}</span>
          ${badge}
          <button type="button" class="btn btn-tertiary btn-sm" data-oracle-copy="${escapeHtml(s.login)}">Copiar</button>
        </div>
      `;
    }).join('');

    return `
      <div class="oracle-card">
        <div class="oracle-card-head">
          <div>
            <strong>${escapeHtml(u.nmUsuario || '—')}</strong>
            <span>Oracle · dbasgu.usuarios</span>
          </div>
          <div class="oracle-code" title="cd_usuario">${escapeHtml(u.cdUsuario || '—')}</div>
        </div>
        <div class="oracle-suggestions">${sugs || '<span class="oracle-sug-rule">Sem sugestões</span>'}</div>
      </div>
    `;
  }).join('')}
  `;
}

async function runOracleSearch() {
  const q = document.getElementById('oracle-query')?.value?.trim() || '';
  const mode = document.getElementById('oracle-mode')?.value || 'auto';
  const checkAd = document.getElementById('oracle-check-ad')?.checked !== false;
  if (q.length < 2) {
    setOracleStatus('oracle-search-status', 'Digite ao menos 2 caracteres.', 'err');
    return;
  }
  setOracleStatus('oracle-search-status', 'Consultando Oracle…', '');
  const btn = document.getElementById('oracle-search-btn');
  if (btn) btn.disabled = true;
  try {
    const url = `/api/oracle/users?q=${encodeURIComponent(q)}&mode=${encodeURIComponent(mode)}&checkAd=${checkAd ? '1' : '0'}`;
    const res = await fetch(url);
    const data = await res.json().catch(() => ({}));
    if (!res.ok || data.ok === false) {
      throw new Error(data.error || 'Falha na consulta Oracle');
    }
    renderOracleResults(data.users || []);
    setOracleStatus(
      'oracle-search-status',
      `${data.count || 0} resultado(s) · padrão ${data.pattern || ''}${checkAd ? ' · AD verificado' : ''}`,
      data.count ? 'ok' : ''
    );
  } catch (err) {
    renderOracleResults([]);
    setOracleStatus('oracle-search-status', err.message, 'err');
  } finally {
    if (btn) btn.disabled = false;
  }
}

function wireOracleLookupUi() {
  const openBtn = document.getElementById('oracle-lookup-open-btn');
  const closeBtn = document.getElementById('oracle-modal-close');
  const backdrop = document.getElementById('oracle-modal-backdrop');
  if (!openBtn || openBtn.dataset.wired) return;
  openBtn.dataset.wired = '1';

  openBtn.addEventListener('click', () => openOracleModal('search'));
  if (closeBtn) closeBtn.addEventListener('click', closeOracleModal);
  if (backdrop) {
    backdrop.addEventListener('click', (e) => {
      if (e.target === backdrop) closeOracleModal();
    });
  }

  document.querySelectorAll('.oracle-tab').forEach((tab) => {
    tab.addEventListener('click', () => switchOracleTab(tab.dataset.oracleTab));
  });

  const searchBtn = document.getElementById('oracle-search-btn');
  const query = document.getElementById('oracle-query');
  if (searchBtn) searchBtn.addEventListener('click', () => runOracleSearch());
  if (query) {
    query.addEventListener('keydown', (e) => {
      if (e.key === 'Enter') runOracleSearch();
    });
  }

  const results = document.getElementById('oracle-results');
  if (results) {
    results.addEventListener('click', async (e) => {
      const btn = e.target.closest('[data-oracle-copy]');
      if (!btn) return;
      const login = btn.getAttribute('data-oracle-copy') || '';
      try {
        await navigator.clipboard.writeText(login);
        const prev = btn.textContent;
        btn.textContent = 'Copiado!';
        setTimeout(() => { btn.textContent = prev; }, 1000);
      } catch {
        alert(`Login: ${login}`);
      }
    });
  }

  const saveCfg = document.getElementById('oracle-cfg-save');
  if (saveCfg) {
    saveCfg.addEventListener('click', async () => {
      const body = {
        user: document.getElementById('oracle-cfg-user')?.value || '',
        connectString: document.getElementById('oracle-cfg-connect')?.value || '',
        table: document.getElementById('oracle-cfg-table')?.value || 'dbasgu.usuarios',
        maxRows: Number(document.getElementById('oracle-cfg-max')?.value || 50),
        thickMode: true,
        libDir: document.getElementById('oracle-cfg-libdir')?.value || ''
      };
      const pass = document.getElementById('oracle-cfg-password')?.value;
      if (pass) body.password = pass;
      const res = await fetch('/api/oracle/config', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body)
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) {
        setOracleStatus('oracle-cfg-status', data.error || 'Falha ao salvar', 'err');
        return;
      }
      setOracleStatus('oracle-cfg-status', 'Configuração Oracle salva.', 'ok');
      await loadOracleConfig();
    });
  }

  const testCfg = document.getElementById('oracle-cfg-test');
  if (testCfg) {
    testCfg.addEventListener('click', async () => {
      setOracleStatus('oracle-cfg-status', 'Testando conexão…', '');
      const res = await fetch('/api/oracle/test', { method: 'POST' });
      const data = await res.json().catch(() => ({}));
      if (!res.ok || !data.ok) {
        setOracleStatus('oracle-cfg-status', data.error || 'Falha no teste', 'err');
        return;
      }
      setOracleStatus('oracle-cfg-status', data.message || 'Conexão OK', 'ok');
    });
  }
}

