/* Clean CSS Reset & Theme Variable Tokens */
:root {
  --bg-main: #08090d;
  --bg-panel: rgba(18, 22, 36, 0.7);
  --bg-console: #05070a;
  --border-color: rgba(255, 255, 255, 0.06);
  --border-glow: rgba(0, 242, 254, 0.15);

  --text-primary: #f8fafc;
  --text-secondary: #94a3b8;
  --text-muted: #64748b;

  --accent: #00f2fe;
  --accent-secondary: #4facfe;
  --accent-glow: rgba(0, 242, 254, 0.3);

  --success: #10b981;
  --success-glow: rgba(16, 185, 129, 0.2);
  --danger: #ef4444;
  --danger-glow: rgba(239, 68, 68, 0.2);
  --warning: #f59e0b;

  --primary-grad: linear-gradient(135deg, #00f2fe 0%, #4facfe 100%);
  --btn-hover-grad: linear-gradient(135deg, #00d8e4 0%, #3a94e0 100%);
  --panel-shadow: 0 8px 32px 0 rgba(0, 0, 0, 0.4);

  --font-ui: 'Plus Jakarta Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  --font-code: 'JetBrains Mono', 'Fira Code', 'Courier New', monospace;

  /* Modais temáticos Canon — dimensões padronizadas */
  --canon-modal-width: min(1080px, 96vw);
  --canon-modal-max-height: min(94vh, 980px);
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  background-color: var(--bg-main);
  color: var(--text-primary);
  font-family: var(--font-ui);
  min-height: 100vh;
  overflow-x: hidden;
  position: relative;
  display: flex;
  flex-direction: column;
}

/* Background Decorative Elements */
.glass-bg-decor {
  position: absolute;
  border-radius: 50%;
  filter: blur(120px);
  opacity: 0.15;
  z-index: -1;
  pointer-events: none;
}

.decor-1 {
  width: 400px;
  height: 400px;
  background: var(--accent);
  top: -100px;
  right: -50px;
}

.decor-2 {
  width: 500px;
  height: 500px;
  background: #7928ca;
  bottom: 10%;
  left: -200px;
}

.decor-3 {
  width: 300px;
  height: 300px;
  background: var(--accent-secondary);
  top: 40%;
  right: 15%;
}

/* Application Layout Container */
.app-container {
  max-width: 1400px;
  width: 100%;
  margin: 0 auto;
  padding: 30px 20px;
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 24px;
}

/* Header Styling */
.app-header {
  display: flex;
  justify-content: space-between;
