  gap: 15px;
}

/* ——— NetScan Canon — branding avançado ——— */
.canon-brand {
  position: relative;
  isolation: isolate;
}

.canon-brand::after {
  content: '';
  position: absolute;
  left: -8px;
  right: -12px;
  top: 50%;
  height: 1px;
  background: linear-gradient(
    90deg,
    transparent 0%,
    rgba(0, 242, 254, 0) 35%,
    rgba(0, 242, 254, 0.85) 50%,
    rgba(79, 172, 254, 0) 65%,
    transparent 100%
  );
  transform: translateY(-50%) scaleX(0.25);
  opacity: 0;
  pointer-events: none;
  animation: canonBrandScan 5.5s ease-in-out infinite;
}

.canon-brand-icon {
  position: relative;
  width: 46px;
  height: 46px;
  display: flex;
  align-items: center;
  justify-content: center;
  filter: drop-shadow(0 0 10px rgba(0, 242, 254, 0.45));
  animation: canonBrandIconFloat 4.8s ease-in-out infinite;
