.canon-brand-core-glow {
  position: absolute;
  inset: 4px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(0, 242, 254, 0.35) 0%, transparent 70%);
  animation: canonBrandCorePulse 2.4s ease-in-out infinite;
