}

.canon-brand-title {
  display: flex;
  align-items: baseline;
  gap: 8px;
  margin: 0;
  font-size: 1.55rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1.1;
}

.canon-brand-netscan {
  position: relative;
  display: inline-block;
  background: linear-gradient(
    110deg,
    #00f2fe 0%,
    #4facfe 22%,
    #ffffff 44%,
    #00f2fe 56%,
    #4facfe 78%,
    #00f2fe 100%
  );
  background-size: 260% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  animation: canonBrandShimmer 4.2s linear infinite;
  filter: drop-shadow(0 0 12px rgba(0, 242, 254, 0.35));
}

.canon-brand-netscan::after {
  content: attr(data-text);
  position: absolute;
  inset: 0;
  background: linear-gradient(110deg, transparent 40%, rgba(255, 255, 255, 0.92) 50%, transparent 60%);
  background-size: 220% 100%;
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
  animation: canonBrandGlint 3.6s ease-in-out infinite;
  pointer-events: none;
}

.canon-brand-canon {
  position: relative;
  font-weight: 300;
  font-size: 1.35rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: #f8fafc;
  text-shadow:
    0 0 8px rgba(0, 242, 254, 0.35),
    0 0 18px rgba(79, 172, 254, 0.18);
  animation: canonBrandCanonGlow 3s ease-in-out infinite;
}

.canon-brand-canon::before {
  content: '';
  position: absolute;
  left: -6px;
  right: -4px;
  bottom: 2px;
  height: 2px;
  border-radius: 999px;
  background: linear-gradient(90deg, transparent, rgba(0, 242, 254, 0.75), rgba(79, 172, 254, 0.35), transparent);
  opacity: 0.65;
  transform: scaleX(0.55);
  animation: canonBrandUnderline 3.8s ease-in-out infinite;
}

.canon-brand-tagline {
  margin: 4px 0 0;
  font-size: 0.75rem;
  color: var(--text-secondary);
  letter-spacing: 0.04em;
  opacity: 0.92;
}

.canon-brand-tagline::after {
  content: '▮';
  display: inline-block;
  margin-left: 4px;
  color: rgba(0, 242, 254, 0.75);
  animation: canonBrandCursor 1.1s step-end infinite;
}

@keyframes canonBrandShimmer {
  0% { background-position: 0% 50%; }
  100% { background-position: 260% 50%; }
}

@keyframes canonBrandGlint {
  0%, 72%, 100% { background-position: 130% 50%; opacity: 0; }
  78% { opacity: 1; }
  88% { background-position: -30% 50%; opacity: 0; }
}

@keyframes canonBrandCanonGlow {
  0%, 100% {
    text-shadow:
      0 0 8px rgba(0, 242, 254, 0.3),
      0 0 16px rgba(79, 172, 254, 0.12);
  }
  50% {
    text-shadow:
      0 0 12px rgba(0, 242, 254, 0.55),
      0 0 28px rgba(79, 172, 254, 0.28);
  }
}

@keyframes canonBrandUnderline {
  0%, 100% { transform: scaleX(0.45); opacity: 0.45; }
  50% { transform: scaleX(1); opacity: 0.9; }
}

@keyframes canonBrandIconFloat {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-2px); }
}

@keyframes canonBrandCorePulse {
  0%, 100% { transform: scale(0.92); opacity: 0.55; }
  50% { transform: scale(1.08); opacity: 1; }
}

@keyframes canonBrandOrbit {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

@keyframes canonBrandScan {
  0%, 58%, 100% { opacity: 0; transform: translateY(-50%) scaleX(0.2); }
  62% { opacity: 0.85; transform: translateY(-50%) scaleX(0.65); }
  74% { opacity: 0; transform: translateY(-50%) scaleX(1.05); }
}

@keyframes canonBrandCursor {
  0%, 49% { opacity: 1; }
  50%, 100% { opacity: 0; }
}

@media (prefers-reduced-motion: reduce) {
  .canon-brand::after,
  .canon-brand-icon,
  .canon-brand-core-glow,
  .canon-brand-orbit,
  .canon-brand-netscan,
  .canon-brand-netscan::after,
  .canon-brand-canon,
  .canon-brand-canon::before,
  .canon-brand-tagline::after {
    animation: none !important;
  }

  .canon-brand-netscan {
    background: var(--primary-grad);
    background-size: 100% 100%;
  }
}

.logo-text h1 {
  font-size: 1.5rem;
  font-weight: 700;
  letter-spacing: -0.5px;
  background: var(--primary-grad);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  display: flex;
  align-items: center;
  gap: 6px;
}

.logo-text h1 span {
  font-weight: 300;
  font-size: 1.3rem;
  opacity: 0.95;
  -webkit-text-fill-color: var(--text-primary);
}

.logo-text p {
  font-size: 0.75rem;
  color: var(--text-secondary);
  margin-top: 2px;
}

/* Badges */
.badge {
  padding: 6px 12px;
  border-radius: 20px;
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.5px;
  text-transform: uppercase;
  transition: all 0.3s ease;
}

.badge-disconnected {
  background: rgba(239, 68, 68, 0.1);
  color: var(--danger);
  border: 1px solid rgba(239, 68, 68, 0.2);
}

.badge-connected {
  position: relative;
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 6px 14px 6px 12px;
  background: rgba(0, 242, 254, 0.07);
  color: var(--accent);
  border: 1px solid rgba(0, 242, 254, 0.55);
  box-shadow:
    0 0 14px rgba(0, 242, 254, 0.35),
    0 0 28px rgba(0, 242, 254, 0.12),
    inset 0 0 14px rgba(0, 242, 254, 0.06);
  overflow: hidden;
  animation: connectionBadgeGlow 2.2s ease-in-out infinite;
  text-shadow: 0 0 12px rgba(0, 242, 254, 0.55);
}

.badge-connected::before {
  content: '';
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--accent);
  box-shadow:
    0 0 6px var(--accent),
    0 0 14px rgba(0, 242, 254, 0.75);
  animation: connectionDotPulse 1.1s ease-in-out infinite;
  flex-shrink: 0;
}

.badge-connected::after {
  content: '';
  position: absolute;
  top: 0;
  left: -120%;
  width: 45%;
  height: 100%;
  background: linear-gradient(
    105deg,
    transparent 0%,
    rgba(0, 242, 254, 0.08) 35%,
    rgba(0, 242, 254, 0.45) 50%,
    rgba(0, 242, 254, 0.08) 65%,
    transparent 100%
  );
  animation: connectionBadgeShimmer 2.8s ease-in-out infinite;
  pointer-events: none;
}

@keyframes connectionBadgeGlow {
  0%, 100% {
    border-color: rgba(0, 242, 254, 0.45);
    box-shadow:
      0 0 10px rgba(0, 242, 254, 0.25),
      0 0 22px rgba(0, 242, 254, 0.08),
      inset 0 0 10px rgba(0, 242, 254, 0.04);
    transform: scale(1);
  }
  50% {
    border-color: rgba(0, 242, 254, 0.95);
    box-shadow:
      0 0 18px rgba(0, 242, 254, 0.55),
      0 0 36px rgba(0, 242, 254, 0.22),
      0 0 52px rgba(0, 242, 254, 0.08),
      inset 0 0 18px rgba(0, 242, 254, 0.1);
    transform: scale(1.03);
  }
}

@keyframes connectionDotPulse {
  0%, 100% {
    transform: scale(1);
    opacity: 1;
    box-shadow:
      0 0 6px var(--accent),
      0 0 14px rgba(0, 242, 254, 0.75);
  }
  50% {
    transform: scale(1.35);
    opacity: 0.85;
    box-shadow:
      0 0 10px var(--accent),
      0 0 22px rgba(0, 242, 254, 0.95),
      0 0 34px rgba(0, 242, 254, 0.35);
  }
}

@keyframes connectionBadgeShimmer {
  0% { left: -120%; }
  45%, 100% { left: 180%; }
}

@media (prefers-reduced-motion: reduce) {
  .badge-connected {
    animation: none;
    transform: none;
  }

  .badge-connected::before {
    animation: none;
  }

  .badge-connected::after {
    display: none;
  }
}

.badge-connecting {
  background: rgba(59, 130, 246, 0.12);
  color: #60a5fa;
  border: 1px solid rgba(59, 130, 246, 0.25);
}

/* Glassmorphism Panel Template */
.glass-panel {
  background: var(--bg-panel);
  border: 1px solid var(--border-color);
  border-radius: 16px;
  box-shadow: var(--panel-shadow);
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  overflow: hidden;
  transition: border-color 0.3s ease, box-shadow 0.3s ease;
}

.glass-panel:hover {
  border-color: rgba(0, 242, 254, 0.15);
  box-shadow: 0 8px 32px 0 rgba(0, 242, 254, 0.03), var(--panel-shadow);
}

.panel-header {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 18px 24px;
  border-bottom: 1px solid var(--border-color);
}

.panel-header h2 {
  font-size: 1.1rem;
  font-weight: 600;
  letter-spacing: -0.2px;
}

.panel-header .icon {
  font-size: 1.25rem;
}

/* Grid Layout (Side-by-Side) */
.scan-grid {
  display: grid;
  grid-template-columns: 1fr 1.3fr;
  gap: 24px;
}

@media (max-width: 900px) {
  .scan-grid {
    grid-template-columns: 1fr;
  }
}

/* Form Styles (Left Panel) */
.config-panel form {
  padding: 24px;
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.form-group label {
  font-size: 0.8rem;
  font-weight: 600;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.form-group input[type="text"], 
.form-group select {
  background: rgba(10, 11, 18, 0.8);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  color: var(--text-primary);
  font-family: var(--font-ui);
  font-size: 0.9rem;
  padding: 12px 16px;
  outline: none;
  transition: all 0.3s ease;
}

.form-group input::placeholder {
  color: var(--text-muted);
}

.form-group input:focus, 
.form-group select:focus {
  border-color: var(--accent);
  box-shadow: 0 0 8px var(--accent-glow);
  background: rgba(10, 11, 18, 0.95);
}

.input-helper {
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 2px;
}

.suggestion-link {
  color: var(--accent-secondary);
  cursor: pointer;
  text-decoration: underline;
  transition: color 0.2s;
}

.suggestion-link:hover {
  color: var(--accent);
}

/* Form Row layout */
.row {
  display: flex;
  gap: 16px;
}

.col {
  flex: 1;
}

/* Toggle Switch Styles */
.checkbox-group {
  flex-direction: row;
  align-items: center;
  gap: 12px;
  margin-top: 4px;
}

.checkbox-label {
  font-size: 0.85rem;
  color: var(--text-secondary);
}

.switch {
  position: relative;
  display: inline-block;
  width: 46px;
  height: 24px;
  flex-shrink: 0;
}

.switch input {
  opacity: 0;
  width: 0;
  height: 0;
}

.slider {
  position: absolute;
  cursor: pointer;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-color: rgba(255, 255, 255, 0.1);
  transition: .3s;
  border: 1px solid var(--border-color);
}

.slider:before {
  position: absolute;
  content: "";
  height: 16px;
  width: 16px;
  left: 3px;
  bottom: 3px;
  background-color: var(--text-primary);
  transition: .3s;
}

input:checked + .slider {
  background: var(--primary-grad);
}

input:focus + .slider {
  box-shadow: 0 0 1px var(--accent);
}

input:checked + .slider:before {
  transform: translateX(22px);
}

.slider.round {
  border-radius: 34px;
}

.slider.round:before {
  border-radius: 50%;
}

/* Helper Class */
.hidden {
  display: none !important;
}

/* Buttons */
.btn {
  border-radius: 8px;
  cursor: pointer;
  font-family: var(--font-ui);
  font-size: 0.9rem;
  font-weight: 600;
  padding: 12px 24px;
  text-align: center;
  transition: all 0.3s ease;
  outline: none;
  border: none;
}

.btn-primary {
  background: var(--primary-grad);
  color: #05070a;
  box-shadow: 0 4px 15px rgba(0, 242, 254, 0.3);
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
}

.btn-primary:hover:not(:disabled) {
  background: var(--btn-hover-grad);
  box-shadow: 0 6px 20px rgba(0, 242, 254, 0.45);
  transform: translateY(-1px);
}

.btn-primary:active:not(:disabled) {
  transform: translateY(1px);
}

.btn-primary:disabled {
  background: var(--text-muted);
  color: rgba(255, 255, 255, 0.35);
  box-shadow: none;
  cursor: not-allowed;
}

.btn-secondary {
  background: rgba(255, 255, 255, 0.05);
  color: var(--text-primary);
  border: 1px solid var(--border-color);
}

.btn-secondary:hover:not(:disabled) {
  background: rgba(255, 255, 255, 0.1);
  border-color: rgba(255, 255, 255, 0.2);
}

.btn-secondary:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.btn-tertiary {
  background: transparent;
  color: var(--text-secondary);
  border: 1px solid var(--border-color);
  padding: 8px 16px;
  font-size: 0.8rem;
}

.btn-tertiary:hover {
  background: rgba(239, 68, 68, 0.1);
  color: var(--danger);
  border-color: rgba(239, 68, 68, 0.2);
}

.form-actions {
  display: grid;
  grid-template-columns: repeat(2, minmax(140px, 1fr));
  gap: 12px;
  margin-top: 10px;
}

  .form-actions button:nth-child(3),
  .form-actions button:nth-child(4) {
    min-width: 0;
  }
.loader {
  border: 2px solid rgba(5, 7, 10, 0.2);
  border-top: 2px solid #05070a;
  border-radius: 50%;
  width: 16px;
  height: 16px;
  animation: spin 0.8s linear infinite;
  display: inline-block;
}

@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

/* Console Panel (Right Panel) */
.console-panel {
  display: flex;
  flex-direction: column;
  height: 100%;
}

.console-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.console-metrics {
  background: rgba(255, 255, 255, 0.05);
  padding: 4px 10px;
  border-radius: 6px;
  border: 1px solid var(--border-color);
}

.metric {
  font-family: var(--font-code);
  font-size: 0.85rem;
  color: var(--accent);
}

.console-wrapper {
  height: 350px;
  background: var(--bg-console);
  margin: 20px;
  box-shadow: 0 10px 30px rgba(15, 23, 42, 0.05);
  border-radius: 8px;
  border: 1px solid var(--border-color);
  position: relative;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

.console-output {
  padding: 16px;
  overflow-y: auto;
  font-family: var(--font-code);
  font-size: 0.85rem;
  line-height: 1.6;
  flex: 1;
  display: block;
  scroll-behavior: smooth;
}

.terminal-line {
  word-break: break-all;
  white-space: pre-wrap;
}

.terminal-line.system-msg {
  color: var(--text-muted);
}

.terminal-line.success-msg {
  color: var(--success);
}

.terminal-line.error-msg {
  color: var(--danger);
}

.terminal-line.accent-msg {
  color: var(--accent);
}

.console-actions {
  padding: 0 20px 20px 20px;
  display: flex;
  justify-content: flex-end;
}

/* Results Panel Layout (Lower Section) */
.results-panel {
  display: flex;
  flex-direction: column;
}

.results-header {
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap;
  gap: 15px;
}

.results-filter input {
  background: rgba(10, 11, 18, 0.8);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  color: var(--text-primary);
  font-family: var(--font-ui);
  font-size: 0.85rem;
  padding: 8px 16px;
  width: 280px;
  outline: none;
  transition: all 0.3s ease;
}

.results-filter input:focus {
  border-color: var(--accent);
  width: 320px;
  box-shadow: 0 0 8px var(--accent-glow);
}

/* Results Statistics Row */
.results-stats {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 16px;
  padding: 20px 24px;
  background: rgba(255, 255, 255, 0.02);
  border-bottom: 1px solid var(--border-color);
}

@media (max-width: 768px) {
  .results-stats {
    grid-template-columns: 1fr 1fr;
  }
}

.stat-card {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 10px;
  padding: 12px 18px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.stat-title {
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  color: var(--text-secondary);
  letter-spacing: 0.5px;
}

.stat-value {
  font-size: 1.4rem;
  font-weight: 700;
}

.text-success {
  color: var(--success) !important;
}

.text-danger {
  color: var(--danger) !important;
}

.text-accent {
  color: var(--accent) !important;
}

/* Results Table UI */
.table-wrapper {
  position: relative;
  overflow-x: auto;
  max-height: 450px;
  overflow-y: auto;
}

table {
  width: 100%;
  min-width: 1000px;
  table-layout: auto;
  border-collapse: separate;
  border-spacing: 0;
  font-size: 0.9rem;
  color: var(--text-primary);
}

th, td {
  padding: 16px 18px;
  border-bottom: 1px solid var(--border-color);
  vertical-align: top;
  word-break: break-word;
  white-space: normal;
  overflow: hidden;
  text-overflow: ellipsis;
  text-align: center;
}

th .column-title {
  display: block;
  width: 100%;
  margin: 0 auto;
}
th {
  display: table-cell;
  vertical-align: top;
  text-align: center;
  white-space: nowrap;
  background: rgba(10, 11, 18, 0.4);
  color: var(--text-secondary);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  font-size: 0.75rem;
  cursor: pointer;
  user-select: none;
  position: sticky;
  top: 0;
  z-index: 10;
}

th:hover {
  background: rgba(0, 242, 254, 0.05);
  color: var(--text-primary);
}

.column-title {
  display: inline-block;
  text-align: center;
  width: 100%;
  line-height: 1.2;
}

.column-subtitle {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-secondary);
  display: block;
  margin-top: 2px;
}

th:nth-child(1), td:nth-child(1) { min-width: 160px; }
th:nth-child(2), td:nth-child(2) { min-width: 120px; }
th:nth-child(3), td:nth-child(3) { min-width: 240px; }
th:nth-child(4), td:nth-child(4) { min-width: 180px; }
th:nth-child(5), td:nth-child(5) { min-width: 280px; }
th:nth-child(5), td:nth-child(5), .manufacturer-cell {
  white-space: normal !important;
  overflow-wrap: anywhere !important;
  word-break: break-word !important;
}
th:nth-child(6), td:nth-child(6) { min-width: 220px; }
th:nth-child(7), td:nth-child(7) { min-width: 140px; }
th:nth-child(8), td:nth-child(8) { min-width: 200px; }
th:nth-child(9), td:nth-child(9) { min-width: 140px; }
th:nth-child(10), td:nth-child(10) { min-width: 200px; }
th:nth-child(11), td:nth-child(11) { min-width: 110px; }
th:nth-child(12), td:nth-child(12) { min-width: 140px; }
th:nth-child(13), td:nth-child(13) { min-width: 140px; }
th:nth-child(14), td:nth-child(14) { min-width: 300px; }

/* Sub-rede (CIDR) — valor completo numa linha, ex.: 172.20.100.0/24 */
td.cell-subnet,
th.col-subnet,
#results-table td:nth-child(9),
#results-table th:nth-child(9),
#idle-table td:nth-child(7),
#idle-table th:nth-child(7) {
  white-space: nowrap;
  word-break: keep-all;
  overflow-wrap: normal;
  min-width: 9.75rem;
  max-width: none;
}

tbody tr {
  transition: background-color 0.2s ease;
}

tbody tr:hover {
  background-color: rgba(255, 255, 255, 0.02);
}

.empty-row {
  text-align: center;
  color: var(--text-muted);
  font-style: italic;
}

.empty-row td {
  padding: 40px 20px;
}

.highlight-row {
  animation: highlightFlash 2.5s ease-in-out;
}

@keyframes highlightFlash {
  0% { background-color: rgba(255,255,0,0.12); }
  50% { background-color: rgba(255,255,0,0.04); }
  100% { background-color: transparent; }
}

/* Port tags in table */
.port-badge {
  display: inline-flex;
  align-items: center;
  background: rgba(255, 255, 255, 0.04);
  border: 1px solid var(--border-color);
  border-radius: 4px;
  padding: 4px 8px;
  margin: 4px 4px 0 0;
  font-family: var(--font-code);
  font-size: 0.75rem;
  transition: transform 0.2s ease, background-color 0.2s ease;
  white-space: nowrap;
}

.port-badge:hover {
