/* Footer UI */
.app-footer {
  margin-top: auto;
  padding: 24px 0;
  text-align: center;
  font-size: 0.75rem;
  color: var(--text-muted);
  border-top: 1px solid var(--border-color);
}

.app-footer-credit {
  margin: 0;
}

.app-footer-credit-inner {
  position: relative;
  display: inline-block;
  padding: 4px 8px;
  isolation: isolate;
}

.app-footer-text {
  position: relative;
  z-index: 1;
  display: inline-block;
  animation: footer-text-consume 5.5s ease-in-out infinite;
}

.app-footer-author {
  color: #94a3b8;
  font-weight: 600;
}

.app-footer-consume-ball {
  position: absolute;
  top: 50%;
  left: 0;
  width: 28px;
  height: 28px;
  margin-top: -14px;
  margin-left: -14px;
  border-radius: 50%;
  background: radial-gradient(circle at 35% 35%, #67e8f9 0%, #0ea5e9 45%, #0369a1 100%);
  box-shadow:
    0 0 16px rgba(14, 165, 233, 0.75),
    0 0 32px rgba(56, 189, 248, 0.35);
  z-index: 2;
  pointer-events: none;
  animation: footer-ball-consume 5.5s ease-in-out infinite;
  opacity: 0;
}

@keyframes footer-ball-consume {
  0%, 8% {
    left: 0;
    opacity: 0;
    transform: scale(0.35);
  }
  14% {
    opacity: 1;
    transform: scale(1);
  }
  48% {
    left: 100%;
    opacity: 1;
    transform: scale(1.15);
  }
  56% {
    left: 100%;
    opacity: 0.85;
    transform: scale(1.25);
  }
  72% {
    left: 100%;
    opacity: 0;
    transform: scale(0.4);
  }
  88%, 100% {
    left: 0;
    opacity: 0;
    transform: scale(0.35);
  }
}

@keyframes footer-text-consume {
  0%, 12%, 78%, 100% {
    opacity: 1;
    filter: blur(0);
    transform: scale(1);
  }
  38%, 58% {
    opacity: 0.12;
    filter: blur(1.2px);
    transform: scale(0.985);
  }
}

@media (prefers-reduced-motion: reduce) {
  .app-footer-text,
  .app-footer-consume-ball {
    animation: none;
  }

  .app-footer-consume-ball {
    display: none;
  }
}

/* Animations and States */
.pulse {
  box-shadow: 0 0 0 0 var(--accent-glow);
  animation: pulse-glow 1.6s infinite cubic-bezier(0.66, 0, 0, 1);
}

@keyframes pulse-glow {
  0% {
    box-shadow: 0 0 0 0 rgba(0, 242, 254, 0.4);
  }
  70% {
    box-shadow: 0 0 0 12px rgba(0, 242, 254, 0);
  }
  100% {
    box-shadow: 0 0 0 0 rgba(0, 242, 254, 0);
  }
}

/* Progress Bar Styling */
.progress-bar-container {
  display: flex;
  align-items: center;
  gap: 16px;
  padding: 14px 24px;
  background: rgba(255, 255, 255, 0.02);
  border-bottom: 1px solid var(--border-color);
  animation: barFadeIn 0.3s ease;
}

.progress-track {
  flex: 1;
  height: 6px;
  background: rgba(5, 7, 10, 0.6);
  border-radius: 4px;
  overflow: hidden;
  border: 1px solid var(--border-color);
}

.progress-fill {
  height: 100%;
  width: 0%;
  background: var(--primary-grad);
  border-radius: 4px;
  box-shadow: 0 0 10px var(--accent-glow);
  transition: width 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.progress-percentage {
  font-family: var(--font-code);
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--accent);
}

@keyframes barFadeIn {
  from { opacity: 0; transform: translateY(-8px); }
  to { opacity: 1; transform: translateY(0); }
}

/* Idle hosts panel */
.idle-panel {
