}

.idle-chip-recovered .idle-chip-value {
  color: #34d399;
}

.idle-chip-group-recovered {
  display: inline-flex;
  align-items: stretch;
  gap: 6px;
}

.idle-chip-group-recovered .idle-chip {
  min-width: 5rem;
}

.idle-recovered-toggle {
  align-self: stretch;
  white-space: nowrap;
}

.idle-recovered-panel {
  margin: 0 0 16px;
  padding: 14px 16px;
  border-radius: 12px;
  border: 1px solid rgba(52, 211, 153, 0.22);
  background: rgba(52, 211, 153, 0.04);
}

.idle-recovered-head {
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: 8px 16px;
  margin-bottom: 10px;
}

.idle-recovered-head h3 {
  margin: 0;
  font-size: 0.95rem;
  font-weight: 600;
}

.idle-recovered-hint {
  margin: 0;
  font-size: 0.78rem;
  color: var(--text-secondary);
}

.idle-recovered-table-wrap {
  max-height: 280px;
