}

.idle-chip-history .idle-chip-value {
  color: #ffffff;
}

.idle-chip-scans .idle-chip-value {
  color: #7dd3fc;
}

.idle-chip-threshold .idle-chip-value {
  color: var(--accent);
  font-size: 0.95rem;
}

.idle-stat-pulse {
  animation: idleStatPulse 0.9s ease;
}

.idle-stat-pulse.idle-chip {
  transform: translateY(-1px);
}

@keyframes idleStatPulse {
  0%, 100% { box-shadow: none; border-color: var(--border-color); }
  40% { box-shadow: 0 0 20px var(--accent-glow); border-color: var(--accent); }
}

.idle-status-error {
  border-color: rgba(239, 68, 68, 0.35);
  color: #fca5a5;
}

.idle-status-flash {
  border-color: var(--accent);
  box-shadow: 0 0 0 1px var(--accent-glow);
}

.idle-stats {
  grid-template-columns: repeat(4, 1fr);
}

@media (max-width: 900px) {
  .idle-controls {
    width: 100%;
