}

.loop-banner.warn {
  background: rgba(255, 180, 50, 0.12);
  border-color: rgba(255, 180, 50, 0.3);
  color: #ffe4a8;
}

.loop-table-panel {
  min-height: 0;
}

.loop-table-wrap {
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  background: rgba(0, 0, 0, 0.2);
}

.loop-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.8rem;
}

.loop-table th,
.loop-table td {
  padding: 10px 12px;
  text-align: left;
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  vertical-align: top;
}

.loop-table th {
  position: sticky;
  top: 0;
  background: rgba(12, 16, 22, 0.98);
