}

.loop-switch-item:hover,
.loop-alert-item:hover {
  border-color: rgba(239, 83, 80, 0.28);
}

.loop-switch-item strong,
.loop-alert-item strong {
  display: block;
  font-size: 0.9rem;
}

.loop-switch-item span,
.loop-alert-item span {
  display: block;
  color: var(--text-secondary);
  font-size: 0.76rem;
  margin-top: 2px;
}

.loop-evidence {
  color: var(--text-secondary);
  font-size: 0.74rem;
  max-width: 260px;
  line-height: 1.4;
}

/* ——— Oracle / Login AD ——— */
.oracle-card {
