  flex-direction: column;
  flex: 0 0 auto;
  min-height: 0;
  min-width: 0;
  overflow: visible;
}

.autotest-section-head {
  flex-shrink: 0;
  padding: 4px 6px 10px;
  border-bottom: 1px solid rgba(148, 163, 184, 0.14);
}

.autotest-section-title {
  margin: 0;
  font-size: 0.94rem;
  font-weight: 700;
  color: #e2e8f0;
  letter-spacing: 0.02em;
}

.autotest-section-sub {
  margin: 4px 0 0;
  font-size: 0.76rem;
  color: #64748b;
  line-height: 1.4;
}

.autotest-status-dock {
  flex-shrink: 0;
  width: 100%;
  margin-top: auto;
  border-top: 1px solid rgba(148, 163, 184, 0.16);
  background: linear-gradient(180deg, transparent 0%, rgba(6, 10, 20, 0.92) 40%);
  backdrop-filter: blur(10px);
  z-index: 3;
}

.autotest-status-dock .autotest-banner-footer {
  align-self: stretch;
  margin: 0;
  max-width: none;
  width: 100%;
  border-radius: 0;
  border-left: none;
  border-right: none;
  border-bottom: none;
  text-align: left;
  box-shadow: none;
  position: static;
}

.autotest-banner-footer {
  flex-shrink: 0;
  margin-top: auto;
  width: 100%;
  max-width: none;
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
  transition:
    opacity 0.5s ease,
    transform 0.5s ease,
    visibility 0.5s ease,
    box-shadow 0.5s ease;
}

.autotest-banner-footer.autotest-banner-visible.autotest-banner-ok {
  animation: autotest-banner-glow-ok 4s ease-in-out infinite;
}

.autotest-banner-footer.autotest-banner-visible.autotest-banner-warn {
  animation: autotest-banner-glow-warn 4s ease-in-out infinite;
}

.autotest-banner-footer.autotest-banner-visible.autotest-banner-fail {
  animation: autotest-banner-glow-fail 4s ease-in-out infinite;
}

.autotest-banner-footer.autotest-banner-hidden {
  opacity: 0;
  visibility: hidden;
  transform: translateY(10px);
  pointer-events: none;
  animation: none;
}

.autotest-status-dock .autotest-banner-footer.autotest-banner-hidden {
  opacity: 1;
  visibility: visible;
  transform: none;
  pointer-events: auto;
}

@keyframes autotest-banner-glow-ok {
  0%, 100% { box-shadow: inset 0 1px 0 rgba(34, 197, 94, 0.08); }
  50% { box-shadow: inset 0 1px 0 rgba(34, 197, 94, 0.2), 0 -2px 20px rgba(34, 197, 94, 0.1); }
}

@keyframes autotest-banner-glow-warn {
  0%, 100% { box-shadow: inset 0 1px 0 rgba(251, 191, 36, 0.08); }
  50% { box-shadow: inset 0 1px 0 rgba(251, 191, 36, 0.22), 0 -2px 20px rgba(251, 191, 36, 0.12); }
}

@keyframes autotest-banner-glow-fail {
  0%, 100% { box-shadow: inset 0 1px 0 rgba(239, 83, 80, 0.1); }
  50% { box-shadow: inset 0 1px 0 rgba(239, 83, 80, 0.28), 0 -2px 22px rgba(239, 83, 80, 0.14); }
}

.autotest-banner-ok {
  background: rgba(34, 197, 94, 0.1);
  border-color: rgba(34, 197, 94, 0.35);
  color: #bbf7d0;
}

.autotest-banner-warn {
  background: rgba(251, 191, 36, 0.1);
  border-color: rgba(251, 191, 36, 0.35);
  color: #fde68a;
}

.autotest-banner-running {
  background: linear-gradient(135deg, rgba(79, 172, 254, 0.14) 0%, rgba(0, 242, 254, 0.08) 100%);
