  visibility: visible;
}

@keyframes autotest-running-glow {
  0%, 100% {
    box-shadow: inset 0 1px 0 rgba(79, 172, 254, 0.12);
  }
  50% {
    box-shadow: inset 0 1px 0 rgba(0, 242, 254, 0.28), 0 -2px 24px rgba(79, 172, 254, 0.18);
  }
}

.autotest-eng-banner-running {
