}

.ad-modal-backdrop .inventory-table-wrap::-webkit-scrollbar {
  height: 10px;
  width: 10px;
}

.ad-modal-backdrop .inventory-table-wrap::-webkit-scrollbar-track {
  background: rgba(15, 23, 42, 0.45);
  border-radius: 8px;
}

.ad-modal-backdrop .inventory-table-wrap::-webkit-scrollbar-thumb {
  background: rgba(6, 182, 212, 0.45);
  border-radius: 8px;
  border: 2px solid rgba(15, 23, 42, 0.45);
}

.ad-modal-backdrop .inventory-table-wrap::-webkit-scrollbar-thumb:hover {
  background: rgba(6, 182, 212, 0.65);
}

/* ——— Loop Rede: altura máxima ——— */
html.loop-modal-open,
body.loop-modal-open {
  overflow: hidden !important;
}

.loop-modal-backdrop .loop-themed-modal.ad-modal {
  max-height: min(calc(100vh - 40px), 940px);
}

.loop-modal-backdrop .loop-themed-modal .loop-scroll-panel {
  flex: 1 1 auto;
  min-height: 0 !important;
  overflow-x: hidden;
  overflow-y: auto;
  overscroll-behavior: contain;
}

/**
 * Canon Design System — Fases 1–3 (camada aditiva sobre style.css)
 * Tokens, dashboard, tabelas, modais, temas claro/escuro e acessibilidade.
 */

:root {
  /* Escala de espaçamento */
  --canon-space-1: 4px;
  --canon-space-2: 8px;
  --canon-space-3: 12px;
  --canon-space-4: 16px;
  --canon-space-5: 20px;
  --canon-space-6: 24px;
  --canon-space-8: 32px;

  /* Raio e sombra */
  --canon-radius-sm: 8px;
  --canon-radius-md: 12px;
  --canon-radius-lg: 16px;
  --canon-shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.25);
  --canon-shadow-md: 0 8px 24px rgba(0, 0, 0, 0.35);
  --canon-shadow-glow: 0 0 0 1px var(--border-glow), 0 8px 32px rgba(0, 242, 254, 0.08);

  /* Tipografia */
  --canon-text-xs: 0.72rem;
  --canon-text-sm: 0.82rem;
  --canon-text-md: 0.92rem;
  --canon-text-lg: 1.05rem;
  --canon-text-xl: 1.35rem;

  /* Transições */
  --canon-ease: cubic-bezier(0.4, 0, 0.2, 1);
  --canon-duration: 0.22s;

  /* Superfícies enterprise */
  --canon-surface-1: rgba(255, 255, 255, 0.03);
  --canon-surface-2: rgba(255, 255, 255, 0.06);
  --canon-surface-3: rgba(255, 255, 255, 0.09);
  --canon-border-subtle: rgba(255, 255, 255, 0.08);
  --canon-border-strong: rgba(0, 242, 254, 0.22);
  --canon-table-head-bg: rgba(12, 16, 28, 0.96);
  --canon-input-bg: rgba(10, 11, 18, 0.85);
  --canon-console-bg: #05070a;
}

/* ——— Foco acessível (não remove outline existente em todos os casos) ——— */
:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

/* ——— Painéis ——— */
.glass-panel.canon-ds-panel {
  box-shadow: var(--canon-shadow-md), var(--canon-shadow-glow);
  border-color: var(--canon-border-subtle);
  transition: box-shadow var(--canon-duration) var(--canon-ease),
    border-color var(--canon-duration) var(--canon-ease);
}

.glass-panel.canon-ds-panel:hover {
  border-color: var(--canon-border-strong);
}

.panel-header.canon-ds-panel-header {
  border-bottom: 1px solid var(--canon-border-subtle);
  padding-bottom: var(--canon-space-3);
}

.panel-header.canon-ds-panel-header h2 {
  letter-spacing: -0.02em;
  font-weight: 600;
}

/* ——— Stat cards (dashboard) ——— */
.stat-card.canon-ds-stat {
  position: relative;
  overflow: hidden;
  transition: transform var(--canon-duration) var(--canon-ease),
    box-shadow var(--canon-duration) var(--canon-ease),
    border-color var(--canon-duration) var(--canon-ease);
}

.stat-card.canon-ds-stat::before {
  content: '';
  position: absolute;
  inset: 0 auto 0 0;
  width: 3px;
  background: var(--primary-grad);
  opacity: 0.85;
  border-radius: 3px 0 0 3px;
}

.stat-card.canon-ds-stat:hover {
  transform: translateY(-2px);
  box-shadow: var(--canon-shadow-sm);
  border-color: var(--canon-border-strong);
}

.stat-card.canon-ds-stat.active-card::before {
  background: linear-gradient(180deg, var(--success), #059669);
}

.stat-card.canon-ds-stat.inactive-card::before {
  background: linear-gradient(180deg, var(--danger), #b91c1c);
}

.stat-card.canon-ds-stat.time-card::before {
  background: var(--primary-grad);
}

.stat-card.canon-ds-stat .stat-title {
  font-size: var(--canon-text-xs);
  letter-spacing: 0.06em;
}

.stat-card.canon-ds-stat .stat-value {
  font-variant-numeric: tabular-nums;
  letter-spacing: -0.02em;
}

/* ——— Busca / filtro ——— */
.results-filter.canon-ds-search-wrap {
  position: relative;
  display: flex;
  align-items: center;
  gap: var(--canon-space-2);
}

.results-filter.canon-ds-search-wrap .canon-ds-search-icon {
  position: absolute;
  left: 14px;
  top: 50%;
  transform: translateY(-50%);
  color: var(--text-muted);
  font-size: 0.9rem;
  pointer-events: none;
  z-index: 1;
}

.results-filter.canon-ds-search-wrap input {
  padding-left: 38px !important;
  min-width: 280px;
}

.results-filter.canon-ds-search-wrap input::placeholder {
  color: var(--text-muted);
  opacity: 0.9;
}

/* ——— Tabelas profissionais ——— */
.table-wrapper.canon-ds-table-wrap {
  border-top: 1px solid var(--canon-border-subtle);
  scrollbar-width: thin;
  scrollbar-color: rgba(0, 242, 254, 0.45) rgba(15, 23, 42, 0.5);
}

.table-wrapper.canon-ds-table-wrap::-webkit-scrollbar {
  height: 10px;
  width: 10px;
}

.table-wrapper.canon-ds-table-wrap::-webkit-scrollbar-thumb {
  background: rgba(0, 242, 254, 0.4);
  border-radius: 8px;
}

table.canon-ds-table tbody tr {
  transition: background-color var(--canon-duration) var(--canon-ease);
}

table.canon-ds-table tbody tr:nth-child(even):not(.empty-row) {
  background: var(--canon-surface-1);
}

table.canon-ds-table tbody tr:hover:not(.empty-row) {
  background: rgba(0, 242, 254, 0.06);
}

table.canon-ds-table th.canon-ds-sorted-asc,
table.canon-ds-table th.canon-ds-sorted-desc {
  color: var(--accent);
  background: rgba(0, 242, 254, 0.08);
}

table.canon-ds-table th.canon-ds-sorted-asc::after {
  content: ' ▲';
  font-size: 0.65em;
  opacity: 0.9;
}

table.canon-ds-table th.canon-ds-sorted-desc::after {
  content: ' ▼';
  font-size: 0.65em;
  opacity: 0.9;
}

table.canon-ds-table tr.empty-row td {
  padding: var(--canon-space-8) var(--canon-space-4);
  color: var(--text-muted);
  font-size: var(--canon-text-sm);
  font-style: italic;
}

/* ——— Rodapé paginação ——— */
.canon-ds-table-footer {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: var(--canon-space-3);
  padding: var(--canon-space-3) var(--canon-space-6);
  background: var(--canon-surface-1);
  border-top: 1px solid var(--canon-border-subtle);
}

.canon-ds-table-meta {
  font-size: var(--canon-text-sm);
  color: var(--text-secondary);
  font-variant-numeric: tabular-nums;
}

.canon-ds-table-pagination {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: var(--canon-space-2);
}

.canon-ds-page-size-label {
  display: inline-flex;
  align-items: center;
  gap: var(--canon-space-2);
  font-size: var(--canon-text-xs);
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  font-weight: 600;
}

.canon-ds-select {
  background: var(--canon-input-bg);
  border: 1px solid var(--canon-border-subtle);
  border-radius: var(--canon-radius-sm);
  color: var(--text-primary);
  font-family: var(--font-ui);
  font-size: var(--canon-text-sm);
  padding: 6px 10px;
  cursor: pointer;
  transition: border-color var(--canon-duration) var(--canon-ease);
}

.canon-ds-select:hover,
.canon-ds-select:focus {
  border-color: var(--accent);
}

.canon-ds-page-indicator {
  font-size: var(--canon-text-sm);
  color: var(--text-primary);
  font-weight: 600;
  min-width: 4.5rem;
  text-align: center;
  font-variant-numeric: tabular-nums;
}

/* ——— Header toolbar ——— */
.header-status.canon-ds-header-actions {
  gap: var(--canon-space-2);
}

.header-status.canon-ds-header-actions .btn {
  transition: transform var(--canon-duration) var(--canon-ease),
    box-shadow var(--canon-duration) var(--canon-ease);
}

.header-status.canon-ds-header-actions .btn:hover:not(:disabled) {
  transform: translateY(-1px);
}

/* ——— Badges de conexão ——— */
.badge.canon-ds-badge {
  font-variant-numeric: tabular-nums;
  letter-spacing: 0.03em;
}

/* ——— Config panel ——— */
.config-panel.canon-ds-config .form-group label {
  font-size: var(--canon-text-sm);
  font-weight: 600;
  color: var(--text-secondary);
}

/* ——— Fase 2: Modais enterprise ——— */
.ad-modal-backdrop:has(.canon-ds-modal) {
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
}

.ad-modal.canon-ds-modal {
  box-shadow: var(--canon-shadow-md), 0 24px 80px rgba(0, 0, 0, 0.55);
  border: 1px solid var(--canon-border-subtle);
  transition: box-shadow var(--canon-duration) var(--canon-ease),
    border-color var(--canon-duration) var(--canon-ease);
}

.ad-modal.canon-ds-modal .ad-modal-header {
  border-bottom: 1px solid var(--canon-border-subtle);
}

.ad-modal.canon-ds-modal .ad-modal-header h2 {
  letter-spacing: -0.02em;
  font-weight: 600;
}

.ad-modal.canon-ds-modal .ad-modal-subtitle {
  font-size: var(--canon-text-sm);
  line-height: 1.45;
}

.ad-modal.canon-ds-modal .ad-modal-close {
  transition: color var(--canon-duration) var(--canon-ease),
    background var(--canon-duration) var(--canon-ease),
    transform var(--canon-duration) var(--canon-ease);
}

.ad-modal.canon-ds-modal .ad-modal-close:hover {
  transform: scale(1.05);
}

.ad-modal.canon-ds-modal .ad-modal-tabs.modal-sticky-tabs {
  border-bottom: 1px solid var(--canon-border-subtle);
  gap: var(--canon-space-1);
}

.ad-modal.canon-ds-modal .ad-tab {
  transition: color var(--canon-duration) var(--canon-ease),
    background var(--canon-duration) var(--canon-ease);
  font-size: var(--canon-text-sm);
}

.ad-modal.canon-ds-modal .ad-tab.active {
  box-shadow: inset 0 -2px 0 var(--accent);
}

.ad-modal.canon-ds-modal .ad-toolbar-card {
  border-color: var(--canon-border-subtle);
  background: var(--canon-surface-1);
  border-radius: var(--canon-radius-md);
}

.ad-modal.canon-ds-modal .ad-field-label {
  font-size: var(--canon-text-xs);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  font-weight: 600;
}

.ad-modal.canon-ds-modal .ad-input,
.ad-modal.canon-ds-modal .ad-select {
  transition: border-color var(--canon-duration) var(--canon-ease),
    box-shadow var(--canon-duration) var(--canon-ease);
}

.ad-modal.canon-ds-modal .ad-input:focus,
.ad-modal.canon-ds-modal .ad-select:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 2px rgba(0, 242, 254, 0.12);
}

.ad-modal.canon-ds-modal .ad-status-bar {
  border-radius: var(--canon-radius-sm);
  font-size: var(--canon-text-sm);
}

.ad-modal.canon-ds-modal .canon-login-form .ad-input {
  font-size: var(--canon-text-md);
}

/* Tabelas dentro de modais */
.ad-modal.canon-ds-modal .loop-table-wrap,
.ad-modal.canon-ds-modal .inventory-table-wrap,
.ad-modal.canon-ds-modal .ad-scroll-panel {
  scrollbar-width: thin;
  scrollbar-color: rgba(0, 242, 254, 0.4) rgba(15, 23, 42, 0.5);
}

.ad-modal.canon-ds-modal table tbody tr {
  transition: background-color var(--canon-duration) var(--canon-ease);
}

.ad-modal.canon-ds-modal table tbody tr:nth-child(even):not(.empty-row) {
  background: var(--canon-surface-1);
}

.ad-modal.canon-ds-modal table tbody tr:hover:not(.empty-row) {
  background: rgba(0, 242, 254, 0.05);
}

/* Stat cards inventário */
.inventory-stat-card.canon-ds-stat-card {
  transition: transform var(--canon-duration) var(--canon-ease),
    border-color var(--canon-duration) var(--canon-ease),
    box-shadow var(--canon-duration) var(--canon-ease);
}

.inventory-stat-card.canon-ds-stat-card:hover {
  transform: translateY(-2px);
  box-shadow: var(--canon-shadow-sm);
  border-color: var(--canon-border-strong);
}

.inventory-stat-card.canon-ds-stat-card strong {
  font-variant-numeric: tabular-nums;
}

/* Ociosos — painel alinhado ao dashboard */
.idle-panel .panel-header.canon-ds-panel-header {
  border-bottom: 1px solid var(--canon-border-subtle);
  padding-bottom: var(--canon-space-3);
}

.idle-recovered-table-wrap.canon-ds-table-wrap {
  border: 1px solid var(--canon-border-subtle);
  border-radius: var(--canon-radius-sm);
}

#idle-recovered-table.canon-ds-table tbody tr:nth-child(even):not(.empty-row) {
  background: var(--canon-surface-1);
}

#idle-recovered-table.canon-ds-table tbody tr:hover:not(.empty-row) {
  background: rgba(0, 242, 254, 0.06);
}

/* Mapa por Ala — scroll e tabela alinhados ao dashboard */
.ala-panel.canon-ds-panel .ala-groups {
  margin: var(--canon-space-3) 0;
}

.ala-group-card.canon-ds-ala-card {
  transition: transform var(--canon-duration) var(--canon-ease),
    border-color var(--canon-duration) var(--canon-ease),
    box-shadow var(--canon-duration) var(--canon-ease);
}

.ala-group-card.canon-ds-ala-card:hover {
  transform: translateY(-2px);
  box-shadow: var(--canon-shadow-sm);
  border-color: var(--canon-border-strong);
}

.ala-group-card.canon-ds-ala-card span {
  font-variant-numeric: tabular-nums;
}

.table-wrapper.ala-table-wrap.canon-ds-table-wrap {
  max-height: min(520px, 60vh);
  border-top: 1px solid var(--canon-border-subtle);
}

.table-wrapper.ala-table-wrap.canon-ds-table-wrap table.canon-ds-table thead th {
  position: sticky;
  top: 0;
  z-index: 2;
  background: var(--canon-table-head-bg);
  backdrop-filter: blur(6px);
  box-shadow: 0 1px 0 var(--canon-border-subtle);
}

.table-wrapper.canon-ds-table-wrap:not(.ala-table-wrap) table.canon-ds-table thead th {
  position: sticky;
  top: 0;
  z-index: 2;
  background: var(--canon-table-head-bg);
  backdrop-filter: blur(6px);
  box-shadow: 0 1px 0 var(--canon-border-subtle);
}

/* ——— Fase 3: Toggle tema + modo claro ——— */
html {
  color-scheme: dark;
}

html[data-theme="light"] {
  color-scheme: light;
}

body,
.glass-panel,
.ad-modal.canon-ds-modal,
.badge,
.btn {
  transition: background-color var(--canon-duration) var(--canon-ease),
    color var(--canon-duration) var(--canon-ease),
    border-color var(--canon-duration) var(--canon-ease),
    box-shadow var(--canon-duration) var(--canon-ease);
}

.canon-ds-theme-switch {
  display: inline-flex;
  align-items: center;
  gap: var(--canon-space-2);
  cursor: pointer;
  user-select: none;
  padding: 2px 4px;
  border-radius: var(--canon-radius-sm);
}

.canon-ds-theme-switch-input {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.canon-ds-theme-switch-icon {
  font-size: 0.85rem;
  line-height: 1;
  color: var(--text-muted);
  transition: color var(--canon-duration) var(--canon-ease);
}

.canon-ds-theme-switch-track {
  position: relative;
  width: 44px;
  height: 24px;
  border-radius: 999px;
  background: var(--canon-surface-2);
  border: 1px solid var(--canon-border-subtle);
  transition: background var(--canon-duration) var(--canon-ease),
    border-color var(--canon-duration) var(--canon-ease),
    box-shadow var(--canon-duration) var(--canon-ease);
}

.canon-ds-theme-switch-thumb {
  position: absolute;
  top: 2px;
  left: 2px;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  background: linear-gradient(145deg, #e2e8f0, #cbd5e1);
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.25);
  transition: transform var(--canon-duration) var(--canon-ease),
    background var(--canon-duration) var(--canon-ease);
}

.canon-ds-theme-switch-input:checked + .canon-ds-theme-switch-track {
  background: rgba(8, 145, 178, 0.22);
  border-color: rgba(8, 145, 178, 0.45);
  box-shadow: 0 0 0 1px rgba(8, 145, 178, 0.15);
}

.canon-ds-theme-switch-input:checked + .canon-ds-theme-switch-track .canon-ds-theme-switch-thumb {
  transform: translateX(20px);
  background: linear-gradient(145deg, #fde68a, #fbbf24);
}

.canon-ds-theme-switch-input:focus-visible + .canon-ds-theme-switch-track {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.canon-ds-theme-switch:hover .canon-ds-theme-switch-track {
  border-color: var(--canon-border-strong);
}

.canon-ds-theme-switch:has(.canon-ds-theme-switch-input:not(:checked)) .canon-ds-theme-switch-icon-dark,
.canon-ds-theme-switch:has(.canon-ds-theme-switch-input:checked) .canon-ds-theme-switch-icon-light {
  color: var(--accent);
}

[data-theme="light"] .canon-ds-theme-switch-track {
  background: rgba(15, 23, 42, 0.08);
}

[data-theme="light"] {
  --bg-main: #eef2f7;
  --bg-panel: rgba(255, 255, 255, 0.94);
  --bg-console: var(--canon-console-bg);
  --border-color: rgba(15, 23, 42, 0.1);
  --border-glow: rgba(8, 145, 178, 0.22);
  --text-primary: #0f172a;
  --text-secondary: #475569;
  --text-muted: #64748b;
  --accent: #0891b2;
  --accent-secondary: #0284c7;
  --accent-glow: rgba(8, 145, 178, 0.18);
  --panel-shadow: 0 8px 32px rgba(15, 23, 42, 0.08);
  --canon-surface-1: rgba(15, 23, 42, 0.025);
  --canon-surface-2: rgba(15, 23, 42, 0.05);
  --canon-surface-3: rgba(15, 23, 42, 0.08);
  --canon-border-subtle: rgba(15, 23, 42, 0.1);
  --canon-border-strong: rgba(8, 145, 178, 0.32);
  --canon-shadow-sm: 0 2px 8px rgba(15, 23, 42, 0.08);
  --canon-shadow-md: 0 8px 24px rgba(15, 23, 42, 0.1);
  --canon-shadow-glow: 0 0 0 1px var(--border-glow), 0 8px 32px rgba(8, 145, 178, 0.06);
  --canon-table-head-bg: rgba(248, 250, 252, 0.96);
  --canon-input-bg: rgba(255, 255, 255, 0.95);
}

[data-theme="light"] .glass-bg-decor {
  opacity: 0.06;
}

[data-theme="light"] .glass-panel:hover {
  border-color: rgba(8, 145, 178, 0.22);
  box-shadow: 0 8px 32px rgba(8, 145, 178, 0.06), var(--panel-shadow);
}

[data-theme="light"] table.canon-ds-table tbody tr:hover:not(.empty-row),
[data-theme="light"] .ad-modal.canon-ds-modal table tbody tr:hover:not(.empty-row) {
  background: rgba(8, 145, 178, 0.06);
}

[data-theme="light"] .inventory-stat-card {
  background: rgba(8, 145, 178, 0.07);
  border-color: rgba(8, 145, 178, 0.2);
}

[data-theme="light"] .inventory-stat-card strong {
  color: #0e7490;
}

[data-theme="light"] .inventory-stat-card span {
  color: var(--text-secondary);
}

[data-theme="light"] .ala-group-card,
[data-theme="light"] .ala-config-details,
[data-theme="light"] .ala-filter-select {
  background: rgba(255, 255, 255, 0.85);
  border-color: var(--canon-border-subtle);
  color: var(--text-primary);
}

[data-theme="light"] .ala-config-editor {
  background: rgba(255, 255, 255, 0.95);
  color: var(--text-primary);
  border-color: var(--canon-border-subtle);
}

[data-theme="light"] .console-output,
[data-theme="light"] #console-output {
  background: var(--canon-console-bg) !important;
  color: #e2e8f0;
}

/* Rodapé paginação dentro de modais */
.inventory-modal-body .canon-ds-table-footer {
  margin-top: auto;
