/* NetScan Canon Platform UI — módulo aditivo */
(function () {
  async function readApiJson(res) {
    if (typeof window.readApiJson === 'function') return window.readApiJson(res);
    const ct = (res.headers.get('content-type') || '').toLowerCase();
    if (ct.includes('application/json')) return res.json().catch(() => ({}));
    throw new Error(`HTTP ${res.status}`);
  }

  function esc(s) {
    if (typeof escapeHtml === 'function') return escapeHtml(s);
    return String(s ?? '').replace(/[&<>"']/g, (c) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c]));
  }

  async function apiGet(path) {
    const res = await fetch(path);
    if (res.status === 401) {
      if (typeof window.gateCanonModalsArea === 'function') {
        window.gateCanonModalsArea({ target: 'platform' });
      }
      throw new Error('Autenticação necessária — faça login.');
    }
    const data = await readApiJson(res);
    if (!res.ok || data.ok === false) throw new Error(data.error || `HTTP ${res.status}`);
    return data;
  }

  async function apiPost(path, body) {
    const res = await fetch(path, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body || {})
    });
    if (res.status === 401) {
      if (typeof window.gateCanonModalsArea === 'function') {
        window.gateCanonModalsArea({ target: 'platform' });
      }
      throw new Error('Autenticação necessária — faça login.');
    }
    const data = await readApiJson(res);
    if (!res.ok || data.ok === false) throw new Error(data.error || `HTTP ${res.status}`);
    return data;
  }

  const STATUS_PULSE_MS = 60 * 1000;
  let statusPulseTimer = null;
  let statusPulseVisible = true;

  function stopStatusPulse() {
    if (statusPulseTimer) {
      clearTimeout(statusPulseTimer);
      statusPulseTimer = null;
    }
  }

  function applyStatusPulseVisibility(el, visible) {
    if (!el) return;
    statusPulseVisible = visible;
    el.classList.toggle('platform-status-hidden', !visible);
    el.classList.toggle('platform-status-visible', visible);
  }

  function scheduleStatusPulseToggle(el) {
    stopStatusPulse();
    if (!el) return;
    const backdrop = document.getElementById('platform-modal-backdrop');
    if (!backdrop || backdrop.classList.contains('hidden')) return;
    statusPulseTimer = setTimeout(() => {
      applyStatusPulseVisibility(el, !statusPulseVisible);
      scheduleStatusPulseToggle(el);
    }, STATUS_PULSE_MS);
  }

  function startStatusPulse(el) {
    if (!el) return;
    applyStatusPulseVisibility(el, true);
    scheduleStatusPulseToggle(el);
  }

  function setStatus(id, text, kind = '') {
    const el = document.getElementById(id);
    if (!el) return;
    el.textContent = text || '';
    const footer = id === 'platform-status' ? ' platform-status-footer' : '';
    el.className = `ad-status-bar${footer}${kind ? ` ${kind}` : ''}`;
    if (id === 'platform-status') startStatusPulse(el);
  }

  function renderJson(el, obj) {
    if (!el) return;
    el.textContent = JSON.stringify(obj, null, 2);
  }

  function switchPlatformTab(tab) {
    document.querySelectorAll('#platform-modal-backdrop .platform-tab').forEach((el) => {
      const active = el.dataset.platformTab === tab;
      el.classList.toggle('active', active);
      el.setAttribute('aria-selected', active ? 'true' : 'false');
    });
    document.querySelectorAll('#platform-modal-backdrop .platform-tab-panel').forEach((panel) => {
      panel.classList.toggle('hidden', panel.id !== `platform-tab-${tab}`);
    });
    const loaders = {
      summary: loadPlatformSummary,
      drift: loadPlatformDrift,
      correlation: loadPlatformCorrelation,
      tls: loadPlatformTls,
      nac: loadPlatformNac,
      lifecycle: loadPlatformLifecycle,
      passive: loadPlatformPassive,
      agent: loadPlatformAgent,
      config: loadPlatformConfig
    };
    if (loaders[tab]) loaders[tab]().catch((err) => setStatus('platform-status', err.message, 'error'));
  }

  async function loadPlatformSummary() {
    setStatus('platform-status', 'Carregando resumo…');
    const data = await apiGet('/api/platform/summary');
    const box = document.getElementById('platform-summary-body');
    if (!box) return;
    box.innerHTML = `
      <div class="platform-summary-grid">
        <div class="platform-stat-card"><strong>${data.scan?.total ?? 0}</strong><span>Hosts no scan</span></div>
        <div class="platform-stat-card"><strong>${data.scan?.active ?? 0}</strong><span>Ativos</span></div>
        <div class="platform-stat-card"><strong>${data.drift?.added ?? '—'}</strong><span>Drift (+)</span></div>
        <div class="platform-stat-card"><strong>${data.drift?.removed ?? '—'}</strong><span>Drift (−)</span></div>
        <div class="platform-stat-card"><strong>${data.lifecycle?.total ?? '—'}</strong><span>CMDB assets</span></div>
        <div class="platform-stat-card"><strong>${data.passive?.count ?? '—'}</strong><span>ARP passivo</span></div>
      </div>
      <p class="ad-section-hint">Site ativo: <strong>${esc(data.site?.name || 'Principal')}</strong></p>
    `;
    setStatus('platform-status', 'Resumo atualizado.', 'ok');
  }

  async function loadPlatformDrift() {
    setStatus('platform-status', 'Calculando drift…');
    const data = await apiGet('/api/platform/drift');
    renderJson(document.getElementById('platform-drift-body'), data);
    setStatus('platform-status', data.message || 'Drift carregado.', data.drift ? 'ok' : '');
  }

  async function loadPlatformCorrelation() {
    setStatus('platform-status', 'Correlacionando IP + AD + switch…');
    const data = await apiGet('/api/platform/correlation?limit=20');
    renderJson(document.getElementById('platform-correlation-body'), data);
    setStatus('platform-status', `${data.count || 0} host(s) correlacionado(s).`, 'ok');
  }

  async function loadPlatformTls() {
    setStatus('platform-status', 'Escaneando certificados TLS (443)…');
    const data = await apiPost('/api/platform/tls-scan', { maxHosts: 24, ports: [443] });
    renderJson(document.getElementById('platform-tls-body'), data);
    setStatus('platform-status', `${data.scanned || 0} teste(s) · ${data.expiringCount || 0} expirando ≤30d`, 'ok');
  }

  async function loadPlatformNac() {
    setStatus('platform-status', 'Avaliando prontidão NAC…');
    const data = await apiGet('/api/platform/nac?limit=30');
    renderJson(document.getElementById('platform-nac-body'), data);
    setStatus('platform-status', `${data.count || 0} avaliação(ões) NAC.`, 'ok');
  }

  async function loadPlatformLifecycle() {
    setStatus('platform-status', 'Carregando CMDB lifecycle…');
    const data = await apiGet('/api/platform/lifecycle');
    const box = document.getElementById('platform-lifecycle-body');
    if (!box) return;
    if (!data.assets?.length) {
      box.innerHTML = '<div class="ad-empty">Nenhum asset no CMDB — rode uma varredura para popular.</div>';
    } else {
      box.innerHTML = `<div class="platform-list">${data.assets.slice(0, 60).map((a) => `
        <div class="platform-list-item"><strong>${esc(a.ip)}</strong> · ${esc(a.state)} · ${esc(a.hostname || '—')} · ${esc(a.updatedAt || '')}</div>
      `).join('')}</div>`;
    }
    setStatus('platform-status', `${data.count || 0} asset(s) no CMDB.`, 'ok');
  }

  async function loadPlatformPassive() {
    setStatus('platform-status', 'Lendo cache ARP local…');
    const data = await apiGet('/api/platform/passive');
    renderJson(document.getElementById('platform-passive-body'), data);
    setStatus('platform-status', `${data.count || 0} entrada(s) ARP.`, 'ok');
  }

  async function loadPlatformAgent() {
    setStatus('platform-status', 'Listando reports do agente…');
    const data = await apiGet('/api/platform/agent/reports?limit=30');
    renderJson(document.getElementById('platform-agent-body'), data);
    setStatus('platform-status', `${data.count || 0} report(s) do agente.`, 'ok');
  }

  async function loadPlatformConfig() {
    setStatus('platform-status', 'Carregando configuração…');
    const data = await apiGet('/api/platform/config');
    const cfg = data.config || {};
    const feat = cfg.features || {};
    const grid = document.getElementById('platform-features-grid');
    if (grid) {
      grid.innerHTML = Object.keys(feat).map((k) => `
        <label><input type="checkbox" data-platform-feature="${esc(k)}" ${feat[k] ? 'checked' : ''}> ${esc(k)}</label>
      `).join('');
    }
    const siteSel = document.getElementById('platform-site-select');
    if (siteSel) {
      siteSel.innerHTML = (cfg.sites || []).map((s) => `<option value="${esc(s.id)}" ${s.id === cfg.activeSiteId ? 'selected' : ''}>${esc(s.name)}</option>`).join('');
    }
    const wh = document.getElementById('platform-webhook-url');
    if (wh) wh.value = cfg.webhooks?.[0]?.url || '';
    const sch = document.getElementById('platform-schedule-enabled');
    if (sch) sch.checked = !!cfg.schedule?.enabled;
    setStatus('platform-status', 'Configuração carregada.', 'ok');
  }

  async function savePlatformConfig() {
    const features = {};
    document.querySelectorAll('[data-platform-feature]').forEach((el) => {
      features[el.getAttribute('data-platform-feature')] = el.checked;
    });
    const payload = {
      features,
      activeSiteId: document.getElementById('platform-site-select')?.value || 'default',
      webhooks: [{
        url: document.getElementById('platform-webhook-url')?.value || '',
        enabled: !!document.getElementById('platform-webhook-url')?.value,
        events: ['scan.complete', 'report.daily', 'agent.report', 'loop.alert']
      }],
      schedule: {
        enabled: !!document.getElementById('platform-schedule-enabled')?.checked,
        intervalHours: Number(document.getElementById('platform-schedule-hours')?.value) || 24
      }
    };
    const res = await fetch('/api/platform/config', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    if (res.status === 401) {
      if (typeof window.gateCanonModalsArea === 'function') {
        window.gateCanonModalsArea({ target: 'platform' });
      }
      throw new Error('Autenticação necessária — faça login.');
    }
    const data = await readApiJson(res);
    if (!res.ok || data.ok === false) throw new Error(data.error || 'Falha ao salvar');
    setStatus('platform-status', 'Configuração salva.', 'ok');
  }

  function openPlatformModalDirect(tab = 'summary') {
    const backdrop = document.getElementById('platform-modal-backdrop');
    if (!backdrop) return;
    backdrop.classList.remove('hidden');
    backdrop.setAttribute('aria-hidden', 'false');
    switchPlatformTab(tab);
  }

  function closePlatformModal() {
    const backdrop = document.getElementById('platform-modal-backdrop');
    if (!backdrop) return;
    stopStatusPulse();
    backdrop.classList.add('hidden');
    backdrop.setAttribute('aria-hidden', 'true');
  }

  function openPlatformModal(tab = 'summary') {
    if (typeof window.gateCanonModalsArea === 'function') {
      window.gateCanonModalsArea({ target: 'platform', tab });
      return;
    }
    openPlatformModalDirect(tab);
  }

  window.openPlatformModalDirect = openPlatformModalDirect;

  function wirePlatformUi() {
    const openBtn = document.getElementById('platform-open-btn');
    const closeBtn = document.getElementById('platform-modal-close');
    const backdrop = document.getElementById('platform-modal-backdrop');
    if (openBtn && !openBtn.dataset.wired) {
      openBtn.dataset.wired = '1';
      openBtn.addEventListener('click', () => openPlatformModal('summary'));
    }
    if (closeBtn && !closeBtn.dataset.wired) {
      closeBtn.dataset.wired = '1';
      closeBtn.addEventListener('click', closePlatformModal);
    }
    if (backdrop && !backdrop.dataset.wired) {
      backdrop.dataset.wired = '1';
      backdrop.addEventListener('click', (e) => { if (e.target === backdrop) closePlatformModal(); });
    }
    document.querySelectorAll('#platform-modal-backdrop .platform-tab').forEach((tab) => {
      if (tab.dataset.wired) return;
      tab.dataset.wired = '1';
      tab.addEventListener('click', () => switchPlatformTab(tab.dataset.platformTab));
    });
    const saveBtn = document.getElementById('platform-save-config');
    if (saveBtn && !saveBtn.dataset.wired) {
      saveBtn.dataset.wired = '1';
      saveBtn.addEventListener('click', () => savePlatformConfig().catch((e) => alert(e.message)));
    }
    const reportBtn = document.getElementById('platform-run-report');
    if (reportBtn && !reportBtn.dataset.wired) {
      reportBtn.dataset.wired = '1';
      reportBtn.addEventListener('click', () => apiPost('/api/platform/reports/run').then((d) => {
        setStatus('platform-status', `Relatório: ${d.file || 'ok'}`, 'ok');
      }).catch((e) => alert(e.message)));
    }
    const whTest = document.getElementById('platform-webhook-test');
    if (whTest && !whTest.dataset.wired) {
      whTest.dataset.wired = '1';
      whTest.addEventListener('click', () => apiPost('/api/platform/webhooks/test').then((d) => {
        setStatus('platform-status', `Webhook: ${d.dispatched || 0} enviado(s)`, 'ok');
      }).catch((e) => alert(e.message)));
    }
  }

  window.wirePlatformUi = wirePlatformUi;
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', wirePlatformUi);
  } else {
    wirePlatformUi();
  }
})();

/* NetScan Canon Platform modal */
.platform-themed-modal.ad-modal {
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.platform-themed-modal .platform-modal-body {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-height: 0;
  overflow: hidden;
  padding-bottom: 0;
}

.platform-status-dock {
  flex-shrink: 0;
  width: 100%;
  margin-top: auto;
  border-top: 1px solid rgba(148, 163, 184, 0.16);
  background: linear-gradient(180deg, transparent 0%, rgba(6, 10, 20, 0.92) 40%);
  backdrop-filter: blur(10px);
  z-index: 3;
}

.platform-status-dock #platform-status.platform-status-footer {
  flex-shrink: 0;
  align-self: stretch;
  margin: 0;
  width: 100%;
  max-width: none;
  padding: 12px 18px 14px;
  position: static;
  text-align: left;
  box-shadow: none;
  border-radius: 0;
  border-left: none;
  border-right: none;
  border-bottom: none;
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
  transition:
    opacity 0.5s ease,
    transform 0.5s ease,
    visibility 0.5s ease,
    box-shadow 0.5s ease;
}

.platform-themed-modal #platform-status.platform-status-footer.platform-status-visible.ok {
  animation: platform-status-glow 4s ease-in-out infinite;
}

.platform-themed-modal #platform-status.platform-status-footer.platform-status-hidden {
  opacity: 0;
  visibility: hidden;
  transform: translateY(10px);
  pointer-events: none;
  animation: none;
}

.platform-status-dock #platform-status.platform-status-footer.platform-status-hidden {
  opacity: 1;
  visibility: visible;
  transform: none;
  pointer-events: auto;
  animation: platform-status-glow 4s ease-in-out infinite;
}

@keyframes platform-status-glow {
  0%, 100% {
    box-shadow: inset 0 1px 0 rgba(16, 185, 129, 0.08);
  }
  50% {
    box-shadow: inset 0 1px 0 rgba(16, 185, 129, 0.22), 0 -2px 20px rgba(16, 185, 129, 0.1);
  }
}

.platform-themed-modal .ad-tab-panel:not(.hidden) {
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

.platform-themed-modal .ad-tab.active::after {
  background: linear-gradient(90deg, #a78bfa, #6366f1);
}

.platform-themed-modal .ad-modal-icon {
  background: rgba(99, 102, 241, 0.18);
  color: #c4b5fd;
}

.platform-summary-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
  gap: 10px;
  margin-bottom: 12px;
}

.platform-stat-card {
  padding: 12px;
  border-radius: 12px;
  background: rgba(99, 102, 241, 0.08);
  border: 1px solid rgba(99, 102, 241, 0.22);
}

.platform-stat-card strong {
  display: block;
  font-size: 1.2rem;
}

.platform-stat-card span {
  font-size: 0.75rem;
  color: var(--text-secondary);
}

.platform-json-panel {
  font-family: var(--font-mono);
  font-size: 0.75rem;
  white-space: pre-wrap;
  word-break: break-word;
  max-height: 420px;
  overflow: auto;
  padding: 12px;
  border-radius: 10px;
  background: rgba(15, 23, 42, 0.55);
  border: 1px solid rgba(148, 163, 184, 0.2);
}

.platform-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.platform-list-item {
  padding: 10px 12px;
  border-radius: 10px;
  border: 1px solid rgba(148, 163, 184, 0.2);
  background: rgba(15, 23, 42, 0.45);
  font-size: 0.82rem;
}

.platform-config-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
  gap: 10px;
}

.platform-config-grid label {
  display: flex;
  flex-direction: column;
  gap: 4px;
  font-size: 0.78rem;
}

.platform-config-grid input[type="text"],
.platform-config-grid input[type="number"],
.platform-config-grid select {
  padding: 8px 10px;
  border-radius: 8px;
  border: 1px solid rgba(148, 163, 184, 0.25);
  background: rgba(15, 23, 42, 0.6);
