const mapStatus = document.getElementById('map-status');
const mapRefreshBtn = document.getElementById('map-refresh-btn');
const mapExportPngButton = document.getElementById('map-export-png');
const mapExportSvgButton = document.getElementById('map-export-svg');
const mapExportXlsxButton = document.getElementById('map-export-xlsx');
const mapContainer = document.getElementById('map-page-canvas');

let Graph = null;
let latestResults = [];
let latestGraphData = { nodes: [], links: [] };
let exportInFlight = false;

const BRAND = 'NetScan Canon';
const COLORS = {
  root: '#00f2fe',
  subnet: '#4facfe',
  host: '#38bdf8',
  dmz: '#f59e0b',
  ot: '#fb7185',
  inactive: '#64748b',
  link: 'rgba(148, 163, 184, 0.45)',
  bg: '#08090d'
};

window.addEventListener('DOMContentLoaded', () => {
  if (mapRefreshBtn) mapRefreshBtn.addEventListener('click', () => refreshTopology());
  if (mapExportPngButton) mapExportPngButton.addEventListener('click', () => exportMapImage('png'));
  if (mapExportSvgButton) mapExportSvgButton.addEventListener('click', () => exportMapImage('svg'));
  if (mapExportXlsxButton) mapExportXlsxButton.addEventListener('click', () => exportMapExcel());
  refreshTopology();
});

async function refreshTopology() {
  setStatus('Atualizando mapa...');
  try {
    const response = await fetch('/api/scan-results');
    if (response.status === 401) {
      setStatus('Login necessário — faça login na página principal (IPs ociosos) e volte ao mapa.');
      return;
    }
    if (!response.ok) throw new Error(`Falha ao obter resultados: ${response.statusText}`);
    const json = await response.json();
    latestResults = Array.isArray(json.results) ? json.results : [];
    render3DMap(latestResults);
    setStatus(`${latestResults.length} hosts · ${new Date(json.updated || Date.now()).toLocaleString('pt-BR')}`);
  } catch (err) {
    setStatus(`Erro: ${err.message}`);
    if (mapContainer) {
      mapContainer.textContent = '';
      const line = document.createElement('div');
      line.className = 'terminal-line error-msg';
      line.textContent = err.message;
      mapContainer.appendChild(line);
    }
  }
}

function setStatus(text) {
  if (mapStatus) mapStatus.textContent = text;
}

function hostColor(host) {
  if (host.status === 'Inativo') return COLORS.inactive;
  if (host.isDMZ) return COLORS.dmz;
  if (host.environment === 'OT/ICS') return COLORS.ot;
  return COLORS.host;
}

function shortLabel(host) {
  const ip = host.ip || '';
  const hn = host.hostname && host.hostname !== 'N/A' ? host.hostname.split('.')[0] : '';
  return hn ? `${ip}\n${hn}` : ip;
}

/**
 * Tree of Knowledge hierarchy in 3D:
 * Root (brand) → Subnet/VLAN branches → Host leaves
 * Positions are precomputed with wide spacing so labels don't collapse.
 */
function buildTreeGraph(results) {
  const active = results.filter(h => h && h.ip);
  const nodes = [];
  const links = [];

  const rootId = 'root:netscan-canon';
  nodes.push({
    id: rootId,
    name: BRAND,
    label: BRAND,
    level: 0,
    kind: 'root',
    color: COLORS.root,
    val: 14
  });

  const groups = {};
  active.forEach(host => {
    const key = host.vlan && host.vlan !== 'N/A'
      ? host.vlan
      : (host.subnet || 'Sub-rede');
    if (!groups[key]) groups[key] = [];
    groups[key].push(host);
  });

  const groupKeys = Object.keys(groups).sort();
  const branchCount = Math.max(groupKeys.length, 1);
  const branchRadius = Math.max(260, 90 + branchCount * 55);

  groupKeys.forEach((key, i) => {
    const branchId = `branch:${key}`;
    const angle = (2 * Math.PI * i) / branchCount - Math.PI / 2;
    const bx = Math.cos(angle) * branchRadius;
    const by = 20;
    const bz = Math.sin(angle) * branchRadius;

    nodes.push({
      id: branchId,
      name: key,
      label: key,
      level: 1,
      kind: 'branch',
      color: COLORS.subnet,
      val: 9,
      fx: bx,
      fy: by,
      fz: bz
    });

    links.push({
      source: rootId,
      target: branchId,
      distance: branchRadius * 0.85,
      kind: 'trunk'
    });

    const hosts = groups[key].slice().sort((a, b) => {
      const an = a.ip.split('.').reduce((n, o) => (n << 8) + parseInt(o, 10), 0) >>> 0;
      const bn = b.ip.split('.').reduce((n, o) => (n << 8) + parseInt(o, 10), 0) >>> 0;
      return an - bn;
    });

    const leafCount = hosts.length;
    const leafRadius = Math.max(140, 70 + leafCount * 18);
    const ringLayers = Math.ceil(leafCount / 12) || 1;

    hosts.forEach((host, j) => {
      const layer = j % ringLayers;
      const indexInLayer = Math.floor(j / ringLayers);
      const inLayerCount = Math.ceil(leafCount / ringLayers);
      const leafAngle = (2 * Math.PI * indexInLayer) / inLayerCount;
      const r = leafRadius + layer * 70;
      const ySpread = -40 - layer * 55 + (indexInLayer % 2) * 18;

      const hx = bx + Math.cos(leafAngle) * r;
      const hy = by + ySpread;
      const hz = bz + Math.sin(leafAngle) * r;

      nodes.push({
        id: host.ip,
        name: shortLabel(host),
        label: shortLabel(host),
        fullName: host.hostname || host.ip,
        level: 2,
        kind: 'host',
        color: hostColor(host),
        val: 4,
        host,
        fx: hx,
        fy: hy,
        fz: hz
      });

      links.push({
        source: branchId,
        target: host.ip,
        distance: r * 0.9,
        kind: 'leaf'
      });
    });
  });

  // Root fixed at origin
  const root = nodes.find(n => n.id === rootId);
  if (root) {
    root.fx = 0;
    root.fy = 120;
    root.fz = 0;
  }

  return { nodes, links };
}

function render3DMap(results) {
  if (!mapContainer) return;
  mapContainer.innerHTML = '';

  if (!results || results.length === 0) {
    mapContainer.innerHTML = '<div class="terminal-line system-msg">Nenhum resultado de varredura disponível para gerar o mapa.</div>';
    Graph = null;
    latestGraphData = { nodes: [], links: [] };
    return;
  }

  latestGraphData = buildTreeGraph(results);
  const { nodes, links } = latestGraphData;

  // preserveDrawingBuffer is required for PNG/screenshot capture from WebGL
  Graph = ForceGraph3D({
    rendererConfig: { preserveDrawingBuffer: true, antialias: true }
  })(mapContainer)
    .graphData({ nodes, links })
    .backgroundColor(COLORS.bg)
    .showNavInfo(false)
    .nodeRelSize(5)
    .nodeOpacity(1)
    .linkOpacity(0.55)
    .linkWidth(link => (link.kind === 'trunk' ? 1.8 : 1.1))
    .linkColor(() => COLORS.link)
    .linkDirectionalParticles(0)
    .cooldownTicks(80)
    .d3VelocityDecay(0.35)
    .nodeLabel(node => {
      if (node.kind === 'host' && node.host) {
        const h = node.host;
        return [
          h.ip,
          h.hostname && h.hostname !== 'N/A' ? h.hostname : null,
          h.deviceType || null,
          h.vlan || h.subnet || null,
          h.os && h.os !== 'N/A' ? h.os : null
        ].filter(Boolean).join('\n');
      }
      return node.label || node.name || node.id;
    })
    .onNodeClick(node => {
      if (node && node.kind === 'host' && node.id && window.opener && !window.opener.closed) {
        try {
          const rowId = `row-${String(node.id).replace(/\./g, '_')}`;
          const row = window.opener.document.getElementById(rowId);
          if (row) {
            row.scrollIntoView({ behavior: 'smooth', block: 'center' });
            row.classList.add('highlight-row');
            setTimeout(() => row.classList.remove('highlight-row'), 2500);
          }
        } catch (e) {
          console.warn('Unable to highlight opener row:', e.message);
        }
      }
    });

  // Stronger separation while keeping fixed tree scaffold
  const charge = Graph.d3Force('charge');
  if (charge) charge.strength(-180).distanceMax(500);
  const linkForce = Graph.d3Force('link');
  if (linkForce) {
    linkForce.distance(l => l.distance || 120).strength(0.35);
  }

  Graph.nodeThreeObject(node => {
    const isRoot = node.kind === 'root';
    const isBranch = node.kind === 'branch';
    const w = isRoot ? 72 : (isBranch ? 56 : 42);
    const h = isRoot ? 28 : (isBranch ? 24 : 28);
    const sprite = new THREE.Sprite(new THREE.SpriteMaterial({
      map: new THREE.CanvasTexture(generateNodeCanvas(node.label || node.name || node.id, node.color || COLORS.host, {
        widthHint: w,
        heightHint: h,
        fontSize: isRoot ? 13 : (isBranch ? 11 : 10),
        multiline: node.kind === 'host'
      })),
      depthWrite: false,
      transparent: true
    }));
    sprite.scale.set(w, h, 1);
    return sprite;
  });

  setTimeout(() => {
    try {
      Graph.cameraPosition({ x: 0, y: 420, z: 720 }, { x: 0, y: 0, z: 0 }, 900);
    } catch (e) {}
  }, 200);
}

function generateNodeCanvas(text, bgColor, opts = {}) {
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');
  const fontSize = opts.fontSize || 11;
  const lines = String(text || '').split('\n').slice(0, 2);
  ctx.font = `600 ${fontSize}px "Plus Jakarta Sans", Arial, sans-serif`;

  const paddingX = 10;
  const paddingY = 6;
  const lineH = fontSize + 3;
  let maxW = 0;
  lines.forEach(line => {
    maxW = Math.max(maxW, ctx.measureText(line).width);
  });
  maxW = Math.min(maxW, 150);

  canvas.width = Math.ceil(maxW + paddingX * 2);
  canvas.height = Math.ceil(lines.length * lineH + paddingY * 2);

  // soft plate
  ctx.fillStyle = 'rgba(8, 9, 13, 0.72)';
  roundRect(ctx, 0, 0, canvas.width, canvas.height, 8);
  ctx.fill();

  ctx.strokeStyle = bgColor || COLORS.host;
  ctx.lineWidth = 1.5;
  roundRect(ctx, 0.75, 0.75, canvas.width - 1.5, canvas.height - 1.5, 8);
  ctx.stroke();

  // accent bar
  ctx.fillStyle = bgColor || COLORS.host;
  ctx.fillRect(0, 0, 4, canvas.height);

  ctx.fillStyle = '#f8fafc';
  ctx.textAlign = 'left';
  ctx.textBaseline = 'middle';
  ctx.font = `600 ${fontSize}px "Plus Jakarta Sans", Arial, sans-serif`;
  lines.forEach((line, i) => {
    const y = paddingY + lineH * i + lineH / 2;
    ctx.fillText(line, paddingX + 2, y, maxW);
  });

  return canvas;
}

function roundRect(ctx, x, y, w, h, r) {
  const radius = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + radius, y);
  ctx.arcTo(x + w, y, x + w, y + h, radius);
  ctx.arcTo(x + w, y + h, x, y + h, radius);
  ctx.arcTo(x, y + h, x, y, radius);
  ctx.arcTo(x, y, x + w, y, radius);
  ctx.closePath();
}

function stampFilename(prefix, ext) {
  const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-');
  return `${prefix}_${stamp}.${ext}`;
}

function exportMapImage(format) {
  if (exportInFlight) return;
  if (!Graph || !latestGraphData.nodes.length) {
    setStatus('Mapa indisponível para exportação.');
    return;
  }

  exportInFlight = true;
  try {
    if (format === 'png') {
      exportMapPng();
      return;
    }
    if (format === 'svg') {
      exportMapSvg();
      return;
    }
    setStatus('Formato de exportação não suportado.');
  } finally {
    setTimeout(() => { exportInFlight = false; }, 800);
  }
}

function getSceneCanvas() {
  try {
    const renderer = Graph && typeof Graph.renderer === 'function' ? Graph.renderer() : null;
    if (renderer && renderer.domElement) return renderer.domElement;
  } catch (e) {}
  return mapContainer ? mapContainer.querySelector('canvas') : null;
}

function exportMapPng() {
  const sceneCanvas = getSceneCanvas();
  if (!sceneCanvas) {
    setStatus('Canvas do mapa não encontrado.');
    return;
  }

  // Force a fresh WebGL paint, then capture in the next frame
  try {
    const renderer = Graph.renderer();
    renderer.render(Graph.scene(), Graph.camera());
  } catch (e) {}

  requestAnimationFrame(() => {
    try {
      const canvasNow = getSceneCanvas() || sceneCanvas;
      const w = canvasNow.width || Math.max(1, Math.floor(canvasNow.clientWidth * (window.devicePixelRatio || 1)));
      const h = canvasNow.height || Math.max(1, Math.floor(canvasNow.clientHeight * (window.devicePixelRatio || 1)));

      if (w < 2 || h < 2) {
        setStatus('Canvas do mapa sem dimensão para exportar. Atualize o mapa e tente de novo.');
        return;
      }

      const headerH = 72;
      const exportCanvas = document.createElement('canvas');
      exportCanvas.width = w;
      exportCanvas.height = h + headerH;
      const ctx = exportCanvas.getContext('2d');

      ctx.fillStyle = COLORS.bg;
      ctx.fillRect(0, 0, exportCanvas.width, exportCanvas.height);

      const grad = ctx.createLinearGradient(0, 0, w, 0);
      grad.addColorStop(0, '#0b1220');
      grad.addColorStop(1, '#102033');
      ctx.fillStyle = grad;
      ctx.fillRect(0, 0, w, headerH);
      ctx.fillStyle = COLORS.root;
      ctx.fillRect(0, headerH - 2, w, 2);

      ctx.fillStyle = '#f8fafc';
      ctx.font = '700 22px "Plus Jakarta Sans", Arial, sans-serif';
      ctx.fillText(BRAND, 28, 32);
      ctx.fillStyle = '#94a3b8';
      ctx.font = '500 13px "Plus Jakarta Sans", Arial, sans-serif';
      ctx.fillText('Topologia de Rede · Vista 3D (Tree of Knowledge)', 28, 54);

      const when = new Date().toLocaleString('pt-BR');
      ctx.textAlign = 'right';
      ctx.fillText(when, w - 28, 42);
      ctx.textAlign = 'left';

      ctx.drawImage(canvasNow, 0, headerH, w, h);

      const url = exportCanvas.toDataURL('image/png');
      const link = document.createElement('a');
      link.href = url;
      link.download = stampFilename('NetScan_Canon_topologia', 'png');
      document.body.appendChild(link);
      link.click();
      link.remove();
      setStatus('PNG exportado com sucesso.');
    } catch (err) {
      setStatus(`Falha ao exportar PNG: ${err.message}`);
    }
  });
}

function exportMapSvg() {
  const { nodes, links } = latestGraphData;
  if (!nodes.length) return;

  // Project 3D (x,z) → 2D with padding; keep tree readability
  const positioned = nodes.filter(n => n.fx != null && n.fz != null);
  const xs = positioned.map(n => n.fx);
  const zs = positioned.map(n => n.fz);
  const minX = Math.min(...xs);
  const maxX = Math.max(...xs);
  const minZ = Math.min(...zs);
  const maxZ = Math.max(...zs);
  const pad = 80;
  const width = 1400;
  const height = 900;
  const spanX = Math.max(maxX - minX, 1);
  const spanZ = Math.max(maxZ - minZ, 1);

  const project = (n) => {
    const x = pad + ((n.fx - minX) / spanX) * (width - pad * 2);
    const y = pad + 60 + ((n.fz - minZ) / spanZ) * (height - pad * 2 - 60);
    return { x, y };
  };

  const nodePos = {};
  nodes.forEach(n => {
    if (n.fx == null) return;
    nodePos[n.id] = project(n);
  });

  const escapeXml = (s) => String(s || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');

  let linksSvg = '';
  links.forEach(l => {
    const s = nodePos[typeof l.source === 'object' ? l.source.id : l.source];
    const t = nodePos[typeof l.target === 'object' ? l.target.id : l.target];
    if (!s || !t) return;
    const sw = l.kind === 'trunk' ? 2.2 : 1.2;
    linksSvg += `<line x1="${s.x.toFixed(1)}" y1="${s.y.toFixed(1)}" x2="${t.x.toFixed(1)}" y2="${t.y.toFixed(1)}" stroke="#94a3b8" stroke-opacity="0.55" stroke-width="${sw}"/>`;
  });

  let nodesSvg = '';
  nodes.forEach(n => {
    const p = nodePos[n.id];
    if (!p) return;
    const label = escapeXml((n.label || n.name || '').split('\n')[0]);
    const r = n.kind === 'root' ? 10 : (n.kind === 'branch' ? 7 : 4.5);
    const color = n.color || COLORS.host;
    nodesSvg += `<g>
      <circle cx="${p.x.toFixed(1)}" cy="${p.y.toFixed(1)}" r="${r}" fill="${color}" stroke="#0b1220" stroke-width="1.5"/>
      <rect x="${(p.x + 8).toFixed(1)}" y="${(p.y - 10).toFixed(1)}" width="${Math.min(160, 8 + label.length * 6.2)}" height="18" rx="4" fill="rgba(8,9,13,0.82)" stroke="${color}" stroke-width="1"/>
      <text x="${(p.x + 14).toFixed(1)}" y="${(p.y + 3).toFixed(1)}" fill="#f8fafc" font-family="Segoe UI, Arial, sans-serif" font-size="11" font-weight="600">${label}</text>
    </g>`;
  });

  const when = escapeXml(new Date().toLocaleString('pt-BR'));
  const svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">
  <defs>
    <linearGradient id="hdr" x1="0" y1="0" x2="1" y2="0">
      <stop offset="0%" stop-color="#0b1220"/>
      <stop offset="100%" stop-color="#102033"/>
    </linearGradient>
  </defs>
  <rect width="100%" height="100%" fill="#08090d"/>
  <rect width="100%" height="56" fill="url(#hdr)"/>
  <rect y="56" width="100%" height="2" fill="#00f2fe"/>
  <text x="28" y="28" fill="#f8fafc" font-family="Segoe UI, Arial, sans-serif" font-size="20" font-weight="700">${escapeXml(BRAND)}</text>
  <text x="28" y="46" fill="#94a3b8" font-family="Segoe UI, Arial, sans-serif" font-size="12">Topologia de Rede · Projeção Tree of Knowledge</text>
  <text x="${width - 28}" y="36" fill="#94a3b8" font-family="Segoe UI, Arial, sans-serif" font-size="12" text-anchor="end">${when}</text>
  ${linksSvg}
  ${nodesSvg}
</svg>`;

  const blob = new Blob([svg], { type: 'image/svg+xml;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.href = url;
  link.download = stampFilename('NetScan_Canon_topologia', 'svg');
  document.body.appendChild(link);
  link.click();
  link.remove();
  URL.revokeObjectURL(url);
  setStatus('SVG exportado com sucesso.');
}

async function exportMapExcel() {
  if (exportInFlight) return;
  if (!latestResults.length) {
    setStatus('Sem dados para exportar Excel.');
    return;
  }
  exportInFlight = true;
  try {
    setStatus('Gerando Excel...');
    const response = await fetch('/export-xlsx', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ results: latestResults })
    });
    if (response.status === 401) {
      setStatus('Login necessário — faça login na página principal (IPs ociosos) e volte ao mapa.');
      return;
    }
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const blob = await response.blob();
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = stampFilename('NetScan_Canon_scan', 'xlsx');
    document.body.appendChild(link);
    link.click();
    link.remove();
    URL.revokeObjectURL(url);
    setStatus('Excel exportado com sucesso.');
  } catch (err) {
    setStatus(`Falha no Excel: ${err.message}`);
  } finally {
    setTimeout(() => { exportInFlight = false; }, 800);
  }
}

# NetScan AutoTest Agent — instalador estilo Veyon (serviço automático Windows)
# Requer PowerShell como Administrador na estação remota.
param(
  [ValidateSet('Install', 'Uninstall', 'Status', 'Start', 'Stop', 'Repair')]
  [string]$Action = 'Install',

  [string]$ServerUrl = '',
  [string]$PairingCode = '',
  [string]$InstallDir = '',
  [int]$IntervalSec = 5,
  [switch]$SkipNpmInstall
)

$ErrorActionPreference = 'Stop'
$TaskName = 'NetScan-AutoTest-Agent'
$SourceRoot = Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)
if (-not $InstallDir) {
  $InstallDir = Join-Path $env:ProgramData 'NetScan\AutoTestAgent'
}

function Test-Admin {
  $id = [Security.Principal.WindowsIdentity]::GetCurrent()
  $p = New-Object Security.Principal.WindowsPrincipal($id)
  return $p.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
}

function Get-NodeExe {
  $node = Get-Command node -ErrorAction SilentlyContinue
  if (-not $node) { throw 'Node.js não encontrado. Instale em https://nodejs.org e tente novamente.' }
  return $node.Source
}

function Write-Section([string]$Title) {
  Write-Host ""
  Write-Host "=== $Title ===" -ForegroundColor Cyan
}

function Get-AgentBundleFiles {
  @(
    'autotestRemoteRunner.js',
    'autoTest.js',
    'autoTestNetwork.js',
    'loopDetection.js',
    'autoTestRemoteSecurity.js',
    'package.agent.json'
  )
}

function Copy-AgentBundle {
  param([string]$Dest)
  New-Item -ItemType Directory -Force -Path $Dest | Out-Null
  New-Item -ItemType Directory -Force -Path (Join-Path $Dest 'data') | Out-Null
  New-Item -ItemType Directory -Force -Path (Join-Path $Dest 'logs') | Out-Null

  foreach ($f in (Get-AgentBundleFiles)) {
    $src = Join-Path $SourceRoot $f
    if (-not (Test-Path $src)) { throw "Arquivo ausente no pacote: $f" }
    if ($f -eq 'package.agent.json') {
      Copy-Item $src (Join-Path $Dest 'package.json') -Force
    } else {
      Copy-Item $src (Join-Path $Dest $f) -Force
    }
  }

  $srcConfig = Join-Path $SourceRoot 'data\auto-test-config.json'
  if (Test-Path $srcConfig) {
    Copy-Item $srcConfig (Join-Path $Dest 'data\auto-test-config.json') -Force
  }
}

function Install-AgentDependencies {
  param([string]$Dest)
  if ($SkipNpmInstall) {
    Write-Host 'SkipNpmInstall — pulando npm install' -ForegroundColor Yellow
    return
  }
  Write-Host 'Instalando dependências (net-snmp)…' -ForegroundColor DarkGray
  Push-Location $Dest
  try {
    & npm install --omit=dev --no-audit --no-fund 2>&1 | ForEach-Object { Write-Host $_ -ForegroundColor DarkGray }
    if ($LASTEXITCODE -ne 0) { throw "npm install falhou (código $LASTEXITCODE)" }
  } finally {
    Pop-Location
  }
}

function Save-AgentConfig {
  param([string]$Dest, [string]$Url, [string]$NodePath)
  $cfg = @{
    version     = '2.1'
    serverUrl   = $Url.TrimEnd('/')
    installedAt = (Get-Date).ToString('o')
    nodePath    = $NodePath
    taskName    = $TaskName
    installDir  = $Dest
  }
  $cfgPath = Join-Path $Dest 'data\agent-config.json'
  $cfg | ConvertTo-Json | Set-Content -Path $cfgPath -Encoding UTF8
}

function Invoke-AgentEnroll {
  param([string]$Dest, [string]$Url, [string]$Code, [string]$NodePath)
  $runner = Join-Path $Dest 'autotestRemoteRunner.js'
  $cred = Join-Path $Dest 'data\autotest-agent-credentials.json'
  $args = @(
    $runner,
    '--server', $Url.TrimEnd('/'),
    '--enroll', '--enroll-only',
    '--pairing-code', $Code,
    '--credentials', $cred,
    '--config', (Join-Path $Dest 'data\agent-config.json')
  )
  Write-Host 'Pareando estação com sala TI…' -ForegroundColor Cyan
  Push-Location $Dest
  try {
    & $NodePath @args
    if ($LASTEXITCODE -ne 0) { throw "Pareamento falhou (código $LASTEXITCODE)" }
  } finally {
    Pop-Location
  }
  if (-not (Test-Path $cred)) { throw 'Credenciais não geradas após pareamento.' }
}

function Register-AgentTask {
  param([string]$Dest, [string]$NodePath)
  $runner = Join-Path $Dest 'autotestRemoteRunner.js'
  $cred = Join-Path $Dest 'data\autotest-agent-credentials.json'
  $cfg = Join-Path $Dest 'data\agent-config.json'
  $log = Join-Path $Dest 'logs\agent.log'

  $argLine = "`"$runner`" --credentials `"$cred`" --config `"$cfg`" --log-file `"$log`" --interval $IntervalSec"
  $action = New-ScheduledTaskAction -Execute $NodePath -Argument $argLine -WorkingDirectory $Dest

  $triggerBoot = New-ScheduledTaskTrigger -AtStartup
  $triggerBoot.Delay = 'PT45S'

  $settings = New-ScheduledTaskSettingsSet `
    -AllowStartIfOnBatteries `
    -DontStopIfGoingOnBatteries `
    -StartWhenAvailable `
    -ExecutionTimeLimit ([TimeSpan]::Zero) `
    -RestartCount 999 `
    -RestartInterval (New-TimeSpan -Minutes 1)

  $principal = New-ScheduledTaskPrincipal -UserId 'SYSTEM' -LogonType ServiceAccount -RunLevel Highest

  Unregister-AgentTask -Quiet
  Register-ScheduledTask `
    -TaskName $TaskName `
    -Action $action `
    -Trigger @($triggerBoot) `
    -Settings $settings `
    -Principal $principal `
    -Description 'NetScan AutoTest — agente remoto de campo (estilo Veyon). Inicia com o Windows.' | Out-Null
}

function Unregister-AgentTask {
  param([switch]$Quiet)
  $existing = Get-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue
  if ($existing) {
    Stop-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue
    Unregister-ScheduledTask -TaskName $TaskName -Confirm:$false
    if (-not $Quiet) { Write-Host "Tarefa $TaskName removida." -ForegroundColor Green }
  } elseif (-not $Quiet) {
    Write-Host "Tarefa $TaskName não estava registrada." -ForegroundColor DarkGray
  }
}

function Show-AgentStatus {
  $task = Get-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue
  Write-Section 'Serviço NetScan AutoTest Agent'
  Write-Host "Instalação: $InstallDir"
  if ($task) {
    $info = Get-ScheduledTaskInfo -TaskName $TaskName
    Write-Host "Tarefa agendada: $TaskName" -ForegroundColor Green
    Write-Host "Estado: $($task.State) · Último resultado: $($info.LastTaskResult) · Última execução: $($info.LastRunTime)"
  } else {
    Write-Host 'Tarefa agendada: NÃO instalada' -ForegroundColor Yellow
  }

  $cfgPath = Join-Path $InstallDir 'data\agent-config.json'
  if (Test-Path $cfgPath) {
    $cfg = Get-Content $cfgPath -Raw | ConvertFrom-Json
    Write-Host "Servidor: $($cfg.serverUrl)"
    Write-Host "Instalado em: $($cfg.installedAt)"
  }

  $credPath = Join-Path $InstallDir 'data\autotest-agent-credentials.json'
  if (Test-Path $credPath) {
    $cred = Get-Content $credPath -Raw | ConvertFrom-Json
    Write-Host "Estação pareada: $($cred.agentId) ($($cred.hostname)) · desde $($cred.enrolledAt)" -ForegroundColor Green
  } else {
    Write-Host 'Estação: NÃO pareada' -ForegroundColor Yellow
  }

  $logPath = Join-Path $InstallDir 'logs\agent.log'
  if (Test-Path $logPath) {
    Write-Section 'Últimas linhas do log'
    Get-Content $logPath -Tail 12 | ForEach-Object { Write-Host $_ -ForegroundColor DarkGray }
  }
}

function Install-AgentService {
  if (-not (Test-Admin)) { throw 'Execute como Administrador (clique direito > Executar como administrador).' }
  if (-not $ServerUrl) {
    $ServerUrl = Read-Host 'URL do servidor NetScan (ex.: http://192.168.1.10:3000)'
  }
  if (-not $PairingCode) {
    Write-Host 'Gere o código na sala TI: AutoTest > Gerar código de pareamento' -ForegroundColor Yellow
    $PairingCode = Read-Host 'Código de pareamento'
  }

  $nodePath = Get-NodeExe
  Write-Section 'Instalando agente NetScan (estilo Veyon)'
  Write-Host "Origem: $SourceRoot"
  Write-Host "Destino: $InstallDir"
  Write-Host "Servidor: $($ServerUrl.TrimEnd('/'))"
  Write-Host "Node: $nodePath"

  Copy-AgentBundle -Dest $InstallDir
  Install-AgentDependencies -Dest $InstallDir
  Save-AgentConfig -Dest $InstallDir -Url $ServerUrl -NodePath $nodePath
  Invoke-AgentEnroll -Dest $InstallDir -Url $ServerUrl -Code $PairingCode -NodePath $nodePath
  Register-AgentTask -Dest $InstallDir -NodePath $nodePath

  Start-ScheduledTask -TaskName $TaskName
  Start-Sleep -Seconds 2
  Show-AgentStatus

  Write-Host ""
  Write-Host 'Instalação concluída. O agente inicia automaticamente com o Windows.' -ForegroundColor Green
  Write-Host 'Não é necessário manter PowerShell ou Node aberto manualmente.' -ForegroundColor Green
}

function Uninstall-AgentService {
  if (-not (Test-Admin)) { throw 'Execute como Administrador.' }
  Write-Section 'Desinstalando agente'
  Unregister-AgentTask
  if (Test-Path $InstallDir) {
    Remove-Item -Recurse -Force $InstallDir
    Write-Host "Pasta removida: $InstallDir" -ForegroundColor Green
  }
  Write-Host 'Desinstalação concluída.' -ForegroundColor Green
}

function Repair-AgentService {
  if (-not (Test-Admin)) { throw 'Execute como Administrador.' }
  if (-not (Test-Path $InstallDir)) { throw "Agente não instalado em $InstallDir" }
  $nodePath = Get-NodeExe
  Write-Section 'Reparando agente'
  Copy-AgentBundle -Dest $InstallDir
  Install-AgentDependencies -Dest $InstallDir
  Register-AgentTask -Dest $InstallDir -NodePath $nodePath
  Start-ScheduledTask -TaskName $TaskName
  Write-Host 'Reparo concluído.' -ForegroundColor Green
}

switch ($Action) {
  'Install' { Install-AgentService }
  'Uninstall' { Uninstall-AgentService }
  'Status' { Show-AgentStatus }
  'Start' {
    if (-not (Test-Admin)) { throw 'Execute como Administrador.' }
    Start-ScheduledTask -TaskName $TaskName
    Write-Host 'Agente iniciado.' -ForegroundColor Green
  }
  'Stop' {
    if (-not (Test-Admin)) { throw 'Execute como Administrador.' }
    Stop-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue
    Write-Host 'Agente parado.' -ForegroundColor Green
  }
  'Repair' { Repair-AgentService }
}

# NetScan AutoTest Agent — instalador estilo Veyon (serviço automático Windows)
# Requer PowerShell como Administrador na estação remota.
param(
  [ValidateSet('Install', 'Uninstall', 'Status', 'Start', 'Stop', 'Repair')]
  [string]$Action = 'Install',

  [string]$ServerUrl = '',
  [string]$PairingCode = '',
  [string]$InstallDir = '',
  [int]$IntervalSec = 5,
  [switch]$SkipNpmInstall
)

$ErrorActionPreference = 'Stop'
$TaskName = 'NetScan-AutoTest-Agent'
$SourceRoot = Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)
if (-not $InstallDir) {
  $InstallDir = Join-Path $env:ProgramData 'NetScan\AutoTestAgent'
}

function Test-Admin {
  $id = [Security.Principal.WindowsIdentity]::GetCurrent()
  $p = New-Object Security.Principal.WindowsPrincipal($id)
  return $p.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
}

function Get-NodeExe {
  $node = Get-Command node -ErrorAction SilentlyContinue
  if (-not $node) { throw 'Node.js não encontrado. Instale em https://nodejs.org e tente novamente.' }
  return $node.Source
}

function Write-Section([string]$Title) {
  Write-Host ""
  Write-Host "=== $Title ===" -ForegroundColor Cyan
}

function Get-AgentBundleFiles {
  @(
    'autotestRemoteRunner.js',
    'autoTest.js',
    'autoTestNetwork.js',
    'loopDetection.js',
    'autoTestRemoteSecurity.js',
    'package.agent.json'
  )
}

function Copy-AgentBundle {
  param([string]$Dest)
  New-Item -ItemType Directory -Force -Path $Dest | Out-Null
  New-Item -ItemType Directory -Force -Path (Join-Path $Dest 'data') | Out-Null
  New-Item -ItemType Directory -Force -Path (Join-Path $Dest 'logs') | Out-Null

  foreach ($f in (Get-AgentBundleFiles)) {
    $src = Join-Path $SourceRoot $f
    if (-not (Test-Path $src)) { throw "Arquivo ausente no pacote: $f" }
    if ($f -eq 'package.agent.json') {
      Copy-Item $src (Join-Path $Dest 'package.json') -Force
    } else {
      Copy-Item $src (Join-Path $Dest $f) -Force
    }
  }

  $srcConfig = Join-Path $SourceRoot 'data\auto-test-config.json'
  if (Test-Path $srcConfig) {
    Copy-Item $srcConfig (Join-Path $Dest 'data\auto-test-config.json') -Force
  }
}

function Install-AgentDependencies {
  param([string]$Dest)
  if ($SkipNpmInstall) {
    Write-Host 'SkipNpmInstall — pulando npm install' -ForegroundColor Yellow
    return
  }
  Write-Host 'Instalando dependências (net-snmp)…' -ForegroundColor DarkGray
  Push-Location $Dest
  try {
    & npm install --omit=dev --no-audit --no-fund 2>&1 | ForEach-Object { Write-Host $_ -ForegroundColor DarkGray }
    if ($LASTEXITCODE -ne 0) { throw "npm install falhou (código $LASTEXITCODE)" }
  } finally {
    Pop-Location
  }
}

function Save-AgentConfig {
  param([string]$Dest, [string]$Url, [string]$NodePath)
  $cfg = @{
    version     = '2.1'
    serverUrl   = $Url.TrimEnd('/')
    installedAt = (Get-Date).ToString('o')
    nodePath    = $NodePath
    taskName    = $TaskName
    installDir  = $Dest
  }
  $cfgPath = Join-Path $Dest 'data\agent-config.json'
  $cfg | ConvertTo-Json | Set-Content -Path $cfgPath -Encoding UTF8
}

function Invoke-AgentEnroll {
  param([string]$Dest, [string]$Url, [string]$Code, [string]$NodePath)
  $runner = Join-Path $Dest 'autotestRemoteRunner.js'
  $cred = Join-Path $Dest 'data\autotest-agent-credentials.json'
  $args = @(
    $runner,
    '--server', $Url.TrimEnd('/'),
    '--enroll', '--enroll-only',
    '--pairing-code', $Code,
    '--credentials', $cred,
    '--config', (Join-Path $Dest 'data\agent-config.json')
  )
  Write-Host 'Pareando estação com sala TI…' -ForegroundColor Cyan
  Push-Location $Dest
  try {
    & $NodePath @args
    if ($LASTEXITCODE -ne 0) { throw "Pareamento falhou (código $LASTEXITCODE)" }
  } finally {
    Pop-Location
  }
  if (-not (Test-Path $cred)) { throw 'Credenciais não geradas após pareamento.' }
}

function Register-AgentTask {
  param([string]$Dest, [string]$NodePath)
  $runner = Join-Path $Dest 'autotestRemoteRunner.js'
  $cred = Join-Path $Dest 'data\autotest-agent-credentials.json'
  $cfg = Join-Path $Dest 'data\agent-config.json'
  $log = Join-Path $Dest 'logs\agent.log'

  $argLine = "`"$runner`" --credentials `"$cred`" --config `"$cfg`" --log-file `"$log`" --interval $IntervalSec"
  $action = New-ScheduledTaskAction -Execute $NodePath -Argument $argLine -WorkingDirectory $Dest

  $triggerBoot = New-ScheduledTaskTrigger -AtStartup
  $triggerBoot.Delay = 'PT45S'

  $settings = New-ScheduledTaskSettingsSet `
    -AllowStartIfOnBatteries `
    -DontStopIfGoingOnBatteries `
    -StartWhenAvailable `
    -ExecutionTimeLimit ([TimeSpan]::Zero) `
    -RestartCount 999 `
    -RestartInterval (New-TimeSpan -Minutes 1)

  $principal = New-ScheduledTaskPrincipal -UserId 'SYSTEM' -LogonType ServiceAccount -RunLevel Highest

  Unregister-AgentTask -Quiet
  Register-ScheduledTask `
    -TaskName $TaskName `
    -Action $action `
    -Trigger @($triggerBoot) `
    -Settings $settings `
    -Principal $principal `
    -Description 'NetScan AutoTest — agente remoto de campo (estilo Veyon). Inicia com o Windows.' | Out-Null
}

function Unregister-AgentTask {
  param([switch]$Quiet)
  $existing = Get-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue
  if ($existing) {
    Stop-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue
    Unregister-ScheduledTask -TaskName $TaskName -Confirm:$false
    if (-not $Quiet) { Write-Host "Tarefa $TaskName removida." -ForegroundColor Green }
  } elseif (-not $Quiet) {
    Write-Host "Tarefa $TaskName não estava registrada." -ForegroundColor DarkGray
  }
}

function Show-AgentStatus {
  $task = Get-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue
  Write-Section 'Serviço NetScan AutoTest Agent'
  Write-Host "Instalação: $InstallDir"
  if ($task) {
    $info = Get-ScheduledTaskInfo -TaskName $TaskName
    Write-Host "Tarefa agendada: $TaskName" -ForegroundColor Green
    Write-Host "Estado: $($task.State) · Último resultado: $($info.LastTaskResult) · Última execução: $($info.LastRunTime)"
  } else {
    Write-Host 'Tarefa agendada: NÃO instalada' -ForegroundColor Yellow
  }

  $cfgPath = Join-Path $InstallDir 'data\agent-config.json'
  if (Test-Path $cfgPath) {
    $cfg = Get-Content $cfgPath -Raw | ConvertFrom-Json
    Write-Host "Servidor: $($cfg.serverUrl)"
    Write-Host "Instalado em: $($cfg.installedAt)"
  }

  $credPath = Join-Path $InstallDir 'data\autotest-agent-credentials.json'
  if (Test-Path $credPath) {
    $cred = Get-Content $credPath -Raw | ConvertFrom-Json
    Write-Host "Estação pareada: $($cred.agentId) ($($cred.hostname)) · desde $($cred.enrolledAt)" -ForegroundColor Green
  } else {
    Write-Host 'Estação: NÃO pareada' -ForegroundColor Yellow
  }

  $logPath = Join-Path $InstallDir 'logs\agent.log'
  if (Test-Path $logPath) {
    Write-Section 'Últimas linhas do log'
    Get-Content $logPath -Tail 12 | ForEach-Object { Write-Host $_ -ForegroundColor DarkGray }
  }
}

function Install-AgentService {
  if (-not (Test-Admin)) { throw 'Execute como Administrador (clique direito > Executar como administrador).' }
  if (-not $ServerUrl) {
    $ServerUrl = Read-Host 'URL do servidor NetScan (ex.: http://192.168.1.10:3000)'
  }
  if (-not $PairingCode) {
    Write-Host 'Gere o código na sala TI: AutoTest > Gerar código de pareamento' -ForegroundColor Yellow
    $PairingCode = Read-Host 'Código de pareamento'
  }

  $nodePath = Get-NodeExe
  Write-Section 'Instalando agente NetScan (estilo Veyon)'
  Write-Host "Origem: $SourceRoot"
  Write-Host "Destino: $InstallDir"
  Write-Host "Servidor: $($ServerUrl.TrimEnd('/'))"
  Write-Host "Node: $nodePath"

  Copy-AgentBundle -Dest $InstallDir
  Install-AgentDependencies -Dest $InstallDir
  Save-AgentConfig -Dest $InstallDir -Url $ServerUrl -NodePath $nodePath
  Invoke-AgentEnroll -Dest $InstallDir -Url $ServerUrl -Code $PairingCode -NodePath $nodePath
  Register-AgentTask -Dest $InstallDir -NodePath $nodePath

  Start-ScheduledTask -TaskName $TaskName
  Start-Sleep -Seconds 2
  Show-AgentStatus

  Write-Host ""
  Write-Host 'Instalação concluída. O agente inicia automaticamente com o Windows.' -ForegroundColor Green
  Write-Host 'Não é necessário manter PowerShell ou Node aberto manualmente.' -ForegroundColor Green
}

function Uninstall-AgentService {
  if (-not (Test-Admin)) { throw 'Execute como Administrador.' }
  Write-Section 'Desinstalando agente'
  Unregister-AgentTask
  if (Test-Path $InstallDir) {
    Remove-Item -Recurse -Force $InstallDir
    Write-Host "Pasta removida: $InstallDir" -ForegroundColor Green
  }
  Write-Host 'Desinstalação concluída.' -ForegroundColor Green
}

function Repair-AgentService {
  if (-not (Test-Admin)) { throw 'Execute como Administrador.' }
  if (-not (Test-Path $InstallDir)) { throw "Agente não instalado em $InstallDir" }
  $nodePath = Get-NodeExe
  Write-Section 'Reparando agente'
  Copy-AgentBundle -Dest $InstallDir
  Install-AgentDependencies -Dest $InstallDir
  Register-AgentTask -Dest $InstallDir -NodePath $nodePath
  Start-ScheduledTask -TaskName $TaskName
  Write-Host 'Reparo concluído.' -ForegroundColor Green
}

switch ($Action) {
  'Install' { Install-AgentService }
  'Uninstall' { Uninstall-AgentService }
  'Status' { Show-AgentStatus }
  'Start' {
    if (-not (Test-Admin)) { throw 'Execute como Administrador.' }
    Start-ScheduledTask -TaskName $TaskName
    Write-Host 'Agente iniciado.' -ForegroundColor Green
  }
  'Stop' {
    if (-not (Test-Admin)) { throw 'Execute como Administrador.' }
    Stop-ScheduledTask -TaskName $TaskName -ErrorAction SilentlyContinue
    Write-Host 'Agente parado.' -ForegroundColor Green
  }
  'Repair' { Repair-AgentService }
}

