# AutoTest remoto — helper: status, comando de instalação, listar agentes, iniciar agente
param(
  [ValidateSet('status', 'agents', 'install-cmd', 'start-agent')]
  [string]$Action = 'status',

  [string]$ServerUrl = 'http://localhost:3000',
  [string]$Token = '',
  [int]$IntervalSec = 5
)

$ErrorActionPreference = 'Stop'
$root = Split-Path -Parent (Split-Path -Parent $MyInvocation.MyCommand.Path)
$agentScript = Join-Path $root 'scripts\autotest-remote-agent.ps1'
$dataFile = Join-Path $root 'data\autotest-remote.json'

function Write-Section([string]$Title) {
  Write-Host ""
  Write-Host "=== $Title ===" -ForegroundColor Cyan
}

function Get-RemoteConfig {
  $url = ($ServerUrl.TrimEnd('/')) + '/api/autotest/remote/config'
  try {
    return Invoke-RestMethod -Uri $url -Method Get -TimeoutSec 10
  } catch {
    $code = $_.Exception.Response.StatusCode.value__
    if ($code -eq 404) {
      Write-Host "[ERRO] API não encontrada (404). Reinicie o servidor: npm start" -ForegroundColor Red
    } else {
      Write-Host "[ERRO] Falha ao contactar $url : $($_.Exception.Message)" -ForegroundColor Red
    }
    return $null
  }
}

function Get-RemoteAgents {
  $url = ($ServerUrl.TrimEnd('/')) + '/api/autotest/remote/agents'
  try {
    return Invoke-RestMethod -Uri $url -Method Get -TimeoutSec 10
  } catch {
    Write-Host "[ERRO] Falha ao listar agentes: $($_.Exception.Message)" -ForegroundColor Red
    return $null
  }
}

function Get-TokenFromFile {
  if (-not (Test-Path $dataFile)) { return $null }
  try {
    $raw = Get-Content $dataFile -Raw | ConvertFrom-Json
    return $raw.agentToken
  } catch {
    return $null
  }
}

function Resolve-Token([object]$Config) {
  if ($Token) { return $Token }
  if ($Config -and $Config.agentToken) { return $Config.agentToken }
  return Get-TokenFromFile
}

function Show-InstallCommand([string]$PairingCode) {
  $installer = Join-Path $root 'scripts\install-autotest-agent-service.ps1'
  Write-Host "Na estação remota — PowerShell como ADMINISTRADOR:" -ForegroundColor Green
  Write-Host ""
  Write-Host "cd `"$root`"" -ForegroundColor White
  $code = if ($PairingCode) { $PairingCode } else { 'CODIGO' }
  Write-Host ".\scripts\install-autotest-agent-service.ps1 -ServerUrl `"$($ServerUrl.TrimEnd('/'))`" -PairingCode `"$code`"" -ForegroundColor White
  Write-Host ""
  Write-Host "Status:     .\scripts\install-autotest-agent-service.ps1 -Action Status" -ForegroundColor DarkGray
  Write-Host "Desinstalar: .\scripts\install-autotest-agent-service.ps1 -Action Uninstall" -ForegroundColor DarkGray
  Write-Host ""
}

function Show-FlowHelp {
  Write-Host @"

FLUXO AUTOTEST REMOTO (estilo Veyon)
------------------------------------
[Sala TI]   Gerar código > Executar remoto (IP ou lista)
[Campo]     Instalar serviço UMA VEZ — sobe com o Windows, sem Node aberto

"@ -ForegroundColor DarkGray
}

# --- Actions ---

$config = Get-RemoteConfig
$resolvedToken = Resolve-Token $config

switch ($Action) {
  'status' {
    Show-FlowHelp
    Write-Section "Servidor"
    Write-Host "URL: $($ServerUrl.TrimEnd('/'))"
    if ($config) {
      Write-Host "API remota: OK" -ForegroundColor Green
      Write-Host "Modo: $($config.securityMode) | Online: $($config.onlineWindowSec)s | Job: $($config.jobTimeoutSec)s"
    } else {
      Write-Host "API remota: indisponível" -ForegroundColor Red
      $fileToken = Get-TokenFromFile
      if ($fileToken) { Write-Host "Token local (data/): $fileToken" -ForegroundColor Yellow }
    }

    Write-Section "Agentes registrados"
    $agentsData = Get-RemoteAgents
    if ($agentsData -and $agentsData.agents.Count -gt 0) {
      foreach ($a in $agentsData.agents) {
        $st = if ($a.online) { '● online' } else { '○ offline' }
        $color = if ($a.online) { 'Green' } else { 'DarkGray' }
        Write-Host "$st  $($a.hostname) ($($a.agentId))  IP=$($a.ip)  visto=$($a.lastSeen)" -ForegroundColor $color
      }
    } else {
      Write-Host "Nenhum agente. Instale o serviço na estação remota (install-cmd)." -ForegroundColor Yellow
    }

    Write-Section "Instalação serviço (estação remota)"
    Show-InstallCommand ''
  }

  'agents' {
    $agentsData = Get-RemoteAgents
    if (-not $agentsData) { exit 1 }
    if ($agentsData.agents.Count -eq 0) {
      Write-Host "Nenhum agente registrado." -ForegroundColor Yellow
      exit 0
    }
    $agentsData.agents | Format-Table agentId, hostname, ip, online, lastSeen -AutoSize
  }

  'install-cmd' {
    Show-FlowHelp
    Write-Section "Instalar serviço (Admin na estação remota)"
    Show-InstallCommand ''
  }

  'start-agent' {
    Write-Host 'Recomendado — serviço instalado:' -ForegroundColor Cyan
    Write-Host "  .\scripts\install-autotest-agent-service.ps1 -Action Start" -ForegroundColor White
    Write-Host 'Modo manual (janela aberta):' -ForegroundColor DarkGray
    if (-not (Test-Path $agentScript)) {
      Write-Error "Script não encontrado: $agentScript"
    }
    & $agentScript -ServerUrl $ServerUrl.TrimEnd('/') -IntervalSec $IntervalSec
  }
}

/**
 * One-off: rebuild data/host-history.json from data/network-baselines.json snapshots.
 * Preserves original scan timestamps for idle-host duration.
 */
const fs = require('fs');
const path = require('path');
const { recordScanHosts, clearHistory, getHistoryStats, HISTORY_FILE } = require('../hostHistory');

const BASELINE_FILE = path.join(__dirname, '..', 'data', 'network-baselines.json');

function loadBaselines() {
  if (!fs.existsSync(BASELINE_FILE)) return { snapshots: [] };
  const raw = JSON.parse(fs.readFileSync(BASELINE_FILE, 'utf8'));
  return { snapshots: Array.isArray(raw.snapshots) ? raw.snapshots : [] };
}

function main() {
  const store = loadBaselines();
  const snapshots = [...store.snapshots].sort((a, b) => a.at - b.at);

  if (snapshots.length === 0) {
    console.error('Nenhum snapshot em network-baselines.json');
    process.exit(1);
  }

  clearHistory();

  for (const snap of snapshots) {
    const hosts = (snap.hosts || []).map((h) => ({
      ...h,
      status: h.status || 'Inativo'
    }));

    const result = recordScanHosts(hosts, {
      target: snap.target,
      at: snap.at,
      scanId: snap.id ? snap.id.replace(/^snap_/, 'scan_') : undefined
    });

    console.log(
      `${snap.atIso || new Date(snap.at).toISOString()} | ${snap.target} | ` +
        `${hosts.length} hosts | active=${result.activeUpdated} inactive=${result.inactiveCount}`
    );
  }

  const history = JSON.parse(fs.readFileSync(HISTORY_FILE, 'utf8'));
  const stats = getHistoryStats(0);

  console.log('\nRestaurado em', HISTORY_FILE);
  console.log('Hosts:', Object.keys(history.hosts).length);
  console.log('Scans:', stats.scanCount);
  console.log('Idle candidates (threshold 0):', stats.idleCandidates);
}

main();

/**
 * Merge idle-hosts export JSON back into data/host-history.json
 */
const fs = require('fs');
const path = require('path');
const {
  backupHistoryFile,
  getIdleHosts,
  HISTORY_FILE
} = require('../hostHistory');

function loadHistoryFile() {
  return JSON.parse(fs.readFileSync(HISTORY_FILE, 'utf8'));
}

const EXPORT_FILE = process.argv[2] || path.join(__dirname, '..', 'data', 'idle-export-recovery.json');

function stripIdleViewFields(record) {
  if (!record || typeof record !== 'object') return record;
  const {
    idleMs, idleFor, inactiveSinceIso, lastSeenIso, lastCheckedIso,
    thresholdMs, neverActive, reason, ...rest
  } = record;
  return rest;
}

function main() {
  if (!fs.existsSync(EXPORT_FILE)) {
    console.error('Export não encontrado:', EXPORT_FILE);
    process.exit(1);
  }

  const exp = JSON.parse(fs.readFileSync(EXPORT_FILE, 'utf8'));
  const idleHosts = Array.isArray(exp.hosts) ? exp.hosts : [];
  if (!idleHosts.length) {
    console.error('Export sem hosts');
    process.exit(1);
  }

  backupHistoryFile('pre-idle-merge');
  const history = loadHistoryFile();
  let added = 0;
  let updated = 0;

  for (const host of idleHosts) {
    if (!host?.ip) continue;
    const clean = stripIdleViewFields(host);
    if (history.hosts[host.ip]) updated++;
    else added++;
    history.hosts[host.ip] = { ...history.hosts[host.ip], ...clean };
  }

  if ((exp.scanCount || 0) > history.scans.length) {
    console.log(`scanCount export=${exp.scanCount} hist=${history.scans.length} (mantendo log de scans local)`);
  }

  const tmp = `${HISTORY_FILE}.tmp`;
  fs.writeFileSync(tmp, JSON.stringify(history, null, 2), 'utf8');
  fs.renameSync(tmp, HISTORY_FILE);

  const idle = getIdleHosts(0);
  console.log('Merge concluído');
  console.log('  export ociosos:', idleHosts.length);
  console.log('  added:', added, 'updated:', updated);
  console.log('  totalTracked:', Object.keys(history.hosts).length);
  console.log('  idle@0:', idle.idleCount);
  console.log('  arquivo:', HISTORY_FILE);
}

main();

